# =========================
# MULTI-DEVICE CONCURRENCY DIAGNOSTICS (PART 1 of multi-device-concurrency spec)
#
# Every major request path (/infer, /text, reasoning streams, TTS streaming,
# news/action handlers, checklist handlers) generates a unique request_id and
# prints structured [REQ start] / [REQ end] / [ASR lock wait] / [ASR done] /
# [TTS lock wait] / [TTS done] / [STREAM open] / [STREAM close] lines. The
# request_id is also exposed via the _current_request_id_var contextvar so
# nested helpers can attribute their own logs to the right request without
# having to pass it explicitly.
#
# Why a SEPARATE id from cost_logging's rid: the cost_logger rid lives inside
# its own ContextVar and is only emitted in cost rows. We want a noisy,
# obvious-in-stdout id that two-device debugging can grep for in a single
# pass. The two ids coexist; cost rows are unaffected.
# =========================

import contextvars

_current_request_id_var: contextvars.ContextVar[str | None] = contextvars.ContextVar(
    "vera_request_id", default=None,
)

# 2026-05-29 — multi-action planner re-entry guard.
#
# The planner shadow-logger calls ``plan_user_actions`` from inside
# ``process_user_input``. When the planner EXECUTOR re-routes each action
# span back through ``process_user_input``, that nested call would otherwise
# fire the shadow logger again on the sub-span, producing noisy
# "[planner] is_multi_action: false …" lines for every single action of
# the original compound command. The contextvar lets us short-circuit the
# shadow path while a top-level execution is already in flight, without
# threading an explicit flag through five function signatures.
_planner_executing_var: contextvars.ContextVar[bool] = contextvars.ContextVar(
    "vera_planner_executing", default=False,
)
# Raw compound utterance for the plan currently executing (voice → panel handoff).
_planner_plan_raw_text_var: contextvars.ContextVar[str] = contextvars.ContextVar(
    "vera_planner_plan_raw_text", default="",
)

# 2026-05-29 LIVE-TRACE DIAGNOSTIC (PART 6 of bypass investigation).
#
# Populated by ``try_execute_planned_actions_for_text`` so the calling
# ``/infer`` (and ``/text``) endpoint can emit ONE structured
# ``[planner_live_trace]`` line that includes every field needed to tell
# why the live route did or did not honor the planner. The fields mirror
# the spec checklist: ``planner_json``, ``planner_validation_ok``,
# ``planner_executed``, ``planner_returned_none_reason``, and the LLM-vs-
# deterministic comparison used by ``[planner_version_or_path_mismatch]``.
#
# The dict shape is intentionally flat so JSON-serializing it adds no
# overhead. We use a contextvar instead of a thread-local because the
# /infer handler runs in an asyncio task that may share threads.
_planner_last_gate_diag_var: contextvars.ContextVar[dict | None] = (
    contextvars.ContextVar("vera_planner_last_gate_diag", default=None)
)


def _new_request_id() -> str:
    """Short, grep-friendly request id. Format: req_<12 hex>."""
    return "req_" + uuid.uuid4().hex[:12]


def _safe_repr_kv(payload: dict) -> str:
    if not payload:
        return ""
    parts: list[str] = []
    for k, v in payload.items():
        if v is None:
            continue
        try:
            s = str(v)
        except Exception:
            s = "<unrepr>"
        if len(s) > 120:
            s = s[:117] + "…"
        if " " in s or "=" in s:
            parts.append(f"{k}={s!r}")
        else:
            parts.append(f"{k}={s}")
    return " ".join(parts)


# 2026-05-29 spec PART 2 — info-intent detector for ``[info_clause_dropped]``.
#
# These patterns mirror the ``info.*`` family anchors in
# ``actions/multi_action_planner.py::ACTION_ANCHORS``. We keep an explicit
# copy here instead of importing the planner so the diagnostic path is
# importable even if the planner module fails to load — the trace logging
# must never raise on a request thread. Each entry is
# ``(family, compiled_pattern)`` and is matched case-insensitively against
# the FULL transcript. A hit means "the user said something info-y enough
# that the plan SHOULD include an info.* (or voice.answer) family for
# that span". Failure to do so emits the warning.
_INFO_INTENT_DETECTORS: tuple[tuple[str, "re.Pattern[str]"], ...] = (
    ("info.time", re.compile(
        r"(?:what(?:'s|s| is)\s+(?:the\s+)?time|"
        r"what\s+time\s+is\s+it|current\s+time|"
        r"tell\s+me\s+(?:the\s+)?time|check\s+(?:the\s+)?time)",
        re.IGNORECASE,
    )),
    ("info.weather", re.compile(
        r"(?:what(?:'s|s| is)\s+(?:the\s+)?weather|"
        r"how(?:'s|s| is)\s+(?:the\s+)?weather|"
        r"tell\s+me\s+(?:the\s+)?weather|check\s+(?:the\s+)?weather|"
        r"current\s+weather|is\s+it\s+(?:raining|rainy|snowing|windy|hot|cold))",
        re.IGNORECASE,
    )),
    ("info.finance", re.compile(
        r"(?:what(?:'s|s| is)\s+[\w.$-]{1,12}(?:'s)?\s+(?:trading\s+at|stock\s+price|share\s+price)|"
        r"(?:stock|share)\s+price\s+(?:of|for)|"
        r"(?:quote|market\s+cap)\s+(?:for|of)|"
        r"[\w.$-]{1,12}\s+(?:trading\s+at|stock\s+price|share\s+price|market\s+cap))",
        re.IGNORECASE,
    )),
    ("info.news", re.compile(
        r"(?:what(?:'s|s| is)\s+(?:the\s+)?(?:latest\s+)?news|"
        r"(?:latest|breaking)\s+news|"
        r"tell\s+me\s+(?:the\s+)?news|"
        r"any\s+(?:updates|news)\s+on|"
        r"latest\s+on\s+\w)",
        re.IGNORECASE,
    )),
    ("info.sports", re.compile(
        r"(?:did\s+(?:the\s+)?[\w][\w\s.&'-]{1,40}\s+(?:win|lose|score)|"
        r"\b(?:lakers|warriors|celtics|knicks|yankees|dodgers|49ers|eagles|"
        r"cowboys|chiefs|liverpool|arsenal|barcelona|real\s+madrid)\s+"
        r"(?:score|won|lost|win|lose|vs\.?|versus|game|games|match))",
        re.IGNORECASE,
    )),
    ("info.product", re.compile(
        r"(?:best|top|cheapest|fastest|highest[-\s]?rated|reviews?\s+of|"
        r"recommend(?:ation)?s?\s+(?:for|of))\s+\w",
        re.IGNORECASE,
    )),
    ("info.location", re.compile(
        r"(?:coffee\s+shops?|cafes?|restaurants?|gyms?|bars?|stores?|hotels?|"
        r"parks?|libraries?|hospitals?|pharmacies?|gas\s+stations?)\s+"
        r"(?:near|in|around|by)\s+\w|\b(?:near|around)\s+me\b",
        re.IGNORECASE,
    )),
    ("info.search", re.compile(
        r"(?:did\s+(?:the\s+)?[\w][\w\s.&'-]{1,40}\s+(?:happen|go|announce|release))",
        re.IGNORECASE,
    )),
)


def _detect_info_intent_families(text: str) -> list[str]:
    """Return the list of ``info.*`` families a transcript appears to want.

    Empty string / None returns []. Pure best-effort matcher used only by
    the diagnostic warning ``[info_clause_dropped]`` — never affects
    routing decisions. Order in the returned list mirrors detector order
    (more specific families first).
    """
    if not text:
        return []
    hits: list[str] = []
    for family, pat in _INFO_INTENT_DETECTORS:
        try:
            if pat.search(text):
                hits.append(family)
        except Exception:
            continue
    return hits


def _emit_compound_route_trace(
    *,
    request_id: str,
    transcript: str,
    endpoint: str,
    input_source: str,
    typed: bool,
    use_browser_asr: bool,
    planner_execution_allowed: bool,
    should_trigger_planner_result: bool,
    planner_trigger_reason: str,
    planner_gate_called: bool,
    planner_executed: bool,
    gate_diag: dict | None,
    action_result: dict | None,
    legacy_router_called: bool,
    legacy_router_selected: str,
    final_action_type: str,
    final_reply: str,
    path: str = "non_stream",
) -> None:
    """Emit ONE structured ``[compound_route_trace]`` JSON line per /infer
    turn that mirrors the field list in the 2026-05-29 spec PART 2.

    All inputs default to safe values so the caller can pass whatever it
    has; missing fields show as the empty string / empty list / None
    rather than raising. The trace ALWAYS prints — even when the planner
    did not execute — so an operator can pivot from any failing test by
    grepping ``[compound_route_trace]`` first.

    Also fires the three hard-warning tags when applicable:
      * [planner_should_have_run_but_did_not]
      * [compound_action_dropped]  (NOTE: secondary check; the primary
        check lives in ``execute_planned_actions``)
      * [info_clause_dropped]

    Never raises — wrapped in a try/except so a malformed input cannot
    take down the request thread.
    """
    try:
        _gate_diag = gate_diag or {}
        ar = action_result if isinstance(action_result, dict) else {}
        payloads: list[dict] = []
        plural = ar.get("ui_payloads")
        if isinstance(plural, list):
            payloads = [p for p in plural if isinstance(p, dict)]
        if not payloads and isinstance(ar.get("ui_payload"), dict):
            payloads = [ar["ui_payload"]]
        payload_types = [(p.get("panel_type") or p.get("type") or "") for p in payloads]
        payload_ops = [(p.get("op") or "") for p in payloads]

        planner_actions: list[str] = []
        if isinstance(ar.get("planner_actions"), list):
            planner_actions = [str(a) for a in ar["planner_actions"]]

        # The deterministic plan's per-action span list is the closest thing we
        # have to "span_segments" without re-running the planner. The shape is
        # ``[{type, span, payload}]``; we map it to a compact form for the log.
        planner_json = _gate_diag.get("planner_json") or {}
        plan_actions = planner_json.get("actions") if isinstance(planner_json, dict) else None
        accepted_anchors = []
        span_segments = []
        normalized_action_payloads = []
        if isinstance(plan_actions, list):
            for a in plan_actions:
                if not isinstance(a, dict):
                    continue
                accepted_anchors.append(a.get("type") or "")
                span_segments.append({
                    "type": a.get("type") or "",
                    "span": (a.get("span") or "")[:120],
                })
                payload_keys = []
                if isinstance(a.get("payload"), dict):
                    payload_keys = sorted(
                        k for k in a["payload"].keys() if not k.startswith("_")
                    )
                normalized_action_payloads.append({
                    "type": a.get("type") or "",
                    "payload_keys": payload_keys,
                })

        # Detect info intents in the transcript that the plan does NOT
        # cover (no info.* / voice.answer action in planner_actions).
        info_intents = _detect_info_intent_families(transcript or "")
        plan_family_set = {(a.split(".")[0] if a else "") for a in planner_actions}
        plan_has_info_or_voice = (
            "info" in plan_family_set or "voice" in plan_family_set
        )

        # The accepted_anchors list (from the plan itself) may include info
        # families even when the executor decided not to emit them — that
        # still counts as "info covered" because the planner anchored them.
        plan_anchor_family_set = {
            (t.split(".")[0] if t else "") for t in accepted_anchors
        }
        if "info" in plan_anchor_family_set or "voice" in plan_anchor_family_set:
            plan_has_info_or_voice = True

        info_clause_dropped = bool(info_intents) and not plan_has_info_or_voice

        trace_obj = {
            "request_id": request_id,
            "transcript": (transcript or "")[:240],
            "endpoint": endpoint,
            "input_source": input_source or "unknown",
            "typed": bool(typed),
            "use_browser_asr": str(use_browser_asr or ""),
            "planner_execution_allowed": bool(planner_execution_allowed),
            "should_trigger_planner_result": bool(should_trigger_planner_result),
            "planner_trigger_reason": planner_trigger_reason or "",
            "planner_gate_called": bool(planner_gate_called),
            "accepted_anchors": accepted_anchors,
            "span_segments": span_segments,
            "planner_actions": planner_actions,
            "normalized_action_payloads": normalized_action_payloads,
            "validation_ok": _gate_diag.get("validation_ok", None),
            "validation_errors": _gate_diag.get("validation_errors", []),
            "planner_executed": bool(planner_executed),
            "planner_returned_none_reason": _gate_diag.get(
                "planner_returned_none_reason", ""
            ),
            "direct_executor_actions": planner_actions,
            "action_payloads_count": len(payloads),
            "action_payload_types": payload_types,
            "action_payload_ops": payload_ops,
            "legacy_router_called": bool(legacy_router_called),
            "legacy_router_selected": legacy_router_selected or "",
            "greedy_router_skipped": bool(planner_executed),
            "final_action_type": final_action_type or "",
            "final_reply": (final_reply or "")[:240],
            "info_intent_families_detected": info_intents,
            "info_clause_dropped": info_clause_dropped,
            "path": path,
        }
        print("[compound_route_trace] " + json.dumps(trace_obj, ensure_ascii=False), flush=True)

        # ------------------------------------------------------------------
        # Hard warning: [planner_should_have_run_but_did_not]
        # Trigger when ``should_trigger_planner=true`` but the realized
        # turn is NOT a multi-action AND the transcript has more than one
        # action family signal. We use the gate's accepted_anchors when
        # available so we know exactly how many distinct families the
        # planner saw; if those are empty, we fall back to checking the
        # number of info-intent families plus a coarse connector check.
        # ------------------------------------------------------------------
        if should_trigger_planner_result and final_action_type != "multi_action":
            distinct_planned_families = {
                (a.split(".")[0] if a else "") for a in accepted_anchors
            }
            distinct_planned_families.discard("")
            # Two music actions (e.g. ``music.play`` + ``music.volume``) is
            # still a compound — collapse them by top-level family for the
            # "distinct families" check, but ALSO count distinct anchor
            # types so a same-family compound still trips the warning.
            distinct_planned_types = {a for a in accepted_anchors if a}
            # Coarse fallback: connector present and >1 info intents.
            has_connector = bool(re.search(
                r"\b(?:and|then|also|plus|after\s+that)\b",
                transcript or "",
                re.IGNORECASE,
            ))
            heuristic_multi = (
                len(distinct_planned_families) >= 2
                or len(distinct_planned_types) >= 2
                or (
                    has_connector and len(info_intents) >= 1
                    and (
                        re.search(
                            r"\b(?:play|pause|stop|skip|next|previous|"
                            r"turn|raise|lower|crank|set\s+a\s+timer|start\s+a\s+timer|"
                            r"add|put|remove|delete|mark|check\s+off|sync|"
                            r"go\s+to|switch\s+to|open|close|reopen|"
                            r"explain|solve|write|summari|analy|describe)\b",
                            transcript or "",
                            re.IGNORECASE,
                        )
                        is not None
                    )
                )
            )
            if heuristic_multi:
                print(
                    "[planner_should_have_run_but_did_not] "
                    + json.dumps(
                        {
                            "request_id": request_id,
                            "endpoint": endpoint,
                            "path": path,
                            "transcript": (transcript or "")[:240],
                            "input_source": input_source or "unknown",
                            "typed": bool(typed),
                            "planner_execution_allowed": bool(planner_execution_allowed),
                            "planner_gate_called": bool(planner_gate_called),
                            "planner_trigger_reason": planner_trigger_reason or "",
                            "planner_executed": bool(planner_executed),
                            "planner_returned_none_reason": _gate_diag.get(
                                "planner_returned_none_reason", ""
                            ),
                            "accepted_anchors": accepted_anchors,
                            "distinct_planned_families": sorted(distinct_planned_families),
                            "distinct_planned_types": sorted(distinct_planned_types),
                            "info_intent_families_detected": info_intents,
                            "legacy_router_called": bool(legacy_router_called),
                            "legacy_router_selected": legacy_router_selected or "",
                            "final_action_type": final_action_type or "",
                            "expected": "multi_action",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )

        # ------------------------------------------------------------------
        # Hard warning: [info_clause_dropped]
        # Transcript has time/weather/news/finance/product/location/sports
        # intent but plan + execution produced no info.* (or voice.answer)
        # action. Lives at the trace stage because by this point we know
        # both the (possibly empty) planner_actions AND the executor result.
        # ------------------------------------------------------------------
        if info_clause_dropped:
            print(
                "[info_clause_dropped] "
                + json.dumps(
                    {
                        "request_id": request_id,
                        "endpoint": endpoint,
                        "path": path,
                        "transcript": (transcript or "")[:240],
                        "info_intent_families_detected": info_intents,
                        "planner_actions": planner_actions,
                        "accepted_anchors": accepted_anchors,
                        "planner_executed": bool(planner_executed),
                        "legacy_router_selected": legacy_router_selected or "",
                        "final_action_type": final_action_type or "",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception as _exc:
        try:
            print(f"[compound_route_trace] emit_failed exc={_exc}", flush=True)
        except Exception:
            pass


def log_req_start(
    *,
    route: str,
    session_id: str,
    request_id: str,
    source: str = "unknown",
    **extras,
) -> float:
    """Emit a [REQ start] line and return a perf_counter() timestamp.

    Always pair with log_req_end(...) using the returned ts as start_ts.
    """
    ts = perf_counter()
    extra_str = _safe_repr_kv(extras)
    print(
        f"[REQ start] session={session_id} request={request_id} route={route} "
        f"source={source}{(' ' + extra_str) if extra_str else ''}",
        flush=True,
    )
    return ts


def log_req_end(
    *,
    route: str,
    session_id: str,
    request_id: str,
    start_ts: float,
    ok: bool = True,
    **extras,
) -> None:
    dur_ms = int((perf_counter() - start_ts) * 1000)
    extra_str = _safe_repr_kv({**extras, "dur_ms": dur_ms})
    print(
        f"[REQ end] session={session_id} request={request_id} route={route} "
        f"ok={'true' if ok else 'false'} {extra_str}",
        flush=True,
    )


def log_stream_open(*, route: str, session_id: str, request_id: str, **extras) -> None:
    extra_str = _safe_repr_kv(extras)
    print(
        f"[STREAM open] session={session_id} request={request_id} route={route}"
        f"{(' ' + extra_str) if extra_str else ''}",
        flush=True,
    )


def log_stream_close(*, route: str, session_id: str, request_id: str, **extras) -> None:
    extra_str = _safe_repr_kv(extras)
    print(
        f"[STREAM close] session={session_id} request={request_id} route={route}"
        f"{(' ' + extra_str) if extra_str else ''}",
        flush=True,
    )


def log_cancellation(*, route: str, session_id: str, request_id: str, source: str, **extras) -> None:
    extra_str = _safe_repr_kv(extras)
    print(
        f"[CANCEL] session={session_id} request={request_id} route={route} "
        f"source={source}{(' ' + extra_str) if extra_str else ''}",
        flush=True,
    )


class _EffortSnapshot:
    """Capture `reasoning_deep_ai.last_deep_reasoning_effort_active` at the
    start of THIS request's stream so a concurrent reasoning stream can't
    overwrite it before we read it for the `done` payload.

    Used by /work_mode/reasoning_stream and /work_mode/reasoning_stream_upload.
    Multi-device-concurrency PART 3 (shared model field).
    """

    __slots__ = ("value",)

    def __init__(self) -> None:
        self.value: bool | None = None


async def _stream_markdown_capture_effort(
    snap: _EffortSnapshot,
    *,
    method,
    **kwargs,
):
    """Iterate the given reasoning_deep_ai async streaming method and snapshot
    `last_deep_reasoning_effort_active` after the first chunk arrives (which
    is the earliest moment the underlying chat.completions.create call has
    actually returned, so the field reflects THIS request).
    """
    first = True
    async for delta in method(**kwargs):
        if first:
            try:
                snap.value = reasoning_deep_ai.last_deep_reasoning_effort_active
            except Exception:
                snap.value = None
            first = False
        yield delta
    if first:
        # No chunks arrived; still try to snapshot (best effort).
        try:
            snap.value = reasoning_deep_ai.last_deep_reasoning_effort_active
        except Exception:
            snap.value = None


def _tts_lock_diag(session_id: str) -> "_LockDiag":
    """Shorthand: TTS lock + diag logs, attributed to the current request id.

    Pulls request id from the contextvar (set by /infer, /text, reasoning
    streams), so all five `async with tts_lock:` sites can use this without
    threading request_id through every helper signature.
    """
    rid = _current_request_id_var.get() or "req_unknown"
    return _LockDiag(tts_lock, name="TTS", session_id=session_id, request_id=rid)


async def _diag_wrap_stream(
    inner_gen,
    *,
    route: str,
    session_id: str,
    request_id: str,
    start_ts: float,
    **extras,
):
    """Wrap a NDJSON / SSE async generator with multi-device concurrency
    diagnostics:

    - [STREAM open] at the moment the iterator is first awaited
    - [STREAM close] when the iterator exits (success, error, or client
      disconnect)
    - [REQ end] with total request latency, so two-device logs always show
      a paired start+end for streaming requests

    The cost-logging middleware (_cost_wrap_streaming_iter) sits AROUND this
    wrapper on its way out, which is fine — both write to stdout
    independently and neither consumes the chunks.
    """
    log_stream_open(route=route, session_id=session_id, request_id=request_id)
    ok = True
    try:
        async for chunk in inner_gen:
            yield chunk
    except Exception as exc:
        ok = False
        log_cancellation(
            route=route,
            session_id=session_id,
            request_id=request_id,
            source=f"exception:{type(exc).__name__}",
        )
        raise
    finally:
        log_stream_close(route=route, session_id=session_id, request_id=request_id)
        log_req_end(
            route=route,
            session_id=session_id,
            request_id=request_id,
            start_ts=start_ts,
            ok=ok,
            **extras,
        )


class _LockDiag:
    """Async context manager that wraps an asyncio.Lock with wait/done logs.

    Usage:
        async with _LockDiag(asr_lock, name="ASR", session_id=sid, request_id=rid):
            ...model work only...
    """

    def __init__(self, lock: asyncio.Lock, *, name: str, session_id: str, request_id: str):
        self._lock = lock
        self._name = name
        self._session_id = session_id
        self._request_id = request_id
        self._wait_t0 = 0.0
        self._hold_t0 = 0.0
        self._wait_ms = 0

    async def __aenter__(self):
        self._wait_t0 = perf_counter()
        # Only emit the "wait" line when we actually have to wait (lock held).
        # This keeps log volume reasonable when there is no contention.
        had_to_wait = self._lock.locked()
        await self._lock.acquire()
        self._wait_ms = int((perf_counter() - self._wait_t0) * 1000)
        self._hold_t0 = perf_counter()
        if had_to_wait or self._wait_ms >= 5:
            print(
                f"[{self._name} lock wait] session={self._session_id} "
                f"request={self._request_id} wait_ms={self._wait_ms}",
                flush=True,
            )
        return self

    async def __aexit__(self, exc_type, exc, tb):
        hold_ms = int((perf_counter() - self._hold_t0) * 1000)
        print(
            f"[{self._name} done] session={self._session_id} "
            f"request={self._request_id} hold_ms={hold_ms} wait_ms={self._wait_ms}",
            flush=True,
        )
        self._lock.release()
        return False


# =========================
# SESSION STATE
# =========================

user_histories = defaultdict(list)
reasoning_lane_histories = defaultdict(list)
reasoning_lane_upload_plain_chain = defaultdict(str)
reasoning_global_memory = defaultdict(list)
user_last_seen = {}
total_sessions_seen = set()
pending_action = {}
recent_action_context = {}
latest_client_context_snapshot = {}
anonymous_work_mode_checklists = {}
# After "clear the checklist", we stash the previous items so "undo that"
# can restore them. Per session_id; expires after CHECKLIST_UNDO_TTL_SEC.
checklist_undo_snapshots: dict[str, dict] = {}
# Short TTL so "undo that" only wins immediately after a clear/erase/delete.
CHECKLIST_UNDO_TTL_SEC = 120
pending_checklist_undo_context: dict[str, dict] = {}


def _checklist_undo_item_titles(items: list) -> list[str]:
    titles: list[str] = []
    for row in items or []:
        if not isinstance(row, dict):
            continue
        text = str((row or {}).get("text") or "").strip()
        if text:
            titles.append(text[:80])
    return titles[:12]


def _checklist_undo_non_empty_items(items: list | None) -> list[dict]:
    out: list[dict] = []
    for row in items or []:
        if not isinstance(row, dict):
            continue
        text = str((row or {}).get("text") or "").strip()
        if not text:
            continue
        out.append(
            {
                "id": str((row or {}).get("id") or ""),
                "text": text,
                "done": bool((row or {}).get("done")),
                "parent_id": (row or {}).get("parent_id"),
            }
        )
    return out


def _checklist_undo_snapshot_from_client_context(client_context_snapshot: dict | None) -> dict | None:
    if not isinstance(client_context_snapshot, dict):
        return None
    raw = client_context_snapshot.get("checklist_undo_snapshot")
    if not isinstance(raw, dict):
        return None
    items = _checklist_undo_non_empty_items(raw.get("items"))
    if not items:
        return None
    created_ms = float(raw.get("created_at_ms") or raw.get("created_at") or 0)
    if created_ms > 1e12:
        created_ms = created_ms / 1000.0
    age = time() - created_ms if created_ms else 0
    if created_ms and age > CHECKLIST_UNDO_TTL_SEC:
        return None
    return {
        "snapshot_id": str(raw.get("snapshot_id") or ""),
        "items": items,
        "completed_collapsed": bool(raw.get("completed_collapsed", False)),
        "created_at": created_ms or time(),
        "source": str(raw.get("source") or "client_snapshot"),
        "valid": True,
    }


def _checklist_undo_snapshot_item_count(snap: dict | None) -> int:
    return len(_checklist_undo_non_empty_items((snap or {}).get("items")))


def _arm_checklist_undo_snapshot(
    session_id: str,
    items: list,
    *,
    completed_collapsed: bool,
    source: str = "checklist.clear",
) -> dict | None:
    non_empty = _checklist_undo_non_empty_items(items)
    if not non_empty:
        return None
    snapshot_id = f"cu-{int(time() * 1000)}-{abs(hash(session_id)) % 100000}"
    created_at = time()
    payload = {
        "snapshot_id": snapshot_id,
        "items": non_empty,
        "completed_collapsed": bool(completed_collapsed),
        "created_at": created_at,
        "source": source,
        "valid": True,
    }
    checklist_undo_snapshots[session_id] = payload
    pending_checklist_undo_context[session_id] = {
        "domain": "checklist",
        "action": "undo_clear",
        "snapshot_id": snapshot_id,
        "snapshot_item_count": len(non_empty),
        "expires_at_ms": int((created_at + CHECKLIST_UNDO_TTL_SEC) * 1000),
    }
    titles = _checklist_undo_item_titles(non_empty)
    _emit_undo_routing_log(
        "checklist_undo_snapshot_created",
        session_id=(session_id or "")[:64],
        snapshot_id=snapshot_id,
        snapshot_item_count=len(non_empty),
        snapshot_titles=titles,
        created_at_ms=int(created_at * 1000),
        expires_at_ms=int((created_at + CHECKLIST_UNDO_TTL_SEC) * 1000),
    )
    _emit_undo_routing_log(
        "checklist_undo_context_set",
        session_id=(session_id or "")[:64],
        snapshot_id=snapshot_id,
        snapshot_item_count=len(non_empty),
        ttl_ms=CHECKLIST_UNDO_TTL_SEC * 1000,
    )
    return payload


def _emit_undo_routing_log(tag: str, **fields) -> None:
    try:
        print(f"[{tag}] " + json.dumps(fields, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _checklist_undo_ttl_remaining_ms(session_id: str) -> int:
    snap = checklist_undo_snapshots.get(session_id)
    if not snap:
        return 0
    remaining = CHECKLIST_UNDO_TTL_SEC - (time() - float(snap.get("created_at") or 0))
    return max(0, int(remaining * 1000))


def _get_checklist_undo_snapshot_valid(session_id: str) -> tuple[dict | None, str]:
    """Return (snapshot, status) where status is valid | expired | missing | empty."""
    snap = checklist_undo_snapshots.get(session_id)
    if not snap:
        return None, "missing"
    age = time() - float(snap.get("created_at") or 0)
    if age > CHECKLIST_UNDO_TTL_SEC:
        checklist_undo_snapshots.pop(session_id, None)
        pending_checklist_undo_context.pop(session_id, None)
        _emit_undo_routing_log(
            "checklist_undo_failed_expired",
            session_id=(session_id or "")[:64],
            snapshot_id=str(snap.get("snapshot_id") or ""),
            decision_reason="ttl_expired",
        )
        return None, "expired"
    if _checklist_undo_snapshot_item_count(snap) <= 0:
        checklist_undo_snapshots.pop(session_id, None)
        pending_checklist_undo_context.pop(session_id, None)
        _emit_undo_routing_log(
            "checklist_undo_failed_empty_snapshot",
            session_id=(session_id or "")[:64],
            snapshot_id=str(snap.get("snapshot_id") or ""),
            decision_reason="empty_snapshot",
        )
        return None, "empty"
    return snap, "valid"


def _undo_clarification_spoken(session_id: str) -> str:
    _snap, status = _get_checklist_undo_snapshot_valid(session_id)
    if status == "valid":
        return "Restored the checklist."
    return "I don't have a recent checklist change to undo."


def resolve_checklist_undo_shortcut(
    session_id: str,
    text: str,
    client_context_snapshot: dict | None = None,
) -> tuple[str, float, dict] | None:
    """High-priority undo routing after checklist clear/erase/delete.

    When the user says undo/restore phrasing:
    - valid snapshot -> checklist.undo_clear
    - otherwise -> spoken clarification (never music volume)
    """
    if not is_checklist_undo_followup(text):
        return None

    norm = (text or "").strip().lower()
    recent = get_recent_action_context(session_id) or {}
    recent_domain = str(recent.get("action_name") or "").split(".")[0]
    snap, snap_status = _get_checklist_undo_snapshot_valid(session_id)
    client_snap = None
    if snap_status != "valid":
        client_snap = _checklist_undo_snapshot_from_client_context(client_context_snapshot)
        if client_snap:
            checklist_undo_snapshots[session_id] = client_snap
            snap, snap_status = client_snap, "valid"
    ttl_ms = _checklist_undo_ttl_remaining_ms(session_id)
    pending_ctx = pending_checklist_undo_context.get(session_id) or {}
    items_now, _collapsed_now, _owner = _load_checklist_state_for_session(session_id)
    current_count = len(_checklist_undo_non_empty_items(items_now))
    base_log = {
        "raw_text": (text or "")[:200],
        "normalized_text": norm[:200],
        "recent_action_domain": recent_domain,
        "pending_undo_domain": "checklist" if snap_status == "valid" else "",
        "checklist_snapshot_exists": snap_status != "missing",
        "checklist_undo_ttl_remaining_ms": ttl_ms,
    }
    _emit_undo_routing_log(
        "undo_intent_detected",
        **base_log,
        decision_reason="undo_phrase_matched",
    )
    _emit_undo_routing_log(
        "checklist_undo_lookup",
        session_id=(session_id or "")[:64],
        pending_undo_exists=bool(pending_ctx),
        snapshot_id=str((snap or {}).get("snapshot_id") or pending_ctx.get("snapshot_id") or ""),
        snapshot_exists=snap_status == "valid",
        snapshot_item_count=_checklist_undo_snapshot_item_count(snap),
        ttl_remaining_ms=ttl_ms,
        current_checklist_item_count=current_count,
        snap_status=snap_status,
        client_snapshot_hydrated=bool(client_snap),
        decision_reason="checklist_snapshot_probe",
    )
    _emit_undo_routing_log(
        "undo_context_candidates",
        **base_log,
        candidates=[{"domain": "checklist", "status": snap_status}],
        decision_reason="checklist_snapshot_probe",
    )

    if snap_status == "valid":
        _emit_undo_routing_log(
            "checklist_undo_context_valid",
            **base_log,
            selected_undo_domain="checklist",
            decision_reason="valid_snapshot",
        )
        _emit_undo_routing_log(
            "checklist_undo_restore_attempt",
            session_id=(session_id or "")[:64],
            snapshot_id=str((snap or {}).get("snapshot_id") or ""),
            snapshot_item_count=_checklist_undo_snapshot_item_count(snap),
        )
        ar = _handle_checklist_action(
            session_id, text, "checklist.undo_clear", client_context_snapshot
        )
        _emit_undo_routing_log(
            "checklist_undo_dispatched",
            **base_log,
            selected_undo_domain="checklist",
            decision_reason="restored_after_clear",
        )
        return action_result_reply(ar) or "", 0.0, ar

    if snap_status == "expired":
        _emit_undo_routing_log(
            "checklist_undo_context_expired",
            **base_log,
            decision_reason="ttl_expired",
        )
        spoken = "I don't have a recent checklist change to undo."
    elif snap_status == "empty":
        _emit_undo_routing_log(
            "checklist_undo_failed_empty_snapshot",
            **base_log,
            decision_reason="empty_snapshot",
        )
        spoken = "I don't have a recent checklist change to undo."
    else:
        _emit_undo_routing_log(
            "checklist_undo_failed_no_snapshot",
            **base_log,
            decision_reason="no_valid_checklist_snapshot",
        )
        spoken = "I don't have a recent checklist change to undo."

    if recent_domain == "music":
        _emit_undo_routing_log(
            "undo_wrong_domain_blocked",
            **base_log,
            blocked_domain="music",
            decision_reason="undo_clarify_instead_of_music",
        )

    ar = {
        "spoken_reply": spoken,
        "action_type": "clarification",
        "data": {"undo_clarification": True, "checklist_snapshot_status": snap_status},
        "ui_payload": None,
    }
    return spoken, 0.0, ar


def peek_checklist_undo_action_name(
    session_id: str,
    text: str,
    client_context_snapshot: dict | None = None,
) -> str | None:
    if not is_checklist_undo_followup(text):
        return None
    _snap, status = _get_checklist_undo_snapshot_valid(session_id)
    if status == "valid":
        return "checklist.undo_clear"
    if pending_checklist_undo_context.get(session_id):
        return "checklist.undo_clear"
    if _checklist_undo_snapshot_from_client_context(client_context_snapshot):
        return "checklist.undo_clear"
    return None
# Current-session memory of facts the user volunteered ("I like tennis", "my name is Sarah").
# Persists for the lifetime of the session_id, not across logins/devices. When Supabase
# accounts arrive, prefer reading/writing the same shape from `user_profile['session_facts']`
# keyed by user_id so this becomes durable per account.
session_user_facts: dict[str, dict] = {}
# Normal Voice UI follow-ups: remember an action VERA *offered* in her last reply
# ("I can give you the latest headlines on it"). Short affirmatives in the next
# turn ("yes please", "can you please do?") resolve to this offered action.
# Per session_id; expires after VOICE_OFFER_TTL_SEC.
pending_voice_actions: dict[str, dict] = {}
VOICE_OFFER_TTL_SEC = 120
# News topic context after any news.latest result. Used to (a) resolve corrective
# follow-ups ("wait, I thought Musk and Huang were on that trip") via entity overlap,
# and (b) answer source requests ("show me the sources") without a new fetch.
recent_news_context: dict[str, dict] = {}
NEWS_CONTEXT_TTL_SEC = 600
# Recent sports topic context, used to resolve follow-ups like
# "how about Sinner?" or "who did they play?" without re-asking the user for
# the team/player/tournament. Keyed by session_id; TTL-protected via
# SPORTS_CONTEXT_TTL_SEC and pruned in cleanup_sessions(). See
# actions.sports.classify_sports_intent for the consumer.
recent_sports_context: dict[str, dict] = {}
SPORTS_CONTEXT_TTL_SEC = 600
# Work mode only: last spoken "due in …" deadline for reminder-at-minus-10-minutes behavior.
work_mode_timer_plans: dict[str, dict] = {}
WORK_MODE_TIMER_EARLY_SEC = 600

# Multi-device-concurrency PART 3 + PART 7:
# `vera.active_user_info_path` is process-global, so two devices signed in as
# different users would corrupt each other's checklist/known_facts. This map
# overlays a per-session active user that takes precedence over the global
# field. The global field stays around for single-user backward compat (CLI
# tests, the first device to sign in still wins for unscoped legacy code).
#
# Lifecycle: written by /api/user/sign-in when a `session_id` is supplied,
# cleared by /api/user/sign-out for the same session_id, and aged out by
# cleanup_sessions() once user_last_seen forgets the session.
_session_active_user: dict[str, str | None] = {}  # session_id -> username stem or None


def set_active_user_for_session(session_id: str, username_stem: str | None) -> None:
    sid = safe_id(session_id or "")
    if not sid:
        return
    if username_stem:
        _session_active_user[sid] = username_stem
    else:
        _session_active_user.pop(sid, None)


def get_active_username_for_session(session_id: str | None) -> str | None:
    """Prefer the per-session active user; fall back to the process-global one.

    The fallback exists so single-user setups (CLI, first sign-in before
    /api/user/sign-in started passing session_id) still resolve a username.
    Multi-device deployments should always pass session_id to sign-in.
    """
    if session_id:
        sid = safe_id(session_id)
        if sid in _session_active_user:
            return _session_active_user[sid]
    return _active_username_from_runtime()

# =========================
# HELPERS
# =========================

def safe_id(value: str) -> str:
    return "".join(c for c in value if c.isalnum() or c in ("_", "-"))

def today():
    return datetime.now().strftime("%Y-%m-%d")

def timestamp():
    return datetime.now().strftime("%H-%M-%S")

def cleanup_sessions():
    now = time()
    expired = [
        sid for sid, last in user_last_seen.items()
        if now - last > SESSION_TTL
    ]
    for sid in expired:
        user_histories.pop(sid, None)
        reasoning_global_memory.pop(sid, None)
        session_user_facts.pop(sid, None)
        pending_voice_actions.pop(sid, None)
        recent_news_context.pop(sid, None)
        recent_sports_context.pop(sid, None)
        for key in [k for k in list(reasoning_lane_histories.keys()) if str(k).startswith(f"{sid}:")]:
            reasoning_lane_histories.pop(key, None)
        for key in [k for k in list(reasoning_lane_upload_plain_chain.keys()) if str(k).startswith(f"{sid}:")]:
            reasoning_lane_upload_plain_chain.pop(key, None)
        user_last_seen.pop(sid, None)
        pending_action.pop(sid, None)
        recent_action_context.pop(sid, None)
        latest_client_context_snapshot.pop(sid, None)
        anonymous_work_mode_checklists.pop(sid, None)
        checklist_undo_snapshots.pop(sid, None)
        pending_checklist_undo_context.pop(sid, None)
        work_mode_timer_plans.pop(sid, None)
        # These were never pruned → unbounded growth and slower dict/GC over days.
    expired_pending = [
        sid for sid, state in pending_action.items()
        if state.get("expires_at", 0) < now
    ]
    for sid in expired_pending:
        pending_action.pop(sid, None)

    expired_recent = [
        sid for sid, state in recent_action_context.items()
        if now - state.get("updated_at", now) > RECENT_ACTION_TTL
    ]
    for sid in expired_recent:
        recent_action_context.pop(sid, None)

    expired_snapshot = [sid for sid in latest_client_context_snapshot.keys() if sid not in user_last_seen]
    for sid in expired_snapshot:
        latest_client_context_snapshot.pop(sid, None)
    expired_anon_checklists = [sid for sid in anonymous_work_mode_checklists.keys() if sid not in user_last_seen]
    for sid in expired_anon_checklists:
        anonymous_work_mode_checklists.pop(sid, None)
    expired_sess_users = [sid for sid in _session_active_user.keys() if sid not in user_last_seen]
    for sid in expired_sess_users:
        _session_active_user.pop(sid, None)

def zero_crossing_rate(samples: np.ndarray) -> float:
    return np.mean(samples[:-1] * samples[1:] < 0)

def voiced_duration(samples: np.ndarray, sr: int, thresh: float) -> float:
    mask = np.abs(samples) > thresh
    if not mask.any():
        return 0.0
    idx = np.where(mask)[0]
    return (idx[-1] - idx[0]) / sr

def spectral_ratio(samples, sr):
    spec = np.abs(np.fft.rfft(samples))
    freqs = np.fft.rfftfreq(len(samples), 1/sr)

    low = spec[(freqs >= 80) & (freqs <= 500)].mean()
    high = spec[(freqs >= 2000) & (freqs <= 6000)].mean()

    return high / (low + 1e-6)


# ===========================================================================
# PART 9 + 10 — server-side equivalents of the JS chooseBestTranscript and
# normalizeCommandTranscript. Kept algorithmically identical (small edit
# distance, token overlap, length ratio) so client + server agree on what
# the "selected" transcript should be for any given browser/whisper pair.
# ===========================================================================

def _asr_normalize_for_compare(s: str) -> str:
    s = (s or "").lower()
    s = re.sub(r"[^a-z0-9\s]+", " ", s)
    return re.sub(r"\s+", " ", s).strip()


def _asr_levenshtein(a: str, b: str) -> int:
    a = a or ""
    b = b or ""
    if not a:
        return len(b)
    if not b:
        return len(a)
    if len(a) > 1000 or len(b) > 1000:
        return max(len(a), len(b))
    prev = list(range(len(b) + 1))
    curr = [0] * (len(b) + 1)
    for i in range(1, len(a) + 1):
        curr[0] = i
        for j in range(1, len(b) + 1):
            cost = 0 if a[i - 1] == b[j - 1] else 1
            curr[j] = min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost)
        prev, curr = curr, prev
    return prev[len(b)]


def _asr_token_overlap_ratio(a: str, b: str) -> float:
    at = set(_asr_normalize_for_compare(a).split())
    bt = set(_asr_normalize_for_compare(b).split())
    if not at or not bt:
        return 0.0
    return len(at & bt) / max(len(at), len(bt))


def _asr_looks_hallucinated(s: str) -> bool:
    t = _asr_normalize_for_compare(s)
    if not t:
        return False
    toks = t.split()
    if len(toks) < 3:
        return False
    uniq = len(set(toks))
    return (uniq / len(toks)) < 0.34


def choose_best_transcript(
    browser_transcript: str,
    whisper_transcript: str,
    whisper_confidence: float | None = None,
) -> dict:
    """Server-side selector. See chooseBestTranscript() in app.js for the
    mirrored client implementation. Both must stay in sync."""
    browser = (browser_transcript or "").strip()
    whisper = (whisper_transcript or "").strip()
    if not browser and not whisper:
        return {
            "selected": "",
            "source": "empty_both",
            "edit_distance": 0,
            "length_ratio": 0.0,
            "token_overlap": 0.0,
            "reason": "both_empty",
        }
    if browser and not whisper:
        return {
            "selected": browser,
            "source": "hybrid_browser",
            "edit_distance": len(browser),
            "length_ratio": 0.0,
            "token_overlap": 0.0,
            "reason": "whisper_empty",
        }
    if whisper and not browser:
        return {
            "selected": whisper,
            "source": "hybrid_whisper",
            "edit_distance": len(whisper),
            "length_ratio": 0.0,
            "token_overlap": 0.0,
            "reason": "browser_empty",
        }
    nb = _asr_normalize_for_compare(browser)
    nw = _asr_normalize_for_compare(whisper)
    ed = _asr_levenshtein(nb, nw)
    len_ratio = (len(nw) / len(nb)) if nb else (float("inf") if nw else 1.0)
    overlap = _asr_token_overlap_ratio(nb, nw)

    if _asr_looks_hallucinated(whisper):
        return {
            "selected": browser,
            "source": "hybrid_browser",
            "edit_distance": ed,
            "length_ratio": len_ratio,
            "token_overlap": overlap,
            "reason": "whisper_looks_hallucinated",
        }
    if (
        whisper_confidence is not None
        and isinstance(whisper_confidence, (int, float))
        and whisper_confidence < 0.35
        and len_ratio < 0.6
    ):
        return {
            "selected": browser,
            "source": "hybrid_browser",
            "edit_distance": ed,
            "length_ratio": len_ratio,
            "token_overlap": overlap,
            "reason": "whisper_low_conf_and_short",
        }
    if len_ratio < 0.55 and overlap < 0.55 and len(nb) > 18:
        return {
            "selected": browser,
            "source": "hybrid_browser",
            "edit_distance": ed,
            "length_ratio": len_ratio,
            "token_overlap": overlap,
            "reason": "whisper_truncated",
        }
    return {
        "selected": whisper,
        "source": "hybrid_whisper",
        "edit_distance": ed,
        "length_ratio": len_ratio,
        "token_overlap": overlap,
        "reason": "prefer_whisper_default",
    }


_ASR_COMMAND_NORMALIZATIONS = [
    (re.compile(r"\b(?:sing|sink|seing|saink|cinq|seink)\s+the\s+plan\b", re.IGNORECASE),
        "sync the plan", "sync_plan_mishear"),
    (re.compile(r"\bsing\s+(?:my|the)\s+(?:plan|tasks|todo)\b", re.IGNORECASE),
        "sync the plan", "sync_plan_mishear"),
    (re.compile(r"\bnew\s+spanel\b", re.IGNORECASE), "news panel", "news_panel_mishear"),
    (re.compile(r"\bnews\s+spanel\b", re.IGNORECASE), "news panel", "news_panel_mishear"),
    (re.compile(r"\b(?:recent|reason|raisen|raising)\s+panel\b", re.IGNORECASE),
        "reasoning panel", "reasoning_panel_mishear"),
    (re.compile(r"\breason(?:ing)?\s+pan\b", re.IGNORECASE), "reasoning panel", "reasoning_panel_mishear"),
    (re.compile(r"\bcheck\s+list\b", re.IGNORECASE), "checklist", "checklist_word_split"),
    (re.compile(r"\bwork\s+(?:mood|moods|moot)\b", re.IGNORECASE), "Work Mode", "work_mode_mishear"),
    (re.compile(r"\bopen\s*a\s*i\b", re.IGNORECASE), "OpenAI", "openai_word_split"),
    (re.compile(r"\bbeem\s+o\b", re.IGNORECASE), "BMO", "bmo_mishear"),
    (re.compile(r"\bvera\s+(?:mood|moot)\b", re.IGNORECASE), "Vera Mode", "vera_mode_mishear"),
]

_ASR_STATE_CHANGING_RE = re.compile(
    r"\b(?:sync|create|delete|remove|update|rename|cancel|schedule|set|change|move|"
    r"copy|email|send|save|file|attach|upload|download|run|execute|start|stop|"
    r"pause|resume|reset|toggle|enable|disable|export|import)\b",
    re.IGNORECASE,
)
_ASR_GENERIC_COMMAND_VERB_RE = re.compile(
    r"\b(?:open|close|show|hide|switch|select|play|pause|resume|skip|mute|unmute|"
    r"delete|remove|cross\s+off|sync|create|add|new|next|previous|continue|"
    r"go\s+to|jump\s+to)\b",
    re.IGNORECASE,
)


def normalize_command_transcript(text: str, *, force_command_context: bool = False) -> dict:
    """Conservatively rewrite common VERA-domain mishears. Only applies when
    the utterance looks like a command — never touches general conversation.
    See normalizeCommandTranscript() in app.js for the mirrored client
    implementation.

    Gate (in priority order):
      1. force_command_context: caller asserts command intent.
      2. The text contains a state-changing verb (sync, create, delete, ...)
         or a generic command verb (open, close, switch, play, ...).
      3. The text matches one of the known-vocabulary mishear patterns
         (e.g. "sing the plan", "new spanel"). Self-authorized because the
         *corrected* form is a command verb by construction — refusing here
         would lose the entire purpose of this function for the most
         common mishear cases.
    """
    t = text or ""
    if not t:
        return {"normalized": t, "applied": False, "corrections": [], "reason": "empty"}

    matches_known_mishear = any(pat.search(t) for pat, _, _ in _ASR_COMMAND_NORMALIZATIONS)
    looks_like_command = (
        bool(_ASR_STATE_CHANGING_RE.search(t))
        or bool(_ASR_GENERIC_COMMAND_VERB_RE.search(t))
        or force_command_context
        or matches_known_mishear
    )
    if not looks_like_command:
        return {"normalized": t, "applied": False, "corrections": [], "reason": "no_command_context"}
    out = t
    corrections: list[dict] = []
    for pat, repl, why in _ASR_COMMAND_NORMALIZATIONS:
        if pat.search(out):
            before = out
            out = pat.sub(repl, out)
            if out != before:
                corrections.append({"pattern": pat.pattern, "replacement": repl, "why": why})
    return {
        "normalized": out,
        "applied": bool(corrections),
        "corrections": corrections,
        "reason": "command_vocab_correction" if corrections else "no_match",
    }


def log_asr_pipeline_decision(payload: dict) -> None:
    """Structured single-line log for PART 16 of the ASR-mode spec."""
    try:
        print("[asr_pipeline_debug] " + json.dumps(payload, ensure_ascii=False), flush=True)
    except Exception:
        try:
            print("[asr_pipeline_debug] log_serialization_failed", flush=True)
        except Exception:
            pass


def get_pending_action(session_id: str):
    state = pending_action.get(session_id)
    if not state:
        return None

    if state.get("expires_at", 0) < time():
        pending_action.pop(session_id, None)
        return None

    return state


def set_pending_action(session_id: str, action_name: str, missing_slot: str, slots: dict | None = None):
    pending_action[session_id] = {
        "action_name": action_name,
        "missing_slot": missing_slot,
        "slots": slots or {},
        "expires_at": time() + PENDING_ACTION_TTL,
    }


def clear_pending_action(session_id: str):
    pending_action.pop(session_id, None)


def get_recent_action_context(session_id: str):
    state = recent_action_context.get(session_id)
    if not state:
        return None

    if time() - state.get("updated_at", 0) > RECENT_ACTION_TTL:
        recent_action_context.pop(session_id, None)
        return None

    return state


def set_recent_action_context(session_id: str, action_name: str, slots: dict, result: dict):
    recent_action_context[session_id] = {
        "action_name": action_name,
        "slots": slots or {},
        "result": result,
        "updated_at": time(),
    }


def action_result_reply(action_result: dict | None) -> str | None:
    if not action_result:
        return None
    return action_result.get("spoken_reply")


def extract_short_followup_value(text: str) -> str | None:
    raw = text.strip().strip(string.punctuation + " ")
    if not raw:
        return None

    has_followup_prefix = bool(
        re.match(
            r"^(how about|what about|and|about|then|instead|for|actually(?:,\s*)?i meant|i meant|no,?\s*i meant)\b",
            raw,
            flags=re.IGNORECASE,
        )
    )
    if not has_followup_prefix:
        return None

    cleaned = raw
    cleaned = re.sub(
        r"^(how about|what about|and|about|then|instead|for|actually(?:,\s*)?i meant|i meant|no,?\s*i meant)\s+",
        "",
        cleaned,
        flags=re.IGNORECASE,
    )
    cleaned = re.sub(
        r"\s+(?:as well|too|also|right now|for me|please)\s*$",
        "",
        cleaned,
        flags=re.IGNORECASE,
    )
    cleaned = cleaned.strip().strip(string.punctuation + " ")
    if not cleaned:
        return None

    words = cleaned.lower().split()
    if len(words) > 4:
        return None

    return cleaned


def is_i_meant_followup(text: str) -> bool:
    raw = (text or "").strip().strip(string.punctuation + " ")
    if not raw:
        return False
    return bool(
        re.match(
            r"^(?:actually(?:,\s*)?i meant|i meant|no,?\s*i meant)\b",
            raw,
            flags=re.IGNORECASE,
        )
    )


# Subject-correction patterns used by both finance-correction paths:
#   - same-message:   "... biggest drawdown of bgt in the past 5 years I said vgt"
#   - next-message:   "I said VGT" / "I meant VGT" / "no, VGT" / "not BGT, VGT"
# The capture group is the corrected subject (ticker / company name / etc.).
_FINANCE_CORRECTION_PATTERNS = (
    # "I said VGT" / "i said it's VGT" / "i was saying VGT"
    r"\bi\s+(?:said|meant|was\s+saying|am\s+saying)\s+(?:it[''']?s\s+|that[''']?s\s+|the\s+)?([A-Za-z][A-Za-z0-9.&'\- ]{0,40})\b",
    # "actually VGT" / "actually it's VGT"
    r"\bactually\s*[,:]?\s*(?:it[''']?s\s+|that[''']?s\s+)?([A-Za-z][A-Za-z0-9.&'\- ]{0,40})\b",
    # "not BGT, VGT" / "not BGT but VGT" / "not BGT - VGT" / "not BGT VGT"
    r"\bnot\s+[A-Za-z0-9.&'\-]{1,30}[\s,;:\u2014\-]+(?:but\s+|rather\s+|i\s+mean\s+|but\s+rather\s+)?([A-Za-z][A-Za-z0-9.&'\- ]{0,40})\b",
    # "no, VGT" / "no I meant VGT"
    r"\bno[,\s]+(?:i\s+(?:said|meant|was\s+saying)\s+)?([A-Za-z][A-Za-z0-9.&'\- ]{1,40})\b",
)


_FINANCE_CORRECTION_NOISE_WORDS = {
    # words that look like a correction subject but aren't a real one
    "yes", "no", "yeah", "yep", "nope", "sure", "ok", "okay",
    "sorry", "actually", "thanks", "thank", "you", "me", "we",
    "that", "this", "it", "the", "a", "an",
    "i", "im", "i'm",
    "stock", "stocks", "share", "shares", "ticker", "etf", "fund", "company",
    "instead", "again", "now",
    # Indefinite pronouns and similar fillers that can follow "I said" but
    # are clearly not a ticker / company name.
    "something", "anything", "everything", "nothing", "someone", "anyone",
    "everyone", "no one", "somebody", "anybody", "everybody", "nobody",
    "what", "who", "when", "where", "why", "how",
    "rather", "but", "and", "or",
}


def _looks_like_finance_subject_candidate(s: str) -> bool:
    """Cheap validation for a captured correction subject.

    A real subject is short, alphanumeric (allowing spaces, dots, dashes),
    and not in the stoplist above. Tickers are 1-5 letters; company names
    are usually 1-3 words.
    """
    cleaned = (s or "").strip().strip(string.punctuation + " ")
    if not cleaned or len(cleaned) > 40:
        return False
    low = cleaned.lower()
    if low in _FINANCE_CORRECTION_NOISE_WORDS:
        return False
    if not re.search(r"[A-Za-z]", cleaned):
        return False
    # Don't let an obvious sentence verb-phrase through ("said something")
    if re.match(r"(?i)^(?:said|meant|saying|wanted|trying)\b", cleaned):
        return False
    # Reject multi-word candidates whose FIRST word is a noise word —
    # captures like "something else", "anyone here", "the next one" should not
    # be treated as a corrected ticker.
    tokens = re.split(r"\s+", cleaned)
    if tokens and tokens[0].lower() in _FINANCE_CORRECTION_NOISE_WORDS:
        return False
    return True


def extract_finance_correction_subject(text: str) -> str | None:
    """Find a corrected ticker/company name in a self-correction phrase.

    Returns the cleaned subject (still as the user spelled it — caller may
    upper-case it for tickers if desired), or None if no clear correction is
    present. Conservative: prefers the LAST plausible correction phrase in
    the text so "drawdown of BGT in 5 years I said VGT" returns VGT.
    """
    raw = (text or "").strip()
    if not raw:
        return None
    best: str | None = None
    for pat in _FINANCE_CORRECTION_PATTERNS:
        for m in re.finditer(pat, raw, flags=re.IGNORECASE):
            candidate = (m.group(1) or "").strip()
            # Trim trailing helper words ("instead", "actually", "now", "please")
            candidate = re.sub(
                r"\s+(?:instead|actually|now|please|sorry)\s*$",
                "",
                candidate,
                flags=re.IGNORECASE,
            ).strip(string.punctuation + " ")
            if _looks_like_finance_subject_candidate(candidate):
                best = candidate
    return best


def _strip_finance_correction_phrase(text: str) -> str:
    """Remove a trailing 'I said X / I meant X / no, X' phrase from text so
    downstream finance-subject extraction sees the original question without
    the correction tacked on. Conservative — only strips when followed by
    end-of-string or sentence punctuation."""
    raw = (text or "").rstrip()
    if not raw:
        return raw
    stripped = re.sub(
        r"\s*[,.\-;:\u2014]?\s*(?:i\s+(?:said|meant|was\s+saying|am\s+saying)|actually|no[,\s])"
        r"\s*[,:]?\s*(?:it[''']?s\s+|that[''']?s\s+|the\s+)?"
        r"[A-Za-z][A-Za-z0-9.&'\- ]{0,40}\s*[.!?]?\s*$",
        "",
        raw,
        flags=re.IGNORECASE,
    )
    return stripped.rstrip(string.punctuation + " ") or raw


def _normalized_reply_text(text: str | None) -> str:
    s = (text or "").strip().lower()
    s = re.sub(r"\s+", " ", s)
    return s.strip(string.punctuation + " ")


def _last_assistant_reply(history: list[dict]) -> str:
    for msg in reversed(history or []):
        if msg.get("role") == "assistant":
            return str(msg.get("content") or "")
    return ""


def should_allow_i_meant_recent_followup(recent: dict | None, history: list[dict]) -> bool:
    if not recent:
        return False

    allowed_actions = {"news.latest", "weather.current", "weather.followup", "time.current"}
    action_name = recent.get("action_name")
    if action_name not in allowed_actions:
        return False

    recent_reply = _normalized_reply_text(action_result_reply(recent.get("result")))
    last_assistant_reply = _normalized_reply_text(_last_assistant_reply(history))
    if not recent_reply or not last_assistant_reply:
        return False

    # Enforce "previous turn only": the latest assistant message must be the recent action reply.
    return recent_reply == last_assistant_reply


def clean_location_text(text: str | None) -> str:
    if text is None:
        return ""

    location = str(text).strip().strip(string.punctuation + " ")
    location = re.sub(r"^(in|for|at)\s+", "", location, flags=re.IGNORECASE)
    location = re.sub(
        r"\s+(?:as well|too|also|right now|for me|please)\s*$",
        "",
        location,
        flags=re.IGNORECASE,
    )
    return location.strip().strip(string.punctuation + " ")


def extract_weather_location(text: str) -> str | None:
    prefix = r"(?:hey vera[\s,]+|vera[\s,]+|can you\s+|could you\s+|would you\s+|please\s+)*"
    patterns = [
        rf"^{prefix}what(?:'s|s| is) the weather in (?P<location>.+)$",
        rf"^{prefix}what(?:'s|s| is) the weather like in (?P<location>.+)$",
        rf"^{prefix}tell me the weather in (?P<location>.+)$",
        rf"^{prefix}tell me what the weather is like in (?P<location>.+)$",
        rf"^{prefix}check the weather in (?P<location>.+)$",
        rf"^{prefix}current weather in (?P<location>.+)$",
        rf"^{prefix}how(?:'s|s| is) the weather in (?P<location>.+)$",
        rf"^{prefix}how(?:'s|s| is) the weather like in (?P<location>.+)$",
        rf"^{prefix}is it raining in (?P<location>.+)$",
        rf"^{prefix}is it rainy in (?P<location>.+)$",
        rf"^{prefix}is there rain in (?P<location>.+)$",
        rf"^{prefix}is it snowing in (?P<location>.+)$",
        rf"^{prefix}is it snowy in (?P<location>.+)$",
        rf"^{prefix}is there snow in (?P<location>.+)$",
        rf"^{prefix}is it sunny in (?P<location>.+)$",
        rf"^{prefix}is it clear in (?P<location>.+)$",
        rf"^{prefix}is it cloudy in (?P<location>.+)$",
        rf"^{prefix}is it overcast in (?P<location>.+)$",
        rf"^{prefix}is it foggy in (?P<location>.+)$",
        rf"^{prefix}is it humid in (?P<location>.+)$",
        rf"^{prefix}is it windy in (?P<location>.+)$",
        rf"^{prefix}how much rain is there in (?P<location>.+)$",
        rf"^{prefix}what(?:'s|s| is) the precipitation in (?P<location>.+)$",
        rf"^{prefix}weather for (?P<location>.+)$",
        rf"^{prefix}weather in (?P<location>.+)$",
    ]

    for pattern in patterns:
        match = re.match(pattern, text.strip(), flags=re.IGNORECASE)
        if not match:
            continue

        location = clean_location_text(match.group("location"))
        if location:
            try:
                from actions.weather_query_parse import strip_weather_time_from_location

                location = strip_weather_time_from_location(location)
            except Exception:
                pass
            if location:
                return location

    return None


def _weather_clarification_prompt(missing_slot: str, *, near_me: bool = False) -> str:
    if near_me and missing_slot in ("location", "both"):
        return "I don't have your location yet. Which city should I check the forecast for?"
    if missing_slot == "both":
        return WEATHER_FORECAST_BOTH_PROMPT
    if missing_slot == "time":
        return WEATHER_FORECAST_TIME_PROMPT
    return WEATHER_FORECAST_LOCATION_PROMPT


def _weather_pending_slots_from_parsed(text: str, parsed: dict) -> dict:
    q = parsed.get("query") or {}
    return {
        "user_text": (text or "").strip(),
        "location": clean_location_text(parsed.get("location") or ""),
        "time_kind": q.get("time_kind"),
        "time_label": q.get("time_label"),
        "intent": parsed.get("intent") or "general",
        "parsed_weather": dict(parsed),
    }


def _log_weather_forecast_clarify(missing_slot: str, parsed: dict) -> None:
    try:
        q = parsed.get("query") or {}
        print(
            "[weather_forecast_clarify] "
            + json.dumps(
                {
                    "missing": missing_slot,
                    "time_kind": q.get("time_kind"),
                    "time_label": q.get("time_label"),
                    "intent": parsed.get("intent") or "general",
                    "location": parsed.get("location"),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _log_weather_forecast_pending_store(session_id: str, missing_slot: str, slots: dict) -> None:
    try:
        print(
            "[weather_forecast_pending_store] "
            + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "type": "weather.forecast",
                    "missing": missing_slot,
                    "pending_payload": {
                        "location": slots.get("location") or None,
                        "time_kind": slots.get("time_kind"),
                        "time_label": slots.get("time_label"),
                        "intent": slots.get("intent") or "general",
                        "user_text": str(slots.get("user_text") or "")[:240],
                    },
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _weather_query_has_forecast_time(q: dict) -> bool:
    time_kind = str((q or {}).get("time_kind") or "now").strip()
    return time_kind not in ("now", "multi_day")


def _log_weather_forecast_pending_resolve(
    user_reply: str,
    *,
    resolved_location: str = "",
    resolved_time: str = "",
    missing_slot: str = "",
    action: str = "weather.forecast",
) -> None:
    try:
        print(
            "[weather_forecast_pending_resolve] "
            + json.dumps(
                {
                    "user_reply": str(user_reply or "")[:240],
                    "missing_slot": missing_slot or None,
                    "resolved_location": resolved_location or None,
                    "resolved_time_label": resolved_time or None,
                    "action": action,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def weather_action_route_from_text(
    text: str,
    *,
    location_hint: str = "",
    session_id: str = "",
) -> dict:
    """Build a structured weather route (current vs forecast) from user text."""
    parsed = parse_weather_query(text or "")
    if session_id:
        parsed = apply_recent_weather_context_to_parsed(
            text,
            parsed,
            get_recent_action_context(session_id),
        )
    parsed_loc = clean_location_text(parsed.get("location") or "")
    hint_loc = clean_location_text(location_hint)
    if hint_loc and not parsed_loc and not parsed.get("needs_location"):
        parsed_loc = hint_loc
        parsed = {
            **parsed,
            "location": hint_loc,
            "location_kind": "explicit",
            "needs_location": False,
            "missing_fields": [m for m in (parsed.get("missing_fields") or []) if m != "location"],
            "needs_time": "time" in (parsed.get("missing_fields") or []),
        }
    loc = parsed_loc or hint_loc
    action_name = parsed.get("action_name") or "weather.current"
    missing_fields = list(parsed.get("missing_fields") or [])
    if parsed.get("needs_location") and "location" not in missing_fields:
        missing_fields.insert(0, "location")
    if parsed.get("needs_time") and "time" not in missing_fields:
        missing_fields.append("time")

    needs_followup = bool(missing_fields) and action_name == "weather.forecast"
    missing_slot = None
    if needs_followup:
        if "location" in missing_fields and "time" in missing_fields:
            missing_slot = "both"
        elif "time" in missing_fields:
            missing_slot = "time"
        else:
            missing_slot = "location"

    q = parsed.get("query") or {}
    slots = {
        "location": loc,
        "user_text": (text or "").strip(),
        "time_kind": q.get("time_kind"),
        "time_label": q.get("time_label"),
        "intent": parsed.get("intent") or "general",
        "parsed_weather": dict(parsed),
    }
    return {
        "domain": "weather",
        "is_action_request": True,
        "action_name": action_name,
        "slots": slots,
        "needs_followup": needs_followup,
        "missing_slot": missing_slot,
        "_parsed_weather": parsed,
    }


def is_plausible_location(text: str) -> bool:
    location = clean_location_text(text)
    if not location or len(location) > 80:
        return False

    if not re.search(r"[A-Za-z]", location):
        return False

    lowered = location.lower()
    if lowered in {
        "pause",
        "unpause",
        "resume",
        "stop",
        "cancel",
        "never mind",
        "nevermind",
    }:
        return False

    if any(phrase in lowered for phrase in ["what time", "what date", "the news", "the weather"]):
        return False

    return True


def resolve_pending_web_search_request(
    session_id: str, text: str, pending: dict, filler_generation: int | None = None
):
    """Resolve a pending ``web.search`` whose location slot was missing.

    Combines the original query (saved in the pending slots) with the
    user's freshly-provided location text and dispatches the web-search
    action. Mirrors `resolve_pending_weather_request`.

    2026-05-28 — IMPORTANT: we pass the *combined* query as
    ``raw_user_text`` to ``handle_web_search_request`` so that
    ``classify_web_search_panel`` sees the explicit city and returns
    ``panel_type=location_map_panel`` with ``location_required=False``.
    Passing the original ("coffee shops near me") would re-trigger the
    clarification branch and we'd silently skip fetching places — which
    was the exact "answers in chat but never opens the panel" bug.
    """
    clear_pending_action(session_id)
    prior_slots = dict(pending.get("slots") or {})
    original_query = (
        prior_slots.get("query")
        or prior_slots.get("user_text")
        or ""
    ).strip()
    extracted_location = (text or "").strip()
    try:
        extracted = vera.extract_location_slot(text)
        loc_guess = clean_location_text(extracted.get("location"))
        if loc_guess:
            extracted_location = loc_guess
    except Exception:
        pass
    if extracted_location:
        try:
            from actions.web_search import _normalize_city_for_display as _norm_city
            extracted_location = _norm_city(extracted_location) or extracted_location
        except Exception:
            pass
    if not extracted_location:
        try:
            from actions.web_search import _log_place_panel as _log_pp
            _log_pp(
                query=original_query,
                place_query_detected=True,
                location_required=True,
                location_available=False,
                pending_place_query_resolved=False,
                place_search_query="",
                places_count=0,
                map_pins_count=0,
                location_panel_created=False,
                pending_original_text=original_query,
                note="pending_resolve_no_location_extracted_reasking",
            )
        except Exception:
            pass
        # Re-arm the pending action so the *next* reply can resolve it; the
        # bug-shaped behavior here used to be "drop the pending state on the
        # floor and answer with the bare prompt forever".
        set_pending_action(session_id, "web.search", "location", prior_slots)
        return {
            "spoken_reply": "I still didn't catch a location — what city or area should I search near?",
            "action_type": "web_search",
            "data": None,
            "ui_payload": None,
        }, 0.0

    # Rebuild the query so it carries the location explicitly. We strip
    # "near me" / "nearby" from the original ask if present so the resulting
    # search string reads naturally ("coffee shops in Irvine").
    base_query = re.sub(
        r"\s*\b(?:near\s+me|nearby|around\s+here|around\s+me|close\s+to\s+me)\b\s*",
        " ",
        original_query,
        flags=re.IGNORECASE,
    ).strip()
    if not base_query:
        base_query = original_query
    combined_query = (
        f"{base_query} in {extracted_location}"
        if base_query
        else extracted_location
    )

    try:
        from actions.web_search import _log_place_panel as _log_pp
        from actions.web_search import extract_venue_category as _evc
        _log_pp(
            query=original_query,
            place_query_detected=True,
            location_required=False,
            location_available=True,
            pending_place_query_resolved=True,
            place_search_query=combined_query,
            places_count=0,  # populated again after the search runs
            map_pins_count=0,
            location_panel_created=False,
            pending_category=_evc(original_query),
            pending_original_text=original_query,
            resolved_location=extracted_location,
            note="pending_resolve_dispatching_to_handle_web_search_request",
        )
    except Exception:
        pass

    t0 = perf_counter()
    action_result = handle_web_search_request(
        vera,
        query=combined_query,
        # Pass combined_query (not original_query) as raw_user_text so the
        # classifier sees the location and routes to location_map_panel.
        raw_user_text=combined_query,
    )
    if action_result.get("data"):
        set_recent_action_context(
            session_id,
            "web.search",
            {"query": combined_query, "location": extracted_location},
            action_result,
        )
    return action_result, perf_counter() - t0


def resolve_pending_weather_forecast_request(session_id: str, text: str, pending: dict | None = None):
    pending = pending or {}
    prior_slots = dict(pending.get("slots") or {})
    missing_slot = str(pending.get("missing_slot") or "location").strip().lower()
    prior_parsed = dict(
        prior_slots.get("parsed_weather")
        or parse_weather_query(prior_slots.get("user_text") or "")
    )
    reply_parsed = parse_weather_query(text or "")
    merged = dict(prior_parsed)

    if missing_slot in ("location", "both"):
        extracted = vera.extract_location_slot(text)
        location = clean_location_text(extracted.get("location"))
        if not location:
            location = clean_location_text(reply_parsed.get("location") or "")
        if not location:
            location = extract_weather_location(text) or clean_location_text(text)
        location = strip_weather_time_from_location(location) if location else ""
        if location and is_plausible_location(location):
            merged["location"] = location
            merged["location_kind"] = "explicit"
        elif missing_slot in ("location", "both") and not merged.get("location"):
            return {
                "spoken_reply": WEATHER_LOCATION_INVALID_REPLY,
                "action_type": "weather_forecast",
                "data": None,
                "ui_payload": None,
            }, 0.0

    if missing_slot in ("time", "both"):
        merged = merge_weather_parsed(
            merged,
            reply_parsed,
            merge_time=True,
            merge_location=missing_slot == "both",
        )
    elif missing_slot == "location":
        merged = merge_weather_parsed(
            merged,
            reply_parsed,
            merge_time=False,
            merge_location=False,
        )

    location = clean_location_text(strip_weather_time_from_location(merged.get("location") or ""))
    q = merged.get("query") or {}
    has_time = _weather_query_has_forecast_time(q)

    if q.get("beyond_horizon"):
        clear_pending_action(session_id)
        return {
            "spoken_reply": (
                "I can only forecast about five days ahead with the current weather service."
            ),
            "action_type": "weather_forecast",
            "data": None,
            "ui_payload": None,
        }, 0.0

    if not location or not has_time:
        next_slot = "both" if (not location and not has_time) else (
            "location" if not location else "time"
        )
        pending_parse = {
            **merged,
            "action_name": "weather.forecast",
            "needs_location": not location,
            "needs_time": not has_time,
            "missing_fields": (
                ["location", "time"]
                if not location and not has_time
                else (["location"] if not location else ["time"])
            ),
        }
        set_pending_action(
            session_id,
            "weather.forecast",
            next_slot,
            _weather_pending_slots_from_parsed(prior_slots.get("user_text") or text, pending_parse),
        )
        _log_weather_forecast_pending_store(session_id, next_slot, prior_slots)
        return {
            "spoken_reply": _weather_clarification_prompt(next_slot),
            "action_type": "weather_forecast",
            "data": None,
            "ui_payload": None,
        }, 0.0

    clear_pending_action(session_id)
    _log_weather_forecast_pending_resolve(
        text,
        resolved_location=location,
        resolved_time=str(q.get("time_label") or ""),
        missing_slot=missing_slot,
        action="weather.forecast",
    )

    merged = {
        **merged,
        "location": location,
        "needs_location": False,
        "needs_time": False,
        "missing_fields": [],
        "action_name": "weather.forecast",
        "location_kind": "explicit",
    }
    t0 = perf_counter()
    user_text = str(prior_slots.get("user_text") or text or "")
    action_result = handle_weather_forecast_request(
        location=location,
        parsed_query=merged,
        user_text=user_text,
    )
    if action_result.get("data") or action_result.get("ui_payload"):
        set_recent_action_context(
            session_id,
            "weather.forecast",
            {
                "location": location,
                **prior_slots,
                "parsed_weather": merged,
                "time_kind": q.get("time_kind"),
                "time_label": q.get("time_label"),
            },
            action_result,
        )
    return action_result, perf_counter() - t0


def resolve_pending_weather_request(session_id: str, text: str, filler_generation: int | None = None):
    clear_pending_action(session_id)

    extracted = vera.extract_location_slot(text)
    location = clean_location_text(extracted.get("location"))
    if not location:
        location = extract_weather_location(text) or clean_location_text(text)
    if not is_plausible_location(location):
        return {
            "spoken_reply": WEATHER_LOCATION_INVALID_REPLY,
            "action_type": "weather",
            "data": None,
            "ui_payload": None,
        }, 0.0

    t0 = perf_counter()
    action_result = handle_weather_request(vera, location=location)
    if action_result.get("data"):
        set_recent_action_context(
            session_id,
            "weather.current",
            {"location": location},
            action_result,
        )
    t_llm = perf_counter() - t0
    return action_result, t_llm


def is_weather_followup(text: str) -> bool:
    lowered = text.lower()
    keywords = [
        "weather",
        "rain",
        "raining",
        "precipitation",
        "sunny",
        "clear",
        "cloudy",
        "overcast",
        "foggy",
        "humid",
        "humidity",
        "wind",
        "windy",
        "temperature",
        "temp",
        "feels like",
        "cloud",
        "visibility",
        "pressure",
        "snow",
    ]
    return any(keyword in lowered for keyword in keywords)


def build_weather_context_message(weather_facts: dict) -> str:
    return (
        "Use this recent weather snapshot as context for follow-up weather questions. "
        "It describes current conditions only, not a forecast. "
        "Answer in a practical, neutral tone: no jokes, teasing, or personalization. "
        "You may add one brief practical tip when the data supports it (e.g. rain and umbrella), same as a weather briefing.\n\n"
        f"Location: {weather_facts['place_name']}\n"
        f"Temperature: {weather_facts['temperature_f']} F\n"
        f"Feels like: {weather_facts['feels_like_f']} F\n"
        f"Conditions: {weather_facts['condition']}\n"
        f"Wind speed: {weather_facts['wind_mph']} mph\n"
        f"Wind gust: {weather_facts['wind_gust_mph']} mph\n"
        f"Humidity: {weather_facts['humidity_percent']} percent\n"
        f"Pressure: {weather_facts['pressure_hpa']} hPa\n"
        f"Cloud cover: {weather_facts['cloudiness_percent']} percent\n"
        f"Visibility: {weather_facts['visibility_m']} meters\n"
        f"Rain in last 1 hour: {weather_facts['rain_1h_mm']} mm\n"
        f"Rain in last 3 hours: {weather_facts['rain_3h_mm']} mm\n"
        f"Snow in last 1 hour: {weather_facts['snow_1h_mm']} mm\n"
        f"Snow in last 3 hours: {weather_facts['snow_3h_mm']} mm\n"
    )


def add_weather_context(messages: list[dict], weather_facts: dict) -> list[dict]:
    augmented = list(messages)
    augmented.insert(-1, {
        "role": "system",
        "content": build_weather_context_message(weather_facts)
    })
    return augmented


def inject_recent_action_context(messages: list[dict], session_id: str, user_text: str) -> list[dict]:
    context = get_recent_action_context(session_id)
    if not context:
        return messages

    if context.get("action_name") != "weather.current":
        return messages

    weather_facts = context.get("result", {}).get("data")
    if not weather_facts or not is_weather_followup(user_text):
        return messages

    return add_weather_context(messages, weather_facts)


def answer_direct_weather_question(
    text: str,
    session_id: str | None,
    action_result: dict,
) -> str:
    weather_facts = action_result.get("data")
    if not weather_facts:
        return action_result_reply(action_result) or WEATHER_LOCATION_INVALID_REPLY

    if session_id is not None:
        set_recent_action_context(
            session_id,
            "weather.current",
            {"location": weather_facts.get("place_name")},
            action_result,
        )

    lowered = text.lower()
    if "weather" in lowered:
        return action_result_reply(action_result) or WEATHER_LOCATION_INVALID_REPLY

    messages = vera.build_messages([], text)
    messages = add_weather_context(messages, weather_facts)
    reply, _ = vera.generate(messages)
    return reply
