def normalize_route(route: dict | None) -> dict:
    fallback = {
        "domain": "general",
        "is_action_request": False,
        "action_name": "general",
        "slots": {},
        "needs_followup": False,
        "missing_slot": None,
    }
    if not isinstance(route, dict):
        return fallback

    merged = dict(fallback)
    merged.update(route)
    if not isinstance(merged.get("slots"), dict):
        merged["slots"] = {}
    return merged


def clean_action_query(text: str | None) -> str:
    value = str(text or "").strip().strip(string.punctuation + " ")
    value = re.sub(r"\s+(?:right now|for me|please)\s*$", "", value, flags=re.IGNORECASE)
    value = re.sub(r"\s+(?:also|and)\s+(?:why|what|how)\b.*$", "", value, flags=re.IGNORECASE)
    return value.strip().strip(string.punctuation + " ")


_WORKMODE_UI_KEYWORD_RE = re.compile(
    r"\b(?:work\s*mode|reasoning|panel|tab|lane|space|page|workspace)\b",
    re.IGNORECASE,
)
_WORKMODE_NAV_VERB_RE = re.compile(
    r"\b(?:go|jump|switch|change|move)\s+to\b|\b(?:show|select|use|open)\b",
    re.IGNORECASE,
)
_REAL_WORLD_GO_TO_RE = re.compile(
    r"\b(?:go|went|gone|going|travel(?:ed|led|ing)?|fly|flew|visit(?:ed|ing)?)\s+to\s+"
    r"(?:[A-Z][a-zA-Z.'-]+|"
    r"(?:china|new york|school|court|meeting|work|home|church|class|college|university|"
    r"hospital|doctor|office|beijing|shanghai|washington|london|paris|tokyo|taiwan|"
    r"india|russia|ukraine|europe|mexico|canada|california|texas|florida))\b",
    re.IGNORECASE,
)


def _log_workmode_navigation_guard(
    user_text: str,
    matched_phrase: str,
    ui_keyword_present: bool,
    real_world_location_detected: bool,
    allowed_navigation: bool,
    reason: str,
) -> None:
    try:
        print(
            "[workmode_navigation_guard] "
            + json.dumps(
                {
                    "user_text": (user_text or "")[:200],
                    "matched_phrase": matched_phrase or "",
                    "ui_keyword_present": bool(ui_keyword_present),
                    "real_world_location_detected": bool(real_world_location_detected),
                    "allowed_navigation": bool(allowed_navigation),
                    "reason": reason,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _workmode_navigation_guard(user_text: str, matched_phrase: str = "") -> bool:
    """Allow Work Mode navigation only when the utterance clearly names UI concepts."""
    text = (user_text or "").strip()
    if not text:
        return False
    ui_keyword_present = bool(_WORKMODE_UI_KEYWORD_RE.search(text))
    nav_verb_present = bool(_WORKMODE_NAV_VERB_RE.search(text))
    real_world_location_detected = bool(_REAL_WORLD_GO_TO_RE.search(text))
    if not nav_verb_present:
        return False
    if ui_keyword_present:
        _log_workmode_navigation_guard(
            text,
            matched_phrase,
            ui_keyword_present,
            real_world_location_detected,
            True,
            "ui_keyword_present",
        )
        return True
    _log_workmode_navigation_guard(
        text,
        matched_phrase,
        ui_keyword_present,
        real_world_location_detected,
        False,
        "missing_ui_keyword_real_world_go_to"
        if real_world_location_detected
        else "missing_ui_keyword",
    )
    return False


_MOVE_LATEST_VOICE_TASK_TO_REASONING_RE = re.compile(
    r"(?i)\b(?:do|put|move|show|open|copy|send|transfer|continue|expand|make)\s+"
    r"(?:that|this|it|the\s+(?:email|draft|answer|response|reply|version|full\s+version))\s+"
    r"(?:in|into|to|on)\s+(?:the\s+)?(?:reasoning(?:\s+(?:panel|space|tab))?|panel|space|tab)\b"
    r"|\b(?:make|create|open|start)\s+(?:a\s+)?(?:reasoning\s+)?panel\s+for\s+"
    r"(?:that|this|it|the\s+(?:email|draft|answer|response|reply))\b"
    r"|\b(?:can\s+you|could\s+you|please)\s+"
    r"(?:do|put|move|show|open|copy|send|transfer|continue|expand)\s+"
    r"(?:that|this|it|the\s+(?:email|draft|answer|response|reply|version|full\s+version))\s+"
    r"(?:in|into|to|on)\s+(?:the\s+)?(?:reasoning(?:\s+(?:panel|space|tab))?|panel|space|tab)\b"
    r"|\b(?:put|show)\s+(?:the\s+)?(?:email|draft|answer|response|reply|full\s+version)\s+"
    r"(?:in|into|to|on)\s+(?:the\s+)?(?:reasoning(?:\s+(?:panel|space|tab))?|panel|space|tab)\b"
)


def _move_latest_voice_task_to_reasoning_intent(user_text: str | None) -> bool:
    """True when "that/this/it" refers to latest Voice UI output/task, not a panel title."""
    return bool(_MOVE_LATEST_VOICE_TASK_TO_REASONING_RE.search(user_text or ""))


def _go_to_reasoning_panel_query_heuristic(user_text: str) -> str | None:
    """
    Tab-title navigation. Must include a UI keyword so real-world
    phrases like "go to China" are never treated as panel switches.
    """
    s = (user_text or "").strip()
    if not s:
        return None
    if _move_latest_voice_task_to_reasoning_intent(s):
        return None
    lowered = s.lower()
    m = re.search(
        r"(?i)\b(?:can you|could you|please)\s+(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+"
        r"(?:the\s+|a\s+|my\s+)?(.+?)(?:\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page))?\s*[?.!]*\s*$",
        s,
    )
    if not m:
        m = re.search(
            r"(?i)\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+|a\s+|my\s+)?"
            r"(.+?)(?:\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page))?\s*[?.!]*\s*$",
            s,
        )
    if not m:
        return None
    matched_phrase = m.group(0).strip()
    if not _workmode_navigation_guard(s, matched_phrase):
        return None
    q = clean_action_query(m.group(1))
    if not q or len(q) < 2:
        return None
    if re.fullmatch(r"\d+", q):
        return None
    low = q.lower().strip()
    stop = frozenset(
        {
            "sleep",
            "bed",
            "home",
            "school",
            "dinner",
            "lunch",
            "breakfast",
            "work",
            "church",
            "google",
            "youtube",
            "spotify",
            "settings",
        }
    )
    if low in stop:
        return None
    if re.match(
        r"(?i)^(explain|describe|tell me|help me|what is|what's|whats|how does|how do|why does|why do)\b",
        q,
    ):
        return None
    had_tab_word = bool(_WORKMODE_UI_KEYWORD_RE.search(lowered))
    # Verbs like "show" / "open" also match the regex above, but without an explicit
    # UI word they collide with normal requests ("show me the code…", "go to China").
    if not had_tab_word and not re.search(
        r"(?i)\b(?:go\s+to|jump\s+to|switch\s+to|change\s+to|move\s+to)\b",
        lowered,
    ):
        return None
    if not had_tab_word and len(q) < 10:
        return None
    return q


def _explicit_work_mode_panel_navigation(user_text: str) -> bool:
    """
    True when the user is asking to switch the reasoning UI to a tab/panel/page,
    not to have a topic explained in the abstract.
    """
    s = (user_text or "").strip()
    low = s.lower()
    if not low:
        return False
    if _move_latest_voice_task_to_reasoning_intent(s):
        return False
    if re.search(
        r"\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+|a\s+|my\s+)?"
        r"(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*#?\s*\d+\b",
        low,
    ):
        return True
    if re.search(
        r"\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+|a\s+|my\s+)?"
        r"(first|second|third|fourth|fifth|sixth|seventh|eighth)\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page)\b",
        low,
    ):
        return True
    if re.search(r"\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\b", low) and re.search(
        r"\b(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*#?\s*\d+\b", low
    ):
        return True
    if re.search(
        r"(?i)\b(?:can you|could you|please)\s+(?:go to|jump to|switch to|change to|move to|show|select|use|open)\b",
        s,
    ) and re.search(r"(?i)\b(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*[?.!]*\s*$", s.strip()):
        return True
    if re.match(
        r"(?i)^(go to|jump to|switch to|change to|move to|show|select|use|open)\b",
        s.strip(),
    ) and re.search(r"(?i)\b(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*[?.!]*\s*$", s.strip()):
        return True
    if _go_to_reasoning_panel_query_heuristic(s) is not None:
        return True
    return False


def _is_explain_style_work_mode_topic_request(user_text: str) -> bool:
    """True for explain / teach / define phrasing (route to reasoning content, not tab switch)."""
    s = (user_text or "").strip().lower()
    if not s:
        return False
    if re.search(
        r"\b(?:can you|could you|please|would you)\s+(?:explain|describe|walk me through|clarify|break down|spell out)\b",
        s,
    ):
        return True
    if re.match(
        r"^(?:explain|describe|what(?:'s|s| is)|what are|how (?:does|do|can|would)|why (?:does|do|is|are))\b",
        s,
    ):
        return True
    if re.search(r"\bhelp me (?:understand|figure out)\b", s):
        return True
    if re.search(r"\btell me (?:more )?about\b", s):
        if re.search(
            r"\b(?:first|second|third|fourth|fifth|sixth|seventh|eighth)\s+(?:reasoning\s+)?(?:panel|tab|space|page)\b",
            s,
        ):
            return False
        if re.search(r"\b(?:reasoning\s+)?(?:panel|tab|space|page)\s*#?\s*\d+\b", s):
            return False
        return True
    return False


_WORK_MODE_REASONING_HANDOFF_CREATION_RE = re.compile(
    r"\b(?:write|draft|compose|prepare|explain|describe|outline|help\s+me\s+(?:write|draft|compose|prepare|explain|with)|"
    r"(?:turn|convert|make)\s+(?:that|this|it)\s+into|open|use)\b",
    re.IGNORECASE,
)
_WORK_MODE_REASONING_HANDOFF_TARGET_RE = re.compile(
    r"\b(?:reasoning\s+(?:space|panel|tab|page)|(?:reasoning\s+)?panel(?:\s+\d+)?|panel\s+\d+|reasoning\s+space|workspace|work\s*mode)\b|"
    r"\b(?:in|into|to)\s+(?:(?:the|this|that)\s+)?(?:reasoning\s+(?:space|panel|tab|page)|panel(?:\s+\d+)?)\b",
    re.IGNORECASE,
)


def _is_work_mode_reasoning_handoff_request(user_text: str) -> bool:
    """True when the user asks to write/draft/explain prior context in a reasoning panel."""
    s = (user_text or "").strip()
    if not s:
        return False
    if not re.search(r"\b(?:that|this|it|these|those)\b", s, re.IGNORECASE):
        return False
    return bool(
        _WORK_MODE_REASONING_HANDOFF_CREATION_RE.search(s)
        and _WORK_MODE_REASONING_HANDOFF_TARGET_RE.search(s)
    )


def clean_finance_subject_text(text: str | None) -> str:
    value = clean_action_query(text)
    value = re.sub(
        r"^(?:uh+|um+|erm+|hmm+|mm+|ah+|like|maybe|probably|i\s+mean|it'?s|its|about|for)\s+",
        "",
        value,
        flags=re.IGNORECASE,
    )
    value = re.sub(
        r"^(?:the\s+)?(?:stock|stock price|share price|price|quote|ticker)\s+(?:of\s+|for\s+)?",
        "",
        value,
        flags=re.IGNORECASE,
    )
    value = re.sub(r"^(?:the\s+)?(?:company|stock|ticker)\s*$", "", value, flags=re.IGNORECASE)
    return value.strip().strip(string.punctuation + " ")


def is_likely_finance_subject(query: str) -> bool:
    lowered = query.lower().strip()
    if not lowered:
        return False

    finance_keywords = [
        "stock",
        "stocks",
        "share",
        "shares",
        "etf",
        "fund",
        "ticker",
        "quote",
        "market",
        "earnings",
        "nasdaq",
        "nyse",
    ]
    if any(keyword in lowered for keyword in finance_keywords):
        return True

    compact = re.sub(r"[^a-z]", "", lowered)
    if compact and len(compact) <= 5 and " " not in lowered:
        return True

    return False


def is_breaking_news_phrase(text: str) -> bool:
    lowered = text.lower().strip()
    if not lowered:
        return False

    return bool(
        re.match(
            r"^(?:(?:can you tell me|tell me|give me|show me)\s+|(?:what(?:'s|s| is))\s+|(?:any)\s+)?"
            r"(?:(?:some|any)\s+)?"
            r"(?:the\s+)?(?:latest\s+)?"
            r"(?:breaking news|news right now|latest updates|what just happened|what happened just now)"
            r"(?:\s+right now)?[?!.\s]*$",
            lowered,
        )
    )


def is_broad_news_reset_request(text: str) -> bool:
    """True for fresh/general headline requests that must ignore prior topic context.

    These are broad news intents ("breaking news", "latest headlines", "other news"),
    not follow-ups to the previous article. Run this check before deictic/pronoun
    follow-up handling so "anything else in the news" does not inherit a prior
    Trump/China topic just because it contains "anything else".
    """
    lowered = re.sub(r"\s+", " ", (text or "").strip().lower())
    if not lowered:
        return False
    patterns = (
        r"^(?:hey\s+vera[, ]+)?(?:can you\s+)?tell me (?:the |some |any )?(?:breaking )?news[?!.\s]*$",
        r"^(?:hey\s+vera[, ]+)?(?:can you\s+)?(?:give|show) me (?:the |some |any )?(?:breaking )?news[?!.\s]*$",
        r"^(?:the\s+)?breaking news[?!.\s]*$",
        r"^(?:the\s+)?(?:latest|top) headlines[?!.\s]*$",
        r"^(?:what(?:'s|s| is)\s+happening today)[?!.\s]*$",
        r"^(?:what(?:'s|s| is)\s+going on in (?:the )?news)[?!.\s]*$",
        r"^(?:anything else|any other stories?|what else|other news)(?:\s+in (?:the )?news)?[?!.\s]*$",
        r"^(?:give|show|tell) me (?:another|a different|one more) headline[?!.\s]*$",
        r"^(?:news|headlines)[?!.\s]*$",
    )
    return any(re.match(pat, lowered) for pat in patterns)


# 2026-06-01 — Supported-app-action intent guard.
#
# Patch goal: "Fix routing priority so supported VERA actions are checked
# before generic info.search." Specifically — utterances like "Can you
# play Feather by Sabrina Carpenter?" used to fall through
# heuristic_route_action (no `play X by Y` heuristic existed), then
# classify_info_tool's mini-LLM search planner would promote the turn to
# general_web_search_tool, sending it to Serper. The LLM router would
# have classified it as music.play_track, but never got the chance.
#
# Priority order, per the patch spec:
#   1. Supported app actions:
#        music.play / pause / resume / next / previous / volume
#        checklist.add / remove / complete
#        timer.set / cancel
#        panel.open / close / navigate
#   2. Dedicated live-info actions (info.weather / finance / news /
#      sports / product / time / location)
#   3. Generic info.search only if no supported action intent matches.
#
# `looks_like_supported_app_action(text)` is the deterministic bucket-1
# detector. When it fires we explicitly defer the info-tool cascade so
# the downstream music / checklist / timer / panel routers get the turn.
# Negative carve-outs keep info-question phrasings ("what's the next
# song", "what's the volume right now") out of the bucket so the user
# can still ASK about app state without it being mistaken for a
# transport command.
_SUPPORTED_APP_ACTION_INFO_QUESTION_RE = re.compile(
    r"^\s*(?:what|which|who|whose|when|how(?:\s+much|\s+many|\s+long|\s+do|\s+does)?|"
    r"why|is\s+(?:the|there|it)\b|are\s+(?:the|there)\b|was\s+(?:the|there|it)\b|"
    r"were\s+(?:the|there)\b|do\s+(?:you|i)\b|did\s+(?:you|i)\b|can\s+you\s+tell\s+me)\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_PLAY_RE = re.compile(
    # Canonical "play X by Y" + variants. "play" / "put on" / "start playing"
    # / "begin playing" alone are too broad on their own (cf. "play it cool",
    # "put on the news"), so we require either an explicit `by ARTIST` clause
    # OR a music-domain noun (music / song / track / album / playlist / lo-fi /
    # spotify / playback) OR a known music verbal frame ("on Spotify", "from
    # my playlist").
    r"\b(?:(?:can|could|would|will|please)\s+you\s+(?:please\s+)?)?"
    r"(?:play|put\s+on|start\s+playing|begin\s+playing|throw\s+on|"
    r"queue\s+up|spin\s+up)\b"
    r"(?:.+?\bby\b\s+\w|"
    r".+?\b(?:music|song|songs|track|tracks|album|albums|playlist|"
    r"playlists|lo[-\s]?fi|lofi|spotify|playback)\b|"
    r".+?\bon\s+(?:my\s+)?spotify\b|"
    r".+?\bfrom\s+(?:my|the)\s+(?:playlist|library|queue|liked\s+songs)\b)",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_TRANSPORT_RE = re.compile(
    # pause / stop / unpause / resume / continue + music keyword
    r"\b(?:pause|unpause|resume|stop|continue)\b"
    r"(?:\s+(?:the\s+|my\s+)?(?:music|song|songs|track|tracks|playback|spotify|playlist))?\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_PAUSE_HARD_RE = re.compile(
    # Sometimes "pause" / "stop" / "resume" appear bare ("pause",
    # "pause please", "resume", "stop the music") — still a transport
    # command. The "please" affix is allowed on either side of the verb.
    r"^\s*(?:please\s+)?"
    r"(?:pause|unpause|resume|continue\s+playing|"
    r"stop\s+(?:the\s+)?(?:music|song|track|playback|spotify))"
    r"(?:\s+please)?\s*[!?.]*\s*$",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_NEXT_RE = re.compile(
    r"\b(?:next|skip|skip\s+(?:to\s+(?:the\s+)?(?:next|following))?|"
    r"forward|advance|fast[-\s]?forward)\s+"
    r"(?:song|songs|track|tracks|playback)\b|"
    r"\b(?:skip|next)\s+(?:this\s+|the\s+)?(?:song|track|playback)\b|"
    r"\bplay\s+(?:the\s+)?next\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_PREVIOUS_RE = re.compile(
    r"\b(?:previous|prev|last|back\s+to\s+(?:the\s+)?(?:previous|last))\s+"
    r"(?:song|songs|track|tracks|playback)\b|"
    r"\bgo\s+back\s+(?:to\s+(?:the\s+)?(?:previous|last)\s+(?:song|track))\b|"
    r"\bplay\s+(?:the\s+)?(?:previous|last)\s+(?:song|track)\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_MUSIC_VOLUME_RE = re.compile(
    r"\b(?:volume|sound)\b.*\b(?:up|down|higher|lower|increase|decrease|"
    r"louder|quieter|raise|reduce|mute|unmute)\b|"
    r"\b(?:turn\s+(?:up|down)|crank\s+(?:up|down)|raise|lower)\s+"
    r"(?:the\s+)?(?:volume|sound|music|playback)\b|"
    r"\b(?:mute|unmute)\s+(?:the\s+)?(?:music|playback|spotify)\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_CHECKLIST_ADD_RE = re.compile(
    r"\b(?:add|put)\b.*?\b(?:to|on)\b\s+"
    r"(?:my\s+|the\s+|our\s+)?(?:checklist|todo|to[-\s]?do|task\s+list|list|plan|reasoning\s+plan)\b|"
    r"\b(?:add|put)\b.*?\bchecklist\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_CHECKLIST_REMOVE_RE = re.compile(
    r"\b(?:remove|delete|drop|take\s+off|cross\s+off|scratch\s+off|strike\s+off)\b.*?"
    r"(?:from\b\s+(?:my\s+|the\s+)?(?:checklist|todo|to[-\s]?do|list|plan)|"
    r"\bchecklist\b|\btodo\b|\bto[-\s]?do\b|\bthe\s+list\b)",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_CHECKLIST_COMPLETE_RE = re.compile(
    r"\bmark\b.*?\b(?:as\s+)?(?:complete|completed|done|finished)\b|"
    r"\b(?:check\s+off|check\s+(?:item|the))\b|"
    r"\bcheck\s+(?:item\s+)?\d+\s+(?:off|done|complete)\b",
    re.IGNORECASE,
)
# Shared timer-START grammar — single source of truth in
# ``actions/timer_duration.py``. Reused by the supported-action priority
# guard below AND by ``_try_work_mode_timer_core`` so all timer phrasings
# (noun-before-duration, duration-before-noun, countdown wording, and the
# "remind me in <N> <unit>" shorthand) are classified identically.
try:
    from actions.timer_duration import (
        TIMER_START_INTENT_PATTERN as _TIMER_START_INTENT_PATTERN,
    )
except Exception:  # pragma: no cover - defensive fallback only
    _TIMER_START_INTENT_PATTERN = (
        r"(?:(?:set|start|create|make|begin|put)\s+(?:up\s+)?"
        r"(?:a\s+|an\s+|another\s+|the\s+|my\s+|me\s+a\s+|one\s+more\s+)?"
        r"(?:[\w-]+\s+){0,5}(?:work\s*mode\s+)?(?:timer|countdown)\b|"
        r"(?:timer|countdown)\s+for\b|"
        r"count\s+down\s+(?:[\w-]+\s+){0,3}"
        r"(?:seconds?|secs?|minutes?|mins?|hours?|hrs?)\b|"
        r"remind\s+me\s+in\s+(?:\d+|one|two|three|four|five|six|seven|eight|nine|ten|"
        r"eleven|twelve|fifteen|twenty|thirty|forty|fifty|sixty|half|a\s+(?:half|quarter|few))"
        r"(?:[-\s]\w+)?\s*(?:seconds?|secs?|minutes?|mins?|hours?|hrs?)\b)"
    )

_SUPPORTED_APP_ACTION_TIMER_SET_RE = re.compile(
    _TIMER_START_INTENT_PATTERN, re.IGNORECASE
)
from actions.timer_extend import (  # noqa: E402
    TIMER_EXTEND_INTENT_RE as _TIMER_EXTEND_INTENT_RE,
    format_timer_duration_label as _format_timer_duration_label,
    parse_timer_extend_request as _parse_timer_extend_request,
    timer_extend_intent_matches as _timer_extend_intent_matches,
)
_SUPPORTED_APP_ACTION_TIMER_EXTEND_RE = _TIMER_EXTEND_INTENT_RE
# Runtime timer dispatcher uses the same compiled grammar.
_WM_TIMER_START_INTENT_RE = _SUPPORTED_APP_ACTION_TIMER_SET_RE
_SUPPORTED_APP_ACTION_TIMER_CANCEL_RE = re.compile(
    r"\b(?:cancel|stop|clear|remove|erase|delete|kill|end|drop|scrap|nix|close|"
    r"turn\s+off|get\s+rid\s+of)\s+"
    r"(?:the\s+|my\s+|that\s+|this\s+)?(?:work\s*mode\s+)?timer\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_PANEL_OPEN_RE = re.compile(
    r"\b(?:open|create|make|add|spin\s+up|bring\s+up)\s+"
    r"(?:up\s+)?(?:a\s+|another\s+|the\s+|one\s+more\s+|my\s+)?"
    r"(?:new\s+|extra\s+|additional\s+|empty\s+)?"
    r"(?:reasoning\s+)?(?:panel|tab|reasoning\s+space|reasoning\s+tab|space)\b|"
    # "reopen the last (closed) (reasoning) panel" — allow optional
    # adjective stack so "reopen the last closed panel" still matches.
    r"\breopen\s+(?:the\s+)?"
    r"(?:(?:last|previous|prior|recent|closed)\s+){1,3}"
    r"(?:reasoning\s+)?(?:panel|tab)\b",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_PANEL_CLOSE_RE = re.compile(
    r"\bclose\s+(?:panel\s+\d+|"
    r"(?:the\s+|this\s+|that\s+)?(?:reasoning\s+)?(?:current|active)?\s*(?:reasoning\s+)?panel\b|"
    r"all\s+(?:other\s+)?(?:reasoning\s+)?panels\b|"
    r"(?:the\s+)?(?:first|second|third|fourth|last)\s+(?:two\s+|three\s+|four\s+)?"
    r"(?:reasoning\s+)?panels?\b)",
    re.IGNORECASE,
)
_SUPPORTED_APP_ACTION_PANEL_NAVIGATE_RE = re.compile(
    r"\b(?:go\s+to|switch\s+to|navigate\s+to|jump\s+to|move\s+to|"
    r"change\s+to|use|go\s+back\s+to)\s+"
    r"(?:the\s+)?(?:panel\s+\d+|"
    r"(?:first|second|third|fourth|last|previous|next)\s+(?:reasoning\s+)?panel|"
    r"\w[\w\s'-]{0,40}?\s+(?:reasoning\s+)?(?:panel|tab))\b",
    re.IGNORECASE,
)


def looks_like_supported_app_action(text: str) -> bool:
    """True when the user transcript clearly matches a supported VERA
    app-action intent (music / checklist / timer / panel) - the bucket-1
    priority tier in the routing spec.

    Used as a pre-guard so the info-tool cascade (and especially the
    mini-LLM search planner) never promotes a clear app-action turn to
    generic info.search / web.search / Serper. Negative carve-out: an
    info-question phrasing (``"what's the next song?"``, ``"what is the
    volume?"``) never counts as an app action - it's still a question.

    Returns False on empty / whitespace input and on info-question
    phrasings even when they contain a music/timer/panel keyword.
    """
    raw = (text or "").strip()
    if not raw:
        return False

    # Info-question carve-out. "What's the next song?" / "Is the timer
    # still running?" / "Which panel am I in?" - these are factual
    # questions about app state, not action invocations. The carve-out
    # only relaxes for explicit "can you <ACTION-VERB>" wording where
    # ACTION-VERB is an unambiguous verb (play / put on / pause / set /
    # open / close / mark / remove / etc.). Bare nouns / adjectives
    # like ``next`` / ``previous`` / ``volume`` DO NOT count - they
    # appear in both action ("next track") and question ("what's the
    # next track") phrasings, and the question form should win when
    # the utterance starts with what/which/who/etc.
    if _SUPPORTED_APP_ACTION_INFO_QUESTION_RE.match(raw):
        lower_head = raw[:80].lower()
        if not re.search(
            r"\b(?:play|put\s+on|pause|unpause|resume|stop|skip|"
            r"mute|unmute|raise|lower|crank\s+(?:up|down)|"
            r"turn\s+(?:up|down|off)|"
            r"add|remove|delete|cross\s+off|check\s+off|mark|"
            r"set|start|create|cancel|clear|"
            r"open|close|switch|go\s+to|navigate|jump\s+to)\b",
            lower_head,
        ):
            return False

    if _SUPPORTED_APP_ACTION_MUSIC_PLAY_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_MUSIC_PAUSE_HARD_RE.match(raw):
        return True
    if _SUPPORTED_APP_ACTION_MUSIC_TRANSPORT_RE.search(raw) and re.search(
        r"\b(?:music|song|songs|track|tracks|playback|spotify|playlist)\b",
        raw,
        re.IGNORECASE,
    ):
        return True
    if _SUPPORTED_APP_ACTION_MUSIC_NEXT_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_MUSIC_PREVIOUS_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_MUSIC_VOLUME_RE.search(raw):
        return True

    if _SUPPORTED_APP_ACTION_CHECKLIST_ADD_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_CHECKLIST_REMOVE_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_CHECKLIST_COMPLETE_RE.search(raw):
        return True

    if _timer_extend_intent_matches(raw):
        return True
    if _SUPPORTED_APP_ACTION_TIMER_SET_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_TIMER_CANCEL_RE.search(raw):
        return True

    if _SUPPORTED_APP_ACTION_PANEL_OPEN_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_PANEL_CLOSE_RE.search(raw):
        return True
    if _SUPPORTED_APP_ACTION_PANEL_NAVIGATE_RE.search(raw):
        return True

    return False


# 2026-06-01 - PRE-SEARCH SANITY GATE -------------------------------------
#
# The adaptive mini-LLM search planner can promote `route="uncertain"` to
# `general_web_search_tool` even when the user is not actually asking for
# external / current information - for example, a bare definition like
# "Wait, what is a tech sell-off?". Spec ("Add a pre-search sanity gate
# before adaptive search planner results are allowed to become
# general_web_search_tool", 2026-06-01):
#
#   1. If deterministic route is already a supported action or dedicated
#      live-info tool, keep it.
#   2. If planner proposes general_web_search_tool, only accept it when
#      has_search_need(text) is true.
#   3. If has_search_need(text) is false and the message looks like
#      explanation/interpretation, return llm_only / voice.answer.
#   4. If unclear, prefer llm_only over web.search unless the user
#      explicitly asked to search or needs current/live data.
#
# The gate runs in two places:
#   * inside `_classify_info_tool_deterministic` at the tail of the
#     cascade (step 11.5), before the "uncertain" default - this short-
#     circuits clear explanation shapes BEFORE the planner LLM is called,
#     saving latency and never letting the planner see them at all; and
#   * inside the `classify_info_tool` wrapper AFTER the planner runs - a
#     defense-in-depth that demotes any `uncertain -> general_web_search_tool`
#     promotion when the raw transcript contains no positive search reason.
#
# Both gates rely on these two helpers. The helpers intentionally focus
# on the GENERAL SHAPE of the request (lookup verbs, freshness markers,
# live-data nouns, news/source keywords, historical/statistical clauses
# vs. conceptual / definition / interpretation phrasings) rather than a
# long allowlist of specific topics, so they generalize cleanly to topics
# we haven't seen before.
_SEARCH_NEED_EXPLICIT_LOOKUP_RE = re.compile(
    r"\b(?:"
    r"search(?:\s+(?:for|up|the\s+web|online|google))?|"
    r"look\s+(?:up|for|into|that\s+up|it\s+up|them\s+up|him\s+up|her\s+up|something\s+up)|"
    r"find\s+(?:out|me|some|the|a|an|info|information|results|sources?)?|"
    r"check\s+(?:on|for|the\s+(?:web|news|price|score))|"
    r"browse|"
    r"google(?:\s+(?:that|it|for|me))?|"
    r"investigate|"
    r"pull\s+up|"
    r"fetch(?:\s+me)?|"
    r"do\s+a\s+(?:quick\s+)?search|"
    r"web\s+search"
    r")\b",
    re.IGNORECASE,
)
_SEARCH_NEED_FRESHNESS_RE = re.compile(
    r"\b(?:"
    r"latest|newest|most\s+recent|"
    r"recent|recently|"
    r"right\s+now|"
    r"currently|"
    r"current\b|"
    r"live\b|"
    r"today(?:'s|s)?|"
    r"tonight(?:'s|s)?|"
    r"yesterday(?:'s|s)?|"
    r"this\s+(?:week|month|year|morning|afternoon|evening|hour)|"
    r"last\s+(?:week|month|year|night|hour|day|few\s+(?:hours|days|weeks|months|years)|"
    r"\d+\s+(?:hours?|days?|weeks?|months?|years?))|"
    r"past\s+(?:week|month|year|hour|24\s+hours|day|days|few\s+(?:hours|days|weeks|months|years)|"
    r"\d+\s+(?:hours?|days?|weeks?|months?|years?))|"
    r"over\s+the\s+(?:past|last)\s+\d+\s+(?:hours?|days?|weeks?|months?|years?)|"
    r"\d+\s+(?:hours?|days?|weeks?|months?|years?)\s+ago|"
    r"breaking|"
    r"just\s+(?:happened|announced|released|launched|came\s+out|broke|posted)"
    r")\b",
    re.IGNORECASE,
)
_SEARCH_NEED_LIVE_DATA_RE = re.compile(
    r"\b(?:"
    r"prices?|priced|"
    r"trading\s+at|"
    r"stock\s+price|share\s+price|"
    r"market\s+cap|"
    r"quotes?|"
    r"weather|temperature|forecast|"
    r"scores?|standings?|schedules?|fixtures?|odds|"
    r"results?\s+of\s+(?:the\s+)?(?:game|match|tournament|race|fight|series|event)|"
    r"earnings(?:\s+(?:report|call|date))?|"
    r"dividends?(?:\s+yield)?"
    r")\b",
    re.IGNORECASE,
)
_SEARCH_NEED_NEWS_RE = re.compile(
    r"\b(?:"
    r"news|"
    r"headlines?|"
    r"breaking|"
    r"articles?|"
    r"reports?(?:\s+(?:say|said))?|reporting|"
    r"press\s+release|"
    r"coverage|"
    r"top\s+stor(?:y|ies)|"
    r"news\s+updates?"
    r")\b",
    re.IGNORECASE,
)
_SEARCH_NEED_SOURCE_RE = re.compile(
    r"\b(?:"
    r"sources?|citations?|"
    r"websites?|"
    r"links?|urls?|"
    r"references?(?:\s+(?:link|page))?"
    r")\b",
    re.IGNORECASE,
)
_SEARCH_NEED_HISTORICAL_STAT_RE = re.compile(
    r"(?:"
    r"\b(?:biggest|smallest|largest|maximum|minimum|max|min|highest|lowest|peak|trough|"
    r"average|median)\s+"
    r"(?:drawdown|return|returns|gain|gains|loss|losses|performance|volatility|sharpe|"
    r"yield|earnings|revenue|profit|profits|dividend|dividends)\b"
    r"|"
    r"\bpast\s+\d+\s+(?:days?|weeks?|months?|years?)\b"
    r"|"
    r"\bin\s+\d{4}\b"
    r"|"
    r"\bsince\s+\d{4}\b"
    r"|"
    r"\bbefore\s+\d{4}\b"
    r"|"
    r"\bafter\s+\d{4}\b"
    r"|"
    r"\b\d{4}\s*[-\u2013\u2014]\s*\d{4}\b"
    r"|"
    r"\bover\s+the\s+(?:past|last)\s+\d+\s+(?:days?|weeks?|months?|years?)\b"
    r"|"
    r"\b\d+[-\s]year\s+(?:high|low|return|drawdown|volatility|chart|history|performance)\b"
    r"|"
    r"\b52[-\s]?week(?:\s+(?:high|low))?\b"
    r"|"
    r"\bytd\b"
    r"|"
    r"\ball[-\s]?time\s+(?:high|low|record)\b"
    r")",
    re.IGNORECASE,
)


def has_search_need(text: str) -> bool:
    """Return True when the transcript carries a positive 'search reason'.

    Used as the pre-search sanity gate (2026-06-01) before the adaptive
    search planner is allowed to promote an `uncertain` classification
    into `general_web_search_tool`. A turn is considered to have search
    need when ANY of these strong signals appears:

      - explicit lookup intent: ``search``, ``look up``, ``find``,
        ``check``, ``browse``, ``google``, ``investigate``, ``pull up``;
      - freshness / currentness: ``latest``, ``current``, ``recent``,
        ``today``, ``right now``, ``live``, ``this week``, ``N hours ago``;
      - live data: ``price``, ``trading at``, ``stock price``, ``weather``,
        ``score``, ``schedule``, ``forecast``, ``odds``, ``earnings``;
      - news request: ``news``, ``headlines``, ``breaking``, ``article``,
        ``report``, ``press release``, ``coverage``;
      - source request: ``source``, ``citation``, ``website``, ``link``,
        ``url``, ``reference``;
      - historical / statistical lookup: ``biggest drawdown``, ``past 5
        years``, ``since 2020``, ``52-week``, ``YTD``, ``all-time high``.

    A bare conceptual question like ``"what is a tech sell-off?"`` or
    ``"what does bearish mean?"`` carries none of these signals and
    therefore has NO search need - the general LLM should answer it
    directly from chat context instead of being upgraded to web.search.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    if _SEARCH_NEED_EXPLICIT_LOOKUP_RE.search(raw):
        return True
    if _SEARCH_NEED_FRESHNESS_RE.search(raw):
        return True
    if _SEARCH_NEED_LIVE_DATA_RE.search(raw):
        return True
    if _SEARCH_NEED_NEWS_RE.search(raw):
        return True
    if _SEARCH_NEED_SOURCE_RE.search(raw):
        return True
    if _SEARCH_NEED_HISTORICAL_STAT_RE.search(raw):
        return True
    return False


_EXPLANATION_OR_INTERPRETATION_RES: tuple[re.Pattern, ...] = (
    # "What is/are/was/were X?" / "What's X?" - bare definition shape.
    # Optional conversational lead-ins ("wait", "hold on", "hmm", "hey
    # vera"), courtesy framing ("can you tell me"), and trailing
    # punctuation are all tolerated. The pattern is anchored end-of-line
    # so we don't accidentally claim "what is the latest news on X about
    # Y?" - those have a tail clause with search-need words that the
    # search-need helper picks up separately.
    re.compile(
        r"^\s*"
        r"(?:wait[,\s!?.]+|hold\s+on[,\s!?.]+|actually[,\s!?.]+|"
        r"so[,\s!?.]+|hmm+[,\s!?.]+|um+[,\s!?.]+|ok(?:ay)?[,\s!?.]+|"
        r"hey\s+vera[,\s!?.]+)?"
        r"(?:can\s+you\s+|could\s+you\s+|please\s+|would\s+you\s+)?"
        r"(?:tell\s+me\s+|remind\s+me\s+)?"
        r"what(?:'s|s|\s+is|\s+are|\s+was|\s+were)\s+"
        r"(?:a\s+|an\s+|the\s+)?[A-Za-z][^?.!\n]*?[?.!]?\s*$",
        re.IGNORECASE,
    ),
    # "What does X mean?" / "What do they mean by X?"
    re.compile(
        r"\bwhat\s+(?:does|do)\s+[^?.!\n]{1,80}?\s+mean\b",
        re.IGNORECASE,
    ),
    # "What does X stand for?"
    re.compile(
        r"\bwhat\s+(?:does|do)\s+[^?.!\n]{1,80}?\s+stand\s+for\b",
        re.IGNORECASE,
    ),
    # "(What's) the meaning of X" / "meaning of X"
    re.compile(
        r"\b(?:what(?:'s|s|\s+is)\s+the\s+)?meaning\s+of\s+[A-Za-z]",
        re.IGNORECASE,
    ),
    # "Define X" / "definition of X"
    re.compile(
        r"^\s*(?:can\s+you\s+|could\s+you\s+|please\s+)?"
        r"define\s+(?:the\s+(?:term|word|concept|phrase|idea)\s+)?[A-Za-z]",
        re.IGNORECASE,
    ),
    re.compile(
        r"\bdefinition\s+of\s+[A-Za-z]",
        re.IGNORECASE,
    ),
    # "Tell me what X is/means" - explanation-style "tell me", distinct
    # from "tell me the news / latest / score" which carry search need.
    re.compile(
        r"\btell\s+me\s+what\s+[^?.!\n]{1,80}?\s+(?:is|are|was|were|means?)\b",
        re.IGNORECASE,
    ),
    # "How does X work?" / "How do X work?"
    re.compile(
        r"\bhow\s+(?:do(?:es)?)\s+[^?.!\n]{1,80}?\s+work\b",
        re.IGNORECASE,
    ),
    # "Why does/is X matter/bad/good/important/relevant/the case?"
    re.compile(
        r"\bwhy\s+(?:does|do|is|are|was|were)\s+"
        r"(?:that|this|it|those|these|[A-Za-z][^?.!\n]{0,80}?)\s+"
        r"(?:matter|matters|mattered|bad|good|important|relevant|significant|"
        r"a\s+problem|a\s+thing|happen|happening|the\s+case)\b",
        re.IGNORECASE,
    ),
    # "Can/could/would/please you (please) explain/clarify/etc."
    re.compile(
        r"\b(?:can|could|would|will|please)\s+(?:you\s+)?(?:please\s+)?"
        r"(?:explain|clarify|interpret|unpack|elaborate|describe|"
        r"walk\s+me\s+through|break\s+(?:that|this|it)\s+down|"
        r"help\s+me\s+understand)\b",
        re.IGNORECASE,
    ),
    re.compile(
        r"^\s*(?:please\s+)?"
        r"(?:explain|clarify|interpret|unpack|elaborate|describe)\b",
        re.IGNORECASE,
    ),
    # Bare imperatives: "walk me through that", "break it down for me",
    # "help me understand", "spell it out", "tell me more". These have
    # no courtesy prefix but are unambiguous explanation/interpretation
    # requests rather than search/lookup intents.
    re.compile(
        r"\b(?:"
        r"walk\s+me\s+through|"
        r"break\s+(?:that|this|it)\s+down|"
        r"help\s+me\s+understand|"
        r"spell\s+(?:that|this|it|out)\s+(?:out|for\s+me)|"
        r"tell\s+me\s+more"
        r")\b",
        re.IGNORECASE,
    ),
    # "Does/do that/this/it mean ...?"
    re.compile(
        r"\b(?:does|do)\s+(?:that|this|it|those|these)\s+mean\b",
        re.IGNORECASE,
    ),
    # "What do/does you/that/this/it mean?"
    re.compile(
        r"\bwhat\s+(?:do|does)\s+(?:you|that|this|it|those|these)\s+mean\b",
        re.IGNORECASE,
    ),
    # "In other words"
    re.compile(
        r"\bin\s+other\s+words\b",
        re.IGNORECASE,
    ),
)


def looks_like_work_mode_schedule_followup(text: str) -> bool:
    """Advice about a visible plan/schedule block — not a local venue search.

    Catches turns like "is gym at 9:20 too late?" where ``gym`` would otherwise
    match ``_INFO_TOOL_VENUE_RE`` and misroute to web search.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    low = raw.lower()
    if re.search(
        r"\b(?:near\s+me|nearby|around\s+here|find\s+(?:a\s+)?(?:gym|gyms|coffee|restaurant|restaurants))\b",
        low,
    ):
        return False
    time_ref = bool(
        re.search(
            r"\b(?:at|by|around)\s+\d{1,2}(?::\d{2})?\s*(?:am|pm)?\b|\b\d{1,2}:\d{2}\s*(?:am|pm)?\b",
            low,
        )
    )
    advice_ref = bool(
        re.search(
            r"\b(?:too\s+(?:late|early)|move\s+(?:it|that|this|gym)?\s*(?:earlier|later)|"
            r"should\s+i\b|realistic|doable|feasible|enough\s+time|"
            r"what(?:'s|s|\s+is)\s+next|what\s+should\s+i\s+do|"
            r"(?:first|next)\s+(?:on|in)\s+(?:the\s+)?(?:plan|schedule|checklist))\b",
            low,
        )
    )
    plan_ref = bool(
        re.search(
            r"\b(?:the\s+)?(?:plan|schedule|checklist|time\s*block)\b|"
            r"\b(?:this|that)\s+(?:too\s+)?(?:late|early)\b",
            low,
        )
    )
    question = bool(
        re.search(r"^\s*(?:is|are|was|were|will|would|should|can|could|do|does|what|when)\b", low)
    )
    if time_ref and (advice_ref or question):
        return True
    if plan_ref and question:
        return True
    if advice_ref and question and len(low.split()) <= 20:
        return True
    return False


def looks_like_explanation_or_interpretation(text: str) -> bool:
    """Return True when the transcript looks like a CONCEPTUAL
    explanation / definition / interpretation request (a "what does X
    mean", "explain that", "does that mean...", etc. shape) - NOT a
    request for external / current information.

    Used together with :func:`has_search_need` by the 2026-06-01 pre-
    search sanity gate. The helper deliberately stays shape-focused
    rather than topic-focused so it generalizes across finance, news,
    tech, science, slang, etc. without per-topic carve-outs.

    Returns False on empty / whitespace input.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    for pat in _EXPLANATION_OR_INTERPRETATION_RES:
        if pat.search(raw):
            return True
    return False


def is_ambiguous_breaking_news_phrase(text: str) -> bool:
    lowered = text.lower().strip()
    if not lowered:
        return False

    return bool(re.match(r"^(?:the\s+)?(?:latest\s+)?breaking news[?!.\s]*$", lowered))


# 2026-06-01 — explicit general-news intent.
#
# Matches transcripts that ask for "general news" with no specific search
# target, e.g. "tell me about the news", "can you tell me the latest news?",
# "what are today's headlines?", "any news updates?". When this fires we
# bypass the broad-news Serper search path and route directly to the BBC
# RSS top-headlines flow (handle_news_request with query=None, breaking=False,
# search_queries=None -> get_top_news(limit=3) -> BBC_NEWS_PREAMBLE).
#
# Negative cases ("BBC news about Ukraine", "search news on Nvidia
# earnings", "show me sports news about Lakers", "what's the weather
# news?") still flow through the existing topical-news / weather / sports
# routers. The guard set on `_CONFLICT_INTENT_RE` keeps domain-specific
# news questions out of the BBC top-headlines path so the corresponding
# routers can claim them.
_GENERAL_NEWS_WORD_RE = re.compile(
    r"\b(news|headlines|top stories|current events|breaking news|news updates|world events)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_ASKS_LATEST_RE = re.compile(
    r"\b(latest|today(?:'s)?|current|currently|happening|going on|update|updates|top|new|recent|fresh)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_GENERAL_PATTERN_RE = re.compile(
    r"\b(tell me|can you tell me|could you tell me|give me|show me|"
    r"what'?s|what is|what are|any)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_SPECIFIC_TARGET_RE = re.compile(
    r"\b(?:about|on|regarding|with|for|from)\b\s+\w+",
    re.IGNORECASE,
)
_GENERAL_NEWS_PERSONAL_OWNER_RE = re.compile(
    r"\bmy\s+(?:mom|dad|family|friend|brother|sister|son|daughter|"
    r"grandma|grandpa|aunt|uncle|cousin|wife|husband|partner|parent|kid|kids|child|children)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_TARGET_EXCEPTION_RE = re.compile(
    r"\babout\s+(?:the\s+)?news\b|\bin\s+(?:the\s+)?world\b|"
    r"\bgoing\s+on\s+in\s+(?:the\s+)?(?:news|world)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_CONFLICT_INTENT_RE = re.compile(
    r"\b(weather|temperature|forecast|stock|stocks|share|shares|"
    r"ticker|crypto|finance|markets?|sports?|game|games|score|scores|"
    r"music|spotify|playlist|song|songs|track|tracks|playback|"
    r"checklist|todo|to-do|to do|timer|alarm|reasoning panel|reasoning panels)\b",
    re.IGNORECASE,
)
_GENERAL_NEWS_WORLD_HAPPENING_RE = re.compile(
    r"\b(?:happening|going\s+on|news)\b.{0,40}\bin\s+(?:the\s+)?world\b",
    re.IGNORECASE,
)


def is_explicit_general_news_intent(text: str) -> bool:
    """True when the user is asking for general latest news / top headlines
    with no specific topic, brand, or domain target.

    Spec ("Patch: route explicit general news requests to BBC, not Serper",
    2026-06-01):

      - "Tell me about the news."                 -> True
      - "Can you tell me the latest news?"        -> True
      - "What's the latest news?"                 -> True
      - "Give me today's headlines."              -> True
      - "Any news updates?"                       -> True
      - "What's happening in the world?"          -> True
      - "Tell me the top stories."                -> True
      - "What are the latest headlines?"          -> True
      - "Search news about Nvidia earnings."      -> False (specific target)
      - "Find latest news on Spotify layoffs."    -> False (specific target)
      - "BBC news about Ukraine."                 -> False (specific target)
      - "Show me sports news about Lakers."       -> False (specific target)
      - "What's the weather news?"                -> False (weather wins)
      - "News about UCI"                          -> False (specific target)
    """
    raw = (text or "").lower().strip()
    if not raw:
        return False

    # World-only positive shortcut: "what's happening in the world?",
    # "what's going on in the world right now?" — these don't contain a
    # bare news/headlines keyword but are explicitly general news intent
    # per the patch spec's positive list.
    world_happening = bool(_GENERAL_NEWS_WORLD_HAPPENING_RE.search(raw))

    if not world_happening and not _GENERAL_NEWS_WORD_RE.search(raw):
        return False

    asks_latest = bool(_GENERAL_NEWS_ASKS_LATEST_RE.search(raw))
    general_pattern = bool(_GENERAL_NEWS_GENERAL_PATTERN_RE.search(raw))
    if not world_happening and not (asks_latest or general_pattern):
        return False

    # Specific-target check: "about Nvidia", "on Spotify layoffs",
    # "regarding the war". The exception list lets "about the news",
    # "in the world", "going on in the news/world" still count as general.
    has_specific_target = bool(_GENERAL_NEWS_SPECIFIC_TARGET_RE.search(raw)) and not bool(
        _GENERAL_NEWS_TARGET_EXCEPTION_RE.search(raw)
    )
    if has_specific_target:
        return False

    # Conflict-intent guard: if the transcript also mentions weather /
    # finance / sports / music / app UI, defer to those routers instead
    # of forcing BBC top headlines.
    if _GENERAL_NEWS_CONFLICT_INTENT_RE.search(raw):
        return False

    # Personal-source guard: "news from my family", "news from my mom"
    # etc. — that's personal/emotional, not a general headlines request.
    # The `from`-clause in _GENERAL_NEWS_SPECIFIC_TARGET_RE already
    # blocks "news from my family" via the specific-target check, but
    # we keep this explicit second pass for cases where the personal
    # owner is mentioned without a preposition ("any news, my family's
    # been worried").
    if _GENERAL_NEWS_PERSONAL_OWNER_RE.search(raw):
        return False

    return True


def is_explicit_news_request(text: str, query: str | None = None, breaking: bool = False) -> bool:
    raw = (text or "").strip().lower()
    if not raw:
        return False

    if breaking:
        return is_breaking_news_phrase(raw)

    if query:
        return bool(
            re.search(
                r"\b(?:news\s+about|news\s+on|latest\s+on|what happened with|what(?:'s|s)\s+going\s+on\s+in|whats?\s+going\s+in|breaking news about|latest updates about|latest updates on)\b",
                raw,
            )
        )

    return bool(
        re.search(
            r"\b(?:what(?:'s|s| is)\s+the\s+news|latest\s+headlines|latest\s+news|breaking\s+news|news\s+right\s+now|update\s+me\s+on\s+the\s+news|tell\s+me\s+(?:some\s+|the\s+)?news|any\s+news)\b",
            raw,
        )
    )


def is_finance_followup_request(text: str, query: str | None = None, recent_action: dict | None = None) -> bool:
    raw = (text or "").strip().lower()
    cleaned_query = clean_finance_subject_text(query)
    if not raw or not cleaned_query or not is_plausible_finance_subject(cleaned_query):
        return False

    recent_action_name = (recent_action or {}).get("action_name")
    if recent_action_name not in {"finance.quote", "finance.context"}:
        return False

    if re.match(r"^(?:how about|what about|and|about)\b", raw):
        return True

    if re.search(r"\b(?:again|instead|according to|using|via|from)\b", raw):
        return True

    if re.search(r"\b(?:check|quote|price|stock|ticker|shares|trading)\b", raw):
        return True

    return False


def is_explicit_finance_request(text: str, action_name: str, query: str | None = None, recent_action: dict | None = None) -> bool:
    raw = (text or "").strip().lower()
    if not raw:
        return False

    if is_finance_followup_request(raw, query=query, recent_action=recent_action):
        return True

    if action_name == "finance.quote":
        return bool(
            re.search(
                r"\b(?:stock price|share price|price of|quote for|trading at|market cap|how much is)\b",
                raw,
            )
        )

    if action_name == "finance.context":
        if re.search(
            r"\b(?:what(?:'s|s| is)\s+happening with|what(?:'s|s| is)\s+going on with|why is|do you know why|what happened to|latest on .+ stock|tell me about .+ earnings|tell me about .+ guidance|how is .+ stock doing)\b",
            raw,
        ):
            return True

        if query and is_likely_finance_subject(query) and re.search(
            r"\b(?:down|up|drop|dropped|dropping|fall|fell|falling|rise|rose|rising|surge|surged|slump|slumped|tank|tanked|selloff|sell-off|red|green)\b",
            raw,
        ):
            return True

        if query and re.search(r"\b(?:earnings|guidance|outlook|stock|shares|etf|fund|ticker|market|quote)\b", raw):
            return True

        return False

    return False


def is_plausible_finance_subject(text: str | None) -> bool:
    subject = clean_finance_subject_text(text)
    if not subject or len(subject) > 80:
        return False

    lowered = subject.lower()
    if lowered in {
        "stock",
        "stocks",
        "share",
        "shares",
        "stock price",
        "share price",
        "price",
        "quote",
        "ticker",
        "company",
        "market",
    }:
        return False

    if not re.search(r"[A-Za-z0-9]", subject):
        return False

    return True


def resolve_pending_breaking_news_request(session_id: str, text: str, filler_generation: int | None = None):
    lowered = text.strip().lower()
    if not lowered:
        set_pending_action(session_id, "news.latest", "breaking_intent", {"breaking": True})
        return {
            "spoken_reply": "Do you want me to look up breaking news, or do you have breaking news for me?",
            "action_type": "news",
            "data": None,
            "ui_payload": None,
        }, 0.0

    query_choice = bool(
        re.search(
            r"\b(?:former|first|first one|the first one|first option|the first option|look it up|query it|search it|check it|fetch it|show me|tell me|give me|for me|from the web|online|you tell me|you look it up)\b",
            lowered,
        )
    )
    share_choice = bool(
        re.search(
            r"\b(?:latter|second|second one|the second one|second option|the second option|from me|for you|i have|i've got|i got|my news|hear me out|mine|my turn)\b",
            lowered,
        )
    )

    query_intent = (
        is_breaking_news_phrase(lowered)
        or bool(re.search(r"\b(?:query|look up|search|check|fetch|show me|tell me|give me|for me|from the web|online)\b", lowered))
        or lowered in {"yes", "yeah", "yep", "sure", "do that"}
        or query_choice
    )
    share_intent = share_choice

    if query_intent and not share_intent:
        clear_pending_action(session_id)
        t0 = perf_counter()
        action_result = handle_news_request(vera, query=None, breaking=True)
        set_recent_action_from_result(session_id, "news.latest", {"breaking": True}, action_result)
        return action_result, perf_counter() - t0

    if share_intent and not query_intent:
        clear_pending_action(session_id)
        return None, 0.0

    set_pending_action(session_id, "news.latest", "breaking_intent", {"breaking": True})
    return {
        "spoken_reply": "Do you want me to look up breaking news, or do you have breaking news for me?",
        "action_type": "news",
        "data": None,
        "ui_payload": None,
    }, 0.0


def resolve_pending_finance_request(session_id: str, text: str, pending: dict, filler_generation: int | None = None):
    action_name = pending.get("action_name")
    subject = clean_finance_subject_text(text)
    if not is_plausible_finance_subject(subject):
        prompt = (
            FINANCE_QUOTE_SUBJECT_PROMPT
            if action_name == "finance.quote"
            else FINANCE_CONTEXT_SUBJECT_PROMPT
        )
        set_pending_action(session_id, action_name, pending.get("missing_slot", "query"), pending.get("slots", {}))
        return {
            "spoken_reply": prompt,
            "action_type": "finance",
            "data": None,
            "ui_payload": None,
        }, 0.0

    clear_pending_action(session_id)
    slots = dict(pending.get("slots", {}))
    slots["query"] = subject

    t0 = perf_counter()
    if action_name == "finance.quote":
        action_result = handle_finance_quote_request(vera, query=subject)
    else:
        action_result = handle_finance_context_request(vera, query=subject)

    set_recent_action_from_result(session_id, action_name, slots, action_result)
    return action_result, perf_counter() - t0


def resolve_pending_music_play_request(session_id: str, text: str) -> tuple[dict, float]:
    q = text.strip()
    if not q:
        set_pending_action(session_id, "music.play_track", "track_query", {})
        return {
            "spoken_reply": MUSIC_TRACK_QUERY_PROMPT,
            "action_type": "music",
            "data": None,
            "ui_payload": None,
        }, 0.0
    clear_pending_action(session_id)
    action_result = handle_music_play_for_user_text(q)
    set_recent_action_from_result(session_id, "music.play_track", {"query": q}, action_result)
    return action_result, 0.0


