def normalize_followup_query(candidate: str) -> str:
    value = clean_action_query(candidate)
    value = re.sub(r"^(?:the|more on|about)\s+", "", value, flags=re.IGNORECASE)
    return value.strip().strip(string.punctuation + " ")


def is_news_refinement_phrase(query: str) -> bool:
    lowered = query.lower()
    return any(
        keyword in lowered for keyword in [
            "economy",
            "economic",
            "business",
            "company",
            "companies",
            "market",
            "markets",
            "politics",
            "political",
            "government",
            "war",
            "conflict",
            "tech",
            "technology",
        ]
    )


def build_news_followup_query(base_query: str | None, candidate: str) -> str:
    followup = normalize_followup_query(candidate)
    if not followup:
        return ""

    base = clean_action_query(base_query)
    if base and is_news_refinement_phrase(followup):
        return f"{base} {followup}".strip()

    return followup


def build_finance_followup_route(recent_action: str, recent_query: str | None, candidate: str) -> dict | None:
    followup = normalize_followup_query(candidate)
    if not followup:
        return None

    recent_subject = clean_action_query(recent_query)
    lowered = followup.lower()

    if re.search(r"\b(?:price|quote|trading at|trading)\b", lowered):
        subject = recent_subject or followup
        if not subject:
            return None
        return {
            "is_action_request": True,
            "action_name": "finance.quote",
            "slots": {"query": subject},
        }

    if re.search(r"\b(?:why|happening|going on|news|earnings|guidance|outlook)\b", lowered):
        subject = recent_subject or followup
        if not subject:
            return None
        return {
            "is_action_request": True,
            "action_name": "finance.context",
            "slots": {"query": subject},
        }

    if is_likely_finance_subject(followup):
        return {
            "is_action_request": True,
            "action_name": recent_action,
            "slots": {"query": followup},
        }

    if recent_subject:
        return {
            "is_action_request": True,
            "action_name": "finance.context",
            "slots": {"query": f"{recent_subject} {followup}".strip()},
        }

    return None


_MUSIC_PANEL_OPEN_PATTERNS: tuple[re.Pattern[str], ...] = (
    # Verb + (music|spotify) [+ optional panel/tab/widget/...]
    re.compile(
        r"\b(?:open|show|bring up|pull up|launch|reopen|display|switch to)\b"
        r"\s+(?:the\s+|a\s+|my\s+)?"
        r"(?:music|spotify)\b(?:\s+(?:panel|tab|page|window|view|controls|player|widget))?"
    ),
    # Verb + playback|spotify + UI noun
    re.compile(
        r"\b(?:open|show|bring up|pull up|display|reopen)\b"
        r"\s+(?:the\s+|my\s+)?(?:playback|spotify)\s+(?:panel|controls|tab|window|view|player)\b"
    ),
    # Bare (music|spotify|playback) + UI noun ("music panel", "playback panel", "spotify tab")
    re.compile(
        r"\b(?:music|spotify|playback)\s+(?:panel|tab|page|window|view|widget|controls|player)\b"
    ),
    # "show me the playback controls" / "give me the playback controls"
    re.compile(
        r"\b(?:show|give me|bring up)\s+(?:the\s+)?playback\s+controls\b"
    ),
    # "I want the music panel", "let me see the spotify tab"
    re.compile(
        r"\b(?:i\s+want|gimme|give\s+me|let me see)\s+(?:the\s+)?(?:music|spotify|playback)\s+(?:panel|tab|controls)?"
    ),
)


def _is_music_open_panel_request(text: str) -> bool:
    """True when the user is asking to surface the music / Spotify / playback panel.

    Routed to `music.open_panel` BEFORE any other heuristic so phrases like
    "open music panel", "show music panel", "bring up music panel",
    "open spotify panel", or bare "playback panel" can never be intercepted
    by the work-mode reasoning-panel regex (which would otherwise reply
    "Turn on VERA work mode to switch reasoning panels.").
    """
    lowered = (text or "").strip().lower()
    if not lowered:
        return False
    return any(rx.search(lowered) for rx in _MUSIC_PANEL_OPEN_PATTERNS)


# =========================================================================
# NEWS PANEL UI ACTIONS
#
# "Open the news panel" / "show news panel" / "close the news panel" are
# pure UI commands. They must be intercepted BEFORE the work-mode
# reasoning-panel regex so the user never gets "Turn on VERA work mode to
# open a new reasoning panel." when they only want to surface the News
# side panel.
#
# Important: the patterns DELIBERATELY require a panel/tab/results/etc.
# noun (or a strict bare imperative like "open news") to fire — we do NOT
# match "tell me the news", "show me breaking news", "what's the latest
# news" here. Those are content requests (handled by the news.latest
# heuristic + LLM router downstream) and a panel-open UI action would
# strip the actual headlines from the answer.
# =========================================================================
_NEWS_PANEL_OPEN_PATTERNS: tuple[re.Pattern[str], ...] = (
    # "open the news panel", "show news tab", "bring up news widget", etc.
    re.compile(
        r"\b(?:open|show|bring\s+up|pull\s+up|launch|reopen|display|switch\s+to|put\s+up)\b"
        r"\s+(?:the\s+|a\s+|my\s+|that\s+|your\s+)?"
        r"news\s+(?:panel|tab|page|window|view|widget|results?|side\s*panel|sidebar)\b"
    ),
    # "open headlines panel/tab"
    re.compile(
        r"\b(?:open|show|bring\s+up|pull\s+up|display)\b"
        r"\s+(?:the\s+)?headlines\s+(?:panel|tab|page|view|widget)\b"
    ),
    # Bare imperatives — strict: must be the whole sentence so we don't
    # eat "open news about Trump" (that's a content search).
    re.compile(
        r"^(?:hey\s+vera[, ]+)?(?:can\s+you\s+|could\s+you\s+|please\s+)?"
        r"(?:open|show|bring\s+up|pull\s+up|display|reopen|put\s+up)\s+"
        r"(?:the\s+|my\s+)?(?:news|news\s+panel|news\s+tab|news\s+results?)\s*[?!.\s]*$"
    ),
    # "I want the news panel"
    re.compile(
        r"\b(?:i\s+want|gimme|give\s+me|let\s+me\s+see)\s+(?:the\s+)?news\s+(?:panel|tab|results?|window)\b"
    ),
)


_NEWS_PANEL_CLOSE_PATTERNS: tuple[re.Pattern[str], ...] = (
    re.compile(
        r"\b(?:close|hide|dismiss|put\s+away|get\s+rid\s+of|minimize|collapse)\b"
        r"\s+(?:the\s+|that\s+|this\s+|my\s+)?"
        r"news\s+(?:panel|tab|page|window|view|widget|results?|side\s*panel|sidebar)\b"
    ),
    re.compile(
        r"\b(?:close|hide)\s+(?:the\s+)?headlines\s+(?:panel|tab|view)?\b"
    ),
    re.compile(
        r"^(?:hey\s+vera[, ]+)?(?:can\s+you\s+|could\s+you\s+|please\s+)?"
        r"(?:close|hide|dismiss|put\s+away|minimize)\s+"
        r"(?:the\s+|my\s+|that\s+)?(?:news|news\s+panel|news\s+tab|news\s+results?)\s*[?!.\s]*$"
    ),
)


def _is_news_panel_open_request(text: str) -> bool:
    """True when the user is asking to surface the News side panel.

    Strictly requires a panel/tab/widget/results noun (or a bare
    "open news" full-sentence imperative). Content requests like
    "tell me the news" or "show me breaking news about Trump" are
    routed to the content path instead.
    """
    lowered = (text or "").strip().lower()
    if not lowered:
        return False
    return any(rx.search(lowered) for rx in _NEWS_PANEL_OPEN_PATTERNS)


def _is_news_panel_close_request(text: str) -> bool:
    """True when the user is asking to hide the News side panel."""
    lowered = (text or "").strip().lower()
    if not lowered:
        return False
    return any(rx.search(lowered) for rx in _NEWS_PANEL_CLOSE_PATTERNS)


# === Reasoning-panel CLOSE intent detection (spec PART 3+13) ===========
#
# "close this panel", "close panel 2", "close the first two panels",
# "close all reasoning panels", "close all other panels", "undo close" —
# these belong to work_mode.reasoning_close_panel. The frontend owns all
# index resolution, refill, undo, and DOM mutation; this module just
# decides which action to dispatch.
#
# IMPORTANT — what we MUST NOT eat (PART 13 + PART 17):
#   • "remove the first item"  → checklist mutation, not panel close
#   • "close the news panel"   → news.close_panel
#   • "close music"            → music.close_panel
#   • "close settings"         → settings (out of scope)
#   • "close browser tab"      → no-op for us
_REASONING_CLOSE_VERB_RE = re.compile(
    r"\b(?:close|clear|hide|dismiss|remove|delete|get\s+rid\s+of)\b", re.IGNORECASE
)
_REASONING_CLOSE_PANEL_NOUN_RE = re.compile(
    r"\b(?:reasoning(?:\s+(?:panel|tab|space|lane|page))?|panels?|tabs?|reasoning\s+space|reasoning\s+lane)\b",
    re.IGNORECASE,
)
# When the user says "keep this one and close the rest" / "close the others",
# the noun "rest"/"others" is what they mean by "the remaining panels", and
# only makes sense in the reasoning-workspace context (you don't "keep one
# and close the rest" of music tracks or news headlines).
_REASONING_CLOSE_REST_OTHERS_RE = re.compile(
    r"\b(?:close|hide|dismiss|remove)\s+(?:all\s+)?(?:the\s+)?(?:rest|others?|other\s+ones?)\b"
    r"|\bkeep\s+this\s+one\s+(?:and\s+(?:close|hide|dismiss|remove)\s+)?(?:the\s+)?(?:rest|others?)\b",
    re.IGNORECASE,
)
_REASONING_CLOSE_NON_REASONING_SUBJECTS_RE = re.compile(
    r"\b(?:news|music|spotify|playback|finance|settings?|checklist|browser\s+tab)\b",
    re.IGNORECASE,
)
_REASONING_CHECKLIST_PATTERN_RE = re.compile(
    r"\b(?:remove|delete|cross\s+off|check\s+off|uncheck|tick|check|mark)\s+(?:the\s+)?"
    r"(?:first|second|third|fourth|fifth|last|\d+(?:st|nd|rd|th)?)?\s*"
    r"(?:and\s+(?:first|second|third|fourth|fifth|last|\d+(?:st|nd|rd|th)?)\s*)?"
    r"(?:item|task|bullet|checklist|to[- ]?do|todo|step)s?\b",
    re.IGNORECASE,
)
_REASONING_REOPEN_RE = re.compile(
    r"\b(?:undo\s+close|reopen\s+(?:the\s+)?(?:last\s+)?(?:reasoning\s+)?panel|"
    r"restore\s+(?:the\s+)?(?:last\s+)?closed\s+(?:reasoning\s+)?panel|"
    r"bring\s+back\s+(?:the\s+)?(?:last|previous)\s+(?:reasoning\s+)?panel)\b",
    re.IGNORECASE,
)

_REASONING_ORDINAL_WORDS = {
    "first": 1, "1st": 1,
    "second": 2, "2nd": 2,
    "third": 3, "3rd": 3,
    "fourth": 4, "4th": 4,
    "fifth": 5, "5th": 5,
    "sixth": 6, "6th": 6,
    "seventh": 7, "7th": 7,
    "eighth": 8, "8th": 8,
}
_REASONING_COUNT_WORDS = {
    "one": 1, "two": 2, "three": 3, "four": 4,
    "five": 5, "six": 6, "seven": 7, "eight": 8,
}


def _is_reasoning_close_panel_request(text: str) -> bool:
    """Cheap top-of-pipeline detector: does this look like a reasoning-panel
    close (or undo-close) command?

    We only return True when we are highly confident — otherwise we let the
    LLM router (work_mode.reasoning_close_panel) decide. False positives
    here would cause the user to lose a tab unintentionally."""
    raw = (text or "").strip()
    if not raw:
        return False
    lowered = raw.lower()
    if _REASONING_REOPEN_RE.search(lowered):
        return True
    if not _REASONING_CLOSE_VERB_RE.search(lowered):
        return False
    if _REASONING_CHECKLIST_PATTERN_RE.search(lowered):
        return False
    # If the user names a different surface (news/music/...), let that
    # surface's own guard handle it.
    if _REASONING_CLOSE_NON_REASONING_SUBJECTS_RE.search(lowered):
        return False
    if _REASONING_CLOSE_PANEL_NOUN_RE.search(lowered):
        return True
    # "keep this one and close the rest" / "close the others" — implicit
    # reasoning-workspace context, no explicit panel/tab noun.
    if _REASONING_CLOSE_REST_OTHERS_RE.search(lowered):
        return True
    return False


def _classify_reasoning_close_panel_scope(text: str) -> dict:
    """Return parsed scope + slots for a reasoning-panel-close request.

    Output shape (compatible with handle_work_mode_reasoning_close_panel):
        {
          "scope": "specific_indices" | "range_first_n" | "range_last_n" |
                   "range" | "all_panels" | "other_panels" |
                   "by_title" | "current_panel" | "reopen_last" |
                   "unresolved",
          "indices": [1-based, ...],   # absolute visual indices when known
          "range_n": int | None,       # for range_last_n we may not know N
          "title_query": str,
          "rationale": str,
        }
    """
    raw = (text or "").strip()
    if not raw:
        return {"scope": "unresolved", "indices": [], "range_n": None, "title_query": "", "rationale": "empty"}
    s = raw.lower()
    if _REASONING_REOPEN_RE.search(s):
        return {"scope": "reopen_last", "indices": [], "range_n": None, "title_query": "", "rationale": "reopen_keyword"}

    # all / others
    if re.search(
        r"\b(?:close|clear)\s+(?:all\s+other\s+|all\s+the\s+other\s+|every\s+other\s+|the\s+other\s+|inactive\s+|other\s+)"
        r"(?:reasoning\s+)?(?:panels?|tabs?|reasoning\s+(?:panel|tab|space)s?)\b",
        s,
    ) or re.search(r"\bkeep\s+this\s+one\s+(?:and\s+close\s+)?(?:the\s+)?(?:rest|others?|other\s+panels?)\b", s):
        return {"scope": "other_panels", "indices": [], "range_n": None, "title_query": "", "rationale": "all_other_panels"}
    if re.search(
        r"\b(?:close|clear)\s+(?:all\s+(?:the\s+)?|every\s+)?(?:reasoning\s+)?(?:panels?|tabs?|reasoning\s+(?:panel|tab|space)s?)\b",
        s,
    ) and not re.search(r"\b(?:panel|tab|reasoning)\s+\d", s):
        # "close all panels" / "clear reasoning panels" / "close every panel"
        if re.search(r"\b(?:all|every|all\s+the)\b", s):
            return {"scope": "all_panels", "indices": [], "range_n": None, "title_query": "", "rationale": "all_panels"}

    # current
    if re.search(
        r"\bclose\s+(?:this|the\s+current|current)\s+(?:reasoning\s+)?(?:panel|tab|space|lane)\b",
        s,
    ) or re.search(r"\bclose\s+this\s+reasoning\s+panel\b", s):
        return {"scope": "current_panel", "indices": [], "range_n": None, "title_query": "", "rationale": "current_panel"}
    if re.search(
        r"\bclose\s+(?:the\s+)?(?:reasoning\s+)?(?:panel|tab|space|lane)\b"
        r"(?!\s*(?:#?\d|first|1st|second|2nd|third|3rd|fourth|4th|fifth|5th|sixth|6th|seventh|7th|eighth|8th|last)\b)",
        s,
    ):
        return {"scope": "current_panel", "indices": [], "range_n": None, "title_query": "", "rationale": "bare_panel_close"}

    # range: "close panels 1 through 3"
    m = re.search(
        r"\bclose\s+(?:the\s+)?(?:reasoning\s+)?(?:panels?|tabs?|reasoning\s+(?:panel|tab|space|lane)s?)\s+(\d+)\s+(?:through|thru|to|-)\s+(\d+)\b",
        s,
    )
    if m:
        try:
            a = int(m.group(1))
            b = int(m.group(2))
            if a <= b:
                return {
                    "scope": "range",
                    "indices": list(range(a, b + 1)),
                    "range_n": None,
                    "title_query": "",
                    "rationale": "range_through",
                }
        except (TypeError, ValueError):
            pass

    # "close the first N"
    m = re.search(
        r"\bclose\s+(?:the\s+)?first\s+(\d+|one|two|three|four|five|six|seven|eight)\s+(?:reasoning\s+)?(?:panels?|tabs?|spaces?|lanes?)\b",
        s,
    )
    if m:
        token = m.group(1)
        n = int(token) if token.isdigit() else _REASONING_COUNT_WORDS.get(token, 0)
        if n > 0:
            return {"scope": "range_first_n", "indices": list(range(1, n + 1)), "range_n": n, "title_query": "", "rationale": "range_first_n"}

    # "close the last N"
    m = re.search(
        r"\bclose\s+(?:the\s+)?last\s+(\d+|one|two|three|four|five|six|seven|eight)\s+(?:reasoning\s+)?(?:panels?|tabs?|spaces?|lanes?)\b",
        s,
    )
    if m:
        token = m.group(1)
        n = int(token) if token.isdigit() else _REASONING_COUNT_WORDS.get(token, 0)
        if n > 0:
            # Frontend resolves the actual indices using its live panel count.
            return {"scope": "range_last_n", "indices": [], "range_n": n, "title_query": "", "rationale": "range_last_n"}

    # specific indices: word ordinals + numeric "panel N"
    found: list[int] = []
    for w_m in re.finditer(
        r"\b(first|1st|second|2nd|third|3rd|fourth|4th|fifth|5th|sixth|6th|seventh|7th|eighth|8th|last)\b",
        s,
    ):
        token = w_m.group(1)
        if token == "last":
            # Treat "last" as "the last index" — emit a sentinel; frontend
            # will resolve. We use 0 to signal "last" since 0 is not a valid
            # 1-based index; the handler skips zeros and reads `last_count`.
            continue
        n = _REASONING_ORDINAL_WORDS.get(token)
        if n:
            found.append(n)

    for n_m in re.finditer(
        r"\b(?:panels?|tabs?|reasoning\s+(?:panel|tab|space|lane)s?)\s+#?\s*"
        r"(\d+(?:\s*(?:,\s*and|,\s*or|and|or|,|&)\s*\d+){0,8})\b",
        s,
    ):
        for piece in re.split(r"\s*(?:,\s*and|,\s*or|and|or|,|&)\s*", n_m.group(1)):
            try:
                found.append(int(piece))
            except (TypeError, ValueError):
                pass

    if found:
        dedup = sorted(set(n for n in found if n >= 1))
        if dedup:
            return {
                "scope": "specific_indices",
                "indices": dedup,
                "range_n": None,
                "title_query": "",
                "rationale": "explicit_ordinals_or_numerics",
            }

    # by title
    m = re.search(
        r"\bclose\s+(?:the\s+)?(.+?)\s+(?:reasoning\s+)?(?:panel|tab|space|lane)\b",
        raw,
        re.IGNORECASE,
    )
    if m:
        candidate = m.group(1).strip()
        if candidate and not re.fullmatch(
            r"this|that|the|a|an|current|other|inactive|new|blank|first|second|third|fourth|fifth|last|right|left|next|previous|prior|active|focused|selected",
            candidate,
            re.IGNORECASE,
        ):
            return {"scope": "by_title", "indices": [], "range_n": None, "title_query": candidate, "rationale": "by_title"}

    return {"scope": "unresolved", "indices": [], "range_n": None, "title_query": "", "rationale": "no_match"}


_SMALL_COUNT_WORDS = {
    "a": 1,
    "an": 1,
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
}


def _parse_small_count_word(value: str | None) -> int | None:
    s = str(value or "").strip().lower()
    if not s:
        return None
    if re.fullmatch(r"\d{1,2}", s):
        n = int(s)
        return n if n > 0 else None
    return _SMALL_COUNT_WORDS.get(s)


def _work_mode_create_reasoning_panel_count(text: str) -> int | None:
    """
    Generic tab/panel creation. Keep this separate from select-panel routing:
    "open a tab" / "new panel" creates, while "open the essay panel" selects.
    """
    s = (text or "").strip().lower()
    if not s:
        return None
    noun = r"(?:reasoning\s+)?(?:panel|space|tab|lane|page)s?"
    count_word = r"(?P<count>\d{1,2}|a|an|one|two|three|four|five|six|seven|eight)"
    patterns = [
        rf"\b(?:open(?:\s+up)?|add|create|make)\s+(?:{count_word}\s+)?(?:new\s+)?{noun}\b",
        rf"\bnew\s+(?:{count_word}\s+)?{noun}\b",
    ]
    for pat in patterns:
        m = re.search(pat, s, flags=re.IGNORECASE)
        if not m:
            continue
        return _parse_small_count_word((m.groupdict() or {}).get("count")) or 1
    return None


# Maps the legacy single-action transport/volume action names to the canonical
# music-family identifier used by ``detect_music_unsupported_modifier`` and the
# unsupported-message builder.
_MUSIC_TRANSPORT_ACTION_FAMILY: dict[str, str] = {
    "music.pause": "music.pause",
    "music.resume": "music.resume",
    "music.skip_next": "music.next",
    "music.skip_previous": "music.previous",
    "music.volume_up": "music.volume",
    "music.volume_down": "music.volume",
}

# "I can <immediate> now" clause per family for the unsupported reply.
_MUSIC_IMMEDIATE_CLAUSE: dict[str, str] = {
    "music.play": "play music",
    "music.pause": "pause music",
    "music.resume": "resume playback",
    "music.next": "skip tracks",
    "music.previous": "skip tracks",
    "music.volume": "change the volume",
}


def _music_unsupported_scheduled_clause(family: str, phrase: str) -> str:
    """The "<scheduled thing>" half of the unsupported reply per family."""
    p = (phrase or "").strip()
    if family == "music.pause":
        return f"pausing {p}".strip() if p else "pausing for later"
    if family == "music.resume":
        return "resuming later"
    if family in ("music.next", "music.previous"):
        return "track changes"
    if family == "music.volume":
        return "volume changes"
    if family == "music.play":
        return "music to start later"
    return "that for later"


def _music_unsupported_spoken(
    family: str, *, phrase: str = "", valid_clause: str | None = None
) -> str:
    """Build the action-specific "can't schedule ... yet" reply.

    ``valid_clause`` overrides the leading "I can <X> now" half so a mixed
    compound ("play Feather and pause in 10 minutes") can name the valid
    sibling: "I can play Feather now, but I can't schedule pausing in 10
    minutes yet."
    """
    immediate = valid_clause or _MUSIC_IMMEDIATE_CLAUSE.get(family, "do that")
    scheduled = _music_unsupported_scheduled_clause(family, phrase)
    return f"I can {immediate} now, but I can't schedule {scheduled} yet."


# A sibling span counts as a "peeled" timing/conditional modifier only when it
# *starts* with a scheduling keyword. This stops a real follow-up request
# ("... and tell me when the timer ends") from being mistaken for a modifier.
_MODIFIER_LEADING_RE = re.compile(
    r"^\s*(?:when|after|once|as\s+soon\s+as|in|at|every|each|"
    r"tomorrow|tonight|later|this|next|daily|hourly|weekly|nightly)\b",
    re.IGNORECASE,
)

_MUSIC_FAMILY_SET = {
    "music.play",
    "music.pause",
    "music.resume",
    "music.next",
    "music.previous",
    "music.volume",
}


def _strip_music_modifier_phrase(query: str, phrase: str) -> str:
    """Remove the unsupported timing phrase from a music.play query.

    Keeps the "can do now" clause clean ("play Feather tomorrow" → "play
    Feather") so the spoken reply does not repeat the scheduling phrase before
    "now". Wording-only; never affects timing detection or playback.
    """
    q = (query or "").strip()
    p = (phrase or "").strip()
    if not q or not p:
        return q
    # The phrase is captured to the end of the span, so strip it as a trailing
    # tail first; fall back to removing any occurrence.
    out = re.sub(r"\s*" + re.escape(p) + r"\s*$", "", q, flags=re.IGNORECASE).strip()
    if not out:
        out = re.sub(r"\b" + re.escape(p) + r"\b", " ", q, flags=re.IGNORECASE)
        out = re.sub(r"\s+", " ", out).strip()
    return out


def _scan_plan_for_unsupported_music(
    actions: list[dict],
) -> tuple[tuple[str, dict], str | None] | None:
    """Find the first music action carrying an unsupported-modifier annotation.

    Returns ``((family, modifier_meta), valid_play_clause)`` or ``None``. The
    ``valid_play_clause`` (e.g. "play Feather") is harvested from a *valid*
    music.play sibling so the combined reply can reference it. Used by the
    pre-execution gate to block the whole compound (Option A).

    Two shapes are detected:

      1. The planner annotated the music action's own payload
         (``pause in 10 minutes`` → music.pause + unsupported metadata).
      2. The segmenter peeled a bare conditional/timing clause into the
         immediately-following sibling (``pause when the timer ends`` →
         music.pause + voice.answer "when the timer ends"). In that case the
         modifier is re-attached to the preceding music action.
    """
    unsupported: tuple[str, dict] | None = None
    valid_play_clause: str | None = None
    acts = actions or []
    n = len(acts)
    for i, a in enumerate(acts):
        fam = (a or {}).get("type") or ""
        payload = (a or {}).get("payload") or {}
        if fam in _MUSIC_FAMILY_SET:
            meta = payload.get("unsupported_music_modifier")
            if isinstance(meta, dict) and meta.get("unsupported"):
                if unsupported is None:
                    unsupported = (fam, meta)
            elif unsupported is None and i + 1 < n:
                sib = acts[i + 1] or {}
                if (sib.get("type") or "") not in _MUSIC_FAMILY_SET:
                    sib_span = (
                        (sib.get("payload") or {}).get("raw")
                        or sib.get("span")
                        or ""
                    )
                    if _MODIFIER_LEADING_RE.match(sib_span):
                        sib_meta = detect_music_unsupported_modifier(sib_span, fam)
                        if sib_meta is not None:
                            unsupported = (fam, sib_meta)
        if fam == "music.play" and valid_play_clause is None:
            q = (payload.get("query") or "").strip()
            # When this play action is itself the unsupported one, its query
            # still carries the timing phrase ("Feather tomorrow"). Strip it so
            # the "can play X now" clause is not "play Feather tomorrow now".
            pl_meta = payload.get("unsupported_music_modifier") or {}
            if isinstance(pl_meta, dict) and pl_meta.get("phrase"):
                q = _strip_music_modifier_phrase(q, pl_meta.get("phrase") or "")
            if q:
                valid_play_clause = f"play {q}"
    if unsupported is None:
        return None
    return unsupported, valid_play_clause


def _music_route_from_verdict(raw: str, verdict: dict) -> dict | None:
    """Map a ``normalize_music_play_request`` verdict to a legacy route dict.

    Single integration point so the legacy single-action route consumes the
    SAME verdict the multi-action planner uses. Returns ``None`` when the
    verdict isn't an actionable single-action music.play (the caller then
    falls through to the existing classifier cascade).
    """
    status = verdict.get("status")
    kind = verdict.get("play_kind")

    if status == "unsupported":
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_unsupported",
            "slots": {"reason": verdict.get("unsupported_reason") or "scheduling", "raw": raw},
            "needs_followup": False,
            "missing_slot": None,
        }

    if status == "needs_clarification":
        # Ask what to play (no playback). A dedicated action keeps degenerate
        # "play" / "play something" out of music.play_track and speaks the spec
        # clarification wording, while still arming the track-query follow-up.
        # Keep needs_followup=False so execute_structured_action reaches the
        # dedicated music.play_clarify branch instead of the generic follow-up
        # allowlist, which would return None and fall through to the LLM.
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_clarify",
            "slots": {"question": verdict.get("clarification_question") or "What would you like me to play?"},
            "needs_followup": False,
            "missing_slot": "track_query",
        }

    if status != "ready":
        return None

    if kind == "builtin":
        bm = verdict.get("builtin_match") or {}
        if bm.get("kind") == "playlist" and bm.get("id"):
            slots = {"playlist_id": bm["id"]}
        elif bm.get("kind") == "sound" and bm.get("id"):
            slots = {"sound_id": bm["id"]}
        else:
            return None
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_builtin",
            "slots": slots,
            "needs_followup": False,
            "missing_slot": None,
        }

    if kind == "album":
        q = (verdict.get("query") or "").strip()
        if not q:
            return None
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_album",
            "slots": {"query": q, "album_name": q},
            "needs_followup": False,
            "missing_slot": None,
        }

    if kind == "playlist_by_name":
        q = (verdict.get("query") or "").strip()
        if not q:
            return None
        slots = {"playlist_name": q}
        if verdict.get("playlist_scope_phrase"):
            slots["playlist_scope_phrase"] = verdict["playlist_scope_phrase"]
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_playlist",
            "slots": slots,
            "needs_followup": False,
            "missing_slot": None,
        }

    if kind == "track":
        q = (verdict.get("query") or "").strip()
        if not q:
            return None
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.play_track",
            "slots": {"query": q, "track_query": q},
            "needs_followup": False,
            "missing_slot": None,
        }

    return None


def heuristic_route_action(text: str) -> dict | None:
    raw = text.strip()
    if not raw:
        return None

    # Defense-in-depth: any music/spotify/playback panel request wins over
    # every later heuristic. The music-panel regex used to live below the
    # transport (pause/skip/...) checks, which made it brittle to future
    # edits. Hoisting it here means a phrase like "show music panel" can
    # never accidentally slip down into the work-mode reasoning-panel block.
    if _is_music_open_panel_request(raw):
        try:
            print(
                f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                "action=music.open_panel via=heuristic_top_guard"
            )
        except Exception:
            pass
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.open_panel",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }

    # Same defense-in-depth for News-panel UI commands. "open the news panel",
    # "show news tab", "close news" must NEVER fall through to the work-mode
    # reasoning open/select path (which currently replies "Turn on VERA work
    # mode to open a new reasoning panel."). News panel is a regular side
    # panel — not a Work Mode reasoning panel.
    if _is_news_panel_open_request(raw):
        try:
            print(
                f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                "action=news.open_panel via=heuristic_top_guard"
            )
            print(
                "[news_panel_ui] " + json.dumps(
                    {
                        "latest_user_text": raw[:200],
                        "ui_action_intent": "open_news_panel",
                        "work_mode_route": False,
                        "reasoning_panel_route": False,
                        "news_panel_opened": True,
                        "news_panel_mode": "open",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.open_panel",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    # Defense-in-depth: reasoning-panel close commands ("close this panel",
    # "close panel 2", "close the first two panels", "close all reasoning
    # panels", "undo close") must reach work_mode.reasoning_close_panel
    # without the LLM having to make the call. The detector explicitly
    # excludes news/music/checklist phrases so we don't steal those routes.
    if _is_reasoning_close_panel_request(raw):
        scope_info = _classify_reasoning_close_panel_scope(raw)
        try:
            print(
                f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                f"action=work_mode.reasoning_close_panel scope={scope_info.get('scope')} "
                "via=heuristic_top_guard"
            )
            print(
                "[reasoning_close_route] " + json.dumps(
                    {
                        "stage": "heuristic_top_guard",
                        "latest_user_text": raw[:200],
                        "scope": scope_info.get("scope"),
                        "indices": scope_info.get("indices") or [],
                        "range_n": scope_info.get("range_n"),
                        "title_query": scope_info.get("title_query") or "",
                        "rationale": scope_info.get("rationale") or "",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        slots: dict = {
            "scope": scope_info.get("scope") or "current_panel",
            "indices": scope_info.get("indices") or [],
            "title_query": scope_info.get("title_query") or "",
        }
        if scope_info.get("range_n") is not None:
            slots["range_n"] = scope_info.get("range_n")
        return {
            "domain": "work_mode",
            "is_action_request": True,
            "action_name": "work_mode.reasoning_close_panel",
            "slots": slots,
            "needs_followup": False,
            "missing_slot": None,
        }

    if _is_news_panel_close_request(raw):
        try:
            print(
                f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                "action=news.close_panel via=heuristic_top_guard"
            )
            print(
                "[news_panel_ui] " + json.dumps(
                    {
                        "latest_user_text": raw[:200],
                        "ui_action_intent": "close_news_panel",
                        "work_mode_route": False,
                        "reasoning_panel_route": False,
                        "news_panel_opened": False,
                        "news_panel_mode": "closed",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.close_panel",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }

    lowered = raw.lower()
    # 2026-06-14 — unified "play X" routing via the shared music.play verdict
    # (``normalize_music_play_request``), the SAME source of truth the
    # multi-action planner consumes. This replaces the old separate
    # ``play X by Y`` and ``play X in my playlist`` regex heuristics so that
    # title-only requests ("play Feather") execute as a track search instead of
    # being downgraded to general chat, while album-cue / playlist-scope /
    # builtin phrasings keep their existing routes. Idioms ("play it cool") and
    # non-play text fall through as ``not_music`` exactly as before.
    _music_verdict = normalize_music_play_request(raw)
    if _music_verdict.get("status") != "not_music" and _music_verdict.get("play_kind") != "resume":
        _music_route = _music_route_from_verdict(raw, _music_verdict)
        if _music_route is not None:
            try:
                print(
                    f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                    f"action={_music_route.get('action_name')} "
                    f"via=heuristic_music_verdict status={_music_verdict.get('status')} "
                    f"play_kind={_music_verdict.get('play_kind')}"
                )
            except Exception:
                pass
            return _music_route
    if re.search(r"\b(?:pause|stop)\b", lowered) and re.search(r"\b(?:music|song|spotify|playback)\b", lowered):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.pause",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    if re.search(r"\b(?:unpause|resume)\b", lowered) and re.search(
        r"\b(?:music|song|spotify|playback)\b", lowered
    ):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.resume",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    if re.search(r"\b(?:continue|keep)\b", lowered) and re.search(
        r"\b(?:playing|playback)\b", lowered
    ) and re.search(r"\b(?:music|song|spotify)\b", lowered):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.resume",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    if re.search(r"\b(?:close|hide|dismiss)\b", lowered) and re.search(r"\b(?:music|spotify)\b", lowered):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.close_panel",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    # Music-panel open commands. The top-of-function `_is_music_open_panel_request`
    # check already short-circuits these; this in-line block is kept as a
    # secondary safety net in case future edits move things around. Same
    # patterns, single source of truth via the module-level compiled regexes.
    if _is_music_open_panel_request(raw):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.open_panel",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    if re.search(r"\b(?:volume|sound)\b", lowered) and re.search(r"\b(?:up|higher|increase|louder|raise)\b", lowered):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.volume_up",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }
    if re.search(r"\b(?:volume|sound)\b", lowered) and re.search(r"\b(?:down|lower|decrease|quieter|reduce)\b", lowered):
        return {
            "domain": "music",
            "is_action_request": True,
            "action_name": "music.volume_down",
            "slots": {},
            "needs_followup": False,
            "missing_slot": None,
        }

    def _music_skip_info_question(s: str) -> bool:
        """Avoid routing 'what is the next song' style lookups as transport skips."""
        if re.search(
            r"\b(?:what|which|who|whose)\s+(?:is|was|are|'s|s)\s+(?:the\s+)?(?:next|previous|last)\b",
            s,
        ):
            return True
        if re.search(r"\b(?:what|which)\s+(?:song|track)\b.*\b(?:next|previous|after|before)\b", s):
            return True
        if re.search(r"\btell me\b", s) and re.search(r"\b(?:next|previous|last)\b", s):
            return True
        if re.search(r"\b(?:guess|know)\b.*\bnext\s+(?:song|track)\b", s):
            return True
        return False

    if not _music_skip_info_question(lowered):
        if re.search(
            r"\b(?:can you|could you)\s+(?:please\s+)?(?:play|skip)\s+(?:the\s+)?next\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\bplease\s+(?:can you|could you)\s+(?:play|skip)\s+(?:the\s+)?next\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:can u|could u)\s+(?:please\s+)?(?:play|skip)\s+(?:the\s+)?next\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:play|skip|go)\s+(?:to\s+)?(?:the\s+)?next\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(r"\bskip\s+(?:forward\s+)?(?:to\s+)?(?:the\s+)?next\b", lowered):
            return {
                "domain": "music",
                "is_action_request": True,
                "action_name": "music.skip_next",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }
        # Treat voice "go back" transport phrasing exactly like pressing the Previous button.
        if re.search(
            r"\b(?:go\s+back|back\s+up|previous|prior|last)\b.*\b(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:skip|jump|move)\s+back(?:ward)?\b",
            lowered,
        ) or re.search(
            r"\b(?:play|go)\s+(?:the\s+)?(?:previous|prior|last)\b",
            lowered,
        ):
            return {
                "domain": "music",
                "is_action_request": True,
                "action_name": "music.skip_previous",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }
        if re.search(
            r"\b(?:can you|could you)\s+(?:please\s+)?play\s+(?:the\s+)?(?:previous|last)\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\bplease\s+(?:can you|could you)\s+play\s+(?:the\s+)?(?:previous|last)\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:can u|could u)\s+(?:please\s+)?play\s+(?:the\s+)?(?:previous|last)\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:play|go)\s+(?:to\s+)?(?:the\s+)?(?:previous|last)\s+(?:song|track|one)\b",
            lowered,
        ) or re.search(
            r"\b(?:previous|prior)\s+(?:song|track)\b",
            lowered,
        ):
            return {
                "domain": "music",
                "is_action_request": True,
                "action_name": "music.skip_previous",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }

    create_panel_count = _work_mode_create_reasoning_panel_count(raw)
    if create_panel_count is not None:
        return {
            "domain": "work",
            "is_action_request": True,
            "action_name": "work_mode.reasoning_open_panel",
            "slots": {"count": create_panel_count},
            "needs_followup": False,
            "missing_slot": None,
        }
    if not re.search(r"\bnew\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page)\b", lowered):
        if _move_latest_voice_task_to_reasoning_intent(raw):
            return None
        wm_num = re.search(
            r"\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+)?"
            r"(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*#?\s*(\d+)\b",
            lowered,
        )
        if wm_num:
            if not _workmode_navigation_guard(raw, wm_num.group(0)):
                return None
            return {
                "domain": "work",
                "is_action_request": True,
                "action_name": "work_mode.reasoning_select_panel",
                "slots": {"panel_number": int(wm_num.group(1))},
                "needs_followup": False,
                "missing_slot": None,
            }
        wm_ord = re.search(
            r"\b(?:(?:can you|could you|please)\s+)?(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+)?"
            r"(first|second|third|fourth|fifth|sixth|seventh|eighth)\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page)\b",
            lowered,
        )
        if wm_ord:
            if not _workmode_navigation_guard(raw, wm_ord.group(0)):
                return None
            ord_map = {
                "first": 1,
                "second": 2,
                "third": 3,
                "fourth": 4,
                "fifth": 5,
                "sixth": 6,
                "seventh": 7,
                "eighth": 8,
            }
            n = ord_map.get(wm_ord.group(1).lower())
            if n:
                return {
                    "domain": "work",
                    "is_action_request": True,
                    "action_name": "work_mode.reasoning_select_panel",
                    "slots": {"panel_number": n},
                    "needs_followup": False,
                    "missing_slot": None,
                }
        wm_name = re.search(
            r"(?i)\b(?:can you|could you|please)\s+(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+"
            r"(?:the\s+|a\s+|my\s+)?(.+?)\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*[?.!]*\s*$",
            raw.strip(),
        )
        if not wm_name:
            wm_name = re.search(
                r"(?i)\b(?:go to|jump to|switch to|change to|move to|show|select|use|open)\s+(?:the\s+|a\s+|my\s+)?"
                r"(.+?)\s+(?:reasoning\s+)?(?:panel|space|tab|lane|page)\s*[?.!]*\s*$",
                raw.strip(),
            )
        if wm_name:
            q = clean_action_query(wm_name.group(1))
            if q and len(q) >= 2 and not re.fullmatch(r"\d+", q):
                if not _workmode_navigation_guard(raw, wm_name.group(0)):
                    return None
                ord_map = {
                    "first": 1,
                    "second": 2,
                    "third": 3,
                    "fourth": 4,
                    "fifth": 5,
                    "sixth": 6,
                    "seventh": 7,
                    "eighth": 8,
                }
                ord_n = ord_map.get(q.lower().strip())
                if ord_n:
                    return {
                        "domain": "work",
                        "is_action_request": True,
                        "action_name": "work_mode.reasoning_select_panel",
                        "slots": {"panel_number": ord_n},
                        "needs_followup": False,
                        "missing_slot": None,
                    }
                # Music / Spotify / playback are dedicated UI panels — never
                # treat them as reasoning-panel tab titles. They were already
                # caught by the music.open_panel heuristic above; this guard
                # is defense-in-depth so the wm_name regex doesn't swallow a
                # phrase like "open the music panel" with panel_query="music".
                # Anything that even MENTIONS music/spotify/playback in the
                # captured tab title is a music intent, not a reasoning tab
                # name — bail out so the LLM router (or the music heuristic)
                # gets a chance instead of misrouting to reasoning_select_panel.
                if re.search(
                    r"(?i)\b(?:music|spotify|playback|playlist|playlists|"
                    r"music\s+player|spotify\s+player|spotify\s+panel|playback\s+controls)\b",
                    q,
                ):
                    return None
                return {
                    "domain": "work",
                    "is_action_request": True,
                    "action_name": "work_mode.reasoning_select_panel",
                    "slots": {"panel_query": q},
                    "needs_followup": False,
                    "missing_slot": None,
                }
        q_loose = _go_to_reasoning_panel_query_heuristic(raw)
        if q_loose:
            ord_map = {
                "first": 1,
                "second": 2,
                "third": 3,
                "fourth": 4,
                "fifth": 5,
                "sixth": 6,
                "seventh": 7,
                "eighth": 8,
            }
            ord_n = ord_map.get(q_loose.lower().strip())
            if ord_n:
                return {
                    "domain": "work",
                    "is_action_request": True,
                    "action_name": "work_mode.reasoning_select_panel",
                    "slots": {"panel_number": ord_n},
                    "needs_followup": False,
                    "missing_slot": None,
                }
            return {
                "domain": "work",
                "is_action_request": True,
                "action_name": "work_mode.reasoning_select_panel",
                "slots": {"panel_query": q_loose},
                "needs_followup": False,
                "missing_slot": None,
            }

    # 2026-06-01 — Explicit general-news intent (highest news-route priority).
    # Catches "tell me the latest news", "any news updates?", "what are
    # today's headlines?", etc. (see is_explicit_general_news_intent). The
    # slot dict deliberately leaves query/topic/search_queries empty AND
    # marks force_top_headlines so _finalize_news_latest_slots short-
    # circuits without injecting a Serper-ready search query — the action
    # dispatcher then calls handle_news_request(query=None, breaking=False,
    # search_queries=None), which hits the BBC RSS top-headlines branch
    # (get_top_news(limit=3) -> _build_bbc_prompt -> BBC_NEWS_PREAMBLE
    # attribution). Must run BEFORE is_broad_news_reset_request because
    # the broad-reset branch builds Serper-targeted search_queries even
    # for general news intents.
    if is_explicit_general_news_intent(raw):
        try:
            print(
                f"[ACTION-ROUTER-PRECHECK] user={raw[:120]!r} "
                "action=news.latest via=explicit_general_news_intent "
                "source_preference=bbc count=3 block_serper=True"
            )
        except Exception:
            pass
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": {
                "query": "",
                "topic": "",
                "entities": [],
                "time_horizon": "",
                "search_queries": [],
                "broad_news_reset": False,
                "force_top_headlines": True,
                "source_preference": "bbc",
                "count": 3,
            },
            "needs_followup": False,
            "missing_slot": None,
        }

    if is_broad_news_reset_request(raw):
        horizon = _extract_news_time_horizon(raw)
        if not horizon or horizon == "unspecified":
            horizon = "today"
        query = "breaking news" if "breaking" in lowered else "latest news headlines"
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": {
                "query": query,
                "topic": query,
                "entities": [],
                "time_horizon": horizon,
                "search_queries": _build_broad_news_search_queries(raw, horizon),
                "broad_news_reset": True,
            },
            "needs_followup": False,
            "missing_slot": None,
        }

    if is_ambiguous_breaking_news_phrase(raw):
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": {"breaking": True},
            "needs_followup": True,
            "missing_slot": "breaking_intent",
        }

    if is_breaking_news_phrase(raw):
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": {"breaking": True},
            "needs_followup": False,
            "missing_slot": None,
        }

    latest_on_match = re.match(
        r"^(?:can you tell me\s+)?latest on (?P<query>.+?)(?:\s+stock)?$",
        raw,
        flags=re.IGNORECASE,
    )
    if latest_on_match:
        query = clean_action_query(latest_on_match.group("query"))
        if not query:
            return None
        action_name = "finance.context" if is_likely_finance_subject(query) else "news.latest"
        domain = "finance" if action_name == "finance.context" else "news"
        return {
            "domain": domain,
            "is_action_request": True,
            "action_name": action_name,
            "slots": {"query": query},
            "needs_followup": False,
            "missing_slot": None,
        }

    patterns = [
        (
            "finance.quote",
            [
                r"^(?:can you tell me\s+)?(?:the\s+)?stock price of (?P<query>.+)$",
                r"^(?:can you tell me\s+)?(?:the\s+)?share price of (?P<query>.+)$",
                r"^(?:what(?:'s|s| is)\s+)?the price of (?P<query>.+)$",
                r"^(?:can you tell me\s+)?quote for (?P<query>.+)$",
                r"^(?:what(?:'s|s| is)\s+)(?P<query>.+?) trading at(?:\s+right now)?$",
            ],
        ),
        (
            "finance.context",
            [
                r"^(?:can you tell me\s+)?what(?:'s|s) happening with (?P<query>.+)$",
                r"^(?:can you tell me\s+)?what(?:'s|s) going on with (?P<query>.+)$",
            ],
        ),
        (
            "news.latest",
            [
                r"^(?:can you tell me\s+)?what(?:'s|s) going on in (?P<query>.+)$",
                r"^(?:can you tell me\s+)?whats going in (?P<query>.+)$",
                r"^(?:can you tell me\s+)?(?:the\s+)?breaking news(?:\s+about|\s+on)? (?P<query>.+)$",
                r"^(?:can you tell me\s+)?(?:the\s+)?latest updates(?:\s+about|\s+on)? (?P<query>.+)$",
            ],
        ),
    ]

    for action_name, action_patterns in patterns:
        for pattern in action_patterns:
            match = re.match(pattern, raw, flags=re.IGNORECASE)
            if not match:
                continue

            query = clean_action_query(match.group("query"))
            if not query:
                return None

            if action_name == "finance.context":
                if not is_likely_finance_subject(query):
                    action_name = "news.latest"
                domain = "news" if action_name == "news.latest" else "finance"
            else:
                domain = "news" if action_name == "news.latest" else "finance"

            return {
                "domain": domain,
                "is_action_request": True,
                "action_name": action_name,
                "slots": {"query": query},
                "needs_followup": False,
                "missing_slot": None,
            }

    return None


def route_action_request(session_id: str, text: str) -> dict:
    try:
        if _is_memory_command_request(text):
            return normalize_route(
                {
                    "domain": "general",
                    "is_action_request": False,
                    "action_name": "",
                    "slots": {},
                    "needs_followup": False,
                    "missing_slot": None,
                }
            )
    except Exception:
        pass

    def _builtin_music_play_intent(user_text: str) -> bool:
        low = (user_text or "").lower()
        if re.search(r"\b(?:play|start|put\s+on|turn\s+on)\b", low):
            return True
        if re.search(
            r"\b(?:can|could|would|will)\s+you\s+(?:please\s+)?(?:play|put|turn)\b",
            low,
        ):
            return True
        return False

    recent_action = get_recent_action_context(session_id)
    news_ctx = get_recent_news_context(session_id)

    # PART 1+8+11 — top-level current-info intent router runs FIRST so the
    # single grep target `[current_info_intent]` records the routing
    # decision for every turn, regardless of how downstream classifiers
    # eventually consume `news_ctx`. The intent log also captures the
    # PART 8 strong-new-topic signal — used immediately below to drop
    # stale recent_news_context whenever the new message clearly belongs
    # to a different domain (finance / math / code / app UI / personal).
    current_info_intent = classify_current_info_intent(
        text,
        recent_news_context=news_ctx,
        session_id=session_id,
    )
    log_current_info_intent(session_id, text, current_info_intent)

    if _is_work_mode_reasoning_handoff_request(text):
        return normalize_route(
            {
                "domain": "general",
                "is_action_request": False,
                "action_name": "",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }
        )

    # PART 14 (2026-05-28): unified [news_router_route] log emitted on EVERY
    # turn (user explicitly chose "every_turn" verbosity). Single grep target
    # that captures the full spec-shape routing decision before downstream
    # mutation. See log_news_router_route() for the field schema.
    try:
        log_news_router_route(
            session_id=session_id,
            text=text,
            current_info_intent=current_info_intent,
            news_ctx=news_ctx,
            stage="route_action_request_pre_dispatch",
        )
    except Exception:
        pass
    _route_debug_cleared_news_ctx = False
    _route_debug_ignored_ctx_reason = ""
    if (
        isinstance(current_info_intent, dict)
        and (current_info_intent.get("signals") or {}).get("strong_new_topic_detected")
    ):
        try:
            if session_id in recent_news_context:
                recent_news_context.pop(session_id, None)
                print(
                    "[current_info_intent_drop_ctx] " + json.dumps(
                        {
                            "session_id": (session_id or "")[:64],
                            "reason": str(
                                (current_info_intent.get("signals") or {}).get(
                                    "strong_new_topic_reason"
                                ) or ""
                            ),
                            "dropped_topic": str(
                                (current_info_intent.get("signals") or {}).get(
                                    "recent_news_context_topic"
                                ) or ""
                            ),
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
        except Exception:
            pass
        news_ctx = None
        _route_debug_cleared_news_ctx = True
        _route_debug_ignored_ctx_reason = str(
            (current_info_intent.get("signals") or {}).get("strong_new_topic_reason") or ""
        )

    news_intent = detect_news_route_intent(text, recent_news_context=news_ctx)
    log_route_debug(
        session_id,
        text,
        stage="route_action_request_after_current_info",
        current_info_intent=current_info_intent,
        news_intent=news_intent,
        selected_route=str(current_info_intent.get("route") or ""),
        selected_action_name="",
        should_search=bool(current_info_intent.get("shouldSearch")),
        serper_called=bool(current_info_intent.get("shouldSearch")),
        used_recent_news_context=bool((current_info_intent.get("signals") or {}).get("followup_detected")),
        ignored_recent_news_context_reason=_route_debug_ignored_ctx_reason,
        cleared_recent_news_context=_route_debug_cleared_news_ctx,
        final_answer_source=str(current_info_intent.get("answer_source") or ""),
    )
    # PART 7: emit the structured current-fact-question decision line as
    # soon as we know the routing intent. This is the per-turn breakdown
    # of question_shape / public_entity / public_domain_noun / recent_time
    # signals + the score, with `routed_to` filled in based on the news
    # intent. The polish-layer router log [news_route_classification]
    # logs a separate downstream view; this log is dedicated to the
    # current-fact gate so spec PART 7 has a single grep target.
    try:
        _fact_score = score_current_fact_question(text)
        _routed_to_initial = (
            "current_fact_search"
            if news_intent.get("action") == "news_search"
            and news_intent.get("current_fact_question")
            else (
                "news_search"
                if news_intent.get("action") == "news_search"
                else (
                    "personal_news_statement"
                    if (news_intent.get("intent_classification") or {}).get("personalNewsStatementDetected")
                    else (
                        "emotional_context"
                        if (news_intent.get("intent_classification") or {}).get("emotionalContextDetected")
                        else "general_chat_or_other"
                    )
                )
            )
        )
        log_current_fact_question_decision(
            session_id,
            text,
            _fact_score,
            routed_to=_routed_to_initial,
            serper_called=(news_intent.get("action") == "news_search"),
            reason=str(news_intent.get("reason") or ""),
        )
    except Exception:
        pass
    # When the user message is personal/emotional, drop any stale stored
    # news context BEFORE the LLM router runs so the next vague follow-up
    # (e.g. "I don't know how to feel about this") cannot inherit the
    # previous bad search topic via the deictic resolver. The post-LLM
    # guard below also performs this cleanup; doing it here too is cheap
    # and means the cleanup happens even when the heuristic alone wins.
    _new_cls = news_intent.get("intent_classification") if isinstance(news_intent.get("intent_classification"), dict) else None
    if _new_cls and (_new_cls.get("personalNewsStatementDetected") or _new_cls.get("emotionalContextDetected")):
        try:
            if session_id in recent_news_context:
                recent_news_context.pop(session_id, None)
        except Exception:
            pass

    def finalize(route: dict | None) -> dict:
        normalized = normalize_route(route)
        # Same-message subject correction: e.g. "... drawdown of BGT in the
        # past 5 years I said VGT". The LLM router usually grabs the first
        # ticker ("BGT") into slots.query. Rewrite the slots so the rerun
        # uses the corrected subject, and clean up user_text the same way.
        if normalized.get("action_name", "").startswith("finance."):
            corrected_subject = extract_finance_correction_subject(text)
            if corrected_subject:
                slots = dict(normalized.get("slots") or {})
                prior_query = (slots.get("query") or "").strip()
                if (
                    prior_query
                    and prior_query.lower() != corrected_subject.lower()
                ):
                    slots["query"] = corrected_subject
                    # Clean the trailing correction phrase from the user_text
                    # we forward to analytics so the LLM sees the actual ask.
                    cleaned_user_text = _strip_finance_correction_phrase(text)
                    cleaned_user_text = re.sub(
                        rf"\b{re.escape(prior_query)}\b",
                        corrected_subject,
                        cleaned_user_text,
                        flags=re.IGNORECASE,
                    )
                    slots["user_text"] = cleaned_user_text
                    normalized["slots"] = slots
                    try:
                        print(
                            "[finance_correction_same_message] "
                            + json.dumps(
                                {
                                    "user_text": (text or "")[:200],
                                    "prior_subject": prior_query[:80],
                                    "corrected_subject": corrected_subject[:80],
                                    "action": normalized.get("action_name"),
                                },
                                ensure_ascii=False,
                            ),
                            flush=True,
                        )
                    except Exception:
                        pass
        # Upgrade quote/context → analytics when the user is asking for a
        # historical/quantitative metric (drawdown, Sharpe, beta, X-year
        # return, volatility, ...). The LLM router doesn't yet know about
        # finance.analytics, so it ships these as finance.quote or .context
        # — using intraday quote data to answer drawdown is wrong, so we
        # promote them here based on the keywords in the user text.
        if (
            normalized.get("action_name") in {"finance.quote", "finance.context"}
            and is_finance_analytics_query(text)
        ):
            old_name = normalized.get("action_name")
            slots = dict(normalized.get("slots") or {})
            slots.setdefault("user_text", text)
            normalized = {
                "domain": "finance",
                "is_action_request": True,
                "action_name": "finance.analytics",
                "slots": slots,
                "needs_followup": False,
                "missing_slot": None,
            }
            try:
                print(
                    "[finance_route_upgrade] "
                    + json.dumps(
                        {
                            "user_text": (text or "")[:200],
                            "from": old_name,
                            "to": "finance.analytics",
                            "reason": "analytics_metric_keyword",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
        if normalized.get("action_name") == "news.latest":
            # POST-LLM SUPPRESSOR: even when the LLM router classifies a
            # personal/emotional turn as news.latest (it sometimes does
            # despite the prompt warning), downgrade to general so the
            # News panel never opens. The pre-LLM heuristic also catches
            # this, but defense-in-depth — the LLM is non-deterministic.
            cls_post = news_intent.get("intent_classification") if isinstance(news_intent.get("intent_classification"), dict) else None
            if cls_post is None:
                cls_post = classify_news_search_intent(text, recent_news_context=news_ctx)
            if cls_post.get("personalNewsStatementDetected") or cls_post.get("emotionalContextDetected"):
                try:
                    print(
                        "[news_route_downgrade] " + json.dumps(
                            {
                                "user_text": (text or "")[:200],
                                "llm_action": "news.latest",
                                "downgraded_to": "general",
                                "reason": cls_post.get("reason") or "personal_or_emotional_post_llm",
                                "personal_news_statement_detected": bool(cls_post.get("personalNewsStatementDetected")),
                                "emotional_context_detected": bool(cls_post.get("emotionalContextDetected")),
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
                # Drop any stale stored news context so future vague
                # follow-ups don't inherit it.
                try:
                    recent_news_context.pop(session_id, None)
                except Exception:
                    pass
                normalized = {
                    "domain": "general",
                    "is_action_request": False,
                    "action_name": "general",
                    "slots": {},
                    "needs_followup": False,
                    "missing_slot": None,
                }
            else:
                # Single source of truth: expand deictic queries, build entity+horizon queries.
                normalized["slots"] = _finalize_news_latest_slots(
                    session_id, text, normalized.get("slots") or {}
                )
        bm = match_builtin_productivity_music(text.strip())
        if bm and _builtin_music_play_intent(text):
            allow_override = normalized.get("action_name") in {
                "general",
                "music.play_track",
                "music.play_playlist",
                "music.play_album",
            }
            if allow_override:
                slots = (
                    {"playlist_id": bm["id"]}
                    if bm["kind"] == "playlist"
                    else {"sound_id": bm["id"]}
                )
                normalized = {
                    "domain": "music",
                    "is_action_request": True,
                    "action_name": "music.play_builtin",
                    "slots": slots,
                    "needs_followup": False,
                    "missing_slot": None,
                }
                print(
                    f"[ACTION-ROUTER] user={repr(text[:120])} "
                    f"action={normalized.get('action_name')} "
                    f"builtin={slots} (priority-over-router)"
                )
                return normalized
        # 2026-06-14 — the old `play X by Y` downgrade (which forced
        # title-only music.play_track requests like "play Feather" back to
        # general chat unless an artist was named) has been removed. The
        # shared music.play verdict (normalize_music_play_request) is now the
        # single source of truth for what counts as a playable track, and the
        # heuristic route consults it directly, so title-only track requests
        # execute as a Spotify track search on both the single-action and
        # multi-action paths.
        if normalized.get("action_name") == "music.play_track":
            try:
                _music_verdict_post = normalize_music_play_request(text)
            except Exception:
                _music_verdict_post = {}
            if _music_verdict_post.get("status") == "not_music":
                try:
                    print(
                        "[music_play_route_source] "
                        + json.dumps(
                            {
                                "stage": "post_llm_not_music_downgrade",
                                "user_text": (text or "")[:200],
                                "llm_action": "music.play_track",
                                "normalizer_status": "not_music",
                                "normalizer_query": str(_music_verdict_post.get("query") or "")[:120],
                                "downgraded_to": "general",
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
                normalized = {
                    "domain": "general",
                    "is_action_request": False,
                    "action_name": "general",
                    "slots": {},
                    "needs_followup": False,
                    "missing_slot": None,
                }
        # 2026-06-15 — music-family unsupported-modifier guard (Option A).
        # A single-action transport/volume route ("pause in 10 minutes",
        # "turn volume up later", "pause when the timer ends") must NOT
        # execute immediately when the user clearly asked for a delayed /
        # conditional / recurring action. Both the heuristic route (volume)
        # and the LLM route (pause/resume/skip) pass through finalize, so this
        # one guard covers every single-action path. Delayed music control is
        # not supported yet → swap in a music.unsupported reply (no payload).
        _transport_family = _MUSIC_TRANSPORT_ACTION_FAMILY.get(
            normalized.get("action_name") or ""
        )
        if _transport_family:
            _unsupported_meta = detect_music_unsupported_modifier(
                text, _transport_family
            )
            if _unsupported_meta is not None:
                try:
                    print(
                        "[music_unsupported_modifier] "
                        + json.dumps(
                            {
                                "stage": "post_route_single_action",
                                "user_text": (text or "")[:200],
                                "blocked_action": normalized.get("action_name"),
                                "family": _transport_family,
                                "timing_kind": _unsupported_meta.get("timing_kind"),
                                "phrase": _unsupported_meta.get("phrase"),
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
                normalized = {
                    "domain": "music",
                    "is_action_request": True,
                    "action_name": "music.unsupported",
                    "slots": {
                        "family": _transport_family,
                        "phrase": _unsupported_meta.get("phrase") or "",
                        "timing_kind": _unsupported_meta.get("timing_kind") or "scheduling",
                        "reason": _unsupported_meta.get("reason") or "",
                    },
                    "needs_followup": False,
                    "missing_slot": None,
                }
        # Defense-in-depth: if the LLM mis-classifies a news-panel UI command
        # ("open the news panel") as a work-mode reasoning request, redirect
        # it to news.open_panel. The heuristic top-guard already catches this
        # case in practice, but the LLM router can still get there if the
        # heuristic guard is bypassed by future edits.
        if normalized.get("action_name") in {
            "work_mode.reasoning_open_panel",
            "work_mode.reasoning_select_panel",
            "work_mode.reasoning_close_panel",
        } and _is_news_panel_open_request(text):
            try:
                print(
                    "[news_panel_ui] " + json.dumps(
                        {
                            "stage": "post_llm_override",
                            "latest_user_text": (text or "")[:200],
                            "ui_action_intent": "open_news_panel",
                            "llm_action": normalized.get("action_name"),
                            "redirected_to": "news.open_panel",
                            "work_mode_route": False,
                            "reasoning_panel_route": False,
                            "news_panel_opened": True,
                            "news_panel_mode": "open",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            normalized = {
                "domain": "news",
                "is_action_request": True,
                "action_name": "news.open_panel",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }
        if normalized.get("action_name") in {
            "work_mode.reasoning_open_panel",
            "work_mode.reasoning_select_panel",
            "work_mode.reasoning_close_panel",
        } and _is_news_panel_close_request(text):
            try:
                print(
                    "[news_panel_ui] " + json.dumps(
                        {
                            "stage": "post_llm_override",
                            "latest_user_text": (text or "")[:200],
                            "ui_action_intent": "close_news_panel",
                            "llm_action": normalized.get("action_name"),
                            "redirected_to": "news.close_panel",
                            "work_mode_route": False,
                            "reasoning_panel_route": False,
                            "news_panel_opened": False,
                            "news_panel_mode": "closed",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            normalized = {
                "domain": "news",
                "is_action_request": True,
                "action_name": "news.close_panel",
                "slots": {},
                "needs_followup": False,
                "missing_slot": None,
            }
        # Single [news_route_decision] log reflecting the FINAL action so it always
        # agrees with [ACTION-ROUTER]. Intent fields stay from the early detection.
        final_action_name = normalized.get("action_name") or "general"
        final_slots = normalized.get("slots") or {}
        final_entities = (
            list(final_slots.get("entities") or [])
            or list(news_intent.get("entities") or [])
        )
        final_horizon = (
            str(final_slots.get("time_horizon") or "")
            or str(news_intent.get("time_horizon") or "unspecified")
        )
        vague_target = resolve_vague_followup_target(
            text,
            recent_news_context=news_ctx,
            history=None,
            active_side_panel=("news" if news_ctx else ""),
        )
        _log_news_route_decision(
            text,
            action=final_action_name,
            reason=str(news_intent.get("reason") or "final_route"),
            current_or_recent_detected=bool(news_intent.get("current_or_recent_detected")),
            source_request_detected=bool(news_intent.get("source_request_detected")),
            entities=final_entities,
            time_horizon=final_horizon,
            intent_classification=news_intent.get("intent_classification") if isinstance(news_intent.get("intent_classification"), dict) else None,
            vague_followup=vague_target,
            history=None,
            active_side_panel=("news" if news_ctx else ""),
        )
        log_route_debug(
            session_id,
            text,
            stage="route_action_request_final",
            current_info_intent=current_info_intent,
            news_intent=news_intent,
            selected_route=normalized.get("domain") or "",
            selected_action_name=final_action_name,
            should_search=final_action_name == "news.latest",
            serper_called=final_action_name == "news.latest",
            used_recent_news_context=bool(final_action_name == "news.latest" and news_ctx),
            ignored_recent_news_context_reason=_route_debug_ignored_ctx_reason,
            cleared_recent_news_context=_route_debug_cleared_news_ctx,
            final_answer_source="action" if normalized.get("is_action_request") else "llm_general",
        )
        print(
            f"[ACTION-ROUTER] user={repr(text[:120])} "
            f"action={normalized.get('action_name')} "
            f"followup={normalized.get('needs_followup')} "
            f"slots={normalized.get('slots')}"
        )
        return normalized

    heuristic = heuristic_route_action(text)
    if heuristic is not None:
        normalized = normalize_route(heuristic)
        # finalize() will run _finalize_news_latest_slots for any news.latest route,
        # so we no longer need a special upgrade path here.
        return finalize(normalized)

    # 2026-05-28 PART 1+2 — single-dispatch info tool router.
    # `heuristic_route_action` above already claimed any local app action
    # (panel/checklist/music/timer/UI). Now we ask the new classifier whether
    # this turn is a clean information request we can dispatch directly.
    # Only confident picks short-circuit; "uncertain" falls through so the
    # existing news_intent + LLM router can still take over.
    sports_ctx = get_recent_sports_context(session_id)
    try:
        _info_tool = classify_info_tool(
            text,
            recent_news_context=news_ctx,
            recent_sports_context=sports_ctx,
            session_id=session_id,
        )
    except Exception as _info_exc:
        print("[info_tool_route] classifier_exception:", _info_exc, flush=True)
        _info_tool = None
    if _info_tool:
        _info_route_built = build_route_from_info_tool(text, _info_tool, session_id)
        if _info_route_built is not None:
            try:
                log_info_tool_route(
                    session_id,
                    text,
                    _info_tool,
                    dispatched_action=str(_info_route_built.get("action_name") or ""),
                    fell_through=False,
                )
            except Exception:
                pass
            return finalize(_info_route_built)
        # Confident "llm_only" / "followup_llm" — skip the news_intent upgrade
        # so a previous news topic can't hijack this turn. The LLM router is
        # the right next step.
        if _info_tool.get("route") in ("llm_only", "followup_llm"):
            try:
                log_info_tool_route(
                    session_id,
                    text,
                    _info_tool,
                    dispatched_action="general_llm",
                    fell_through=False,
                )
            except Exception:
                pass
            # Do not ask the action router again here. For pronoun follow-ups
            # like "Was he part of OpenAI?", the classifier has already made
            # the important decision: answer from chat/source context, not a
            # fresh news search. Calling vera.route_action can re-promote the
            # turn to news.latest because it sees the named entity "OpenAI".
            normalized = normalize_route(
                {
                    "domain": "general",
                    "is_action_request": False,
                    "action_name": "general",
                    "slots": {},
                    "needs_followup": False,
                    "missing_slot": None,
                }
            )
            return finalize(normalized)
        # "uncertain" / "followup_search" / "clarification_needed" already
        # returned above. Anything else falls through unchanged.
        try:
            log_info_tool_route(
                session_id,
                text,
                _info_tool,
                dispatched_action="",
                fell_through=True,
            )
        except Exception:
            pass

    # New hybrid: if the user is asking about a current/recent topic with named entities,
    # (or a deictic followup with prior news context) route to news.latest directly.
    if news_intent.get("action") == "news_search":
        upgraded = build_route_from_news_intent(text, news_intent, session_id=session_id)
        if upgraded is not None:
            return finalize(upgraded)

    if is_checklist_undo_followup(text):
        snap, snap_status = _get_checklist_undo_snapshot_valid(session_id)
        if snap_status == "valid" or pending_checklist_undo_context.get(session_id):
            return finalize(
                normalize_route(
                    {
                        "domain": "checklist",
                        "is_action_request": True,
                        "action_name": "checklist.undo_clear",
                        "slots": {},
                        "needs_followup": False,
                        "missing_slot": None,
                    }
                )
            )
        spoken = "I don't have a recent checklist change to undo."
        recent = get_recent_action_context(session_id) or {}
        recent_domain = str(recent.get("action_name") or "").split(".")[0]
        _emit_undo_routing_log(
            "undo_wrong_domain_blocked",
            raw_text=(text or "")[:200],
            normalized_text=(text or "").strip().lower()[:200],
            recent_action_domain=recent_domain,
            pending_undo_domain="",
            checklist_snapshot_exists=session_id in checklist_undo_snapshots,
            checklist_undo_ttl_remaining_ms=_checklist_undo_ttl_remaining_ms(session_id),
            selected_undo_domain="",
            blocked_domain=recent_domain or "llm_router",
            decision_reason="blocked_before_chat_router",
        )
        return finalize(
            normalize_route(
                {
                    "domain": "clarification",
                    "is_action_request": True,
                    "action_name": "clarification.undo",
                    "slots": {"spoken": spoken},
                    "needs_followup": False,
                    "missing_slot": None,
                }
            )
        )

    normalized = normalize_route(
        vera.route_action(
            text,
            pending_action=get_pending_action(session_id),
            recent_action=recent_action,
        )
    )
    return finalize(normalized)


def set_recent_action_from_result(session_id: str, action_name: str, slots: dict, action_result: dict):
    if action_result.get("data") is None and action_result.get("ui_payload") is None:
        return
    set_recent_action_context(session_id, action_name, slots, action_result)


def execute_structured_action(
    session_id: str,
    text: str,
    route: dict,
    filler_generation: int | None = None,
    client_context_snapshot: dict | None = None,
) -> tuple[dict | None, float]:
    action_name = route.get("action_name")
    slots = route.get("slots", {})
    t0 = perf_counter()

    if action_name == "clarification.undo":
        spoken = str((slots or {}).get("spoken") or _undo_clarification_spoken(session_id))
        action_result = {
            "spoken_reply": spoken,
            "action_type": "clarification",
            "data": {"undo_clarification": True},
            "ui_payload": None,
        }
        return action_result, perf_counter() - t0

    if route.get("needs_followup"):
        if action_name == "weather.current" and route.get("missing_slot") == "location":
            set_pending_action(session_id, "weather.current", "location", slots)
            action_result = {
                "spoken_reply": WEATHER_LOCATION_PROMPT,
                "action_type": "weather",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "weather.forecast" and route.get("missing_slot") in {
            "location",
            "time",
            "both",
        }:
            missing_slot = route.get("missing_slot") or "location"
            parsed = (route or {}).get("_parsed_weather") or parse_weather_query(text)
            pending_slots = _weather_pending_slots_from_parsed(text, parsed)
            set_pending_action(session_id, "weather.forecast", missing_slot, pending_slots)
            _log_weather_forecast_pending_store(session_id, missing_slot, pending_slots)
            _log_weather_forecast_clarify(missing_slot, parsed)
            action_result = {
                "spoken_reply": _weather_clarification_prompt(
                    missing_slot,
                    near_me=parsed.get("location_kind") == "near_me",
                ),
                "action_type": "weather_forecast",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "news.latest" and route.get("missing_slot") == "breaking_intent":
            set_pending_action(session_id, "news.latest", "breaking_intent", slots)
            action_result = {
                "spoken_reply": "Do you want me to look up breaking news, or do you have breaking news for me?",
                "action_type": "news",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name in {"finance.quote", "finance.context"} and route.get("missing_slot") in {"query", "ticker", "subject", None}:
            missing_slot = route.get("missing_slot") or "query"
            set_pending_action(session_id, action_name, missing_slot, slots)
            action_result = {
                "spoken_reply": (
                    FINANCE_QUOTE_SUBJECT_PROMPT
                    if action_name == "finance.quote"
                    else FINANCE_CONTEXT_SUBJECT_PROMPT
                ),
                "action_type": "finance",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "web.search" and route.get("missing_slot") == "location":
            # 2026-05-28 PART 1 — beta info-tool router clarification path.
            # Triggered when classify_info_tool returns clarification_needed
            # with required_context=["location"] (e.g. "coffee shops near me"
            # with no location available). Re-uses the existing pending
            # action plumbing so the next turn's location text resolves the
            # original web.search query.
            set_pending_action(session_id, "web.search", "location", slots)
            try:
                from actions.web_search import _log_place_panel as _log_pp
                from actions.web_search import extract_venue_category as _evc
                _orig = str(slots.get("user_text") or slots.get("query") or text or "")
                _log_pp(
                    query=_orig,
                    place_query_detected=True,
                    location_required=True,
                    location_available=False,
                    pending_place_query_set=True,
                    place_search_query="",
                    places_count=0,
                    map_pins_count=0,
                    location_panel_created=False,
                    pending_category=_evc(_orig),
                    pending_original_text=_orig,
                    note="pending_action_armed_for_near_me_without_city",
                )
            except Exception:
                pass
            action_result = {
                "spoken_reply": WEB_SEARCH_LOCATION_PROMPT,
                "action_type": "web_search",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "music.play_track" and route.get("missing_slot") == "track_query":
            set_pending_action(session_id, "music.play_track", "track_query", slots)
            action_result = {
                "spoken_reply": MUSIC_TRACK_QUERY_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "music.play_album" and route.get("missing_slot") == "album_query":
            set_pending_action(session_id, "music.play_album", "album_query", slots)
            action_result = {
                "spoken_reply": MUSIC_ALBUM_QUERY_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        if action_name == "music.play_playlist" and route.get("missing_slot") == "playlist_name":
            set_pending_action(session_id, "music.play_playlist", "playlist_name", slots)
            action_result = {
                "spoken_reply": MUSIC_PLAYLIST_NAME_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        return None, 0.0

    try:
        _cap_action, _cap_feature = _credit_action_for_structured_action(action_name)
        if _cap_action:
            _enforce_usage_credit_cap(
                _cap_action,
                session_id=session_id,
                feature_type=_cap_feature,
            )
    except HTTPException:
        raise

    if action_name == "weather.forecast":
        location = clean_location_text(slots.get("location", ""))
        parsed = (route or {}).get("_parsed_weather") or parse_weather_query(text)
        if not location:
            location = clean_location_text(parsed.get("location") or "")
        if not location:
            set_pending_action(session_id, "weather.forecast", "location", _weather_pending_slots_from_parsed(text, parsed))
            _log_weather_forecast_pending_store(session_id, "location", slots)
            _log_weather_forecast_clarify("location", parsed)
            action_result = {
                "spoken_reply": _weather_clarification_prompt(
                    "location",
                    near_me=parsed.get("location_kind") == "near_me",
                ),
                "action_type": "weather_forecast",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0

        parsed = {
            **parsed,
            "location": location,
            "needs_location": False,
            "location_kind": "explicit",
        }
        action_result = handle_weather_forecast_request(
            location=location,
            parsed_query=parsed,
            user_text=text,
        )
        if action_result.get("data") or action_result.get("ui_payload"):
            effective_slots = dict(slots)
            effective_slots["location"] = location
            set_recent_action_from_result(session_id, action_name, effective_slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "weather.current":
        location = clean_location_text(slots.get("location", ""))
        if not location:
            set_pending_action(session_id, "weather.current", "location", slots)
            action_result = {
                "spoken_reply": WEATHER_LOCATION_PROMPT,
                "action_type": "weather",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0

        action_result = handle_weather_request(vera, location=location)
        if action_result.get("data"):
            reply = answer_direct_weather_question(text, session_id, action_result)
            action_result = {**action_result, "spoken_reply": reply}
            set_recent_action_from_result(session_id, action_name, {"location": location, **slots}, action_result)
        return action_result, perf_counter() - t0

    if action_name == "weather.followup":
        recent = get_recent_action_context(session_id)
        if recent and recent.get("action_name") in ("weather.current", "weather.forecast"):
            action_result = dict(recent.get("result", {}))
            if recent.get("action_name") == "weather.forecast":
                action_result["spoken_reply"] = action_result.get("spoken_reply") or ""
            else:
                action_result["spoken_reply"] = answer_direct_weather_question(text, session_id, action_result)
            set_recent_action_from_result(
                session_id,
                recent.get("action_name"),
                recent.get("slots", {}),
                action_result,
            )
            return action_result, perf_counter() - t0
        return None, 0.0

    if action_name == "time.current":
        location = clean_location_text(slots.get("location", ""))
        action_result = handle_time_request(vera, location=location or None)
        effective_slots = dict(slots)
        effective_slots["location"] = location or action_result.get("data", {}).get("place_name")
        set_recent_action_from_result(session_id, action_name, effective_slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "date.current":
        location = clean_location_text(slots.get("location", ""))
        action_result = handle_date_request(vera, location=location or None)
        effective_slots = dict(slots)
        effective_slots["location"] = location or action_result.get("data", {}).get("place_name")
        set_recent_action_from_result(session_id, action_name, effective_slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "date.delta":
        target_name = (slots.get("target_name") or slots.get("target") or "").strip()
        location = clean_location_text(slots.get("location", ""))
        if not target_name:
            return None, 0.0
        action_result = handle_date_delta_request(vera, target_name=target_name, location=location or None)
        action_data = action_result.get("data") or {}
        effective_slots = dict(slots)
        effective_slots["target_name"] = target_name
        effective_slots["location"] = location or action_data.get("place_name")
        set_recent_action_from_result(session_id, action_name, effective_slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "news.latest":
        # Safety net: any direct invocation that bypassed route_action_request still
        # goes through the single-source-of-truth finalizer (deictic expansion +
        # entity/timeframe query building) so we never literal-search 'this trip'.
        slots = _finalize_news_latest_slots(session_id, text, dict(slots or {}))
        query = (slots.get("query") or slots.get("topic") or "").strip()
        breaking = bool(slots.get("breaking"))
        search_queries = list(slots.get("search_queries") or [])
        time_horizon = (slots.get("time_horizon") or "").strip() or None
        entities = list(slots.get("entities") or [])
        action_result = handle_news_request(
            vera,
            query=query or None,
            breaking=breaking,
            search_queries=search_queries or None,
            time_horizon=time_horizon,
            entities=entities or None,
        )
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        # PART 4 polish: record the route_classification that produced this
        # search so the next-turn classifier can read previous_route_type.
        _polish_route = classify_news_route_for_turn(text, ctx=None)
        set_recent_news_context_from_action_result(
            session_id,
            text,
            action_result,
            previous_route_type=_polish_route.get("route_classification") or "topical_news_search",
        )
        try:
            log_news_route_classification(session_id, text, _polish_route)
        except Exception:
            pass
        return action_result, perf_counter() - t0

    if action_name == "finance.quote":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None, 0.0
        action_result = handle_finance_quote_request(vera, query=query)
        set_recent_action_from_result(session_id, action_name, {"query": query, **slots}, action_result)
        return action_result, perf_counter() - t0

    if action_name == "finance.context":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None, 0.0
        action_result = handle_finance_context_request(vera, query=query)
        set_recent_action_from_result(session_id, action_name, {"query": query, **slots}, action_result)
        return action_result, perf_counter() - t0

    if action_name == "finance.analytics":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None, 0.0
        raw_user_text = (slots.get("user_text") or text or "").strip() or None
        action_result = handle_finance_analytics_request(
            vera, query=query, raw_user_text=raw_user_text
        )
        set_recent_action_from_result(
            session_id, action_name, {"query": query, **slots}, action_result
        )
        return action_result, perf_counter() - t0

    if action_name in SPORTS_ACTION_NAMES:
        # 2026-05-30 sport-aware router. The intent dict is built upstream by
        # classify_sports_intent and threaded through slots. We re-classify
        # only if the upstream caller didn't (defense-in-depth for any direct
        # invocation by tests).
        raw_user_text = (slots.get("user_text") or text or "").strip()
        sports_intent = slots.get("sports_intent")
        if not isinstance(sports_intent, dict) or not sports_intent.get("is_sports"):
            sports_intent = classify_sports_intent(
                raw_user_text,
                recent_sports_context=get_recent_sports_context(session_id),
            )
        action_result = handle_sports_request(
            vera,
            intent=sports_intent,
            original_text=raw_user_text,
            session_id=session_id or "",
        )
        set_recent_action_from_result(
            session_id, action_name, {"query": raw_user_text, **slots}, action_result
        )
        try:
            set_recent_sports_context_from_action_result(
                session_id or "", raw_user_text, sports_intent, action_result
            )
        except Exception as _sport_ctx_exc:  # noqa: BLE001
            print("[sports_context_save_error]", _sport_ctx_exc, flush=True)
        return action_result, perf_counter() - t0

    if action_name == "web.search":
        # 2026-05-28 PART 1 — beta info-tool router.
        # Generic web-search fallback for sports / shopping / local / factoid
        # questions that don't fit a specialized tool. Streams an LLM answer
        # using Serper /search snippets; never opens a side panel.
        query = (slots.get("query") or slots.get("user_text") or text or "").strip()
        if not query:
            return None, 0.0
        try:
            print(
                "[search_action_execute] "
                + json.dumps({"query": query[:240]}, ensure_ascii=False),
                flush=True,
            )
        except Exception:
            pass
        raw_user_text = (slots.get("user_text") or text or "").strip() or None
        action_result = handle_web_search_request(
            vera, query=query, raw_user_text=raw_user_text
        )
        set_recent_action_from_result(
            session_id, action_name, {"query": query, **slots}, action_result
        )
        return action_result, perf_counter() - t0

    if action_name == "music.open_panel":
        action_result = handle_music_open_panel()
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "news.open_panel":
        # Pure UI command. Never touches Work Mode / reasoning panels.
        # We deliberately do NOT call set_recent_news_context here because
        # opening the panel surface should not invalidate the user's prior
        # search context, and we do NOT want a vague follow-up to inherit
        # this empty surface as if it were a fresh news topic.
        slot_query = ""
        slot_title = ""
        if isinstance(slots, dict):
            slot_query = str(slots.get("query") or "").strip()
            slot_title = str(slots.get("title") or slots.get("topic") or "").strip()
        action_result = handle_news_open_panel(query=slot_query, title=slot_title)
        try:
            print(
                "[news_panel_ui] " + json.dumps(
                    {
                        "stage": "executed",
                        "latest_user_text": (text or "")[:200],
                        "ui_action_intent": "open_news_panel",
                        "work_mode_route": False,
                        "reasoning_panel_route": False,
                        "news_panel_opened": True,
                        "news_panel_mode": "open",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "news.close_panel":
        action_result = handle_news_close_panel()
        try:
            print(
                "[news_panel_ui] " + json.dumps(
                    {
                        "stage": "executed",
                        "latest_user_text": (text or "")[:200],
                        "ui_action_intent": "close_news_panel",
                        "work_mode_route": False,
                        "reasoning_panel_route": False,
                        "news_panel_opened": False,
                        "news_panel_mode": "closed",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.close_panel":
        action_result = handle_music_close_panel()
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.pause":
        action_result = handle_music_pause()
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.resume":
        action_result = handle_music_resume()
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.volume_up":
        if is_checklist_undo_followup(text):
            spoken = _undo_clarification_spoken(session_id)
            return {
                "spoken_reply": spoken,
                "action_type": "clarification",
                "data": {"undo_clarification": True},
                "ui_payload": None,
            }, perf_counter() - t0
        action_result = handle_music_volume_up(0.05)
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.volume_down":
        if is_checklist_undo_followup(text):
            spoken = _undo_clarification_spoken(session_id)
            _emit_undo_routing_log(
                "undo_wrong_domain_blocked",
                raw_text=(text or "")[:200],
                normalized_text=(text or "").strip().lower()[:200],
                recent_action_domain="music",
                pending_undo_domain="",
                checklist_snapshot_exists=session_id in checklist_undo_snapshots,
                checklist_undo_ttl_remaining_ms=_checklist_undo_ttl_remaining_ms(session_id),
                selected_undo_domain="",
                blocked_domain="music.volume_down",
                decision_reason="blocked_volume_down_for_undo_intent",
            )
            return {
                "spoken_reply": spoken,
                "action_type": "clarification",
                "data": {"undo_clarification": True},
                "ui_payload": None,
            }, perf_counter() - t0
        action_result = handle_music_volume_down(0.05)
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.skip_next":
        action_result = handle_music_skip_next(client_context_snapshot)
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.skip_previous":
        action_result = handle_music_skip_previous(client_context_snapshot)
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "work_mode.reasoning_select_panel":
        if _is_explain_style_work_mode_topic_request(text) and not _explicit_work_mode_panel_navigation(text):
            return None, 0.0
        action_result = handle_work_mode_reasoning_select_panel(
            dict(slots or {}), client_context_snapshot, user_text=text
        )
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "work_mode.reasoning_open_panel":
        action_result = handle_work_mode_reasoning_open_panel(client_context_snapshot, dict(slots or {}))
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "work_mode.reasoning_close_panel":
        action_result = handle_work_mode_reasoning_close_panel(
            client_snapshot=client_context_snapshot,
            slots=dict(slots or {}),
            user_text=text,
        )
        set_recent_action_from_result(session_id, action_name, slots, action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.play_builtin":
        pid = (slots.get("playlist_id") or "").strip()
        sid = (slots.get("sound_id") or "").strip()
        action_result = handle_music_play_builtin(playlist_id=pid or None, sound_id=sid or None)
        set_recent_action_from_result(session_id, action_name, dict(slots or {}), action_result)
        return action_result, perf_counter() - t0

    if action_name == "music.play_track":
        q = build_music_search_query(slots or {})
        if not q:
            set_pending_action(session_id, "music.play_track", "track_query", dict(slots or {}))
            action_result = {
                "spoken_reply": MUSIC_TRACK_QUERY_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        action_result = handle_music_play_track(dict(slots or {}))
        set_recent_action_from_result(
            session_id, action_name, {**(slots or {}), "resolved_query": q}, action_result
        )
        return action_result, perf_counter() - t0

    if action_name == "music.play_album":
        q = build_music_album_query(slots or {})
        if not q:
            set_pending_action(session_id, "music.play_album", "album_query", dict(slots or {}))
            action_result = {
                "spoken_reply": MUSIC_ALBUM_QUERY_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        action_result = handle_music_play_album(dict(slots or {}))
        set_recent_action_from_result(
            session_id, action_name, {**(slots or {}), "resolved_query": q}, action_result
        )
        return action_result, perf_counter() - t0

    if action_name == "music.play_playlist":
        name = build_music_playlist_name_query(slots or {})
        if not name:
            set_pending_action(session_id, "music.play_playlist", "playlist_name", dict(slots or {}))
            action_result = {
                "spoken_reply": MUSIC_PLAYLIST_NAME_PROMPT,
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            return action_result, perf_counter() - t0
        action_result = handle_music_play_playlist(dict(slots or {}))
        set_recent_action_from_result(
            session_id, action_name, {**(slots or {}), "resolved_playlist": name}, action_result
        )
        return action_result, perf_counter() - t0

    if action_name == "music.play_clarify":
        # Degenerate "play" / "play something": ask what to play and arm the
        # existing track-query pending flow so a follow-up ("Feather") resolves.
        question = (slots.get("question") or "What would you like me to play?").strip()
        set_pending_action(session_id, "music.play_track", "track_query", {})
        action_result = {
            "spoken_reply": question,
            "action_type": "music",
            "data": None,
            "ui_payload": None,
        }
        return action_result, perf_counter() - t0

    if action_name == "music.play_unsupported":
        # 2026-06-14 — the music.play verdict detected an unsupported
        # scheduling / recurrence / conditional tail (e.g. "play music in 15
        # minutes"). Speak a clear "can't schedule yet" message and do NOT
        # emit any playback ui_payload. Partial / deferred multi-action
        # behavior is intentionally out of scope for Phase 1.
        reason = (slots.get("reason") or "scheduling").strip().lower()
        if reason == "recurrence":
            spoken = "I can play music now, but I can't schedule it to repeat yet."
        elif reason == "conditional":
            spoken = "I can play music now, but I can't trigger it on a condition yet."
        else:
            spoken = "I can play music now, but I can't schedule it to start later yet."
        action_result = {
            "spoken_reply": spoken,
            "action_type": "music",
            "data": {"unsupported": True, "reason": reason},
            "ui_payload": None,
        }
        return action_result, perf_counter() - t0

    if action_name == "music.unsupported":
        # 2026-06-15 — music-family unsupported-modifier guard (Option A) for
        # transport/volume single-action routes ("pause in 10 minutes", "turn
        # volume up later", "pause when the timer ends"). Speak the
        # action-specific "can't schedule yet" message and do NOT emit any
        # music_control / playback ui_payload. No scheduling is performed.
        family = (slots.get("family") or "music.pause").strip()
        phrase = (slots.get("phrase") or "").strip()
        spoken = _music_unsupported_spoken(family, phrase=phrase)
        action_result = {
            "spoken_reply": spoken,
            "action_type": "music",
            "data": {
                "unsupported": True,
                "family": family,
                "reason": slots.get("reason") or "",
                "timing_kind": slots.get("timing_kind") or "",
            },
            "ui_payload": None,
        }
        return action_result, perf_counter() - t0

    return None, 0.0


class PreparedStreamingAction:
    """Structured action routed to async_generate_stream + sentence TTS (same as general chat)."""

    __slots__ = ("messages", "meta_action_type", "meta_action_payload", "finalize")

    def __init__(
        self,
        messages: list[dict],
        meta_action_type: str | None,
        meta_action_payload: dict | None,
        finalize: Callable[[str], dict],
    ):
        self.messages = messages
        self.meta_action_type = meta_action_type
        self.meta_action_payload = meta_action_payload
        self.finalize = finalize


def build_weather_stream_messages(vera, transcript: str, facts: dict) -> list[dict]:
    """Match handle_weather_request + answer_direct_weather_question without generate."""
    lowered = transcript.lower()
    if "weather" in lowered:
        return vera.build_messages([], build_weather_prompt(facts))
    messages = vera.build_messages([], transcript)
    return add_weather_context(messages, facts)


def prepare_streaming_structured_action(
    session_id: str,
    text: str,
    route: dict,
    filler_generation: int | None = None,
) -> PreparedStreamingAction | None:
    """Mirror execute_structured_action but return LLM messages + finalize() instead of blocking generate."""
    action_name = route.get("action_name")
    slots = route.get("slots", {})

    if route.get("needs_followup"):
        return None

    try:
        _cap_action, _cap_feature = _credit_action_for_structured_action(action_name)
        if _cap_action:
            _enforce_usage_credit_cap(
                _cap_action,
                session_id=session_id,
                feature_type=_cap_feature,
            )
    except HTTPException:
        raise

    if action_name == "weather.current":
        location = clean_location_text(slots.get("location", ""))
        if not location:
            return None
        facts, err = fetch_weather_facts_for_action(location)
        if err:
            return None
        messages = build_weather_stream_messages(vera, text, facts)
        cache_key = normalize_location_key(location or DEFAULT_LOCATION)
        effective_slots = dict(slots)
        effective_slots["location"] = location or facts.get("place_name")

        def finalize(full_reply: str) -> dict:
            ar = {
                "spoken_reply": full_reply,
                "action_type": "weather",
                "data": facts,
                "ui_payload": None,
            }
            cache_weather_action_result(cache_key, ar)
            set_recent_action_from_result(session_id, "weather.current", effective_slots, ar)
            return ar

        return PreparedStreamingAction(messages, "weather", None, finalize)

    if action_name == "weather.followup":
        recent = get_recent_action_context(session_id)
        if not recent or recent.get("action_name") != "weather.current":
            return None
        action_result = dict(recent.get("result", {}))
        facts = action_result.get("data")
        if not facts:
            return None
        messages = build_weather_stream_messages(vera, text, facts)

        def finalize(full_reply: str) -> dict:
            ar = {**action_result, "spoken_reply": full_reply}
            set_recent_action_from_result(session_id, "weather.current", recent.get("slots", {}), ar)
            return ar

        return PreparedStreamingAction(messages, "weather", None, finalize)

    if action_name == "time.current":
        location = clean_location_text(slots.get("location", ""))
        p = prepare_time_stream_messages(vera, location or None)
        if p is None:
            return None
        messages, facts = p
        effective_slots = dict(slots)
        effective_slots["location"] = location or facts.get("place_name")

        def finalize(full_reply: str) -> dict:
            ar = {
                "spoken_reply": full_reply,
                "action_type": "time",
                "data": facts,
                "ui_payload": None,
            }
            set_recent_action_from_result(session_id, "time.current", effective_slots, ar)
            return ar

        return PreparedStreamingAction(messages, "time", None, finalize)

    if action_name == "date.current":
        location = clean_location_text(slots.get("location", ""))
        p = prepare_date_stream_messages(vera, location or None)
        if p is None:
            return None
        messages, facts = p
        effective_slots = dict(slots)
        effective_slots["location"] = location or facts.get("place_name")

        def finalize(full_reply: str) -> dict:
            ar = {
                "spoken_reply": full_reply,
                "action_type": "date",
                "data": facts,
                "ui_payload": None,
            }
            set_recent_action_from_result(session_id, "date.current", effective_slots, ar)
            return ar

        return PreparedStreamingAction(messages, "date", None, finalize)

    if action_name == "date.delta":
        target_name = (slots.get("target_name") or slots.get("target") or "").strip()
        location = clean_location_text(slots.get("location", ""))
        if not target_name:
            return None
        p = prepare_date_delta_stream_messages(vera, target_name, location or None)
        if p is None:
            return None
        messages, facts = p
        effective_slots = dict(slots)
        effective_slots["target_name"] = target_name
        effective_slots["location"] = location or facts.get("place_name")

        def finalize(full_reply: str) -> dict:
            ar = {
                "spoken_reply": full_reply,
                "action_type": "date",
                "data": facts,
                "ui_payload": None,
            }
            set_recent_action_from_result(session_id, "date.delta", effective_slots, ar)
            return ar

        return PreparedStreamingAction(messages, "date", None, finalize)

    if action_name == "news.latest":
        slots = _finalize_news_latest_slots(session_id, text, dict(slots or {}))
        query = (slots.get("query") or slots.get("topic") or "").strip()
        breaking = bool(slots.get("breaking"))
        search_queries = list(slots.get("search_queries") or [])
        time_horizon = (slots.get("time_horizon") or "").strip() or None
        entities = list(slots.get("entities") or [])
        prepared = prepare_news_streaming_messages(
            vera,
            query or None,
            breaking,
            search_queries=search_queries or None,
            time_horizon=time_horizon,
            entities=entities or None,
        )
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(session_id, "news.latest", slots, ar)
            # PART 4+5 polish: capture route_classification + answer_summary
            # (the streamed reply text) on the stored context so the next
            # turn's classifier sees both "what we searched for" and "what we
            # already told the user".
            _polish_route = classify_news_route_for_turn(text, ctx=None)
            set_recent_news_context_from_action_result(
                session_id,
                text,
                ar,
                previous_route_type=_polish_route.get("route_classification") or "topical_news_search",
                answer_summary=full_reply or "",
            )
            try:
                log_news_route_classification(session_id, text, _polish_route)
            except Exception:
                pass
            return ar

        return PreparedStreamingAction(messages, "news", ui_payload, finalize)

    if action_name == "finance.quote":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None
        prepared = prepare_finance_quote_streaming(vera, query)
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(session_id, "finance.quote", {"query": query, **slots}, ar)
            return ar

        return PreparedStreamingAction(messages, "finance", ui_payload, finalize)

    if action_name == "finance.context":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None
        prepared = prepare_finance_context_streaming(vera, query)
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(session_id, "finance.context", {"query": query, **slots}, ar)
            return ar

        return PreparedStreamingAction(messages, "finance", ui_payload, finalize)

    if action_name == "finance.analytics":
        query = (slots.get("query") or slots.get("ticker") or slots.get("subject") or "").strip()
        if not query:
            return None
        raw_user_text = (slots.get("user_text") or text or "").strip() or None
        prepared = prepare_finance_analytics_streaming(
            vera, query, raw_user_text=raw_user_text
        )
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(
                session_id, "finance.analytics", {"query": query, **slots}, ar
            )
            return ar

        return PreparedStreamingAction(messages, "finance", ui_payload, finalize)

    if action_name == "web.search":
        # 2026-05-28 PART 1 — beta info-tool router streaming path.
        # Same shape as finance.analytics: prepare messages with Serper
        # snippets, let the LLM stream the final voice-friendly answer.
        query = (slots.get("query") or slots.get("user_text") or text or "").strip()
        if not query:
            return None
        raw_user_text = (slots.get("user_text") or text or "").strip() or None
        prepared = prepare_web_search_streaming(
            vera, query, raw_user_text=raw_user_text
        )
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(
                session_id, "web.search", {"query": query, **slots}, ar
            )
            return ar

        return PreparedStreamingAction(messages, "web_search", ui_payload, finalize)

    if action_name in SPORTS_ACTION_NAMES:
        # 2026-05-30 sport-aware streaming path. Mirrors the web.search path
        # but routes through actions.sports for sport- and query-type-aware
        # query construction + Sports/Tournament Results panel labeling.
        raw_user_text = (slots.get("user_text") or text or "").strip()
        sports_intent = slots.get("sports_intent")
        if not isinstance(sports_intent, dict) or not sports_intent.get("is_sports"):
            sports_intent = classify_sports_intent(
                raw_user_text,
                recent_sports_context=get_recent_sports_context(session_id),
            )
        if sports_intent.get("needs_clarification"):
            # Synthesize a minimal action_result so the caller can finalize
            # without invoking the LLM. The streaming layer surfaces this as
            # a normal short reply.
            def _clarif_finalize(_full_reply: str) -> dict:
                ar = {
                    "spoken_reply": _full_reply or
                        "Which team or player did you mean? I lost the previous sports topic.",
                    "action_type": "web_search",
                    "data": {
                        "sports_intent": sports_intent,
                        "needs_clarification": True,
                    },
                    "ui_payload": None,
                }
                set_recent_action_from_result(
                    session_id, action_name,
                    {"query": raw_user_text, **slots}, ar
                )
                return ar
            try:
                messages = vera.build_messages(
                    [],
                    "Reply ONLY with a single short clarification: "
                    "ask the user which team or player they meant. Do not "
                    "invent an answer.",
                )
            except Exception:  # noqa: BLE001
                return None
            return PreparedStreamingAction(messages, "web_search", None, _clarif_finalize)
        prepared = prepare_sports_streaming(
            vera,
            intent=sports_intent,
            original_text=raw_user_text,
            session_id=session_id or "",
        )
        if prepared is None:
            return None
        messages, ui_payload, fin = prepared

        def finalize(full_reply: str) -> dict:
            ar = fin(full_reply)
            set_recent_action_from_result(
                session_id, action_name,
                {"query": raw_user_text, **slots}, ar
            )
            try:
                set_recent_sports_context_from_action_result(
                    session_id or "", raw_user_text, sports_intent, ar
                )
            except Exception as _ctx_exc:  # noqa: BLE001
                print("[sports_context_save_error]", _ctx_exc, flush=True)
            return ar

        return PreparedStreamingAction(messages, "web_search", ui_payload, finalize)

    return None


def _strip_question_prefix_for_topic(s: str) -> str:
    """Convert 'Hey Vera, do you know that Elon Musk is suing OpenAI?' → 'Elon Musk suing OpenAI'."""
    raw = (s or "").strip().strip(string.punctuation + " ")
    if not raw:
        return ""
    low = raw.lower()
    for pat in (
        r"^(?:hey\s+)?(?:vera|jarvis|bmo)[,\s]+",
        r"^(?:hey|hi|hello)[,\s]+",
        r"^(?:do you know|did you know|have you heard|are you aware)\s+(?:that|about|of)?\s*",
        r"^(?:can you|could you|would you|please)\s+(?:tell me|give me|share|explain|describe|search|look up|find|get|pull up|read me)\s+(?:about|on|regarding)?\s*",
        r"^(?:tell me|give me|i want to know|i'd like to know)\s+(?:about|on|regarding)?\s*",
        r"^(?:what|who|when|where|why|how)\s+(?:is|are|was|were|does|do|did)\s+",
        r"^(?:the\s+)?(?:latest|recent|newest)\s+(?:news|headlines?)\s+(?:on|about|regarding|for)\s+",
        r"^(?:news|headlines?)\s+(?:on|about|regarding|for)\s+",
    ):
        m = re.match(pat, low)
        if m:
            raw = raw[m.end():].strip().strip(string.punctuation + " ")
            low = raw.lower()
    return raw[:200]


def _detect_voice_action_offer_from_assistant_reply(
    assistant_text: str, previous_user_text: str
) -> dict | None:
    """If the assistant offered to take a structured action, return a pending voice action dict."""
    t = (assistant_text or "").strip().lower()
    if not t:
        return None
    offer_lead = (
        r"\b(?:i can|i could|i['’]d be (?:happy|glad) to|happy to|"
        r"want me to|would you like me to|do you want me to|shall i|let me)\b"
    )
    news_verb = (
        r"\b(?:give|share|pull (?:up|together)?|get|fetch|find|look up|search|"
        r"tell you|read (?:you|out|me)?|grab|surface|run through|round up|summari[sz]e)\b"
    )
    news_object = (
        r"\b(?:latest|recent|breaking|today['’]?s|known)?\s*"
        r"(?:headlines?|news|updates?|articles?|stories|coverage|reports?|status)\b"
    )
    looks_like_news_offer = bool(
        re.search(f"{offer_lead}.{{0,80}}{news_verb}.{{0,80}}{news_object}", t)
        or re.search(rf"{offer_lead}.{{0,60}}{news_object}", t)
        or re.search(r"\bgive you the latest\b", t)
        or re.search(r"\bsummari[sz]e the latest (?:known )?status\b", t)
        or re.search(r"\b(?:the )?latest (?:headlines?|news|updates?)\b.{0,40}\b(?:on it|about it|on this|on that)\b", t)
    )
    if looks_like_news_offer:
        topic = _strip_question_prefix_for_topic(previous_user_text or "")
        if topic:
            return {
                "action_type": "latest_news_search",
                "topic": topic,
                "created_at": time(),
                "expires_after_ms": VOICE_OFFER_TTL_SEC * 1000,
            }
    return None


def _is_short_voice_followup_affirmative(text: str) -> bool:
    raw = (text or "").strip().lower().strip(string.punctuation + " ")
    if not raw:
        return False
    if len(raw.split()) > 8:
        return False
    patterns = (
        r"^(?:yes|yeah|yep|yup|sure|of course|absolutely|definitely|alright|all right|ok|okay|fine)$",
        r"^(?:yes|yeah|yep|yup|sure|ok|okay)\s*(?:,|\.)?\s*please$",
        r"^please(?:\s+do)?$",
        r"^(?:please\s+)?(?:do(?:\s+(?:it|that|so))?)$",
        r"^go ahead$",
        r"^(?:can|could|would)\s+you(?:\s+please)?(?:\s+do(?:\s+(?:it|that|so|the\s+\w+))?)?\??$",
        r"^(?:can|could|would)\s+you\s+please(?:\s+do(?:\s+(?:it|that|so))?)?\??$",
        r"^tell me more$",
        r"^give me (?:the )?(?:latest|news|details|headlines?|update|the rundown)$",
        r"^(?:let['’]s|lets) hear (?:it|them)$",
        r"^show me$",
        r"^i['’]d like that$",
        r"^that['’]?d be (?:great|good|helpful)$",
        r"^that would be (?:great|good|helpful)$",
        r"^sounds good$",
    )
    for pat in patterns:
        if re.match(pat, raw):
            return True
    return False


def _last_assistant_and_previous_user_from_history(history: list[dict]) -> tuple[str, str]:
    """Return (last_assistant_text, user_text_immediately_before_that_assistant)."""
    assistant_idx = -1
    for i in range(len(history) - 1, -1, -1):
        if (history[i] or {}).get("role") == "assistant":
            assistant_idx = i
            break
    if assistant_idx < 0:
        return "", ""
    assistant_text = str(history[assistant_idx].get("content") or "")
    previous_user_text = ""
    for j in range(assistant_idx - 1, -1, -1):
        if (history[j] or {}).get("role") == "user":
            previous_user_text = str(history[j].get("content") or "")
            break
    return assistant_text, previous_user_text


def _capture_pending_voice_offer(session_id: str, history: list[dict]) -> dict | None:
    """Inspect the latest assistant turn; if it contained an offer, store + return it."""
    if not session_id or not history:
        return None
    assistant_text, previous_user_text = _last_assistant_and_previous_user_from_history(history)
    if not assistant_text:
        return pending_voice_actions.get(session_id)
    offer = _detect_voice_action_offer_from_assistant_reply(assistant_text, previous_user_text)
    if offer:
        pending_voice_actions[session_id] = offer
        return offer
    return pending_voice_actions.get(session_id)


def _get_pending_voice_action(session_id: str) -> dict | None:
    p = pending_voice_actions.get(session_id)
    if not p:
        return None
    created_at = float(p.get("created_at") or 0)
    ttl_ms = float(p.get("expires_after_ms") or 0)
    if (time() - created_at) * 1000.0 > ttl_ms:
        pending_voice_actions.pop(session_id, None)
        return None
    return p


def _clear_pending_voice_action(session_id: str) -> None:
    pending_voice_actions.pop(session_id, None)


def _log_voice_followup_resolution(row: dict) -> None:
    try:
        print("[voice_followup_resolution] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _build_route_for_pending_voice_action(
    action: dict | None, *, session_id: str | None = None
) -> dict | None:
    if not isinstance(action, dict):
        return None
    if action.get("action_type") == "latest_news_search":
        topic = str(action.get("topic") or "").strip()
        if not topic:
            return None
        initial_slots = {
            "query": _normalize_news_topic_phrase(topic) or topic,
            "entities": _extract_news_entities(topic),
            "time_horizon": _extract_news_time_horizon(topic),
        }
        final_slots = _finalize_news_latest_slots(session_id, topic, initial_slots)
        if not final_slots.get("search_queries"):
            return None
        return normalize_route(
            {
                "is_action_request": True,
                "action_name": "news.latest",
                "slots": final_slots,
            }
        )
    return None


def try_resolve_pending_voice_action(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    client_context_snapshot: dict | None = None,
    filler_generation: int | None = None,
) -> tuple[dict | None, float]:
    """Execute the assistant's previously-offered action when the user replies with a short
    affirmative ("yes please", "can you please do?"). Skipped in Work Mode."""
    if _is_work_mode_snapshot(client_context_snapshot):
        return None, 0.0
    history = history or []
    assistant_text, previous_user_text = _last_assistant_and_previous_user_from_history(history)
    pending = _capture_pending_voice_offer(session_id, history) or _get_pending_voice_action(session_id)
    is_short_affirm = _is_short_voice_followup_affirmative(text)

    log_row = {
        "user_text": (text or "")[:200],
        "previous_user_text": previous_user_text[:200],
        "previous_assistant_text": assistant_text[:200],
        "pending_action_type": (pending or {}).get("action_type"),
        "pending_topic": (pending or {}).get("topic"),
        "resolved_followup": False,
        "reason": "",
    }
    if not pending:
        log_row["reason"] = "no_pending_voice_action"
        _log_voice_followup_resolution(log_row)
        return None, 0.0
    if not is_short_affirm:
        log_row["reason"] = "user_not_short_affirmative"
        _log_voice_followup_resolution(log_row)
        return None, 0.0
    route = _build_route_for_pending_voice_action(pending, session_id=session_id)
    if not route:
        log_row["reason"] = f"unsupported_action_type:{pending.get('action_type')}"
        _log_voice_followup_resolution(log_row)
        return None, 0.0

    action_result, t_llm = execute_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )
    _clear_pending_voice_action(session_id)
    log_row["resolved_followup"] = action_result is not None
    log_row["reason"] = "executed_pending_voice_action"
    _log_voice_followup_resolution(log_row)
    return action_result, t_llm


# =========================
# NEWS ROUTE / FOLLOW-UP (current-events hybrid)
# =========================
_NEWS_ENTITY_STOPWORDS = {
    "hey", "hi", "hello", "yo", "okay", "ok", "vera", "jarvis", "bmo",
    "i", "i'm", "im", "me", "my", "mine", "we", "us", "our",
    "you", "your", "yours", "he", "she", "they", "them",
    "what", "who", "when", "where", "why", "how", "which",
    "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
    "do", "does", "did", "doing", "done",
    "and", "or", "but", "so", "then", "if", "of", "for", "on", "in",
    "to", "from", "with", "about", "into", "than", "that", "this", "these", "those",
    "today", "tomorrow", "yesterday", "now", "current", "latest", "recent", "recently",
    "morning", "noon", "afternoon", "evening", "night", "tonight",
    "monday", "tuesday", "wednesday", "thursday", "friday", "saturday", "sunday",
    "january", "february", "march", "april", "may", "june", "july",
    "august", "september", "october", "november", "december",
    "news", "headline", "headlines", "article", "articles", "story", "stories",
    "source", "sources", "update", "updates",
    "please", "tell", "give", "show", "explain", "share",
    "lawsuit", "trip", "visit",  # entity-adjacent topic nouns – not entities themselves
    # Common single-token verbs/modals/connectives that show up capitalized at
    # the start of an assistant sentence (e.g. "Want the latest?" → "Want").
    # Without these, `_extract_news_entities` was treating them as named entities.
    "want", "wants", "wanted", "need", "needs", "needed",
    "can", "could", "will", "would", "shall", "should", "may", "might", "must",
    "have", "has", "had", "having",
    "let", "lets", "let's",
    "yes", "no", "yeah", "yep", "nope", "sure",
    "more", "most", "less", "least",
    "good", "great", "nice", "fine",
    "according",
}

_NEWS_ENTITY_ALIASES = {
    "trump": "Trump",
    "donald trump": "Donald Trump",
    "china": "China",
    "openai": "OpenAI",
    "open ai": "OpenAI",
    "elon musk": "Elon Musk",
    "musk": "Musk",
    "jensen huang": "Jensen Huang",
    "beijing": "Beijing",
    "new york": "New York",
    "russia": "Russia",
    "ukraine": "Ukraine",
    "taiwan": "Taiwan",
    "iran": "Iran",
    "israel": "Israel",
    "gaza": "Gaza",
    "europe": "Europe",
    "microsoft": "Microsoft",
}


def _extract_news_entities(text: str) -> list[str]:
    """Pull likely named entities, including common lowercase ASR forms."""
    raw = (text or "").strip()
    if not raw:
        return []
    candidates = re.findall(
        r"\b(?:[A-Z][a-zA-Z\.'\-]{1,30}(?:\s+[A-Z][a-zA-Z\.'\-]{1,30}){0,3})\b",
        raw,
    )
    seen: set = set()
    out: list[str] = []
    for c in candidates:
        c_clean = c.strip(".,!?;:'\"")
        if not c_clean:
            continue
        low = c_clean.lower()
        # Drop if every token is a stopword (e.g. "What", "Hey Vera").
        # Also normalize "'s" suffix so "What's" → "what" matches the stopword
        # set, otherwise "What's the reason?" leaks "What's" as an entity and
        # breaks the interpretive classifier (PART 5 of the polish spec).
        tokens = []
        for tok in re.split(r"\s+", c_clean):
            t = tok.lower().strip(".,!?;:'\"")
            if not t:
                continue
            if t.endswith("'s") or t.endswith("\u2019s"):
                t = t[:-2]
            tokens.append(t)
        if not tokens or all(t in _NEWS_ENTITY_STOPWORDS for t in tokens):
            continue
        key = low
        if key in seen:
            continue
        seen.add(key)
        out.append(c_clean)
        if len(out) >= 8:
            break
    lowered = raw.lower()
    for phrase, canonical in _NEWS_ENTITY_ALIASES.items():
        if len(out) >= 8:
            break
        if re.search(rf"\b{re.escape(phrase)}\b", lowered):
            key = canonical.lower()
            if key not in seen:
                seen.add(key)
                out.append(canonical)
    return out


def _extract_news_time_horizon(text: str) -> str:
    raw = (text or "").strip().lower()
    if not raw:
        return "unspecified"
    if re.search(r"\b(?:in the )?past\s+(?:24|twenty[\s-]?four)\s*(?:hours?|hrs?)\b", raw):
        return "past_24h"
    if re.search(r"\b(?:today|tonight|this morning|this afternoon|this evening|right now|just now)\b", raw):
        return "today"
    if re.search(r"\b(?:past|last|this)\s+week\b", raw) or "in the past week" in raw:
        return "past_week"
    if re.search(r"\b(?:past|last)\s+(?:two|2)\s+weeks?\b", raw) or re.search(r"\b(?:past|last)\s+14\s+days?\b", raw):
        return "past_14_days"
    if re.search(r"\b(?:past|last|this)\s+month\b", raw) or re.search(r"\b(?:past|last)\s+30\s+days?\b", raw):
        return "past_month"
    return "unspecified"


def _normalize_news_topic_phrase(text: str) -> str:
    """Strip greetings/question-prefixes to get the topical core. Reuses `_strip_question_prefix_for_topic`."""
    return _strip_question_prefix_for_topic(text)


def _build_news_search_queries(
    entities: list[str],
    time_horizon: str,
    topic_phrase: str,
    extra_entities: list[str] | None = None,
) -> list[str]:
    """2-3 targeted queries from entities + time horizon. Avoid `latest developments in X`."""
    ent = [str(e).strip() for e in (entities or []) if str(e).strip()]
    extra = [str(e).strip() for e in (extra_entities or []) if str(e).strip()]
    if extra:
        for e in extra:
            if e not in ent:
                ent.append(e)
    base_topic = (topic_phrase or "").strip()
    horizon_word = ""
    if time_horizon == "today":
        horizon_word = "today"
    elif time_horizon == "past_24h":
        horizon_word = "past 24 hours"
    elif time_horizon == "past_week":
        horizon_word = "past week"
    elif time_horizon == "past_14_days":
        horizon_word = "past two weeks"
    elif time_horizon == "past_month":
        horizon_word = "past month"

    queries: list[str] = []

    def _add(q: str) -> None:
        s = re.sub(r"\s+", " ", q).strip(" -–—")
        if s and s.lower() not in {x.lower() for x in queries}:
            queries.append(s)

    if ent:
        _add(" ".join(ent[:4]) + (f" {horizon_word}" if horizon_word else " latest"))
        _add(" ".join(ent[:4]) + " latest news")
        if base_topic and base_topic.lower() not in " ".join(ent).lower():
            _add(" ".join(ent[:3]) + " " + base_topic + (f" {horizon_word}" if horizon_word else ""))
    elif base_topic:
        _add(base_topic + (f" {horizon_word}" if horizon_word else " latest"))
        _add(base_topic + " latest news")
        _add(base_topic + " update")
    return queries[:3]


def _build_broad_news_search_queries(text: str, time_horizon: str) -> list[str]:
    """Queries for fresh general headline requests.

    Deliberately contains no prior-topic terms. This is used for broad reset
    requests like "tell me some breaking news" after a specific news thread.
    """
    low = (text or "").strip().lower()
    horizon_word = ""
    if time_horizon in {"today", "past_24h"}:
        horizon_word = "today"
    elif time_horizon == "past_week":
        horizon_word = "this week"

    if "breaking" in low:
        base = "breaking news"
    elif "headline" in low:
        base = "top headlines"
    else:
        base = "latest news headlines"

    suffix = f" {horizon_word}" if horizon_word else ""
    queries = [
        f"{base}{suffix}".strip(),
        f"world news headlines{suffix}".strip(),
        f"top news stories{suffix}".strip(),
    ]
    out: list[str] = []
    for q in queries:
        s = re.sub(r"\s+", " ", q).strip()
        if s and s.lower() not in {x.lower() for x in out}:
            out.append(s)
    return out[:3]


def _log_news_search_query_built(
    original_user_text: str,
    entities: list[str],
    time_horizon: str,
    normalized_queries: list[str],
    *,
    raw_query: str = "",
) -> None:
    try:
        print(
            "[news_search_query_built] " + json.dumps(
                {
                    "original_user_text": (original_user_text or "")[:200],
                    "raw_query": (raw_query or "")[:200],
                    "entities": entities[:8],
                    "time_horizon": time_horizon,
                    "normalized_queries": normalized_queries[:5],
                    "final_queries": normalized_queries[:5],
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


# Deictic / context-dependent follow-up phrases that should NOT be searched literally.
_NEWS_DEICTIC_RE = re.compile(
    r"\b(?:this|that|the)\s+"
    r"(?:trip|visit|lawsuit|case|issue|event|story|deal|election|series|incident|"
    r"matter|topic|saga|drama|controversy|crisis|conflict|situation|game|episode|"
    r"chapter|fight|battle|war|meeting|summit|negotiation|talks|investigation)\b"
    r"|\b(?:any|anything)\s+else\b"
    r"|\b(?:what|anything|how)\s+(?:else\s+)?happened\b"
    r"|\bduring (?:this|that|it)\b"
    r"|\babout (?:this|that|it|them)\b"
    r"|\bmore (?:on|about) (?:this|that|it|them)\b"
    r"|\bwhat\s+(?:else|other|other\s+thing(?:s)?)\b"
    r"|^(?:that|this|it)\b",
    re.IGNORECASE,
)


# Pronoun/locative follow-up patterns. These only resolve against a prior news
# topic, never on their own — so "why was he there", "when was that",
# "what happened after", etc. don't fire a literal Serper search like "why was
# he there". Callers must check that prior news context exists before treating
# these as news follow-ups.
_NEWS_PRONOUN_FOLLOWUP_RE = re.compile(
    r"\b(?:why|how|when|where|what)\s+(?:was|were|did|do|does|is|are|would|"
    r"should|could)\s+(?:he|she|they|them|it|that|this|those|these)\b"
    r"|\b(?:was|were|did|do|does|is|are)\s+(?:he|she|they|them|it)\b"
    r"|\b(?:what|when|why|how)\s+(?:happened|happens)\b\s*(?:after|next|then)?\b"
    r"|\bwhen\s+was\s+(?:that|this|it)\b"
    r"|\b(?:is|was)\s+(?:that|this|it)\s+true\b"
    r"|\bwhy\s+(?:did|does|do)\s+(?:that|this|it)\s+happen\b"
    r"|\b(?:you\s+know\s+)?why\s+(?:he|she|they|them)\b"
    r"|\b(?:you\s+know\s+)?why\s+(?:was|were|is|are)\s+(?:he|she|they|them|it)\s+(?:there|here)\b"
    r"|\b(?:over\s+)?there\b\s*(?:why|how|when)?",
    re.IGNORECASE,
)


def _is_pronoun_news_followup(text: str) -> bool:
    raw = (text or "").strip()
    if not raw:
        return False
    # Pronoun follow-ups only make sense as short, dependent clauses. Long
    # standalone questions that happen to contain "he"/"she" are probably
    # fresh requests with named entities elsewhere.
    if len(raw.split()) > 18:
        return False
    if not _NEWS_PRONOUN_FOLLOWUP_RE.search(raw.lower()):
        return False
    # Don't treat as pronoun follow-up if the message also contains a clear
    # named entity — at that point the user has re-specified the subject and
    # the existing entity-overlap / fresh-search paths handle it.
    new_entities = _extract_news_entities(raw)
    substantive = [e for e in new_entities if _is_substantive_news_entity(e)]
    if substantive:
        return False
    return True


def _is_deictic_news_followup(text: str) -> bool:
    raw = (text or "").strip().lower()
    if not raw:
        return False
    if _NEWS_DEICTIC_RE.search(raw):
        return True
    if _is_pronoun_news_followup(text):
        return True
    return False


def _log_news_deictic_resolution(row: dict) -> None:
    try:
        print("[news_deictic_resolution] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _finalize_news_latest_slots(
    session_id: str | None,
    text: str,
    slots: dict | None,
) -> dict:
    """Single source of truth for news.latest slot finalization.

    - If query is deictic ("this trip", "anything else", "more on that") AND we have
      recent_news_context, expand it from the stored topic+entities so we never send
      Serper a literal query like 'latest developments in this trip'.
    - If entities are present but search_queries is empty, build 2-3 targeted queries
      (no 'latest developments in X' wrapping).
    - Emits [news_deictic_resolution] and [news_search_query_built] with raw_query +
      final_queries fields.
    - Idempotent when slots already have non-empty `search_queries` AND the query is
      not deictic (skips re-logging to keep things quiet on the hot path).
    """
    slots = dict(slots or {})
    raw_query = str(slots.get("query") or slots.get("topic") or "").strip()
    raw_text = (text or "").strip()
    incoming_queries = [
        str(q).strip() for q in (slots.get("search_queries") or []) if str(q).strip()
    ]
    # 2026-06-01 — Explicit general-news intent short-circuit. When the
    # upstream router (heuristic_route_action /
    # build_route_from_info_tool) flagged this turn as a BBC top-headlines
    # request, strip any inherited query / search_queries / entities so
    # the action dispatcher hits handle_news_request(query=None,
    # breaking=False, search_queries=None) and reaches the BBC RSS branch
    # in prepare_news_streaming_messages. Must run BEFORE the broad-reset
    # branch below (which would otherwise rebuild Serper-targeted
    # search_queries).
    if bool(slots.get("force_top_headlines")):
        slots["query"] = ""
        slots["topic"] = ""
        slots["entities"] = []
        slots["search_queries"] = []
        slots["time_horizon"] = ""
        slots["broad_news_reset"] = False
        slots["force_top_headlines"] = True
        slots["source_preference"] = str(slots.get("source_preference") or "bbc")
        try:
            slots["count"] = int(slots.get("count") or 3)
        except Exception:
            slots["count"] = 3
        _log_news_deictic_resolution(
            {
                "user_text": raw_text[:200],
                "raw_query": raw_query[:200],
                "prior_topic": "",
                "prior_entities": [],
                "resolved_topic": "",
                "resolved_queries": [],
                "reason": "force_top_headlines_bbc_route",
            }
        )
        _log_news_search_query_built(
            raw_text,
            [],
            "",
            [],
            raw_query=raw_query,
        )
        return slots
    if bool(slots.get("broad_news_reset")) or is_broad_news_reset_request(raw_text):
        horizon = str(slots.get("time_horizon") or "").strip()
        if not horizon or horizon == "unspecified":
            horizon = _extract_news_time_horizon(raw_text)
        if not horizon or horizon == "unspecified":
            horizon = "today"
        queries = incoming_queries or _build_broad_news_search_queries(raw_text or raw_query, horizon)
        slots["query"] = str(slots.get("query") or raw_query or "latest news headlines").strip()
        slots["topic"] = str(slots.get("topic") or slots["query"]).strip()
        slots["entities"] = []
        slots["time_horizon"] = horizon
        slots["search_queries"] = queries
        slots["broad_news_reset"] = True
        _log_news_deictic_resolution(
            {
                "user_text": raw_text[:200],
                "raw_query": raw_query[:200],
                "prior_topic": "",
                "prior_entities": [],
                "resolved_topic": slots["query"][:200],
                "resolved_queries": queries[:5],
                "reason": "broad_news_reset_ignore_context",
            }
        )
        _log_news_search_query_built(
            raw_text,
            [],
            horizon,
            queries,
            raw_query=raw_query or slots["query"],
        )
        return slots
    # 2026-05-30: the pre-news info normalizer flags merged-context queries
    # as `pre_normalized=True` so we MUST trust the caller's search_queries
    # even when the raw user turn was deictic ("give me some news on that").
    # Without this short-circuit the deictic-rebuild branch below would
    # discard the merged "Garden Grove Orange County chemical leak news"
    # query and replace it with a generic ctx-only rebuild, dropping the
    # new location the user just provided.
    pre_normalized = bool(slots.get("pre_normalized"))
    deictic_text = _is_deictic_news_followup(raw_text)
    deictic_query = _is_deictic_news_followup(raw_query)
    if incoming_queries and (pre_normalized or (not deictic_text and not deictic_query)):
        # Trust caller; nothing to rebuild. Keep slots untouched but normalize types.
        # Dedupe trailing "news news" before sending downstream.
        cleaned_queries = [_info_norm_dedupe_news_keywords(q) for q in incoming_queries]
        slots["search_queries"] = [q for q in cleaned_queries if q]
        slots["entities"] = list(slots.get("entities") or [])
        slots["time_horizon"] = str(slots.get("time_horizon") or "unspecified")
        if pre_normalized:
            # Keep the normalized query on the slot dict so downstream
            # consumers (panel title, logs) can pick it up.
            slots.setdefault("query", slots["search_queries"][0] if slots["search_queries"] else (raw_query or ""))
            slots["pre_normalized"] = True
        return slots

    ctx = get_recent_news_context(session_id) if session_id else None
    incoming_entities = [
        str(e).strip() for e in (slots.get("entities") or []) if str(e).strip()
    ]
    extracted_entities = _extract_news_entities(raw_text) or _extract_news_entities(raw_query)
    merged_entities: list[str] = []
    for e in incoming_entities + extracted_entities:
        if e and e not in merged_entities:
            merged_entities.append(e)

    horizon = str(slots.get("time_horizon") or "").strip()
    if not horizon or horizon == "unspecified":
        horizon = _extract_news_time_horizon(raw_text)
    if not horizon or horizon == "unspecified":
        horizon = _extract_news_time_horizon(raw_query) or horizon

    resolved_topic = raw_query
    expand_reason = "as_supplied"
    prior_topic = ""
    prior_entities: list[str] = []
    if ctx:
        prior_topic = str(ctx.get("topic") or "").strip()
        prior_entities = [str(e).strip() for e in (ctx.get("entities") or []) if str(e).strip()]
    # PART 7+11 (2026-05-28) stale-query reuse guard. If the current user
    # message contains its own named entity AND a complete question shape,
    # we MUST NOT silently rewrite the topic to the prior stored topic just
    # because the text looks deictic-ish or no raw_query was supplied.
    # See try_resolve_news_followup_corrective for the matched guard.
    current_has_named_entity = bool(merged_entities) or _has_named_entity_hint(raw_text)
    current_has_question_shape = _has_current_fact_question_lead(raw_text)
    _current_msg_is_standalone_factual = (
        current_has_named_entity and current_has_question_shape
    )
    if ctx and (deictic_text or deictic_query or (not merged_entities and not raw_query)):
        if _current_msg_is_standalone_factual and not deictic_text and not deictic_query:
            # Caller passed empty entities/query but the user text is a
            # complete standalone question. Use the user's own text as the
            # topic instead of replaying ctx.topic.
            normalized_current = _normalize_news_topic_phrase(raw_text)
            resolved_topic = normalized_current or raw_text or resolved_topic
            expand_reason = "standalone_factual_guard_ignored_context"
            try:
                print(
                    "[news_router_stale_query_guarded] "
                    + json.dumps(
                        {
                            "session_id": (session_id or "")[:64],
                            "where": "_finalize_news_latest_slots",
                            "user_text": raw_text[:200],
                            "stored_prior_topic": prior_topic[:200],
                            "chosen_topic": (resolved_topic or "")[:200],
                            "reason": "current_msg_has_named_entity_and_question_shape",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
        elif prior_entities or prior_topic:
            for e in prior_entities:
                if e and e not in merged_entities:
                    merged_entities.append(e)
            if not horizon or horizon == "unspecified":
                horizon = str(ctx.get("timeframe") or "unspecified")
            resolved_topic = prior_topic or resolved_topic or " ".join(merged_entities[:3])
            expand_reason = "deictic_expanded_from_context"
        else:
            expand_reason = "context_empty"
    elif ctx and merged_entities and not incoming_entities:
        # No deictic, but text has entities AND we already have a topic — bias to it
        # only if there's a clear overlap with stored entities. Otherwise leave alone.
        overlap = _entities_overlap(merged_entities, prior_entities)
        if overlap:
            for e in prior_entities:
                if e and e not in merged_entities:
                    merged_entities.append(e)
            if not horizon or horizon == "unspecified":
                horizon = str(ctx.get("timeframe") or "unspecified")
            expand_reason = "entity_overlap_merged_with_context"
    horizon = horizon or "unspecified"

    if incoming_queries and (deictic_text or deictic_query):
        # The caller passed queries built from a literal deictic — rebuild instead.
        queries = _build_news_search_queries(merged_entities, horizon, resolved_topic)
    elif incoming_queries:
        queries = incoming_queries
    else:
        queries = _build_news_search_queries(merged_entities, horizon, resolved_topic)

    # If this is a pronoun/deictic follow-up that expanded from context, also
    # append a query that fuses entities with the verbatim follow-up clause —
    # e.g. "Trump China visit past week why was he there". This lets Serper
    # surface articles about the actual interpretive angle the user asked.
    if (
        expand_reason == "deictic_expanded_from_context"
        and merged_entities
        and raw_text
        and _is_pronoun_news_followup(raw_text)
    ):
        clause = re.sub(r"^(?:you\s+know\s+|do\s+you\s+know\s+)", "", raw_text.strip(), flags=re.IGNORECASE)
        clause = clause.strip(string.punctuation + " ")
        if clause and len(clause) <= 80:
            fused = (" ".join(merged_entities[:4]) + " " + clause).strip()
            if fused and fused.lower() not in {q.lower() for q in queries}:
                queries.append(fused)
                queries = queries[:4]

    if not queries:
        if resolved_topic:
            # Last resort: keep the resolved topic, attach the timeframe directly.
            tail = ""
            if horizon == "past_week":
                tail = " past week"
            elif horizon == "past_24h":
                tail = " past 24 hours"
            elif horizon == "today":
                tail = " today"
            elif horizon == "past_14_days":
                tail = " past two weeks"
            elif horizon == "past_month":
                tail = " past month"
            else:
                tail = " latest"
            queries = [(resolved_topic + tail).strip()]
        elif merged_entities:
            queries = [" ".join(merged_entities[:4]) + " latest"]

    _log_news_deictic_resolution(
        {
            "user_text": raw_text[:200],
            "raw_query": raw_query[:200],
            "prior_topic": prior_topic,
            "prior_entities": prior_entities[:8],
            "resolved_topic": (resolved_topic or "")[:200],
            "resolved_queries": queries[:5],
            "reason": expand_reason,
        }
    )
    _log_news_search_query_built(
        raw_text,
        merged_entities,
        horizon,
        queries,
        raw_query=raw_query,
    )

    slots["query"] = resolved_topic or raw_query
    slots["entities"] = merged_entities
    slots["time_horizon"] = horizon
    slots["search_queries"] = queries
    return slots


def _log_news_route_decision(
    user_text: str,
    action: str,
    reason: str,
    current_or_recent_detected: bool,
    source_request_detected: bool,
    entities: list[str],
    time_horizon: str,
    intent_classification: dict | None = None,
    vague_followup: dict | None = None,
    history: list[dict] | None = None,
    active_side_panel: str = "",
) -> None:
    try:
        cls = intent_classification if isinstance(intent_classification, dict) else {}
        vf = vague_followup if isinstance(vague_followup, dict) else {}
        is_search = bool(cls.get("shouldSearchNews")) or action.startswith("news_")
        is_downgraded = (
            cls.get("personalNewsStatementDetected") or cls.get("emotionalContextDetected")
        ) and action in {"skip", "general"}
        final_route = (
            "emotional_support" if cls.get("emotionalContextDetected")
            else "general_llm" if cls.get("personalNewsStatementDetected")
            else "news_search" if action == "news_search"
            else "news_sources" if action == "news_sources"
            else "news_category_prompt" if action == "news_category_prompt"
            else "side_panel_followup" if vf.get("target") == "active_news_panel"
            else "general_chat" if action == "skip"
            else action or "general_chat"
        )
        suppressed_reason = ""
        if cls.get("personalNewsStatementDetected"):
            suppressed_reason = "personal/emotional statement, not information-seeking request"
        elif cls.get("emotionalContextDetected"):
            suppressed_reason = "emotional/distress context detected"
        elif reason == "current_or_recent_without_request_shape":
            suppressed_reason = "no information-seeking request shape (no imperative or question)"
        elif reason == "bare_news_keyword_no_request_shape":
            suppressed_reason = "bare keyword 'news' without request shape"
        elif vf.get("target") == "recent_chat_context" and vf.get("isVague"):
            suppressed_reason = vf.get("reason") or "vague_followup_recent_chat_context"
        recent_excerpt = ""
        if isinstance(history, list) and history:
            for turn in reversed(history[-4:]):
                if isinstance(turn, dict) and turn.get("role") == "user":
                    recent_excerpt = str(turn.get("content") or "")[:160]
                    if recent_excerpt:
                        break
        print(
            "[news_route_decision] " + json.dumps(
                {
                    "latest_user_text": (user_text or "")[:200],
                    "user_text": (user_text or "")[:200],
                    "action": action,
                    "reason": reason,
                    "current_or_recent_detected": bool(current_or_recent_detected),
                    "source_request_detected": bool(source_request_detected),
                    "entities": entities[:8],
                    "time_horizon": time_horizon,
                    "raw_keyword_news_detected": bool(cls.get("rawKeywordNewsDetected")),
                    "raw_news_keyword_detected": bool(cls.get("rawKeywordNewsDetected")),
                    "request_shape_detected": bool(cls.get("requestShapeDetected")),
                    "personal_news_statement_detected": bool(cls.get("personalNewsStatementDetected")),
                    "emotional_context_detected": bool(cls.get("emotionalContextDetected")),
                    "emotional_category": (
                        "grief" if cls.get("emotionalContextDetected")
                        and re.search(r"\b(passed\s+away|died|funeral|memorial|wake|burial|cremation|obituary|grieving|mourning)\b", user_text or "", re.IGNORECASE)
                        else "distress" if cls.get("emotionalContextDetected")
                        else "personal_bad_news" if cls.get("personalNewsStatementDetected")
                        else "none"
                    ),
                    "emotional_confidence": float(cls.get("confidence") or 0.0) if (cls.get("emotionalContextDetected") or cls.get("personalNewsStatementDetected")) else 0.0,
                    "search_intent_detected": is_search,
                    "search_confidence": float(cls.get("confidence") or 0.0),
                    "search_suppressed": bool(is_downgraded or suppressed_reason),
                    "search_suppressed_reason": suppressed_reason,
                    "news_search_intent": is_search,
                    "news_search_confidence": float(cls.get("confidence") or 0.0),
                    "news_search_suppressed_reason": suppressed_reason,
                    "intent_type": cls.get("intentType") or "unknown",
                    "side_panel_opened": is_search,
                    "active_side_panel": vf.get("activeSidePanel") or active_side_panel or "",
                    "active_side_panel_allowed_as_context": bool(vf.get("activeSidePanelAllowedAsContext", True)) if vf else True,
                    "vague_followup_detected": bool(vf.get("isVague")),
                    "vague_followup_target": vf.get("target") or "",
                    "recent_chat_context_excerpt": recent_excerpt,
                    "final_route": final_route,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _log_news_context_saved(ctx: dict | None) -> None:
    if not isinstance(ctx, dict):
        return
    try:
        print(
            "[news_context_saved] " + json.dumps(
                {
                    "topic": ctx.get("topic"),
                    "entities": (ctx.get("entities") or [])[:8],
                    "timeframe": ctx.get("timeframe"),
                    "result_titles": (ctx.get("result_titles") or [])[:6],
                    "result_sources": (ctx.get("result_sources") or [])[:6],
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _log_news_followup_resolution(row: dict) -> None:
    try:
        print("[news_followup_resolution] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


_NEWS_SOURCE_REQUEST_PATTERNS = (
    # explicit "show me / give me / share / cite sources"
    r"\b(?:show|give|share|send)\s+(?:me\s+)?(?:the\s+|any\s+|some\s+)?sources?\b",
    r"\b(?:show|give|share|send)\s+(?:me\s+)?(?:the\s+|an?\s+|some\s+)?articles?\b",
    r"\b(?:show|give|share|send)\s+(?:me\s+)?(?:the\s+|a\s+|some\s+)?links?\b",
    r"\bcite (?:your |that|this|those|it|them)?\s*\w*\b",
    r"\bcan you cite (?:that|this|those|it|them|sources?)?\b",
    # "do you have a/any source(s)/link(s)/article(s)"
    r"\bdo you have (?:any |a |an |the |some )?sources?\b",
    r"\bdo you have (?:any |a |an |the |some )?links?\b",
    r"\bdo you have (?:any |an |a |the |some )?articles?\b",
    r"\bdo you have (?:any |the |some )?(?:proof|evidence|citations?|references?|receipts?)\b",
    # question forms
    r"\b(?:what|which) (?:are|were|is) (?:your |the )?sources?\b",
    r"\bwhat(?:'?s|\s+is)\s+(?:your |the )?source\b",
    r"\bwhat sources? did you (?:use|read|consult|check)\b",
    # "where" forms
    r"\bwhere (?:did|do) you (?:get|read|find|hear|see) (?:that|this|those|it|them)\b",
    r"\bwhere (?:is|are) (?:that|this|those|it|them) from\b",
    r"\bwhere(?:'?s| is) (?:that|this) from\b",
    r"\bfrom where\b",
    # one-word / very short forms
    r"^sources?\??\s*$",
    r"^links?\??\s*$",
    r"^citations?\??\s*$",
    r"^references?\??\s*$",
    r"^urls?\??\s*$",
    r"^articles?\??\s*$",
    r"\bany sources?\??\s*$",
    r"\bany links?\??\s*$",
    r"\bany articles?\??\s*$",
    # outlet-specific source asks
    r"\b(?:from|via|on|in)\s+(?:reuters|associated press|ap|new york times|nyt|cnn|bbc|bloomberg|axios|the verge|wsj|wall street journal|cnbc|fox|guardian|the guardian|washington post|wapo|npr|politico)\b",
)


def _match_source_request_pattern(text: str) -> str | None:
    raw = (text or "").strip().lower()
    if not raw:
        return None
    for p in _NEWS_SOURCE_REQUEST_PATTERNS:
        if re.search(p, raw):
            return p
    return None


def _is_news_source_request(text: str) -> bool:
    return _match_source_request_pattern(text) is not None


def _log_source_request_detection(
    user_text: str,
    matched_pattern: str | None,
    has_last_news_context: bool,
    fallback_topic_from_previous_turn: str,
    final_action: str,
) -> None:
    try:
        print(
            "[source_request_detection] " + json.dumps(
                {
                    "user_text": (user_text or "")[:200],
                    "source_request_detected": matched_pattern is not None,
                    "matched_pattern": matched_pattern or "",
                    "has_last_news_context": bool(has_last_news_context),
                    "fallback_topic_from_previous_turn": (fallback_topic_from_previous_turn or "")[:200],
                    "final_action": final_action or "",
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _build_sources_fallback_route(
    session_id: str | None,
    text: str,
    history: list[dict],
) -> dict | None:
    """Source request without stored news context: build a Serper route from the
    previous user message + previous assistant reply so we never answer with
    invented citations from the general LLM.
    """
    if not _is_news_source_request(text):
        return None
    if session_id and get_recent_news_context(session_id) is not None:
        # Stored-context path handles this; only build the fresh-search fallback when
        # there's no stored news context (i.e., previous turn was general LLM, not news).
        return None
    prev_assistant, prev_user = _last_assistant_and_previous_user_from_history(history or [])
    combined = (prev_user + " " + prev_assistant).strip()
    if not combined:
        return None
    # Entities ranked from BOTH the previous user question and the assistant reply;
    # the user's question is usually richer in proper nouns the user actually cares about.
    entities = _extract_news_entities(prev_user) + _extract_news_entities(prev_assistant)
    seen: set = set()
    deduped: list[str] = []
    for e in entities:
        key = e.lower()
        if key in seen:
            continue
        seen.add(key)
        deduped.append(e)
    entities = deduped[:6]
    topic_phrase = _normalize_news_topic_phrase(prev_user) if prev_user else ""
    if not entities and not topic_phrase:
        return None
    initial_slots = {
        "query": topic_phrase or " ".join(entities[:3]),
        "entities": entities,
        "time_horizon": _extract_news_time_horizon(prev_user or "") or "unspecified",
    }
    final_slots = _finalize_news_latest_slots(session_id, prev_user or text, initial_slots)
    # Bias queries toward citations: append a few source-flavored variants.
    queries = list(final_slots.get("search_queries") or [])
    if entities:
        extras = [
            " ".join(entities[:4]) + " sources",
            " ".join(entities[:4]) + " article",
            " ".join(entities[:4]) + " Reuters",
        ]
        for q in extras:
            if q not in queries:
                queries.append(q)
    elif topic_phrase:
        for q in [topic_phrase + " sources", topic_phrase + " article"]:
            if q not in queries:
                queries.append(q)
    final_slots["search_queries"] = queries[:5]
    return normalize_route(
        {
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": final_slots,
        }
    )


def try_resolve_news_sources_fallback(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
) -> tuple[dict | None, float]:
    route = _build_sources_fallback_route(session_id, text, history)
    if route is None:
        return None, 0.0
    return execute_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )


def try_resolve_news_sources_fallback_streaming(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
):
    route = _build_sources_fallback_route(session_id, text, history)
    if route is None:
        return None
    return prepare_streaming_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )


_NEWS_RECENT_TERMS = (
    r"\blatest\b", r"\bcurrent(?:ly)?\b", r"\brecent(?:ly)?\b",
    r"\btoday(?:'s)?\b", r"\btonight\b", r"\bthis (?:week|month|morning|afternoon|evening)\b",
    r"\bpast (?:week|month|24|two weeks|14 days|30 days)\b",
    r"\blast (?:week|month|24 hours|night)\b",
    r"\bwhat happened\b", r"\bwhat['’]?s going on\b", r"\bwhat is going on\b",
    r"\bheadlines?\b", r"\barticles?\b", r"\bnews\b", r"\bcoverage\b",
    r"\bbreaking\b", r"\bupdates?\b",
)
_NEWS_TOPIC_NOUNS = (
    r"\blawsuit(?:s)?\b", r"\btrip\b", r"\bvisit\b", r"\binterview\b",
    r"\bdeal\b", r"\bsigned\b", r"\bagreement\b", r"\bsanction(?:s)?\b",
    r"\bearnings\b", r"\bmarket(?:s)?\b", r"\bstock(?:s)?\b",
    r"\belection(?:s)?\b", r"\bpoll(?:s)?\b",
)
_NEWS_OUTLET_RE = re.compile(
    r"\b(?:reuters|associated press|ap|new york times|nyt|cnn|bbc|bloomberg|axios|"
    r"the verge|wsj|wall street journal|cnbc|fox|guardian)\b",
    re.IGNORECASE,
)


def _detect_current_or_recent(text: str) -> bool:
    low = (text or "").strip().lower()
    if not low:
        return False
    for pat in _NEWS_RECENT_TERMS:
        if re.search(pat, low):
            return True
    for pat in _NEWS_TOPIC_NOUNS:
        if re.search(pat, low):
            return True
    return False


# =========================================================================
# INTENT-BASED NEWS / SEARCH CLASSIFIER
#
# The heuristic above (`_detect_current_or_recent`) is a permissive keyword
# scan — it fires on the bare word "news". That used to be enough to wake
# the news-search route, which meant utterances like:
#
#     "Wait nvm I just saw the news my friend just passed away"
#
# were classified as news queries (Wait → entity, news → current term →
# news_search). The fix below adds intent-shape guards so the news route
# only fires when the user is ACTUALLY asking for headlines, not merely
# narrating a personal experience that contains the word "news".
#
# Order of precedence:
#   1. Personal-news statement   → suppress (general/emotional response)
#   2. Emotional / grief context → suppress (general/emotional response)
#   3. Explicit news/search request shape + news intent → news search
#   4. Bare keyword without request shape → suppress (general response)
# =========================================================================

_PERSONAL_NEWS_STATEMENT_RE = re.compile(
    r"\b("
    # "I/we (just/already) got/heard/saw/received/read/learned/wanted NEWS"
    r"(?:i|we)\s+(?:'?ve\s+|have\s+)?(?:just\s+|already\s+|recently\s+|finally\s+)?"
    r"(?:got|gotten|received|heard|saw|seen|read|learned|find\s+out|found\s+out|"
    r"figured\s+out|caught|hear|wanted|needed|wanted\s+some|needed\s+some)\s+"
    r"(?:some\s+|the\s+|any\s+|bad\s+|sad\s+|terrible\s+|good\s+|great\s+|big\s+|"
    r"awful\s+|devastating\s+|heartbreaking\s+|shocking\s+|crazy\s+|breaking\s+)?news"
    # "I've got news / I have news / I have some bad/breaking news (sharing direction)"
    r"|(?:i|we)\s+(?:'?ve\s+|have\s+|had\s+)(?:got\s+|gotten\s+)?"
    r"(?:some\s+|the\s+|any\s+|bad\s+|sad\s+|terrible\s+|good\s+|great\s+|big\s+|"
    r"awful\s+|devastating\s+|heartbreaking\s+|shocking\s+|crazy\s+|breaking\s+)?news\b"
    # "I have news for you / for us" — explicit sharing direction wins over
    # any other interpretation (e.g. "I have breaking news for you").
    r"|(?:i|we|someone|somebody)\s+(?:'?ve\s+|have\s+|has\s+|had\s+)(?:got\s+|gotten\s+)?"
    r"(?:some\s+|the\s+|any\s+|bad\s+|sad\s+|terrible\s+|good\s+|great\s+|big\s+|"
    r"awful\s+|devastating\s+|heartbreaking\s+|shocking\s+|crazy\s+|breaking\s+)?"
    r"news\s+for\s+(?:you|us|y'?all|everyone)\b"
    # "the news from my <relative>" / "news from my family"
    r"|(?:the\s+)?news\s+(?:from|about)\s+(?:my\s+|our\s+|his\s+|her\s+|their\s+|the\s+)"
    r"(?:mom|mum|mother|dad|father|family|friend|sister|brother|son|daughter|wife|"
    r"husband|partner|spouse|kid|kids|child|children|parents|grandma|grandpa|"
    r"grandmother|grandfather|aunt|uncle|cousin|neighbor|coworker|boss|boyfriend|girlfriend)\b"
    # "news my mom/dad/friend/family ..." (e.g. "news my friend passed away")
    r"|\bnews\s+(?:my|our|his|her|their)\s+"
    r"(?:mom|mum|mother|dad|father|family|friend|sister|brother|son|daughter|wife|"
    r"husband|partner|spouse|kid|kids|child|children|parents|grandma|grandpa|"
    r"grandmother|grandfather|aunt|uncle|cousin|neighbor|coworker|boss|boyfriend|girlfriend)\b"
    # "(it was|that was|this is|that's) ... news" — sentiment narration
    r"|(?:it\s+was|that\s+was|this\s+is|that's|it's)\s+"
    r"(?:such\s+|so\s+|really\s+|very\s+|kind\s+of\s+|sort\s+of\s+)?"
    r"(?:bad|sad|terrible|devastating|awful|heartbreaking|tragic|crushing|"
    r"shocking|hard|tough|rough|horrible|crazy|big)\s+news\b"
    # adjectival "bad/sad/terrible news" anywhere
    r"|\b(?:bad|sad|terrible|devastating|awful|heartbreaking|tragic|crushing|"
    r"shocking|hard|tough|rough|horrible|big|huge)\s+news\b"
    # narration: "I don't know how to feel about this/that/the news"
    r"|\b(?:don'?t|do\s+not)\s+know\s+how\s+to\s+feel\s+about\s+(?:this|that|the)\s+news\b"
    # narration: "the news has been (stressful|hard|sad|...)"
    r"|\b(?:the\s+)?news\s+(?:has|have)\s+been\s+(?:so\s+|really\s+|very\s+|kind\s+of\s+|sort\s+of\s+)?"
    r"(?:bad|sad|stressful|terrible|devastating|awful|heartbreaking|tragic|"
    r"shocking|hard|tough|rough|horrible|depressing|exhausting|overwhelming)\b"
    # narration: "this news made me ..." / "that news made me ..."
    r"|\b(?:this|that|the)\s+news\s+(?:made|makes|is\s+making)\s+(?:me|us|him|her|them)\b"
    # "someone/they/she/he/mom/dad/family/friend/doctor (just) told/texted/messaged/called me"
    r"|(?:someone|somebody|they|she|he|mom|mum|dad|family|friend|doctor|nurse|"
    r"teacher|wife|husband|partner)\s+(?:just\s+|recently\s+|finally\s+)?"
    r"(?:told|texted|messaged|called|notified|informed|wrote)\s+(?:me|us)\b"
    r")\b",
    re.IGNORECASE,
)


_EMOTIONAL_DISTRESS_RE = re.compile(
    r"\b("
    # death / passing away
    r"passed\s+(?:away|on)|passes\s+away|passing\s+(?:away|on)|pass\s+away"
    r"|(?:has|had|have|just|recently|suddenly|already)\s+died"
    r"|\b(?:died|dying|deceased|gone\s+forever)\b"
    r"|killed|murdered|suicide|took\s+(?:his|her|their)\s+(?:own\s+)?life"
    r"|overdose|overdosed"
    r"|funeral|memorial\s+service|wake\b|burial|cremation|obituary"
    # severe health crises
    r"|(?:in\s+the\s+|at\s+the\s+|to\s+the\s+|the\s+)?(?:hospital|emergency\s+room|ER|ICU|intensive\s+care)\b"
    r"|cancer\s+diagnos|terminal\s+(?:illness|cancer|condition)|chemotherapy|chemo\b"
    r"|stroke|heart\s+attack|heart\s+failure|aneurysm|sepsis"
    r"|miscarriage|miscarried|stillbirth|still\s*born|coma|brain[-\s]?dead|life\s+support"
    # accidents / harm
    r"|car\s+(?:crash|accident|wreck)|crashed\s+(?:his|her|their|the)\s+car"
    r"|\b(?:got\s+(?:in|into)\s+an\s+accident|in\s+an\s+accident|had\s+an\s+accident)\b"
    r"|(?:hit|struck)\s+by\s+a\s+(?:car|truck|driver|bus)"
    r"|attacked|assaulted|abused|hurt\s+(?:badly|seriously|in\s+a)"
    # mental-health crisis
    r"|self[-\s]?harm|hurting\s+(?:myself|themselves)|suicidal|kill(?:ing)?\s+myself"
    r"|wanting?\s+to\s+(?:die|end\s+it)"
    # explicit grief / shock verbs
    r"|grieving|grief\b|mourning|in\s+(?:total\s+)?shock|devastated|heartbroken"
    r"|broken\s+up\s+about|falling\s+apart|cant\s+stop\s+crying|can'?t\s+stop\s+crying"
    r"|cried\s+all\s+(?:day|night)"
    # additional generic emotional distress phrases — overwhelmed / numb /
    # "don't know how to feel". These signal a personal-emotional turn that
    # MUST never trigger a news search, even when accompanied by the word
    # "news" elsewhere in the message.
    r"|(?:i['’]?m|i\s+am|i\s+feel)\s+(?:so\s+|really\s+|completely\s+|totally\s+|just\s+)?(?:overwhelmed|numb|empty|hopeless|broken|lost|destroyed|crushed|shattered)\b"
    r"|(?:i\s+)?(?:don'?t|do\s+not)\s+know\s+how\s+to\s+feel\b"
    # generic "bad/sad/terrible/devastating news" — already in personal regex
    # but keep here so a message like "got terrible news" alone is enough.
    r"|(?:bad|sad|terrible|devastating|awful|heartbreaking|tragic|crushing|"
    r"shocking|horrible)\s+news"
    r")\b",
    re.IGNORECASE,
)


_NEWS_REQUEST_SHAPE_RE = re.compile(
    r"("
    # Imperative — assistant-directed verb asking for news/info
    r"\b(?:tell|show|give|find|search|look\s+up|pull\s+up|fetch|get|read|grab|"
    r"bring\s+up|open|display)\s+"
    r"(?:me\s+|us\s+)?"
    r"(?:the\s+|some\s+|any\s+|a\s+few\s+)?"
    r"(?:latest\s+|breaking\s+|recent\s+|top\s+|fresh\s+)?"
    r"(?:news|headlines?|articles?|updates?|coverage|stories?|story|results?)\b"
    # "search news/articles/web about X" / "search the news for X"
    r"|\bsearch\s+(?:the\s+)?(?:news|web|internet|google|articles?|stories?)\b"
    r"|\bsearch\s+for\s+(?:news|articles?|stories?|coverage|updates?)\b"
    # "what happened (today|yesterday|with X)" — info-seeking question
    r"|\bwhat\s+(?:just\s+)?happened\b"
    r"|\bwhat['’]?s\s+(?:happening|going\s+on)\b"
    r"|\bwhat\s+is\s+(?:happening|going\s+on)\b"
    # "what's the latest" / "what's the news" / "what's new" — info question
    r"|\bwhat(?:['’]?s|s|\s+is)\s+(?:the\s+)?(?:latest|news|headlines?|updates?|story|word|scoop)\b"
    r"|\bwhat(?:['’]?s|s|\s+is)\s+new\b"
    # "any updates / any news / any headlines on X"
    r"|\bany\s+(?:updates?|news|headlines?|new\s+(?:info|developments?))\b"
    # "is there (any) news about X" / "is there an update on X"
    r"|\bis\s+there\s+(?:any\s+|some\s+)?(?:news|updates?|coverage|headlines?|developments?)\s+(?:about|on|regarding|for)\b"
    # "do you have (any) news on X"
    r"|\bdo\s+you\s+have\s+(?:any\s+)?(?:news|updates?|headlines?|coverage)\b"
    # "what are the headlines"
    r"|\bwhat\s+are\s+(?:the\s+)?(?:headlines?|top\s+stories|latest\s+stories|breaking\s+stories)\b"
    # "open the news panel" / "show news panel"
    r"|\b(?:open|show|bring\s+up|pull\s+up|launch|display)\s+(?:the\s+)?news"
    r"(?:\s+(?:panel|results?|tab|page|view|app))?\b"
    # category-specific imperative: "give me tech news", "show me sports news"
    r"|\b(?:tech|technology|world|sports|business|finance|us|u\.s\.|political|politics|"
    r"local|breaking|science|health|entertainment|gaming|crypto|ai)\s+news\b"
    # "look up the latest on X"
    r"|\blook(?:\s+up|\s+into)?\s+(?:the\s+)?(?:latest|news|update|story|coverage)\b"
    # "find articles about X"
    r"|\bfind\s+(?:me\s+)?(?:articles?|stories?|coverage|news)\b"
    r")",
    re.IGNORECASE,
)


def _is_personal_news_statement(text: str) -> bool:
    """True when the user is sharing/narrating personal news (e.g. 'I just
    saw the news my friend passed away', 'I got bad news', 'the news from
    my family is bad') rather than asking for headlines."""
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_PERSONAL_NEWS_STATEMENT_RE.search(raw))


def _is_emotional_distress_statement(text: str) -> bool:
    """True when the user is expressing grief, distress, or describing a
    death / serious illness / accident / mental-health crisis. These turns
    must NEVER trigger news search even if they contain the word 'news'."""
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_EMOTIONAL_DISTRESS_RE.search(raw))


def _has_news_request_shape(text: str) -> bool:
    """True when the message has explicit request shape for news/web/search
    info — imperative verb aimed at the assistant or an info-seeking
    question. Required for the keyword-based news route to fire.

    Also returns True when the message is a current-fact verification
    question (e.g. "Did Trump go to China last week?"). Those are
    info-seeking questions about recent public events even though they
    don't use words like "news" or "search" — see _is_current_fact_question
    for the gating logic.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    if _NEWS_REQUEST_SHAPE_RE.search(raw):
        return True
    if _is_current_fact_question(raw):
        return True
    return False


# =========================================================================
# CURRENT-FACT QUESTION DETECTION
#
# Yes/no question shapes about recent or current public events. These
# previously fell through to general_chat because the legacy
# `_NEWS_REQUEST_SHAPE_RE` only caught imperatives ("tell me ...") and
# explicit "what's happening" / "any updates" question shapes. Asking a
# verification question like:
#
#     "Did Trump go to China last week?"
#     "Was the LA fire contained?"
#     "Is the highway still closed?"
#     "Did Elon Musk win the case against OpenAI?"
#
# is just as much a news/search request as "any updates on X", but the
# regex didn't recognize it. The bug surfaced as:
#     final_route = general_chat
#     answer = "I don't have confirmation that he went to China last week."
# Spec PART 5 calls this exact failure out: do not let general chat
# answer current fact checks without search.
#
# Detection signals (must combine):
#   1. Question shape:
#        - did / does / do / is / are / was / were / has / have / had
#          + (subject) + verb / state
#        - "what happened" / "what is happening with ..."
#        - "is it confirmed" / "was it confirmed" / "is X verified"
#        - "is X still ..." / "has X happened"
#   2. Public entity or public-event domain noun:
#        - Capitalized proper noun OR a recognized topic noun
#          (case, trip, visit, election, fire, lawsuit, closure, ...)
#   3. Recent / current time marker OR the question itself implies
#      currency:
#        - "today", "yesterday", "last week", "recently", "still",
#          "now", "currently", "confirmed", "this week", "this month",
#          "right now", "as of now"
#
# Helper is gated so we do NOT fire on benign personal questions like:
#   - "Did you sleep well?"  (entity = "you", which is a stopword)
#   - "Is dinner ready?"     (no entity, no temporal marker)
#   - "Did I send the email?" (entity = pronoun, stopword)
# =========================================================================

_NEWS_CURRENT_FACT_QUESTION_LEAD_RE = re.compile(
    r"^(?:hey\s+vera[, ]+)?(?:wait[, ]+)?"
    # Yes/no auxiliaries:  did / does / do / is / are / was / were /
    # has / have / had / will / can / could / should / would
    r"(?:did|does|do|is|are|was|were|has|have|had|will|can|could|should|would)\b"
    # OR explicit "what happened" / "what's happening with X" / verification asks
    r"|^(?:what(?:'?s|s|\s+is)?\s+(?:just\s+)?happen(?:ed|ing)?)\b"
    r"|^(?:is|was)\s+(?:it|that|this|the\s+\w+|\w+)\s+(?:confirmed|verified|true|real|finalized|resolved|over|settled)\b"
    r"|\bis\s+(?:it|that|this|\w+)\s+confirmed\b"
    r"|\bwas\s+(?:it|that|this|\w+)\s+confirmed\b"
    # Bare "what happened with X" anywhere in the sentence
    r"|\bwhat\s+(?:just\s+)?happened\s+(?:with|to|in|at|on)\b"
    r"|\bwhat['’]?s\s+happening\s+(?:with|to|in|at|on)\b",
    re.IGNORECASE,
)

# Domain nouns that signal "this is about a public event/topic", so a
# yes/no question + this noun counts as a current-fact question even
# without a strong proper-noun entity (e.g. "Is the highway still closed?"
# — "highway" is the public subject, "still" is the temporal marker).
_NEWS_PUBLIC_DOMAIN_NOUN_RE = re.compile(
    r"\b(?:"
    # Civic / political
    r"case|trial|lawsuit|verdict|ruling|court|judge|jury|charges?|indictment|"
    r"election|primary|primaries|debate|vote|ballot|recount|impeachment|"
    r"resignation|investigation|hearing|subpoena|tariffs?|sanctions?|treaty|"
    r"agreement|deal|signed|negotiation|talks|summit|meeting|policy|bill|"
    r"law|legislation|regulation|order|veto|"
    # Travel / diplomatic
    r"trip|visit|tour|state\s+visit|"
    # Conflict / disaster
    r"war|conflict|invasion|ceasefire|attack|shooting|protest|riot|strike|"
    r"fire|wildfire|hurricane|storm|tornado|earthquake|tsunami|flood|"
    r"outbreak|pandemic|epidemic|crisis|"
    # Public infrastructure
    r"highway|freeway|interstate|bridge|tunnel|border|airport|port|station|"
    r"school|university|hospital|stadium|"
    # Business / market
    r"merger|acquisition|launch|announcement|earnings|ipo|bankruptcy|"
    # Sports
    r"tournament|championship|finals|game|match|series|playoff|"
    # Public actions
    r"closure|reopening|opening|shutdown|recall|"
    # Public people roles (when used as nouns, not titles)
    r"president|senator|governor|mayor|ceo|judge"
    r")\b",
    re.IGNORECASE,
)

# Recent / current time markers + recency-implying state words. Broader
# than `_NEWS_RECENT_TERMS` (which also includes "news" itself — we don't
# want THAT to count as a temporal marker here).
_NEWS_CURRENT_TIME_MARKER_RE = re.compile(
    r"\b(?:"
    r"today|tonight|yesterday|right\s+now|now|currently|recently|just\s+now|"
    r"earlier(?:\s+today)?|last\s+(?:week|month|year|night|hour|day)|"
    r"this\s+(?:week|month|year|morning|afternoon|evening|hour)|"
    r"past\s+(?:week|month|year|24|few\s+days|two\s+weeks|14\s+days|30\s+days)|"
    r"latest|newest|most\s+recent|breaking|just\s+(?:happened|in|broke|announced|released|signed)|"
    r"still|already|finally|new|"
    r"confirmed|verified|finalized|resolved|over|settled|contained|"
    r"announce(?:s|d|ment)?|releas(?:e|es|ed)|launch(?:es|ed)?|"
    r"unveil(?:s|ed)?|reveal(?:s|ed)?|debut(?:s|ed)?|drop(?:s|ped)?|"
    r"won|lost|happen(?:s|ed|ing)?|sign(?:s|ed)?|"
    r"acquir(?:e|es|ed)|merg(?:e|es|ed)|sue(?:s|d)?|"
    r"file(?:s|d)?|settle(?:s|d)?|reach(?:es|ed)?|reopen(?:s|ed)?|"
    r"fire(?:s|d)?|hire(?:s|d)?|quit|resign(?:s|ed)?|"
    r"as\s+of\s+(?:now|today|yesterday|this\s+week)"
    r")\b",
    re.IGNORECASE,
)


def _has_current_fact_question_lead(text: str) -> bool:
    """Returns True when the message opens with (or contains) one of the
    yes/no / "what happened" question shapes used for fact verification."""
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_NEWS_CURRENT_FACT_QUESTION_LEAD_RE.search(raw))


def _has_public_domain_noun(text: str) -> bool:
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_NEWS_PUBLIC_DOMAIN_NOUN_RE.search(raw))


def _has_recent_time_marker(text: str) -> bool:
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_NEWS_CURRENT_TIME_MARKER_RE.search(raw))


# ---------------------------------------------------------------------------
# PART 2 (2026-05-28): historical / educational / explanatory question gate.
#
# Routes "Can you explain the Vietnam War?", "What caused the Cold War?",
# "Tell me about Napoleon", "Who founded OpenAI?", etc. to general LLM,
# NOT to news search. The presence of famous people, wars, countries, or
# political nouns alone must never trigger news routing — the predicate
# has to be contemporary/change-shaped (announced/won/sued/released/...).
#
# These patterns are intentionally specific: a verb of explanation/teaching
# (`explain`, `tell me about`, `describe`, `summarize`, `what is`, `what
# was`, `who was`, `why did X happen` for historical events) combined with
# either a historical-period noun (war, empire, dynasty, revolution,
# century, era, ancient, medieval) or an open-ended educational lead.
# ---------------------------------------------------------------------------

# Explanatory / pedagogical verbs that strongly indicate the user wants a
# background explanation, not breaking news.
_HIST_EDU_LEAD_RE = re.compile(
    r"^\s*(?:can\s+you\s+|could\s+you\s+|would\s+you\s+|please\s+)?"
    r"(?:"
    r"explain|describe|summari[sz]e|teach\s+me\s+about|"
    r"tell\s+me\s+(?:about|the\s+history\s+of|more\s+about)|"
    r"give\s+me\s+(?:a\s+)?(?:summary|overview|background|brief|primer|"
    r"explanation|history)\s+of|"
    r"walk\s+me\s+through|"
    r"what\s+(?:is|was|were|are)\s+(?:the\s+)?|"
    r"who\s+(?:is|was|were|are)\s+(?:the\s+)?|"
    r"how\s+(?:did|does|do)\s+(?:the\s+)?|"
    r"why\s+(?:did|does|do)\s+(?:the\s+)?"
    r")",
    re.IGNORECASE,
)

# Historical-period / educational-domain nouns. A pure history noun in
# isolation flips the route to historical/educational even when paired
# with a contemporary-looking question word. ("Why did the Soviet Union
# collapse?" is history, not news.)
_HIST_EDU_TOPIC_NOUN_RE = re.compile(
    r"\b(?:"
    # Wars / conflicts (with optional WW prefix)
    r"vietnam\s+war|world\s+war\s+(?:i|ii|one|two|1|2)|world\s+wars?|"
    r"cold\s+war|korean\s+war|civil\s+war|gulf\s+war|iraq\s+war|"
    r"afghanistan\s+war|napoleonic\s+wars?|crimean\s+war|"
    r"hundred\s+years[\u2019']?\s+war|thirty\s+years[\u2019']?\s+war|"
    r"french\s+(?:and\s+indian\s+)?revolution|american\s+revolution|"
    r"russian\s+revolution|industrial\s+revolution|"
    # Empires / dynasties / civilizations
    r"roman\s+empire|byzantine\s+empire|ottoman\s+empire|british\s+empire|"
    r"holy\s+roman\s+empire|persian\s+empire|mongol\s+empire|"
    r"ming\s+dynasty|qing\s+dynasty|han\s+dynasty|tang\s+dynasty|"
    r"han|qing|ming|tang|"
    r"ancient\s+(?:rome|greece|egypt|china|persia|mesopotamia|india)|"
    r"medieval\s+(?:europe|england|france|japan|china)|"
    r"renaissance|enlightenment|reformation|"
    # Eras / time-period nouns
    r"middle\s+ages|dark\s+ages|stone\s+age|bronze\s+age|iron\s+age|"
    r"victorian\s+era|edwardian\s+era|elizabethan\s+era|"
    r"\d{2,4}s?\s+century|\d{2,4}th\s+century|"
    # Historic events / movements (well past current-events window)
    r"holocaust|cuban\s+missile\s+crisis|berlin\s+wall|"
    r"soviet\s+union(?!\s+today)|ussr|"
    r"french\s+revolution|bolshevik\s+revolution|"
    r"manhattan\s+project|cold\s+war|"
    r"slavery|abolition|civil\s+rights\s+movement|"
    # Historical figures whose actions are inherently past
    r"napoleon|julius\s+caesar|alexander\s+the\s+great|"
    r"genghis\s+khan|cleopatra|"
    # Pure educational nouns
    r"theorem|equation|formula|definition|concept|paradigm|"
    r"theory\s+of\s+(?:relativity|evolution|gravity)|"
    r"big\s+bang|black\s+hole|photosynthesis|mitosis|dna|"
    r"shakespeare|odyssey|iliad|"
    r"physics|chemistry|biology|calculus|algebra|geometry|"
    r"linguistics|philosophy|psychology|sociology"
    r")\b",
    re.IGNORECASE,
)

# Predicates that DO indicate a contemporary/news-shaped question even
# when paired with a historical topic noun. Example overrides:
#   "Latest news about the Vietnam War documentary" (contemporary doc)
#   "Did Netflix release a Cold War series?"
#   "Today's news about Civil War reenactment"
# When ANY of these signals fire, the historical-topic-noun veto is
# inhibited and routing falls through to the normal news/current-fact
# classifier.
_HIST_EDU_NEWS_OVERRIDE_RE = re.compile(
    r"\b(?:"
    r"news|headlines?|breaking|today|yesterday|last\s+week|"
    r"recently|currently|right\s+now|just\s+(?:released|announced|launched)|"
    r"latest\s+(?:on|about|update|news)|new\s+(?:episode|season|series|"
    r"documentary|movie|film|book|trailer|game)|"
    r"upcoming|premiere|release\s+date|"
    r"announce(?:s|d|ment)|launch(?:es|ed)?|debut(?:s|ed)?"
    r")\b",
    re.IGNORECASE,
)


def _is_historical_or_educational_question(text: str) -> bool:
    """PART 2 — return True for historical/educational/explanatory queries
    that must route to general LLM, NOT news search.

    Decision logic:
      1. Hist-edu topic noun + no news/current override → True.
      2. Hist-edu lead verb ("explain", "tell me about", "what was") +
         optional hist-edu topic noun + no current/news override → True.
      3. Otherwise → False (let downstream classifier decide).

    Examples (True):
        "Can you explain the Vietnam War?"
        "What caused the Vietnam War?"
        "Who won World War II?"
        "Tell me about Napoleon."
        "Explain the French Revolution."
        "What is the Roman Empire?"
        "Why did the Soviet Union collapse?"

    Examples (False — fall through):
        "Latest news about the Vietnam War documentary"
        "Did Netflix release a Cold War series?"
        "Did Donald Trump go to China last week?"
        "What time is it in Tokyo?"
        "Was Elon Musk part of the OpenAI team?" (no hist-edu noun)
    """
    raw = (text or "").strip()
    if not raw:
        return False
    # If the message explicitly asks for news / latest / today / breaking
    # coverage of a historical-sounding topic, that's a legitimate news
    # query (e.g. "Latest news about the Vietnam War documentary"). Let
    # the downstream news classifier handle it.
    if _HIST_EDU_NEWS_OVERRIDE_RE.search(raw):
        return False
    has_hist_noun = bool(_HIST_EDU_TOPIC_NOUN_RE.search(raw))
    if has_hist_noun:
        return True
    # The lead verb alone ("why did he do that?", "can you explain?")
    # is intentionally NOT enough to flip the route to historical — those
    # are usually interpretive follow-ups over stored news context. We
    # require a historical/educational TOPIC NOUN to be safe. This keeps
    # "What is OpenAI?", "Why did the senator resign?", "Can you explain
    # the Trump tariffs?", and other contemporary lead-shaped questions
    # routing through the normal news/follow-up classifier instead.
    return False


def score_current_fact_question(text: str) -> dict:
    """Return a structured score for the current-fact-question detector
    so logs (PART 7) can show exactly which signals fired.

    Score is computed from the three required signals:
      * question_shape_detected (yes/no question lead OR "what happened")
      * public_entity_detected  (proper noun OR public-domain noun)
      * recent_time_marker_detected (time/state marker that implies recency)

    A "current fact question" requires:
        question_shape AND (public_entity OR public_domain_noun) AND
        (recent_time_marker OR public_domain_noun)

    The (public_domain_noun OR recent_time_marker) gate means:
      - "Did Trump go to China last week?" — entity + temporal → fires
      - "Is the highway still closed?"      — domain noun + "still" → fires
      - "Did the senator resign?"           — domain noun + verb of public
        action; counts via domain_noun on the temporal slot too
      - "Did you sleep well?"               — no entity, no domain noun → no fire
      - "Is dinner ready?"                  — no entity, no domain noun → no fire
    """
    raw = (text or "").strip()
    out = {
        "question_shape_detected": False,
        "public_entity_detected": False,
        "public_domain_noun_detected": False,
        "recent_time_marker_detected": False,
        "current_fact_question_score": 0.0,
        "matches": True,
    }
    if not raw:
        out["matches"] = False
        return out
    out["question_shape_detected"] = _has_current_fact_question_lead(raw)
    out["public_entity_detected"] = _has_named_entity_hint(raw)
    out["public_domain_noun_detected"] = _has_public_domain_noun(raw)
    out["recent_time_marker_detected"] = _has_recent_time_marker(raw)

    if not out["question_shape_detected"]:
        out["matches"] = False
    if not (out["public_entity_detected"] or out["public_domain_noun_detected"]):
        out["matches"] = False
    if not (out["recent_time_marker_detected"] or out["public_domain_noun_detected"]):
        out["matches"] = False

    # Score 0.0–1.0 (rough confidence): question + entity + temporal = 1.0;
    # missing entity OR temporal lowers it.
    parts = [
        1.0 if out["question_shape_detected"] else 0.0,
        1.0 if out["public_entity_detected"] else (0.5 if out["public_domain_noun_detected"] else 0.0),
        1.0 if out["recent_time_marker_detected"] else (0.5 if out["public_domain_noun_detected"] else 0.0),
    ]
    out["current_fact_question_score"] = round(sum(parts) / 3.0, 3) if out["matches"] else 0.0
    return out


def _is_current_fact_question(text: str) -> bool:
    """Single-bit version of score_current_fact_question for callers that
    don't need the breakdown. Used by `_has_news_request_shape`,
    `classify_news_search_intent`, and the polish-layer router guard."""
    raw = (text or "").strip()
    if not raw:
        return False
    # Hard suppressors: personal/emotional context wins, since "Did my mom
    # call?" or "Is my dad still in the hospital?" must NOT trigger a news
    # search even though they match the regex shape.
    if _is_personal_news_statement(raw) or _is_emotional_distress_statement(raw):
        return False
    return bool(score_current_fact_question(raw)["matches"])


def log_current_fact_question_decision(session_id: str, text: str, score: dict, *,
                                       routed_to: str | None = None,
                                       serper_called: bool | None = None,
                                       reason: str = "") -> None:
    """Structured log for PART 7. One line per turn that goes through the
    current-fact-question gate, so grep '[news_current_fact_decision]' shows
    the full classifier breakdown + final routing decision."""
    try:
        print(
            "[news_current_fact_decision] "
            + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "latest_user_text": (text or "")[:200],
                    "question_shape_detected": bool(score.get("question_shape_detected")),
                    "public_entity_detected": bool(score.get("public_entity_detected")),
                    "public_domain_noun_detected": bool(score.get("public_domain_noun_detected")),
                    "recent_time_marker_detected": bool(score.get("recent_time_marker_detected")),
                    "current_fact_question_score": float(score.get("current_fact_question_score") or 0.0),
                    "matches": bool(score.get("matches")),
                    "routed_to": routed_to or "",
                    "serper_called": bool(serper_called) if serper_called is not None else None,
                    "reason": reason or "",
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


# Vague follow-up phrases that depend on context to be meaningful.
# Examples: "I don't know how to feel about this", "what should I do",
# "I'm not sure", "this", "that", "it", "about this", "how should I feel".
# These must NOT default to the active news/search panel when the recent
# conversation is personal/emotional — that's the bug described in the spec.
_VAGUE_FOLLOWUP_PHRASE_RE = re.compile(
    r"^\s*(?:i\s+)?(?:'?m\s+|am\s+)?not\s+sure\b"
    r"|^\s*(?:i\s+)?(?:don'?t|do\s+not)\s+know\s+(?:what|how|why)\b"
    r"|^\s*(?:i\s+)?(?:don'?t|do\s+not)\s+know\s+what\s+to\s+(?:think|do|feel|say)\b"
    r"|\bhow\s+(?:should|do)\s+i\s+(?:feel|react|respond|handle\s+this)\b"
    r"|\bwhat\s+should\s+i\s+(?:do|say|feel|think)\b"
    r"|\bwhat\s+do\s+(?:i|you)\s+(?:do|say|think)\b"
    r"|\bcan\s+you\s+explain\b\s*(?:this|that|it)?\s*$"
    r"|\bwhy\s+do\s+i\s+feel\s+(?:like\s+)?this\b"
    r"|\bwhat\s+now\b\s*\??$"
    r"|\bwhat\s+do\s+i\s+do\s+now\b"
    r"|\babout\s+(?:this|that|it)\b\s*\??$"
    r"|^\s*(?:this|that|it)\b\s*\??$"
    r"|^\s*(?:huh|hmm+|idk|i\s+don'?t\s+know)\s*\??$"
    r"|\bi'?m\s+(?:so\s+)?(?:lost|confused|overwhelmed|stuck)\b",
    re.IGNORECASE,
)


def _is_vague_followup_phrase(text: str) -> bool:
    """True when the message is a vague follow-up like 'about this',
    'what should I do', 'how should I feel', 'I'm not sure'. These must
    resolve against recent CHAT context, not against an active side panel,
    when the recent chat is personal/emotional."""
    raw = (text or "").strip()
    if not raw:
        return False
    if _VAGUE_FOLLOWUP_PHRASE_RE.search(raw):
        return True
    # Also flag very short messages that contain only deictic pronouns/about
    # phrases — these are inherently vague.
    if len(raw.split()) <= 8 and bool(_NEWS_DEICTIC_RE.search(raw.lower())):
        return True
    return False


def _recent_chat_has_personal_emotional_context(history: list[dict] | None) -> dict:
    """Scan the last few user/assistant turns for personal-news / emotional
    distress signals. Returns a small dict with the strongest match so the
    caller can decide whether vague follow-ups should ignore an active news
    panel and route to the general LLM."""
    out = {
        "detected": False,
        "category": "none",
        "matched_text": "",
        "matched_role": "",
        "matched_turn_age": -1,
    }
    if not isinstance(history, list) or not history:
        return out
    # Walk the last 6 turns from the most recent backwards.
    for age, turn in enumerate(reversed(history[-8:])):
        if not isinstance(turn, dict):
            continue
        role = str(turn.get("role") or "").lower()
        content = str(turn.get("content") or "").strip()
        if not content:
            continue
        # Only consider user-spoken turns for personal/emotional context.
        # Assistant turns may quote news headlines etc. and would create
        # false positives.
        if role != "user":
            continue
        if _is_emotional_distress_statement(content):
            out["detected"] = True
            out["category"] = "grief" if re.search(
                r"\b(passed\s+away|died|dying|deceased|funeral|memorial|wake|burial|cremation|obituary|grieving|mourning)\b",
                content, re.IGNORECASE,
            ) else "distress"
            out["matched_text"] = content[:200]
            out["matched_role"] = role
            out["matched_turn_age"] = age
            return out
        if _is_personal_news_statement(content):
            out["detected"] = True
            out["category"] = "personal_bad_news"
            out["matched_text"] = content[:200]
            out["matched_role"] = role
            out["matched_turn_age"] = age
            return out
    return out


def resolve_vague_followup_target(
    text: str,
    *,
    recent_news_context: dict | None = None,
    history: list[dict] | None = None,
    active_side_panel: str = "",
) -> dict:
    """Spec-shape resolver for vague follow-ups. Returns:
        {
          target: 'recent_chat_context' | 'active_news_panel' |
                  'active_reasoning_panel' | 'unknown',
          confidence: float,
          reason: str,
          isVague: bool,
          activeSidePanel: str,
          activeSidePanelAllowedAsContext: bool,
        }

    Decision order:
      1. Recent chat has personal/emotional context → recent_chat_context.
         (The active news panel is NOT allowed as context here — see spec
         Part 5: emotional follow-ups must NOT inherit a stale news result.)
      2. Vague phrase + active news panel that the user EXPLICITLY references
         (e.g. 'summarize the first result') → active_news_panel.
      3. Default: recent_chat_context.
    """
    is_vague = _is_vague_followup_phrase(text)
    personal_recent = _recent_chat_has_personal_emotional_context(history)
    has_news_panel = bool(recent_news_context) or active_side_panel == "news"
    # Explicit side-panel references — user is clearly asking about a result
    # card, an article, an image, etc. These keep the active news panel as
    # the legitimate target.
    explicit_side_panel = bool(
        re.search(
            r"\b(?:summarize|summarise|open|read|show|tell\s+me\s+about)\s+"
            r"(?:the\s+)?(?:first|second|third|fourth|fifth|next|previous|"
            r"\d+(?:st|nd|rd|th)?|that|this)\s+"
            r"(?:result|article|story|headline|news|news\s+result|card|item)\b",
            text or "",
            re.IGNORECASE,
        )
        or re.search(
            r"\b(?:search|show)\s+more\s+(?:results?|news|articles?|stories?)\b",
            text or "",
            re.IGNORECASE,
        )
        or re.search(
            r"\bwhat\s+(?:does|did)\s+(?:the\s+)?(?:result|article|story|headline|news\s+result)\s+say\b",
            text or "",
            re.IGNORECASE,
        )
        or re.search(
            r"\bwhat\s+about\s+result\s+\d+\b",
            text or "",
            re.IGNORECASE,
        )
    )
    if explicit_side_panel and has_news_panel:
        return {
            "target": "active_news_panel",
            "confidence": 0.95,
            "reason": "explicit_side_panel_reference",
            "isVague": is_vague,
            "activeSidePanel": active_side_panel or ("news" if recent_news_context else ""),
            "activeSidePanelAllowedAsContext": True,
        }
    if personal_recent["detected"]:
        return {
            "target": "recent_chat_context",
            "confidence": 0.95,
            "reason": f"recent_chat_personal_emotional:{personal_recent['category']}",
            "isVague": is_vague,
            "activeSidePanel": active_side_panel or ("news" if recent_news_context else ""),
            "activeSidePanelAllowedAsContext": False,
            "matchedRecentText": personal_recent["matched_text"],
            "matchedTurnAge": personal_recent["matched_turn_age"],
        }
    if is_vague and has_news_panel:
        return {
            "target": "active_news_panel",
            "confidence": 0.6,
            "reason": "vague_followup_with_news_panel_no_personal_context",
            "isVague": True,
            "activeSidePanel": active_side_panel or "news",
            "activeSidePanelAllowedAsContext": True,
        }
    return {
        "target": "recent_chat_context",
        "confidence": 0.5,
        "reason": "default_recent_chat",
        "isVague": is_vague,
        "activeSidePanel": active_side_panel or ("news" if recent_news_context else ""),
        "activeSidePanelAllowedAsContext": False,
    }


# =========================================================================
# NEWS REQUEST TYPE CLASSIFIER + FOLLOW-UP RESOLVER
#
# Centralized classification used by the news routing layer and the spec
# logging surface. Distinguishes:
#
#   ui_open_news_panel              "open the news panel"
#   ui_close_news_panel             "close news"
#   broad_news_request              "tell me the news", "today's headlines"
#   specific_current_event_question "did Trump go to China last week?"
#   personal_news_statement         "I got bad news"
#   emotional_context               "my friend just died"
#   general_chat                    everything else
#
# Specific current-event questions are routed LLM-first with Serper-grounded
# sources rather than raw headline summaries — that's the user spec's PART 3.
# =========================================================================

# Words to ignore when probing for "is there a specific named entity here?".
# These can appear capitalized at the start of a sentence ("Why was he there?")
# or as common short capitalizations but never represent the kind of subject
# that makes a question 'specific'.
_NAMED_ENTITY_STOPWORDS = {
    "Why", "What", "When", "Where", "Who", "How", "Did", "Does", "Do", "Is",
    "Are", "Was", "Were", "Has", "Have", "Had", "Will", "Would", "Can",
    "Could", "Should", "May", "Might", "Tell", "Show", "Give", "Find",
    "Search", "I", "We", "You", "He", "She", "They", "It", "Hey", "Yo",
    "OK", "Ok", "Yes", "No", "The", "A", "An", "And", "Or", "But", "So",
    "If", "Wait", "Just", "Vera", "BMO",
}


def _has_named_entity_hint(text: str) -> bool:
    """Returns True when the text contains at least one capitalized token
    that looks like a real proper noun (not a sentence-leading wh-word or
    pronoun). Used as a cheap 'is there a specific subject?' probe for the
    request-type classifier."""
    raw = (text or "").strip()
    if not raw:
        return False
    # Multi-word capitalized names ("Elon Musk", "Orange County", "LA fire")
    if re.search(r"\b[A-Z][a-zA-Z]+\s+[A-Z][a-zA-Z]+\b", raw):
        return True
    # All-caps acronyms 2-5 chars (LA, NYC, NPR, NASA, OpenAI excluded since
    # it's mixed case — handled elsewhere). Avoid the leading "I".
    for m in re.finditer(r"\b([A-Z]{2,5})\b", raw):
        token = m.group(1)
        if token in _NAMED_ENTITY_STOPWORDS:
            continue
        return True
    # Single capitalized word that is NOT a sentence-leading wh/pronoun/
    # auxiliary stopword. We deliberately skip the very first token of the
    # sentence to avoid catching "Why", "Did", "Tell" at position 0.
    tokens = re.findall(r"\b([A-Za-z][a-zA-Z]+)\b", raw)
    for idx, token in enumerate(tokens):
        if idx == 0:
            # Skip the absolute first token (sentence-leading capitalization
            # is grammatical, not entity evidence).
            continue
        if not token[0].isupper():
            continue
        if token in _NAMED_ENTITY_STOPWORDS:
            continue
        # Mixed-case (e.g. OpenAI, iPhone) or capitalized middle-of-sentence
        # word — likely a proper noun.
        return True
    return False


_SPECIFIC_FACTUAL_QUESTION_LEAD_RE = re.compile(
    r"^(?:hey\s+vera[, ]+)?(?:do\s+you\s+know\s+|tell\s+me\s+|can\s+you\s+(?:tell\s+me\s+|say\s+))?"
    r"(?:if|whether|why|when|where|what|who|how|did|does|do|is|are|was|were|has|have|had|will|would|can|could|should)\b",
    re.IGNORECASE,
)


_BROAD_HEADLINES_RE = re.compile(
    r"^(?:hey\s+vera[, ]+)?(?:can\s+you\s+|could\s+you\s+|please\s+)?"
    r"(?:tell|give|show|read|bring\s+up|pull\s+up|open|get)\s+(?:me\s+|us\s+)?"
    r"(?:the\s+|some\s+|a\s+few\s+|today'?s\s+|any\s+)?"
    r"(?:latest\s+|breaking\s+|top\s+|fresh\s+|major\s+)?"
    r"(?:news|headlines?|stories?)\b\s*[?!.\s]*$"
    r"|^what(?:'?s|s|\s+is)\s+(?:the\s+)?(?:latest\s+)?(?:news|headlines?)\b\s*[?!.\s]*$"
    r"|^what(?:'?s|s|\s+is)\s+happening\s+(?:today|right\s+now|in\s+the\s+world)\b"
    r"|^what(?:'?s|s|\s+is)\s+new\b\s*[?!.\s]*$"
    r"|^(?:show|give)\s+me\s+(?:the\s+)?(?:top\s+)?headlines\b"
    # Bare noun phrases — "today's headlines", "the latest news", "breaking news"
    r"|^(?:(?:today'?s|todays|the|this\s+week'?s)\s+)?(?:latest\s+|breaking\s+|top\s+)?(?:news|headlines?)\s*[?!.\s]*$"
    r"|^breaking\s+news\s*[?!.\s]*$",
    re.IGNORECASE,
)


def classify_news_request_type(text: str) -> dict:
    """Spec-shape classifier returning:
        {
          requestType: 'ui_open_news_panel' | 'ui_close_news_panel' |
                       'broad_news_request' |
                       'specific_current_event_question' |
                       'personal_news_statement' | 'emotional_context' |
                       'general_chat',
          confidence: float,
          reason: str,
          rawKeywordNewsDetected: bool,
          requestShapeDetected: bool,
          specificQuestionDetected: bool,
          broadHeadlinesDetected: bool,
          personalNewsStatementDetected: bool,
          emotionalContextDetected: bool,
          uiOpenNewsPanelDetected: bool,
          uiCloseNewsPanelDetected: bool,
        }

    Pure judgment — no side effects, safe to call from any router gate.
    Priority order (spec PART 6 + PART 2):
      1. ui_open_news_panel / ui_close_news_panel (highest)
      2. personal_news_statement / emotional_context
      3. specific_current_event_question (LLM-first w/ Serper sources)
      4. broad_news_request (populates headline cards)
      5. general_chat
    """
    raw = (text or "").strip()
    if not raw:
        return {
            "requestType": "general_chat",
            "confidence": 0.0,
            "reason": "empty_text",
            "rawKeywordNewsDetected": False,
            "requestShapeDetected": False,
            "specificQuestionDetected": False,
            "broadHeadlinesDetected": False,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
            "uiOpenNewsPanelDetected": False,
            "uiCloseNewsPanelDetected": False,
        }

    ui_open = _is_news_panel_open_request(raw)
    ui_close = _is_news_panel_close_request(raw)
    if ui_open:
        return {
            "requestType": "ui_open_news_panel",
            "confidence": 0.95,
            "reason": "matched_ui_open_pattern",
            "rawKeywordNewsDetected": True,
            "requestShapeDetected": False,
            "specificQuestionDetected": False,
            "broadHeadlinesDetected": False,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
            "uiOpenNewsPanelDetected": True,
            "uiCloseNewsPanelDetected": False,
        }
    if ui_close:
        return {
            "requestType": "ui_close_news_panel",
            "confidence": 0.95,
            "reason": "matched_ui_close_pattern",
            "rawKeywordNewsDetected": True,
            "requestShapeDetected": False,
            "specificQuestionDetected": False,
            "broadHeadlinesDetected": False,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
            "uiOpenNewsPanelDetected": False,
            "uiCloseNewsPanelDetected": True,
        }

    personal = _is_personal_news_statement(raw)
    emotional = _is_emotional_distress_statement(raw)
    if personal or emotional:
        # Distress signals strictly stronger than "bare adjective + news":
        # death, hospital, accident, mental-health crisis, etc. If the only
        # thing tripping `_EMOTIONAL_DISTRESS_RE` is the adjective-news
        # pattern itself ("I got bad news"), prefer personal_news_statement
        # so the spec example list classifies as the user expects.
        strong_distress = bool(
            re.search(
                r"\b(?:passed\s+(?:away|on)|passes\s+away|passing\s+(?:away|on)|"
                r"died|dying|deceased|killed|murdered|suicide|overdose|funeral|"
                r"memorial|burial|cremation|obituary|hospital|emergency\s+room|"
                r"ICU|intensive\s+care|cancer|terminal|chemo|chemotherapy|stroke|"
                r"heart\s+attack|aneurysm|sepsis|miscarriage|stillbirth|coma|"
                r"life\s+support|car\s+crash|accident|assaulted|attacked|self[-\s]?harm|"
                r"suicidal|grieving|mourning|heartbroken|devastated|in\s+shock)\b",
                raw,
                re.IGNORECASE,
            )
        )
        if emotional and not strong_distress and personal:
            request_type = "personal_news_statement"
            reason = "personal_share_with_adjective_news"
        elif emotional and strong_distress:
            request_type = "emotional_context"
            reason = "strong_distress_signal"
        elif emotional:
            request_type = "emotional_context"
            reason = "emotional_pattern_match"
        else:
            request_type = "personal_news_statement"
            reason = "personal_share"
        return {
            "requestType": request_type,
            "confidence": 0.95,
            "reason": reason,
            "rawKeywordNewsDetected": bool(re.search(r"\b(?:news|headlines?)\b", raw.lower())),
            "requestShapeDetected": _has_news_request_shape(raw),
            "specificQuestionDetected": False,
            "broadHeadlinesDetected": False,
            "personalNewsStatementDetected": personal,
            "emotionalContextDetected": emotional,
            "uiOpenNewsPanelDetected": False,
            "uiCloseNewsPanelDetected": False,
        }

    request_shape = _has_news_request_shape(raw)
    raw_keyword_news = bool(re.search(r"\b(?:news|headlines?|breaking)\b", raw.lower()))
    broad = bool(_BROAD_HEADLINES_RE.search(raw))

    # A "specific current-event question" looks like:
    #  - A wh-/aux-verb question lead ("did Trump…", "do you know if Elon…")
    #  - AND has at least one named-entity-shaped token OR a clearly
    #    domain-specific noun ("the case", "the trip", "the election",
    #    "the lawsuit", "the fire", "the highway closure", etc.)
    #  - AND is NOT just a request for headlines.
    question_lead = bool(_SPECIFIC_FACTUAL_QUESTION_LEAD_RE.search(raw))
    has_entity = _has_named_entity_hint(raw)
    has_domain_noun = bool(
        re.search(
            r"\b(?:case|trip|visit|lawsuit|deal|election|fire|closure|negotiation|"
            r"investigation|summit|meeting|talks|controversy|scandal|policy|"
            r"bill|law|ruling|court|company|merger|acquisition|launch|announcement|"
            r"shooting|protest|strike|tariffs?|sanctions?|war|conflict|earthquake|"
            r"hurricane|storm|outbreak|pandemic|tournament|game|match|series|"
            # Public-infrastructure / ongoing-situation nouns common in
            # current-event Q&A ("is the highway still closed", "what about
            # the border", "any updates on the airport reopening").
            r"highway|freeway|interstate|road|bridge|border|airport|port|"
            r"terminal|station|tunnel|school|university|hospital|stadium|"
            r"city|town|neighborhood|district|county|state|country|region)\b",
            raw,
            re.IGNORECASE,
        )
    )
    has_temporal = bool(
        re.search(
            r"\b(?:today|yesterday|last\s+(?:week|month|year|night)|this\s+(?:week|month|year|morning|afternoon)|"
            r"recently|just\s+now|earlier(?:\s+today)?|right\s+now|last\s+night)\b",
            raw,
            re.IGNORECASE,
        )
    )

    specific_question = (
        question_lead
        and (has_entity or has_domain_noun)
        and not broad
        # Reject "what's the news about X" — that's broad-ish; still a search,
        # but route via the existing news.latest path.
        and not re.search(r"\b(?:the\s+)?news\s+(?:about|on)\b", raw, re.IGNORECASE)
    )

    if specific_question:
        return {
            "requestType": "specific_current_event_question",
            "confidence": 0.85 if (has_entity and has_temporal) else 0.75,
            "reason": "wh_question_with_named_entity_or_domain_noun",
            "rawKeywordNewsDetected": raw_keyword_news,
            "requestShapeDetected": request_shape,
            "specificQuestionDetected": True,
            "broadHeadlinesDetected": False,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
            "uiOpenNewsPanelDetected": False,
            "uiCloseNewsPanelDetected": False,
        }

    if broad or (request_shape and raw_keyword_news):
        return {
            "requestType": "broad_news_request",
            "confidence": 0.85 if broad else 0.7,
            "reason": "broad_headlines" if broad else "request_shape_plus_news_keyword",
            "rawKeywordNewsDetected": raw_keyword_news,
            "requestShapeDetected": request_shape,
            "specificQuestionDetected": False,
            "broadHeadlinesDetected": broad,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
            "uiOpenNewsPanelDetected": False,
            "uiCloseNewsPanelDetected": False,
        }

    return {
        "requestType": "general_chat",
        "confidence": 0.5,
        "reason": "no_news_indicators_or_unclear",
        "rawKeywordNewsDetected": raw_keyword_news,
        "requestShapeDetected": request_shape,
        "specificQuestionDetected": False,
        "broadHeadlinesDetected": False,
        "personalNewsStatementDetected": False,
        "emotionalContextDetected": False,
        "uiOpenNewsPanelDetected": False,
        "uiCloseNewsPanelDetected": False,
    }


# Strong new-topic indicators per spec PART 8. When the user message clearly
# belongs to a different domain (finance/math/code/app-action/personal-
# emotional), we must NEVER inherit a stale recent_news_context — even when
# that context exists from an earlier Trump/China / NVIDIA / fire / etc.
# turn. These regexes are intentionally narrow so they only fire on signals
# that unambiguously belong elsewhere.
_STRONG_NEW_TOPIC_FINANCE_RE = re.compile(
    r"\b(?:"
    r"drawdown|sharpe|sortino|alpha|beta|volatility|stdev|standard\s+deviation|"
    r"portfolio|allocation|asset\s+class|p/e|p\.e\.|pe\s+ratio|price[-\s]to[-\s]earnings|"
    r"market\s+cap|book\s+value|dividend|dividends|yield|earnings|eps|revenue|"
    r"option|options\s+chain|strike\s+price|expiration|implied\s+volatility|iv|"
    r"return(?:s)?|annualized|cumulative|cagr|year[-\s]over[-\s]year|yoy|"
    r"correlation|covariance|regression|backtest|rebalance|moving\s+average|"
    r"ema|sma|rsi|macd|bollinger|fibonacci"
    r")\b",
    re.IGNORECASE,
)

_STRONG_NEW_TOPIC_MATH_RE = re.compile(
    r"\b(?:"
    r"solve|simplify|integrate|differentiate|factor|prove|"
    r"integral|derivative|equation|inequality|matrix|determinant|"
    r"polynomial|trigonometr(?:y|ic)|logarithm|exponent|exponential|"
    r"theorem|lemma|axiom|proof"
    r")\b",
    re.IGNORECASE,
)

_STRONG_NEW_TOPIC_CODE_RE = re.compile(
    r"\b(?:write|debug|fix|implement|refactor|generate|compile|run)\s+"
    r"(?:a\s+|the\s+|some\s+|this\s+|that\s+)?"
    r"(?:python|javascript|typescript|java|c\+\+|c#|go(?:lang)?|rust|swift|kotlin|"
    r"ruby|php|html|css|sql|bash|powershell|node|react|"
    r"code|function|method|class|component|module|script|program|snippet|loop|algorithm)\b",
    re.IGNORECASE,
)


def _is_strong_new_topic_message(text: str) -> dict:
    """PART 8: classify whether the new user message must bypass any stored
    `recent_news_context` entirely. Returns a small dict so callers can log
    the rationale:

        {"detected": bool, "reason": str}

    True for messages that unambiguously belong to a different domain than
    recent news — finance analytics, math/code requests, app UI commands,
    or personal/emotional statements. Without this gate, a turn like
    "what's the biggest drawdown of VGT in the past 5 years?" could inherit
    a Trump/China news context via the deictic resolver and get the wrong
    answer.
    """
    raw = (text or "").strip()
    if not raw:
        return {"detected": False, "reason": "empty_text"}

    if _is_personal_news_statement(raw) or _is_emotional_distress_statement(raw):
        return {"detected": True, "reason": "personal_or_emotional_statement"}

    if _STRONG_NEW_TOPIC_FINANCE_RE.search(raw):
        return {"detected": True, "reason": "finance_analytics_keyword"}

    # Tickers / generic finance subject (short uppercase token, no spaces)
    # is a strong-new-topic only when there is no news request shape AND no
    # current-fact-question shape. Otherwise "Did NVDA hit a new high?" — a
    # legitimate current-fact question — would be wrongly suppressed.
    if (
        is_likely_finance_subject(raw)
        and not _has_news_request_shape(raw)
        and not _has_current_fact_question_lead(raw)
    ):
        return {"detected": True, "reason": "finance_subject_no_news_shape"}

    if _STRONG_NEW_TOPIC_MATH_RE.search(raw):
        return {"detected": True, "reason": "math_request"}
    if _STRONG_NEW_TOPIC_CODE_RE.search(raw):
        return {"detected": True, "reason": "code_request"}

    # App UI commands have dedicated routes that should never be hijacked
    # by news context.
    try:
        if _is_news_panel_open_request(raw):
            return {"detected": True, "reason": "news_panel_open_command"}
        if _is_news_panel_close_request(raw):
            return {"detected": True, "reason": "news_panel_close_command"}
    except Exception:
        pass
    try:
        if _is_music_open_panel_request(raw):
            return {"detected": True, "reason": "music_panel_ui_command"}
    except Exception:
        pass
    try:
        if _is_reasoning_close_panel_request(raw):
            return {"detected": True, "reason": "reasoning_panel_close_command"}
    except Exception:
        pass
    if _is_work_mode_reasoning_handoff_request(raw):
        return {"detected": True, "reason": "work_mode_reasoning_handoff"}

    return {"detected": False, "reason": "no_strong_new_topic_signal"}


def _topic_similarity_to_recent_news_context(text: str, ctx: dict | None) -> float:
    """Quick overlap score between the new message and the stored news
    context. Returns 0.0 (no overlap) to 1.0 (clear match).

    Used by PART 8 to decide whether a vague follow-up can legitimately
    inherit the stored topic. Low overlap means the follow-up almost
    certainly belongs to a different story.
    """
    if not isinstance(ctx, dict) or not text:
        return 0.0
    stored_entities = {
        str(e).strip().lower()
        for e in (ctx.get("entities") or [])
        if str(e).strip()
    }
    stored_topic = str(ctx.get("topic") or ctx.get("resolved_topic") or "").lower()
    if not stored_entities and not stored_topic:
        return 0.0

    raw_low = (text or "").lower()
    score = 0.0

    try:
        new_entities_raw = _extract_news_entities(text) or []
    except Exception:
        new_entities_raw = []
    new_entities = [
        e.lower() for e in new_entities_raw if _is_substantive_news_entity(e)
    ]
    if stored_entities:
        if new_entities:
            overlap = sum(1 for e in new_entities if e in stored_entities)
            score = max(score, overlap / max(1, len(new_entities)))
        else:
            for e in stored_entities:
                if len(e) >= 3 and e in raw_low:
                    score = max(score, 0.6)

    if stored_topic:
        topic_tokens = {
            t for t in re.findall(r"[a-z]{4,}", stored_topic)
            if t not in {
                "news", "story", "today", "yesterday", "latest", "update",
                "updates", "report", "reports", "article", "articles",
            }
        }
        if topic_tokens:
            hits = sum(1 for t in topic_tokens if t in raw_low)
            score = max(score, hits / max(1, len(topic_tokens)))

    return float(min(1.0, max(0.0, score)))


# Broad-headline question shapes that don't include an imperative verb
# ("tell me", "show me"). These match the spec PART 4A examples:
#   "what are today's headlines"
#   "what's happening today"
#   "today's top headlines"
_BROAD_HEADLINE_QUESTION_RE = re.compile(
    r"^\s*what(?:'?s|s|\s+is|\s+are)?\s+(?:today'?s\s+|the\s+|current\s+)?(?:top\s+)?(?:headlines?|news)\b"
    r"|^\s*what(?:'?s|s|\s+is|\s+are)?\s+happening\s+(?:today|right\s+now|now)\b"
    r"|^\s*(?:today'?s|the)\s+(?:top\s+)?headlines?\b",
    re.IGNORECASE,
)

# Topical news/search request shapes WITHOUT an imperative verb. These
# match the spec PART 4B examples:
#   "latest news about OpenAI"
#   "any updates on the new NVIDIA GPU"
#   "news about NVIDIA"
#   "articles about Trump China"
# The existing `_has_news_request_shape` regex only fires on imperatives
# ("search ...", "tell me ..."), which leaves these bare topical asks at
# general_chat.
_EXPLICIT_TOPICAL_NEWS_RE = re.compile(
    r"\b(?:latest|newest|recent|breaking|new)\s+"
    r"(?:news|articles?|coverage|stories|reports?|updates?|headlines?)\s+"
    r"(?:about|on|regarding|for|of|from)\s+\S+"
    r"|\b(?:news|articles?|coverage|stories|reports?|updates?|headlines?)\s+"
    r"(?:about|on|regarding)\s+\S+"
    r"|\bany\s+(?:new\s+)?(?:news|articles?|coverage|stories|reports?|updates?|headlines?)\s+"
    r"(?:about|on|regarding|for)\s+\S+",
    re.IGNORECASE,
)


def classify_current_info_intent(
    text: str,
    *,
    recent_news_context: dict | None = None,
    session_id: str | None = None,
) -> dict:
    """Top-level current-info / news intent router (spec PART 1+2+8+10).

    This is the SINGLE source of truth for current-info routing. It composes
    the existing classifiers (`classify_news_request_type`,
    `classify_news_search_intent`, `score_current_fact_question`,
    `classify_news_route_for_turn`) into one unified spec-shape result so
    callers no longer need scattered keyword checks like
    `text.includes("news")` or "let active news panel own this turn".

    Returns:
        {
          "route": one of
              "personal_emotional" |
              "historical_or_educational_explanation" |  # PART 2 (2026-05-28)
              "explicit_news_headlines" |
              "explicit_news_search" |
              "current_fact_search" |
              "interpretive_followup_llm" |
              "fresh_update_search" |
              "source_specific_followup" |
              "general_chat",
          "shouldSearch": bool,
          "shouldOpenNewsPanel": bool,
          "news_panel_mode": "ui_only" | "headlines" |
              "sources_for_answer" | "topic_results" | "unchanged",
          "answer_source": "llm_general" | "search_result" |
              "stored_source_context" | "emotional_support",
          "confidence": float,
          "reason": str,
          "entities": list[str],
          "topic": str | None,
          "signals": {  # PART 11 — fields the structured log consumes
              "raw_news_keyword_detected": bool,
              "personal_emotional_detected": bool,
              "explicit_news_command_detected": bool,
              "current_fact_question_detected": bool,
              "question_shape_detected": bool,
              "public_entity_detected": bool,
              "recent_or_change_marker_detected": bool,
              "followup_detected": bool,
              "followup_type":
                  "interpretive" | "fresh_update" |
                  "source_specific" | "new_topic" | "none",
              "recent_news_context_available": bool,
              "recent_news_context_topic": str,
              "topic_similarity_to_recent_news": float,
              "strong_new_topic_detected": bool,
              "strong_new_topic_reason": str,
          },
        }

    Priority (spec PART 2):
        1. Personal/emotional/safety context (PART 3)
        2. Explicit UI/app actions
        3. Explicit news/headline/search command (PART 4)
        4. Current factual public question (PART 5)
        5. Follow-up classification using recent context (PART 6+7)
        6. General chat

    Pure — no side effects, safe to call from any router gate or test.
    """
    raw = (text or "").strip()
    has_ctx = isinstance(recent_news_context, dict) and bool(recent_news_context)
    signals = {
        "raw_news_keyword_detected": False,
        "personal_emotional_detected": False,
        "explicit_news_command_detected": False,
        "current_fact_question_detected": False,
        "question_shape_detected": False,
        "public_entity_detected": False,
        "recent_or_change_marker_detected": False,
        "followup_detected": False,
        "followup_type": "none",
        "historical_or_educational_detected": False,  # PART 2 (2026-05-28)
        "recent_news_context_available": bool(has_ctx),
        "recent_news_context_topic": str(
            (recent_news_context or {}).get("topic") or ""
        ) if has_ctx else "",
        "topic_similarity_to_recent_news": 0.0,
        "strong_new_topic_detected": False,
        "strong_new_topic_reason": "",
    }
    out: dict = {
        "route": "general_chat",
        "shouldSearch": False,
        "shouldOpenNewsPanel": False,
        "news_panel_mode": "unchanged",
        "answer_source": "llm_general",
        "confidence": 0.5,
        "reason": "default_general_chat",
        "entities": [],
        "topic": None,
        "signals": signals,
    }
    if not raw:
        out["reason"] = "empty_text"
        return out

    low = raw.lower()
    signals["raw_news_keyword_detected"] = bool(
        re.search(r"\b(?:news|headlines?|breaking)\b", low)
    )

    # ---- PART 3: personal/emotional ALWAYS wins, even when the message
    # contains the word "news".
    personal = _is_personal_news_statement(raw)
    emotional = _is_emotional_distress_statement(raw)
    if personal or emotional:
        signals["personal_emotional_detected"] = True
        out["route"] = "personal_emotional"
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = False
        out["news_panel_mode"] = "unchanged"
        out["answer_source"] = "emotional_support"
        out["confidence"] = 0.95
        out["reason"] = (
            "emotional_distress" if emotional else "personal_news_share"
        )
        return out

    # PART 8 — strong-new-topic gate. Computed early so the [current_info_intent]
    # log always records whether ctx would have been dropped this turn.
    strong = _is_strong_new_topic_message(raw)
    signals["strong_new_topic_detected"] = bool(strong["detected"])
    signals["strong_new_topic_reason"] = str(strong["reason"])

    if has_ctx and not strong["detected"]:
        signals["topic_similarity_to_recent_news"] = (
            _topic_similarity_to_recent_news_context(raw, recent_news_context)
        )

    # ---- PART 2 (2026-05-28): historical / educational / explanatory
    # questions route to general LLM, NEVER to news. The detector has its
    # own override for "Latest news about X documentary" style queries so
    # legitimate news about historical topics still goes through.
    # This gate runs BEFORE the explicit-news classifier so the existing
    # `news` keyword match cannot accidentally win on a sentence like
    # "Can you explain the news embargo on Cold War files?" (very rare;
    # the override regex catches it).
    if _is_historical_or_educational_question(raw):
        signals["historical_or_educational_detected"] = True
        out["route"] = "historical_or_educational_explanation"
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = False
        out["news_panel_mode"] = "unchanged"
        out["answer_source"] = "llm_general"
        out["confidence"] = 0.9
        out["reason"] = "historical_or_educational_topic"
        return out

    # ---- PART 4C: news-panel UI-only commands route to the UI but never
    # fetch data on their own.
    base = classify_news_request_type(raw)
    base_type = str(base.get("requestType") or "general_chat")

    if base_type == "ui_open_news_panel":
        signals["explicit_news_command_detected"] = True
        out["route"] = "explicit_news_headlines"
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = True
        out["news_panel_mode"] = "ui_only"
        out["answer_source"] = "llm_general"
        out["confidence"] = float(base.get("confidence") or 0.9)
        out["reason"] = str(base.get("reason") or "ui_open_news_panel")
        return out
    if base_type == "ui_close_news_panel":
        signals["explicit_news_command_detected"] = True
        out["route"] = "explicit_news_headlines"
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = False
        out["news_panel_mode"] = "ui_only"
        out["answer_source"] = "llm_general"
        out["confidence"] = float(base.get("confidence") or 0.9)
        out["reason"] = str(base.get("reason") or "ui_close_news_panel")
        return out

    # ---- PART 4A: broad headline requests → headlines panel.
    if base_type == "broad_news_request" or _BROAD_HEADLINE_QUESTION_RE.search(raw):
        signals["explicit_news_command_detected"] = True
        out["route"] = "explicit_news_headlines"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["news_panel_mode"] = "headlines"
        out["answer_source"] = "search_result"
        out["confidence"] = float(base.get("confidence") or 0.85)
        out["reason"] = str(base.get("reason") or "broad_headlines")
        return out

    # ---- PART 6+7: follow-up classification runs BEFORE current-fact and
    # explicit-search so that messages like "what does Reuters say?" or
    # "any updates today?" — which would otherwise match the current-fact
    # heuristic on the entity alone — get attributed to the stored news
    # context instead of triggering a brand-new search. Only fires when
    # `recent_news_context` exists AND this is not a strong new topic
    # (PART 8 — finance / math / code / app UI / personal-emotional must
    # never inherit a stale Trump/China context via follow-up resolution).
    if has_ctx and strong["detected"]:
        signals["followup_type"] = "new_topic"
    if has_ctx and not strong["detected"]:
        polish_route = classify_news_route_for_turn(raw, ctx=recent_news_context)
        polish_cls = str(polish_route.get("route_classification") or "")
        # Outlet-mention follow-ups (e.g. "what does Reuters say?", "any
        # Bloomberg coverage?") are conceptually source-specific even when
        # the existing polish-layer regex routes them through the
        # fresh-update branch. Override so the unified router emits the
        # source_specific_followup label that the spec asks for.
        outlet_mentioned = bool(_NEWS_MEDIA_OUTLETS_RE.search(low))
        outlet_source_ask = outlet_mentioned and bool(
            re.search(
                r"\b(?:what\s+(?:does|do|did)\s+(?:the\s+)?\S|any\s+(?:the\s+)?\S+\s+(?:coverage|reporting|article|story|piece)|"
                r"from\s+(?:the\s+)?\S)",
                low,
            )
        )
        if polish_cls == "source_specific_followup" or outlet_source_ask:
            signals["followup_detected"] = True
            signals["followup_type"] = "source_specific"
            if outlet_source_ask and polish_cls != "source_specific_followup":
                try:
                    stored_cards = bool(_stored_sources_have_cards(recent_news_context))
                except Exception:
                    stored_cards = False
                serper_called = not stored_cards
            else:
                serper_called = bool(polish_route.get("serper_called"))
            out["route"] = "source_specific_followup"
            out["shouldSearch"] = serper_called
            out["shouldOpenNewsPanel"] = True
            out["news_panel_mode"] = "sources_for_answer"
            out["answer_source"] = (
                "search_result" if serper_called else "stored_source_context"
            )
            out["confidence"] = 0.85
            out["reason"] = str(
                polish_route.get("reason") or "source_specific_followup"
            )
            return out
        if polish_cls == "fresh_update_followup":
            signals["followup_detected"] = True
            signals["followup_type"] = "fresh_update"
            out["route"] = "fresh_update_search"
            out["shouldSearch"] = True
            out["shouldOpenNewsPanel"] = True
            out["news_panel_mode"] = "sources_for_answer"
            out["answer_source"] = "search_result"
            out["confidence"] = 0.85
            out["reason"] = str(
                polish_route.get("reason") or "fresh_update_followup"
            )
            return out
        if polish_cls == "interpretive_followup_llm_first":
            signals["followup_detected"] = True
            signals["followup_type"] = "interpretive"
            out["route"] = "interpretive_followup_llm"
            out["shouldSearch"] = False
            out["shouldOpenNewsPanel"] = False
            out["news_panel_mode"] = "unchanged"
            out["answer_source"] = "stored_source_context"
            out["confidence"] = 0.9
            out["reason"] = str(
                polish_route.get("reason") or "interpretive_followup_uses_stored_ctx"
            )
            return out

    # ---- PART 5: current-fact public question — search even without "news".
    fact_score = score_current_fact_question(raw)
    signals["question_shape_detected"] = bool(
        fact_score.get("question_shape_detected")
    )
    signals["public_entity_detected"] = bool(
        fact_score.get("public_entity_detected")
        or fact_score.get("public_domain_noun_detected")
    )
    signals["recent_or_change_marker_detected"] = bool(
        fact_score.get("recent_time_marker_detected")
        or fact_score.get("public_domain_noun_detected")
    )

    is_current_fact_q = bool(fact_score.get("matches"))
    if (base_type == "specific_current_event_question" or is_current_fact_q) and not strong["detected"]:
        signals["current_fact_question_detected"] = True
        if base_type != "general_chat":
            signals["explicit_news_command_detected"] = True
        try:
            entities = _extract_news_entities(raw) or []
        except Exception:
            entities = []
        try:
            topic = _normalize_news_topic_phrase(raw) or None
        except Exception:
            topic = None
        out["route"] = "current_fact_search"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["news_panel_mode"] = "sources_for_answer"
        out["answer_source"] = "search_result"
        out["entities"] = list(entities)
        out["topic"] = topic
        out["confidence"] = float(
            base.get("confidence")
            or (0.75 + 0.25 * float(fact_score.get("current_fact_question_score") or 0.0))
        )
        out["reason"] = "current_fact_question"
        return out

    # ---- PART 4B: explicit topical news/search command. First, the
    # imperative-shape variant the existing classifier handles
    # ("search news about NVIDIA", "look up latest updates on the LA fire").
    explicit_cls = classify_news_search_intent(
        raw, recent_news_context=recent_news_context
    )
    explicit_intent = explicit_cls.get("intentType") if isinstance(explicit_cls, dict) else None
    if (
        explicit_cls.get("shouldSearchNews")
        and explicit_intent in {"explicit_news_request", "explicit_web_search_request"}
    ):
        signals["explicit_news_command_detected"] = True
        try:
            entities = _extract_news_entities(raw) or []
        except Exception:
            entities = []
        try:
            topic = _normalize_news_topic_phrase(raw) or None
        except Exception:
            topic = None
        out["route"] = "explicit_news_search"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["news_panel_mode"] = "topic_results" if entities else "sources_for_answer"
        out["answer_source"] = "search_result"
        out["entities"] = list(entities)
        out["topic"] = topic
        out["confidence"] = float(explicit_cls.get("confidence") or 0.8)
        out["reason"] = str(
            explicit_cls.get("reason") or "explicit_search_imperative"
        )
        return out

    # ---- PART 4B (continued): bare topical news asks without an
    # imperative verb ("latest news about OpenAI", "news about NVIDIA",
    # "any updates on the new NVIDIA GPU"). The legacy classifier reports
    # these as `bare_news_keyword_no_request_shape` because there's no
    # "tell me" / "search". We catch them with a dedicated regex so they
    # route to news search instead of general chat.
    if _EXPLICIT_TOPICAL_NEWS_RE.search(raw):
        signals["explicit_news_command_detected"] = True
        try:
            entities = _extract_news_entities(raw) or []
        except Exception:
            entities = []
        try:
            topic = _normalize_news_topic_phrase(raw) or None
        except Exception:
            topic = None
        out["route"] = "explicit_news_search"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["news_panel_mode"] = "topic_results" if entities else "sources_for_answer"
        out["answer_source"] = "search_result"
        out["entities"] = list(entities)
        out["topic"] = topic
        out["confidence"] = 0.8
        out["reason"] = "bare_topical_news_pattern"
        return out

    # ---- PART 6 default: general chat. Stale recent_news_context is NOT
    # consulted here — the caller (route_action_request) is responsible for
    # dropping it before the LLM runs, based on `strong_new_topic_detected`.
    out["route"] = "general_chat"
    out["shouldSearch"] = False
    out["shouldOpenNewsPanel"] = False
    out["news_panel_mode"] = "unchanged"
    out["answer_source"] = "llm_general"
    out["confidence"] = 0.5
    out["reason"] = (
        "strong_new_topic_no_news_intent"
        if strong["detected"]
        else (
            "raw_news_keyword_only_no_search_intent"
            if signals["raw_news_keyword_detected"]
            else "no_news_intent"
        )
    )
    return out


def log_news_router_route(
    *,
    session_id: str | None,
    text: str,
    current_info_intent: dict,
    news_ctx: dict | None,
    stage: str = "route_action_request_pre_dispatch",
) -> None:
    """PART 14 (2026-05-28): single grep target `[news_router_route]` that
    emits the full spec-shape routing decision once per turn, BEFORE any
    downstream search/mutation runs. Use this to debug stale-query-reuse,
    historical-misroutes, personal-suppression misses, and follow-up
    misclassification.

    Schema follows spec PART 14 fields verbatim:
      latest_user_text, route, shouldSearchNews, shouldOpenNewsPanel,
      explicit_news_request_detected, current_fact_search_detected,
      historical_or_educational_detected, utility_query_detected,
      personal_emotional_detected, followup_detected, followup_type,
      pronoun_or_deictic_detected, named_entity_in_current_message,
      previous_news_context_available, previous_news_context_used,
      previous_news_context_ignored_reason, search_query_generated,
      search_query_source, blocked_news_reason.

    User chose "every_turn" verbosity — this fires for general_chat turns
    too so the log is the per-turn source of truth.
    """
    try:
        raw = (text or "").strip()
        intent = current_info_intent if isinstance(current_info_intent, dict) else {}
        signals = intent.get("signals") if isinstance(intent.get("signals"), dict) else {}
        route = str(intent.get("route") or "general_chat")
        should_search = bool(intent.get("shouldSearch"))
        should_open_panel = bool(intent.get("shouldOpenNewsPanel"))
        explicit_news = bool(signals.get("explicit_news_command_detected"))
        current_fact = bool(signals.get("current_fact_question_detected"))
        historical = bool(signals.get("historical_or_educational_detected"))
        utility = bool(_is_utility_route_message(raw))
        personal = bool(signals.get("personal_emotional_detected"))
        followup = bool(signals.get("followup_detected"))
        followup_type = str(signals.get("followup_type") or "none")
        pronoun_or_deictic = bool(
            _is_pronoun_news_followup(raw) or _is_deictic_news_followup(raw)
        )
        named_entity = bool(_has_named_entity_hint(raw)) or bool(_extract_news_entities(raw))
        ctx_avail = isinstance(news_ctx, dict) and bool(news_ctx)
        # `previous_news_context_used` is True when the classifier indicates
        # this turn is a follow-up resolving against the stored ctx, OR when
        # the deictic resolver merged ctx entities/topic.
        ctx_used = bool(ctx_avail and (followup or signals.get("topic_similarity_to_recent_news") and float(signals.get("topic_similarity_to_recent_news") or 0.0) >= 0.4))
        ctx_ignored_reason = ""
        if ctx_avail and not ctx_used:
            if signals.get("strong_new_topic_detected"):
                ctx_ignored_reason = "strong_new_topic"
            elif historical:
                ctx_ignored_reason = "historical_or_educational"
            elif personal:
                ctx_ignored_reason = "personal_emotional"
            elif utility:
                ctx_ignored_reason = "utility_query"
            elif named_entity and not pronoun_or_deictic:
                ctx_ignored_reason = "current_msg_has_named_entity"
            else:
                ctx_ignored_reason = "low_topic_similarity"
        # search_query_generated / search_query_source: at the pre-dispatch
        # stage we don't yet have the finalized search_queries — those are
        # emitted by [news_search_query_built] downstream. We surface the
        # intent's `topic` field plus the source-of-record so the log is
        # still actionable for stale-query debugging.
        topic_for_query = str(intent.get("topic") or "")
        if not should_search:
            query_source = "none"
            query_generated = ""
        elif pronoun_or_deictic and ctx_used:
            query_source = "resolved_followup"
            query_generated = topic_for_query or raw
        elif explicit_news:
            query_source = "explicit_news_topic"
            query_generated = topic_for_query or raw
        else:
            query_source = "current_user_text"
            query_generated = raw
        blocked_news_reason = ""
        if not should_search:
            if personal:
                blocked_news_reason = "personal_emotional"
            elif historical:
                blocked_news_reason = "historical_or_educational"
            elif utility:
                blocked_news_reason = "utility_query"
            elif route == "general_chat":
                blocked_news_reason = "general_chat_no_news_signal"
            elif route == "interpretive_followup_llm":
                blocked_news_reason = "interpretive_followup_answer_from_stored_ctx"
            else:
                blocked_news_reason = ""
        print(
            "[news_router_route] " + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "stage": stage,
                    "latest_user_text": raw[:200],
                    "route": route,
                    "shouldSearchNews": should_search,
                    "shouldOpenNewsPanel": should_open_panel,
                    "explicit_news_request_detected": explicit_news,
                    "current_fact_search_detected": current_fact,
                    "historical_or_educational_detected": historical,
                    "utility_query_detected": utility,
                    "personal_emotional_detected": personal,
                    "followup_detected": followup,
                    "followup_type": followup_type,
                    "pronoun_or_deictic_detected": pronoun_or_deictic,
                    "named_entity_in_current_message": named_entity,
                    "previous_news_context_available": ctx_avail,
                    "previous_news_context_used": ctx_used,
                    "previous_news_context_ignored_reason": ctx_ignored_reason,
                    "search_query_generated": query_generated[:200],
                    "search_query_source": query_source,
                    "blocked_news_reason": blocked_news_reason,
                    "confidence": float(intent.get("confidence") or 0.0),
                    "answer_source": str(intent.get("answer_source") or ""),
                    "reason": str(intent.get("reason") or ""),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        try:
            print("[news_router_route] log_serialization_failed", flush=True)
        except Exception:
            pass


def log_current_info_intent(session_id: str, text: str, intent: dict) -> None:
    """PART 11: single structured log line per turn covering every field
    spec'd by the new router. Grep target: '[current_info_intent]'.
    """
    try:
        sig = intent.get("signals") or {}
        print(
            "[current_info_intent] " + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "latest_user_text": (text or "")[:200],
                    "route": str(intent.get("route") or ""),
                    "shouldSearch": bool(intent.get("shouldSearch")),
                    "shouldOpenNewsPanel": bool(intent.get("shouldOpenNewsPanel")),
                    "news_panel_mode": str(intent.get("news_panel_mode") or ""),
                    "answer_source": str(intent.get("answer_source") or ""),
                    "confidence": float(intent.get("confidence") or 0.0),
                    "reason": str(intent.get("reason") or ""),
                    "entities": list(intent.get("entities") or [])[:8],
                    "topic": str(intent.get("topic") or ""),
                    "raw_news_keyword_detected": bool(sig.get("raw_news_keyword_detected")),
                    "personal_emotional_detected": bool(sig.get("personal_emotional_detected")),
                    "explicit_news_command_detected": bool(sig.get("explicit_news_command_detected")),
                    "current_fact_question_detected": bool(sig.get("current_fact_question_detected")),
                    "question_shape_detected": bool(sig.get("question_shape_detected")),
                    "public_entity_detected": bool(sig.get("public_entity_detected")),
                    "recent_or_change_marker_detected": bool(sig.get("recent_or_change_marker_detected")),
                    "followup_detected": bool(sig.get("followup_detected")),
                    "followup_type": str(sig.get("followup_type") or "none"),
                    "recent_news_context_available": bool(sig.get("recent_news_context_available")),
                    "recent_news_context_topic": str(sig.get("recent_news_context_topic") or ""),
                    "topic_similarity_to_recent_news": float(sig.get("topic_similarity_to_recent_news") or 0.0),
                    "strong_new_topic_detected": bool(sig.get("strong_new_topic_detected")),
                    "strong_new_topic_reason": str(sig.get("strong_new_topic_reason") or ""),
                    # serper_called is a downstream observable — the polish
                    # log already records it; the router records the
                    # *decision* to search via shouldSearch.
                    "serper_called": bool(intent.get("shouldSearch")),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


# ============================================================================
# 2026-05-28 PART 1+2 — single-dispatch info tool router (beta).
#
# `classify_info_tool` is the single classifier the dispatcher consults AFTER
# `heuristic_route_action` has had a chance to claim local app actions
# (panel/checklist/music/timer/UI). The classifier's job is to pick exactly
# ONE downstream tool for public-information requests so news/time/finance
# can never silently compete after this point.
#
# Returns a dict matching the spec contract:
#   {
#     "route": "time_tool" | "weather_tool" | "finance_quote_tool" |
#              "finance_search_tool" | "news_search_tool" |
#              "general_web_search_tool" | "llm_only" | "followup_llm" |
#              "followup_search" | "clarification_needed" | "uncertain",
#     "tool": "time" | "weather" | "finance_quote" | "web_search" |
#             "news" | "none",
#     "query": str,                  # what the dispatched tool should run
#     "entities": list[str],
#     "metric": str | None,
#     "timeframe": str | None,
#     "required_context": list[str] | None,
#     "confidence": float,
#     "reason": str,
#   }
#
# `route == "uncertain"` means "I don't have a confident pick — let the
# existing news_intent + LLM-router pipeline handle this turn". This keeps
# the classifier non-destructive: every existing turn that this classifier
# doesn't claim falls through to the pre-existing dispatch unchanged.
#
# Caller: `route_action_request` (between `heuristic_route_action` and
# `detect_news_route_intent` upgrade).
# ============================================================================

# Time/date — explicit utility questions.
_INFO_TOOL_TIME_RE = re.compile(
    r"\b(?:what(?:'s|s|\s+is)?|whats|tell\s+me|current|do\s+you\s+know)\b[^?]*?"
    r"\b(?:time|hour|clock)\b",
    re.IGNORECASE,
)
_INFO_TOOL_DATE_RE = re.compile(
    r"\b(?:what(?:'s|s|\s+is)?|whats|tell\s+me|today(?:'s|s)?)\b[^?]*?"
    r"\b(?:day|date)\b(?!\s+(?:of\s+the\s+week\s+did|that))",
    re.IGNORECASE,
)
# Weather — bare verb/noun forms. Location extraction happens downstream.
_INFO_TOOL_WEATHER_RE = re.compile(
    r"\b(?:weather|forecast|temperature|temp|raining|rain|snow(?:ing)?|"
    r"sunny|cloudy|windy|humid(?:ity)?|how(?:'s|s|\s+is)?\s+the\s+weather)\b",
    re.IGNORECASE,
)
# Finance quote — explicit "price of / trading at / quote for / how is X stock".
_INFO_TOOL_FINANCE_QUOTE_RE = re.compile(
    r"\b(?:stock\s+price|share\s+price|price\s+of|quote\s+for|trading\s+at|"
    r"market\s+cap|how\s+much\s+is|how(?:'s|s|\s+is)\s+(?:[a-z]+\s+)?stock|"
    r"how(?:'s|s|\s+is)\s+(?:[a-z]+\s+)?doing\s+today)\b",
    re.IGNORECASE,
)
# Broader finance anchors for blocking bare "what's the latest" → news when the
# full compound turn is a stock quote request.
_FINANCE_TURN_ANCHOR_RE = re.compile(
    r"\b(?:stock\s+price|share\s+price|price\s+of|quote\s+for|trading\s+at|"
    r"market\s+cap|(?:ticker|shares?)\b|"
    r"[\w.$-]{1,12}\s+(?:stock\s+price|share\s+price|trading\s+at|market\s+cap|shares?))\b",
    re.IGNORECASE,
)
_BARE_LATEST_RECENCY_QUERY_RE = re.compile(
    r"^\s*what(?:'?s|s|\s+is)\s+(?:the\s+)?(?:latest|current|newest)\s*[?!.]?\s*$",
    re.IGNORECASE,
)


def _has_finance_anchor_in_text(text: str) -> bool:
    return bool(_FINANCE_TURN_ANCHOR_RE.search(str(text or "").strip()))


def _planner_full_turn_context() -> str:
    try:
        return str(_planner_plan_raw_text_var.get() or "").strip()
    except Exception:
        return ""


def _bare_latest_news_blocked_by_finance_anchor(span: str, *, full_turn: str = "") -> bool:
    """True when a bare recency fragment must not route to news.latest."""
    s = str(span or "").strip()
    if not s:
        return False
    if re.search(r"\b(?:news|headlines?)\b", s, re.IGNORECASE):
        return False
    if not _BARE_LATEST_RECENCY_QUERY_RE.match(s):
        return False
    context = str(full_turn or "").strip() or _planner_full_turn_context()
    return bool(context and _has_finance_anchor_in_text(context))
# Sports — explicit win/lose/score/play/schedule questions about a team.
_INFO_TOOL_SPORTS_TEAM_RE = re.compile(
    r"\b(?:lakers|clippers|warriors|celtics|knicks|heat|bulls|spurs|nets|"
    r"sixers|76ers|raptors|bucks|mavericks|nuggets|suns|kings|pelicans|"
    r"jazz|wizards|hawks|hornets|magic|grizzlies|thunder|rockets|"
    r"timberwolves|trail\s*blazers|pacers|pistons|cavaliers|cavs|"
    r"yankees|red\s*sox|dodgers|giants|cubs|astros|mets|braves|phillies|"
    r"orioles|nationals|cardinals|brewers|padres|angels|royals|tigers|"
    r"chiefs|patriots|eagles|cowboys|49ers|niners|packers|bears|bills|"
    r"steelers|ravens|broncos|raiders|chargers|jets|giants|saints|"
    r"falcons|panthers|buccaneers|seahawks|rams|vikings|lions|"
    r"liverpool|arsenal|chelsea|manchester|man\s+city|man\s+utd|"
    r"barcelona|real\s+madrid|psg|bayern|juventus|inter|milan)\b",
    re.IGNORECASE,
)
_INFO_TOOL_SPORTS_VERB_RE = re.compile(
    r"\b(?:win|won|lose|lost|beat|beating|score|scored|game|games|"
    r"match|matches|play(?:ing|ed)?|tonight|last\s+night|yesterday)\b",
    re.IGNORECASE,
)
# Shopping / recommendation — "best X under $Y", "X vs Y", "reviews of X".
_INFO_TOOL_SHOPPING_RE = re.compile(
    r"\b(?:best|top|cheap(?:est)?|good|recommended)\s+[a-z0-9\- ]{2,40}\s+"
    r"(?:under|below|less\s+than|for\s+under)\s*\$?\s*\d"
    r"|\bbest\s+[a-z0-9\- ]{2,40}\s+(?:for|to|in)\s+[a-z0-9\- ]{2,40}"
    r"|\b(?:reviews?\s+of|reviews?\s+for|review\s+of)\b"
    r"|\bcompare\s+[a-z0-9\- ]{1,30}\s+(?:vs|versus|and|to)\s+[a-z0-9\- ]{1,30}"
    r"|\b[a-z0-9\- ]{1,20}\s+(?:vs|versus)\s+[a-z0-9\- ]{1,20}\b",
    re.IGNORECASE,
)
# Local — "near me", "nearby", "around here", "in <city>" + venue noun.
_INFO_TOOL_NEAR_ME_RE = re.compile(
    r"\b(?:near\s+me|nearby|around\s+here|around\s+me|close\s+to\s+me|"
    r"what(?:'s|s)\s+open\s+(?:near|nearby|around))\b",
    re.IGNORECASE,
)
_INFO_TOOL_VENUE_RE = re.compile(
    # 2026-05-28 — expanded to mirror actions.web_search._VENUE_NOUN_RE so
    # bare "coffee" / "boba" / "bakery" / "barbershop" / "store" etc. also
    # trip the local-venue path. Without this, "coffee near irvine" never
    # entered the location_map_panel branch and silently fell through to
    # general LLM.
    r"\b(?:coffee(?:\s+shop|s+shops)?|cafe|cafes|caf[eé]s?|"
    r"boba|bubble\s+tea|matcha|tea\s+(?:shop|shops|house|houses)?|"
    r"bakery|bakeries|brunch|brunch\s+spots?|breakfast\s+spots?|"
    r"restaurant|restaurants|diner|diners|ramen|sushi|pho|"
    r"taquer[ií]a|taquer[ií]as|tacos?|pizza|"
    r"barbershop|barbershops|barber|barbers|salon|salons|nail\s+salons?|spa|spas|"
    r"gym|gyms|bar|bars|pub|pubs|brewery|breweries|winery|wineries|"
    r"gas\s+station|gas\s+stations|grocery|supermarket|store|stores|market|markets|"
    r"pharmacy|pharmacies|atm|atms|hotel|hotels|motel|motels|park|parks|"
    r"hospital|hospitals|urgent\s+care|library|libraries|bookstore|bookstores|"
    r"study\s+(?:cafe|cafes|spot|spots|space|spaces))\b",
    re.IGNORECASE,
)
# Case-insensitive so voice transcripts like "coffee near irvine" still
# resolve a place name; we strip non-city tail words downstream.
_INFO_TOOL_LOCAL_IN_CITY_RE = re.compile(
    r"\b(?:in|around|near)\s+(?:the\s+)?(?P<place>[a-zA-Z]+(?:\s+[a-zA-Z]+){0,3})\b",
    re.IGNORECASE,
)
_INFO_TOOL_NON_CITY_TAIL_WORDS = {
    "me", "us", "here", "there",
    "town", "downtown", "midtown", "uptown",
    "the", "a", "an",
}
# Episode / show / generic-factoid markers that benefit from search.
_INFO_TOOL_SHOW_RE = re.compile(
    r"\b(?:how\s+many\s+(?:episodes|seasons|chapters|volumes)|"
    r"what\s+season|when\s+does\s+(?:season|episode)|"
    r"release\s+date|release\s+dates?\s+of)\b",
    re.IGNORECASE,
)
# Personal/emotional — same regex spirit as the news router's
# `_NEWS_ROUTER_PERSONAL_NEWS_RE`. We keep this local so the new router
# remains self-contained for unit testing.
_INFO_TOOL_PERSONAL_NEWS_RE = re.compile(
    r"\b(?:i\s+(?:got|just\s+got|received|heard|just\s+heard|just\s+saw|"
    r"saw|read)\s+(?:bad|terrible|good|sad|tragic|awful)?\s*news\b|"
    r"\bbad\s+news\b|\bterrible\s+news\b|\bmy\s+(?:friend|mom|mother|dad|"
    r"father|brother|sister|family)\s+(?:passed\s+away|died|is\s+sick)\b)",
    re.IGNORECASE,
)
# Pronoun / deictic markers for follow-up classification.
_INFO_TOOL_PRONOUN_RE = re.compile(
    r"\b(?:he|she|they|him|her|them|his|hers|their|that|this|those|these|"
    r"after\s+that|then|there|right\s+after)\b",
    re.IGNORECASE,
)
# Fresh-update / source markers — push pronoun followups to followup_search.
_INFO_TOOL_FRESH_FOLLOWUP_RE = re.compile(
    r"\b(?:any\s+updates?|what(?:'s|s)?\s+the\s+latest|latest\s+(?:on|with|about)|"
    r"who\s+else|what(?:'s|s)?\s+(?:next|after\s+that)|when\s+exactly|"
    r"can\s+you\s+verify|verify\s+that|"
    r"what\s+does\s+(?:reuters|bloomberg|ap|the\s+(?:new\s+york\s+)?times|cnn|"
    r"bbc|nbc|cnbc|wsj|the\s+wall\s+street\s+journal|wapo)\s+say|"
    r"find\s+more\s+sources?|more\s+sources?)\b",
    re.IGNORECASE,
)
# Explicit news triggers — broad reset, breaking, "latest news about X".
_INFO_TOOL_EXPLICIT_NEWS_RE = re.compile(
    r"\b(?:tell\s+me\s+(?:the\s+)?news|what(?:'s|s)?\s+(?:the\s+)?(?:latest\s+)?news|"
    r"breaking\s+news|today(?:'s|s)?\s+headlines|news\s+about|"
    r"any\s+(?:news|updates?)\s+(?:on|about)|latest\s+(?:news\s+)?(?:on|about)|"
    r"any\s+(?:news|updates?)\b|show\s+me\s+(?:the\s+)?news|headlines)\b",
    re.IGNORECASE,
)


def _info_tool_extract_named_entities(text: str) -> list[str]:
    """Lightweight named-entity scan: capitalized run-ons + known ticker shapes.

    The classifier doesn't need perfect NER — it just needs to know whether
    the message names a specific public subject (entity) vs. asks for a
    stable concept (no specific subject)."""
    raw = (text or "").strip()
    if not raw:
        return []
    # Sentence-leading question/imperative verbs we never want to count as
    # entities even when capitalized ("Who else was there?" / "Compare X").
    _SKIP = {
        "what", "why", "when", "how", "did", "do", "does", "is", "are",
        "was", "were", "has", "have", "had", "will", "can", "could",
        "should", "would", "tell", "give", "show", "explain", "the",
        "a", "an", "this", "that", "those", "these", "i", "we",
        # 2026-05-28 — extra skip tokens so the follow-up classifier sees a
        # "no new entity" signal for vague turns like "Who else was there?"
        # and so verb-led shopping/compare phrases ("Compare X and Y") don't
        # accidentally name themselves as the entity.
        "who", "compare", "find", "search", "look", "any", "best", "top",
    }
    out: list[str] = []
    for m in re.finditer(r"\b[A-Z][a-zA-Z]+(?:\s+[A-Z][a-zA-Z]+){0,4}\b", raw):
        cand = m.group(0).strip()
        first_word = cand.split()[0].lower() if cand else ""
        low = cand.lower()
        if low in _SKIP:
            continue
        # If the first word is a skip verb (Compare/Find/...) but the rest
        # is a real entity, return only the rest so "Compare VGT" → "VGT".
        if first_word in _SKIP and len(cand.split()) > 1:
            tail = " ".join(cand.split()[1:]).strip()
            if tail:
                out.append(tail)
            continue
        out.append(cand)
    for m in re.finditer(r"\b[A-Z]{2,5}\b", raw):
        tok = m.group(0)
        if tok not in {"WHAT", "DID", "WAS", "IS", "ARE", "WHY", "WHO", "HOW"}:
            out.append(tok)
    # Dedupe preserving order.
    seen = set()
    deduped: list[str] = []
    for entry in out:
        key = entry.lower()
        if key in seen:
            continue
        seen.add(key)
        deduped.append(entry)
    return deduped[:8]


def _info_tool_clean_in_city_capture(capture: str) -> str:
    """Strip non-city tail words from an in/near/around capture."""
    raw = (capture or "").strip().strip(".,!?;:")
    if not raw:
        return ""
    parts = raw.split()
    while parts and parts[-1].lower() in _INFO_TOOL_NON_CITY_TAIL_WORDS:
        parts.pop()
    cleaned = " ".join(parts).strip()
    if not cleaned or cleaned.lower() in _INFO_TOOL_NON_CITY_TAIL_WORDS:
        return ""
    return cleaned


_INFO_TOOL_LOCATION_ACRONYMS = frozenset({"uci", "ucla", "usc", "csuf", "csulb"})


def _info_tool_title_case_location(cleaned: str) -> str:
    """Title-case a parsed city for display + downstream regex."""
    if not cleaned:
        return ""
    out_parts: list[str] = []
    for part in cleaned.split():
        low = part.lower()
        if low in _INFO_TOOL_LOCATION_ACRONYMS:
            out_parts.append(part.upper())
        elif len(part) == 2 and part.isalpha():
            out_parts.append(part.upper())
        else:
            out_parts.append(part[:1].upper() + part[1:].lower())
    return " ".join(out_parts)


def _info_tool_extract_location_in_text(text: str) -> str:
    """Best-effort location extraction. Re-uses the weather helper so we
    don't drift from the existing weather location parser."""
    raw = (text or "").strip()
    if not raw:
        return ""
    try:
        loc = extract_weather_location(raw)
        if loc:
            return clean_location_text(loc) or ""
    except Exception:
        pass
    # Fallback: scan all in/near/around captures and keep the last valid one
    # so "coffee near irvine" → "irvine" and "near me in fountain valley" →
    # "fountain valley" (not "me").
    location = ""
    for m in _INFO_TOOL_LOCAL_IN_CITY_RE.finditer(raw):
        candidate = _info_tool_clean_in_city_capture(m.group("place") or "")
        if not candidate:
            continue
        if _INFO_TOOL_VENUE_RE.fullmatch(candidate):
            continue
        location = candidate
    if location:
        return _info_tool_title_case_location(location)
    return ""


_INFO_TOOL_TIMEZONE_ALIASES = {
    "tokyo": ("Tokyo", "Asia/Tokyo"),
    "japan": ("Japan", "Asia/Tokyo"),
    "ho chi minh city": ("Ho Chi Minh City", "Asia/Ho_Chi_Minh"),
    "ho chi minh": ("Ho Chi Minh City", "Asia/Ho_Chi_Minh"),
    "hcmc": ("Ho Chi Minh City", "Asia/Ho_Chi_Minh"),
    "saigon": ("Ho Chi Minh City", "Asia/Ho_Chi_Minh"),
    "sai gon": ("Ho Chi Minh City", "Asia/Ho_Chi_Minh"),
    "vietnam": ("Vietnam", "Asia/Ho_Chi_Minh"),
    "viet nam": ("Vietnam", "Asia/Ho_Chi_Minh"),
    "paris": ("Paris", "Europe/Paris"),
    "london": ("London", "Europe/London"),
    "new york": ("New York", "America/New_York"),
    "nyc": ("New York", "America/New_York"),
    "irvine": ("Irvine", "America/Los_Angeles"),
    "orange county": ("Orange County", "America/Los_Angeles"),
    "los angeles": ("Los Angeles", "America/Los_Angeles"),
    "la": ("Los Angeles", "America/Los_Angeles"),
}


def _normalize_info_tool_time_location(location: str | None) -> str:
    loc = clean_location_text(location)
    if not loc:
        return ""
    key = re.sub(r"[^\w\s]", " ", loc.lower())
    key = re.sub(r"\s+", " ", key).strip()
    alias = _INFO_TOOL_TIMEZONE_ALIASES.get(key)
    if alias:
        return alias[0]
    return loc


def _info_tool_time_location_metadata(location: str | None) -> dict:
    raw_loc = clean_location_text(location)
    normalized = _normalize_info_tool_time_location(raw_loc)
    key = re.sub(r"[^\w\s]", " ", raw_loc.lower())
    key = re.sub(r"\s+", " ", key).strip()
    alias = _INFO_TOOL_TIMEZONE_ALIASES.get(key)
    timezone_name = alias[1] if alias else ""
    failed_reason = ""
    if raw_loc and not timezone_name:
        failed_reason = "not_in_static_alias_map_geocode_fallback"
    if not raw_loc:
        normalized = ""
        failed_reason = "no_location_in_text_using_default_or_followup"
    return {
        "time_tool_location_raw": raw_loc,
        "time_tool_location_normalized": normalized,
        "timezone_resolved": timezone_name,
        "timezone_resolution_failed_reason": failed_reason,
    }


def _info_tool_extract_time_location(text: str) -> str:
    """Extract just the city/timezone slot from time/date utility queries.

    Do not pass the whole utterance (e.g. "What time is it in Tokyo right
    now?") to the time handler; geocoding that whole string is what produced
    "I couldn't recognize that location." for otherwise common places.
    """
    raw = (text or "").strip()
    if not raw:
        return ""
    prefix = r"(?:hey vera[\s,]+|vera[\s,]+|can you\s+|could you\s+|would you\s+|please\s+)*"
    patterns = [
        rf"^{prefix}what(?:'s|s|\s+is)?\s+the\s+time\s+(?:right\s+now\s+)?(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}what\s+time\s+is\s+it\s+(?:right\s+now\s+)?(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}tell\s+me\s+the\s+time\s+(?:right\s+now\s+)?(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}current\s+time\s+(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}time\s+(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}what(?:'s|s|\s+is)?\s+the\s+(?:day|date)\s+(?:in|at|for)\s+(?P<location>.+)$",
        rf"^{prefix}what\s+(?:day|date)\s+is\s+it\s+(?:in|at|for)\s+(?P<location>.+)$",
    ]
    for pattern in patterns:
        m = re.match(pattern, raw, flags=re.IGNORECASE)
        if not m:
            continue
        loc = clean_location_text(m.group("location"))
        loc = re.sub(r"\b(?:right\s+now|now|today|currently)\b\s*$", "", loc, flags=re.IGNORECASE)
        return _normalize_info_tool_time_location(loc)
    return ""


def _classify_info_tool_deterministic(
    text: str,
    *,
    recent_news_context: dict | None = None,
    recent_sports_context: dict | None = None,
    session_id: str = "",
    location_available: bool = False,
) -> dict:
    """Deterministic, regex-only single-dispatch classifier for public-
    information requests.

    Returns the spec'd schema. Does NOT execute or mutate anything.
    ``route == "uncertain"`` means "fall through to the legacy pipeline".

    2026-05-31: this used to BE ``classify_info_tool``. The public
    ``classify_info_tool`` is now a thin wrapper (defined below) that
    runs this deterministic cascade first and then conditionally invokes
    the mini-LLM ``search_planner`` for messy / contextual / low-
    confidence info queries. The wrapper preserves the exact same return
    schema; the planner only ENRICHES the dict (adds
    ``search_planner_*`` fields, optionally overwrites ``query`` /
    ``normalized_query``, and — when deterministic returned "uncertain"
    — fills in ``route``). Callers don't need to change.
    """
    raw = (text or "").strip()
    out: dict = {
        "route": "uncertain",
        "tool": "none",
        "query": raw,
        "entities": [],
        "metric": None,
        "timeframe": None,
        "required_context": None,
        "confidence": 0.0,
        "reason": "",
    }
    if not raw:
        out["reason"] = "empty_text"
        return out

    low = raw.lower()
    entities = _info_tool_extract_named_entities(raw)
    out["entities"] = entities

    # ---- 1) PERSONAL/EMOTIONAL — never search ---------------------------
    if _INFO_TOOL_PERSONAL_NEWS_RE.search(raw):
        out.update(
            route="llm_only",
            tool="none",
            confidence=0.95,
            reason="personal_or_emotional_news_statement",
        )
        return out

    # ---- 1.25) SUPPORTED APP-ACTION GUARD (bucket 1 in priority order) --
    # 2026-06-01 — Patch: "Fix routing priority so supported VERA actions
    # are checked before generic info.search." When the transcript clearly
    # matches a music / checklist / timer / panel intent we defer the
    # entire info-tool cascade (including the mini-LLM search planner) so
    # the downstream LLM router / single-action heuristics can dispatch
    # the supported action. Without this guard a turn like "Can you play
    # Feather by Sabrina Carpenter?" leaks to general_web_search_tool
    # because no deterministic info family matches AND the search planner
    # treats "play Feather by Sabrina Carpenter" as a web search target.
    if looks_like_supported_app_action(raw):
        out.update(
            route="uncertain",
            tool="none",
            confidence=0.0,
            reason="defer_to_supported_app_action_intent",
        )
        return out

    # ---- 1.5) PRE-NEWS INFO NORMALIZER ----------------------------------
    # 2026-05-30: a tiny normalization layer that runs BEFORE the rest of
    # the cascade and intercepts the two cases the legacy pipeline gets
    # wrong today:
    #
    #   (a) PRODUCT RECOMMENDATIONS — "can you suggest me some webcam any
    #       price is fine? i have a zoom meeting next..." used to fall
    #       through to news.latest and produce a messy "X latest news"
    #       Serper query with a "News Results" panel. We now short-circuit
    #       these into general_web_search_tool with a normalized query like
    #       "best webcam for Zoom meeting", which classify_web_search_panel
    #       already maps to product_results_panel.
    #
    #   (b) NEWS FOLLOW-UPS WITH CONTEXT MERGE — "well it was in Garden
    #       Grove i think can you give me some news on that?" after a
    #       chemical-leak query was treated as a generic LLM follow-up,
    #       losing the prior topic. We now build a merged query like
    #       "Garden Grove Orange County chemical leak news" and route it as
    #       news_search_tool with pre_normalized=True so news.latest trusts
    #       the caller's query instead of rebuilding it from the deictic.
    #
    # Time / weather / finance / sports / location are NOT intercepted here
    # because the existing cascade handles them correctly today. Stick to
    # the smallest structural fix.
    try:
        _norm = _normalize_info_request(
            raw, recent_news_context=recent_news_context, location_available=location_available
        )
    except Exception as _norm_exc:  # noqa: BLE001
        print(f"[info_normalizer_error] {_norm_exc!r}", flush=True)
        _norm = None
    if isinstance(_norm, dict):
        _intent_type = str(_norm.get("intent_type") or "")
        # Ambiguity breadcrumb for "best webcam news" -style turns.
        if _norm.get("ambiguity_signals"):
            try:
                _log_info_query_ambiguous_warning(
                    session_id=session_id,
                    raw_user_text=raw,
                    chosen_intent=_intent_type,
                    competing_signals=list(_norm.get("ambiguity_signals") or []),
                )
            except Exception:
                pass
        if _intent_type == "product":
            normalized_q = str(_norm.get("normalized_query") or raw)
            out.update(
                route="general_web_search_tool",
                tool="web_search",
                confidence=float(_norm.get("confidence") or 0.9),
                reason=str(_norm.get("reason") or "product_recommendation_intent"),
                query=normalized_q,
            )
            out["product_intent"] = {
                "product_category": _norm.get("product_category"),
                "product_budget": _norm.get("product_budget"),
                "product_use_case": _norm.get("product_use_case"),
            }
            out["normalized_query"] = normalized_q
            try:
                _log_info_route_trace(
                    session_id=session_id,
                    raw_user_text=raw,
                    resolved_user_text=raw,
                    prior_info_context=recent_news_context if isinstance(recent_news_context, dict) else None,
                    info_intent_detected=True,
                    info_intent_type="product",
                    normalized_query=normalized_q,
                    entity=_norm.get("topic"),
                    product_category=_norm.get("product_category"),
                    product_budget=_norm.get("product_budget"),
                    product_use_case=_norm.get("product_use_case"),
                    confidence=float(_norm.get("confidence") or 0.9),
                    reason=str(_norm.get("reason") or ""),
                    serper_endpoint_used="search/shopping",
                )
            except Exception:
                pass
            return out
        if _intent_type == "news" and _norm.get("context_used"):
            normalized_q = _info_norm_dedupe_news_keywords(
                str(_norm.get("normalized_query") or raw)
            )
            ctx_topic = str(_norm.get("topic") or "")
            # Hard warning: user asked "news on that" but the merged query
            # doesn't include the prior topic. Should never happen for the
            # ctx-merge branch, but log it defensively so we catch regressions.
            try:
                if ctx_topic and ctx_topic.lower() not in normalized_q.lower():
                    _log_news_query_missing_topic_context_warning(
                        session_id=session_id,
                        raw_user_text=raw,
                        normalized_query=normalized_q,
                    )
            except Exception:
                pass
            out.update(
                route="news_search_tool",
                tool="news",
                confidence=float(_norm.get("confidence") or 0.85),
                reason=str(_norm.get("reason") or "news_followup_topic_merge"),
                query=normalized_q,
            )
            out["normalized_query"] = normalized_q
            out["news_pre_normalized"] = True
            # Entities for downstream news.latest finalize step.
            _entities: list[str] = []
            for piece in (_norm.get("entity"), _norm.get("location")):
                if not piece:
                    continue
                # location may be "Garden Grove, Orange County" -> split on comma.
                for part in str(piece).split(","):
                    part = part.strip()
                    if part and part not in _entities:
                        _entities.append(part)
            if _entities:
                out["entities"] = _entities
            try:
                _log_info_route_trace(
                    session_id=session_id,
                    raw_user_text=raw,
                    resolved_user_text=normalized_q,
                    prior_info_context=recent_news_context if isinstance(recent_news_context, dict) else None,
                    info_intent_detected=True,
                    info_intent_type="news",
                    normalized_query=normalized_q,
                    query_terms_added_from_context=[ctx_topic] if ctx_topic else [],
                    entity=_norm.get("entity"),
                    location=_norm.get("location"),
                    confidence=float(_norm.get("confidence") or 0.85),
                    reason=str(_norm.get("reason") or ""),
                    serper_endpoint_used="news",
                )
            except Exception:
                pass
            return out
        # intent_type == "location" / plain "news" without ctx merge /
        # "unknown" -> fall through to the existing cascade, which already
        # handles these correctly.

    # ---- 2) TIME / DATE — utility beats news ----------------------------
    if _INFO_TOOL_TIME_RE.search(raw):
        time_loc = _info_tool_extract_time_location(raw)
        time_meta = _info_tool_time_location_metadata(time_loc)
        out.update(
            route="time_tool",
            tool="time",
            query=(time_loc or raw),
            confidence=0.95,
            reason="explicit_time_question",
            **time_meta,
        )
        return out
    if _INFO_TOOL_DATE_RE.search(raw):
        time_loc = _info_tool_extract_time_location(raw)
        time_meta = _info_tool_time_location_metadata(time_loc)
        out.update(
            route="time_tool",
            tool="time",
            query=(time_loc or raw),
            confidence=0.9,
            reason="explicit_date_question",
            **time_meta,
        )
        return out

    # ---- 3) WEATHER — utility beats news --------------------------------
    if _INFO_TOOL_WEATHER_RE.search(raw):
        loc = _info_tool_extract_location_in_text(raw)
        out.update(
            route="weather_tool",
            tool="weather",
            confidence=0.95,
            reason="explicit_weather_question",
        )
        if loc:
            # Surface to caller via slots later; classifier just notes it here.
            out["query"] = loc
        else:
            out["required_context"] = ["location"]
        return out

    # ---- 4) HISTORICAL / EDUCATIONAL — LLM, never news ------------------
    try:
        if _is_historical_or_educational_question(raw):
            out.update(
                route="llm_only",
                tool="none",
                confidence=0.9,
                reason="historical_or_educational_explanation",
            )
            return out
    except Exception:
        pass

    # ---- 5) FINANCE — quote vs analytics --------------------------------
    if _INFO_TOOL_FINANCE_QUOTE_RE.search(raw) and not is_finance_analytics_query(raw):
        out.update(
            route="finance_quote_tool",
            tool="finance_quote",
            confidence=0.9,
            reason="explicit_finance_quote_request",
        )
        return out
    # Finance-search supplemental detection. `is_finance_analytics_query` is
    # the source-of-truth for the classic analytics keywords (drawdown,
    # Sharpe, CAGR, "past N years return", …). On top of that we accept:
    #   * "52-week high/low" patterns (range-based historical questions).
    #   * "compare <TICKER> and <TICKER>" with a finance noun (performance,
    #     return, drawdown) — otherwise the shopping regex below would steal
    #     it, since "compare A and B" also matches a generic comparison.
    _has_ticker_pair = bool(
        re.search(r"\b[A-Z]{2,5}\b[^A-Z]{0,30}\b[A-Z]{2,5}\b", raw)
    )
    _has_finance_noun = bool(
        re.search(
            r"\b(?:performance|return|returns|drawdown|volatility|cagr|sharpe|yield|gain|loss)\b",
            low,
        )
    )
    _looks_like_52_week = bool(
        re.search(
            r"\b52[-\s]?week\b|\b52\s*week\s+(?:high|low|range)\b",
            low,
        )
    )
    _looks_like_compare_perf = bool(
        re.search(r"\bcompare\b[^.?!]*\bperformance\b", low)
        and _has_ticker_pair
    )
    if (
        is_finance_analytics_query(raw)
        or _looks_like_52_week
        or _looks_like_compare_perf
    ):
        # Try to surface a timeframe/metric for downstream logs.
        metric_match = re.search(
            r"\b(drawdown|sharpe|sortino|alpha|beta|volatility|cagr|return|returns|yield|performance|low|high)\b",
            low,
        )
        timeframe_match = re.search(
            r"\b(?:past|last|over\s+the\s+past|over\s+the\s+last|trailing)\s+\d+\s+"
            r"(?:day|days|week|weeks|month|months|year|years)\b"
            r"|\b\d+\s*(?:d|w|mo|m|y|yr|yrs|year|years)[-\s]?(?:return|performance|drawdown|volatility|high|low)?\b"
            r"|\bytd\b|\ball[-\s]?time\b|\b52[-\s]?week\b",
            low,
        )
        out.update(
            route="finance_search_tool",
            tool="web_search",  # delegated to finance.analytics + serper
            confidence=0.85,
            reason="finance_historical_or_analytics_question",
            metric=(metric_match.group(1) if metric_match else None),
            timeframe=(timeframe_match.group(0) if timeframe_match else None),
        )
        return out

    # ---- 6) FOLLOW-UP — pronoun/deictic + recent context ----------------
    # This intentionally runs before explicit/current-news upgrades. A turn
    # like "Was he part of OpenAI?" contains a named entity ("OpenAI"), but
    # the pronoun "he" is dependent on the recent Elon Musk/OpenAI context and
    # should stay LLM-first unless the user asks for freshness/sources.
    has_ctx = bool(
        isinstance(recent_news_context, dict) and recent_news_context
    )
    pronoun_lead = bool(_INFO_TOOL_PRONOUN_RE.search(raw))
    fresh_marker = bool(_INFO_TOOL_FRESH_FOLLOWUP_RE.search(raw))
    if has_ctx and pronoun_lead:
        ctx_entities = [
            str(e).strip().lower()
            for e in (recent_news_context.get("entities") or [])
            if str(e).strip()
        ]
        ctx_blob = " ".join(
            str(recent_news_context.get(k) or "")
            for k in ("topic", "resolved_topic", "answer_summary", "query")
        ).lower()
        novel_entities = [
            e for e in entities
            if e.lower() not in ctx_entities and e.lower() not in ctx_blob
        ]
        if fresh_marker:
            out.update(
                route="followup_search",
                tool="news",
                confidence=0.75,
                reason="fresh_source_followup_with_pronoun",
            )
            return out
        if not novel_entities:
            out.update(
                route="followup_llm",
                tool="none",
                confidence=0.84,
                reason="interpretive_pronoun_followup",
            )
            return out

    # ---- 7) EXPLICIT NEWS / BROAD NEWS ----------------------------------
    if _INFO_TOOL_EXPLICIT_NEWS_RE.search(raw):
        out.update(
            route="news_search_tool",
            tool="news",
            confidence=0.9,
            reason="explicit_news_request",
        )
        return out

    # ---- 8) SPORTS — sport-aware router with web fallback --------------
    # 2026-05-30: the legacy branch below was an NBA-heavy regex pair that
    # collapsed every sports turn into the generic media_tabs "Search Results"
    # panel. We now run the sport-aware classifier FIRST so tennis players,
    # tournament names, follow-ups, and pronoun resolution all get a proper
    # sports route. The legacy regex stays as a last-resort safety net so we
    # never regress recognized team names that the classifier missed.
    try:
        _sports_intent = classify_sports_intent(
            raw, recent_sports_context=recent_sports_context
        )
    except Exception as _sport_exc:  # noqa: BLE001
        print("[sports_router] classifier_exception:", _sport_exc, flush=True)
        _sports_intent = None
    if isinstance(_sports_intent, dict) and _sports_intent.get("is_sports"):
        if _sports_intent.get("needs_clarification"):
            out.update(
                route="sports_clarification_needed",
                tool="none",
                confidence=float(_sports_intent.get("confidence") or 0.6),
                reason=_sports_intent.get("reason") or "sports_pronoun_no_context",
            )
            out["sports_intent"] = _sports_intent
            return out
        action_name = _sports_action_name_for_intent(_sports_intent)
        out.update(
            route="sports_tool",
            tool="sports",
            confidence=float(_sports_intent.get("confidence") or 0.85),
            reason=_sports_intent.get("reason") or "sports_intent_detected",
        )
        out["sports_intent"] = _sports_intent
        out["sports_action_name"] = action_name
        return out
    if (
        _INFO_TOOL_SPORTS_TEAM_RE.search(raw)
        and _INFO_TOOL_SPORTS_VERB_RE.search(raw)
    ):
        out.update(
            route="general_web_search_tool",
            tool="web_search",
            confidence=0.85,
            reason="sports_team_question_web_search_fallback_legacy",
        )
        return out

    # ---- 9) SHOPPING / RECOMMENDATION -----------------------------------
    if _INFO_TOOL_SHOPPING_RE.search(raw):
        out.update(
            route="general_web_search_tool",
            tool="web_search",
            confidence=0.85,
            reason="shopping_or_recommendation_web_search",
        )
        return out

    # ---- 10) SHOW / EPISODE / FACTOID -----------------------------------
    if _INFO_TOOL_SHOW_RE.search(raw):
        out.update(
            route="general_web_search_tool",
            tool="web_search",
            confidence=0.8,
            reason="show_or_episode_question_web_search",
        )
        return out

    # ---- 10.75) WORK-MODE SCHEDULE / PLAN FOLLOW-UP --------------------
    # "is gym at 9:20 too late?" contains ``gym`` which matches the venue
    # noun list — answer from visible plan context via LLM, not Serper.
    if looks_like_work_mode_schedule_followup(raw):
        out.update(
            route="llm_only",
            tool="none",
            confidence=0.92,
            reason="work_mode_schedule_followup_not_venue_search",
        )
        return out

    # ---- 11) LOCAL — "near me" needs location; "in <city>" does not ----
    if _INFO_TOOL_VENUE_RE.search(raw):
        near_me_flag = bool(_INFO_TOOL_NEAR_ME_RE.search(raw))
        loc_in_text = _info_tool_extract_location_in_text(raw)
        if near_me_flag and not loc_in_text and not location_available:
            out.update(
                route="clarification_needed",
                tool="none",
                confidence=0.9,
                reason="local_venue_query_missing_location",
                required_context=["location"],
            )
            return out
        out.update(
            route="general_web_search_tool",
            tool="web_search",
            confidence=0.85,
            reason="local_venue_query_web_search",
        )
        if loc_in_text:
            out["query"] = f"{raw} near {loc_in_text}" if "near" not in low else raw
        return out

    # ---- 11.5) PRE-SEARCH SANITY GATE (2026-06-01) ---------------------
    # If we reach here the deterministic cascade has rejected every
    # dedicated info family (time / weather / finance / news / sports /
    # shopping / show / local venue). That means the only candidates
    # below are (a) `route="uncertain"` plus the mini-LLM search planner,
    # which can promote uncertain -> general_web_search_tool, or (b) the
    # downstream LLM router via `vera.route_action`. For a turn that
    # carries no positive "search reason" AND looks like a conceptual
    # explanation / definition / interpretation request, we short-
    # circuit to `route="llm_only"` so the general LLM answers from chat
    # context. This is the patch-spec rule 3 ("If has_search_need(text)
    # is false and the message looks like explanation/interpretation,
    # return llm_only / voice.answer"). Rule 1 ("If deterministic route
    # is already a supported action or dedicated live-info tool, keep
    # it") is satisfied by placement: this gate only runs AFTER every
    # dedicated route has had its chance.
    if (
        looks_like_explanation_or_interpretation(raw)
        and not has_search_need(raw)
    ):
        out.update(
            route="llm_only",
            tool="none",
            confidence=0.85,
            reason="explanation_or_interpretation_no_search_need",
        )
        return out

    # ---- 12) DEFAULT — let legacy pipeline decide ----------------------
    # We intentionally return "uncertain" here so the dispatcher can fall
    # through to detect_news_route_intent / vera.route_action. The legacy
    # path is the single point that decides current_fact_search vs general
    # LLM for ambiguous turns; we don't want to overrule it without strong
    # evidence.
    out["reason"] = "no_confident_pick_falls_through"
    return out


# 2026-05-31 ADAPTIVE MINI-LLM SEARCH PLANNER WRAPPER ----------------------
#
# The deterministic cascade above runs first; the wrapper below adds an
# adaptive second pass that calls the local LLM (vera) when the
# classification looks messy / contextual / low-confidence. See
# actions/search_planner.py for the decision matrix and prompt.
#
# Important guarantees:
#   * The wrapper preserves the original return schema. It only ADDS
#     ``search_planner_*`` fields and optionally overwrites ``query`` /
#     ``normalized_query`` / ``route`` for downstream consumers.
#   * It is strictly INFO-only. It does not affect app actions (music /
#     checklist / timer / panel / reasoning), because those routes never
#     pass through classify_info_tool in the first place.
#   * If ``vera`` is None (early startup) or the LLM call raises, we fall
#     back to the deterministic result and log the failure.
def _maybe_apply_search_planner(
    raw_user_text: str,
    classification: dict,
    *,
    recent_news_context: dict | None,
    recent_sports_context: dict | None,
    session_id: str,
) -> None:
    """Optionally invoke the mini-LLM search planner and merge its plan
    into ``classification`` (mutated in place). Always emits exactly one
    ``[search_planner_trace]`` log line.
    """
    det_confidence = float(classification.get("confidence") or 0.0)
    det_route = str(classification.get("route") or "")

    use_planner, skip_reason = _should_use_search_planner(
        raw_user_text,
        classification,
        recent_news_context=recent_news_context,
        recent_sports_context=recent_sports_context,
    )

    plan: dict | None = None
    planner_called = False
    # Read the module-level `vera` lazily — early-startup callers may run
    # before it's been initialized, which is fine: we'll just skip the
    # planner and fall back to deterministic.
    _vera = globals().get("vera")
    if use_planner and _vera is not None:
        planner_called = True
        plan = _run_search_planner(
            raw_user_text,
            _vera,
            classification=classification,
            recent_news_context=recent_news_context,
            recent_sports_context=recent_sports_context,
            session_id=session_id,
        )
        if plan is not None:
            _apply_search_plan(plan, classification)
    elif use_planner and _vera is None:
        # Planner WANTED to run but vera isn't loaded yet. Surface this
        # specifically so it's distinguishable from a deliberate skip.
        skip_reason = "planner_unavailable_vera_not_initialized"

    deterministic_fallback_used = not bool(
        classification.get("search_planner_applied")
    )

    _log_search_planner_decision(
        session_id=session_id,
        raw_user_text=raw_user_text,
        search_planner_considered=True,
        search_planner_called=planner_called,
        search_planner_skipped_reason="" if planner_called else skip_reason,
        deterministic_confidence=det_confidence,
        deterministic_route=det_route,
        search_planner_latency_ms=(
            plan.get("_latency_ms") if isinstance(plan, dict) else None
        ),
        search_planner_intent_type=(
            plan.get("intent_type") if isinstance(plan, dict) else ""
        ) or "",
        search_planner_normalized_queries=(
            plan.get("normalized_queries") if isinstance(plan, dict) else None
        ),
        search_planner_answer_policy=(
            plan.get("answer_policy") if isinstance(plan, dict) else ""
        ) or "",
        deterministic_fallback_used=deterministic_fallback_used,
        final_search_queries=(
            classification.get("search_planner_normalized_queries")
            or [classification.get("query") or raw_user_text]
        ),
        final_result_kind="",  # filled in by downstream panel logic
        answer_confidence="",  # filled in by downstream answer logic
    )


def classify_info_tool(
    text: str,
    *,
    recent_news_context: dict | None = None,
    recent_sports_context: dict | None = None,
    session_id: str = "",
    location_available: bool = False,
) -> dict:
    """Public single-dispatch classifier for public-information requests.

    Runs the deterministic cascade in
    :func:`_classify_info_tool_deterministic`, then optionally invokes
    the mini-LLM search planner via :func:`_maybe_apply_search_planner`
    when the deterministic result looks messy / contextual / low-
    confidence. Return schema is unchanged; the wrapper only ADDS
    ``search_planner_*`` keys and optionally overwrites ``query`` /
    ``normalized_query`` / ``route`` when the planner produced a
    confident plan.
    """
    out = _classify_info_tool_deterministic(
        text,
        recent_news_context=recent_news_context,
        recent_sports_context=recent_sports_context,
        session_id=session_id,
        location_available=location_available,
    )
    # Capture the deterministic verdict BEFORE the planner can rewrite
    # `route` - the 2026-06-01 search-necessity gate below only demotes
    # planner UPGRADES from "uncertain" to "general_web_search_tool"
    # (deterministic shopping / show / local-venue routes have already
    # validated their own search need and must stay untouched).
    deterministic_route_pre_planner = str(out.get("route") or "")
    # Defensive: never let a planner failure break the deterministic
    # cascade. classify_info_tool is on the hot path for every info turn.
    try:
        _maybe_apply_search_planner(
            text or "",
            out,
            recent_news_context=recent_news_context,
            recent_sports_context=recent_sports_context,
            session_id=session_id,
        )
    except Exception as _planner_exc:  # noqa: BLE001
        print(f"[search_planner_error] {_planner_exc!r}", flush=True)

    # ---- POST-PLANNER SEARCH-NECESSITY GATE (2026-06-01) ---------------
    # Spec rule 2 ("If planner proposes general_web_search_tool, only
    # accept it when has_search_need(text) is true") and rule 4 ("If
    # unclear, prefer llm_only over web.search unless the user explicitly
    # asked to search or needs current/live data"). Implemented as a
    # narrow demotion: ONLY fire when (a) the planner upgraded uncertain
    # to general_web_search_tool, AND (b) the raw transcript carries no
    # positive search reason. Deterministic shopping / show / local-venue
    # turns (which emit general_web_search_tool from the cascade itself)
    # are never demoted because `deterministic_route_pre_planner` is not
    # "uncertain" for them.
    if (
        str(out.get("route") or "") == "general_web_search_tool"
        and deterministic_route_pre_planner in ("uncertain", "")
        and not has_search_need(text or "")
    ):
        previous_reason = str(out.get("reason") or "")
        out["route"] = "llm_only"
        out["tool"] = "none"
        out["reason"] = "|".join(
            part for part in (
                previous_reason,
                "search_necessity_gate_demoted_no_positive_search_need",
            ) if part
        )
        out["search_necessity_gate_demoted"] = True
        try:
            print(
                "[search_necessity_gate] "
                + json.dumps(
                    {
                        "session_id": (session_id or "")[:64],
                        "raw_user_text": (text or "")[:200],
                        "previous_route": "general_web_search_tool",
                        "demoted_route": "llm_only",
                        "previous_reason": previous_reason[:160],
                        "explanation_shape": bool(
                            looks_like_explanation_or_interpretation(text or "")
                        ),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass

    return out


def build_route_from_info_tool(
    text: str, classification: dict, session_id: str = ""
) -> dict | None:
    """Translate a `classify_info_tool` result into a route dict that the
    existing `execute_structured_action` / `prepare_streaming_structured_action`
    pipelines can dispatch.

    Returns None when the classifier says "uncertain", "llm_only",
    "followup_llm", or "followup_search" — the caller falls through to the
    legacy pipeline (LLM router + general LLM) for those, because they
    don't need a structured action.
    """
    if not classification:
        return None
    route = classification.get("route")
    if route in (None, "", "uncertain", "llm_only", "followup_llm", "followup_search"):
        return None

    raw = (text or "").strip()

    if route == "clarification_needed":
        required = list(classification.get("required_context") or [])
        if "location" in required:
            # Treat as a synthetic web.search action that the standard
            # needs_followup handling re-asks for. Reuse the location slot
            # name so the same pending-action plumbing works.
            return {
                "domain": "web",
                "is_action_request": True,
                "action_name": "web.search",
                "slots": {"user_text": raw, "query": raw},
                "needs_followup": True,
                "missing_slot": "location",
            }
        return None

    if route == "time_tool":
        loc_hint = ""
        if classification.get("query") and classification.get("query") != raw:
            loc_hint = str(classification.get("query") or "")
        if not loc_hint:
            loc_hint = _info_tool_extract_time_location(raw)
        location = clean_location_text(loc_hint) or ""
        return {
            "domain": "utility",
            "is_action_request": True,
            "action_name": "time.current",
            "slots": {"location": location},
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "weather_tool":
        loc_hint = (
            classification.get("query")
            if classification.get("query") and classification.get("query") != raw
            else ""
        )
        return weather_action_route_from_text(raw, location_hint=loc_hint, session_id=session_id)

    if route == "finance_quote_tool":
        return {
            "domain": "finance",
            "is_action_request": True,
            "action_name": "finance.quote",
            "slots": {"query": raw, "user_text": raw},
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "finance_search_tool":
        return {
            "domain": "finance",
            "is_action_request": True,
            "action_name": "finance.analytics",
            "slots": {"query": raw, "user_text": raw},
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "news_search_tool":
        # 2026-06-01 — defense-in-depth for the explicit general-news
        # intent override. heuristic_route_action catches these turns
        # first and short-circuits, but if a future refactor lets a
        # general "tell me the latest news"-style transcript reach the
        # info_tool classifier (which currently classifies it as
        # news_search_tool via the info.news regex), we still force the
        # BBC top-headlines route here instead of building a Serper
        # search query from the raw transcript ("can you tell me the
        # latest news?" -> Serper /news -> News12 weather results).
        if is_explicit_general_news_intent(raw):
            return {
                "domain": "news",
                "is_action_request": True,
                "action_name": "news.latest",
                "slots": {
                    "query": "",
                    "topic": "",
                    "entities": [],
                    "time_horizon": "",
                    "search_queries": [],
                    "broad_news_reset": False,
                    "force_top_headlines": True,
                    "source_preference": "bbc",
                    "count": 3,
                    "user_text": raw,
                },
                "needs_followup": False,
                "missing_slot": None,
            }
        # 2026-05-30: when the pre-news info normalizer (`normalize_info_request`)
        # built a merged query out of stored topic + new location, it stamps
        # `news_pre_normalized=True` on the classification. We promote that
        # query into the slot dict AND pre-fill `search_queries`/`entities`
        # so `_finalize_news_latest_slots` trusts the caller and skips the
        # deictic-rebuild branch that would otherwise blow our merged query
        # away.
        pre_normalized = bool(classification.get("news_pre_normalized"))
        normalized_q = str(classification.get("normalized_query") or "").strip()
        entities = list(classification.get("entities") or [])
        slot_query = normalized_q if (pre_normalized and normalized_q) else raw
        slots: dict[str, Any] = {"query": slot_query, "user_text": raw}
        if pre_normalized and normalized_q:
            slots["pre_normalized"] = True
            slots["search_queries"] = [normalized_q]
            slots["normalized_query"] = normalized_q
            if entities:
                slots["entities"] = entities
        return {
            "domain": "news",
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": slots,
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "general_web_search_tool":
        # 2026-06-01 — Defense-in-depth for the priority-order patch.
        # _classify_info_tool_deterministic already short-circuits when
        # looks_like_supported_app_action(raw) is true, but the mini-LLM
        # search planner can still overwrite route to
        # general_web_search_tool in _apply_search_plan(). Re-check here
        # so a planner mistake never sends a clear music / checklist /
        # timer / panel intent to Serper. Returning None lets the caller
        # (route_action_request) fall through to the LLM router, which
        # has the proper music.play_track / timer.set / etc. dispatch.
        if looks_like_supported_app_action(raw):
            return None
        web_query = classification.get("query") or raw
        slots: dict[str, Any] = {"query": web_query, "user_text": raw}
        # Propagate product_intent so downstream panel classification +
        # logging can stamp result_kind=product / "Shopping Results" instead
        # of leaving it to inference on the raw user wording.
        if isinstance(classification.get("product_intent"), dict):
            slots["product_intent"] = dict(classification.get("product_intent") or {})
        if classification.get("normalized_query"):
            slots["normalized_query"] = str(classification.get("normalized_query") or "")
        return {
            "domain": "web",
            "is_action_request": True,
            "action_name": "web.search",
            "slots": slots,
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "sports_tool":
        sports_intent = classification.get("sports_intent") or {}
        action_name = classification.get("sports_action_name") or "web.sports_score"
        return {
            "domain": "sports",
            "is_action_request": True,
            "action_name": action_name,
            "slots": {
                "query": raw,
                "user_text": raw,
                "sports_intent": sports_intent,
            },
            "needs_followup": False,
            "missing_slot": None,
        }

    if route == "sports_clarification_needed":
        sports_intent = classification.get("sports_intent") or {}
        return {
            "domain": "sports",
            "is_action_request": True,
            "action_name": "web.sports_score",
            "slots": {
                "query": raw,
                "user_text": raw,
                "sports_intent": sports_intent,
                "needs_clarification": True,
            },
            "needs_followup": False,
            "missing_slot": None,
        }

    return None


def log_info_tool_route(
    session_id: str,
    text: str,
    classification: dict,
    *,
    dispatched_action: str = "",
    fell_through: bool = False,
    location_available: bool = False,
) -> None:
    """Structured log of every info-tool routing decision.

    Grep target: ``[info_tool_route]``. Emitted on EVERY turn that runs
    through `route_action_request`, regardless of whether the new
    classifier or the legacy pipeline actually dispatches.
    """
    try:
        print(
            "[info_tool_route] " + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "raw_user_text": (text or "")[:200],
                    "selected_route": str(classification.get("route") or ""),
                    "selected_tool": str(classification.get("tool") or ""),
                    "query": str(classification.get("query") or "")[:200],
                    "query_source": (
                        "current_user_text"
                        if (classification.get("query") or "").strip().lower()
                        == (text or "").strip().lower()
                        else "resolved_followup"
                        if classification.get("route")
                        in ("followup_llm", "followup_search")
                        else "none"
                    ),
                    "entities": list(classification.get("entities") or [])[:8],
                    "metric": classification.get("metric"),
                    "timeframe": classification.get("timeframe"),
                    "time_tool_location_raw": str(
                        classification.get("time_tool_location_raw") or ""
                    )[:120],
                    "time_tool_location_normalized": str(
                        classification.get("time_tool_location_normalized") or ""
                    )[:120],
                    "timezone_resolved": str(
                        classification.get("timezone_resolved") or ""
                    )[:120],
                    "timezone_resolution_failed_reason": str(
                        classification.get("timezone_resolution_failed_reason") or ""
                    )[:160],
                    "required_context": list(classification.get("required_context") or []),
                    "clarification_needed": classification.get("route")
                    == "clarification_needed",
                    "confidence": float(classification.get("confidence") or 0.0),
                    "reason": str(classification.get("reason") or ""),
                    "dispatched_action": dispatched_action,
                    "fell_through_to_legacy_pipeline": bool(fell_through),
                    "skipped_news_reason": (
                        classification.get("reason") or ""
                        if classification.get("route")
                        in ("time_tool", "weather_tool", "finance_quote_tool",
                            "llm_only")
                        else ""
                    ),
                    "skipped_specialized_tool_reason": (
                        "general_web_search_fallback"
                        if classification.get("route") == "general_web_search_tool"
                        else ""
                    ),
                    "location_available": bool(location_available),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        try:
            print("[info_tool_route] log_serialization_failed", flush=True)
        except Exception:
            pass


def _route_debug_finance_snapshot(text: str) -> dict:
    """Diagnostic-only finance/ticker snapshot for news-router hijack traces."""
    raw = (text or "").strip()
    low = raw.lower()
    metric = ""
    metric_match = re.search(
        r"\b(drawdown|sharpe|sortino|alpha|beta|volatility|cagr|return|returns|yield|dividend|earnings|eps|revenue)\b",
        low,
        re.IGNORECASE,
    )
    if metric_match:
        metric = metric_match.group(1).lower()
    timeframe_match = re.search(
        r"\b(?:past|last)\s+\d+\s+(?:day|days|week|weeks|month|months|year|years)\b"
        r"|\b\d+\s*(?:d|w|mo|m|y|yr|yrs|year|years)\b"
        r"|\bytd\b|\ball[-\s]?time\b|\bsince\s+\d{4}\b",
        raw,
        re.IGNORECASE,
    )
    ticker = ""
    ticker_match = re.search(r"\b[A-Z]{2,5}\b", raw)
    if ticker_match:
        ticker = ticker_match.group(0)
    elif metric or is_finance_analytics_query(raw):
        # ASR commonly lowercases tickers; capture short tokens near finance
        # phrasing for diagnostics only.
        for tok in re.findall(r"\b[a-z]{2,5}\b", low):
            if tok not in {
                "can", "you", "the", "and", "past", "when", "was", "were",
                "what", "big", "draw", "down", "for", "years", "year", "it",
            }:
                ticker = tok.upper()
                break
    return {
        "finance_query_detected": bool(
            is_finance_analytics_query(raw)
            or metric
            or (ticker and re.search(r"\b(?:stock|etf|fund|ticker|market|price|quote)\b", low))
        ),
        "finance_ticker": ticker,
        "finance_metric": metric,
        "finance_timeframe": timeframe_match.group(0) if timeframe_match else "",
    }


def log_route_debug(
    session_id: str,
    text: str,
    *,
    stage: str,
    current_info_intent: dict | None = None,
    news_intent: dict | None = None,
    selected_route: str = "",
    selected_action_name: str = "",
    should_search: bool | None = None,
    serper_called: bool | None = None,
    used_recent_news_context: bool | None = None,
    ignored_recent_news_context_reason: str = "",
    cleared_recent_news_context: bool = False,
    final_answer_source: str = "",
    note: str = "",
) -> None:
    """Structured diagnostic line for route-order investigations.

    This is intentionally side-effect free: it calls only pure classifiers and
    snapshots existing context. Grep target: [route_debug].
    """
    try:
        raw = (text or "").strip()
        ctx = get_recent_news_context(session_id) if session_id else None
        if current_info_intent is None:
            current_info_intent = classify_current_info_intent(
                raw,
                recent_news_context=ctx,
                session_id=session_id,
            )
        sig = (current_info_intent or {}).get("signals") or {}
        if news_intent is None:
            news_intent = detect_news_route_intent(raw, recent_news_context=ctx)
        news_cls = (
            (news_intent or {}).get("intent_classification")
            if isinstance((news_intent or {}).get("intent_classification"), dict)
            else classify_news_search_intent(raw, recent_news_context=ctx)
        )
        finance = _route_debug_finance_snapshot(raw)
        app_action_detected = bool(
            _is_news_panel_open_request(raw)
            or _is_news_panel_close_request(raw)
            or _is_music_open_panel_request(raw)
            or _is_reasoning_close_panel_request(raw)
            or is_checklist_action_request(raw)
        )
        time_query_detected = bool(
            re.search(r"\b(?:what(?:'s|s| is)?\s+)?(?:the\s+)?time\b", raw, re.IGNORECASE)
            or re.search(r"\btime\s+in\s+[A-Za-z]", raw, re.IGNORECASE)
        )
        weather_query_detected = bool(re.search(r"\bweather\b", raw, re.IGNORECASE))
        route = selected_route or str((current_info_intent or {}).get("route") or "")
        inferred_should_search = bool((current_info_intent or {}).get("shouldSearch"))
        print(
            "[route_debug] "
            + json.dumps(
                {
                    "tag": "route_debug",
                    "stage": stage,
                    "text": raw[:240],
                    "session_id": (session_id or "")[:64],
                    "recent_news_context_available": bool(ctx),
                    "recent_news_context_topic": str((ctx or {}).get("topic") or ""),
                    "recent_news_context_entities": list((ctx or {}).get("entities") or [])[:8],
                    "previous_route_type": get_previous_news_route_type(session_id),
                    "personal_emotional_detected": bool(sig.get("personal_emotional_detected")),
                    "app_action_detected": app_action_detected,
                    "time_query_detected": time_query_detected,
                    "weather_query_detected": weather_query_detected,
                    "finance_query_detected": bool(finance.get("finance_query_detected")),
                    "finance_ticker": finance.get("finance_ticker") or "",
                    "finance_metric": finance.get("finance_metric") or "",
                    "finance_timeframe": finance.get("finance_timeframe") or "",
                    "explicit_news_command_detected": bool(sig.get("explicit_news_command_detected")),
                    "current_fact_search_detected": bool(sig.get("current_fact_question_detected")),
                    "raw_news_keyword_detected": bool((news_cls or {}).get("rawKeywordNewsDetected")),
                    "news_followup_candidate": bool(sig.get("followup_detected")),
                    "news_followup_type": str(sig.get("followup_type") or "none"),
                    "topic_similarity_to_recent_news": float(sig.get("topic_similarity_to_recent_news") or 0.0),
                    "strong_new_topic_detected": bool(sig.get("strong_new_topic_detected")),
                    "strong_new_topic_reason": str(sig.get("strong_new_topic_reason") or ""),
                    "selected_route": route,
                    "selected_action_name": selected_action_name,
                    "should_search": inferred_should_search if should_search is None else bool(should_search),
                    "serper_called": inferred_should_search if serper_called is None else bool(serper_called),
                    "used_recent_news_context": bool(used_recent_news_context) if used_recent_news_context is not None else False,
                    "ignored_recent_news_context_reason": ignored_recent_news_context_reason,
                    "cleared_recent_news_context": bool(cleared_recent_news_context),
                    "final_answer_source": final_answer_source or str((current_info_intent or {}).get("answer_source") or ""),
                    "news_intent_action": str((news_intent or {}).get("action") or ""),
                    "news_intent_reason": str((news_intent or {}).get("reason") or ""),
                    "note": note,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


# ─────────────────────────────────────────────────────────────────────────────
# Stage 1 — route-family classifier (PART 1 of the news router refactor)
#
# `classify_route_family(...)` is the single authoritative classifier that
# decides which family of routes a user turn belongs to BEFORE any news
# follow-up shortcut or recent_news_context lookup runs. It composes the
# existing helpers (`_is_personal_news_statement`,
# `_is_emotional_distress_statement`, `_is_utility_route_message`,
# `is_finance_analytics_query`, `_is_strong_new_topic_message`,
# `classify_current_info_intent`, the panel/checklist detectors) — it does
# NOT introduce parallel regex.
#
# In Stage 1 the result is consumed only by `log_route_family_debug(...)`
# (instrumentation only — no dispatcher change). Stages 2+ wire it into the
# wrappers and `route_action_request(...)`.
# ─────────────────────────────────────────────────────────────────────────────


def _route_family_default(raw_text: str) -> dict:
    """Spec-shape default for `classify_route_family(...)` results."""
    return {
        "routeFamily": "general_chat",
        "actionName": None,
        "shouldSearch": False,
        "shouldOpenNewsPanel": False,
        "shouldUseRecentNewsContext": False,
        "shouldStoreNewsContext": False,
        "shouldClearNewsContext": False,
        "topic": None,
        "entities": [],
        "resolvedQuestion": raw_text or None,
        "answerMode": "general_chat",
        "confidence": 0.5,
        "reason": "default_general_chat",
    }


def _detect_app_action_route_family(text: str) -> dict | None:
    """Detect explicit app/UI action route families WITHOUT side effects.

    Mirrors the high-level priorities of `heuristic_route_action(...)` but
    only the pure-regex helpers so this is safe to call from instrumentation
    paths. Returns None when no app action matches; callers fall through to
    the lower-priority families.

    Coverage is intentionally narrow in Stage 1 (the obvious panels +
    checklist + core music transport). A "general_chat" shadow result for a
    turn that the real router dispatches as a niche app action (e.g.
    `music.skip_next`) is an expected Stage-1 miss and will be widened in
    Stage 2 when we share a unified detector with `heuristic_route_action`.
    """
    raw = (text or "").strip()
    if not raw:
        return None

    def _hit(action_name: str, reason: str, *, open_news: bool = False) -> dict:
        out = _route_family_default(raw)
        out["routeFamily"] = "app_action"
        out["actionName"] = action_name
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = open_news
        out["answerMode"] = "utility"
        out["confidence"] = 0.95
        out["reason"] = reason
        return out

    try:
        if _is_news_panel_open_request(raw):
            return _hit("news.open_panel", "heuristic_news_open_panel", open_news=True)
        if _is_news_panel_close_request(raw):
            return _hit("news.close_panel", "heuristic_news_close_panel")
        if _is_music_open_panel_request(raw):
            return _hit("music.open_panel", "heuristic_music_open_panel")
        if _is_reasoning_close_panel_request(raw):
            return _hit("work_mode.reasoning_close_panel", "heuristic_reasoning_close_panel")
        checklist_action = is_checklist_action_request(raw)
        if checklist_action:
            return _hit(str(checklist_action), "heuristic_checklist_action")
    except Exception:
        pass

    lowered = raw.lower()
    try:
        if is_checklist_undo_request(raw):
            return None
        has_music_subject = bool(
            re.search(r"\b(?:music|song|track|spotify|playback)\b", lowered)
        )
        if has_music_subject:
            if re.search(r"\b(?:pause|stop)\b", lowered):
                return _hit("music.pause", "heuristic_music_pause")
            if re.search(r"\b(?:unpause|resume|continue|keep playing)\b", lowered):
                return _hit("music.resume", "heuristic_music_resume")
            if re.search(r"\b(?:close|hide|dismiss)\b", lowered):
                return _hit("music.close_panel", "heuristic_music_close_panel")
        if re.search(r"\b(?:volume|sound)\b", lowered):
            if re.search(r"\b(?:up|higher|increase|louder|raise|boost)\b", lowered):
                return _hit("music.volume_up", "heuristic_music_volume_up")
            if re.search(r"\b(?:down|lower|decrease|quieter|reduce|soften)\b", lowered):
                return _hit("music.volume_down", "heuristic_music_volume_down")
    except Exception:
        pass

    return None


# ─────────────────────────────────────────────────────────────────────────────
# Stage 2.5 — LLM-first follow-up policy
#
# After a news / current-fact thread starts, deictic factoid follow-ups
# ("Who else was there?", "When was that?", "Tell me more", "What happened
# after that?") should be answered LLM-first using the stored context, NOT
# re-routed to a fresh Serper search.
#
# A NEW search only triggers when the user EXPLICITLY asks for fresh
# retrieval ("any updates today", "what's the latest", "search ...",
# "verify that", "is there newer info", "was that confirmed later") or for
# source-specific coverage ("what does Reuters say", "find more sources",
# "show me the source", outlet-specific asks).
#
# `classify_route_family(...)` consumes the regexes/helpers below to
# promote eligible turns to the new `news_followup_llm_context` family.
# The Stage 2 gate allows that family through the LLM-from-context branch
# of the news follow-up shortcut.
# ─────────────────────────────────────────────────────────────────────────────


_NEWS_FOLLOWUP_OUTLET_TOKEN = (
    r"(?:reuters|bloomberg|bbc|cnn|nyt|new\s+york\s+times|the\s+new\s+york\s+times|"
    r"ap|ap\s+news|associated\s+press|wsj|wall\s+street\s+journal|cnbc|fox(?:\s+news)?|"
    r"the\s+guardian|guardian|the\s+washington\s+post|washington\s+post|wapo|npr|politico|"
    r"the\s+economist|financial\s+times|ft|al\s+jazeera|abc(?:\s+news)?|nbc(?:\s+news)?|"
    r"cbs(?:\s+news)?|espn|axios|the\s+verge|techcrunch|ars\s+technica|the\s+seattle\s+times)"
)


_NEWS_FOLLOWUP_EXPLICIT_FRESH_RE = re.compile(
    r"\b(?:"
    # "any updates [today|right now|on that/this/it]"
    r"any\s+updates?(?:\s+today|\s+right\s+now|\s+on\s+(?:that|this|it))?"
    # "what's the latest" / "what is the latest|newest|new" / "what's new"
    r"|what(?:['’]s|\s+is)\s+(?:the\s+)?(?:latest|newest|new)"
    r"|what(?:['’]s|\s+is)\s+new"
    # "is/are there (any) newer/new info/news/details/reports"
    r"|(?:is|are)\s+there\s+(?:any\s+)?(?:newer|new)\s+(?:info|information|news|details?|reports?|facts?)"
    # "can you verify/confirm/double-check/fact-check that?"
    r"|(?:can\s+you\s+)?(?:verify|confirm|double[-\s]?check|fact[-\s]?check)(?:\s+(?:that|this|it))?"
    # "was that confirmed later/since/after"
    r"|was\s+(?:that|this|it)\s+(?:confirmed|verified)\s+(?:later|since|after(?:\s+(?:that|this|then))?)"
    # explicit search verbs: "search for X", "look up X", "find more sources"
    r"|search\s+(?:for|who|what|when|where|why|how|the|more|news|online|google|web|up)"
    r"|look\s+(?:up|it\s+up|that\s+up|this\s+up|for|into)"
    r"|find\s+(?:more\s+)?(?:sources?|articles?|stories?|news|results?|info|information)"
    # "breaking news" as a fresh-retrieval marker too
    r"|breaking\s+news"
    r")\b",
    re.IGNORECASE,
)


_NEWS_FOLLOWUP_EXPLICIT_SOURCE_RE = re.compile(
    # "what does Reuters say" / "what did Reuters report"
    r"\bwhat\s+(?:does|do|did)\s+(?:the\s+)?" + _NEWS_FOLLOWUP_OUTLET_TOKEN
    + r"\s+(?:say|report|cover|think)\b"
    # "any Reuters coverage" / "any Bloomberg reporting"
    + r"|\bany\s+(?:the\s+)?" + _NEWS_FOLLOWUP_OUTLET_TOKEN
    + r"\s+(?:coverage|reporting|article|story|piece)\b"
    # "show me the source(s)" / "show me the link(s)"
    + r"|\bshow\s+me\s+the\s+(?:source|sources|link|links|article|articles)\b"
    # "what did/does the first/second/... article|result|source|story say"
    + r"|\b(?:what\s+(?:did|does)|read|open|show)\s+(?:the\s+)?"
    + r"(?:first|second|third|fourth|fifth|1st|2nd|3rd|4th|5th)\s+"
    + r"(?:article|result|source|story|headline|news\s+result)\s+(?:say)?\b",
    re.IGNORECASE,
)


_NEWS_FOLLOWUP_DEICTIC_FACTOID_RE = re.compile(
    r"^\s*(?:(?:ok(?:ay)?|so|hmm|well|but|and|just|hey|um|uh)\b\s*[,.!?]?\s*)*"
    r"(?:"
    # who [else|was|were|did|is|are|...] ...?  "who else was there", "who saw", "who joined"
    r"who(?:\s+(?:else|was|were|did|is|are|saw|met|attended|came|joined|accompanied|sued|killed|hit|hosted|spoke|signed|paid|left|right|now|then))?\b"
    # when [was|did|is|are|will|exactly|...] [that|this|it|he|she|they|the X]?
    r"|when\s+(?:was|did|is|are|will|exactly|precisely|specifically)?\s*(?:that|this|it|he|she|they|the\s+\w+)?\b"
    # where [was|did|is|are|will|...] [that|this|it|he|she|they|the X]?
    r"|where\s+(?:was|did|is|are|will|exactly|precisely|specifically)?\s*(?:that|this|it|he|she|they|the\s+\w+)?\b"
    # how [did|does|do|is|was|will|come] [that|this|it|he|she|they|the X]?
    r"|how\s+(?:did|does|do|is|are|was|were|will|come|come\s+to|exactly|precisely)\s*(?:that|this|it|he|she|they|the\s+\w+)?\b"
    # "what happened" / "what happened after/before/next/since/then"
    r"|what\s+happened(?:\s+(?:after|before|next|since|then|to\s+\w+))?\b"
    # "what (else|other|other things|other news|other info)"
    r"|what\s+(?:else|other|other\s+(?:things?|news|info|details?|stuff))\b"
    # "tell me more" / "more on/about X" / "anything else"
    r"|tell\s+me\s+more\b"
    r"|(?:any|anything|something)\s+else\b"
    r"|more\s+(?:on|about)\s+(?:that|this|it|him|her|them|the\s+\w+)\b"
    # bare conversational continuations: "and?", "go on", "continue"
    r"|(?:go\s+on|continue|keep\s+going|and(?:\?|$))\b"
    r")",
    re.IGNORECASE,
)


def _news_followup_should_search_again(text: str) -> bool:
    """Returns True only when the follow-up contains an EXPLICIT fresh-
    retrieval or source-specific marker (any updates / latest / verify /
    search / look up / find more sources / what does Reuters say / etc.).

    Used by `classify_route_family(...)` so that deictic factoid follow-ups
    stay LLM-first by default after a news/current-fact thread.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(
        _NEWS_FOLLOWUP_EXPLICIT_FRESH_RE.search(raw)
        or _NEWS_FOLLOWUP_EXPLICIT_SOURCE_RE.search(raw)
    )


def _news_followup_is_deictic_factoid(text: str) -> bool:
    """Returns True if the turn looks like a deictic factoid follow-up
    (who/when/where/how-it-happened/what-happened-after/tell-me-more/...)
    that should be answered LLM-first using stored context.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    return bool(_NEWS_FOLLOWUP_DEICTIC_FACTOID_RE.search(raw))


def classify_route_family(
    text: str,
    *,
    session_id: str | None = None,
    history: list[dict] | None = None,
    recent_news_context: dict | None = None,
) -> dict:
    """Stage 1 of the news router refactor (PART 1 of the spec).

    Single authoritative route-family classifier. Composes existing helpers
    so we do NOT duplicate regex. PURE — no side effects — safe to call from
    any wrapper, gate, or test.

    Priority (matches PART 3 of the spec):
        1. Personal / emotional / safety
        2. Explicit app/UI actions (panels, checklist, music transport)
        3. Time/date utility
        4. Weather utility
        5. Finance/ticker/market analytics
        6-9. News/current-info families (via classify_current_info_intent)
        10. General chat

    Returns a dict matching the PART 1 spec shape.

    NOTE: In Stage 1 the dispatchers (`try_prepare_streaming_action_messages`,
    `resolve_reply_if_not_general_llm`, `route_action_request`) ignore this
    result entirely. Only `log_route_family_debug(...)` consumes it for
    shadow comparison against the actually-selected route. Stage 2 wires the
    pre-flight guards; Stages 3+ make `route_action_request` dispatch
    news/current/follow-up from this classifier.
    """
    raw = (text or "").strip()
    out = _route_family_default(raw)
    if not raw:
        out["reason"] = "empty_text"
        return out

    has_ctx = isinstance(recent_news_context, dict) and bool(recent_news_context)

    # ---- PRIORITY 1: personal / emotional / safety -----------------------
    try:
        if _is_personal_news_statement(raw) or _is_emotional_distress_statement(raw):
            out["routeFamily"] = "personal_emotional"
            out["actionName"] = None
            out["shouldSearch"] = False
            out["shouldOpenNewsPanel"] = False
            out["shouldClearNewsContext"] = True
            out["answerMode"] = "general_chat"
            out["confidence"] = 0.95
            out["reason"] = "personal_or_emotional_statement"
            return out
    except Exception:
        pass

    # ---- PRIORITY 2: explicit app/UI actions -----------------------------
    app = _detect_app_action_route_family(raw)
    if app is not None:
        return app

    # ---- PRIORITY 3+4: time/weather utility ------------------------------
    try:
        util = _is_utility_route_message(raw)
    except Exception:
        util = {"detected": False, "reason": ""}
    util_reason = str((util or {}).get("reason") or "")
    if (util or {}).get("detected"):
        if util_reason == "time_or_date_query":
            out["routeFamily"] = "time_query"
            out["actionName"] = "time.current"
            out["answerMode"] = "utility"
            out["confidence"] = 0.9
            out["reason"] = "time_or_date_query"
            return out
        if util_reason == "weather_query":
            out["routeFamily"] = "weather_query"
            out["actionName"] = "weather.current"
            out["answerMode"] = "utility"
            out["confidence"] = 0.9
            out["reason"] = "weather_query"
            return out

    # ---- PRIORITY 5: finance/ticker/market analytics ---------------------
    try:
        finance_analytics = bool(is_finance_analytics_query(raw))
    except Exception:
        finance_analytics = False
    if finance_analytics:
        out["routeFamily"] = "finance_query"
        out["actionName"] = "finance.context"
        out["answerMode"] = "finance"
        out["confidence"] = 0.85
        out["reason"] = "finance_analytics_query"
        return out
    try:
        strong = _is_strong_new_topic_message(raw) or {}
    except Exception:
        strong = {}
    strong_reason = str(strong.get("reason") or "")
    if strong.get("detected") and strong_reason in {
        "finance_analytics_keyword",
        "finance_subject_no_news_shape",
    }:
        out["routeFamily"] = "finance_query"
        out["actionName"] = (
            "finance.quote"
            if strong_reason == "finance_subject_no_news_shape"
            else "finance.context"
        )
        out["answerMode"] = "finance"
        out["confidence"] = 0.8
        out["reason"] = strong_reason
        return out

    # ---- PRIORITIES 6-9: news/current-info via unified classifier --------
    try:
        ci = classify_current_info_intent(
            raw, recent_news_context=recent_news_context, session_id=session_id
        )
    except Exception:
        ci = {}
    ci_route = str((ci or {}).get("route") or "general_chat")
    entities = list((ci or {}).get("entities") or [])
    topic = (ci or {}).get("topic")
    confidence = float((ci or {}).get("confidence") or 0.5)
    reason = str((ci or {}).get("reason") or "")
    ci_should_search = bool((ci or {}).get("shouldSearch"))
    ci_should_open_panel = bool((ci or {}).get("shouldOpenNewsPanel"))

    # ---- Stage 2.5 policy override: LLM-first deictic factoid follow-ups -
    # When an active news/current-fact thread exists and the user asks a
    # deictic factoid follow-up ("Who else was there?", "When was that?",
    # "Tell me more", "What happened after that?") WITHOUT explicit fresh-
    # retrieval or source-specific markers, promote to
    # `news_followup_llm_context`. The Stage 2 gate allows this family
    # through the LLM-from-context branch of the news follow-up shortcut,
    # so the answer comes from the stored sources/summary instead of a
    # fresh Serper call.
    if (
        has_ctx
        and _news_followup_is_deictic_factoid(raw)
        and not _news_followup_should_search_again(raw)
    ):
        out["routeFamily"] = "news_followup_llm_context"
        out["actionName"] = None
        out["shouldSearch"] = False
        out["shouldOpenNewsPanel"] = False
        out["shouldUseRecentNewsContext"] = True
        out["shouldStoreNewsContext"] = False
        out["answerMode"] = "interpretive_followup"
        out["topic"] = topic or str(
            (recent_news_context or {}).get("topic") or ""
        ) or None
        out["entities"] = entities or list(
            (recent_news_context or {}).get("entities") or []
        )
        out["confidence"] = max(0.85, confidence)
        out["reason"] = "deictic_factoid_followup_llm_first"
        return out

    if ci_route == "explicit_news_headlines":
        out["routeFamily"] = "explicit_news_headlines"
        out["actionName"] = "news.latest"
        out["shouldSearch"] = ci_should_search
        out["shouldOpenNewsPanel"] = ci_should_open_panel
        out["shouldStoreNewsContext"] = ci_should_search
        out["answerMode"] = "broad_news_summary"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "explicit_news_headlines"
        return out
    if ci_route == "explicit_news_search":
        out["routeFamily"] = "explicit_news_search"
        out["actionName"] = "news.latest"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["shouldStoreNewsContext"] = True
        out["answerMode"] = "broad_news_summary"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "explicit_news_search"
        return out
    if ci_route == "current_fact_search":
        out["routeFamily"] = "current_fact_search"
        out["actionName"] = "news.latest"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["shouldStoreNewsContext"] = True
        out["answerMode"] = "current_fact_answer"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "current_fact_search"
        return out
    if ci_route == "interpretive_followup_llm":
        out["routeFamily"] = "news_followup_interpretive"
        out["actionName"] = None
        out["shouldSearch"] = False
        out["shouldUseRecentNewsContext"] = has_ctx
        out["answerMode"] = "interpretive_followup"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "interpretive_followup"
        return out
    if ci_route == "fresh_update_search":
        out["routeFamily"] = "news_followup_fresh_update"
        out["actionName"] = "news.latest"
        out["shouldSearch"] = True
        out["shouldOpenNewsPanel"] = True
        out["shouldUseRecentNewsContext"] = has_ctx
        out["shouldStoreNewsContext"] = True
        out["answerMode"] = "current_fact_answer"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "fresh_update_search"
        return out
    if ci_route == "source_specific_followup":
        out["routeFamily"] = "news_followup_source_specific"
        out["actionName"] = "news.latest"
        out["shouldSearch"] = ci_should_search
        out["shouldOpenNewsPanel"] = True
        out["shouldUseRecentNewsContext"] = True
        out["answerMode"] = "current_fact_answer"
        out["topic"] = topic
        out["entities"] = entities
        out["confidence"] = confidence
        out["reason"] = reason or "source_specific_followup"
        return out
    if ci_route == "personal_emotional":
        out["routeFamily"] = "personal_emotional"
        out["shouldClearNewsContext"] = True
        out["answerMode"] = "general_chat"
        out["confidence"] = confidence
        out["reason"] = reason or "personal_or_emotional_statement"
        return out

    # ---- PRIORITY 10: general chat fallback ------------------------------
    out["routeFamily"] = "general_chat"
    out["actionName"] = None
    out["shouldSearch"] = False
    out["shouldOpenNewsPanel"] = False
    out["answerMode"] = "general_chat"
    out["confidence"] = confidence
    out["reason"] = reason or "no_route_family_signal"
    return out


def log_route_family_debug(
    session_id: str | None,
    text: str,
    *,
    mode: str,
    route_family_result: dict | None = None,
    recent_news_context: dict | None = None,
    selected_action_name: str = "",
    selected_route_label: str = "",
    chosen_context_source: str = "",
    chosen_context_reason: str = "",
    immediate_topic: str = "",
    immediate_entities: list[str] | None = None,
    note: str = "",
) -> None:
    """Shadow-mode structured log for `classify_route_family(...)` (PART 14).

    Grep target: `[route_family_debug]`. Side-effect-free aside from the
    print itself; never raises.
    """
    try:
        raw = (text or "").strip()
        ctx = recent_news_context
        if ctx is None and session_id:
            try:
                ctx = get_recent_news_context(session_id)
            except Exception:
                ctx = None
        rf = route_family_result
        if rf is None:
            try:
                rf = classify_route_family(
                    raw,
                    session_id=session_id,
                    recent_news_context=ctx,
                )
            except Exception:
                rf = _route_family_default(raw)
        rf = rf if isinstance(rf, dict) else _route_family_default(raw)
        finance_snap = _route_debug_finance_snapshot(raw)
        try:
            personal_or_emotional = bool(
                _is_personal_news_statement(raw)
                or _is_emotional_distress_statement(raw)
            )
        except Exception:
            personal_or_emotional = False
        try:
            time_hit = bool(_UTILITY_TIME_QUERY_RE.search(raw))
        except Exception:
            time_hit = False
        try:
            weather_hit = bool(_UTILITY_WEATHER_QUERY_RE.search(raw))
        except Exception:
            weather_hit = False
        try:
            app_action_detected = bool(_detect_app_action_route_family(raw))
        except Exception:
            app_action_detected = False
        payload = {
            "tag": "route_family_debug",
            "mode": mode or "",
            "session_id": (session_id or "")[:64],
            "text": raw[:240],
            "routeFamily": str(rf.get("routeFamily") or ""),
            "actionName": str(rf.get("actionName") or ""),
            "shouldSearch": bool(rf.get("shouldSearch")),
            "shouldOpenNewsPanel": bool(rf.get("shouldOpenNewsPanel")),
            "shouldUseRecentNewsContext": bool(rf.get("shouldUseRecentNewsContext")),
            "shouldStoreNewsContext": bool(rf.get("shouldStoreNewsContext")),
            "shouldClearNewsContext": bool(rf.get("shouldClearNewsContext")),
            "answerMode": str(rf.get("answerMode") or ""),
            "topic": str(rf.get("topic") or "")[:120],
            "entities": list(rf.get("entities") or [])[:8],
            "confidence": float(rf.get("confidence") or 0.0),
            "reason": str(rf.get("reason") or ""),
            "personal_emotional_detected": personal_or_emotional,
            "app_action_detected": app_action_detected,
            "time_query_detected": time_hit,
            "weather_query_detected": weather_hit,
            "finance_query_detected": bool(finance_snap.get("finance_query_detected")),
            "finance_ticker": str(finance_snap.get("finance_ticker") or ""),
            "finance_metric": str(finance_snap.get("finance_metric") or ""),
            "recent_news_context_available": bool(ctx),
            "recent_news_context_topic": str((ctx or {}).get("topic") or "")[:120],
            "recent_news_context_entities": list((ctx or {}).get("entities") or [])[:8],
            "immediate_topic": immediate_topic or "",
            "immediate_entities": list(immediate_entities or [])[:8],
            "selected_action_name": selected_action_name or "",
            "selected_route_label": selected_route_label or "",
            "chosen_context_source": chosen_context_source or "",
            "chosen_context_reason": chosen_context_reason or "",
            "note": note or "",
        }
        print(
            "[route_family_debug] "
            + json.dumps(payload, ensure_ascii=False, default=str),
            flush=True,
        )
    except Exception:
        pass


def classify_news_route_for_turn(text: str, ctx: dict | None = None) -> dict:
    """Spec-shape, top-level route classifier for a single user turn.

    Returns:
        {
          route_classification: one of
              "current_fact_search"
            | "broad_news_headlines"
            | "topical_news_search"
            | "interpretive_followup_llm_first"
            | "fresh_update_followup"
            | "source_specific_followup"
            | "personal_news_statement"
            | "emotional_context"
            | "general_chat"
            | "ui_open_news_panel"
            | "ui_close_news_panel",
          serper_called: bool — whether this route is expected to hit the
              search API (True for current_fact_search, fresh_update_followup,
              source_specific_followup (when stored cards are insufficient),
              topical_news_search, broad_news_headlines).
          answer_from: "search" | "stored_source_context" | "llm" | "panel_only",
          reason: human-readable rationale.
          base_classification: the request-type label from
              classify_news_request_type for transparency.
        }

    This is the polish-spec "simpler rule" router. It's PURE — no side
    effects — and is safe to call from any pre-LLM guard, post-LLM guard,
    or test. The dispatching code reads `route_classification` to pick
    the right downstream path; the existing per-path implementations
    (`try_resolve_news_followup_streaming`, `_classify_news_followup_type`,
    `handle_news_request`) are unchanged.
    """
    raw = (text or "").strip()
    if not raw:
        return {
            "route_classification": "general_chat",
            "serper_called": False,
            "answer_from": "llm",
            "reason": "empty_text",
            "base_classification": "general_chat",
        }

    base = classify_news_request_type(raw)
    base_type = base.get("requestType") or "general_chat"

    # UI commands win immediately.
    if base_type == "ui_open_news_panel":
        return {
            "route_classification": "ui_open_news_panel",
            "serper_called": False,
            "answer_from": "panel_only",
            "reason": base.get("reason") or "ui_open_pattern",
            "base_classification": base_type,
        }
    if base_type == "ui_close_news_panel":
        return {
            "route_classification": "ui_close_news_panel",
            "serper_called": False,
            "answer_from": "panel_only",
            "reason": base.get("reason") or "ui_close_pattern",
            "base_classification": base_type,
        }
    if base_type == "personal_news_statement":
        return {
            "route_classification": "personal_news_statement",
            "serper_called": False,
            "answer_from": "llm",
            "reason": base.get("reason") or "personal_news_share",
            "base_classification": base_type,
        }
    if base_type == "emotional_context":
        return {
            "route_classification": "emotional_context",
            "serper_called": False,
            "answer_from": "llm",
            "reason": base.get("reason") or "emotional_distress",
            "base_classification": base_type,
        }

    has_ctx = isinstance(ctx, dict) and bool(ctx)
    low = raw.lower()

    # ---- Follow-up branch: only when we have recent_news_context to fall
    # back on. Without it, every interpretive question is just general chat
    # (no "stored sources" to lean on yet).
    if has_ctx:
        # Source-specific follow-up: "what did the first article say",
        # "any other sources", "links?", "from Reuters", "what does Reuters say"
        is_source_request_text = _is_news_source_request(raw)
        article_index_ask = bool(
            re.search(
                r"\bwhat (?:did|does) the (?:first|second|third|fourth|fifth|1st|2nd|3rd|4th|5th|top|first|other) "
                r"(?:article|source|headline|report|story)\b",
                low,
            )
        )
        if is_source_request_text or article_index_ask:
            stored_cards = bool(_stored_sources_have_cards(ctx))
            return {
                "route_classification": "source_specific_followup",
                # Re-search only when we don't have usable cards to answer from.
                "serper_called": not stored_cards,
                "answer_from": "stored_source_context" if stored_cards else "search",
                "reason": "source_specific_request_with_stored_cards"
                if stored_cards
                else "source_specific_request_no_stored_cards",
                "base_classification": base_type,
            }
        # Fresh-update follow-up: "any updates today", "newer report",
        # "can you verify", "what does Reuters say"
        if _NEWS_LATEST_UPDATE_RE.search(low):
            return {
                "route_classification": "fresh_update_followup",
                "serper_called": True,
                "answer_from": "search",
                "reason": "latest_update_or_verify_keyword",
                "base_classification": base_type,
            }
        # Interpretive follow-up: "why was he there", "what does that mean",
        # "can you explain", "is that bad", "what's the reason"
        is_interpretive = bool(_NEWS_INTERPRETIVE_RE.search(low))
        if is_interpretive:
            new_entities = _extract_news_entities(raw)
            stored_lower = {str(e).lower() for e in (ctx.get("entities") or []) if str(e).strip()}
            substantive_fresh = [
                e for e in new_entities
                if str(e).lower() not in stored_lower
                and _is_substantive_news_entity(e)
            ]
            if not substantive_fresh:
                return {
                    "route_classification": "interpretive_followup_llm_first",
                    "serper_called": False,
                    "answer_from": "stored_source_context",
                    "reason": "interpretive_question_no_substantive_new_entities",
                    "base_classification": base_type,
                }
            # Interpretive question that ALSO names new entities → a fresh
            # search is needed before the LLM can interpret responsibly.
            return {
                "route_classification": "current_fact_search",
                "serper_called": True,
                "answer_from": "search",
                "reason": f"interpretive_with_new_entities:{','.join(substantive_fresh[:3])}",
                "base_classification": base_type,
            }
        # Deictic-ish "who else / what else / who else was there" → if the
        # stored context can answer (entities list is rich), prefer context;
        # otherwise search.
        if re.search(
            r"\b(?:who else|what else|where else|when else|any other (?:people|details|reasons|reports?))\b",
            low,
        ):
            entities_count = len([e for e in (ctx.get("entities") or []) if str(e).strip()])
            rich_context = (
                bool(ctx.get("result_titles"))
                and entities_count >= 3
                and bool(ctx.get("answer_summary"))
            )
            if rich_context:
                return {
                    "route_classification": "interpretive_followup_llm_first",
                    "serper_called": False,
                    "answer_from": "stored_source_context",
                    "reason": "missing_detail_question_answerable_from_context",
                    "base_classification": base_type,
                }
            return {
                "route_classification": "current_fact_search",
                "serper_called": True,
                "answer_from": "search",
                "reason": "missing_detail_question_context_insufficient",
                "base_classification": base_type,
            }

    # ---- No-context (or unmatched) branches: fall through to base type.
    if base_type == "specific_current_event_question":
        return {
            "route_classification": "current_fact_search",
            "serper_called": True,
            "answer_from": "search",
            "reason": base.get("reason") or "wh_question_with_entity_or_domain_noun",
            "base_classification": base_type,
        }
    if base_type == "broad_news_request":
        return {
            "route_classification": "broad_news_headlines",
            "serper_called": True,
            "answer_from": "search",
            "reason": base.get("reason") or "broad_headlines_request",
            "base_classification": base_type,
        }

    # PART 5 — override guard:
    # base_type came back as `general_chat`, but the message is actually a
    # yes/no fact-verification question about a recent public event
    # ("Did Trump go to China last week?", "Was the LA fire contained?").
    # The legacy `_SPECIFIC_FACTUAL_QUESTION_LEAD_RE` is broad enough to
    # catch many of these via `specific_current_event_question`, but the
    # standalone helper here is a defense-in-depth net so the route is
    # consistent even when the base classifier disagrees.
    fact_score = score_current_fact_question(raw)
    if (
        bool(fact_score.get("matches"))
        and not base.get("personalNewsStatementDetected")
        and not base.get("emotionalContextDetected")
    ):
        return {
            "route_classification": "current_fact_search",
            "serper_called": True,
            "answer_from": "search",
            "reason": "general_chat_override_current_fact_question",
            "base_classification": base_type,
            "current_fact_question_score": float(fact_score.get("current_fact_question_score") or 0.0),
        }

    return {
        "route_classification": "general_chat",
        "serper_called": False,
        "answer_from": "llm",
        "reason": base.get("reason") or "no_news_indicators_or_unclear",
        "base_classification": base_type,
    }


def log_news_route_classification(session_id: str, text: str, route: dict) -> None:
    r"""Single per-turn log line for the polish-layer router. Easy to grep:
        rg '\[news_route_classification\]' logs/...
    """
    try:
        print(
            "[news_route_classification] "
            + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "user_text": (text or "")[:200],
                    "route_classification": route.get("route_classification") or "",
                    "serper_called": bool(route.get("serper_called")),
                    "answer_from": route.get("answer_from") or "",
                    "reason": route.get("reason") or "",
                    "base_classification": route.get("base_classification") or "",
                    "previous_route_type": get_previous_news_route_type(session_id),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass


def _scan_recent_specific_news_question(history: list[dict] | None) -> dict | None:
    """Look back through the most recent ~8 chat turns for the latest USER
    message classified as a specific_current_event_question. Returns
    {text, age} or None. Used by `resolve_followup_for_news_question` to
    pull pronouns/topic from real chat context instead of from whatever
    happens to be in an active side panel."""
    if not isinstance(history, list) or not history:
        return None
    for age, turn in enumerate(reversed(history[-10:])):
        if not isinstance(turn, dict):
            continue
        role = str(turn.get("role") or "").lower()
        content = str(turn.get("content") or "").strip()
        if role != "user" or not content:
            continue
        cls = classify_news_request_type(content)
        if cls["requestType"] == "specific_current_event_question":
            return {"text": content, "age": age, "classification": cls}
    return None


def resolve_followup_for_news_question(
    latest_user_text: str,
    *,
    history: list[dict] | None = None,
    last_search_query: str = "",
    last_source_cards: list[dict] | None = None,
) -> dict:
    """Spec-shape resolver for news-question follow-ups. Returns:
        {
          resolvedQuestion: str,
          entities: list[str],
          shouldSearchAgain: bool,
          reason: str,
          followupDetected: bool,
          followupKind: 'pronoun_continuation' | 'new_topic' | 'verbatim' | 'none',
        }

    Rules (PART 4):
      - If the follow-up uses pronouns/vague references ("he", "there",
        "that case", "did he win"), resolve them against the latest
        specific-news Q&A in the recent chat. Search again with the
        resolved query.
      - If the follow-up introduces a new named entity/topic, run a
        fresh search. Do not reuse Trump/China sources for an Elon Musk
        question.
      - If the recent chat does not have a specific-news Q&A, just
        return the follow-up text verbatim and let the downstream search
        run as-is.
    """
    raw = (latest_user_text or "").strip()
    out = {
        "resolvedQuestion": raw,
        "entities": [],
        "shouldSearchAgain": False,
        "reason": "",
        "followupDetected": False,
        "followupKind": "none",
    }
    if not raw:
        out["reason"] = "empty_text"
        return out

    cls = classify_news_request_type(raw)
    new_entities = _extract_news_entities(raw) if "_extract_news_entities" in globals() else []
    out["entities"] = list(new_entities)
    prior = _scan_recent_specific_news_question(history)

    # Pronoun / deictic shape — "he/she/they", "there", "that", "did he win",
    # "what case", etc.
    pronoun_like = bool(
        re.search(
            r"\b(?:he|she|they|them|him|her|his|hers|their|theirs|it)\b"
            r"|\b(?:there|that|this)\b"
            r"|\bwhat\s+(?:case|trip|deal|fire|election|lawsuit|story|topic)\b"
            r"|\bdid\s+(?:he|she|they|it)\b",
            raw,
            re.IGNORECASE,
        )
    )

    if prior and pronoun_like and not new_entities:
        # Pronoun continuation. Resolve by appending the new question to the
        # prior topic, e.g. previous="did Trump go to China last week" +
        # new="do you know why he was there" -> "regarding Trump's trip to
        # China last week, do you know why he was there".
        prior_text = prior["text"].rstrip("?. ")
        resolved = f"Regarding the question \"{prior_text}\" — {raw}"
        out["resolvedQuestion"] = resolved
        out["shouldSearchAgain"] = True
        out["followupDetected"] = True
        out["followupKind"] = "pronoun_continuation"
        out["reason"] = "pronoun_continuation_from_prior_specific_question"
        return out

    if prior and new_entities and not pronoun_like:
        # New topic introduced. Use verbatim follow-up; fresh search.
        out["resolvedQuestion"] = raw
        out["shouldSearchAgain"] = True
        out["followupDetected"] = True
        out["followupKind"] = "new_topic"
        out["reason"] = "new_named_entity_introduced"
        return out

    if cls["requestType"] == "specific_current_event_question":
        out["resolvedQuestion"] = raw
        out["shouldSearchAgain"] = True
        out["followupDetected"] = bool(prior)
        out["followupKind"] = "verbatim" if prior else "none"
        out["reason"] = "specific_question_verbatim"
        return out

    out["reason"] = "not_a_news_followup"
    return out


def _log_news_request_classification(payload: dict) -> None:
    """Structured spec-shape log per spec PART 7."""
    try:
        print(
            "[news_route_v2] " + json.dumps(payload, ensure_ascii=False, default=str),
            flush=True,
        )
    except Exception:
        pass


def _log_news_followup_suppressed(payload: dict) -> None:
    """Structured log emitted whenever a news follow-up resolver short-circuits
    because the new message is personal/emotional, or because the recent chat
    is personal/emotional and the new message is vague."""
    try:
        print(
            "[news_followup_suppressed] " + json.dumps(payload, ensure_ascii=False, default=str),
            flush=True,
        )
    except Exception:
        pass


def classify_news_search_intent(
    text: str,
    recent_news_context: dict | None = None,
) -> dict:
    """Spec-shape classifier returning:
        {
          shouldSearchNews: bool,
          confidence: float,
          intentType: 'explicit_news_request' | 'explicit_web_search_request' |
                      'personal_news_statement' | 'emotional_context' |
                      'general_chat' | 'unknown',
          reason: str,
          rawKeywordNewsDetected: bool,
          requestShapeDetected: bool,
          personalNewsStatementDetected: bool,
          emotionalContextDetected: bool,
        }

    Pure judgment — no side effects, safe to call from any router gate.
    Personal/emotional always wins, even when the message ALSO has request
    shape (e.g. "tell me what happened, my friend just died" — that's
    emotional, not a news lookup).
    """
    raw = (text or "").strip()
    if not raw:
        return {
            "shouldSearchNews": False,
            "confidence": 0.0,
            "intentType": "unknown",
            "reason": "empty_text",
            "rawKeywordNewsDetected": False,
            "requestShapeDetected": False,
            "currentFactQuestionDetected": False,
            "currentFactQuestionScore": 0.0,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
        }

    lowered = raw.lower()
    raw_keyword_news = bool(re.search(r"\b(?:news|headlines?|breaking)\b", lowered))
    personal = _is_personal_news_statement(raw)
    emotional = _is_emotional_distress_statement(raw)
    request_shape = _has_news_request_shape(raw)
    fact_score = score_current_fact_question(raw)
    is_current_fact_q = bool(fact_score.get("matches")) and not (personal or emotional)

    if personal or emotional:
        intent_type = "emotional_context" if emotional else "personal_news_statement"
        return {
            "shouldSearchNews": False,
            "confidence": 0.95,
            "intentType": intent_type,
            "reason": f"suppressed_{intent_type}",
            "rawKeywordNewsDetected": raw_keyword_news,
            "requestShapeDetected": request_shape,
            "currentFactQuestionDetected": False,
            "currentFactQuestionScore": 0.0,
            "personalNewsStatementDetected": personal,
            "emotionalContextDetected": emotional,
        }

    # PART 1 + PART 5: yes/no fact-verification questions about recent
    # public events ALWAYS take the search route, even when the message
    # contains no "news" / "headlines" / "search" keyword. This is what
    # makes "Did Trump go to China last week?" route to news.latest
    # instead of falling through to general_chat.
    if is_current_fact_q:
        return {
            "shouldSearchNews": True,
            "confidence": min(0.98, 0.75 + 0.25 * float(fact_score.get("current_fact_question_score") or 0.0)),
            "intentType": "current_fact_question",
            "reason": "yes_no_question_about_recent_public_event",
            "rawKeywordNewsDetected": raw_keyword_news,
            # Treat current-fact questions as having request shape so the
            # downstream `detect_news_route_intent` suppressor does not
            # drop them for "current_or_recent_without_request_shape".
            "requestShapeDetected": True,
            "currentFactQuestionDetected": True,
            "currentFactQuestionScore": float(fact_score.get("current_fact_question_score") or 0.0),
            "currentFactQuestionSignals": {
                "question_shape_detected": bool(fact_score.get("question_shape_detected")),
                "public_entity_detected": bool(fact_score.get("public_entity_detected")),
                "public_domain_noun_detected": bool(fact_score.get("public_domain_noun_detected")),
                "recent_time_marker_detected": bool(fact_score.get("recent_time_marker_detected")),
            },
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
        }

    if request_shape and (raw_keyword_news or _detect_current_or_recent(raw)):
        if _bare_latest_news_blocked_by_finance_anchor(raw):
            try:
                print(
                    "[news_latest_blocked_by_finance_anchor] "
                    + json.dumps(
                        {
                            "raw_clause": raw[:240],
                            "normalized_clause": lowered[:240],
                            "full_turn_context": (
                                _planner_full_turn_context() or raw
                            )[:240],
                            "finance_anchor_detected": True,
                            "candidate_routes": ["news.latest"],
                            "blocked_routes": ["news.latest"],
                            "selected_route": "general_chat",
                            "decision_reason": "bare_latest_recency_with_finance_in_full_turn",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            return {
                "shouldSearchNews": False,
                "confidence": 0.85,
                "intentType": "general_chat",
                "reason": "finance_anchor_blocks_bare_latest_news",
                "rawKeywordNewsDetected": raw_keyword_news,
                "requestShapeDetected": request_shape,
                "currentFactQuestionDetected": False,
                "currentFactQuestionScore": 0.0,
                "personalNewsStatementDetected": False,
                "emotionalContextDetected": False,
            }
        try:
            print(
                "[news_latest_candidate] "
                + json.dumps(
                    {
                        "raw_clause": raw[:240],
                        "normalized_clause": lowered[:240],
                        "candidate_routes": ["news.latest"],
                        "reason": "request_shape_plus_news_or_recent_terms",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return {
            "shouldSearchNews": True,
            "confidence": 0.9,
            "intentType": "explicit_news_request",
            "reason": "request_shape_plus_news_or_recent_terms",
            "rawKeywordNewsDetected": raw_keyword_news,
            "requestShapeDetected": True,
            "currentFactQuestionDetected": False,
            "currentFactQuestionScore": 0.0,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
        }

    if request_shape:
        # Imperative for search/news with no news keyword — e.g.
        # "search the web for X", "look up X". Treat as explicit web
        # search request; the downstream router will decide whether to
        # honor it as news.latest or generic search.
        return {
            "shouldSearchNews": True,
            "confidence": 0.75,
            "intentType": "explicit_web_search_request",
            "reason": "explicit_search_imperative",
            "rawKeywordNewsDetected": raw_keyword_news,
            "requestShapeDetected": True,
            "currentFactQuestionDetected": False,
            "currentFactQuestionScore": 0.0,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
        }

    if raw_keyword_news:
        return {
            "shouldSearchNews": False,
            "confidence": 0.7,
            "intentType": "general_chat",
            "reason": "bare_news_keyword_no_request_shape",
            "rawKeywordNewsDetected": True,
            "requestShapeDetected": False,
            "currentFactQuestionDetected": False,
            "currentFactQuestionScore": 0.0,
            "personalNewsStatementDetected": False,
            "emotionalContextDetected": False,
        }

    return {
        "shouldSearchNews": False,
        "confidence": 0.5,
        "intentType": "general_chat",
        "reason": "no_news_indicators",
        "rawKeywordNewsDetected": False,
        "requestShapeDetected": False,
        "currentFactQuestionDetected": False,
        "currentFactQuestionScore": 0.0,
        "personalNewsStatementDetected": False,
        "emotionalContextDetected": False,
    }


def detect_news_route_intent(
    text: str,
    *,
    has_recent_news_context: bool = False,
    recent_news_context: dict | None = None,
) -> dict:
    """Return action+reason for hybrid news routing. Does NOT execute anything.

    Always consults `classify_news_search_intent` first so personal-news
    statements ("I just saw the news my friend passed away") and emotional
    distress context ("got bad news, my dad died") suppress the route even
    when ordinal `_NEWS_RECENT_TERMS` / `_extract_news_entities` would have
    fired. The keyword-driven `current_or_recent + entities` branch now also
    requires explicit request shape so casual mentions of "news" never
    open the News panel.
    """
    raw = (text or "").strip()
    low = raw.lower()
    entities = _extract_news_entities(raw)
    time_horizon = _extract_news_time_horizon(raw)
    source_request = _is_news_source_request(raw)
    current_or_recent = _detect_current_or_recent(raw)
    outlet_mention = bool(_NEWS_OUTLET_RE.search(raw))
    deictic = _is_deictic_news_followup(raw)
    has_ctx = bool(recent_news_context) or has_recent_news_context
    intent_cls = classify_news_search_intent(raw, recent_news_context=recent_news_context)
    if not raw:
        return {
            "action": "skip",
            "reason": "empty",
            "current_or_recent_detected": False,
            "source_request_detected": False,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
        }

    # HARD SUPPRESSOR: personal news / emotional distress always wins, even
    # when the message also contains words that look like a request shape.
    # The user is sharing something — not asking for headlines.
    # (Stale `recent_news_context` is dropped by the caller — see
    # `route_action_request`'s pre-guard — because this function does not
    # have session_id.)
    if intent_cls.get("personalNewsStatementDetected") or intent_cls.get("emotionalContextDetected"):
        return {
            "action": "skip",
            "reason": intent_cls.get("reason") or "personal_or_emotional_statement",
            "current_or_recent_detected": current_or_recent,
            "source_request_detected": source_request,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
            "suppressed": True,
        }

    broad_reset = is_broad_news_reset_request(raw)
    if broad_reset:
        return {
            "action": "news_search",
            "reason": "broad_news_reset",
            "current_or_recent_detected": True,
            "source_request_detected": source_request,
            "entities": [],
            "time_horizon": time_horizon if time_horizon != "unspecified" else "today",
            "broad_news_reset": True,
            "intent_classification": intent_cls,
        }

    if source_request and has_ctx:
        return {
            "action": "news_sources",
            "reason": "source_request_with_context",
            "current_or_recent_detected": current_or_recent,
            "source_request_detected": True,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
        }

    if deictic and recent_news_context:
        stored_entities = [
            str(e).strip() for e in (recent_news_context.get("entities") or []) if str(e).strip()
        ]
        merged: list[str] = []
        for e in list(entities) + stored_entities:
            if e and e not in merged:
                merged.append(e)
        stored_horizon = str(recent_news_context.get("timeframe") or "unspecified")
        return {
            "action": "news_search",
            "reason": "deictic_followup_with_context",
            "current_or_recent_detected": True,
            "source_request_detected": source_request,
            "entities": merged,
            "time_horizon": time_horizon if time_horizon != "unspecified" else stored_horizon,
            "intent_classification": intent_cls,
        }

    broad = bool(
        re.match(
            r"^(?:can you )?(?:tell|give|show)\s+me\s+(?:some\s+|the\s+)?news[\s\?\.\!]*$",
            low,
        )
        or re.match(r"^(?:any|whats|what['’]s)\s+(?:new|the\s+news)\??$", low)
        or re.match(r"^news[\s\?\.\!]*$", low)
    )
    if broad and not entities:
        return {
            "action": "news_category_prompt",
            "reason": "broad_news_no_topic",
            "current_or_recent_detected": True,
            "source_request_detected": False,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
        }

    # PART 1: explicit current-fact verification question (e.g. "Did Trump
    # go to China last week?", "Is the highway still closed?", "Was the
    # LA fire contained?"). These always route to news_search, even when
    # `_NEWS_RECENT_TERMS` doesn't fire (the question itself is the
    # currency signal) and even when no proper noun is present (a public
    # domain noun like "highway" + "still" is enough). Personal/emotional
    # was already suppressed above.
    if intent_cls.get("currentFactQuestionDetected"):
        return {
            "action": "news_search",
            "reason": "current_fact_question",
            "current_or_recent_detected": True,
            "source_request_detected": source_request,
            "entities": entities,
            "time_horizon": time_horizon if time_horizon != "unspecified" else "recent",
            "intent_classification": intent_cls,
            "current_fact_question": True,
        }

    if current_or_recent and (entities or outlet_mention):
        # Require either explicit request shape (imperative/info question)
        # OR a known news outlet mention — bare "I saw [Entity] in the news"
        # is NOT a search request.
        if not intent_cls.get("requestShapeDetected") and not outlet_mention:
            return {
                "action": "skip",
                "reason": "current_or_recent_without_request_shape",
                "current_or_recent_detected": True,
                "source_request_detected": source_request,
                "entities": entities,
                "time_horizon": time_horizon,
                "intent_classification": intent_cls,
                "suppressed": True,
            }
        return {
            "action": "news_search",
            "reason": "current_or_recent_with_entities",
            "current_or_recent_detected": True,
            "source_request_detected": source_request,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
        }

    if entities and source_request:
        # Source request without stored context — fall back to a fresh search.
        return {
            "action": "news_search",
            "reason": "source_request_fresh_search",
            "current_or_recent_detected": True,
            "source_request_detected": True,
            "entities": entities,
            "time_horizon": time_horizon,
            "intent_classification": intent_cls,
        }

    return {
        "action": "skip",
        "reason": "no_current_or_recent_intent",
        "current_or_recent_detected": current_or_recent,
        "source_request_detected": source_request,
        "entities": entities,
        "time_horizon": time_horizon,
        "intent_classification": intent_cls,
    }


def _category_prompt_reply() -> str:
    return "Do you want world, tech, finance, A.I., or U.S. news?"


def build_route_from_news_intent(
    text: str,
    intent: dict,
    *,
    session_id: str | None = None,
) -> dict | None:
    if intent.get("action") != "news_search":
        return None
    entities = list(intent.get("entities") or [])
    time_horizon = str(intent.get("time_horizon") or "unspecified")
    broad_reset = bool(intent.get("broad_news_reset")) or is_broad_news_reset_request(text)
    if broad_reset:
        query = "breaking news" if "breaking" in (text or "").lower() else "latest news headlines"
        final_slots = {
            "query": query,
            "topic": query,
            "entities": [],
            "time_horizon": time_horizon if time_horizon != "unspecified" else "today",
            "search_queries": _build_broad_news_search_queries(
                text, time_horizon if time_horizon != "unspecified" else "today"
            ),
            "broad_news_reset": True,
        }
        _log_news_search_query_built(
            text,
            [],
            str(final_slots.get("time_horizon") or "today"),
            list(final_slots.get("search_queries") or []),
            raw_query=query,
        )
        return normalize_route(
            {
                "is_action_request": True,
                "action_name": "news.latest",
                "slots": final_slots,
            }
        )
    topic_phrase = _normalize_news_topic_phrase(text)
    # Build initial slots; _finalize_news_latest_slots will expand deictic queries
    # against stored context and emit [news_deictic_resolution] + [news_search_query_built].
    initial_slots = {
        "query": topic_phrase or " ".join(entities[:3]),
        "entities": entities,
        "time_horizon": time_horizon,
    }
    final_slots = _finalize_news_latest_slots(session_id, text, initial_slots)
    if not final_slots.get("search_queries"):
        return None
    return normalize_route(
        {
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": final_slots,
        }
    )


def set_recent_news_context_from_action_result(
    session_id: str,
    text: str,
    action_result: dict | None,
    *,
    assistant_offer: str | None = None,
    previous_route_type: str | None = None,
    answer_summary: str | None = None,
) -> None:
    if not session_id or not isinstance(action_result, dict):
        return
    data = action_result.get("data") or {}
    if not isinstance(data, dict) or not data.get("headlines"):
        return
    # `answer_summary` defaults to whatever the action's natural reply was so
    # later interpretive follow-ups can answer from "what we already told the
    # user" plus the source cards. We prefer an explicit summary when the
    # caller has one (e.g. a streaming layer that captured the assembled
    # LLM reply), then fall back to action data.summary / spoken_reply.
    resolved_summary = (
        (answer_summary or "").strip()
        or str(data.get("summary") or "").strip()
        or str(action_result.get("spoken_reply") or "").strip()
    )
    ctx = {
        "topic": data.get("query") or "",
        # PART 5 (polish): spec asks for `resolved_topic` and `original_user_question`
        # field names. We keep the legacy fields for backward compat AND
        # mirror the spec names so consumers can use either.
        "resolved_topic": data.get("query") or "",
        "original_user_query": (text or "")[:400],
        "original_user_question": (text or "")[:400],
        "normalized_search_queries": list(data.get("search_queries") or []),
        "entities": list(data.get("entities") or []),
        "timeframe": data.get("time_horizon") or "unspecified",
        "result_titles": list(data.get("result_titles") or []),
        "result_sources": list(data.get("result_sources") or []),
        "result_urls_if_available": list(data.get("result_urls") or []),
        "result_published": list(data.get("result_published") or []),
        "result_summaries": list(data.get("result_summaries") or []),
        # PART 4 (polish): expose `sources` + `source_summaries` aliases too.
        "sources": list(data.get("result_sources") or []),
        "source_summaries": list(data.get("result_summaries") or []),
        "answer_summary": resolved_summary[:1200],
        "previous_route_type": (previous_route_type or "").strip() or "topical_news_search",
        "created_at": time(),
        # PART 4 (polish): explicit `timestamp` alias for `created_at` (spec
        # uses the friendlier name; both stay synced).
        "timestamp": time(),
        "assistant_offer": assistant_offer or "",
    }
    recent_news_context[session_id] = ctx
    _log_news_context_saved(ctx)


def set_recent_news_previous_route_type(session_id: str, route_type: str) -> None:
    """Helper for the streaming path so a route classification logged BEFORE
    the action result lands (e.g. a personal-news guard) still ends up on
    the stored context for the next-turn classifier to read."""
    if not session_id:
        return
    ctx = recent_news_context.get(session_id)
    if not isinstance(ctx, dict):
        recent_news_context[session_id] = {
            "previous_route_type": (route_type or "").strip(),
            "created_at": time(),
            "timestamp": time(),
        }
        return
    ctx["previous_route_type"] = (route_type or "").strip()


def get_previous_news_route_type(session_id: str) -> str:
    """Return the last route_classification stored for this session, or ''."""
    if not session_id:
        return ""
    ctx = recent_news_context.get(session_id)
    if not isinstance(ctx, dict):
        return ""
    return str(ctx.get("previous_route_type") or "").strip()


def get_recent_news_context(session_id: str) -> dict | None:
    ctx = recent_news_context.get(session_id)
    if not ctx:
        return None
    if time() - float(ctx.get("created_at") or 0) > NEWS_CONTEXT_TTL_SEC:
        recent_news_context.pop(session_id, None)
        return None
    return ctx


def get_recent_sports_context(session_id: str) -> dict | None:
    """Per-session sports topic, TTL-protected. Used by the sports router to
    resolve follow-ups ("how about Sinner?", "did they win?") without
    re-asking the user for the team/player/tournament.

    Returns ``None`` when no context is stored OR when the stored context is
    older than ``SPORTS_CONTEXT_TTL_SEC``. Side-effect: expired contexts are
    evicted lazily on read.
    """
    if not session_id:
        return None
    ctx = recent_sports_context.get(session_id)
    if not ctx:
        return None
    if time() - float(ctx.get("created_at") or 0) > SPORTS_CONTEXT_TTL_SEC:
        recent_sports_context.pop(session_id, None)
        return None
    return ctx


def set_recent_sports_context_from_action_result(
    session_id: str,
    text: str,
    intent: dict | None,
    action_result: dict | None,
) -> None:
    """Persist the sports topic for the next turn. No-op when the intent is
    not a sports turn or when the action result is empty (e.g. clarification
    bubble). Confidence-low answers still update the context — the user is
    likely to follow up with "are you sure?" or "how about Y", and the
    follow-up classifier needs to see the same entity/topic."""
    if not session_id or not isinstance(intent, dict):
        return
    if not intent.get("is_sports"):
        return
    if not isinstance(action_result, dict):
        return
    if not (intent.get("entity") or intent.get("tournament_or_league")):
        return
    try:
        ctx = _build_sports_context_from_intent_and_result(intent, action_result, text)
        recent_sports_context[session_id] = ctx
    except Exception as exc:  # noqa: BLE001
        print("[sports_context_save_error]", exc, flush=True)


def _ordinal(n: int) -> str:
    return ("1st", "2nd", "3rd", "4th", "5th", "6th", "7th", "8th")[n - 1] if 1 <= n <= 8 else f"{n}th"


def _build_sources_spoken_reply(ctx: dict) -> str:
    """Short Voice UI confirmation. Full source cards live in the news panel, so we
    do NOT enumerate titles/outlets/dates aloud. Keep this to one sentence."""
    topic = (ctx.get("topic") or "").strip()
    if topic and 1 <= len(topic) <= 60:
        return f"I put the source cards for the {topic} search in the News panel."
    return "I opened the sources in the News panel."


def _stored_sources_have_cards(ctx: dict | None) -> bool:
    if not isinstance(ctx, dict):
        return False
    return bool(
        any((t or "").strip() for t in (ctx.get("result_titles") or []))
        or any((s or "").strip() for s in (ctx.get("result_sources") or []))
    )


def try_resolve_news_sources_request(
    session_id: str, text: str
) -> tuple[dict | None, float]:
    if not _is_news_source_request(text):
        return None, 0.0
    ctx = get_recent_news_context(session_id)
    if not ctx or not _stored_sources_have_cards(ctx):
        # No usable cards stored — let the fallback fresh search handle it.
        return None, 0.0
    titles = [(t or "").strip() for t in (ctx.get("result_titles") or [])]
    sources = [(s or "").strip() for s in (ctx.get("result_sources") or [])]
    urls = [(u or "").strip() for u in (ctx.get("result_urls_if_available") or [])]
    published = [(p or "").strip() for p in (ctx.get("result_published") or [])]
    summaries = [(s or "").strip() for s in (ctx.get("result_summaries") or [])]
    serialized: list[dict] = []
    max_len = max(len(titles), len(sources), len(urls), len(published), len(summaries))
    for i in range(max_len):
        title = titles[i] if i < len(titles) else ""
        source = sources[i] if i < len(sources) else ""
        url = urls[i] if i < len(urls) else ""
        date = published[i] if i < len(published) else ""
        summary = summaries[i] if i < len(summaries) else ""
        if not title and not source and not url:
            continue
        serialized.append(
            {
                "title": title,
                "summary": summary,
                "published": "",
                "published_display": date,
                "source": source,
                "url": url,
            }
        )
    spoken = _build_sources_spoken_reply(ctx)
    action_result = {
        "spoken_reply": spoken,
        "action_type": "news",
        "data": {
            "headlines": serialized,
            "summary": spoken,
            "mode": "sources",
            "query": ctx.get("topic") or "",
            "time_horizon": ctx.get("timeframe"),
            "entities": ctx.get("entities") or [],
            "search_queries": ctx.get("normalized_search_queries") or [],
            "result_titles": [s["title"] for s in serialized],
            "result_sources": [s["source"] for s in serialized],
            "result_urls": [s["url"] for s in serialized],
            "result_published": [s["published_display"] for s in serialized],
        },
        "ui_payload": {
            "panel_type": "media_tabs",
            "title": "Sources",
            "query": ctx.get("topic") or "",
            "news_results": serialized,
            "images": [],
            "videos": [],
            "default_tab": "news",
        },
    }
    _log_news_followup_resolution(
        {
            "user_text": (text or "")[:200],
            "previous_user_text": ctx.get("original_user_query", "")[:200],
            "previous_assistant_text": "",
            "pending_action_type": "news_sources",
            "pending_topic": ctx.get("topic"),
            "overlapping_entities": ctx.get("entities") or [],
            "resolved_followup": True,
            "reason": "news_sources_from_context",
        }
    )
    return action_result, 0.0


def _entities_overlap(a: list[str], b: list[str]) -> list[str]:
    set_b = {str(x).strip().lower() for x in (b or []) if str(x).strip()}
    out = []
    for x in a or []:
        if str(x).strip().lower() in set_b:
            out.append(x)
    return out


_NEWS_CORRECTIVE_RE = re.compile(
    r"^(?:wait[,.\s]+|but\s+|actually[,\s]+|hold on[,\s]+|hmm[,\s]+)?"
    r"(?:i (?:thought|heard|read)|didn['’]t|wasn['’]?t|isn['’]?t|aren['’]?t|"
    r"how does that relate|is that the same|what about|how about)\b",
    re.IGNORECASE,
)


def _is_corrective_news_followup(text: str) -> bool:
    raw = (text or "").strip()
    if not raw or len(raw.split()) > 40:
        return False
    if _NEWS_CORRECTIVE_RE.match(raw):
        return True
    if re.match(r"^(?:what about|how about)\s+\w+", raw, re.IGNORECASE):
        return True
    return False


# =========================
# News follow-up strategy (LLM-from-context vs. fresh Serper search)
# =========================
_NEWS_INTERPRETIVE_RE = re.compile(
    # "Why was he there?" / "Why did he do that?" / "Why is that important?"
    r"\bwhy (?:were|was|did|do|does|is|are|would|should|had|have|might)\b"
    # "How does that relate / matter / work / happen / fit?"
    r"|\bhow (?:does|do|did|is|are|would|could|should) (?:that|this|it|they|them|those|these) (?:relate|connect|matter|work|happen|come about|fit|play out)\b"
    # "What does that mean / imply / suggest / indicate?"
    r"|\bwhat (?:does|do|did|is|are) (?:that|this|it|they|them|those|these) (?:mean|imply|suggest|indicate|signal|tell us)\b"
    # "Is that bad / important / significant / serious / good / true / real…?"
    r"|\b(?:is|was|isn['’]?t|wasn['’]?t) (?:that|this|it) (?:bad|good|important|significant|serious|true|real|relevant|surprising|expected|unusual|notable|big|risky|safe|legal|illegal|controversial|fine)\b"
    # "What's the reason / meaning / point / context / backstory?"
    r"|\bwhat['’]?s the (?:reason|meaning|point|significance|implication|context|backstory|takeaway|big deal)\b"
    # "What was/were the reason / meaning / point / context?"
    r"|\bwhat (?:was|were|is|are) the (?:reason|meaning|point|significance|implication|context|backstory|takeaway|big deal|story)\b"
    # "So that means…" leadins
    r"|\bso (?:that|this|it) (?:means|implies|suggests)\b"
    # "Can you explain (it/that/this/why/the situation)?" — also "explain"
    # with no object since spec explicitly lists "Can you explain?".
    r"|\bcan you (?:explain|interpret|unpack|clarify|elaborate|walk me through|break (?:that|this|it) down)(?:\s+(?:that|this|it|why|how|the situation|the context))?\b"
    # "Explain (that/this/it)" — bare imperative
    r"|^(?:please\s+)?(?:explain|interpret|unpack|clarify|elaborate)(?:\s+(?:that|this|it))?[?.!\s]*$"
    # "What do you make of / think of / think about that?"
    r"|\bwhat do you (?:make of|think of|think about) (?:that|this|it|them|those|these)\b",
    re.IGNORECASE,
)

# Outlet names get a dedicated set so the followup classifier can treat
# "what does Reuters say" as a fresh-source request (search), not as a
# "new entity → fresh fact" search, and so the interpretive branch doesn't
# get knocked off course by the user naming a media outlet for sourcing.
_NEWS_MEDIA_OUTLETS = frozenset(
    {
        "reuters", "associated press", "ap", "ap news", "new york times", "nyt",
        "cnn", "bbc", "bloomberg", "axios", "the verge", "wsj",
        "wall street journal", "cnbc", "fox", "fox news", "guardian",
        "the guardian", "washington post", "wapo", "npr", "politico",
        "the economist", "financial times", "ft", "al jazeera", "abc",
        "abc news", "nbc", "nbc news", "cbs", "cbs news", "espn",
    }
)
_NEWS_MEDIA_OUTLETS_RE = re.compile(
    r"\b(?:" + "|".join(re.escape(o) for o in sorted(_NEWS_MEDIA_OUTLETS, key=len, reverse=True)) + r")\b",
    re.IGNORECASE,
)

_NEWS_LATEST_UPDATE_RE = re.compile(
    # Time-now / recency cues
    r"\b(?:latest|newest|most recent|breaking|just happened|just in|update|"
    r"new development|new info|new information|newer info|newer information|newer facts?|"
    r"what(?:'?s| is) new|what(?:'?s| is) the (?:latest|newest)|any new|"
    r"newer report|newer reports|fresh take|fresh report|"
    r"today|tonight|right now|as of now|since (?:then|that|this))\b"
    # Explicit verification asks
    r"|\bcan you (?:verify|confirm|double[-\s]?check|fact[-\s]?check)\b"
    r"|\b(?:any\s+)?updates?\s+(?:today|right now|on (?:that|this|it))?\b"
    # "what happened after/since (that|then|this)"
    r"|\bwhat\s+happened\s+(?:after|since)\s+(?:that|then|this|it)\b"
    # "was that confirmed later/since/after that"
    r"|\bwas\s+(?:it|that|this)\s+(?:confirmed|verified)\s+(?:later|since|after(?:\s+(?:that|this|then))?)\b"
    # "is there newer info / newer information"
    r"|\b(?:is|are)\s+there\s+(?:any\s+)?(?:newer|new)\s+(?:info|information|reports?|facts?|news|details?)\b"
    # "Find more sources" / "give me more sources" / "any other sources"
    r"|\b(?:find|get|give me|show me|pull up|any other|more) (?:more\s+)?(?:sources?|links?|articles?|citations?|references?)\b"
    # Outlet-mention follow-ups ("what does Reuters say", "what does the
    # New York Times say", "any Bloomberg coverage"). The optional "the "
    # lets multi-word outlets that conventionally take a definite article
    # ("the New York Times", "the Guardian", "the Washington Post") match.
    r"|\bwhat (?:does|do) (?:the\s+)?" + _NEWS_MEDIA_OUTLETS_RE.pattern + r" (?:say|report|cover|think)\b"
    r"|\bany (?:the\s+)?" + _NEWS_MEDIA_OUTLETS_RE.pattern + r" (?:coverage|reporting|article|story|piece)\b",
    re.IGNORECASE,
)
_NEWS_PLACE_ENTITIES = frozenset(
    {
        "china", "beijing", "shanghai", "russia", "moscow", "ukraine", "kyiv",
        "iran", "tehran", "israel", "gaza", "europe", "germany", "berlin",
        "france", "paris", "uk", "britain", "london", "tokyo", "japan",
        "taiwan", "india", "delhi", "mexico", "canada", "new york",
        "washington", "los angeles", "san francisco", "silicon valley",
    }
)


def _log_news_followup_strategy(row: dict) -> None:
    try:
        print("[news_followup_strategy] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


_NEWS_NOISE_SINGLE_TOKENS = frozenset(
    {
        "can", "could", "would", "should", "will", "shall", "may", "might",
        "must", "do", "does", "did", "is", "are", "was", "were", "be", "been",
        "the", "a", "an", "this", "that", "these", "those",
        "mr", "ms", "mrs", "dr", "sir",
    }
)


def _is_substantive_news_entity(e: str) -> bool:
    """A fresh entity is 'substantive' only if it's clearly a person/company/place name
    rather than a 3-letter ASR fragment, modal verb, or a short capitalized initialism
    that's already inferable as context noise.

    Media outlets (Reuters, Bloomberg, AP, …) are NOT substantive even though they
    pass the length test, because user phrasings like "what does Reuters say" are
    asks for sourcing on the SAME topic, not a pivot to a new subject. They're
    handled by _NEWS_LATEST_UPDATE_RE → latest_update → search_again instead.
    """
    s = (e or "").strip()
    if not s:
        return False
    tokens = [t for t in re.split(r"\s+", s) if t]
    if not tokens:
        return False
    low = s.lower().rstrip(".")
    if low in _NEWS_NOISE_SINGLE_TOKENS:
        return False
    if low in _NEWS_MEDIA_OUTLETS:
        return False
    if len(tokens) >= 2:
        # Reject multi-token outlet names too ("Associated Press", "New York Times").
        joined = " ".join(t.lower() for t in tokens).rstrip(".")
        if joined in _NEWS_MEDIA_OUTLETS:
            return False
        return True
    # Single-token: require length > 3 chars AFTER stripping periods/punctuation.
    bare = re.sub(r"[^A-Za-z]", "", s)
    return len(bare) > 3


def _classify_news_followup_type(text: str, ctx: dict | None) -> dict:
    """Decide whether a news follow-up should be answered from stored context (LLM-only)
    or trigger a fresh Serper search.

    Returns: {followup_type, strategy, reason}
      followup_type ∈ {"interpretive", "new_fact", "source_request",
                        "latest_update", "skip_unrelated"}
      strategy      ∈ {"answer_from_context", "search_again", "skip"}
    """
    raw = (text or "").strip()
    if not raw or not isinstance(ctx, dict) or not ctx:
        return {
            "followup_type": "new_fact",
            "strategy": "search_again",
            "reason": "no_context",
        }
    low = raw.lower()

    # Defense-in-depth: any turn that clearly belongs to a different domain
    # (finance analytics, time/weather utility, math/code/app UI, etc.) must
    # NOT be classified as a news follow-up even when deictic-shaped words
    # like "when was it" co-occur with the question. The resolver-level
    # pre-flight guard already catches these; this branch is here so any
    # future caller of this classifier inherits the same protection.
    utility = _is_utility_route_message(raw)
    if utility.get("detected"):
        return {
            "followup_type": "skip_unrelated",
            "strategy": "skip",
            "reason": f"utility_route:{utility.get('reason') or ''}",
        }
    if is_finance_analytics_query(raw):
        return {
            "followup_type": "skip_unrelated",
            "strategy": "skip",
            "reason": "finance_analytics_query",
        }
    strong = _is_strong_new_topic_message(raw)
    if strong.get("detected"):
        return {
            "followup_type": "skip_unrelated",
            "strategy": "skip",
            "reason": f"strong_new_topic:{strong.get('reason') or ''}",
        }

    if _is_news_source_request(raw):
        return {
            "followup_type": "source_request",
            "strategy": "search_again",
            "reason": "source_request_detected",
        }

    # Stage 2.5 LLM-first policy: deictic factoid follow-ups
    # ("who else was there", "when was that", "where did that happen",
    # "what happened after that", "tell me more") answer from stored
    # context UNLESS the turn carries an explicit fresh-retrieval or
    # source-specific marker. This must run BEFORE the latest_update
    # branch so phrases like "what happened after that" aren't lumped in
    # with "any updates today".
    if (
        _news_followup_is_deictic_factoid(raw)
        and not _news_followup_should_search_again(raw)
    ):
        return {
            "followup_type": "interpretive",
            "strategy": "answer_from_context",
            "reason": "stage25_deictic_factoid_llm_first",
        }

    if _NEWS_LATEST_UPDATE_RE.search(low):
        return {
            "followup_type": "latest_update",
            "strategy": "search_again",
            "reason": "latest_update_intent",
        }

    new_entities = _extract_news_entities(raw)
    stored_entities = list(ctx.get("entities") or [])
    stored_lower = {str(e).lower() for e in stored_entities if str(e).strip()}
    fresh_entities = [e for e in new_entities if str(e).lower() not in stored_lower]
    # Only count substantive fresh entities (multi-word names, or single tokens
    # longer than 3 chars and not a modal/auxiliary noise word). This avoids
    # flipping interpretive follow-ups to search just because the user said
    # "Can you ..." or "What does that mean for U.S. trade?".
    # NOTE: _is_substantive_news_entity now also rejects media outlet names
    # (Reuters, AP, Bloomberg, ...) so "what does Reuters say" stays in the
    # latest_update branch instead of being treated as a topic pivot.
    substantive_fresh = [e for e in fresh_entities if _is_substantive_news_entity(e)]

    is_interpretive = bool(_NEWS_INTERPRETIVE_RE.search(low))
    is_deictic = _is_deictic_news_followup(raw)
    has_rich_context = bool(
        (ctx.get("result_titles") or []) or (ctx.get("result_sources") or [])
    )

    if is_interpretive and not substantive_fresh:
        return {
            "followup_type": "interpretive",
            "strategy": "answer_from_context",
            "reason": "interpretive_question_no_substantive_new_entities",
        }

    if substantive_fresh:
        return {
            "followup_type": "new_fact",
            "strategy": "search_again",
            "reason": f"new_entities:{','.join(substantive_fresh[:3])}",
        }

    if is_interpretive and has_rich_context:
        # Even with overlap-only entities, interpretive + rich context → answer from ctx.
        return {
            "followup_type": "interpretive",
            "strategy": "answer_from_context",
            "reason": "interpretive_with_rich_context",
        }

    if is_deictic and has_rich_context and not is_interpretive:
        # Stage 2.5 LLM-first follow-up policy: deictic factoid follow-ups
        # ("who else was there", "when was that", "where did that happen",
        # "what happened after that", "tell me more") default to answering
        # from stored context. The LLM is prompted to acknowledge missing
        # details rather than silently re-running a Serper search. Explicit
        # fresh-retrieval and source-specific markers were already matched
        # above (latest_update / source_request) and so don't reach this
        # branch.
        return {
            "followup_type": "interpretive",
            "strategy": "answer_from_context",
            "reason": "deictic_followup_with_rich_context_llm_first",
        }

    return {
        "followup_type": "new_fact",
        "strategy": "search_again",
        "reason": "default_to_search",
    }


def _resolve_deictics_in_text(text: str, ctx: dict | None) -> str:
    """Rewrite he/she/they/them/there/this trip into named entities/topic from stored context."""
    raw = (text or "").strip()
    if not raw or not isinstance(ctx, dict) or not ctx:
        return raw
    entities = [str(e).strip() for e in (ctx.get("entities") or []) if str(e).strip()]
    topic = str(ctx.get("topic") or "").strip()
    if not entities and not topic:
        return raw

    # For pronouns like "they"/"them", prefer person/organization entities over place
    # entities so we don't say "they = Trump, China" when China is really the location.
    person_entities = [e for e in entities if e.lower() not in _NEWS_PLACE_ENTITIES]
    pron_entities = person_entities or entities

    def _english_join(items: list[str]) -> str:
        if not items:
            return topic or "the people involved"
        if len(items) == 1:
            return items[0]
        if len(items) == 2:
            return f"{items[0]} and {items[1]}"
        return ", ".join(items[:-1]) + ", and " + items[-1]

    entity_str = _english_join(pron_entities[:4])
    # Singular pronouns map to the FIRST person entity (most prominent subject).
    singular_entity = pron_entities[0] if pron_entities else (topic or "")

    location_hint = ""
    for e in entities:
        if e.lower() in _NEWS_PLACE_ENTITIES:
            location_hint = e
            break

    resolved = raw
    resolved = re.sub(r"\bthey\b", entity_str, resolved, flags=re.IGNORECASE)
    resolved = re.sub(r"\bthem\b", entity_str, resolved, flags=re.IGNORECASE)
    # Singular he/she/him/his/her — only rewrite when we have a clear singular
    # subject. "His/her" become "<entity>'s" possessive.
    if singular_entity:
        resolved = re.sub(r"\b(?:he|she)\b", singular_entity, resolved, flags=re.IGNORECASE)
        resolved = re.sub(r"\bhim\b", singular_entity, resolved, flags=re.IGNORECASE)
        resolved = re.sub(
            r"\b(?:his|her)\b",
            f"{singular_entity}'s",
            resolved,
            flags=re.IGNORECASE,
        )
    if location_hint:
        resolved = re.sub(r"\bthere\b", f"in {location_hint}", resolved, flags=re.IGNORECASE)
    if topic:
        resolved = re.sub(
            r"\b(?:this|that)\s+(?:trip|visit|lawsuit|case|deal|meeting|summit|talks|negotiation|investigation|event|story)\b",
            topic,
            resolved,
            flags=re.IGNORECASE,
        )
    return resolved


def _format_news_context_blob(ctx: dict | None) -> str:
    if not isinstance(ctx, dict) or not ctx:
        return ""
    lines: list[str] = []
    topic = str(ctx.get("topic") or "").strip()
    if topic:
        lines.append(f"Topic: {topic}")
    entities = [str(e).strip() for e in (ctx.get("entities") or []) if str(e).strip()]
    if entities:
        lines.append(f"Key entities: {', '.join(entities[:6])}")
    timeframe = str(ctx.get("timeframe") or "").strip()
    if timeframe and timeframe != "unspecified":
        lines.append(f"Timeframe: {timeframe}")
    titles = [str(t).strip() for t in (ctx.get("result_titles") or []) if str(t).strip()]
    sources = [str(s).strip() for s in (ctx.get("result_sources") or []) if str(s).strip()]
    if titles:
        lines.append("Headlines from the prior search:")
        for i in range(min(len(titles), 5)):
            src = sources[i] if i < len(sources) else ""
            if src:
                lines.append(f"  {i + 1}. {src}: {titles[i]}")
            else:
                lines.append(f"  {i + 1}. {titles[i]}")
    return "\n".join(lines)


_CONTEXT_FOLLOWUP_PREAMBLE = (
    "You previously summarized a news topic for the user. They are asking an interpretive "
    "follow-up that should be answered using the stored context below, NOT by searching "
    "again. Keep the answer concise and natural for spoken delivery (1–3 sentences). "
    "If the stored context truly does not have enough information to answer, say so "
    "briefly and suggest a more specific search. Do not invent sources or quotes.\n\n"
)


def _build_news_context_followup_messages(
    raw_text: str, resolved_text: str, ctx: dict | None
) -> list[dict]:
    blob = _format_news_context_blob(ctx)
    raw_text = (raw_text or "").strip()
    resolved_text = (resolved_text or "").strip()
    deictic_note = ""
    if resolved_text and resolved_text.lower() != raw_text.lower():
        deictic_note = (
            "\n\nDeictic references in the user's message resolve to: "
            + resolved_text
        )
    user_text = (
        _CONTEXT_FOLLOWUP_PREAMBLE
        + "Stored news context:\n"
        + (blob or "(no detailed context available)")
        + "\n\nUser follow-up (verbatim): "
        + (raw_text or "")
        + deictic_note
    )
    return vera.build_messages(chat_history=[], user_text=user_text)


def _news_context_followup_action_result(
    spoken_reply: str, ctx: dict | None
) -> dict:
    spoken = (spoken_reply or "").strip() or "I don't have enough from the prior context to answer that."
    ctx = ctx if isinstance(ctx, dict) else {}
    return {
        "spoken_reply": spoken,
        "action_type": "news",
        "data": {
            "summary": spoken,
            "mode": "context_followup",
            "query": ctx.get("topic") or "",
            "entities": list(ctx.get("entities") or []),
            "time_horizon": ctx.get("timeframe") or "unspecified",
            "result_titles": list(ctx.get("result_titles") or []),
            "result_sources": list(ctx.get("result_sources") or []),
            "result_urls": list(ctx.get("result_urls_if_available") or []),
            "search_queries": [],
            "headlines": [],
        },
        # Don't re-render a news panel for an interpretive answer; prior panel stands.
        "ui_payload": None,
    }


def _execute_news_context_followup_sync(
    session_id: str, text: str, ctx: dict
) -> tuple[dict | None, float]:
    t0 = perf_counter()
    resolved = _resolve_deictics_in_text(text, ctx)
    messages = _build_news_context_followup_messages(text, resolved, ctx)
    try:
        response, _ = vera.generate(messages)
    except Exception as exc:
        print(f"[news_context_followup] LLM error: {exc}", flush=True)
        return None, perf_counter() - t0
    return _news_context_followup_action_result(response or "", ctx), perf_counter() - t0


def _prepare_news_context_followup_streaming(
    session_id: str, text: str, ctx: dict
) -> "PreparedStreamingAction":
    resolved = _resolve_deictics_in_text(text, ctx)
    messages = _build_news_context_followup_messages(text, resolved, ctx)

    def finalize(full_reply: str) -> dict:
        return _news_context_followup_action_result(full_reply or "", ctx)

    return PreparedStreamingAction(messages, "news", None, finalize)


def try_resolve_news_followup_corrective(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
    ctx_override: dict | None = None,
):
    """Corrective/contrastive follow-ups ('wait, I thought Musk and Huang were on that trip').

    Resolves to a fresh news search whose entities = stored ones ∪ new entities in the
    follow-up — only when there's entity overlap, a corrective lead, OR a pronoun/deictic
    follow-up with a known recent topic (possibly synthesized from history).
    """
    ctx = ctx_override if ctx_override is not None else get_recent_news_context(session_id)
    if not ctx:
        return None
    raw = (text or "").strip()
    if not raw:
        return None
    is_corrective = _is_corrective_news_followup(raw)
    is_deictic = _is_deictic_news_followup(raw)
    new_entities = _extract_news_entities(raw)
    overlap = _entities_overlap(new_entities, ctx.get("entities") or [])
    if not is_corrective and not is_deictic and not overlap:
        return None
    # ----------------------------------------------------------------------
    # PART 7+11 (2026-05-28) stale-query reuse guard.
    # If the current user message is a standalone factual question that
    # contains its own named entity AND a question shape, treat it as a
    # NEW search query — never reuse the stored prior topic just because
    # entities happen to overlap.
    #
    # Example regression this prevents:
    #   prior turn:  "Why did Elon Musk sue OpenAI?"   (ctx.topic stored)
    #   new turn:    "Was Elon Musk part of the OpenAI team?"
    # Both turns share entities {Elon Musk, OpenAI} so overlap=True,
    # but the new turn is a complete standalone question. Pre-fix code
    # used ctx.topic ("elon musk sue openai") as the search query
    # instead of the user's actual question.
    #
    # Note: corrective ('wait, I thought ...') and deictic ('what about
    # him then') follow-ups can still safely reuse ctx.topic because they
    # lack a complete standalone question shape.
    current_has_named_entity = bool(new_entities) or _has_named_entity_hint(raw)
    current_has_question_shape = _has_current_fact_question_lead(raw)
    prefer_current_topic = (
        current_has_named_entity
        and current_has_question_shape
        and not is_corrective
        and not is_deictic
    )
    if prefer_current_topic:
        normalized_current = _normalize_news_topic_phrase(raw)
        initial_query = normalized_current or raw
        try:
            print(
                "[news_router_stale_query_guarded] "
                + json.dumps(
                    {
                        "session_id": (session_id or "")[:64],
                        "where": "try_resolve_news_followup_corrective",
                        "user_text": raw[:200],
                        "stored_prior_topic": (ctx.get("topic") or "")[:200],
                        "chosen_query": initial_query[:200],
                        "reason": "current_msg_has_named_entity_and_question_shape",
                        "overlap_entities": overlap,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
    else:
        initial_query = ctx.get("topic") or _normalize_news_topic_phrase(raw)
    # Build initial slots; the finalizer expands deictic queries from ctx, merges
    # entities, applies the prior timeframe if unspecified, and builds queries.
    initial_slots = {
        "query": initial_query,
        "entities": new_entities,
        "time_horizon": _extract_news_time_horizon(raw),
    }
    final_slots = _finalize_news_latest_slots(session_id, text, initial_slots)
    if not final_slots.get("search_queries"):
        return None
    route = normalize_route(
        {
            "is_action_request": True,
            "action_name": "news.latest",
            "slots": final_slots,
        }
    )
    if is_corrective and overlap:
        reason = "corrective_followup_with_overlap"
    elif is_corrective:
        reason = "corrective_lead_no_overlap"
    elif is_deictic:
        reason = "deictic_followup_from_context"
    else:
        reason = "entity_overlap_followup"
    _log_news_followup_resolution(
        {
            "user_text": raw[:200],
            "previous_user_text": ctx.get("original_user_query", "")[:200],
            "previous_assistant_text": "",
            "pending_action_type": "news_search_corrective",
            "pending_topic": ctx.get("topic"),
            "overlapping_entities": overlap,
            "resolved_followup": True,
            "reason": reason,
        }
    )
    return route


def _synthesize_news_ctx_from_history(
    session_id: str | None, text: str, history: list[dict]
) -> dict | None:
    """Build a transient news ctx from the most recent user/assistant turn.

    Used when no `recent_news_context` is stored (e.g. the prior turn answered
    a news-y question via the general LLM path), so pronoun/deictic follow-ups
    like "you know why he was there" can still resolve against named entities
    + time horizon from the previous turn instead of being shipped to Serper
    as a literal "why was he there" query.

    Returns a dict shaped like `recent_news_context` entries (without
    `result_titles`/`result_sources`), or None if no usable signal exists.
    """
    if not isinstance(history, list) or not history:
        return None
    raw = (text or "").strip()
    if not raw:
        return None
    if not _is_pronoun_news_followup(raw) and not _is_deictic_news_followup(raw):
        return None

    prev_user = ""
    prev_assistant = ""
    for msg in reversed(history):
        if not isinstance(msg, dict):
            continue
        role = (msg.get("role") or "").lower()
        content = str(msg.get("content") or "").strip()
        if not content:
            continue
        if role == "assistant" and not prev_assistant:
            prev_assistant = content
        elif role == "user" and not prev_user:
            prev_user = content
        if prev_user and prev_assistant:
            break

    if not prev_user and not prev_assistant:
        return None

    # Prefer entities from the user's prior message — they are the most
    # reliable signal of the conversation topic. Assistant text is allowed
    # to contribute additional names, but only when they're known aliases
    # (Trump, China, OpenAI, …) to avoid grabbing capitalized sentence-start
    # words like "Want", "According", etc. as if they were entities.
    user_entities = _extract_news_entities(prev_user)
    asst_entities_all = _extract_news_entities(prev_assistant)
    alias_canonicals = {v.lower() for v in _NEWS_ENTITY_ALIASES.values()}
    asst_entities_safe = [
        e for e in asst_entities_all if e.lower() in alias_canonicals
    ]
    seen: set[str] = set()
    deduped_entities: list[str] = []
    for e in user_entities + asst_entities_safe:
        key = e.lower()
        if key in seen:
            continue
        seen.add(key)
        deduped_entities.append(e)
    substantive = [e for e in deduped_entities if _is_substantive_news_entity(e)]
    if not substantive:
        return None

    timeframe = _extract_news_time_horizon(prev_user) or _extract_news_time_horizon(prev_assistant)
    if not timeframe:
        timeframe = "unspecified"
    raw_topic = _normalize_news_topic_phrase(prev_user) or " ".join(substantive[:3])
    # Strip leading filler words like "if" / "whether" / "that" that survive
    # the question-prefix strip but make the search query awkward.
    topic = re.sub(
        r"(?i)^(?:if|whether|that|about)\s+", "", (raw_topic or "").strip()
    )

    return {
        "topic": (topic or "").strip()[:200],
        "original_user_query": (prev_user or "")[:400],
        "normalized_search_queries": [],
        "entities": substantive,
        "timeframe": timeframe,
        "result_titles": [],
        "result_sources": [],
        "result_urls_if_available": [],
        "result_published": [],
        "result_summaries": [],
        "created_at": time(),
        "assistant_offer": "",
        "synthesized_from_history": True,
    }


def _get_or_synthesize_news_ctx(
    session_id: str | None, text: str, history: list[dict]
) -> dict | None:
    """Return stored news ctx, or synthesize one from history for pronoun/deictic follow-ups.

    When synthesizing, the ctx is also installed into `recent_news_context` for
    this session so downstream helpers like `_finalize_news_latest_slots` (which
    look up the stored ctx by session_id) can see it without explicit threading.
    The synthesized ctx has no `result_titles`/`result_sources`, so further
    classifier decisions will lean toward search_again instead of answer_from_context.
    """
    ctx = get_recent_news_context(session_id) if session_id else None
    if ctx:
        return ctx
    synth = _synthesize_news_ctx_from_history(session_id, text, history)
    if synth and session_id:
        recent_news_context[session_id] = synth
        try:
            print(
                "[news_ctx_synthesized] "
                + json.dumps(
                    {
                        "session_id": (session_id or "")[:64],
                        "topic": synth.get("topic"),
                        "entities": synth.get("entities", [])[:8],
                        "timeframe": synth.get("timeframe"),
                        "user_text": (text or "")[:120],
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
    return synth


_UTILITY_TIME_QUERY_RE = re.compile(
    r"\b(?:"
    r"what(?:'?s|s|\s+is)?\s+(?:the\s+)?time\b"
    r"|what\s+time\s+is\s+it\b"
    r"|tell\s+me\s+the\s+time\b"
    r"|current\s+time\b"
    r"|time\s+(?:in|at|of)\s+[A-Za-z]"
    r"|time\s+zone\s+(?:in|of|for)\b"
    r"|what(?:'?s|s|\s+is)\s+(?:the\s+|today'?s\s+)?date\b"
    r"|what\s+day\s+is\s+(?:it|today)\b"
    r"|what(?:'?s|s|\s+is)?\s+(?:today'?s)?\s*date\b"
    r"|days\s+(?:until|till|to)\b"
    r"|how\s+many\s+days\s+(?:until|till|to)\b"
    r"|countdown\b"
    r")",
    re.IGNORECASE,
)

_UTILITY_WEATHER_QUERY_RE = re.compile(
    r"\b(?:"
    r"weather\b"
    r"|temperature\b"
    r"|forecast\b"
    r"|how\s+(?:hot|cold|warm|humid|windy)\s+(?:is\s+it|will\s+it\s+be)"
    r"|is\s+it\s+(?:raining|snowing|sunny|cloudy|cold|hot|warm|humid|windy)"
    r")",
    re.IGNORECASE,
)


def _is_utility_route_message(text: str) -> dict:
    """Detect time/weather/date utility questions that must NEVER be answered
    from stored news context. Returns {detected, reason}.
    """
    raw = (text or "").strip()
    if not raw:
        return {"detected": False, "reason": "empty_text"}
    if _UTILITY_TIME_QUERY_RE.search(raw):
        return {"detected": True, "reason": "time_or_date_query"}
    if _UTILITY_WEATHER_QUERY_RE.search(raw):
        return {"detected": True, "reason": "weather_query"}
    return {"detected": False, "reason": "no_utility_signal"}


def _news_followup_should_defer_for_other_route(
    session_id: str | None,
    text: str,
    *,
    flow: str,
) -> dict:
    """Pre-flight gate for news follow-up resolvers.

    Returns {"defer": bool, "reason": str}. When defer=True, the caller must
    NOT run news follow-up logic for this turn — let it fall through to
    route_action_request() so the proper finance/utility/app route fires.

    Does NOT drop recent_news_context: utility/finance one-offs shouldn't
    invalidate prior news interest. If the message is a strong-new-topic
    (finance analytics keyword, math/code, app UI command, etc.), the
    existing `route_action_request` guard will drop the context downstream
    when appropriate. Personal/emotional turns are handled separately by
    `_news_followup_personal_emotional_guard`, which DOES drop context.
    """
    raw = (text or "").strip()
    if not raw:
        return {"defer": False, "reason": "empty_text"}

    # Pronoun-style follow-ups ("why was he there", "what does that mean")
    # without finance/utility verbs are exactly what the news follow-up
    # resolver exists for. Don't defer them.
    utility = _is_utility_route_message(raw)
    if utility["detected"]:
        _log_news_route_deferred(
            session_id, raw, flow=flow, reason=utility["reason"],
            category="utility",
        )
        return {"defer": True, "reason": utility["reason"]}

    if is_finance_analytics_query(raw):
        _log_news_route_deferred(
            session_id, raw, flow=flow, reason="finance_analytics_query",
            category="finance_analytics",
        )
        return {"defer": True, "reason": "finance_analytics_query"}

    strong = _is_strong_new_topic_message(raw)
    if strong.get("detected"):
        _log_news_route_deferred(
            session_id, raw, flow=flow, reason=str(strong.get("reason") or "strong_new_topic"),
            category="strong_new_topic",
        )
        return {"defer": True, "reason": str(strong.get("reason") or "strong_new_topic")}

    return {"defer": False, "reason": "no_other_route_signal"}


def _log_news_route_deferred(
    session_id: str | None,
    text: str,
    *,
    flow: str,
    reason: str,
    category: str,
) -> None:
    """Structured log emitted whenever a news follow-up resolver stands down
    because the turn belongs to a different domain (utility/finance/strong
    new topic). Grep target: [news_followup_deferred].
    """
    try:
        print(
            "[news_followup_deferred] "
            + json.dumps(
                {
                    "flow": flow,
                    "category": category,
                    "reason": reason,
                    "session_id": (session_id or "")[:64],
                    "user_text": (text or "")[:200],
                    "recent_news_context_kept": True,
                },
                ensure_ascii=False,
                default=str,
            ),
            flush=True,
        )
    except Exception:
        pass


# Stage 2 — strict whitelist for "clearly interpretive/explanatory" turns
# (PART 7A of the news router refactor spec). Used by
# `_stage2_news_followup_gate(...)` as the second-line filter on top of
# routeFamily, so that fresh-update / source-specific / new-topic follow-ups
# (e.g. "Who else was there?", "What happened after that?") fall through to
# `route_action_request(...)` rather than being served by the early news
# follow-up shortcut.
_STAGE2_INTERPRETIVE_RE = re.compile(
    r"^\s*(?:(?:ok(?:ay)?|so|hmm|well|but|and|just|hey|um|uh)\b\s*[,.!?]?\s*)*"
    r"(?:"
    # "why ..." anything (why was he, why did, why is that, "why?")
    r"why\b"
    # "what does/did/do that|this|it mean|imply|suggest|signify|indicate"
    r"|what\s+(?:does|do|did)\s+(?:that|this|it)\s+(?:mean|imply|suggest|signify|indicate|change)\b"
    # "what was/were/is the reason|point|cause|purpose|motivation|backstory"
    r"|what\s+(?:was|were|is)\s+(?:the\s+)?(?:reason|point|cause|purpose|motivation|backstory|significance|deal|big\s+deal)\b"
    # "is that bad|good|important|true|real|surprising|normal|legal|safe|unsafe|new|big|fine|ok|okay"
    r"|is\s+(?:that|this|it)\s+(?:bad|good|important|true|real|surprising|normal|legal|safe|unsafe|fine|ok|okay|new|big|notable|controversial|relevant|significant)\b"
    # "(can|could|would|will) you explain|elaborate|clarify|break that down"
    r"|(?:can|could|would|will)\s+you\s+(?:explain|elaborate|clarify|break\s+(?:that|this|it)\s+down|tell\s+me\s+more)\b"
    # "please explain|elaborate|clarify"
    r"|please\s+(?:explain|elaborate|clarify)\b"
    # bare "explain that|this|it|more|further|the reason|the context|the background"
    r"|explain\s+(?:that|this|it|more|further|the\s+(?:reason|reasoning|context|background|significance))?\b"
    r")",
    re.IGNORECASE,
)


def _stage2_news_followup_gate(
    session_id: str | None,
    text: str,
    *,
    flow: str,
    history: list[dict] | None = None,
) -> dict:
    """Stage 2 — gate the news follow-up shortcuts behind routeFamily.

    Allow rules:
      1. routeFamily == "news_followup_interpretive"
         AND text matches `_STAGE2_INTERPRETIVE_RE` (why was he / what does
         that mean / can you explain / ...). Strict whitelist because the
         interpretive family is conceptually narrower.
      2. routeFamily == "news_followup_llm_context" — Stage 2.5 LLM-first
         policy. The family itself is already gated by classify_route_family
         on `has_ctx` AND deictic-factoid shape AND no fresh/source trigger,
         so no extra whitelist check is needed here.

    Everything else — fresh_update, source_specific, current_fact, explicit
    news, finance, time, weather, app_action, personal_emotional,
    general_chat, clarification_needed — is BLOCKED so the request falls
    through to `route_action_request(...)` for proper dispatch.

    Returns:
        {
          "action": "allow" | "block",
          "reason": str,
          "routeFamily": str,
        }

    Side effect: one `[route_family_debug]` line with note set to one of:
      - stage2_allowed_interpretive_followup
      - stage2_allowed_llm_context_followup
      - stage2_blocked_news_followup
    """
    raw = (text or "").strip()
    try:
        ctx = get_recent_news_context(session_id) if session_id else None
    except Exception:
        ctx = None
    try:
        rf = classify_route_family(
            raw,
            session_id=session_id,
            history=history,
            recent_news_context=ctx,
        )
    except Exception:
        rf = _route_family_default(raw)
    route_family = str((rf or {}).get("routeFamily") or "general_chat")
    interpretive_match = bool(_STAGE2_INTERPRETIVE_RE.search(raw)) if raw else False
    if route_family == "news_followup_interpretive" and interpretive_match:
        allow = True
        reason = "news_followup_interpretive_with_whitelist_match"
        note = "stage2_allowed_interpretive_followup"
    elif route_family == "news_followup_llm_context":
        allow = True
        reason = "news_followup_llm_context_deictic_factoid"
        note = "stage2_allowed_llm_context_followup"
    elif route_family == "news_followup_interpretive" and not interpretive_match:
        allow = False
        reason = "interpretive_followup_failed_whitelist"
        note = "stage2_blocked_news_followup"
    else:
        allow = False
        reason = f"non_interpretive_route_family:{route_family}"
        note = "stage2_blocked_news_followup"
    try:
        log_route_family_debug(
            session_id,
            raw,
            mode=f"stage2_{flow}",
            route_family_result=rf,
            recent_news_context=ctx,
            note=note,
            chosen_context_reason=reason,
        )
    except Exception:
        pass
    return {
        "action": "allow" if allow else "block",
        "reason": reason,
        "routeFamily": route_family,
    }


def _news_followup_personal_emotional_guard(
    session_id: str | None,
    text: str,
    history: list[dict] | None,
    *,
    flow: str,
) -> bool:
    """Return True if a news follow-up resolver MUST stand down because the
    new message (or the recent chat) is personal/emotional. Side effects:
      - Drops `recent_news_context` for the session so subsequent vague
        turns don't keep inheriting the stale topic (spec Part 6).
      - Emits `[news_followup_suppressed]` with the spec debug fields.
    """
    raw = (text or "").strip()
    if not raw:
        return False
    new_msg_personal = _is_personal_news_statement(raw)
    new_msg_emotional = _is_emotional_distress_statement(raw)
    is_vague = _is_vague_followup_phrase(raw)
    recent_personal = _recent_chat_has_personal_emotional_context(history)
    explicit_news_target = bool(
        re.search(
            r"\b(?:summarize|summarise|open|read|show|tell\s+me\s+about)\s+(?:the\s+)?(?:first|second|third|fourth|fifth|next|previous|\d+(?:st|nd|rd|th)?|that|this)\s+(?:result|article|story|headline|news|news\s+result|card|item)\b"
            r"|\b(?:search|show)\s+more\s+(?:results?|news|articles?|stories?)\b"
            r"|\bwhat\s+(?:does|did)\s+(?:the\s+)?(?:result|article|story|headline|news\s+result)\s+say\b"
            r"|\bwhat\s+about\s+result\s+\d+\b",
            raw,
            re.IGNORECASE,
        )
    )
    suppressed = False
    reason = ""
    if explicit_news_target:
        # User explicitly references the side panel/result — leave it alone.
        return False
    if new_msg_personal or new_msg_emotional:
        suppressed = True
        reason = "new_message_personal_or_emotional"
    elif is_vague and recent_personal.get("detected"):
        suppressed = True
        reason = f"vague_followup_with_recent_personal_emotional:{recent_personal.get('category')}"
    if not suppressed:
        return False
    try:
        _log_news_followup_suppressed({
            "flow": flow,
            "latest_user_text": raw[:200],
            "new_message_personal_news": bool(new_msg_personal),
            "new_message_emotional": bool(new_msg_emotional),
            "vague_followup_detected": bool(is_vague),
            "recent_chat_personal_emotional_detected": bool(recent_personal.get("detected")),
            "recent_chat_emotional_category": recent_personal.get("category"),
            "recent_chat_context_excerpt": recent_personal.get("matched_text", ""),
            "active_side_panel": "news",
            "active_side_panel_allowed_as_context": False,
            "vague_followup_target": "recent_chat_context",
            "final_route": "general_llm",
            "reason": reason,
        })
    except Exception:
        pass
    # Drop the stale stored news context so the next vague turn can't
    # silently re-route here either.
    try:
        if session_id:
            recent_news_context.pop(session_id, None)
    except Exception:
        pass
    return True


def try_resolve_news_followup_streaming(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
):
    """Streaming version. Classifies the follow-up first:
      - interpretive / "tell me more" with rich context → LLM-from-context (no Serper).
      - new fact / latest update / new entity → fresh Serper search via the corrective path.

    Always short-circuits before any news work when the new message is
    personal/emotional, or when the recent chat is personal/emotional and the
    new message is just a vague follow-up like "I'm not sure how to feel".
    """
    if _news_followup_personal_emotional_guard(
        session_id, text, history, flow="streaming"
    ):
        return None
    # Stage 2: routeFamily gate. Only `news_followup_interpretive` turns
    # that also match the strict interpretive whitelist may use this
    # shortcut. Everything else (fresh_update, source_specific,
    # current_fact, explicit news, finance, time/weather, app_action,
    # general_chat, etc.) falls through to `route_action_request(...)`
    # so the action router picks the proper route. Emits one
    # `[route_family_debug]` line per turn.
    if _stage2_news_followup_gate(
        session_id, text, flow="streaming", history=history
    ).get("action") == "block":
        return None
    # PRE-FLIGHT (backstop): defer to route_action_request for
    # finance/utility/strong new topic. Stage 2 above already covers these,
    # but the original guard stays as belt-and-suspenders until Stage 7
    # demotion.
    if _news_followup_should_defer_for_other_route(
        session_id, text, flow="streaming"
    ).get("defer"):
        return None
    ctx = _get_or_synthesize_news_ctx(session_id, text, history)
    if not ctx:
        return None
    raw = (text or "").strip()
    if not raw:
        return None
    classification = _classify_news_followup_type(raw, ctx)
    _log_news_followup_strategy(
        {
            "user_text": raw[:200],
            "prior_topic": ctx.get("topic") or "",
            "prior_entities": list(ctx.get("entities") or [])[:8],
            "followup_type": classification.get("followup_type") or "",
            "strategy": classification.get("strategy") or "",
            "reason": classification.get("reason") or "",
        }
    )
    if classification.get("strategy") == "skip":
        return None
    if classification.get("followup_type") == "source_request":
        # Source requests are handled by the source-request pipeline (stored cards or
        # history-fallback search). Never run a fresh corrective Serper search here.
        return None
    if classification.get("strategy") == "answer_from_context":
        return _prepare_news_context_followup_streaming(session_id, raw, ctx)
    route = try_resolve_news_followup_corrective(
        session_id, text, history, filler_generation=filler_generation
    )
    if route is None:
        return None
    return prepare_streaming_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )


def try_resolve_news_followup_execute(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
) -> tuple[dict | None, float]:
    """Non-streaming version. Same classifier as the streaming path.

    Always short-circuits before any news work when the new message is
    personal/emotional, or when the recent chat is personal/emotional and
    the new message is just a vague follow-up like "what should I do now?".
    """
    if _news_followup_personal_emotional_guard(
        session_id, text, history, flow="execute"
    ):
        return None, 0.0
    # Stage 2: routeFamily gate. Mirror of the streaming gate so sync/typed
    # flow behaves identically. Only strict interpretive follow-ups proceed;
    # everything else falls through to `route_action_request(...)`.
    if _stage2_news_followup_gate(
        session_id, text, flow="execute", history=history
    ).get("action") == "block":
        return None, 0.0
    # PRE-FLIGHT (backstop): defer to route_action_request for
    # finance/utility/strong new topic — mirror of the streaming guard so
    # sync/typed flow behaves identically. Stage 7 will demote this once
    # Stage 2's routeFamily gate is proven in production.
    if _news_followup_should_defer_for_other_route(
        session_id, text, flow="execute"
    ).get("defer"):
        return None, 0.0
    ctx = _get_or_synthesize_news_ctx(session_id, text, history)
    if not ctx:
        return None, 0.0
    raw = (text or "").strip()
    if not raw:
        return None, 0.0
    classification = _classify_news_followup_type(raw, ctx)
    _log_news_followup_strategy(
        {
            "user_text": raw[:200],
            "prior_topic": ctx.get("topic") or "",
            "prior_entities": list(ctx.get("entities") or [])[:8],
            "followup_type": classification.get("followup_type") or "",
            "strategy": classification.get("strategy") or "",
            "reason": classification.get("reason") or "",
        }
    )
    if classification.get("strategy") == "skip":
        return None, 0.0
    if classification.get("followup_type") == "source_request":
        return None, 0.0
    if classification.get("strategy") == "answer_from_context":
        return _execute_news_context_followup_sync(session_id, raw, ctx)
    route = try_resolve_news_followup_corrective(
        session_id, text, history, filler_generation=filler_generation
    )
    if route is None:
        return None, 0.0
    return execute_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )


def _build_finance_correction_route(
    session_id: str, text: str, corrected_subject: str, recent: dict
) -> dict | None:
    """Build a route that reruns the prior finance intent with a corrected subject.

    Preserves the prior action_name (finance.quote / finance.context /
    finance.analytics) and the original user-text slot (so analytics keeps its
    metric context). Returns None if the prior intent isn't a finance one.
    """
    action_name = recent.get("action_name") or ""
    if action_name not in {"finance.quote", "finance.context", "finance.analytics"}:
        return None
    prior_slots = dict(recent.get("slots") or {})
    new_slots = {**prior_slots, "query": corrected_subject}
    # Carry the original user_text forward for analytics so the metric phrasing
    # ("biggest drawdown ... past 5 years") survives the rerun.
    if action_name == "finance.analytics":
        prior_user_text = (
            prior_slots.get("user_text")
            or _strip_finance_correction_phrase(text)
            or text
        )
        # Replace the wrong ticker mention in the prior user_text with the
        # corrected one so the LLM sees the intended subject.
        old_subject = (prior_slots.get("query") or "").strip()
        rewritten = prior_user_text
        if old_subject:
            rewritten = re.sub(
                rf"\b{re.escape(old_subject)}\b",
                corrected_subject,
                prior_user_text,
                flags=re.IGNORECASE,
            )
        new_slots["user_text"] = rewritten
    try:
        print(
            "[finance_correction_resolved] "
            + json.dumps(
                {
                    "session_id": (session_id or "")[:64],
                    "user_text": (text or "")[:200],
                    "prior_action": action_name,
                    "prior_subject": (prior_slots.get("query") or "")[:80],
                    "corrected_subject": corrected_subject[:80],
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    return {
        "is_action_request": True,
        "action_name": action_name,
        "slots": new_slots,
    }


def try_resolve_finance_correction_streaming(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
):
    """Streaming version of finance-correction resolution.

    Triggers when the user message is essentially just a subject correction
    ("I said VGT", "actually VGT", "no, VGT") AND there's a recent finance
    action. Bypasses the standard routing so we don't accidentally start a
    fresh finance.quote/general turn on the corrected subject alone.
    """
    raw = (text or "").strip()
    if not raw:
        return None
    corrected = extract_finance_correction_subject(raw)
    if not corrected:
        return None
    # Only resolve when the message is short — a long sentence with a "I said X"
    # tail is handled by the same-message correction inside route_action_request,
    # not here. This path is for standalone correction follow-ups.
    if len(raw.split()) > 8:
        return None
    recent = get_recent_action_context(session_id)
    if not recent:
        return None
    route = _build_finance_correction_route(session_id, text, corrected, recent)
    if not route:
        return None
    return prepare_streaming_structured_action(
        session_id, text, normalize_route(route), filler_generation=filler_generation
    )


def try_resolve_finance_correction_execute(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    filler_generation: int | None = None,
) -> tuple[dict | None, float]:
    """Non-streaming version. Same gating as the streaming path."""
    raw = (text or "").strip()
    if not raw:
        return None, 0.0
    corrected = extract_finance_correction_subject(raw)
    if not corrected:
        return None, 0.0
    if len(raw.split()) > 8:
        return None, 0.0
    recent = get_recent_action_context(session_id)
    if not recent:
        return None, 0.0
    route = _build_finance_correction_route(session_id, text, corrected, recent)
    if not route:
        return None, 0.0
    return execute_structured_action(
        session_id, text, normalize_route(route), filler_generation=filler_generation
    )


def try_prepare_streaming_pending_voice_action(
    session_id: str,
    text: str,
    history: list[dict],
    *,
    client_context_snapshot: dict | None = None,
    filler_generation: int | None = None,
):
    if _is_work_mode_snapshot(client_context_snapshot):
        return None
    history = history or []
    pending = _capture_pending_voice_offer(session_id, history) or _get_pending_voice_action(session_id)
    if not pending:
        return None
    if not _is_short_voice_followup_affirmative(text):
        return None
    route = _build_route_for_pending_voice_action(pending, session_id=session_id)
    if not route:
        return None
    prepared = prepare_streaming_structured_action(
        session_id, text, route, filler_generation=filler_generation
    )
    if prepared is None:
        return None
    _clear_pending_voice_action(session_id)
    assistant_text, previous_user_text = _last_assistant_and_previous_user_from_history(history)
    _log_voice_followup_resolution(
        {
            "user_text": (text or "")[:200],
            "previous_user_text": previous_user_text[:200],
            "previous_assistant_text": assistant_text[:200],
            "pending_action_type": pending.get("action_type"),
            "pending_topic": pending.get("topic"),
            "resolved_followup": True,
            "reason": "executed_pending_voice_action_streaming",
        }
    )
    return prepared


def resolve_recent_action_followup(
    session_id: str,
    text: str,
    history: list[dict],
    filler_generation: int | None = None,
) -> tuple[dict | None, float]:
    recent = get_recent_action_context(session_id)
    if not recent:
        return None, 0.0

    candidate = extract_short_followup_value(text)
    if not candidate:
        return None, 0.0

    if is_i_meant_followup(text) and not should_allow_i_meant_recent_followup(recent, history):
        return None, 0.0

    action_name = recent.get("action_name")
    recent_slots = recent.get("slots", {})
    route = None

    if action_name in {"weather.current", "time.current", "date.current"} and is_plausible_location(candidate):
        route = {
            "is_action_request": True,
            "action_name": action_name,
            "slots": {"location": candidate},
        }
    elif action_name == "date.delta":
        if is_supported_date_target(candidate):
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": candidate,
                    "location": recent_slots.get("location"),
                },
            }
        elif is_plausible_location(candidate):
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": recent_slots.get("target_name"),
                    "location": candidate,
                },
            }
        else:
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": candidate,
                    "location": recent_slots.get("location"),
                },
            }
    elif action_name == "news.latest":
        query = build_news_followup_query(recent_slots.get("query"), candidate)
        if query:
            route = {
                "is_action_request": True,
                "action_name": "news.latest",
                "slots": {"query": query},
            }
    elif action_name in {"finance.quote", "finance.context"}:
        route = build_finance_followup_route(action_name, recent_slots.get("query"), candidate)

    if not route:
        return None, 0.0

    action_result, t_llm = execute_structured_action(session_id, text, normalize_route(route), filler_generation=filler_generation)
    if action_result is None:
        return None, t_llm

    if action_result.get("data") is None:
        return None, 0.0

    return action_result, t_llm


def prepare_streaming_followup(
    session_id: str,
    text: str,
    history: list[dict],
    filler_generation: int | None = None,
) -> PreparedStreamingAction | None:
    recent = get_recent_action_context(session_id)
    if not recent:
        return None

    candidate = extract_short_followup_value(text)
    if not candidate:
        return None

    if is_i_meant_followup(text) and not should_allow_i_meant_recent_followup(recent, history):
        return None

    action_name = recent.get("action_name")
    recent_slots = recent.get("slots", {})
    route = None

    if action_name in {"weather.current", "time.current", "date.current"} and is_plausible_location(candidate):
        route = {
            "is_action_request": True,
            "action_name": action_name,
            "slots": {"location": candidate},
        }
    elif action_name == "date.delta":
        if is_supported_date_target(candidate):
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": candidate,
                    "location": recent_slots.get("location"),
                },
            }
        elif is_plausible_location(candidate):
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": recent_slots.get("target_name"),
                    "location": candidate,
                },
            }
        else:
            route = {
                "is_action_request": True,
                "action_name": "date.delta",
                "slots": {
                    "target_name": candidate,
                    "location": recent_slots.get("location"),
                },
            }
    elif action_name == "news.latest":
        query = build_news_followup_query(recent_slots.get("query"), candidate)
        if query:
            route = {
                "is_action_request": True,
                "action_name": "news.latest",
                "slots": {"query": query},
            }
    elif action_name in {"finance.quote", "finance.context"}:
        route = build_finance_followup_route(action_name, recent_slots.get("query"), candidate)

    if not route:
        return None

    return prepare_streaming_structured_action(session_id, text, normalize_route(route), filler_generation=filler_generation)


def try_prepare_streaming_action_messages(
    session_id: str, text: str, history: list[dict], filler_generation: int | None = None
) -> PreparedStreamingAction | None:
    try:
        if _is_memory_command_request(text):
            return None
    except Exception:
        pass
    log_route_debug(
        session_id,
        text,
        stage="streaming_action_entry",
        selected_route="pre_route",
        selected_action_name="",
        should_search=False,
        serper_called=False,
        used_recent_news_context=False,
        note="before source/voice/finance/news followup shortcuts",
    )
    # Stage 1: shadow log only. classify_route_family() does NOT yet gate
    # any shortcut below. Compare `routeFamily` against the actually-selected
    # action in downstream `[route_debug]` lines to validate Stage 2 wiring.
    try:
        _rf_ctx_stream = get_recent_news_context(session_id) if session_id else None
    except Exception:
        _rf_ctx_stream = None
    try:
        _rf_result_stream = classify_route_family(
            text,
            session_id=session_id,
            history=history,
            recent_news_context=_rf_ctx_stream,
        )
    except Exception:
        _rf_result_stream = None
    log_route_family_debug(
        session_id,
        text,
        mode="streaming",
        route_family_result=_rf_result_stream,
        recent_news_context=_rf_ctx_stream,
        note="shadow_only_streaming_entry",
    )
    pending = get_pending_action(session_id)
    if pending and pending.get("action_name") in ("weather.current", "weather.forecast") and pending.get(
        "missing_slot"
    ) in ("location", "time", "both"):
        return None
    # 2026-05-28 PART 1 — beta info-tool router clarification follow-up.
    # Same shape as the weather pending guard: defer streaming so the sync
    # path's `resolve_pending_web_search_request` handles the re-ask reply.
    if pending and pending.get("action_name") == "web.search" and pending.get("missing_slot") == "location":
        return None
    if pending and pending.get("action_name") == "news.latest" and pending.get("missing_slot") == "breaking_intent":
        return None
    if pending and pending.get("action_name") in {"finance.quote", "finance.context"}:
        return None
    if pending and pending.get("action_name") == "music.play_track" and pending.get("missing_slot") == "track_query":
        return None
    if pending and pending.get("action_name") == "music.play_album" and pending.get("missing_slot") == "album_query":
        return None
    if pending and pending.get("action_name") == "music.play_playlist" and pending.get("missing_slot") == "playlist_name":
        return None

    # Explicit source requests must override the general/LLM path. Detect first and
    # try the fresh-search fallback (uses prev user topic + assistant reply when there's
    # no stored news context). Stored-context path is handled in the sync resolver.
    source_pattern_stream = _match_source_request_pattern(text)
    if source_pattern_stream is not None:
        ctx_for_sources = get_recent_news_context(session_id)
        # If we have stored source CARDS, defer to the sync path which renders the
        # cards verbatim (title, outlet, date, link) instead of asking the LLM to
        # write another prose summary. Returning None short-circuits streaming so
        # resolve_reply_if_not_general_llm runs and returns the cards action_result.
        if _stored_sources_have_cards(ctx_for_sources):
            _log_source_request_detection(
                text, source_pattern_stream,
                has_last_news_context=True,
                fallback_topic_from_previous_turn="",
                final_action="news.sources_from_context_via_sync",
            )
            return None
        from_sources_fallback = try_resolve_news_sources_fallback_streaming(
            session_id, text, history, filler_generation=filler_generation
        )
        if from_sources_fallback is not None:
            fallback_topic = ""
            try:
                # Inspect the route slots embedded inside the prepared action's messages
                # is tricky; instead, rebuild the route once for logging only.
                preview_route = _build_sources_fallback_route(session_id, text, history)
                if preview_route is not None:
                    fallback_topic = str((preview_route.get("slots") or {}).get("query") or "")
            except Exception:
                fallback_topic = ""
            _log_source_request_detection(
                text, source_pattern_stream,
                has_last_news_context=ctx_for_sources is not None,
                fallback_topic_from_previous_turn=fallback_topic,
                final_action="news.latest_from_history_streaming",
            )
            return from_sources_fallback
        # No stored cards and no fallback route either; let sync/general handle it.
        _log_source_request_detection(
            text, source_pattern_stream,
            has_last_news_context=ctx_for_sources is not None,
            fallback_topic_from_previous_turn="",
            final_action="deferred_to_sync_or_general",
        )

    from_voice_offer = try_prepare_streaming_pending_voice_action(
        session_id,
        text,
        history,
        filler_generation=filler_generation,
    )
    if from_voice_offer is not None:
        return from_voice_offer

    from_finance_correction = try_resolve_finance_correction_streaming(
        session_id, text, history, filler_generation=filler_generation
    )
    if from_finance_correction is not None:
        return from_finance_correction

    from_news_corrective = try_resolve_news_followup_streaming(
        session_id, text, history, filler_generation=filler_generation
    )
    if from_news_corrective is not None:
        log_route_debug(
            session_id,
            text,
            stage="streaming_selected_news_followup",
            selected_route="news_followup_streaming",
            selected_action_name="news.context_or_latest",
            should_search=False,
            serper_called=False,
            used_recent_news_context=True,
            final_answer_source="stored_source_context_or_news_action",
            note="returned before route_action_request utility/finance router",
        )
        return from_news_corrective

    from_followup = prepare_streaming_followup(session_id, text, history, filler_generation)
    if from_followup is not None:
        _route_debug_recent = get_recent_action_context(session_id) or {}
        log_route_debug(
            session_id,
            text,
            stage="streaming_selected_recent_action_followup",
            selected_route="recent_action_followup_streaming",
            selected_action_name=str(_route_debug_recent.get("action_name") or "recent_action"),
            should_search=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            serper_called=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            used_recent_news_context=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            final_answer_source="recent_action",
            note="returned before route_action_request final router",
        )
        return from_followup

    route = route_action_request(session_id, text)
    if not route.get("is_action_request"):
        log_route_debug(
            session_id,
            text,
            stage="streaming_selected_general_llm",
            selected_route="general",
            selected_action_name="general",
            should_search=False,
            serper_called=False,
            used_recent_news_context=False,
            final_answer_source="llm_general",
        )
        return None
    log_route_debug(
        session_id,
        text,
        stage="streaming_selected_route_action",
        selected_route=route.get("domain") or "",
        selected_action_name=route.get("action_name") or "",
        should_search=route.get("action_name") == "news.latest",
        serper_called=route.get("action_name") == "news.latest",
        used_recent_news_context=bool(route.get("action_name") == "news.latest" and get_recent_news_context(session_id)),
        final_answer_source="action",
    )
    return prepare_streaming_structured_action(session_id, text, route, filler_generation=filler_generation)


def _inject_thread_follow_up_anchor(
    messages: list[dict], anchor: str | None, user_transcript: str
) -> list[dict]:
    if not anchor or not str(anchor).strip():
        return messages
    a = str(anchor).strip()[:4000]
    block = (
        "Work mode — thread grounding (trusted):\n"
        "The user's CURRENT message may be short or vague (pronouns, 'the north', 'why did they', etc.). "
        "Interpret it as a FOLLOW-UP to their IMMEDIATELY PRIOR topic below — NOT as switching to a "
        "different famous topic that shares the same ambiguous phrase.\n\n"
        f'Prior topic / request (anchor): "{a}"\n\n'
        f'Current user words: "{user_transcript}"\n\n'
        "Answer about the anchor topic unless the user clearly names a different subject. "
        "Example: anchor was Vietnam War → 'how did the north win' refers to North Vietnamese / DRV "
        "success vs South Vietnam — not the American Civil War unless they explicitly say so."
    )
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out


def _reasoning_voice_same_panel_no_auto_route(client_context: dict | None) -> bool:
    """True when reasoning stays on the user's active panel (auto-route off)."""
    if not isinstance(client_context, dict):
        return False
    ar = client_context.get("reasoning_auto_route")
    if ar is False or ar == 0:
        return True
    if isinstance(ar, str) and ar.strip().lower() in ("false", "0", "no", "off"):
        return True
    return False


def _default_reasoning_voice_handoff_line(same_panel: bool) -> str:
    """Canned second line for single-line digests; same-panel mode keeps it rare (~10%)."""
    if not same_panel:
        return "I'm opening a full step-by-step explanation now."
    return "I'm opening a full step-by-step explanation now." if random.random() < 0.1 else ""


def _inject_reasoning_voice_coach(
    messages: list[dict],
    coach: str | None,
    user_transcript: str,
    client_context: dict | None = None,
) -> list[dict]:
    if not coach or not str(coach).strip():
        return messages
    digest = str(coach).strip()
    digest_lines = [ln.strip() for ln in digest.replace("\r", "\n").split("\n") if ln.strip()]
    answer_line = digest_lines[0] if digest_lines else digest
    same_panel = _reasoning_voice_same_panel_no_auto_route(client_context)
    if len(digest_lines) > 1:
        handoff_line = digest_lines[1]
    else:
        handoff_line = _default_reasoning_voice_handoff_line(same_panel)

    if same_panel and not handoff_line:
        block = (
            "Work mode: a reasoning partner produced this spoken digest (the user does not see the long markdown plan):\n"
            f"\"{digest}\"\n\n"
            f"Digest line 1 (core idea): \"{answer_line}\"\n\n"
            f"The user's words in this turn were: \"{user_transcript}\".\n"
            "Respond for voice in ONE short sentence that expresses the core idea from digest line 1.\n"
            "Do not mention markdown, models, digests, panels, or that you are opening or routing to an explanation."
        )
    else:
        block = (
            "Work mode: a reasoning partner produced this spoken digest (the user does not see the long markdown plan):\n"
            f"\"{digest}\"\n\n"
            f"Digest line 1 (core idea): \"{answer_line}\"\n"
            f"Digest line 2 (handoff): \"{handoff_line}\"\n\n"
            f"The user's words in this turn were: \"{user_transcript}\".\n"
            "Respond for voice in exactly 2 short sentences.\n"
            "Sentence 1 must express the core idea from digest line 1.\n"
            "Sentence 2 must be an explicit handoff into deeper reasoning and should closely follow digest line 2.\n"
            "Do not mention markdown, models, digests, panels, or internal routing."
        )
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out


def _normalize_reasoning_voice_reply(coach: str | None, client_context: dict | None = None) -> str | None:
    if not coach or not str(coach).strip():
        return None
    lines = [ln.strip() for ln in str(coach).replace("\r", "\n").split("\n") if ln.strip()]
    if not lines:
        return None
    answer = lines[0]
    same_panel = _reasoning_voice_same_panel_no_auto_route(client_context)
    if len(lines) > 1:
        handoff = lines[1]
    else:
        handoff = _default_reasoning_voice_handoff_line(same_panel)
    if not re.search(r"[.!?]$", answer):
        answer = f"{answer}."
    if not handoff:
        return answer
    if not re.search(r"[.!?]$", handoff):
        handoff = f"{handoff}."
    return f"{answer} {handoff}"


def _inject_reasoning_attachment_context(
    messages: list[dict], attachment_context: str | None, user_transcript: str
) -> list[dict]:
    if not attachment_context or not str(attachment_context).strip():
        return messages
    ctx = str(attachment_context).strip()
    block = (
        "Work mode: the user uploaded a file this turn. The excerpt below was extracted from that file.\n"
        "You MUST treat it as authoritative source material for this turn whenever the user refers to "
        "the file, the document, the image, or what it contains. If the excerpt is incomplete, say what "
        "you can see and ask one focused follow-up.\n\n"
        f"{ctx}\n\n"
        f"The user's words in this turn were: \"{user_transcript}\"."
    )
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out


def _normalize_work_mode_reasoning_context_payload(raw: object) -> dict | None:
    if raw is None:
        return None
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return None
        try:
            obj = json.loads(s)
            return obj if isinstance(obj, dict) else None
        except Exception:
            return None
    return None


def _normalize_work_mode_stage2_turn(raw: object) -> dict | None:
    if raw is None:
        return None
    if isinstance(raw, dict):
        return raw or None
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return None
        try:
            obj = json.loads(s)
            return obj if isinstance(obj, dict) else None
        except Exception:
            return None
    return None


def _detect_substantive_work_mode_reasoning_answer(raw: str, turn_intent: str = "") -> bool:
    text = (raw or "").strip()
    low = text.lower()
    intent = (turn_intent or "").strip().lower()
    if len(text) < 80:
        return False
    solved_signals = (
        r"\bfinal answer\b",
        r"\btherefore[,]?\s+",
        r"\bconclusion\b",
        r"\bthe (?:call|put|option) (?:is worth|price is|premium is)\b",
        r"\b=\s*\$?[\d,]+(?:\.\d+)?",
        r"\bin one sentence\b",
        r"\bkey terms\b",
    )
    if any(re.search(p, text, re.I) for p in solved_signals):
        return True
    if "```" in text and len(text) >= 100:
        return True
    if re.search(r"\|.+\|.+\|", text) and len(text) >= 140:
        return True
    has_headings = bool(re.search(r"^#{1,6}\s", text, re.M))
    has_bullets = bool(re.search(r"^\s*[-*•]\s", text, re.M) or re.search(r"^\s*\d+\.\s", text, re.M))
    has_table = bool(re.search(r"\|.+\|.+\|", text) or re.search(r"\|\s*---+\s*\|", text))
    paragraphs = len(re.findall(r"\n\s*\n", text))
    explain_like = intent in {"explain", "summarize", "plan"} or re.search(
        r"\b(explain|overview|summary|background|timeline|essay|outline)\b", low
    )
    if explain_like and len(text) >= 320 and (has_headings or has_bullets or has_table or paragraphs >= 2):
        return True
    if has_headings and has_bullets and len(text) >= 220:
        return True
    if paragraphs >= 2 and len(text) >= 400:
        return True
    if len(text) >= 700 and (has_headings or has_bullets or has_table):
        return True
    return False


def _detect_explicit_partial_work_mode_reasoning(raw: str) -> bool:
    patterns = (
        r"\bpartial(?:ly)? (?:complete|completed|done|finished|solved)\b",
        r"\bpartial progress\b",
        r"\bincomplete\b",
        r"\bunfinished\b",
        r"\bdraft only\b",
        r"\bsetup only\b",
        r"\bonly (?:the )?setup\b",
        r"\bcannot finish yet\b",
        r"\bnot fully finished\b",
        r"\bnot (?:yet )?complete\b",
        r"\bstill working on\b",
        r"\b(incomplete|partial) (?:setup|draft|solution|answer|work)\b",
        r"\bhave(?:n't| not) finished\b",
        r"\bcan't finish yet\b",
    )
    return any(re.search(p, raw, re.I) for p in patterns)


def _classify_work_mode_same_turn_result_status(text: str, turn_intent: str = "") -> dict:
    """Mirror client heuristics: classify same-turn reasoning excerpt for Stage 2 voice."""
    raw = (text or "").strip()
    low = raw.lower()
    missing: list[str] = []
    if re.search(r"\bvolatility\b|\bsigma\b|σ", raw, re.I):
        missing.append("volatility σ")
    if re.search(r"\brisk-?free rate\b", raw, re.I):
        missing.append("risk-free rate r")
    if re.search(r"\bdividend yield\b", raw, re.I):
        missing.append("dividend yield q")

    substantive = _detect_substantive_work_mode_reasoning_answer(raw, turn_intent)
    explicit_partial = _detect_explicit_partial_work_mode_reasoning(raw)
    needs_patterns = (
        r"\bmissing inputs?\b",
        r"\bunder-?specified\b",
        r"\bstill need\b",
        r"\bi still need\b",
        r"\bnot (?:shown|provided|given|included)\b",
        r"\bwithout those\b",
        r"\bplease (?:provide|send|supply|give)\b",
        r"\bneed (?:the )?(?:following|missing)\b",
        r"\bcannot (?:compute|calculate|solve|finish)\b[^\n]{0,80}\bwithout\b",
        r"\bcan't (?:compute|calculate|solve|finish)\b[^\n]{0,80}\bwithout\b",
        r"\bone important issue\b",
        r"\bbefore i can (?:finish|complete|solve)\b",
        r"\bmissing parameters?\b",
        r"\bneed more information\b",
        r"\bneed (?:volatility|risk-?free|dividend)\b",
        r"\b#{1,6}\s*missing inputs?\b",
    )
    explicit_missing = any(re.search(p, raw, re.I) for p in needs_patterns) or (
        len(missing) >= 1
        and re.search(
            r"\b(?:missing inputs?|under-?specified|still need|cannot .{0,80} without|"
            r"before i can (?:finish|complete|solve)|need (?:volatility|risk-?free|dividend))\b",
            low,
        )
    )

    if not raw:
        status, reason = "failed", "empty_output"
    elif re.search(r"\b(reasoning error|stream failed|could not complete)\b", raw, re.I):
        status, reason = "failed", "stream_error_text"
    elif explicit_missing:
        status, reason = "needs_missing_info", "explicit_missing_info"
    elif (
        re.search(
            r"\b(which one|could you clarify|please confirm|do you mean|need clarification|could you specify)\b",
            low,
        )
        and "?" in raw
        and not substantive
    ):
        status, reason = "clarification_required", "clarification_question"
    elif explicit_partial and not substantive:
        status, reason = "partially_completed", "explicit_partial_language"
    elif substantive:
        status, reason = "solved", "substantive_answer_detected"
    elif explicit_partial:
        status, reason = "partially_completed", "explicit_partial_with_substance"
    elif len(raw) >= 120:
        status, reason = "solved", "default_substantive_length"
    else:
        status, reason = "failed", "insufficient_content"

    return {
        "status": status,
        "missing_inputs": missing[:8],
        "same_turn_summary_preview": raw[:220],
        "status_reason": reason,
        "explicit_missing_info_found": explicit_missing,
        "explicit_partial_found": explicit_partial,
        "substantive_answer_detected": substantive,
    }


def _should_use_canned_stage2_spoken_line(status: str, detected: dict | None) -> bool:
    st = (status or "").strip().lower()
    det = detected or {}
    if st in {"needs_missing_info", "clarification_required", "failed"}:
        return True
    if st == "partially_completed":
        return bool(det.get("explicit_partial_found"))
    return False


def _stage2_status_scope_matches(
    stage2_turn: dict | None,
    wm_ctx: dict | None,
) -> bool:
    """Stage 2 status/missing_inputs apply only when turn_id and lane_id match."""
    st = stage2_turn or {}
    wm = wm_ctx or {}
    cur_turn = str(st.get("turn_id") or "").strip()
    cur_lane = str(st.get("lane_id") or "").strip()
    status_turn = str(wm.get("status_turn_id") or st.get("turn_id") or "").strip()
    status_lane = str(wm.get("status_lane_id") or wm.get("active_lane_id") or "").strip()
    if status_turn and cur_turn and status_turn != cur_turn:
        return False
    if status_lane and cur_lane and status_lane != cur_lane:
        return False
    if status_turn and not cur_turn:
        return False
    return True


def _log_stage2_status_scope_check(
    *,
    stage2_turn: dict | None,
    wm_ctx: dict | None,
    detected: dict | None,
    status_used: bool,
    reason: str,
    status_source: str = "",
) -> None:
    st = stage2_turn or {}
    wm = wm_ctx or {}
    row = {
        "current_turn_id": st.get("turn_id"),
        "current_lane_id": st.get("lane_id"),
        "status_turn_id": wm.get("status_turn_id") or st.get("turn_id"),
        "status_lane_id": wm.get("status_lane_id") or wm.get("active_lane_id"),
        "status_used": bool(status_used),
        "detected_status": (detected or {}).get("status"),
        "missing_inputs": (detected or {}).get("missing_inputs") or [],
        "reason": reason,
        "status_source": status_source,
    }
    try:
        print("[stage2_status_scope_check] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _resolve_stage2_result_status(
    wm_ctx: dict | None,
    stage2_turn: dict | None,
) -> dict:
    st = stage2_turn or {}
    wm = wm_ctx or {}
    scope_ok = _stage2_status_scope_matches(stage2_turn, wm_ctx)
    client_status = str(st.get("reasoning_result_status") or wm.get("same_turn_result_status") or "").strip()
    client_missing = st.get("missing_inputs") or wm.get("missing_inputs") or []
    if not isinstance(client_missing, list):
        client_missing = []
    excerpt = str(wm.get("same_turn_reasoning_excerpt") or wm.get("main_context_excerpt") or "").strip()
    summary = str(wm.get("latest_reasoning_summary") or "").strip()
    turn_intent = str(st.get("turn_intent") or wm.get("turn_intent") or "").strip()
    classified = _classify_work_mode_same_turn_result_status(f"{excerpt}\n{summary}", turn_intent)
    if client_status and scope_ok:
        classified["status"] = client_status
        if client_missing:
            classified["missing_inputs"] = [str(x) for x in client_missing if str(x).strip()][:8]
        _log_stage2_status_scope_check(
            stage2_turn=stage2_turn,
            wm_ctx=wm_ctx,
            detected=classified,
            status_used=True,
            reason="client_status_scope_ok",
            status_source="client",
        )
    elif client_status and not scope_ok:
        _log_stage2_status_scope_check(
            stage2_turn=stage2_turn,
            wm_ctx=wm_ctx,
            detected=classified,
            status_used=False,
            reason="client_status_scope_mismatch",
            status_source="client",
        )
    else:
        _log_stage2_status_scope_check(
            stage2_turn=stage2_turn,
            wm_ctx=wm_ctx,
            detected=classified,
            status_used=False,
            reason="classified_from_excerpt",
            status_source="server_classify",
        )
    preview = str(st.get("same_turn_summary_preview") or wm.get("same_turn_summary_preview") or "").strip()
    if preview:
        classified["same_turn_summary_preview"] = preview[:220]
    return classified


def _log_stage2_result_status(
    *,
    transcript: str,
    reply: str,
    wm_ctx: dict | None,
    stage2_turn: dict | None,
) -> None:
    st = stage2_turn or {}
    detected = _resolve_stage2_result_status(wm_ctx, stage2_turn)
    used_canned = bool(
        _should_use_canned_stage2_spoken_line(str(detected.get("status") or ""), detected)
        and (str(reply or "").strip())
    )
    row = {
        "turn_id": st.get("turn_id"),
        "user_text": st.get("current_user_text") or transcript,
        "detected_status": detected.get("status"),
        "status_reason": detected.get("status_reason"),
        "explicit_missing_info_found": bool(detected.get("explicit_missing_info_found")),
        "explicit_partial_found": bool(detected.get("explicit_partial_found")),
        "substantive_answer_detected": bool(detected.get("substantive_answer_detected")),
        "generated_stage2_text": (str(reply or ""))[:500],
        "used_canned_line": used_canned,
        "missing_inputs": detected.get("missing_inputs") or [],
    }
    try:
        print("[stage2_result_status] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _log_stage2_voice_generation(
    *,
    transcript: str,
    reply: str,
    wm_ctx: dict | None,
    stage2_turn: dict | None,
    spoken_override: str | None = None,
) -> None:
    st = stage2_turn or {}
    wm = wm_ctx or {}
    detected = _resolve_stage2_result_status(wm_ctx, stage2_turn)
    row = {
        "turn_id": st.get("turn_id"),
        "lane_id": st.get("lane_id"),
        "lane_title": st.get("lane_title"),
        "current_user_text": st.get("current_user_text") or transcript,
        "turn_intent": st.get("turn_intent"),
        "reasoning_result_status": detected.get("status"),
        "main_context_type": wm.get("main_context_type"),
        "reasoning_summary_preview": (str(wm.get("latest_reasoning_summary") or ""))[:220],
        "generated_stage2_text": (str(reply or ""))[:500],
        "spoken_override": spoken_override,
    }
    try:
        print("[stage2_voice_generation] " + json.dumps(row, ensure_ascii=False), flush=True)
    except Exception:
        pass
    _log_stage2_result_status(
        transcript=transcript,
        reply=reply,
        wm_ctx=wm_ctx,
        stage2_turn=stage2_turn,
    )


def _inject_work_mode_reasoning_handoff(
    messages: list[dict],
    ctx: dict | None,
    user_transcript: str,
) -> list[dict]:
    """Structured handoff from the browser's active reasoning lane into Voice /infer."""
    if not ctx:
        return messages
    main_excerpt = str(ctx.get("main_context_excerpt") or "").strip()
    excerpt = main_excerpt or str(ctx.get("latest_final_answer_excerpt") or "").strip()
    if len(excerpt) > 12000:
        excerpt = f"{excerpt[:12000]}\n…"
    same_turn = str(ctx.get("same_turn_reasoning_excerpt") or "").strip()
    if len(same_turn) > 12000:
        same_turn = f"{same_turn[:12000]}\n…"
    lane_bg = str(ctx.get("lane_background_excerpt") or "").strip()
    if len(lane_bg) > 8000:
        lane_bg = f"{lane_bg[:8000]}\n…"
    grounding = str(ctx.get("stage2_grounding") or "").strip()
    summary = str(ctx.get("latest_reasoning_summary") or "").strip()
    if len(summary) > 2500:
        summary = f"{summary[:2500]}…"
    preview_src = main_excerpt or str(ctx.get("latest_markdown_preview") or "").strip()
    preview = preview_src
    if len(preview) > 3500:
        preview = f"{preview[:3500]}…"
    main_context_type = str(ctx.get("main_context_type") or "").strip()
    lane_title = str(ctx.get("title") or ctx.get("lane_title") or "").strip()
    lines = [
        "ACTIVE_WORK_MODE_REASONING_CONTEXT (authoritative for this voice turn; mirrors the Reasoning panel):",
        "",
        f"- active_lane_id: {str(ctx.get('active_lane_id') or '').strip()}",
        f"- lane_title: {lane_title}",
        f"- main_context_type: {main_context_type}",
        f"- same_turn_result_status: {str(ctx.get('same_turn_result_status') or '').strip()}",
        f"- stage2_grounding: {grounding or '(not set)'}",
        f"- last_user_request: {str(ctx.get('last_user_request') or '').strip()}",
        f"- prior_problem_anchor: {str(ctx.get('prior_problem_anchor') or '').strip()}",
        f"- latest_reasoning_summary: {summary}",
        f"- latest_markdown_preview:\n{preview}",
        f"- main_context_excerpt:\n{excerpt}",
        f"- latest_final_answer_excerpt:\n{excerpt}",
        f"- code_or_math_generated: {bool(ctx.get('code_or_math_generated'))}",
        "",
    ]
    if same_turn:
        lines.extend(
            [
                "SAME_TURN_REASONING_RESULT (finished in this voice turn — **highest priority** for strike prices, "
                "problem numbers, and what was just solved or written; ignore conflicting older phrasing elsewhere):",
                same_turn,
                "",
            ]
        )
    if lane_bg:
        lines.extend(
            [
                "LANE_BACKGROUND_EXCERPT (older lane state — use only if SAME_TURN / main excerpt is empty; "
                "never prefer this over SAME_TURN for which problem or variant was just completed):",
                lane_bg,
                "",
            ]
        )
    lines.extend(
        [
            "Rules:",
            "- For deictic references (this problem, this answer, the code, that solution), treat this block as the **primary** anchor; "
            "do not let unrelated Voice UI chat override it.",
            "- If SAME_TURN_REASONING_RESULT is present, your spoken summary must reflect **that** work (what just finished), "
            "not an older problem still mentioned in LANE_BACKGROUND_EXCERPT or prior panels.",
            "- The spoken line may be a short follow-up ('this problem', 'the code', 'show me', 'that answer'). "
            "If excerpt or summary is non-empty, the substantive work is already in the reasoning lane — "
            "confirm briefly (e.g. Python code is in the reasoning space) instead of asking for the full problem again.",
            "- Do not contradict this context; do not claim you lack the problem when excerpt/summary shows the solution.",
            f"- Current spoken user line: \"{user_transcript}\".",
        ]
    )
    block = "\n".join(lines)
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out


def _inject_work_mode_voice_brief_completion_rules(
    messages: list[dict],
    brief: bool,
    user_transcript: str,
    stage2_also_prefix: bool = False,
    stage2_turn: dict | None = None,
) -> list[dict]:
    """
    After the Work Mode reasoning stream, Voice UI /infer should give a single spoken summary
    that points at the Reasoning panel — not a full repeat of the written answer.
    """
    if not brief:
        return messages
    also_rule = ""
    if stage2_also_prefix:
        also_rule = (
            "\n- The user may have continued with another request since you acknowledged this task. "
            "Begin your one sentence with the word **Also** immediately followed by a comma, then the summary "
            '(spoken as "Also, …"), still in **past tense** after the comma.'
        )
    st = stage2_turn or {}
    turn_intent = str(st.get("turn_intent") or "general").strip().lower() or "general"
    current_line = str(st.get("current_user_text") or user_transcript or "").strip()
    lane_id = str(st.get("lane_id") or "").strip()
    lane_title = str(st.get("lane_title") or "").strip()
    turn_id = str(st.get("turn_id") or "").strip()
    content_type = str(st.get("content_type_requested") or "").strip()
    action = str(st.get("stage2_completion_action") or "").strip()
    result_status = str(st.get("reasoning_result_status") or "").strip().lower()
    missing_inputs = st.get("missing_inputs") or []
    if not isinstance(missing_inputs, list):
        missing_inputs = []
    missing_json = json.dumps([str(x) for x in missing_inputs if str(x).strip()][:8], ensure_ascii=False)
    ut_json = json.dumps(str(user_transcript or ""), ensure_ascii=False)
    cl_json = json.dumps(current_line, ensure_ascii=False)
    status_rules = ""
    if result_status:
        status_rules = (
            "\n\nSAME_TURN_RESULT_STATUS (from same-turn reasoning stream — **highest priority**; do not claim success if status is not solved):\n"
            f"- **{result_status}**\n"
            + (f"- MISSING_INPUTS: {missing_json}\n" if missing_inputs else "")
            + "\n- Status meanings (one past-tense sentence, point to the reasoning panel):\n"
            "  - **solved**: the reasoning panel has a complete final answer — you may say you solved or finished it there.\n"
            "  - **partially_completed**: some progress or setup is in the panel, but it is **not** fully finished.\n"
            "  - **needs_missing_info**: the panel says inputs are missing / under-specified — say you set up the problem "
            "but still need the missing inputs (name them briefly if known) before you can finish; **never** say you solved it.\n"
            "  - **clarification_required**: the panel needs a clarification from the user before finishing.\n"
            "  - **failed**: reasoning did not complete — say you could not finish it and point to the panel.\n"
            "- **Forbidden when status is needs_missing_info, clarification_required, failed, or partially_completed:** "
            '"I solved it", "I worked out the problem", "the full answer is ready", "I finished solving it".\n'
        )
    intent_rules = (
        "\n\nCURRENT_TURN_INTENT (secondary — how the user phrased the request; do not override SAME_TURN_RESULT_STATUS):\n"
        f"- **{turn_intent}**"
        + (f"\n- CONTENT_TYPE_REQUESTED: {content_type}" if content_type else "")
        + (f"\n- STAGE2_COMPLETION_ACTION: {action}" if action else "")
        + (f"\n- FROZEN_TURN_ID: {turn_id}" if turn_id else "")
        + (f"\n- FROZEN_LANE_ID: {lane_id}" if lane_id else "")
        + (f"\n- FROZEN_LANE_TITLE: {lane_title}" if lane_title else "")
        + "\n\nCURRENT_TURN_RULES:\n"
        "- **Priority:** (1) **SAME_TURN_RESULT_STATUS** and **SAME_TURN_REASONING_RESULT** text; "
        "(2) **CURRENT_TURN_INTENT** and the **current user line**; (3) **ACTIVE_WORK_MODE_REASONING_CONTEXT**; "
        "(4) older lane background only when same-turn is missing.\n"
        "- Your one sentence must describe what **just finished in this same turn**, not an older exercise.\n"
        "- Use **ACTIVE_WORK_MODE_REASONING_CONTEXT** / **LANE_BACKGROUND** only for topic grounding — never to override same-turn status.\n"
        "- Match **solved** intent wording only when SAME_TURN_RESULT_STATUS is **solved**:\n"
        "  - **code**: you put the code in the reasoning panel.\n"
        "  - **solve**: you solved the problem in the reasoning panel (only if actually solved).\n"
        "  - **explain**: you wrote the explanation in the reasoning panel.\n"
        "  - **plan**: you laid out the plan in the reasoning panel.\n"
        f"- Current submitted user line (verbatim JSON string): {ut_json}\n"
        f"- Client-classified current line for intent (usually same): {cl_json}\n"
    )
    block = (
        "VOICE_OUTPUT_MODE_REASONING_STAGE2 (this turn already streamed into the Work Mode Reasoning panel; "
        "ACTIVE_WORK_MODE_REASONING_CONTEXT holds that content):\n"
        "- Your entire assistant reply for this turn MUST be **exactly one sentence** (one period or question mark at most; "
        "no bullet lists, no second paragraph).\n"
        "- Use **past tense** throughout.\n"
        "- Summarize **actual outcome** from same-turn reasoning — not assumed success from the user's question alone.\n"
        "- Do not recite code, tables, LaTeX, or long numbers aloud.\n"
        "- End by pointing to the reasoning panel so the user knows where to look.\n"
        f"- User line (context only — do not repeat verbatim): {ut_json}."
        + also_rule
        + status_rules
        + intent_rules
    )
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out


def _normalize_client_context_snapshot(raw: object) -> dict | None:
    if raw is None:
        return None
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return None
        try:
            obj = json.loads(s)
            return obj if isinstance(obj, dict) else None
        except Exception:
            return None
    return None


_DEICTIC_WORK_MODE_FOLLOWUP_RE = re.compile(
    r"\b(?:this|that|it|same|these|those|them|previous|prior|earlier|above|last)\b"
    r"|(?:\b(?:this|that)\s+(?:problem|question|one|code|solution|answer|case|part)\b)"
    r"|(?:\b(?:the|your)\s+(?:answer|solution|result|work|proof|method|code|numbers?)\b)"
    r"|(?:\bpart\s+[a-z0-9]{1,4}\b|\bsection\s+\d+)"
    r"|(?:\b(?:give|show|write|put|send)\s+me\b.*\b(?:code|answer|solution|table)\b)"
    r"|(?:\bgive me code\b)"
    r"|(?:\bcode to (?:this|that)\b)"
    r"|(?:\b(?:show|give|write)\b.*\b(?:answer|solution|result)\b.*\bcode\b)"
    r"|(?:\b(?:show|give)\b.*\bin\s+code\b)"
    r"|(?:\bcode\s+for\s+(?:this|that|it)\b)"
    r"|(?:\b(?:continue|go on|more detail|shorter|expand|elaborate|how come|what about)\b)"
    r"|(?:\bwhy\s+(?:is|are|was|were|does|did|would|that|this|it)\b)"
    r"|(?:\b(?:answer|grading)\s*sheet\b|\buse\s+the\s+(?:sheet|upload|attachment|pdf)\b)"
    r"|(?:\b(?:wrong|mistake|not\s+right|correct\s+that)\b)",
    re.I,
)


def _work_mode_transcript_asks_deictic_followup(user_transcript: str) -> bool:
    """Short / deictic turns that should use Reasoning workspace + Voice UI snapshot, not digest-only TTS."""
    ql = str(user_transcript or "").strip().lower()
    if not ql:
        return False
    return bool(_DEICTIC_WORK_MODE_FOLLOWUP_RE.search(ql))


def _work_mode_reasoning_handoff_usable(ctx: dict | None) -> bool:
    if not ctx or not isinstance(ctx, dict):
        return False
    return bool(
        str(ctx.get("main_context_excerpt") or "").strip()
        or str(ctx.get("latest_final_answer_excerpt") or "").strip()
        or str(ctx.get("latest_reasoning_summary") or "").strip()
        or str(ctx.get("last_user_request") or "").strip()
    )


def _voice_tail_aligned_with_work_mode_lane(voice_excerpt: str, wm: dict | None) -> bool:
    """Heuristic: include Voice UI tail as secondary only when it plausibly matches the selected reasoning lane."""
    v = (voice_excerpt or "").strip().lower()
    if not v:
        return False
    if not wm or not isinstance(wm, dict):
        return True
    bits = [
        str(wm.get("title") or wm.get("lane_title") or "").strip(),
        str(wm.get("last_user_request") or "").strip(),
        str(wm.get("prior_problem_anchor") or "").strip(),
        (str(wm.get("latest_reasoning_summary") or "").strip())[:500],
        (str(wm.get("main_context_excerpt") or wm.get("latest_final_answer_excerpt") or "").strip())[:400],
    ]
    lane_blob = " ".join(b for b in bits if b).lower()
    if len(lane_blob) < 10:
        return True
    stop = {
        "this", "that", "with", "from", "your", "user", "assistant", "have", "been", "will",
        "what", "when", "where", "which", "their", "there", "here", "they", "them", "then",
    }
    toks = {t for t in re.findall(r"[a-z0-9]{4,}", lane_blob) if t not in stop}
    if not toks:
        return True
    hits = sum(1 for t in toks if t in v)
    return hits >= 2 or (len(toks) <= 3 and hits >= 1)


def _inject_client_context_snapshot(
    messages: list[dict],
    snapshot: dict | None,
    user_transcript: str,
    work_mode_reasoning_handoff: dict | None = None,
    *,
    strict_lane_handoff: bool = False,
) -> tuple[list[dict], dict]:
    lane_debug: dict = {
        "final_server_handoff_lane_title": "",
        "final_server_handoff_lane_id": "",
        "voice_context_used_server": False,
        "voice_suppress_reason": "no_snapshot",
        "strict_lane_test": False,
        "_infer_context_source": "",
    }
    if not snapshot:
        return messages, lane_debug
    handoff_usable = _work_mode_reasoning_handoff_usable(work_mode_reasoning_handoff)
    voice_ctx_used = False
    voice_reason = "no_voice_excerpt_in_snapshot"

    music = snapshot.get("music") if isinstance(snapshot.get("music"), dict) else {}
    checklist = snapshot.get("checklist") if isinstance(snapshot.get("checklist"), dict) else {}
    checklist_items = checklist.get("ongoing_items") if isinstance(checklist.get("ongoing_items"), list) else []
    checklist_items = [str(x).strip()[:120] for x in checklist_items if str(x).strip()][:8]
    checklist_detail_items: list[str] = []
    main_items_snap = (
        checklist.get("main_items") if isinstance(checklist.get("main_items"), list) else []
    )
    if main_items_snap:
        for m in main_items_snap[:12]:
            if not isinstance(m, dict):
                continue
            label = str(m.get("text") or "").strip()
            if not label:
                continue
            children = m.get("children") if isinstance(m.get("children"), list) else []
            child_bits = [
                str(c.get("text") or "").strip()[:120]
                for c in children
                if isinstance(c, dict) and str(c.get("text") or "").strip()
            ][:6]
            if child_bits:
                checklist_detail_items.append(
                    f"main: {label[:160]} (details: {', '.join(child_bits)})"
                )
            else:
                checklist_detail_items.append(f"main: {label[:160]}")
    else:
        id_to_text: dict[str, str] = {}
        for it in (checklist.get("items") if isinstance(checklist.get("items"), list) else [])[:40]:
            if isinstance(it, dict) and str(it.get("id") or "").strip():
                id_to_text[str(it.get("id") or "").strip()] = str(it.get("text") or "").strip()
        for it in (checklist.get("items") if isinstance(checklist.get("items"), list) else [])[:20]:
            if not isinstance(it, dict):
                continue
            label = str(it.get("text") or "").strip()
            if not label:
                continue
            pid = str(it.get("parent_id") or "").strip()
            if pid and pid in id_to_text:
                prefix = "sub"
            else:
                prefix = "main"
            checklist_detail_items.append(f"{prefix}: {label[:160]}")
    asks_schedule_followup = looks_like_work_mode_schedule_followup(user_transcript)
    reasoning = snapshot.get("reasoning") if isinstance(snapshot.get("reasoning"), dict) else {}
    snapshot_strict_flag = bool(reasoning.get("contamination_test_no_voice"))
    suppress_voice = handoff_usable and (
        strict_lane_handoff or WORK_MODE_STRICT_LANE_HANDOFF_TEST or snapshot_strict_flag
    )
    excerpt = str(reasoning.get("recent_problem_excerpt") or "").strip()
    excerpt = excerpt[:14000]
    voice_excerpt = str(reasoning.get("recent_voice_excerpt") or "").strip()
    voice_excerpt = voice_excerpt[:5000]
    rp_label = str(reasoning.get("active_panel_label") or "").strip()
    rp_idx = reasoning.get("active_panel_index")
    rp_panels = reasoning.get("panels") if isinstance(reasoning.get("panels"), list) else []
    rp_panel_line = ""
    if rp_panels:
        bits = []
        for p in rp_panels[:12]:
            if not isinstance(p, dict):
                continue
            lab = str(p.get("label") or "").strip()[:90]
            bits.append(f"{p.get('index')}:{lab}")
        if bits:
            rp_panel_line = f"- reasoning.panels ({len(rp_panels)}): " + "; ".join(bits) + "\n"
    asks_deictic_followup = _work_mode_transcript_asks_deictic_followup(user_transcript)
    latest_voice_user_line = ""
    latest_voice_assistant_line = ""
    if voice_excerpt:
        users = re.findall(r"^\s*User:\s*(.+)$", voice_excerpt, flags=re.I | re.M)
        if users:
            latest_voice_user_line = str(users[-1]).strip()[:800]
        assts = re.findall(r"^\s*Assistant:\s*(.+)$", voice_excerpt, flags=re.I | re.M)
        if assts:
            latest_voice_assistant_line = str(assts[-1]).strip()[:800]
    reasoning_lines = ""
    if excerpt:
        panel_bits = []
        if rp_label:
            panel_bits.append(f"active_panel_label={rp_label}")
        if rp_idx is not None and str(rp_idx).strip() != "":
            panel_bits.append(f"active_panel_index={rp_idx}")
        panel_line = ("; ".join(panel_bits) + "\n") if panel_bits else ""
        reasoning_lines = (
            "\nReasoning workspace (user is likely referring to this for follow-ups such as "
            "'the problem', 'that answer', 'give me the code', 'show the answer in code', 'are you sure', or 'this result'):\n"
            f"{panel_line}"
            f"{excerpt}\n"
        )
    if voice_excerpt:
        if suppress_voice:
            voice_ctx_used = False
            voice_reason = "strict_lane_handoff_suppressed_voice_tail"
        elif handoff_usable:
            if _voice_tail_aligned_with_work_mode_lane(voice_excerpt, work_mode_reasoning_handoff):
                reasoning_lines += (
                    "\nSecondary background — Recent Voice UI (may include other lanes; must NOT override "
                    "ACTIVE_WORK_MODE_REASONING_CONTEXT for phrases like this problem, this answer, the code, or that solution):\n"
                    f"{voice_excerpt}\n"
                )
                voice_ctx_used = True
                voice_reason = "included_tail_heuristic_aligned_with_handoff_lane"
            else:
                voice_reason = "omitted_voice_tail_not_aligned_with_handoff_lane"
        else:
            reasoning_lines += (
                "\nRecent Voice UI context (latest turns in the visible chat panel):\n"
                f"{voice_excerpt}\n"
            )
            voice_ctx_used = True
            voice_reason = "included_no_usable_work_mode_handoff"

    if str(snapshot.get("mode", "")).lower() == "work" and (excerpt or voice_excerpt):
        if handoff_usable:
            reasoning_lines += (
                "\nWork mode reference resolution: use ACTIVE_WORK_MODE_REASONING_CONTEXT (inserted separately in "
                "another developer message) as the **primary** source for references like this problem, this answer, "
                "the code, or that solution. Recent Voice UI context above (if any) is only background and may involve "
                "other lanes — it must not override the selected reasoning lane.\n"
            )
        else:
            reasoning_lines += (
                "\nWork mode thread default: unless the user clearly opens a brand-new independent problem "
                "(e.g. 'new question', 'different problem', 'forget that'), treat their turn as continuing "
                "the same visible task; combine the reasoning excerpt with the latest assistant reply when resolving references.\n"
            )
    if asks_schedule_followup and (excerpt or checklist_detail_items or checklist_items):
        reasoning_lines += (
            "\nSchedule/plan follow-up rule for this turn: the user is asking about the "
            "visible evening/day plan, schedule blocks, or checklist (timing, order, whether "
            "a block is too late/early, what to do next, or if the plan is realistic). "
            "Answer using the Reasoning workspace excerpt and checklist items above. "
            "Treat words like 'gym' as scheduled activities from the plan, not local venue "
            "searches.\n"
        )
    if asks_deictic_followup and (excerpt or voice_excerpt or handoff_usable):
        if handoff_usable:
            reasoning_lines += (
                "\nFollow-up resolution rule for this turn: resolve deictic references using "
                "ACTIVE_WORK_MODE_REASONING_CONTEXT first. Voice UI lines (if present) are secondary only.\n"
            )
        else:
            anchor_bits = []
            if latest_voice_user_line:
                anchor_bits.append(f"Latest user line: {latest_voice_user_line}")
            if latest_voice_assistant_line:
                anchor_bits.append(f"Latest assistant reply: {latest_voice_assistant_line}")
            anchor_line = (
                "\nCurrent task anchor for this turn:\n" + "\n".join(anchor_bits) + "\n"
                if anchor_bits
                else "\nCurrent task anchor for this turn: use the latest concrete problem and assistant material in the snapshot above.\n"
            )
            reasoning_lines += (
                "\nFollow-up resolution rule for this turn: the user is continuing the same task unless they explicitly started a new one. "
                "Interpret deictic or short follow-ups ('this', 'that', 'it', 'the answer', 'part b', 'continue', 'why is that wrong', "
                "'use the answer sheet', 'in a table', 'in code') as referring to the Reasoning workspace excerpt, the Voice UI lines, "
                "and especially the latest assistant reply when resolving references.\n"
                f"{anchor_line}"
            )
    if handoff_usable:
        ground_tail = (
            "Grounding rule: ACTIVE_WORK_MODE_REASONING_CONTEXT (from `work_mode_reasoning_context`) is authoritative "
            "for deictic references on this turn. Use the Reasoning workspace snapshot as panel context; treat any Voice UI "
            "lines above as weak background when present."
        )
    else:
        ground_tail = (
            "Grounding rule: when `Reasoning workspace` and/or `Recent Voice UI context` appears above, default to **task continuation**: "
            "short or deictic turns ('it', 'this', 'that', 'the answer', 'part b', 'continue', 'why', 'in code', 'answer sheet', etc.) "
            "inherit the active problem, attachment-derived details already shown, reasoning markdown, and the **latest assistant reply**. "
            "Only treat the user as lacking context if both the reasoning excerpt and the voice excerpt are empty. "
            "If the user asks about current song or checklist status, answer directly from this snapshot."
        )
    block = (
        "Client UI state snapshot for grounding (trusted for this turn):\n"
        f"- app={snapshot.get('app', 'unknown')}\n"
        f"- mode={snapshot.get('mode', 'unknown')}\n"
        f"- music.title={str(music.get('title', '')).strip()}\n"
        f"- music.artist={str(music.get('artist', '')).strip()}\n"
        f"- music.is_playing={bool(music.get('is_playing'))}\n"
        + (
            f"- music.skip_next_available={bool(music.get('skip_next_available'))}\n"
            if "skip_next_available" in music
            else "- music.skip_next_available=(unknown)\n"
        )
        + (
            f"- music.skip_prev_available={bool(music.get('skip_prev_available'))}\n"
            if "skip_prev_available" in music
            else "- music.skip_prev_available=(unknown)\n"
        )
        + f"- checklist.ongoing_count={int(checklist.get('ongoing_count') or 0)}\n"
        f"- checklist.main_count={int(checklist.get('main_count') or 0)}\n"
        f"- checklist.subitem_count={int(checklist.get('subitem_count') or 0)}\n"
        f"- checklist.completed_count={int(checklist.get('completed_count') or 0)}\n"
        f"- checklist.ongoing_items={'; '.join(checklist_items) if checklist_items else '(none)'}\n"
        f"- checklist.items_detail={'; '.join(checklist_detail_items) if checklist_detail_items else '(none)'}\n"
        f"- schedule_followup_detected={asks_schedule_followup}\n"
        f"{rp_panel_line}"
        f"{reasoning_lines}"
        f"\nThe user's words in this turn were: \"{user_transcript}\".\n"
        f"{ground_tail}"
    )
    wm_aid = str((work_mode_reasoning_handoff or {}).get("active_lane_id") or "").strip()
    wm_title = str((work_mode_reasoning_handoff or {}).get("lane_title") or "").strip()
    client_src = str((work_mode_reasoning_handoff or {}).get("_infer_context_source") or "").strip()
    src = client_src or ("work_mode_handoff_authoritative" if handoff_usable else "snapshot_only")
    lane_debug = {
        "final_server_handoff_lane_title": wm_title,
        "final_server_handoff_lane_id": wm_aid,
        "voice_context_used_server": voice_ctx_used,
        "voice_suppress_reason": voice_reason,
        "strict_lane_test": bool(suppress_voice),
        "_infer_context_source": src,
        "selected_context_source": src,
    }
    print(
        "[infer_reference_resolution] "
        + json.dumps(
            {
                "user_text": (user_transcript or "")[:500],
                "active_lane_id": wm_aid,
                "selected_context_source": src,
                "selected_lane_title": wm_title,
                "voice_context_used": voice_ctx_used,
                "reason": voice_reason,
            },
            ensure_ascii=False,
        ),
        flush=True,
    )
    out = list(messages)
    insert_at = 1 if len(out) >= 1 else 0
    out.insert(insert_at, {"role": "developer", "content": block})
    return out, lane_debug


def _snapshot_fastpath_reply(text: str, snapshot: dict | None) -> str | None:
    if not snapshot:
        return None
    q = (text or "").strip().lower()
    if not q:
        return None
    music = snapshot.get("music") if isinstance(snapshot.get("music"), dict) else {}
    title = str(music.get("title") or "").strip()
    artist = str(music.get("artist") or "").strip()
    is_playing = bool(music.get("is_playing"))
    asks_song = (
        ("song" in q or "track" in q)
        and ("playing" in q or "currently" in q or "right now" in q)
    ) or bool(re.search(r"\bwhat(?:'s| is)\s+the\s+name\s+of\s+the\s+(?:song|track)\b", q))
    if asks_song:
        if title and is_playing:
            return f"You're currently playing {title} by {artist}." if artist else f"You're currently playing {title}."
        if title:
            return f"The selected track is {title} by {artist}, and it is currently paused." if artist else f"The selected track is {title}, and it is currently paused."
        return "I do not see a track playing right now."

    asks_checklist = False
    if "checklist" in q:
        is_checklist_edit = bool(
            re.search(r"\b(add|remove|update|replace)\b", q)
        )
        asks_checklist = (not is_checklist_edit) and bool(
            re.search(r"\bwhat\b", q)
            or re.search(r"\bshow\b", q)
            or re.search(r"\blist\b", q)
            or re.search(r"\bon my\b", q)
            or re.search(r"\bstatus\b", q)
        )
    checklist = snapshot.get("checklist") if isinstance(snapshot.get("checklist"), dict) else None
    if asks_checklist and checklist is not None:
        ongoing = int(checklist.get("ongoing_count") or 0)
        completed = int(checklist.get("completed_count") or 0)
        items = checklist.get("ongoing_items") if isinstance(checklist.get("ongoing_items"), list) else []
        cleaned = [str(x).strip() for x in items if str(x).strip()]
        if cleaned:
            preview = ", ".join(cleaned[:3])
            more = "" if len(cleaned) <= 3 else f", plus {len(cleaned) - 3} more"
            return f"You have {ongoing} ongoing and {completed} completed checklist items. Ongoing: {preview}{more}."
        return f"You have {ongoing} ongoing and {completed} completed checklist items."
    return None


# Explicit Work Mode toggle commands only — bare "on"/"off" elsewhere in the
# utterance must not flip mode (e.g. "run it on RunPod", "focus on …").
_WORK_MODE_TOGGLE_ON_RE = re.compile(
    r"(?:"
    r"\bturn\s+on\s+work\s*mode\b"
    r"|\bturn\s+work\s*mode\s+on\b"
    r"|\b(?:activate|enable|enter)\s+work\s*mode\b(?!\s+(?:reasoning|panel|panels|feature|ui)\b)"
    r"|\bswitch\s+to\s+work\s*mode\b"
    r"|\bopen\s+work\s*mode\b(?!\s+(?:reasoning|panel|panels|feature|ui)\b)"
    r"|\bwork\s*mode\s+on\b"
    r")",
    re.IGNORECASE,
)
_WORK_MODE_TOGGLE_OFF_RE = re.compile(
    r"(?:"
    r"\bturn\s+off\s+work\s*mode\b"
    r"|\bturn\s+work\s*mode\s+off\b"
    r"|\b(?:deactivate|disable|exit|leave)\s+work\s*mode\b"
    r"|\bwork\s*mode\s+off\b"
    r")",
    re.IGNORECASE,
)


def _work_mode_toggle_intent(text: str, client: str, snapshot: dict | None) -> str | None:
    if str(client or "vera").strip().lower() != "vera":
        return None
    q = (text or "").strip()
    if not q:
        return None
    wants_on = bool(_WORK_MODE_TOGGLE_ON_RE.search(q))
    wants_off = bool(_WORK_MODE_TOGGLE_OFF_RE.search(q))
    if wants_on and not wants_off:
        return "on"
    if wants_off and not wants_on:
        return "off"
    return None


def _work_mode_toggle_reply(intent: str, snapshot: dict | None) -> tuple[str, str]:
    mode = str((snapshot or {}).get("mode") or "").strip().lower()
    is_work = mode == "work"
    if intent == "on":
        if is_work:
            return "work_mode_on", "Work mode is already on."
        return "work_mode_on", "Work mode is now on."
    if is_work:
        return "work_mode_off", "Work mode is now off."
    return "work_mode_off", "Work mode is already off."


def _new_session_user_facts_blob() -> dict:
    return {
        "name": None,
        "likes": [],
        "dislikes": [],
        "identity": [],
        "statements": [],
    }


def _get_session_user_facts(session_id: str | None) -> dict:
    sid = (session_id or "").strip()
    if not sid:
        return _new_session_user_facts_blob()
    blob = session_user_facts.get(sid)
    if not isinstance(blob, dict):
        blob = _new_session_user_facts_blob()
        session_user_facts[sid] = blob
    for k, default in (("likes", []), ("dislikes", []), ("identity", []), ("statements", [])):
        if not isinstance(blob.get(k), list):
            blob[k] = list(default)
    return blob


def _add_unique_fact(bucket: list, value: str, limit: int = 24) -> None:
    v = (value or "").strip()
    if not v or len(v) > 120:
        return
    low = v.lower()
    for existing in bucket:
        if str(existing).strip().lower() == low:
            return
    bucket.append(v)
    if len(bucket) > limit:
        del bucket[: len(bucket) - limit]


# Explicit memory triggers. The user must say one of these before Vera saves
# anything into session memory. Casual statements ("I love tennis", "my name
# is Nam") no longer auto-store — the about-me question lets the LLM read
# them straight out of the recent conversation history instead.
_EXPLICIT_MEMORY_TRIGGER_RE = re.compile(
    r"(?ix)\b("
    r"remember\s+(?:that|this|to|me\s+as)|"
    r"please\s+remember|"
    r"save\s+(?:this|that)|"
    r"make\s+a\s+note(?:\s+(?:that|of))?|"
    r"note\s+that|"
    r"keep\s+in\s+mind\s+that|"
    r"from\s+now\s+on|"
    r"going\s+forward|"
    r"for\s+future|"
    r"for\s+the\s+future|"
    r"use\s+(?:this|that|[a-z][a-z\s\-']{0,40}?)\s+as\s+(?:my|the)\s+(?:default|local|preferred|primary)|"
    r"use\s+[a-z][a-z\s\-']{0,40}?\s+as\s+my\s+(?:default|local|preferred|primary|area|location)|"
    r"my\s+preference\s+is|"
    r"my\s+preferences?\s+are|"
    r"i\s+prefer\s+(?:to\s+be\s+)?(?:called|known\s+as)|"
    r"call\s+me"
    r")\b"
)


def _has_explicit_memory_trigger(text: str) -> bool:
    """True only when the user explicitly asks Vera to remember/save something.

    Used as the sole gate for session fact storage. Casual self-disclosure
    ("I love tennis", "my name is Nam") does not match — those facts are
    still available to the LLM via recent chat history when the user later
    asks "what do you know about me", they just aren't permanently stored.
    """
    if not text:
        return False
    return bool(_EXPLICIT_MEMORY_TRIGGER_RE.search(text))


def _is_memory_command_request(text: str) -> bool:
    """Remember / forget / about-me recall commands — terminal for action routing."""
    try:
        from auth.memory_commands import is_memory_command_request

        return is_memory_command_request(text)
    except Exception:
        return False


# ---------------------------------------------------------------------------
# Conversational vs. persistent self-disclosure (May 2026 policy)
#
# When the user says something like "I actually live in Orange County",
# VERA used to respond with memory-flavored language ("Got it. I'll keep
# Orange County in mind."). That feels unnatural — the user was just
# clarifying conversational context, not asking for a profile update.
#
# These helpers classify the turn and rewrite the reply so memory-style
# acknowledgements only fire when the user actually requested persistence.
# Location statements are treated especially conservatively because users
# almost always mention "where I live" / "I'm from there" as immediate
# conversational color, not a persistent profile claim.
# ---------------------------------------------------------------------------

# First-person self-disclosure cue. The classifier flags a turn as a
# "memory candidate" only when both this AND a self-disclosure topic
# (location / identity / preference) are present, so neutral utterances
# like "what's the weather?" never get flagged.
_FIRST_PERSON_CUE_RE = re.compile(
    r"(?i)\b("
    # Allow up to two short adverbs/intensifiers between "I" and the verb
    # ("I actually live", "I really do live", "I just moved").
    r"i(?:\s+(?:actually|really|just|currently|now|still|also|basically|"
    r"literally|honestly|always|usually|technically|originally|here))*"
    r"\s+(?:am|'m|live|stay|reside|grew\s+up|was\s+born|come\s+from|moved\s+to|"
    r"work|study|prefer|like|love|enjoy|hate|dislike|don't\s+like|do\s+not\s+like)"
    r"|my\s+(?:name|home|house|family|job|address|location|hometown|city|state|"
    r"country|area|neighborhood|region|zone|default|preferred|local\s+area|"
    r"primary\s+(?:area|location))"
    r"|i'm\s+(?:actually\s+|really\s+|just\s+|currently\s+|originally\s+)?from"
    r"|i'm\s+(?:actually\s+|really\s+|just\s+|currently\s+|originally\s+)?(?:in|at|near|around|by)"
    r")\b"
)

# Topics that COULD become persistent profile facts when asked. The
# classifier uses these only to set memory_candidate=True so the
# sanitizer knows it's allowed to strip memory-language from a reply
# that doesn't pair with an explicit trigger.
_LOCATION_CUE_RE = re.compile(
    r"(?i)\b("
    r"live|living|reside|from|in|at|near|around|by|next\s+to|"
    r"hometown|city|state|country|address|location|area|neighborhood|region|county"
    r")\b"
)
_IDENTITY_CUE_RE = re.compile(
    r"(?i)\b("
    r"work\s+as|job|career|profession|study|studying|major|grade|year\s+in\s+(?:school|college)|"
    r"i\s+am\s+(?:a|an)|i'm\s+(?:a|an)"
    r")\b"
)
_PREFERENCE_CUE_RE = re.compile(
    r"(?i)\b("
    r"prefer|favorite|favourite|like|love|enjoy|hate|dislike|"
    r"don't\s+like|do\s+not\s+like|can't\s+stand|cannot\s+stand"
    r")\b"
)

# Conversational-context cues. When present alongside a self-disclosure
# they STRENGTHEN the "this is just chat, don't persist" signal — used
# only for richer debug context.
_CONVERSATIONAL_CUE_RE = re.compile(
    r"(?i)\b("
    r"actually|i\s+meant|i\s+mean|no\s+i\s+(?:mean|meant)|"
    r"know\s+(?:the\s+)?area|i\s+know\s+(?:this|the)\s+(?:area|place|spot)|"
    r"that's\s+(?:near|close\s+to)\s+(?:me|here|where\s+i)|"
    r"i'm\s+(?:from|around)\s+there|"
    r"so\s+i\s+(?:know|get)"
    r")\b"
)


def _classify_memory_request(text: str) -> dict:
    """Decide whether the user is asking VERA to PERSIST something or just
    sharing conversational context. Returns a structured dict that the
    sanitizer + debug logger consume.

    Output keys:
        - ``memory_candidate``        bool — utterance contains self-disclosure
        - ``explicit_memory_request`` bool — user used an explicit trigger
        - ``persistence_reason``      str  — short tag for debug logs
        - ``conversational_context``  bool — user clarified topic w/o persistence
        - ``is_location_only``        bool — self-disclosure was only locational
    """
    raw = (text or "").strip()
    if not raw:
        return {
            "memory_candidate": False,
            "explicit_memory_request": False,
            "persistence_reason": "empty_input",
            "conversational_context": False,
            "is_location_only": False,
        }

    explicit = _has_explicit_memory_trigger(raw)
    first_person = bool(_FIRST_PERSON_CUE_RE.search(raw))
    has_location = bool(_LOCATION_CUE_RE.search(raw))
    has_identity = bool(_IDENTITY_CUE_RE.search(raw))
    has_preference = bool(_PREFERENCE_CUE_RE.search(raw))
    has_disclosure_topic = has_location or has_identity or has_preference
    memory_candidate = first_person and has_disclosure_topic
    conversational = bool(_CONVERSATIONAL_CUE_RE.search(raw))
    is_location_only = has_location and not (has_identity or has_preference)

    if explicit:
        reason = "explicit_trigger"
    elif memory_candidate and is_location_only:
        # Per spec: be especially conservative about locations.
        reason = "location_context_only"
    elif memory_candidate and conversational:
        reason = "conversational_context_only"
    elif memory_candidate:
        reason = "self_disclosure_no_persistence_language"
    else:
        reason = "not_self_disclosure"

    return {
        "memory_candidate": memory_candidate,
        "explicit_memory_request": explicit,
        "persistence_reason": reason,
        "conversational_context": conversational,
        "is_location_only": is_location_only,
    }


# Patterns that flag a SENTENCE as memory-flavored (the LLM mistook a
# casual self-disclosure for a profile update). The sanitizer drops the
# whole sentence — not just the matched span — so we never leave hanging
# fragments like "Got it. location.". Patterns intentionally allow free
# objects ("that location", "that you live in OC") because the entire
# sentence is going away regardless.
_MEMORY_SENTENCE_PATTERNS: list[re.Pattern] = [
    # "I'll/I will keep that/Orange County/it in mind"
    re.compile(
        r"(?i)\b(?:i'?ll|i\s+will|let\s+me)\s+keep\s+[^.!?]*?in\s+mind\b",
    ),
    # "I've noted that ..." / "I have noted that you ..."
    re.compile(
        r"(?i)\b(?:i'?ve|i\s+have)\s+noted\b",
    ),
    # "I'll remember/memorize/store ..."
    re.compile(
        r"(?i)\b(?:i'?ll|i\s+will)\s+(?:remember|memorize|store)\b",
    ),
    # "I'll save (that location / that for next time / your address ...)"
    re.compile(
        r"(?i)\b(?:i'?ll|i\s+will)\s+save\b",
    ),
    # "I'll update your profile / preferences / location / address / memory"
    re.compile(
        r"(?i)\b(?:i'?ll|i\s+will)\s+update\s+your\s+"
        r"(?:profile|preferences?|location|address|notes?|memory)\b",
    ),
    # "I'll add (that/...) to my notes / memory / your profile / preferences"
    re.compile(
        r"(?i)\b(?:i'?ll|i\s+will)\s+add\s+[^.!?]*?to\s+"
        r"(?:my\s+notes?|my\s+memory|your\s+profile|your\s+preferences?)\b",
    ),
    # Bare "Noted." / "Noted!" (entire short sentence)
    re.compile(r"(?i)^\s*noted[.!?]?\s*$"),
]


def _split_into_sentences(text: str) -> list[str]:
    """Cheap sentence splitter that preserves trailing punctuation and
    intermediate whitespace. Good enough for spoken replies (typically
    1-4 sentences); avoids the nltk dependency."""
    raw = (text or "").strip()
    if not raw:
        return []
    # Split on ., !, ? followed by whitespace or end of string.
    parts = re.split(r"(?<=[.!?])\s+", raw)
    return [p.strip() for p in parts if p.strip()]


def _sanitize_memory_language_in_reply(
    reply: str,
    memory_signal: dict,
) -> tuple[str, dict]:
    """Drop sentences whose only purpose is to claim VERA remembered /
    saved / noted something, when the user did NOT explicitly ask for
    persistence. Returns ``(new_reply, dbg)``.

    Sentence-level (not span-level) so we never end up with dangling
    objects ("Got it. location.", "I'll. that area."). The ``dbg``
    payload feeds [MEMORY_CONTEXT_DEBUG] so we can audit every turn.
    """
    dbg = {
        "sanitized": False,
        "matched_patterns": [],
        "dropped_sentences": [],
        "original_excerpt": "",
    }
    if not reply:
        return reply, dbg
    if memory_signal.get("explicit_memory_request"):
        return reply, dbg

    sentences = _split_into_sentences(reply)
    if not sentences:
        return reply, dbg

    kept: list[str] = []
    for s in sentences:
        triggered_pattern: str | None = None
        for pat in _MEMORY_SENTENCE_PATTERNS:
            if pat.search(s):
                triggered_pattern = pat.pattern[:80]
                break
        if triggered_pattern is not None:
            dbg["matched_patterns"].append(triggered_pattern)
            dbg["dropped_sentences"].append(s[:160])
            continue
        kept.append(s)

    if not dbg["dropped_sentences"]:
        return reply, dbg

    # If we removed every sentence (or nothing meaningful remains), fall
    # back to a short, natural acknowledgement so the user always hears
    # something — but never a memory claim.
    if not kept or all(
        re.fullmatch(r"[\s.,!?;:'-]+", s or "") for s in kept
    ):
        kept = ["Got it."]

    new_reply = " ".join(kept).strip()
    # Tidy double spaces / leading punctuation from the join.
    new_reply = re.sub(r"[ \t]{2,}", " ", new_reply)
    new_reply = re.sub(r"^[\s.,!;:]+", "", new_reply).strip()
    if not new_reply:
        new_reply = "Got it."

    dbg["sanitized"] = True
    dbg["original_excerpt"] = reply[:160]
    return new_reply, dbg


def _log_memory_context_debug(
    *,
    user_text: str,
    reply_before: str,
    reply_after: str,
    memory_signal: dict,
    sanitize_dbg: dict,
) -> None:
    """Per-spec structured log. Always one line per turn (even when nothing
    changed) so the log is easy to filter to inspect memory routing."""
    sanitized = bool(sanitize_dbg.get("sanitized"))
    final_behavior = (
        "memory_update"
        if memory_signal.get("explicit_memory_request")
        else "conversational_context_only"
    )
    payload = {
        "user_text": (user_text or "")[:200],
        "memory_candidate": bool(memory_signal.get("memory_candidate")),
        "explicit_memory_request": bool(memory_signal.get("explicit_memory_request")),
        "persistence_reason": memory_signal.get("persistence_reason"),
        "conversational_context": bool(memory_signal.get("conversational_context")),
        "is_location_only": bool(memory_signal.get("is_location_only")),
        "final_behavior": final_behavior,
        "reply_sanitized": sanitized,
        "matched_memory_patterns": sanitize_dbg.get("matched_patterns") or [],
        "reply_before_excerpt": (reply_before or "")[:160] if sanitized else None,
        "reply_after_excerpt": (reply_after or "")[:160] if sanitized else None,
    }
    try:
        print("[MEMORY_CONTEXT_DEBUG]", json.dumps(payload, ensure_ascii=False))
    except Exception:
        try:
            print("[MEMORY_CONTEXT_DEBUG] <unserializable payload>")
        except Exception:
            pass


def _norm_value(s: str) -> str:
    return re.sub(r"\s+", " ", str(s or "").strip(" .,!?;:\"'")).strip()


def _title_case_name(s: str) -> str:
    cleaned = _norm_value(s)
    if not cleaned:
        return ""
    # Preserve already-capitalized acronyms / mixed-case; otherwise title-case
    # token-by-token so ASR lowercase ("nam") still renders as "Nam".
    parts = []
    for tok in cleaned.split(" "):
        if not tok:
            continue
        if tok[1:].isupper() and len(tok) > 1:
            parts.append(tok)
        elif tok.isupper() and len(tok) <= 4:
            # Short all-caps tokens (initials) — leave alone.
            parts.append(tok)
        else:
            parts.append(tok[:1].upper() + tok[1:].lower())
    return " ".join(parts)


_NAME_STOPWORDS = frozenset({
    "a", "the", "an", "not", "just", "still", "ok", "okay", "fine",
    "sorry", "tired", "back", "here", "there", "good", "great",
    "happy", "sad", "right", "ready", "done", "in", "on", "out",
    "up", "down", "going", "gonna", "trying", "feeling", "thinking",
    "looking", "working", "studying", "starting", "saying", "off",
})


def _extract_and_store_session_user_facts(session_id: str | None, text: str) -> dict:
    """Store explicit user-memory facts into session-only memory.

    POLICY CHANGE (May 2026): casual self-disclosure no longer auto-stores.
    The user must use an explicit memory trigger ("remember that ...",
    "save this ...", "from now on ...", "call me X", "my preference is ...",
    etc.). For non-trigger turns this function is a no-op — the LLM still
    sees the casual statement via chat history and can answer about-me
    questions from that context without us pretending to "remember" facts
    that the user never asked us to save.
    """
    blob = _get_session_user_facts(session_id)
    raw = (text or "").strip()
    if not raw or len(raw) > 600:
        return blob
    if not _has_explicit_memory_trigger(raw):
        return blob

    # Name patterns. "call me X" is itself an explicit trigger, so its full
    # phrasing must still parse here even when the trigger is the same span.
    for pat in (
        r"\bremember\s+(?:that\s+)?my name is\s+([a-zA-Z][a-zA-Z'\-]{1,30}(?:\s+[a-zA-Z][a-zA-Z'\-]{1,30}){0,2})\b",
        r"\bremember\s+me\s+as\s+([a-zA-Z][a-zA-Z'\-]{1,30})\b",
        r"\bcall me\s+([a-zA-Z][a-zA-Z'\-]{1,30})\b",
        r"\b(?:i\s+prefer\s+(?:to\s+be\s+)?(?:called|known\s+as))\s+([a-zA-Z][a-zA-Z'\-]{1,30})\b",
    ):
        m = re.search(pat, raw, flags=re.IGNORECASE)
        if m:
            name = _title_case_name(m.group(1))
            if name and name.lower() not in _NAME_STOPWORDS:
                blob["name"] = name
                blob["statements"].append({"text": raw[:280], "kind": "name", "trigger": "explicit"})
                if len(blob["statements"]) > 60:
                    del blob["statements"][: len(blob["statements"]) - 60]
            break

    # Likes / preferences — require BOTH an explicit trigger (already
    # confirmed above) AND a recognizable like-statement inside the turn.
    for pat in (
        r"\b(?:remember|save|note)(?:\s+\w+){0,3}\s+(?:that\s+)?i (?:really )?(?:like|love|enjoy|prefer)\s+([^.,!?;\n]{2,80})",
        r"\bmy preference is\s+([^.,!?;\n]{2,80})",
        r"\bmy preferences are\s+([^.,!?;\n]{2,80})",
        r"\bfrom now on[, ]+i (?:really )?(?:like|love|enjoy|prefer)\s+([^.,!?;\n]{2,80})",
    ):
        for m in re.finditer(pat, raw, flags=re.IGNORECASE):
            val = _norm_value(m.group(1))
            if val:
                _add_unique_fact(blob["likes"], val)
                blob["statements"].append({"text": raw[:280], "kind": "like", "trigger": "explicit"})

    # Dislikes — same explicit-trigger requirement.
    for pat in (
        r"\b(?:remember|save|note)(?:\s+\w+){0,3}\s+(?:that\s+)?i (?:really )?(?:hate|dislike|don['’]t like|do not like|can['’]t stand)\s+([^.,!?;\n]{2,80})",
        r"\bfrom now on[, ]+i (?:really )?(?:hate|dislike|don['’]t like|do not like|can['’]t stand)\s+([^.,!?;\n]{2,80})",
    ):
        for m in re.finditer(pat, raw, flags=re.IGNORECASE):
            val = _norm_value(m.group(1))
            if val:
                _add_unique_fact(blob["dislikes"], val)
                blob["statements"].append({"text": raw[:280], "kind": "dislike", "trigger": "explicit"})

    # Identity — same explicit-trigger requirement.
    for pat in (
        r"\b(?:remember|save|note)(?:\s+\w+){0,3}\s+(?:that\s+)?i (?:am|'m) (?:a|an)\s+([a-zA-Z][a-zA-Z\s\-]{1,60})",
        r"\b(?:remember|save|note)(?:\s+\w+){0,3}\s+(?:that\s+)?i work as (?:a|an)\s+([a-zA-Z][a-zA-Z\s\-]{1,60})",
        r"\b(?:remember|save|note)(?:\s+\w+){0,3}\s+(?:that\s+)?i study\s+([a-zA-Z][a-zA-Z\s\-]{1,60})",
        r"\bfrom now on[, ]+i (?:am|'m) (?:a|an)\s+([a-zA-Z][a-zA-Z\s\-]{1,60})",
    ):
        for m in re.finditer(pat, raw, flags=re.IGNORECASE):
            val = _norm_value(m.group(1))
            stop = {"sorry", "not sure", "fine", "ok", "okay", "good", "tired", "happy", "sad"}
            if val and val.lower() not in stop:
                _add_unique_fact(blob["identity"], val)
                blob["statements"].append({"text": raw[:280], "kind": "identity", "trigger": "explicit"})

    if len(blob["statements"]) > 60:
        del blob["statements"][: len(blob["statements"]) - 60]
    try:
        print(
            "[session_fact_stored] "
            + json.dumps(
                {
                    "session_id": (session_id or "")[:32],
                    "user_text": raw[:200],
                    "name": blob.get("name"),
                    "likes_count": len(blob.get("likes") or []),
                    "dislikes_count": len(blob.get("dislikes") or []),
                    "identity_count": len(blob.get("identity") or []),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    return blob


def _user_session_facts_has_content(blob: dict | None) -> bool:
    if not isinstance(blob, dict):
        return False
    if (blob.get("name") or "").strip():
        return True
    for k in ("likes", "dislikes", "identity"):
        v = blob.get(k)
        if isinstance(v, list) and any(str(x).strip() for x in v):
            return True
    return False


def _project_user_profile_to_known_facts(profile_json: dict | None) -> dict | None:
    """Project users_files/<name>.json -> user_profile into the known_facts
    shape consumed by ``_build_about_me_reply``.

    The about-me handler historically only honored ``profile.known_facts``
    (a flat ``{name, likes, dislikes, identity}`` dict). User profiles like
    ``Nam.json`` carry richer slots under ``user_profile`` instead
    (``name`` / ``skills`` / ``interests`` / ``habits`` / ``life_context``).
    Without this projection ``has_profile`` is False for Nam, the
    deterministic template branch never fires, and the LLM fallback ends
    up freely teasing the user about their habits.

    The projection is intentionally conservative:
      - ``name``     <- user_profile.name
      - ``likes``    <- user_profile.interests + skills + habits (in that
                       priority order; deduped; capped at 8 entries)
      - ``identity`` <- user_profile.life_context
      - ``dislikes`` <- []  (no equivalent slot in the legacy schema)

    ``social_traits`` are intentionally NOT projected: they describe
    third-party observations ("friends often joke he flakes on plans"),
    not facts the user wants VERA to recall about them.
    """
    if not isinstance(profile_json, dict):
        return None
    up = profile_json.get("user_profile")
    if not isinstance(up, dict):
        return None

    name = ""
    raw_name = up.get("name")
    if isinstance(raw_name, str):
        name = raw_name.strip()

    def _list_field(key: str) -> list[str]:
        v = up.get(key)
        if not isinstance(v, list):
            return []
        out: list[str] = []
        for item in v:
            s = str(item).strip()
            if s:
                out.append(s)
        return out

    interests = _list_field("interests")
    skills = _list_field("skills")
    habits = _list_field("habits")
    life_context = _list_field("life_context")

    likes: list[str] = []
    seen: set[str] = set()
    for src in (interests, skills, habits):
        for x in src:
            low = x.lower()
            if low in seen:
                continue
            seen.add(low)
            likes.append(x)
            if len(likes) >= 8:
                break
        if len(likes) >= 8:
            break

    has_any = bool(name) or bool(likes) or bool(life_context)
    if not has_any:
        return None

    return {
        "name": name or None,
        "likes": likes,
        "dislikes": [],
        "identity": list(life_context),
    }


def _logged_in_user_known_facts(session_id: str | None = None) -> dict | None:
    """When a real account is active, surface persistent facts. Stub now; Supabase later.

    Multi-device-concurrency: when a session_id is passed, prefer that
    session's active user so two devices signed in as different users get
    their own facts. Falls back to the process-global active user only when
    no session mapping exists.

    2026-05-31 about-me consistency fix: when ``profile.known_facts`` is
    absent we now also project ``profile.user_profile`` into the same
    ``{name, likes, dislikes, identity}`` shape. This is what makes the
    deterministic, source-attributed template ("From your saved profile,
    your name is Nam; you like ...") fire for the existing Nam.json shape
    instead of falling through to the LLM branch which used to mine the
    profile and synthesize personality traits.
    """
    stem = get_active_username_for_session(session_id) if session_id else _active_username_from_runtime()
    if not stem:
        return None
    try:
        path = _ensure_user_profile_json_path(stem)
        profile = _read_user_profile_json(path) or {}
    except Exception:
        return None
    facts = profile.get("known_facts")
    if isinstance(facts, dict) and any(bool(v) for v in facts.values()):
        return facts
    projected = _project_user_profile_to_known_facts(profile)
    if projected is not None:
        return projected
    return None


def _format_list_for_speech(items: list[str], max_items: int = 4) -> str:
    cleaned: list[str] = []
    seen: set = set()
    for x in items or []:
        s = str(x).strip()
        if not s:
            continue
        low = s.lower()
        if low in seen:
            continue
        seen.add(low)
        cleaned.append(s)
        if len(cleaned) >= max_items:
            break
    if not cleaned:
        return ""
    if len(cleaned) == 1:
        return cleaned[0]
    if len(cleaned) == 2:
        return f"{cleaned[0]} and {cleaned[1]}"
    return ", ".join(cleaned[:-1]) + f", and {cleaned[-1]}"


def _build_about_me_reply(session_id: str | None) -> str:
    profile_facts = _logged_in_user_known_facts(session_id)
    blob = _get_session_user_facts(session_id)
    has_session = _user_session_facts_has_content(blob)
    has_profile = isinstance(profile_facts, dict) and any(
        bool(v) for v in profile_facts.values()
    )

    if not has_profile and not has_session:
        return "I don't know anything about you yet."

    parts: list[str] = []
    if has_profile:
        name = str(profile_facts.get("name") or "").strip()
        likes = profile_facts.get("likes") if isinstance(profile_facts.get("likes"), list) else []
        identity = (
            profile_facts.get("identity") if isinstance(profile_facts.get("identity"), list) else []
        )
        prof_bits: list[str] = []
        if name:
            prof_bits.append(f"your name is {name}")
        ident_s = _format_list_for_speech(identity)
        if ident_s:
            prof_bits.append(f"you are {ident_s}")
        likes_s = _format_list_for_speech(likes)
        if likes_s:
            prof_bits.append(f"you like {likes_s}")
        if prof_bits:
            parts.append("From your saved profile, " + "; ".join(prof_bits) + ".")

    if has_session:
        session_name = (blob.get("name") or "").strip()
        likes_s = _format_list_for_speech(blob.get("likes") or [])
        dislikes_s = _format_list_for_speech(blob.get("dislikes") or [])
        ident_s = _format_list_for_speech(blob.get("identity") or [])
        profile_name = str((profile_facts or {}).get("name") or "").strip()
        name_already_in_profile = bool(
            has_profile and profile_name and profile_name.lower() == session_name.lower()
        )

        # Name is the most identity-defining session fact. Lead with it so the
        # reply opens "Your name is Nam, and from this session, you like ..."
        # instead of burying the name inside a semicolon list.
        if session_name and not name_already_in_profile:
            session_facts: list[str] = []
            if likes_s:
                session_facts.append(f"you like {likes_s}")
            if dislikes_s:
                session_facts.append(f"you don't like {dislikes_s}")
            if ident_s:
                session_facts.append(f"you are {ident_s}")
            if session_facts:
                parts.append(
                    f"Your name is {session_name}, and from this session, "
                    + "; ".join(session_facts)
                    + "."
                )
            else:
                parts.append(f"From this session, you told me your name is {session_name}.")
        else:
            sess_bits: list[str] = []
            if session_name and name_already_in_profile:
                # Avoid restating the same name a second time.
                pass
            if likes_s:
                sess_bits.append(f"you like {likes_s}")
            if dislikes_s:
                sess_bits.append(f"you don't like {dislikes_s}")
            if ident_s:
                sess_bits.append(f"you are {ident_s}")
            if sess_bits:
                parts.append("From this session, " + "; ".join(sess_bits) + ".")

    return " ".join(p for p in parts if p).strip() or "I don't know anything about you yet."


def _transcript_asks_about_me(text: str) -> bool:
    q = (text or "").strip().lower()
    if not q:
        return False
    return bool(
        re.search(r"\bwhat do you know about me\b", q)
        or re.search(r"\bdo you know me\b", q)
        or re.search(r"\bwho am i\b", q)
        or re.search(r"\bwhat do you know\b.*\bme\b", q)
        or re.search(r"\btell me what you know about me\b", q)
        or re.search(r"\bwhat have i told you\b", q)
        # 2026-05-31 about-me consistency fix: cover the "remember" phrasings
        # so the dedicated handler fires for "what do you remember about me",
        # "do you remember me", "do you remember anything about me", etc.
        # Without this, those phrasings fell through to the normal LLM chat
        # path, which sees the active user profile in the system prompt and
        # synthesizes traits ("you like keeping things moving") from it.
        or re.search(r"\bwhat do you remember about me\b", q)
        or re.search(r"\bdo you remember me\b", q)
        or re.search(r"\bdo you remember anything about me\b", q)
        or re.search(r"\b(?:tell me )?what(?:'s| is)? in my profile\b", q)
    )


ABOUT_ME_FALLBACK_NO_CONTEXT = (
    "I don't know much about you yet from this conversation."
)


ABOUT_ME_LLM_DEVELOPER_INSTRUCTION = (
    "The user just asked you what you know about them. Answer briefly (one or "
    "two short sentences) based ONLY on what the user has actually said earlier "
    "in this conversation. Do not invent details or repeat trivia from general "
    "knowledge. Lead with their name if they have shared it, then list a few "
    "interests, identity facts, or preferences they mentioned, in a natural "
    "voice. Prefix the answer with \"From this conversation,\" so it is clear "
    "this is session-only memory, not a saved profile. If you cannot find "
    "anything they shared, reply with EXACTLY this line and nothing else: "
    f"\"{ABOUT_ME_FALLBACK_NO_CONTEXT}\""
)


def _recent_user_turns_for_about_me(history: list[dict] | None, max_turns: int = 12) -> list[str]:
    """Return the most recent user utterances from chat history (newest last).

    Used as a fallback when we want to detect whether there's any user-shared
    content at all before we kick the LLM. Bounded to keep the prompt cheap.
    """
    if not isinstance(history, list):
        return []
    out: list[str] = []
    for msg in history:
        if not isinstance(msg, dict):
            continue
        if msg.get("role") != "user":
            continue
        c = str(msg.get("content") or "").strip()
        if not c:
            continue
        out.append(c)
    if len(out) > max_turns:
        out = out[-max_turns:]
    return out


_ABOUT_ME_LLM_SYSTEM_PROMPT = (
    "You are VERA, a calm, precise voice assistant. The user just asked "
    "you what you know about them. You have NOT been given a saved profile "
    "for this turn. Answer using ONLY what the user actually said earlier "
    "in this conversation (the user/assistant turns below).\n\n"
    "Rules:\n"
    "- Keep the answer to one or two short sentences suitable for spoken output.\n"
    "- Prefix the answer with \"From this conversation,\" so it is clear "
    "this is session-only memory, not a saved profile.\n"
    "- Do NOT invent personality traits, habits, or preferences. Do NOT "
    "infer how the user behaves from a single line. If they said \"you "
    "know me\" without telling you anything specific, that is NOT a fact.\n"
    "- Do NOT pull in any name, hobby, occupation, or detail from outside "
    "the conversation below.\n"
    "- Do NOT end with a question.\n"
    "- If the user has not shared anything specific you can recall, reply "
    "with EXACTLY this single line and nothing else: "
    f"\"{ABOUT_ME_FALLBACK_NO_CONTEXT}\""
)


def _generate_about_me_llm_reply(
    text: str, session_id: str | None, history: list[dict] | None
) -> str | None:
    """Ask the LLM to answer "what do you know about me" using recent history.

    Synchronous one-shot generate — about-me replies are short (1-2 sentences)
    so the extra latency vs. the streaming general path is small. Returns the
    LLM string on success, or `None` if the call fails / the model returned
    nothing usable. Callers should fall back to a sensible default in that case.

    2026-05-31 about-me consistency fix: this used to call
    ``vera.build_messages(chat, scoped_user_text)``, which re-injected the
    full active user profile (``Name: Nam. Skills: ... Interests: ...
    Habits: ...``) into the system prompt via
    ``CHAT3.build_profile_context``. Combined with the base persona's
    "lightly tease the user using their habits/interests" instruction, the
    developer-level "answer only from the conversation" rule kept losing
    to the system context — the model would fabricate traits like "you
    like keeping things moving" from ``Habits: working out at the gym``.
    We now build the message stack inline with a focused system prompt
    that contains NO profile data; the chat history is preserved so the
    model can still summarize what the user volunteered this session.
    """
    try:
        chat = []
        if isinstance(history, list):
            for msg in history:
                if not isinstance(msg, dict):
                    continue
                role = msg.get("role")
                if role not in {"user", "assistant"}:
                    continue
                content = str(msg.get("content") or "").strip()
                if not content:
                    continue
                chat.append({"role": role, "content": content[:2000]})
        if len(chat) > 24:
            chat = chat[-24:]

        messages: list[dict] = [
            {"role": "developer", "content": _ABOUT_ME_LLM_SYSTEM_PROMPT}
        ]
        messages.extend(chat)
        messages.append({"role": "user", "content": text})

        reply, _ = vera.generate(messages)
        cleaned = (reply or "").strip()
        if not cleaned:
            return None
        return cleaned
    except Exception as exc:
        try:
            print(
                "[about_me_llm_failed] "
                + json.dumps(
                    {
                        "session_id": (session_id or "")[:32],
                        "error": str(exc)[:200],
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return None


def _about_me_diagnostics(
    session_id: str | None,
    history: list[dict] | None,
    profile_facts: dict | None,
    has_profile: bool,
    has_explicit_session: bool,
    blob: dict | None,
) -> dict:
    """Build the diagnostic payload that accompanies every [about_me_reply].

    Centralized so every branch (template / llm / fallback) emits the same
    keys. Keeping the call sites uniform makes downstream log parsing and
    grep-based debugging consistent.

    Field meanings:
      session_id                     last 32 chars of the session id (or "").
      backend_history_turns_count    number of user+assistant turns stored
                                     on the backend for this session.
      current_session_turns_count    same number, mirrored for the spec
                                     wording (frontend may also be checked).
      frontend_history_sent_count    -1 — the frontend does NOT POST chat
                                     history; backend reads it from
                                     user_histories[session_id]. Sentinel
                                     value so downstream log parsers know
                                     the field was intentionally absent
                                     rather than forgotten.
      user_profile_context_present   True iff any field (name/likes/identity)
                                     was projected from a signed-in profile.
      persistent_memory_enabled      True iff has_profile (alias kept for
                                     spec parity).
      explicit_session_facts_present True iff the user used a memory trigger
                                     ("remember that ...") earlier this
                                     session, so session_user_facts has
                                     content.
      source_of_user_name            "profile" / "session_facts" /
                                     "conversation" / "none".
      source_of_user_facts           "profile" / "session_facts" /
                                     "conversation" / "none".
      what_do_you_know_about_me_route final routing token: template_profile
                                     / template_session / template_both /
                                     llm_history / fallback_no_history /
                                     fallback_llm_failed.
    """
    backend_count = 0
    if isinstance(history, list):
        for msg in history:
            if isinstance(msg, dict) and msg.get("role") in {"user", "assistant"}:
                if str(msg.get("content") or "").strip():
                    backend_count += 1

    profile_has_name = bool(
        isinstance(profile_facts, dict) and (profile_facts.get("name") or "")
    )
    session_has_name = bool(
        isinstance(blob, dict) and str(blob.get("name") or "").strip()
    )

    def _source_for(profile_key: str) -> str:
        if (
            isinstance(profile_facts, dict)
            and profile_facts.get(profile_key)
        ):
            return "profile"
        if isinstance(blob, dict):
            v = blob.get(profile_key)
            if isinstance(v, list) and any(str(x).strip() for x in v):
                return "session_facts"
            if isinstance(v, str) and v.strip():
                return "session_facts"
        if backend_count > 0:
            return "conversation"
        return "none"

    if profile_has_name:
        source_of_name = "profile"
    elif session_has_name:
        source_of_name = "session_facts"
    elif backend_count > 0:
        source_of_name = "conversation"
    else:
        source_of_name = "none"

    return {
        "session_id": (session_id or "")[:32],
        "backend_history_turns_count": backend_count,
        "current_session_turns_count": backend_count,
        "frontend_history_sent_count": -1,
        "user_profile_context_present": has_profile,
        "persistent_memory_enabled": has_profile,
        "explicit_session_facts_present": has_explicit_session,
        "source_of_user_name": source_of_name,
        "source_of_user_facts": _source_for("likes"),
    }


# =========================================================================
# 2026-06-01 Identity-leak patch helpers
# =========================================================================
# These helpers implement the strict session-scoped profile resolver used by
# the chat prompt builders, plus the identity-challenge fastpath that
# answers "how do you know my name is X" / "what's my name" / "am I X" /
# "did I tell you my name" safely without going through the general LLM.
# The general LLM is exactly where the leak surfaces, so we short-circuit.

def _session_scoped_active_username(session_id: str | None) -> str | None:
    """Strict per-session active-user lookup. Does NOT fall back to
    ``vera.active_user_info_path`` / the process-global active user. This
    is the function prompt-building code paths must use to decide
    whether to inject ``Current active user profile:`` into the chat
    prompt — the lenient ``get_active_username_for_session`` fallback to
    process-global state is the root cause of cross-session identity
    leakage (one device signs in as Nam -> every session's prompt gets
    Nam as ``Current active user``).
    """
    sid = (session_id or "").strip()
    if not sid:
        return None
    try:
        sid_safe = safe_id(sid)
    except Exception:
        return None
    if not sid_safe:
        return None
    stem = _session_active_user.get(sid_safe)
    if not stem:
        return None
    return str(stem).strip() or None


def _session_scoped_active_user_info(session_id: str | None) -> dict | None:
    """Return the raw profile JSON dict for the session-scoped active
    user (same shape as ``users_files/<stem>.json``), or None.

    This is the value to pass as
    ``vera.build_messages(..., session_active_user_info=...)``. Returning
    None means "this session is anonymous; do not inject any profile
    block". Critically, this never falls back to the process-global
    profile.
    """
    stem = _session_scoped_active_username(session_id)
    if not stem:
        return None
    try:
        path = _ensure_user_profile_json_path(stem)
        profile = _read_user_profile_json(path)
    except Exception:
        return None
    if isinstance(profile, dict):
        return profile
    return None


def _session_active_user_info_for_prompt(session_id: str | None) -> dict | None:
    """Profile dict for ``build_messages``, or explicit None to skip injection.

    When a Supabase JWT is bound, legacy ``users_files`` profile blocks are
    suppressed so account context comes only from ``auth.memory_context``.
    """
    try:
        from auth.request_auth import get_bound_auth_user

        if get_bound_auth_user() is not None:
            return None
    except Exception:
        pass
    return _session_scoped_active_user_info(session_id)


def _inject_supabase_account_context(messages: list[dict]) -> list[dict]:
    try:
        from auth.memory_context import inject_explicit_user_memory

        return inject_explicit_user_memory(messages)
    except Exception as _mem_inj_err:
        print(f"[explicit_memory] inject swallowed: {_mem_inj_err}")
        return messages


def _session_scoped_active_user_name(session_id: str | None) -> str | None:
    """Return the display name from the session-scoped signed-in profile,
    or None. Looks at ``profile.user_profile.name`` then ``profile.name``
    then ``profile.known_facts.name`` then the username stem itself.
    """
    profile = _session_scoped_active_user_info(session_id)
    if not isinstance(profile, dict):
        # Even with no profile JSON, the username stem may still be a
        # usable display name (e.g. user signed in as "Alex" with no
        # profile file). Fall back to the stem so the fastpath has
        # something to say.
        return _session_scoped_active_username(session_id)
    up = profile.get("user_profile")
    if isinstance(up, dict):
        n = up.get("name")
        if isinstance(n, str) and n.strip():
            return n.strip()
    n = profile.get("name")
    if isinstance(n, str) and n.strip():
        return n.strip()
    kf = profile.get("known_facts")
    if isinstance(kf, dict):
        n = kf.get("name")
        if isinstance(n, str) and n.strip():
            return n.strip()
    return _session_scoped_active_username(session_id)


# -- Identity-challenge detection ------------------------------------------
# Patterns the fastpath catches BEFORE the general LLM has a chance to
# hallucinate a source like "you told me earlier". Patterns are deliberately
# narrow: only "how do you know my name", "why do you call me X", "did I
# tell you my name", "am I X", "what's my name", "do you know my name",
# "who am I to you" style questions. Anything broader stays on the normal
# path.
_IDENTITY_CHALLENGE_HOW_RES: tuple[re.Pattern, ...] = (
    # "How / why do you know that my name is Nam?" (claimed-name variant)
    re.compile(
        r"(?ix)\b(?:how|why)\s+(?:do|did|does|would|could|are)\s+you\s+"
        r"(?:know|think|assume|believe|guess|decide)\s+"
        r"(?:that\s+)?(?:my\s+name\s+(?:is|was)|i(?:'m|\s+am))\s+"
        r"([a-z][a-z'\-]{1,30}(?:\s+[a-z][a-z'\-]{1,30})?)\b"
    ),
    # "Why are you calling me Nam?" / "How come you call me Nam?"
    re.compile(
        r"(?ix)\b(?:why|how)\s+(?:come\s+)?(?:are|is|do|did|would)\s+you\s+"
        r"call(?:ing)?\s+me\s+"
        r"([a-z][a-z'\-]{1,30})\b"
    ),
)

# Plain identity-source challenges with no claimed name attached.
_IDENTITY_CHALLENGE_PLAIN_RES: tuple[re.Pattern, ...] = (
    # "Did I tell you my name?" / "Did I say my name?" / "Did I mention my name?"
    re.compile(
        r"(?ix)\bdid\s+i\s+(?:tell|say|mention|give|share)\s+you\s+"
        r"(?:my\s+name|who\s+i\s+am|what\s+my\s+name\s+is)\b"
    ),
    # "How / why do you know who I am?" / "How do you know what my name is?"
    re.compile(
        r"(?ix)\b(?:how|why)\s+(?:do|did|would|could)\s+you\s+know\s+"
        r"(?:who\s+i\s+am|what\s+my\s+name\s+(?:is|was)|my\s+name)\b"
    ),
    # "Do you know my name?" / "Do you know what my name is?"
    re.compile(
        r"(?ix)\bdo\s+you\s+know\s+(?:what\s+)?my\s+name(?:\s+is)?\b"
    ),
    # "What's my name?" / "What is my name?" / "Whats my name?" (ASR) / "Tell me my name."
    re.compile(
        r"(?ix)\b(?:what(?:'s|\s+is|s)\s+my\s+name|tell\s+me\s+my\s+name)\b"
    ),
    # "Who am I to you?" / "Who am I?"
    re.compile(r"(?ix)^\s*who\s+am\s+i(?:\s+to\s+you)?\s*\??\s*$"),
    # "Do you know who I am?" / "Do you remember who I am?"
    re.compile(r"(?ix)\bdo\s+you\s+(?:know|remember)\s+who\s+i\s+am\b"),
    # "Do you recognize me?" / "Do you remember me?"
    re.compile(r"(?ix)\bdo\s+you\s+(?:recogni[sz]e|remember)\s+me\b"),
)

# Recognition-style identity questions ("do you know who I am?", "do you
# recognize me?"). These read as a yes/no recognition probe rather than an
# open "what is my name" — so when ungrounded we answer with the inviting
# "I'm not sure yet — you can tell me." wording instead of the open-question
# fallback. Kept separate from detection so the existing
# ``_detect_identity_challenge`` return signature stays unchanged.
_IDENTITY_RECOGNITION_RES: tuple[re.Pattern, ...] = (
    re.compile(r"(?ix)\bdo\s+you\s+(?:know|remember)\s+who\s+i\s+am\b"),
    re.compile(r"(?ix)\bdo\s+you\s+(?:recogni[sz]e|remember)\s+me\b"),
)


def _is_recognition_style_identity_q(text: str) -> bool:
    """True for yes/no recognition probes like "do you know who I am?"."""
    raw = (text or "").strip()
    if not raw:
        return False
    return any(rx.search(raw) for rx in _IDENTITY_RECOGNITION_RES)

# "Am I Nam?" (yes/no identity probe, claimed-name variant).
_IDENTITY_CHALLENGE_AM_I_RE = re.compile(
    r"(?ix)^\s*am\s+i\s+([a-z][a-z'\-]{1,30})\s*\??\s*$"
)


def _normalize_identity_challenge_text(text: str) -> str:
    """Normalize ASR / mobile-keyboard punctuation for identity regexes."""
    raw = (text or "").strip()
    if not raw:
        return raw
    return (
        raw.replace("\u2019", "'")
        .replace("\u2018", "'")
        .replace("\u2032", "'")
        .replace("`", "'")
    )


def _detect_identity_challenge(text: str) -> tuple[bool, str | None]:
    """Detect whether ``text`` is an identity-challenge question.

    Returns ``(matched, claimed_name)`` where ``claimed_name`` is set
    when the user named a specific person in the challenge (e.g.
    "How do you know my name is Nam?" -> ``("Nam",)``). For plain
    challenges like "What's my name?" the claimed_name is None.
    """
    raw = _normalize_identity_challenge_text(text)
    if not raw:
        return False, None
    for rx in _IDENTITY_CHALLENGE_HOW_RES:
        m = rx.search(raw)
        if m:
            return True, (m.group(1) or "").strip() or None
    am_i = _IDENTITY_CHALLENGE_AM_I_RE.match(raw)
    if am_i:
        return True, (am_i.group(1) or "").strip() or None
    for rx in _IDENTITY_CHALLENGE_PLAIN_RES:
        if rx.search(raw):
            return True, None
    return False, None


# -- Grounded name resolution ---------------------------------------------
# Patterns that count as the user disclosing their name in the visible
# conversation. We deliberately require explicit "my name is X" / "I'm X"
# / "call me X" / "you can call me X" / "this is X speaking" style
# phrasing so we never claim "you mentioned it earlier" based on a stray
# proper noun in chat history.
_NAME_DISCLOSURE_RES: tuple[re.Pattern, ...] = (
    re.compile(
        r"(?ix)\bmy\s+name(?:'s|\s+is|\s+was)\s+"
        r"([A-Z][A-Za-z'\-]{1,30}(?:\s+[A-Z][A-Za-z'\-]{1,30})?)\b"
    ),
    re.compile(
        r"(?ix)\b(?:please\s+)?call\s+me\s+"
        r"([A-Z][A-Za-z'\-]{1,30}(?:\s+[A-Z][A-Za-z'\-]{1,30})?)\b"
    ),
    re.compile(
        r"(?ix)\byou\s+can\s+call\s+me\s+"
        r"([A-Z][A-Za-z'\-]{1,30}(?:\s+[A-Z][A-Za-z'\-]{1,30})?)\b"
    ),
    re.compile(
        r"(?ix)\bi(?:'m|\s+am)\s+"
        r"([A-Z][A-Za-z'\-]{1,30}(?:\s+[A-Z][A-Za-z'\-]{1,30})?)\b"
        r"(?=\s*[\.\!\,\;\?]|\s*$)"
    ),
    re.compile(
        r"(?ix)\bthis\s+is\s+"
        r"([A-Z][A-Za-z'\-]{1,30}(?:\s+[A-Z][A-Za-z'\-]{1,30})?)\s+"
        r"speaking\b"
    ),
)


# Utterances that mention a name only inside remember/forget/save commands
# must NOT count as conversational name disclosure for identity lookup.
_MEMORY_CMD_NAME_UTTERANCE_RES: tuple[re.Pattern, ...] = (
    re.compile(
        r"(?is)\b(?:forget|remember|save|note|delete|remove)\b.*\bmy\s+name\b"
    ),
    re.compile(
        r"(?is)\b(?:forget|remember|save|note)\b.*\bcall\s+me\b"
    ),
)


def _skip_chat_name_disclosure(content: str) -> bool:
    """True when a user turn mentions a name only as a memory command."""
    raw = (content or "").strip()
    if not raw:
        return True
    for rx in _MEMORY_CMD_NAME_UTTERANCE_RES:
        if rx.search(raw):
            return True
    try:
        from auth.memory_commands import is_forget_memory_command

        if is_forget_memory_command(raw):
            return True
    except Exception:
        pass
    # Remember/save/note + name — not bare conversational "call me X".
    if re.search(
        r"(?is)\b(?:remember|save|note|make a note|keep in mind)\b", raw
    ) and re.search(r"(?is)\b(?:my\s+name|call\s+me)\b", raw):
        return True
    return False


def _user_name_from_visible_chat(history: list[dict] | None) -> str | None:
    """Scan the visible chat history (most recent first) for an explicit
    name disclosure by the user. Returns the most recent disclosure, or
    None. Only ``role == "user"`` turns are considered; we never treat
    an assistant turn's use of a name as evidence.
    """
    if not history:
        return None
    for msg in reversed(list(history)):
        if not isinstance(msg, dict):
            continue
        role = str(msg.get("role", "")).strip().lower()
        if role != "user":
            continue
        content = msg.get("content")
        if not isinstance(content, str):
            continue
        if _skip_chat_name_disclosure(content):
            continue
        for rx in _NAME_DISCLOSURE_RES:
            m = rx.search(content)
            if m:
                name = (m.group(1) or "").strip()
                if name:
                    return name
    return None


def _user_name_from_session_facts(session_id: str | None) -> str | None:
    """Return the user-facts name we explicitly stored this session
    (set only when an explicit memory trigger fires). NOT process-global.
    """
    sid = (session_id or "").strip()
    if not sid:
        return None
    blob = session_user_facts.get(sid)
    if not isinstance(blob, dict):
        return None
    n = blob.get("name")
    if isinstance(n, str) and n.strip():
        return n.strip()
    return None


def _user_name_from_supabase_memories() -> str | None:
    """Explicit name memory from Supabase (logged-in users only)."""
    try:
        from auth.request_auth import get_bound_auth_user
        from auth.memory_normalize import name_from_supabase_memories

        user = get_bound_auth_user()
        if not user:
            return None
        return name_from_supabase_memories(user.user_id)
    except Exception:
        return None


def _user_name_from_supabase_profile() -> str | None:
    """Supabase profiles.display_name for the JWT-authenticated user."""
    try:
        from auth.profile_identity import profile_display_name_for_bound_user

        return profile_display_name_for_bound_user()
    except Exception:
        return None


def _grounded_user_name_sources(
    session_id: str | None, history: list[dict] | None
) -> dict:
    """Resolve every grounded source of the current user's name for the
    identity-challenge fastpath.

    Logged-in Supabase users: explicit memory > profile.display_name >
    session facts > legacy users_files > visible chat (last resort).

    Anonymous / legacy: visible chat > session facts > legacy users_files.
    """
    return {
        "from_history": _user_name_from_visible_chat(history),
        "from_supabase_memories": _user_name_from_supabase_memories(),
        "from_supabase_profile": _user_name_from_supabase_profile(),
        "from_session_facts": _user_name_from_session_facts(session_id),
        "from_signed_in_profile": _session_scoped_active_user_name(session_id),
    }


def _identity_uses_supabase_account_priority() -> bool:
    try:
        from auth.request_auth import get_bound_auth_user

        return get_bound_auth_user() is not None
    except Exception:
        return False


def _identity_source_chain(sources: dict) -> list[tuple[str, str | None]]:
    if _identity_uses_supabase_account_priority():
        return [
            ("supabase_memories", sources.get("from_supabase_memories")),
            ("supabase_profile", sources.get("from_supabase_profile")),
            ("session_facts", sources.get("from_session_facts")),
            ("legacy_profile", sources.get("from_signed_in_profile")),
            ("history", sources.get("from_history")),
        ]
    return [
        ("history", sources.get("from_history")),
        ("session_facts", sources.get("from_session_facts")),
        ("legacy_profile", sources.get("from_signed_in_profile")),
    ]


def _identity_primary_name(sources: dict) -> tuple[str, str | None]:
    for via, name in _identity_source_chain(sources):
        if name:
            return via, name
    return "none", None


def _identity_match_claimed_name(
    claimed: str, sources: dict
) -> tuple[str, str | None]:
    for via, name in _identity_source_chain(sources):
        n = name if isinstance(name, str) else None
        if n and claimed.strip().lower() == n.strip().lower():
            return via, n
    return "none", None


def _identity_reply_for_source(via: str, name: str, *, claimed: bool = False) -> str:
    if via == "history":
        if claimed:
            return (
                f"You mentioned it earlier in this conversation - you said "
                f"your name is {name}."
            )
        return (
            f"You mentioned earlier in this conversation that your name is "
            f"{name}."
        )
    if via == "supabase_memories":
        return f"Your name is {name}."
    if via == "supabase_profile":
        if claimed:
            return f"Your account name is {name}."
        return f"I know you as {name}."
    if via == "session_facts":
        return (
            f"You told me earlier this session to use {name} as "
            f"your name."
        )
    if via == "legacy_profile":
        if claimed:
            return (
                f"I'm using the name from your signed-in profile - it says "
                f"{name}."
            )
        return f"Your signed-in profile says {name}."
    return _IDENTITY_FASTPATH_NO_GROUND


# 2026-06-12 persona-wording pass: keep the unknown-identity reply short,
# conversational, and voice-friendly. The old wording ("I should not
# assume that. I may have mixed it up with stored or demo context...")
# read like a safety policy. We never fabricate a source — we just say we
# don't know yet and invite the user to tell us.
_IDENTITY_FASTPATH_NO_GROUND = "I don't know for sure, so I shouldn't guess."
# Inviting variant used for yes/no recognition probes ("do you know who I
# am?", "do you recognize me?").
_IDENTITY_FASTPATH_NO_GROUND_RECOGNITION = "I'm not sure yet — you can tell me."


def _log_identity_lookup(
    *,
    text: str,
    session_id: str | None,
    sources: dict,
    grounded_via: str,
    matched: bool,
    reply: str | None = None,
    request_path: str = "/infer",
) -> None:
    try:
        from auth.request_auth import auth_bind_diagnostics

        auth = auth_bind_diagnostics()
        via, primary = _identity_primary_name(sources)
        payload = {
            "request_path": request_path,
            "session_id": (session_id or "")[:32],
            "transcript": (text or "")[:120],
            "identity_matched": matched,
            "has_authorization_header": auth.get("has_authorization_header"),
            "bound_user_id": auth.get("bound_user_id"),
            "auth": auth,
            "supabase_name_memory": sources.get("from_supabase_memories"),
            "supabase_profile_display_name": sources.get("from_supabase_profile"),
            "session_name": sources.get("from_session_facts"),
            "legacy_name": sources.get("from_signed_in_profile"),
            "history_name": sources.get("from_history"),
            "session_user_facts_name": sources.get("from_session_facts"),
            "legacy_profile_name": sources.get("from_signed_in_profile"),
            "history_name_skipped_memory_cmds": True,
            "uses_supabase_account_priority": _identity_uses_supabase_account_priority(),
            "selected_source": grounded_via if grounded_via != "none" else via,
            "grounded_via": grounded_via,
            "final_reply": (reply or "")[:240],
        }
        print("[identity_lookup] " + json.dumps(payload, ensure_ascii=False), flush=True)
    except Exception:
        pass


def _identity_challenge_fastpath_reply(
    text: str,
    session_id: str | None = None,
    history: list[dict] | None = None,
    request_path: str = "/infer",
) -> str | None:
    """Return a safe identity-challenge reply, or None if ``text`` is
    not an identity challenge.

    The fastpath never invents a source. The only sources it may claim
    are:
      - "You mentioned earlier in this conversation"  (visible chat)
      - "You mentioned that earlier this session"     (session facts)
      - "Your signed-in profile says ..."             (verified profile)
      - "I should not assume that..."                 (no ground)

    Crucially, it NEVER says "you told me earlier" / "I remember" / "from
    our previous conversation" unless the corresponding source is
    actually present and visible to the user.
    """
    matched, claimed_name = _detect_identity_challenge(text)
    if not matched:
        return None

    sources = _grounded_user_name_sources(session_id, history)

    # "Am I X?" / "How do you know my name is X?" -- the user named a
    # specific person. Confirm only if X is grounded in priority order.
    if claimed_name:
        grounded_via, matched_name = _identity_match_claimed_name(
            claimed_name, sources
        )
        if matched_name:
            reply = _identity_reply_for_source(
                grounded_via, matched_name, claimed=True
            )
        else:
            reply = _IDENTITY_FASTPATH_NO_GROUND
        _log_identity_lookup(
            text=text,
            session_id=session_id,
            sources=sources,
            grounded_via=grounded_via if matched_name else "none",
            matched=True,
            reply=reply,
            request_path=request_path,
        )
        return reply

    # Plain "What's my name?" / "Do you know my name?" / "Who am I?" /
    # "Did I tell you my name?" -- the user did NOT name a person.
    grounded_via, primary_name = _identity_primary_name(sources)
    if primary_name:
        reply = _identity_reply_for_source(grounded_via, primary_name)
    else:
        # No grounded source. Pick the inviting recognition wording for
        # yes/no probes ("do you know who I am?"), otherwise the open
        # "I don't know for sure..." fallback.
        if _is_recognition_style_identity_q(text):
            reply = _IDENTITY_FASTPATH_NO_GROUND_RECOGNITION
        else:
            reply = _IDENTITY_FASTPATH_NO_GROUND
        grounded_via = "none"
    _log_identity_lookup(
        text=text,
        session_id=session_id,
        sources=sources,
        grounded_via=grounded_via,
        matched=True,
        reply=reply,
        request_path=request_path,
    )
    return reply


# -- Creator / persona fastpath ------------------------------------------
# "Who made/built/created/designed/developed you (or VERA)?" and
# "Who's your creator/maker/developer?" — answered with a short, natural,
# voice-friendly line rather than a stiff README-style "Nam is the
# creator/developer of VERA." We keep this a narrow persona rule that runs
# alongside the identity fastpath (it rides the same short-circuit slot),
# so the main action router is untouched.
_CREATOR_QUESTION_RES: tuple[re.Pattern, ...] = (
    # "who (actually/really) made/built/created/... you/VERA/this app?"
    re.compile(
        r"(?ix)\bwho(?:'s|\s+is|\s+are|\s+was)?\b[\w\s]{0,24}?\b"
        r"(?:made|built|created|designed|develop(?:ed)?|wrote|coded|"
        r"programmed|invented|engineered|came\s+up\s+with|"
        r"is\s+behind|are\s+behind)\s+"
        r"(?:you|vera|this\s+(?:app|assistant|ai|thing|project|bot))\b"
    ),
    # "who is your creator/maker/developer/designer/builder/author?"
    re.compile(
        r"(?ix)\bwho(?:'s|\s+is|\s+are)\s+"
        r"(?:your|vera'?s|the)\s+"
        r"(?:creator|maker|developer|designer|builder|author|inventor)s?\b"
    ),
)

# Preferred natural creator answer. Short and conversational; avoids
# "Nam is the creator/developer of VERA." per the persona spec.
_CREATOR_FASTPATH_REPLY = "I was built by Nam."


def _detect_creator_question(text: str) -> bool:
    """True when ``text`` asks who designed / made / built / created VERA."""
    raw = (text or "").strip()
    if not raw:
        return False
    return any(rx.search(raw) for rx in _CREATOR_QUESTION_RES)


def _creator_question_fastpath_reply(text: str) -> str | None:
    """Return a short natural creator answer, or None if not a creator
    question. Deterministic so the persona stays consistent in live chat."""
    if not _detect_creator_question(text):
        return None
    try:
        print(
            "[creator_fastpath] "
            + json.dumps({"matched": True, "reply": _CREATOR_FASTPATH_REPLY}, ensure_ascii=False),
            flush=True,
        )
    except Exception:
        pass
    return _CREATOR_FASTPATH_REPLY


def _anonymous_user_fastpath_reply(
    text: str, session_id: str | None = None, history: list[dict] | None = None
) -> str | None:
    """Answer "what do you know about me" without leaving the fastpath.

    POLICY CHANGE (May 2026): no more templated reply from auto-extracted
    casual chat. The order of precedence is now:

      1. If a logged-in profile or explicitly-stored session facts exist,
         use the deterministic template (so persisted memory always wins).
      2. Otherwise ask the LLM to answer briefly using recent chat history.
      3. If the LLM call fails for any reason, fall back to the no-context
         line so the user always gets a sensible reply.

    2026-05-31 about-me consistency fix: ``_logged_in_user_known_facts``
    now also projects ``profile.user_profile`` into the known_facts shape,
    so users signed in with the legacy Nam.json shape (no ``known_facts``
    block) hit branch (1) with a clean "From your saved profile, ..."
    template instead of leaking into the LLM branch. The LLM branch
    itself was rewritten to NOT include the active user profile in the
    system prompt — see ``_generate_about_me_llm_reply``.
    """
    if not _transcript_asks_about_me(text):
        return None

    try:
        from auth.request_auth import get_bound_auth_user

        if get_bound_auth_user() is not None:
            return None
    except Exception:
        pass

    profile_facts = _logged_in_user_known_facts(session_id)
    has_profile = isinstance(profile_facts, dict) and any(
        bool(v) for v in profile_facts.values()
    )
    blob = _get_session_user_facts(session_id)
    has_explicit_session = _user_session_facts_has_content(blob)

    diag = _about_me_diagnostics(
        session_id, history, profile_facts, has_profile, has_explicit_session, blob
    )

    if has_profile or has_explicit_session:
        templated = _build_about_me_reply(session_id)
        if has_profile and has_explicit_session:
            route = "template_both"
        elif has_profile:
            route = "template_profile"
        else:
            route = "template_session"
        try:
            payload = {
                **diag,
                "source": "template",
                "what_do_you_know_about_me_route": route,
                "has_profile": has_profile,
                "has_explicit_session": has_explicit_session,
            }
            print(
                "[about_me_reply] " + json.dumps(payload, ensure_ascii=False),
                flush=True,
            )
        except Exception:
            pass
        return templated

    # No profile, no explicit session memory — answer from recent history.
    recent_user_turns = _recent_user_turns_for_about_me(history)
    if not recent_user_turns:
        try:
            payload = {
                **diag,
                "source": "fallback_no_history",
                "what_do_you_know_about_me_route": "fallback_no_history",
            }
            print(
                "[about_me_reply] " + json.dumps(payload, ensure_ascii=False),
                flush=True,
            )
        except Exception:
            pass
        return ABOUT_ME_FALLBACK_NO_CONTEXT

    llm_reply = _generate_about_me_llm_reply(text, session_id, history)
    try:
        payload = {
            **diag,
            "source": "llm" if llm_reply else "fallback_llm_failed",
            "what_do_you_know_about_me_route": (
                "llm_history" if llm_reply else "fallback_llm_failed"
            ),
            "history_user_turns": len(recent_user_turns),
        }
        print(
            "[about_me_reply] " + json.dumps(payload, ensure_ascii=False),
            flush=True,
        )
    except Exception:
        pass
    return llm_reply or ABOUT_ME_FALLBACK_NO_CONTEXT


def _is_work_mode_snapshot(snapshot: dict | None) -> bool:
    if not isinstance(snapshot, dict):
        return False
    return str(snapshot.get("mode") or "").strip().lower() == "work"


def _wm_timer_parse_duration_seconds(text: str) -> int | None:
    """Parse a total delay in seconds from phrases like '15 minutes', '1 hour
    50 minutes', 'for 2 hours', 'one hour', 'an hour', 'ninety minutes', or
    'one hour and thirty minutes'.

    Delegates to ``actions.timer_duration.parse_timer_duration_seconds`` so
    the runtime timer dispatcher and the multi-action planner agree on what
    counts as a valid duration. Previously this routine only accepted digit
    counts, which meant ``"set a timer for one hour and go to the second
    panel"`` had the planner produce ``timer.set(duration_seconds=None)``,
    failed validation, and fell back to a single-action panel shortcut.
    """
    try:
        from actions.timer_duration import (
            parse_timer_duration_seconds as _shared_parse_timer_duration_seconds,
        )
    except Exception:
        _shared_parse_timer_duration_seconds = None  # type: ignore[assignment]

    parsed_shared: int | None = None
    if _shared_parse_timer_duration_seconds is not None:
        try:
            parsed_shared = _shared_parse_timer_duration_seconds(text)
        except Exception:
            parsed_shared = None

    s = (text or "").strip().lower()
    if not s and parsed_shared is None:
        _log_timer_duration_parse(text, parsed_shared, source="shared")
        return None

    legacy_total = 0
    if s:
        mh = re.search(r"\b(\d+)\s*(?:hours?|hrs?|h)\b", s)
        if mh:
            legacy_total += int(mh.group(1)) * 3600
        mm = re.search(r"\b(\d+)\s*(?:minutes?|mins?|m)\b", s)
        if mm:
            legacy_total += int(mm.group(1)) * 60
        ms = re.search(r"\b(\d+)\s*(?:seconds?|secs?|s)\b", s)
        if ms:
            legacy_total += int(ms.group(1))
    legacy_parsed = legacy_total if legacy_total > 0 else None

    if parsed_shared is not None:
        _log_timer_duration_parse(text, parsed_shared, source="shared")
        return parsed_shared
    if legacy_parsed is not None:
        _log_timer_duration_parse(text, legacy_parsed, source="legacy_digit_fallback")
        return legacy_parsed
    _log_timer_duration_parse(text, None, source="none")
    return None


def _log_timer_duration_parse(raw_text: str | None, parsed: int | None, *, source: str) -> None:
    try:
        log_obj = {
            "tag": "timer_duration_parse",
            "raw_timer_text": (raw_text or "")[:300],
            "parsed_timer_duration_seconds": parsed,
            "timer_duration_parser_source": source,
        }
        print(f"[planner] {json.dumps(log_obj, ensure_ascii=False)}", flush=True)
    except Exception:
        pass


def _wm_timer_format_hm_words(total_sec: int) -> str:
    """Spoken-style duration for whole seconds (hours + minutes only)."""
    s = int(max(0, total_sec))
    h, rem = divmod(s, 3600)
    m = rem // 60
    parts: list[str] = []
    if h:
        parts.append(f"{h} hour{'s' if h != 1 else ''}")
    if m:
        parts.append(f"{m} minute{'s' if m != 1 else ''}")
    if not parts:
        return "less than a minute"
    if len(parts) == 2:
        return f"{parts[0]} and {parts[1]}"
    return parts[0]


def _wm_timer_client_wants_planning_deadline_timer(client_context: dict | None) -> bool:
    """When user states an explicit due-in window, optionally arm a client countdown (default on)."""
    if not isinstance(client_context, dict):
        return True
    v = client_context.get("planning_deadline_timer")
    if v is None:
        return True
    if isinstance(v, bool):
        return v
    s = str(v).strip().lower()
    return s not in ("0", "false", "off", "no")


def _wm_timer_try_capture_plan(
    session_id: str, q: str, client_context: dict | None
) -> dict | None:
    """
    If the user states an explicit due-in time (e.g. due in 2 hours), remember the full deadline and,
    when the client allows it, return a client countdown that ends WORK_MODE_TIMER_EARLY_SEC (10 minutes)
    before that due-in (e.g. 1 hour 50 minutes for a 2-hour window). No explicit time → no match.
    """
    now = time()
    patterns = [
        (
            re.compile(
                r"\b(?:homework|assignment|project|essay|paper)\b[\s\S]{0,120}?"
                r"\b(?:due|deadline|submit|hand\s*in)\b[\s\S]{0,60}?"
                r"\bin\s+(\d+)\s*(hours?|hrs?|h|minutes?|mins?|m)\b",
                re.I,
            ),
            "homework",
        ),
        (
            re.compile(
                r"\b(?:due|deadline|submit|hand\s*in)\b[\s\S]{0,80}?"
                r"\bin\s+(\d+)\s*(hours?|hrs?|h|minutes?|mins?|m)\b",
                re.I,
            ),
            "task",
        ),
        (
            re.compile(
                r"\bin\s+(\d+)\s*(hours?|hrs?|h|minutes?|mins?|m)\b[\s\S]{0,100}?"
                r"\b(?:due|deadline|submit)\b",
                re.I,
            ),
            "task",
        ),
    ]
    for rx, label_hint in patterns:
        m = rx.search(q)
        if not m:
            continue
        n = int(m.group(1))
        unit = str(m.group(2)).lower()
        if unit.startswith("h"):
            delta = n * 3600
        else:
            delta = n * 60
        if delta <= 0 or delta > 86400 * 14:
            continue
        deadline_ts = now + float(delta)
        work_mode_timer_plans[session_id] = {
            "deadline_ts": deadline_ts,
            "label": label_hint,
        }
        human = f"{n} hour{'s' if n != 1 else ''}" if unit.startswith("h") else f"{n} minute{'s' if n != 1 else ''}"
        if not _wm_timer_client_wants_planning_deadline_timer(client_context):
            reply = (
                f"I've noted that in about {human}. "
                "Say remind me before it's due and I'll alert you ten minutes ahead, "
                "or say set a timer for fifteen minutes for a simple countdown."
            )
            return {"reply": reply, "work_mode_timer": None}

        tid = uuid.uuid4().hex[:12]
        timer_delta = max(60, int(delta) - int(WORK_MODE_TIMER_EARLY_SEC))
        timer_fire_ts = now + float(timer_delta)
        if int(delta) > int(WORK_MODE_TIMER_EARLY_SEC):
            timer_human = _wm_timer_format_hm_words(timer_delta)
            wm_message = (
                f"Time's up — about ten minutes before your {label_hint} was due "
                f"(you said about {human} from when you set this)."
            )
            reply = (
                f"I've noted your work is due in about {human}, and I've set a timer for {timer_human} "
                "— ten minutes before that deadline."
            )
        else:
            wm_message = (
                f"Time's up — your {label_hint} deadline is soon "
                f"(you said about {human} from when you set this)."
            )
            reply = (
                f"I've noted your work is due in about {human}, and I've set a short timer before then."
            )
        wm = {
            "id": tid,
            "fire_at_epoch_ms": int(timer_fire_ts * 1000.0),
            "message": wm_message,
            "label": label_hint,
        }
        return {"reply": reply, "work_mode_timer": wm}
    return None


"""
Work-mode timer cancellation intent.

Matches natural phrasings the user can speak (or type) to remove a running
work-mode timer, including the timer-up modal that's blocking on Acknowledge.
The client treats ``{"work_mode_timer": {"cancel": True}}`` as a full clear
(see ``clearVeraWorkModeClientTimer`` in app.js), so any of these phrasings
also dismisses the "Timer is up" overtime modal.

Supported verbs (always followed by an optional article + "timer"):
    cancel, stop, clear, remove, erase, delete, kill, end, drop, scrap, nix

Plus phrasal forms handled separately:
    "turn off the timer" / "turn the timer off"
    "get rid of the timer"
"""
_WM_TIMER_CANCEL_VERB_RX = re.compile(
    r"\b(cancel|stop|clear|remove|erase|delete|kill|end|drop|scrap|nix)\s+"
    r"(?:the\s+|my\s+|that\s+|this\s+)?"
    r"(?:work\s*mode\s+)?timer\b",
    re.IGNORECASE,
)
_WM_TIMER_TURN_OFF_RX = re.compile(
    r"\bturn\s+off\s+(?:the\s+|my\s+|that\s+|this\s+)?(?:work\s*mode\s+)?timer\b"
    r"|\bturn\s+(?:the\s+|my\s+|that\s+|this\s+)?(?:work\s*mode\s+)?timer\s+off\b",
    re.IGNORECASE,
)
_WM_TIMER_GET_RID_RX = re.compile(
    r"\bget\s+rid\s+of\s+(?:the\s+|my\s+|that\s+|this\s+)?(?:work\s*mode\s+)?timer\b",
    re.IGNORECASE,
)


def _wm_timer_cancel_intent_match(text_lower: str) -> str | None:
    """Return the matched cancel-intent pattern name, or None if no match."""
    if _WM_TIMER_CANCEL_VERB_RX.search(text_lower):
        return "verb"
    if _WM_TIMER_TURN_OFF_RX.search(text_lower):
        return "turn_off"
    if _WM_TIMER_GET_RID_RX.search(text_lower):
        return "get_rid_of"
    return None


def _try_work_mode_timer_core(
    session_id: str, transcript: str, client_context: dict | None, client: str
) -> dict | None:
    """
    Work-mode-only timer + planning deadline memory.
    Returns {reply, work_mode_timer} for short-circuit responses, or None.
    """
    if str(client or "").strip().lower() != "vera":
        return None
    q = (transcript or "").strip()
    if not q:
        return None
    ql = q.lower()
    cancel_match = _wm_timer_cancel_intent_match(ql)
    timer_start_match = _WM_TIMER_START_INTENT_RE.search(ql)
    explicit_timer_intent = bool(
        timer_start_match is not None
        or re.search(r"\btimer\b.*\b\d+\b", ql)
        or cancel_match is not None
    )
    try:
        print(
            "[timer_route] "
            + json.dumps(
                {
                    "original_text": (transcript or "")[:200],
                    "normalized_text": ql[:200],
                    "timer_intent_matched": timer_start_match is not None,
                    "cancel_intent_matched": cancel_match is not None,
                    "matched_span": (
                        timer_start_match.group(0)[:120]
                        if timer_start_match is not None
                        else None
                    ),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    if not _is_work_mode_snapshot(client_context):
        if explicit_timer_intent:
            return {
                "reply": (
                    "Timers are only available in Work Mode right now. "
                    "Turn on Work Mode, then ask me to set the timer."
                ),
                "work_mode_timer": None,
            }
        return None

    plan_hit = _wm_timer_try_capture_plan(session_id, ql, client_context)
    if plan_hit is not None:
        return plan_hit

    if cancel_match is not None:
        try:
            print(
                f"[wm_timer_cancel_intent] match={cancel_match} text={q[:120]!r}"
            )
        except Exception:
            pass
        return {
            "reply": "Okay, I've removed your work mode timer.",
            "work_mode_timer": {"cancel": True},
        }

    before_due = bool(
        re.search(
            r"\b(remind|alert|notify)\s+me\b[\s\S]{0,50}?\b(before|prior\s+to)\b[\s\S]{0,40}?"
            r"\b(due|deadline|submit|homework|assignment|it)\b",
            ql,
        )
    )

    plan = work_mode_timer_plans.get(session_id)
    deadline_ts = None
    label = "task"
    if isinstance(plan, dict):
        label = str(plan.get("label") or "task")
        raw_dead = plan.get("deadline_ts")
        if raw_dead is not None:
            try:
                deadline_ts = float(raw_dead)
            except (TypeError, ValueError):
                deadline_ts = None

    now = time()
    fire_ts: float | None = None
    spoken = ""
    early_reminder = False
    has_timer_for = bool(
        re.search(r"\bset\s+(?:a\s+)?timer\s+for\b", ql)
        or re.search(r"\b(?:timer|countdown)\s+for\b", ql)
    )

    if before_due and deadline_ts is not None:
        fire_ts = deadline_ts - float(WORK_MODE_TIMER_EARLY_SEC)
        spoken = f"I'll remind you about your {label} ten minutes before it's due."
        early_reminder = True
    elif (
        deadline_ts is not None
        and re.search(r"\bset\s+(?:a\s+)?timer\b", ql)
        and not has_timer_for
    ):
        fire_ts = deadline_ts - float(WORK_MODE_TIMER_EARLY_SEC)
        spoken = "I'll remind you ten minutes before that deadline."
        early_reminder = True
    elif timer_start_match is not None or re.search(r"\btimer\b.*\b\d+\b", ql):
        dur = _wm_timer_parse_duration_seconds(q)
        try:
            print(
                "[timer_duration_extracted] "
                + json.dumps(
                    {
                        "stage": "timer_core",
                        "normalized_text": ql[:200],
                        "duration_seconds": dur,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        if dur is None:
            if timer_start_match is not None:
                try:
                    print(
                        "[timer_client_start_failed] "
                        + json.dumps(
                            {
                                "reason": "duration_parse_failed",
                                "normalized_text": ql[:200],
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
                return {
                    "reply": (
                        "I understood the timer request, but couldn't start it. "
                        "Try saying 'set a timer for 10 minutes.'"
                    ),
                    "work_mode_timer": None,
                }
            return None
        fire_ts = now + float(dur)
        if dur >= 3600 and dur % 3600 == 0:
            h = dur // 3600
            spoken = f"Timer set for {h} hour{'s' if h != 1 else ''} from now."
        elif dur >= 60 and dur % 60 == 0:
            m = dur // 60
            spoken = f"Timer set for {m} minute{'s' if m != 1 else ''} from now."
        else:
            spoken = f"Timer set for {dur} seconds from now."

    if fire_ts is None:
        return None

    fire_ts = min(fire_ts, now + 86400.0 * 2)
    if fire_ts <= now + 2.0:
        fire_ts = now + 3.0
        spoken = "That's almost now, so I'll nudge you in a few seconds."

    tid = uuid.uuid4().hex[:12]
    msg = (
        f"About ten minutes before your {label} is due."
        if early_reminder
        else "Your work mode timer is up."
    )
    wm = {
        "id": tid,
        "fire_at_epoch_ms": int(fire_ts * 1000.0),
        "message": msg,
        "label": label,
    }
    try:
        print(
            "[timer_payload] "
            + json.dumps(
                {
                    "stage": "timer_core",
                    "work_mode_timer_created": True,
                    "fire_at_epoch_ms": wm["fire_at_epoch_ms"],
                    "label": label,
                    "early_reminder": early_reminder,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
        print(
            "[timer_result] "
            + json.dumps(
                {"stage": "timer_core", "reply": spoken.strip()[:200]},
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    return {"reply": spoken.strip(), "work_mode_timer": wm}


def _timer_snapshot_from_client_context(client_context: dict | None) -> dict:
    snap = client_context if isinstance(client_context, dict) else {}
    timer = snap.get("timer") if isinstance(snap.get("timer"), dict) else {}
    fire_raw = timer.get("fire_at_epoch_ms")
    try:
        fire_at = int(fire_raw) if fire_raw is not None else None
    except (TypeError, ValueError):
        fire_at = None
    return {
        "active": bool(timer.get("active")),
        "expired": bool(timer.get("expired")),
        "fire_at_epoch_ms": fire_at,
        "remaining_seconds": timer.get("remaining_seconds"),
        "timer_id": str(timer.get("timer_id") or "").strip() or None,
    }


def _try_work_mode_timer_extend_core(
    session_id: str, transcript: str, client_context: dict | None, client: str
) -> dict | None:
    """Extend an active client-authoritative work-mode timer by a parsed delta."""
    if str(client or "").strip().lower() != "vera":
        return None
    q = (transcript or "").strip()
    if not q:
        return None
    req = _parse_timer_extend_request(q)
    if not req:
        return None

    delta = int(req.get("duration_delta_seconds") or 0)
    if delta <= 0:
        return None

    if not _is_work_mode_snapshot(client_context):
        label = _format_timer_duration_label(delta)
        return {
            "reply": (
                "Timers are only available in Work Mode right now. "
                f"Turn on Work Mode, then ask me to add {label} to the timer."
            ),
            "work_mode_timer": None,
        }

    timer_state = _timer_snapshot_from_client_context(client_context)
    label = _format_timer_duration_label(delta)

    try:
        print(
            "[timer_extend_execute_start] "
            + json.dumps(
                {
                    "raw_text": q[:240],
                    "duration_delta_seconds": delta,
                    "timer_active": timer_state.get("active"),
                    "timer_expired": timer_state.get("expired"),
                    "timer_id": timer_state.get("timer_id"),
                    "fire_at_epoch_ms": timer_state.get("fire_at_epoch_ms"),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass

    if not timer_state.get("active"):
        if timer_state.get("expired"):
            reply = (
                f"I can't add time because that timer already finished. "
                f"Want me to start a new {label} timer?"
            )
        else:
            reply = (
                f"There isn't an active timer to extend. "
                f"Want me to start a {label} timer?"
            )
        try:
            print(
                "[timer_extend_execute_done] "
                + json.dumps(
                    {
                        "success": False,
                        "reason": "expired" if timer_state.get("expired") else "no_active_timer",
                        "duration_delta_seconds": delta,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return {"reply": reply, "work_mode_timer": None}

    fire_at = timer_state.get("fire_at_epoch_ms")
    if fire_at is None:
        reply = (
            f"There isn't an active timer to extend. "
            f"Want me to start a {label} timer?"
        )
        return {"reply": reply, "work_mode_timer": None}

    new_fire_at = int(fire_at) + int(delta) * 1000
    timer_id = timer_state.get("timer_id") or uuid.uuid4().hex[:12]
    wm = {
        "id": timer_id,
        "fire_at_epoch_ms": new_fire_at,
        "extend": True,
        "duration_delta_seconds": delta,
        "message": "Your work mode timer is up.",
        "label": "timer",
    }
    spoken = f"Added {label} to your timer."
    try:
        print(
            "[timer_extend_execute_done] "
            + json.dumps(
                {
                    "success": True,
                    "duration_delta_seconds": delta,
                    "old_fire_at_epoch_ms": fire_at,
                    "new_fire_at_epoch_ms": new_fire_at,
                    "timer_id": timer_id,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    return {"reply": spoken.strip(), "work_mode_timer": wm}


def _resolve_checklist_items_for_mutation(
    session_id: str,
    server_items: list,
    client_context_snapshot: dict | None,
    *,
    source: str = "",
) -> tuple[list, str]:
    """Choose the checklist base for a normal mutation (add/remove/etc.).

    Undo snapshots are never merged into add — they only gate whether an
    explicit client-side empty snapshot should override stale server rows
    after a recent clear/erase.
    """
    items = server_items if isinstance(server_items, list) else []
    selected_base = "server"
    snapshot_checklist = (
        client_context_snapshot.get("checklist")
        if isinstance(client_context_snapshot, dict) and isinstance(client_context_snapshot.get("checklist"), dict)
        else None
    )
    snapshot_items = snapshot_checklist.get("items") if isinstance(snapshot_checklist, dict) else None
    server_item_count_before = len(_checklist_undo_non_empty_items(items))
    client_snapshot_item_count = (
        len(_checklist_undo_non_empty_items(snapshot_items))
        if isinstance(snapshot_items, list)
        else None
    )
    client_undo = _checklist_undo_snapshot_from_client_context(client_context_snapshot)
    server_undo = checklist_undo_snapshots.get(session_id)
    pending_undo = pending_checklist_undo_context.get(session_id)
    pending_server_undo = bool(server_undo or pending_undo)

    if isinstance(snapshot_items, list):
        client_nonempty = _checklist_undo_non_empty_items(snapshot_items)
        if client_nonempty:
            items = snapshot_items
            selected_base = "client_snapshot"
        elif not server_item_count_before:
            items = snapshot_items
            selected_base = "client_snapshot"
        elif len(snapshot_items) == 0 and (client_undo or pending_server_undo):
            items = []
            selected_base = "client_current_empty"

    try:
        _emit_undo_routing_log(
            "checklist_resolve_mutation_base",
            session_id=(session_id or "")[:64],
            source=str(source or "")[:40],
            server_item_count_before=server_item_count_before,
            client_snapshot_item_count=client_snapshot_item_count
            if client_snapshot_item_count is not None
            else -1,
            client_undo_snapshot_present=bool(client_undo),
            pending_server_undo=pending_server_undo,
            selected_base=selected_base,
        )
    except Exception:
        pass
    return items, selected_base


def _resolve_checklist_items_for_clear(
    session_id: str,
    server_items: list,
    client_context_snapshot: dict | None,
) -> tuple[list, str, str]:
    """Choose which checklist rows to clear and snapshot for undo.

    Unlike add mutations, clear prefers server when non-empty, but falls
    back to the client-visible checklist when the server was cleared
    separately (e.g. UI erase PUT) while localStorage still has items.
    """
    _ = session_id  # reserved for future session-scoped hints
    items = server_items if isinstance(server_items, list) else []
    server_count = len(_checklist_undo_non_empty_items(items))
    snapshot_checklist = (
        client_context_snapshot.get("checklist")
        if isinstance(client_context_snapshot, dict) and isinstance(client_context_snapshot.get("checklist"), dict)
        else None
    )
    snapshot_items = snapshot_checklist.get("items") if isinstance(snapshot_checklist, dict) else None
    client_count = (
        len(_checklist_undo_non_empty_items(snapshot_items))
        if isinstance(snapshot_items, list)
        else 0
    )
    if server_count > 0:
        return items, "server", "server_has_items"
    if client_count > 0 and isinstance(snapshot_items, list):
        return _normalize_checklist_items(snapshot_items), "client_snapshot", "server_empty_client_has_items"
    return [], "empty", "both_empty"


def _handle_checklist_action(
    session_id: str,
    text: str,
    action_name: str,
    client_context_snapshot: dict | None,
) -> dict:
    undo_snap_peek = (
        checklist_undo_snapshots.get(session_id)
        if action_name == "checklist.undo_clear"
        else None
    )
    undo_snap_fresh = bool(
        undo_snap_peek
        and (time() - float(undo_snap_peek.get("created_at") or 0)) <= CHECKLIST_UNDO_TTL_SEC
    )
    if not _is_work_mode_snapshot(client_context_snapshot) and not (
        action_name == "checklist.undo_clear" and undo_snap_fresh
    ):
        return {
            "spoken_reply": "Checklist voice and typed editing only works in Work Mode.",
            "action_type": "checklist",
            "data": None,
            "ui_payload": None,
        }
    items, collapsed, owner_stem = _load_checklist_state_for_session(session_id)
    server_item_count_before = len(_checklist_undo_non_empty_items(items))
    snapshot_checklist = (
        client_context_snapshot.get("checklist")
        if isinstance(client_context_snapshot, dict) and isinstance(client_context_snapshot.get("checklist"), dict)
        else None
    )
    snapshot_items = snapshot_checklist.get("items") if isinstance(snapshot_checklist, dict) else None
    client_snapshot_item_count = (
        len(_checklist_undo_non_empty_items(snapshot_items))
        if isinstance(snapshot_items, list)
        else -1
    )
    client_undo_present = bool(_checklist_undo_snapshot_from_client_context(client_context_snapshot))
    pending_server_undo = bool(
        checklist_undo_snapshots.get(session_id) or pending_checklist_undo_context.get(session_id)
    )
    selected_base = "server"
    if action_name not in ("checklist.clear_all", "checklist.undo_clear"):
        items, selected_base = _resolve_checklist_items_for_mutation(
            session_id,
            items,
            client_context_snapshot,
            source=action_name or "unknown",
        )
    if not isinstance(items, list):
        items = []

    if action_name == "checklist.add_item":
        _emit_undo_routing_log(
            "checklist_add_execute_start",
            session_id=(session_id or "")[:64],
            source="add",
            server_item_count_before=server_item_count_before,
            client_snapshot_item_count=client_snapshot_item_count,
            client_undo_snapshot_present=client_undo_present,
            pending_server_undo=pending_server_undo,
            selected_base=selected_base,
            item_text=str(text or "")[:160],
        )

    if action_name == "checklist.undo_clear":
        snap = checklist_undo_snapshots.get(session_id)
        if not snap or (time() - float(snap.get("created_at") or 0)) > CHECKLIST_UNDO_TTL_SEC:
            checklist_undo_snapshots.pop(session_id, None)
            pending_checklist_undo_context.pop(session_id, None)
            client_snap = _checklist_undo_snapshot_from_client_context(client_context_snapshot)
            if client_snap:
                snap = client_snap
                checklist_undo_snapshots[session_id] = snap
        if not snap or _checklist_undo_snapshot_item_count(snap) <= 0:
            checklist_undo_snapshots.pop(session_id, None)
            pending_checklist_undo_context.pop(session_id, None)
            _emit_undo_routing_log(
                "checklist_undo_failed_no_snapshot",
                session_id=(session_id or "")[:64],
                snapshot_id=str((snap or {}).get("snapshot_id") or ""),
                decision_reason="no_snapshot_on_restore",
            )
            return {
                "spoken_reply": "I don't have a recent checklist change to undo.",
                "action_type": "checklist",
                "data": {"changed": False, "undo_available": False},
                "ui_payload": None,
            }
        if (time() - float(snap.get("created_at") or 0)) > CHECKLIST_UNDO_TTL_SEC:
            checklist_undo_snapshots.pop(session_id, None)
            pending_checklist_undo_context.pop(session_id, None)
            _emit_undo_routing_log(
                "checklist_undo_failed_expired",
                session_id=(session_id or "")[:64],
                snapshot_id=str(snap.get("snapshot_id") or ""),
                decision_reason="ttl_expired_on_restore",
            )
            return {
                "spoken_reply": "I don't have a recent checklist change to undo.",
                "action_type": "checklist",
                "data": {"changed": False, "undo_available": False},
                "ui_payload": None,
            }
        restored_items = _checklist_undo_non_empty_items(snap.get("items") or [])
        restored_collapsed = bool(snap.get("completed_collapsed", collapsed))
        _emit_undo_routing_log(
            "checklist_undo_restore_attempt",
            session_id=(session_id or "")[:64],
            snapshot_id=str(snap.get("snapshot_id") or ""),
            snapshot_item_count=len(restored_items),
        )
        _save_checklist_state_for_session(
            session_id, restored_items, completed_collapsed=restored_collapsed
        )
        checklist_undo_snapshots.pop(session_id, None)
        pending_checklist_undo_context.pop(session_id, None)
        non_empty = len(restored_items)
        titles = _checklist_undo_item_titles(restored_items)
        print(
            f"[CHECKLIST_DEBUG][undo_clear] session={session_id} restored_count={non_empty}"
        )
        _emit_undo_routing_log(
            "checklist_undo_restored",
            session_id=(session_id or "")[:64],
            snapshot_id=str(snap.get("snapshot_id") or ""),
            restored_item_count=non_empty,
            restored_titles=titles,
        )
        return {
            "spoken_reply": "Restored the checklist.",
            "action_type": "checklist",
            "data": {"changed": True, "undo": True, "restored_count": non_empty},
            "ui_payload": {
                "panel_type": "checklist_control",
                "op": "checklist.undo_clear",
                "items": restored_items,
                "completed_collapsed": restored_collapsed,
                "owner_username": owner_stem,
            },
        }

    if action_name == "checklist.clear_all":
        client_titles = (
            _checklist_undo_item_titles(snapshot_items)
            if isinstance(snapshot_items, list)
            else []
        )
        items, selected_clear_base, clear_reason = _resolve_checklist_items_for_clear(
            session_id,
            items,
            client_context_snapshot,
        )
        titles_before = _checklist_undo_item_titles(items)
        item_count_before = len(_checklist_undo_non_empty_items(items))
        _emit_undo_routing_log(
            "checklist_clear_execute_start",
            session_id=(session_id or "")[:64],
            source="voice_clear",
            server_item_count_before=server_item_count_before,
            client_snapshot_item_count=client_snapshot_item_count,
            client_titles=client_titles[:20],
            client_undo_snapshot_present=client_undo_present,
            pending_server_undo=pending_server_undo,
            selected_clear_base=selected_clear_base,
            reason=clear_reason,
        )
        if item_count_before <= 0:
            _emit_undo_routing_log(
                "checklist_clear_already_empty_decision",
                session_id=(session_id or "")[:64],
                server_item_count_before=server_item_count_before,
                client_snapshot_item_count=client_snapshot_item_count,
                reason=clear_reason,
            )
            return {
                "spoken_reply": "Your checklist is already empty.",
                "action_type": "checklist",
                "data": {"changed": False, "cleared_count": 0, "undo_available": False},
                "ui_payload": None,
            }
        _emit_undo_routing_log(
            "checklist_clear_requested",
            session_id=(session_id or "")[:64],
            mode=str((client_context_snapshot or {}).get("mode") or ""),
            item_count_before_clear=item_count_before,
            item_titles_before_clear=titles_before,
        )
        before_total = len(items)
        before_done = sum(1 for r in items if isinstance(r, dict) and bool(r.get("done")))
        snapshot_payload = {
            "items": [
                {
                    "id": str((r or {}).get("id") or ""),
                    "text": str((r or {}).get("text") or ""),
                    "done": bool((r or {}).get("done")),
                    "parent_id": (r or {}).get("parent_id"),
                }
                for r in items
                if isinstance(r, dict)
            ],
            "completed_collapsed": bool(collapsed),
            "created_at": time(),
        }
        next_items, spoken_reply, changed = apply_checklist_action(
            items, action_name, {"action": action_name}, vera=vera, user_text=text
        )
        if changed and item_count_before > 0:
            armed = _arm_checklist_undo_snapshot(
                session_id,
                snapshot_payload.get("items") or items,
                completed_collapsed=bool(collapsed),
                source="checklist.clear",
            )
            if not armed:
                checklist_undo_snapshots.pop(session_id, None)
                pending_checklist_undo_context.pop(session_id, None)
            _save_checklist_state_for_session(session_id, next_items, completed_collapsed=collapsed)
        else:
            checklist_undo_snapshots.pop(session_id, None)
            pending_checklist_undo_context.pop(session_id, None)
        after_count = len(_checklist_undo_non_empty_items(next_items))
        _emit_undo_routing_log(
            "checklist_clear_execute_done",
            session_id=(session_id or "")[:64],
            source="voice_clear",
            server_item_count_before=server_item_count_before,
            cleared_item_count=item_count_before if changed else 0,
            undo_snapshot_source=selected_clear_base if changed and item_count_before > 0 else None,
            result_item_count=after_count,
            result_titles=_checklist_undo_item_titles(next_items),
        )
        _emit_undo_routing_log(
            "checklist_cleared",
            session_id=(session_id or "")[:64],
            item_count_after_clear=after_count,
            undo_snapshot_item_count=_checklist_undo_snapshot_item_count(
                checklist_undo_snapshots.get(session_id)
            ),
        )
        print(
            "[CHECKLIST_DEBUG][clear_all] "
            f"session={session_id} before={before_total} done_before={before_done} "
            f"after={len(next_items)} undo_snapshot_available={changed and item_count_before > 0}"
        )
        return {
            "spoken_reply": spoken_reply,
            "action_type": "checklist",
            "data": {
                "changed": changed,
                "cleared_count": before_total if changed else 0,
                "undo_available": changed and item_count_before > 0,
            },
            "ui_payload": (
                {
                    "panel_type": "checklist_control",
                    "op": "checklist.clear_all",
                    "items": next_items,
                    "completed_collapsed": bool(collapsed),
                    "owner_username": owner_stem,
                }
                if changed
                else None
            ),
        }

    parsed = parse_checklist_command(vera, text, action_name)
    try:
        print(
            "[CHECKLIST_DEBUG][parse] "
            f"action={action_name} "
            f"parsed_count={parsed.get('target_count')} "
            f"count_mode={parsed.get('target_count_mode')} "
            f"count_reason={parsed.get('target_count_reason')} "
            f"target_text={parsed.get('target_text')!r} "
            f"target_index={parsed.get('target_index')} "
            f"user_text={text!r}"
        )
    except Exception:
        pass
    before_total = len(items)
    next_items, spoken_reply, changed = apply_checklist_action(
        items,
        action_name,
        parsed,
        vera=vera,
        user_text=text,
    )
    if changed:
        # Save an undo snapshot so "undo that" restores even non-clear edits.
        try:
            checklist_undo_snapshots[session_id] = {
                "items": [
                    {
                        "id": str((r or {}).get("id") or ""),
                        "text": str((r or {}).get("text") or ""),
                        "done": bool((r or {}).get("done")),
                        "parent_id": (r or {}).get("parent_id"),
                    }
                    for r in items
                    if isinstance(r, dict)
                ],
                "completed_collapsed": bool(collapsed),
                "created_at": time(),
            }
        except Exception:
            pass
        _save_checklist_state_for_session(session_id, next_items, completed_collapsed=collapsed)
    if isinstance(parsed.get("target_count"), int) and parsed.get("target_count", 0) > 0:
        try:
            print(
                "[CHECKLIST_DEBUG][apply_count] "
                f"action={action_name} "
                f"count={parsed.get('target_count')} "
                f"checklist_count_before={before_total} "
                f"checklist_count_after={len(next_items)} "
                f"changed={changed}"
            )
        except Exception:
            pass
    # 2026-05-29 spec PART 5 — diagnostic log for checklist add/remove/etc.
    # The payload mode is "full_state": ``items`` carries the post-action
    # checklist, the frontend REPLACES localStorage with it, and dedupe on
    # ``request_id+payload_index`` guards against double-apply. We compute
    # which items are new vs preserved so logs can show the delta.
    try:
        before_texts = [
            str((r or {}).get("text") or "")
            for r in items if isinstance(r, dict)
        ]
        after_texts = [
            str((r or {}).get("text") or "")
            for r in (next_items or []) if isinstance(r, dict)
        ]
        before_set = set(t for t in before_texts if t)
        after_set = set(t for t in after_texts if t)
        items_added = [t for t in after_texts if t and t not in before_set]
        items_removed = [t for t in before_texts if t and t not in after_set]
        print(
            "[checklist_payload] "
            + json.dumps(
                {
                    "op": action_name,
                    "checklist_payload_mode": "full_state",
                    "checklist_items_before_count": len(before_texts),
                    "checklist_items_after_count": len(after_texts),
                    "checklist_items_added": items_added[:20],
                    "checklist_items_removed": items_removed[:20],
                    "changed": bool(changed),
                    "request_id": _current_request_id_var.get() or "",
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    if action_name == "checklist.add_item":
        result_titles = _checklist_undo_item_titles(next_items or [])
        _emit_undo_routing_log(
            "checklist_add_execute_done",
            session_id=(session_id or "")[:64],
            source="add",
            server_item_count_before=server_item_count_before,
            client_snapshot_item_count=client_snapshot_item_count,
            client_undo_snapshot_present=client_undo_present,
            pending_server_undo=pending_server_undo,
            selected_base=selected_base,
            item_text=str(text or "")[:160],
            result_item_count=len(result_titles),
            result_titles=result_titles[:20],
        )
    return {
        "spoken_reply": spoken_reply,
        "action_type": "checklist",
        "data": {"changed": changed, "parsed": parsed},
        "ui_payload": (
            {
                "panel_type": "checklist_control",
                "op": action_name,
                "items": next_items,
                "completed_collapsed": bool(collapsed),
                "owner_username": owner_stem,
                # ``payload_mode`` documents the intended apply behavior so
                # the frontend never mixes "full state" + "append" modes.
                # Per 2026-05-29 spec PART 5 we use full_state + replace.
                "payload_mode": "full_state",
            }
            if changed
            else None
        ),
    }


def _fallback_infer_attachment_context(filename: str, mime: str, raw: bytes) -> str:
    """When ReasoningAI is unavailable, still give /infer a minimal text signal from the upload."""
    name = (filename or "upload").strip() or "upload"
    mime_l = (mime or "").lower()
    low = name.lower()
    if mime_l.startswith("text/") or low.endswith((".txt", ".csv", ".json", ".md", ".log")):
        body = raw.decode("utf-8", errors="replace")[:120000]
        return f"[Attachment: {name} — plain-text decode]\n{body}"
    return (
        f"[Attachment: {name} — type {mime or 'unknown'}, {len(raw)} bytes]\n"
        "Structured PDF/image extraction is unavailable on this server instance. "
        "Acknowledge the upload and ask the user to paste the key passage or try again when extraction is enabled."
    )


def run_general_llm(
    history: list[dict],
    text: str,
    session_id: str,
    reasoning_voice_coach: str | None = None,
    reasoning_attachment_context: str | None = None,
    client_context_snapshot: dict | None = None,
    thread_follow_up_anchor: str | None = None,
    work_mode_reasoning_context: dict | None = None,
    work_mode_voice_brief_completion: bool = False,
    work_mode_stage2_also_prefix: bool = False,
    work_mode_strict_lane_context: bool = False,
    work_mode_stage2_turn: dict | None = None,
    work_mode_stage2_spoken_override: str | None = None,
) -> tuple[str, float]:
    try:
        _enforce_usage_credit_cap("voice_assistant", session_id=session_id)
    except HTTPException:
        raise
    # 2026-06-01 identity-leak patch: pass the session-scoped active user
    # profile so the chat prompt only contains a "Current active user
    # profile" block when THIS session has explicitly signed in. Without
    # this, a stale process-global profile (typically users_files/Nam.json)
    # bleeds into every session's developer prompt.
    messages = vera.build_messages(
        history,
        text,
        session_active_user_info=_session_active_user_info_for_prompt(session_id),
    )
    messages, _lane_dbg = _inject_client_context_snapshot(
        messages,
        client_context_snapshot,
        text,
        work_mode_reasoning_context,
        strict_lane_handoff=work_mode_strict_lane_context,
    )
    messages = _inject_thread_follow_up_anchor(messages, thread_follow_up_anchor, text)
    messages = _inject_reasoning_voice_coach(
        messages, reasoning_voice_coach, text, client_context_snapshot
    )
    messages = _inject_reasoning_attachment_context(messages, reasoning_attachment_context, text)
    messages = _inject_work_mode_reasoning_handoff(messages, work_mode_reasoning_context, text)
    messages = _inject_work_mode_voice_brief_completion_rules(
        messages,
        work_mode_voice_brief_completion,
        text,
        stage2_also_prefix=work_mode_stage2_also_prefix,
        stage2_turn=work_mode_stage2_turn,
    )
    messages = inject_recent_action_context(messages, session_id, text)
    messages = _inject_supabase_account_context(messages)

    t0 = perf_counter()
    reply, confidence = vera.generate(messages)
    t_llm = perf_counter() - t0
    print(f"[LLM] conf={confidence:.3f}")
    if work_mode_voice_brief_completion:
        override = (work_mode_stage2_spoken_override or "").strip()
        if override and _stage2_status_scope_matches(work_mode_stage2_turn, work_mode_reasoning_context):
            reply = override
        _log_stage2_voice_generation(
            transcript=text,
            reply=reply,
            wm_ctx=work_mode_reasoning_context,
            stage2_turn=work_mode_stage2_turn,
            spoken_override=work_mode_stage2_spoken_override,
        )

    # Memory-language sanitizer. The LLM occasionally responds with
    # "Got it, I'll keep Orange County in mind." after a casual location
    # mention. When the user did NOT explicitly ask us to remember
    # anything, strip that phrasing so the reply reads like normal
    # conversation. The decision + every substitution are emitted to
    # [MEMORY_CONTEXT_DEBUG] so we can audit routing per turn.
    memory_signal = _classify_memory_request(text)
    reply_before = reply
    reply, _memory_sanitize_dbg = _sanitize_memory_language_in_reply(
        reply, memory_signal
    )
    _log_memory_context_debug(
        user_text=text,
        reply_before=reply_before,
        reply_after=reply,
        memory_signal=memory_signal,
        sanitize_dbg=_memory_sanitize_dbg,
    )

    return reply, t_llm


def resolve_reply_if_not_general_llm(
    session_id: str,
    text: str,
    history: list[dict],
    filler_generation: int | None = None,
    client_context_snapshot: dict | None = None,
) -> tuple[str, float, dict | None] | None:
    """
    If routing would call run_general_llm, return None.
    Otherwise return the same (reply, t_llm, action_result) as process_user_input for action/followup paths.
    """
    try:
        if _is_memory_command_request(text):
            return None
    except Exception:
        pass
    log_route_debug(
        session_id,
        text,
        stage="sync_resolve_entry",
        selected_route="pre_route",
        selected_action_name="",
        should_search=False,
        serper_called=False,
        used_recent_news_context=False,
        note="before source/voice/finance/news followup shortcuts",
    )
    # Stage 1: shadow log only. classify_route_family() does NOT yet gate
    # any shortcut below. Compare `routeFamily` against the actually-selected
    # action in downstream `[route_debug]` lines to validate Stage 2 wiring.
    try:
        _rf_ctx_sync = get_recent_news_context(session_id) if session_id else None
    except Exception:
        _rf_ctx_sync = None
    try:
        _rf_result_sync = classify_route_family(
            text,
            session_id=session_id,
            history=history,
            recent_news_context=_rf_ctx_sync,
        )
    except Exception:
        _rf_result_sync = None
    log_route_family_debug(
        session_id,
        text,
        mode="sync",
        route_family_result=_rf_result_sync,
        recent_news_context=_rf_ctx_sync,
        note="shadow_only_sync_entry",
    )

    undo_resolved = resolve_checklist_undo_shortcut(
        session_id,
        text,
        client_context_snapshot=client_context_snapshot,
    )
    if undo_resolved is not None:
        reply, t_llm, action_result = undo_resolved
        return reply, t_llm, action_result

    pending = get_pending_action(session_id)
    if pending and pending.get("action_name") == "weather.forecast" and pending.get("missing_slot") in {
        "location",
        "time",
        "both",
    }:
        action_result, t_llm = resolve_pending_weather_forecast_request(session_id, text, pending)
        return action_result_reply(action_result) or WEATHER_LOCATION_INVALID_REPLY, t_llm, action_result
    if pending and pending.get("action_name") == "weather.current" and pending.get("missing_slot") == "location":
        action_result, t_llm = resolve_pending_weather_request(session_id, text, filler_generation=filler_generation)
        return action_result_reply(action_result) or WEATHER_LOCATION_INVALID_REPLY, t_llm, action_result
    if pending and pending.get("action_name") == "web.search" and pending.get("missing_slot") == "location":
        # 2026-05-28 PART 1 — beta info-tool router clarification follow-up.
        action_result, t_llm = resolve_pending_web_search_request(
            session_id, text, pending, filler_generation=filler_generation
        )
        return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, t_llm, action_result
    if pending and pending.get("action_name") == "news.latest" and pending.get("missing_slot") == "breaking_intent":
        action_result, t_llm = resolve_pending_breaking_news_request(session_id, text, filler_generation=filler_generation)
        if action_result is not None:
            return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, t_llm, action_result
    if pending and pending.get("action_name") in {"finance.quote", "finance.context"}:
        action_result, t_llm = resolve_pending_finance_request(session_id, text, pending, filler_generation=filler_generation)
        return action_result_reply(action_result) or FINANCE_SUBJECT_INVALID_REPLY, t_llm, action_result
    if pending and pending.get("action_name") == "music.play_track" and pending.get("missing_slot") == "track_query":
        action_result, t_llm = resolve_pending_music_play_request(session_id, text)
        return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, t_llm, action_result
    if pending and pending.get("action_name") == "music.play_album" and pending.get("missing_slot") == "album_query":
        action_result, t_llm = resolve_pending_music_album_request(session_id, text)
        return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, t_llm, action_result
    if pending and pending.get("action_name") == "music.play_playlist" and pending.get("missing_slot") == "playlist_name":
        action_result, t_llm = resolve_pending_music_playlist_request(session_id, text)
        return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, t_llm, action_result

    source_pattern = _match_source_request_pattern(text)
    if source_pattern is not None:
        has_ctx = get_recent_news_context(session_id) is not None
        sources_result, sources_t_llm = try_resolve_news_sources_request(session_id, text)
        if sources_result is not None:
            _log_source_request_detection(
                text, source_pattern,
                has_last_news_context=True,
                fallback_topic_from_previous_turn="",
                final_action="news.sources_from_context",
            )
            reply = action_result_reply(sources_result) or EMPTY_REPLY_FALLBACK
            return reply, sources_t_llm, sources_result
        fallback_result, fallback_t_llm = try_resolve_news_sources_fallback(
            session_id, text, history, filler_generation=filler_generation
        )
        if fallback_result is not None:
            fallback_topic = (
                (fallback_result.get("data") or {}).get("query")
                or ""
            )
            _log_source_request_detection(
                text, source_pattern,
                has_last_news_context=has_ctx,
                fallback_topic_from_previous_turn=fallback_topic,
                final_action="news.latest_from_history",
            )
            reply = action_result_reply(fallback_result) or EMPTY_REPLY_FALLBACK
            return reply, fallback_t_llm, fallback_result
        # Couldn't fulfill via stored context or fallback search; fall through but
        # log so we can see why source request didn't override general.
        _log_source_request_detection(
            text, source_pattern,
            has_last_news_context=has_ctx,
            fallback_topic_from_previous_turn="",
            final_action="general",
        )

    voice_offer_result, voice_offer_t_llm = try_resolve_pending_voice_action(
        session_id,
        text,
        history,
        client_context_snapshot=client_context_snapshot,
        filler_generation=filler_generation,
    )
    if voice_offer_result is not None:
        reply = action_result_reply(voice_offer_result) or EMPTY_REPLY_FALLBACK
        return reply, voice_offer_t_llm, voice_offer_result

    finance_correction_result, finance_correction_t_llm = try_resolve_finance_correction_execute(
        session_id, text, history, filler_generation=filler_generation
    )
    if finance_correction_result is not None:
        reply = action_result_reply(finance_correction_result) or EMPTY_REPLY_FALLBACK
        return reply, finance_correction_t_llm, finance_correction_result

    news_corrective_result, news_corrective_t_llm = try_resolve_news_followup_execute(
        session_id, text, history, filler_generation=filler_generation
    )
    if news_corrective_result is not None:
        log_route_debug(
            session_id,
            text,
            stage="sync_selected_news_followup",
            selected_route="news_followup_execute",
            selected_action_name="news.context_or_latest",
            should_search=(news_corrective_result.get("action_type") == "news" and bool((news_corrective_result.get("data") or {}).get("headlines"))),
            serper_called=(news_corrective_result.get("action_type") == "news" and bool((news_corrective_result.get("data") or {}).get("headlines"))),
            used_recent_news_context=True,
            final_answer_source="stored_source_context_or_news_action",
            note="returned before route_action_request utility/finance router",
        )
        reply = action_result_reply(news_corrective_result) or EMPTY_REPLY_FALLBACK
        return reply, news_corrective_t_llm, news_corrective_result

    followup_result, followup_t_llm = resolve_recent_action_followup(
        session_id,
        text,
        history,
        filler_generation=filler_generation,
    )
    if followup_result is not None:
        _route_debug_recent = get_recent_action_context(session_id) or {}
        log_route_debug(
            session_id,
            text,
            stage="sync_selected_recent_action_followup",
            selected_route="recent_action_followup_execute",
            selected_action_name=str(_route_debug_recent.get("action_name") or "recent_action"),
            should_search=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            serper_called=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            used_recent_news_context=str(_route_debug_recent.get("action_name") or "") == "news.latest",
            final_answer_source="recent_action",
            note="returned before route_action_request final router",
        )
        reply = action_result_reply(followup_result) or EMPTY_REPLY_FALLBACK
        return reply, followup_t_llm, followup_result

    checklist_action = is_checklist_action_request(text)
    if checklist_action:
        action_result = _handle_checklist_action(
            session_id, text, checklist_action, client_context_snapshot
        )
        return action_result_reply(action_result) or EMPTY_REPLY_FALLBACK, 0.0, action_result

    route = route_action_request(session_id, text)
    if route.get("is_action_request"):
        log_route_debug(
            session_id,
            text,
            stage="sync_selected_route_action",
            selected_route=route.get("domain") or "",
            selected_action_name=route.get("action_name") or "",
            should_search=route.get("action_name") == "news.latest",
            serper_called=route.get("action_name") == "news.latest",
            used_recent_news_context=bool(route.get("action_name") == "news.latest" and get_recent_news_context(session_id)),
            final_answer_source="action",
        )
        action_result, t_llm = execute_structured_action(
            session_id,
            text,
            route,
            filler_generation=filler_generation,
            client_context_snapshot=client_context_snapshot,
        )
        if action_result is not None:
            reply = action_result_reply(action_result) or EMPTY_REPLY_FALLBACK
            return reply, t_llm, action_result

    log_route_debug(
        session_id,
        text,
        stage="sync_selected_general_llm",
        selected_route="general",
        selected_action_name="general",
        should_search=False,
        serper_called=False,
        used_recent_news_context=False,
        final_answer_source="llm_general",
    )
    return None


def process_user_input(
    session_id: str,
    text: str,
    history: list[dict],
    filler_generation: int | None = None,
    reasoning_voice_coach: str | None = None,
    reasoning_attachment_context: str | None = None,
    client_context_snapshot: dict | None = None,
    thread_follow_up_anchor: str | None = None,
    work_mode_reasoning_context: dict | None = None,
    work_mode_voice_brief_completion: bool = False,
    work_mode_stage2_also_prefix: bool = False,
    work_mode_strict_lane_context: bool = False,
    work_mode_stage2_turn: dict | None = None,
    work_mode_stage2_spoken_override: str | None = None,
) -> tuple[str, float, dict | None]:
    # 2026-05-29 — multi-action planner SHADOW pass. Logs only this turn.
    # `process_user_input` is the single consolidation point both /text and
    # /infer flow through (the streaming bypass in /infer hits
    # try_prepare_streaming_action_messages first, but anything that
    # reaches the LLM lands here). Shadow-logging here is enough for
    # offline analysis without touching execution.
    try:
        _shadow_run_multi_action_planner(
            text=text, session_id=session_id, note="process_user_input_shadow"
        )
    except Exception as _planner_err:
        print(f"[planner] process_user_input shadow swallowed: {_planner_err}")

    if work_mode_voice_brief_completion:
        override = (work_mode_stage2_spoken_override or "").strip()
        if override and _stage2_status_scope_matches(
            work_mode_stage2_turn, work_mode_reasoning_context
        ):
            return override, 0.0, None
    else:
        resolved = resolve_reply_if_not_general_llm(
            session_id,
            text,
            history,
            filler_generation=filler_generation,
            client_context_snapshot=client_context_snapshot,
        )
        if resolved is not None:
            return resolved
    llm_history = [] if work_mode_voice_brief_completion else history
    reply, t_llm = run_general_llm(
        llm_history,
        text,
        session_id,
        reasoning_voice_coach,
        reasoning_attachment_context,
        client_context_snapshot,
        thread_follow_up_anchor,
        work_mode_reasoning_context,
        work_mode_voice_brief_completion,
        work_mode_stage2_also_prefix,
        work_mode_strict_lane_context,
        work_mode_stage2_turn,
        work_mode_stage2_spoken_override,
    )
    return reply, t_llm, None


def _sync_synthesize_segment(
    seg: str,
    session_id: str,
    date_str: str,
    tts_dir: Path,
    use_bmo_fish: bool,
    client: str,
) -> str:
    """Blocking TTS for one segment; returns relative URL /audio/..."""
    ext = ".mp3" if use_bmo_fish else ".wav"
    fname = f"{timestamp()}-{uuid.uuid4().hex[:10]}{ext}"
    path = tts_dir / fname

    if use_bmo_fish:
        try:
            generate_bmo_audio(seg, path)
        except Exception as e:
            print(f"[TTS][BMO][FISH] fallback to local SpeechT5: {e}")
            fname = f"{timestamp()}-{uuid.uuid4().hex[:10]}.wav"
            path = tts_dir / fname
            speak_to_file(seg, path)
    else:
        if (client or "vera").strip().lower() == "bmo" and not bmo_fish_configured():
            print(
                "[TTS][BMO] Fish not configured — set FISH_API_KEY + REFERENCE_ID "
                "for the same process that runs app.py (e.g. `.env` next to app.py + "
                "`pip install python-dotenv`), or export vars before starting uvicorn."
            )
        speak_to_file(seg, path)

    return f"/audio/{session_id}/{date_str}/{fname}"


def _segments_for_tts(reply: str) -> list[str]:
    if not reply or not str(reply).strip():
        reply = EMPTY_REPLY_FALLBACK
    if tts_sentence_chunks_enabled():
        segments = split_sentences_for_tts(reply)
        if not segments:
            segments = [reply.strip() or EMPTY_REPLY_FALLBACK]
    else:
        segments = [reply.strip() or EMPTY_REPLY_FALLBACK]
    return segments


def _cumulative_reply_display(parts: list[str]) -> str:
    """Join completed TTS segments for incremental assistant bubble text."""
    return " ".join(s.strip() for s in parts if s and str(s).strip()).strip()


async def iter_tts_chunk_ndjson_lines(session_id: str, reply: str, client: str) -> AsyncIterator[str]:
    """
    Yield one NDJSON line per synthesized chunk as soon as it's ready (streaming TTS).
    Each line: {"type":"chunk","index":i,"url":"/audio/..."}
    """
    if not reply or not str(reply).strip():
        reply = EMPTY_REPLY_FALLBACK
    tts_dir = user_tts_dir(session_id)
    use_bmo_fish = (client or "vera").strip().lower() == "bmo" and bmo_fish_configured()
    segments = _segments_for_tts(reply)
    date_str = today()
    cum_parts: list[str] = []
    # Multi-device-concurrency PART 1 + PART 5: surface TTS lock waits per
    # session so two-device debugging can see when one device is blocked
    # behind another's TTS synthesis. The lock body only runs the synth
    # call (BMO Fish network OR local SpeechT5) — no streaming.
    _tts_request_id = _current_request_id_var.get() or "req_unknown"
    for i, seg in enumerate(segments):
        async with _LockDiag(tts_lock, name="TTS", session_id=session_id, request_id=_tts_request_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                seg,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        cum_parts.append(seg)
        reply_so_far = _cumulative_reply_display(cum_parts)
        line = json.dumps(
            {"type": "chunk", "index": i, "url": rel, "reply_so_far": reply_so_far},
            ensure_ascii=False,
        ) + "\n"
        yield line
        await asyncio.sleep(0)

def _compute_work_mode_voice_quote(transcript: str, action_result) -> tuple[str, str]:
    """Choose the value for ``work_mode_voice_quote`` on multi-action turns.

    Spec PART 6: ``work_mode_voice_quote`` historically echoed the raw
    user transcript verbatim. For compound commands the transcript
    contains music/panel/timer/checklist phrases that should not be
    spoken back as part of a brief stage-2 voice reply. When the action
    executor produced a clean span summary (``voice_quote_override``),
    use that. Otherwise fall back to the original transcript so single
    -action turns keep their previous behavior.

    Returns ``(quote, source)`` where ``source`` is one of
    ``raw_transcript`` / ``cleaned_span`` / ``action_summary`` — used by
    the [work_mode_voice_quote_decision] log line.
    """
    raw = transcript or ""
    quote_source = "raw_transcript"
    if isinstance(action_result, dict):
        override = (action_result.get("voice_quote_override") or "").strip()
        if override:
            try:
                print(
                    "[work_mode_voice_quote_decision] "
                    + json.dumps(
                        {
                            "work_mode_voice_quote_before": raw[:200],
                            "work_mode_voice_quote_after": override[:200],
                            "quote_source": "cleaned_span",
                            "action_type": action_result.get("action_type"),
                            "planner_actions": action_result.get("planner_actions") or [],
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            return override, "cleaned_span"
    # Single-action turn (or no override) — keep legacy behavior.
    try:
        if isinstance(action_result, dict) and action_result.get("action_type") == "multi_action":
            # Multi-action but the executor didn't attach an override —
            # log so we can spot regressions where a new multi-action
            # path forgets to compute voice_quote_override.
            print(
                "[work_mode_voice_quote_decision] "
                + json.dumps(
                    {
                        "work_mode_voice_quote_before": raw[:200],
                        "work_mode_voice_quote_after": raw[:200],
                        "quote_source": "raw_transcript_multi_action_missing_override",
                        "action_type": "multi_action",
                        "planner_actions": action_result.get("planner_actions") or [],
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass
    return raw, quote_source


async def iter_infer_tts_ndjson_stream(
    *,
    infer_t0: float,
    session_id: str,
    transcript: str,
    reply: str,
    client: str,
    action_result,
    t_pre_asr: float,
    t_asr_lock: float,
    t_asr_transcribe: float,
    t_asr_lock_end: float,
    t_llm_start: float,
    t_llm_end: float,
    t_llm_reported: float,
    work_mode_timer: dict | None = None,
    work_mode_voice_brief_completion: bool = False,
) -> AsyncIterator[str]:
    """NDJSON: meta → chunk lines → done (full infer latency)."""
    if not reply or not str(reply).strip():
        reply = EMPTY_REPLY_FALLBACK

    t_bridge = t_llm_start - t_asr_lock_end
    t_llm_wall = t_llm_end - t_llm_start
    segs = _segments_for_tts(reply)
    request_id = _current_request_id_var.get() or None
    action_payloads = []
    planner_actions = []
    if isinstance(action_result, dict):
        action_payloads = action_result.get("ui_payloads") or []
        planner_actions = action_result.get("planner_actions") or []
    checklist_items_count = 0
    music_payload_present = False
    if isinstance(action_payloads, list):
        for _p in action_payloads:
            if not isinstance(_p, dict):
                continue
            if _p.get("panel_type") == "checklist_control":
                checklist_items_count += len(_p.get("items") or [])
            if _p.get("panel_type") == "music_control":
                music_payload_present = True

    meta = {
        "type": "meta",
        "reply": reply,
        "session_id": session_id,
        "client": client,
        "request_id": request_id,
        "tts_segment_count": len(segs),
        "action_payload": action_result.get("ui_payload") if action_result else None,
        "action_type": action_result.get("action_type") if action_result else None,
    }
    if action_payloads:
        meta["action_payloads"] = action_payloads
    if planner_actions:
        meta["planner_actions"] = planner_actions
    try:
        print(
            "[ndjson_payloads] "
            + json.dumps(
                {
                    "endpoint": "/infer",
                    "event": "meta",
                    "request_id": request_id,
                    "ndjson_meta_action_payloads_count": len(action_payloads),
                    "ndjson_done_action_payloads_count": None,
                    "planner_actions": planner_actions,
                    "checklist_items_count": checklist_items_count,
                    "music_payload_present": music_payload_present,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    if not work_mode_voice_brief_completion:
        meta["transcript"] = transcript
    else:
        meta["work_mode_voice_brief_completion"] = True
        _vq, _vq_src = _compute_work_mode_voice_quote(transcript, action_result)
        meta["work_mode_voice_quote"] = _vq
        meta["work_mode_voice_quote_source"] = _vq_src
    if work_mode_timer is not None:
        meta["work_mode_timer"] = work_mode_timer
    yield json.dumps(meta, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)

    t_tts_start = perf_counter()
    t_post_llm = t_tts_start - t_llm_end
    audio_urls: list[str] = []
    first_chunk_ts: float | None = None

    async for line in iter_tts_chunk_ndjson_lines(session_id, reply, client):
        if first_chunk_ts is None:
            first_chunk_ts = perf_counter() - t_tts_start
        yield line
        obj = json.loads(line.strip())
        if obj.get("type") == "chunk" and obj.get("url"):
            audio_urls.append(obj["url"])

    t_tts = perf_counter() - t_tts_start
    t_total = perf_counter() - infer_t0

    _print_infer_latency_breakdown(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
    )
    print(
        f"[LATENCY_DETAIL] process_user_input internal t_llm={t_llm_reported:.3f}s "
        f"(subset of LLM column when paths return partial timings)"
    )

    latency_payload = _infer_latency_json(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
        llm_internal_reported=t_llm_reported,
    )
    if first_chunk_ts is not None:
        latency_payload["tts_first_chunk_s"] = round(first_chunk_ts, 4)

    done = {
        "type": "done",
        "reply": reply,
        "request_id": request_id,
        "audio_url": audio_urls[0] if audio_urls else "",
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "latency": latency_payload,
    }
    if not work_mode_voice_brief_completion:
        done["transcript"] = transcript
    else:
        done["work_mode_voice_brief_completion"] = True
        _vq, _vq_src = _compute_work_mode_voice_quote(transcript, action_result)
        done["work_mode_voice_quote"] = _vq
        done["work_mode_voice_quote_source"] = _vq_src
    if work_mode_timer is not None:
        done["work_mode_timer"] = work_mode_timer
    if action_result is not None:
        _ap = action_result.get("ui_payload")
        _at = action_result.get("action_type")
        if _ap is not None:
            done["action_payload"] = _ap
        if _at is not None:
            done["action_type"] = _at
        # Multi-action planner pass-through (typed-text only this turn).
        _aps = action_result.get("ui_payloads")
        if _aps:
            done["action_payloads"] = _aps
        _pa = action_result.get("planner_actions")
        if _pa:
            done["planner_actions"] = _pa
    try:
        print(
            "[ndjson_payloads] "
            + json.dumps(
                {
                    "endpoint": "/infer",
                    "event": "done",
                    "request_id": request_id,
                    "ndjson_meta_action_payloads_count": len(action_payloads),
                    "ndjson_done_action_payloads_count": len(action_payloads),
                    "planner_actions": planner_actions,
                    "checklist_items_count": checklist_items_count,
                    "music_payload_present": music_payload_present,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    yield json.dumps(done, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)


async def iter_text_tts_ndjson_stream(
    *,
    t_start: float,
    session_id: str,
    user_text: str,
    reply: str,
    client: str,
    action_result,
    t_llm_end: float,
    t_llm_wall: float,
    work_mode_timer: dict | None = None,
) -> AsyncIterator[str]:
    """NDJSON: meta → chunk lines → done (text path latency)."""
    if not reply or not str(reply).strip():
        reply = EMPTY_REPLY_FALLBACK

    segs = _segments_for_tts(reply)
    meta = {
        "type": "meta",
        "user_text": user_text,
        "reply": reply,
        "session_id": session_id,
        "client": client,
        "tts_segment_count": len(segs),
        "action_payload": action_result.get("ui_payload") if action_result else None,
        "action_type": action_result.get("action_type") if action_result else None,
    }
    if work_mode_timer is not None:
        meta["work_mode_timer"] = work_mode_timer
    yield json.dumps(meta, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)

    t_tts_start = perf_counter()
    t_post_llm = t_tts_start - t_llm_end
    audio_urls: list[str] = []
    first_chunk_ts: float | None = None

    async for line in iter_tts_chunk_ndjson_lines(session_id, reply, client):
        if first_chunk_ts is None:
            first_chunk_ts = perf_counter() - t_tts_start
        yield line
        obj = json.loads(line.strip())
        if obj.get("type") == "chunk" and obj.get("url"):
            audio_urls.append(obj["url"])

    t_tts = perf_counter() - t_tts_start
    t_total = perf_counter() - t_start

    print(
        "[LATENCY][TEXT] "
        f"LLM={t_llm_wall:.3f}s TTS={t_tts:.3f}s TOTAL={t_total:.3f}s"
    )

    latency = {
        "total_s": round(t_total, 4),
        "llm_s": round(t_llm_wall, 4),
        "post_llm_s": round(t_post_llm, 4),
        "tts_s": round(t_tts, 4),
        "short_circuit": "text",
    }
    if first_chunk_ts is not None:
        latency["tts_first_chunk_s"] = round(first_chunk_ts, 4)

    done = {
        "type": "done",
        "reply": reply,
        "audio_url": audio_urls[0] if audio_urls else "",
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "latency": latency,
    }
    if work_mode_timer is not None:
        done["work_mode_timer"] = work_mode_timer
    if action_result is not None:
        _ap = action_result.get("ui_payload")
        _at = action_result.get("action_type")
        if _ap is not None:
            done["action_payload"] = _ap
        if _at is not None:
            done["action_type"] = _at
        # Multi-action planner pass-through (typed-text only this turn).
        _aps = action_result.get("ui_payloads")
        if _aps:
            done["action_payloads"] = _aps
        _pa = action_result.get("planner_actions")
        if _pa:
            done["planner_actions"] = _pa
    yield json.dumps(done, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)


async def _pump_llm_segments_to_queue(
    messages: list[dict],
    segment_queue: asyncio.Queue,
    out_state: dict,
) -> None:
    """
    Consume the LLM token stream and push complete sentence segments onto segment_queue.
    Ends with None sentinel. LLM keeps running while TTS works in parallel (do not await TTS here).

    out_state keys set: reply_accum (str), t_llm_first_token_ts (float | None), t_llm_end (float | None).
    """
    buffer = ""
    out_state["reply_accum"] = ""
    out_state["t_llm_first_token_ts"] = None
    out_state["t_llm_end"] = None
    try:
        async for delta in vera.async_generate_stream(messages):
            if out_state["t_llm_first_token_ts"] is None:
                out_state["t_llm_first_token_ts"] = perf_counter()
            out_state["reply_accum"] += delta
            buffer += delta
            while True:
                popped, buffer = pop_first_complete_segment(buffer)
                if not popped:
                    break
                await segment_queue.put(popped)
        out_state["t_llm_end"] = perf_counter()
        if buffer.strip():
            await segment_queue.put(buffer.strip())
    finally:
        await segment_queue.put(None)


async def iter_infer_tts_ndjson_stream_llm_stream(
    *,
    infer_t0: float,
    session_id: str,
    transcript: str,
    client: str,
    t_pre_asr: float,
    t_asr_lock: float,
    t_asr_transcribe: float,
    t_asr_lock_end: float,
    t_llm_start: float,
    t_bridge: float,
    history: list[dict],
    messages_override: list[dict] | None = None,
    meta_action_type: str | None = None,
    meta_action_payload: dict | None = None,
    finalize_action_result: Callable[[str], dict] | None = None,
    reasoning_voice_coach: str | None = None,
    reasoning_attachment_context: str | None = None,
    client_context_snapshot: dict | None = None,
    thread_follow_up_anchor: str | None = None,
    work_mode_reasoning_context: dict | None = None,
    work_mode_voice_brief_completion: bool = False,
    work_mode_stage2_also_prefix: bool = False,
    work_mode_strict_lane_context: bool = False,
    work_mode_stage2_turn: dict | None = None,
    work_mode_stage2_spoken_override: str | None = None,
) -> AsyncIterator[str]:
    """
    NDJSON: meta (reply empty until done) → TTS chunk lines as each sentence is ready
    while the LLM streams; then done. Pipelines first-sentence TTS with later LLM tokens.
    """
    _cap_action, _cap_feature = _credit_action_for_streaming_meta(meta_action_type)
    if messages_override is None:
        _cap_action = "voice_assistant"
        _cap_feature = None
    try:
        _enforce_usage_credit_cap(
            _cap_action,
            session_id=session_id,
            feature_type=_cap_feature,
        )
    except HTTPException:
        raise
    lane_dbg: dict = {}
    if messages_override is not None:
        messages = list(messages_override)
        messages, lane_dbg = _inject_client_context_snapshot(
            messages,
            client_context_snapshot,
            transcript,
            work_mode_reasoning_context,
            strict_lane_handoff=work_mode_strict_lane_context,
        )
        messages = _inject_thread_follow_up_anchor(messages, thread_follow_up_anchor, transcript)
        messages = _inject_reasoning_voice_coach(
            messages, reasoning_voice_coach, transcript, client_context_snapshot
        )
        messages = _inject_reasoning_attachment_context(messages, reasoning_attachment_context, transcript)
        messages = _inject_work_mode_reasoning_handoff(messages, work_mode_reasoning_context, transcript)
        messages = _inject_work_mode_voice_brief_completion_rules(
            messages,
            work_mode_voice_brief_completion,
            transcript,
            stage2_also_prefix=work_mode_stage2_also_prefix,
            stage2_turn=work_mode_stage2_turn,
        )
        messages = inject_recent_action_context(messages, session_id, transcript)
    else:
        # 2026-06-01 identity-leak patch: see run_general_llm above for why
        # we pass session_active_user_info explicitly.
        messages = vera.build_messages(
            [] if work_mode_voice_brief_completion else history,
            transcript,
            session_active_user_info=_session_active_user_info_for_prompt(session_id),
        )
        messages, lane_dbg = _inject_client_context_snapshot(
            messages,
            client_context_snapshot,
            transcript,
            work_mode_reasoning_context,
            strict_lane_handoff=work_mode_strict_lane_context,
        )
        messages = _inject_thread_follow_up_anchor(messages, thread_follow_up_anchor, transcript)
        messages = _inject_reasoning_voice_coach(
            messages, reasoning_voice_coach, transcript, client_context_snapshot
        )
        messages = _inject_reasoning_attachment_context(messages, reasoning_attachment_context, transcript)
        messages = _inject_work_mode_reasoning_handoff(messages, work_mode_reasoning_context, transcript)
        messages = _inject_work_mode_voice_brief_completion_rules(
            messages,
            work_mode_voice_brief_completion,
            transcript,
            stage2_also_prefix=work_mode_stage2_also_prefix,
            stage2_turn=work_mode_stage2_turn,
        )
        messages = inject_recent_action_context(messages, session_id, transcript)
    messages = _inject_supabase_account_context(messages)

    meta = {
        "type": "meta",
        "reply": "",
        "session_id": session_id,
        "client": client,
        "tts_segment_count": 0,
        "action_payload": meta_action_payload,
        "action_type": meta_action_type,
        "llm_streaming": True,
    }
    if lane_dbg:
        meta["work_mode_lane_debug"] = lane_dbg
    if not work_mode_voice_brief_completion:
        meta["transcript"] = transcript
    else:
        meta["work_mode_voice_brief_completion"] = True
        # The streaming-LLM variant only has meta_action_payload /
        # meta_action_type at meta time. Synthesize a minimal action_result
        # so the multi-action voice-quote override (when present) wins.
        _meta_ar_stub = {
            "action_type": meta_action_type,
            "ui_payload": meta_action_payload,
        }
        _vq, _vq_src = _compute_work_mode_voice_quote(transcript, _meta_ar_stub)
        meta["work_mode_voice_quote"] = _vq
        meta["work_mode_voice_quote_source"] = _vq_src
    yield json.dumps(meta, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)

    tts_dir = user_tts_dir(session_id)
    use_bmo_fish = (client or "vera").strip().lower() == "bmo" and bmo_fish_configured()
    date_str = today()
    audio_urls: list[str] = []
    chunk_index = 0
    reply_so_far_parts: list[str] = []
    t_tts_start: float | None = None
    first_chunk_ts: float | None = None
    t_first_chunk_emitted: float | None = None
    t_first_tts_segment_done: float | None = None

    # Producer keeps pulling LLM tokens while TTS runs — do not await TTS inside async_generate_stream.
    segment_queue: asyncio.Queue = asyncio.Queue()
    llm_stream_state: dict = {}
    prod_task = asyncio.create_task(_pump_llm_segments_to_queue(messages, segment_queue, llm_stream_state))

    while True:
        popped = await segment_queue.get()
        if popped is None:
            break
        if t_tts_start is None:
            t_tts_start = perf_counter()
        async with _tts_lock_diag(session_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                popped,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        if t_first_tts_segment_done is None:
            t_first_tts_segment_done = perf_counter()
        if first_chunk_ts is None and t_tts_start is not None:
            first_chunk_ts = perf_counter() - t_tts_start
        audio_urls.append(rel)
        reply_so_far_parts.append(popped)
        reply_so_far = _cumulative_reply_display(reply_so_far_parts)
        line = (
            json.dumps(
                {"type": "chunk", "index": chunk_index, "url": rel, "reply_so_far": reply_so_far},
                ensure_ascii=False,
            )
            + "\n"
        )
        chunk_index += 1
        if t_first_chunk_emitted is None:
            t_first_chunk_emitted = perf_counter()
        yield line
        await asyncio.sleep(0)

    await prod_task

    reply_accum = llm_stream_state.get("reply_accum", "")
    t_llm_first_token_ts = llm_stream_state.get("t_llm_first_token_ts")
    t_llm_end = llm_stream_state.get("t_llm_end") or perf_counter()
    t_llm_wall = t_llm_end - t_llm_start
    t_llm_reported = t_llm_wall

    full_reply = reply_accum.strip() or EMPTY_REPLY_FALLBACK
    override = (work_mode_stage2_spoken_override or "").strip()
    if (
        work_mode_voice_brief_completion
        and override
        and _stage2_status_scope_matches(work_mode_stage2_turn, work_mode_reasoning_context)
    ):
        full_reply = override
    if work_mode_voice_brief_completion:
        _log_stage2_voice_generation(
            transcript=transcript,
            reply=full_reply,
            wm_ctx=work_mode_reasoning_context,
            stage2_turn=work_mode_stage2_turn,
            spoken_override=work_mode_stage2_spoken_override,
        )
    if not audio_urls and full_reply:
        if t_tts_start is None:
            t_tts_start = perf_counter()
        async with _tts_lock_diag(session_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                full_reply,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        if t_first_tts_segment_done is None:
            t_first_tts_segment_done = perf_counter()
        if first_chunk_ts is None and t_tts_start is not None:
            first_chunk_ts = perf_counter() - t_tts_start
        audio_urls.append(rel)
        if t_first_chunk_emitted is None:
            t_first_chunk_emitted = perf_counter()
        yield (
            json.dumps(
                {"type": "chunk", "index": 0, "url": rel, "reply_so_far": full_reply},
                ensure_ascii=False,
            )
            + "\n"
        )
        await asyncio.sleep(0)

    t_tts_wall = t_tts_start if t_tts_start is not None else t_llm_end
    t_tts = perf_counter() - t_tts_wall
    t_post_llm = max(0.0, (t_tts_start or t_llm_end) - t_llm_end)
    t_total = perf_counter() - infer_t0

    llm_first_token_s = (
        (t_llm_first_token_ts - t_llm_start) if t_llm_first_token_ts is not None else None
    )
    llm_first_sentence_ready_s = (
        (t_first_chunk_emitted - t_llm_start) if t_first_chunk_emitted is not None else None
    )

    first_tts_audio_ready_total_s = None
    first_tts_audio_ready_after_pre_asr_s = None
    first_tts_audio_ready_after_asr_end_s = None
    if t_first_tts_segment_done is not None:
        first_tts_audio_ready_total_s = t_first_tts_segment_done - infer_t0
        first_tts_audio_ready_after_pre_asr_s = t_first_tts_segment_done - infer_t0 - t_pre_asr
        first_tts_audio_ready_after_asr_end_s = t_first_tts_segment_done - t_asr_lock_end

    finalized_action: dict | None = None
    if finalize_action_result is not None:
        finalized_action = finalize_action_result(full_reply)

    history.append({"role": "user", "content": transcript})
    history.append({"role": "assistant", "content": full_reply})
    if len(history) > MAX_TURNS * 2:
        history[:] = history[-MAX_TURNS * 2 :]

    _print_infer_latency_breakdown(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
    )
    print(
        f"[LATENCY_DETAIL] stream LLM + sentence TTS t_llm={t_llm_reported:.3f}s "
        f"tts_segments={len(audio_urls)}"
    )
    if llm_first_token_s is not None:
        print(
            f"[LATENCY_DETAIL] LLM first token (TTFT from LLM phase start)={llm_first_token_s:.3f}s | "
            f"first sentence TTS + NDJSON chunk ready={llm_first_sentence_ready_s:.3f}s"
            if llm_first_sentence_ready_s is not None
            else f"[LATENCY_DETAIL] LLM first token (TTFT)={llm_first_token_s:.3f}s"
        )
    if first_tts_audio_ready_total_s is not None:
        print(
            "[LATENCY_DETAIL] first TTS segment file ready (server): "
            f"infer_start→{first_tts_audio_ready_total_s:.3f}s | "
            f"after_PreASR→{first_tts_audio_ready_after_pre_asr_s:.3f}s | "
            f"after_ASR_end→{first_tts_audio_ready_after_asr_end_s:.3f}s"
        )

    latency_payload = _infer_latency_json(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
        llm_internal_reported=t_llm_reported,
        llm_first_token_s=llm_first_token_s,
        llm_first_sentence_ready_s=llm_first_sentence_ready_s,
        first_tts_audio_ready_total_s=first_tts_audio_ready_total_s,
        first_tts_audio_ready_after_pre_asr_s=first_tts_audio_ready_after_pre_asr_s,
        first_tts_audio_ready_after_asr_end_s=first_tts_audio_ready_after_asr_end_s,
    )
    if first_chunk_ts is not None:
        latency_payload["tts_first_chunk_s"] = round(first_chunk_ts, 4)

    done = {
        "type": "done",
        "reply": full_reply,
        "audio_url": audio_urls[0] if audio_urls else "",
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "latency": latency_payload,
    }
    if not work_mode_voice_brief_completion:
        done["transcript"] = transcript
    else:
        done["work_mode_voice_brief_completion"] = True
        _vq, _vq_src = _compute_work_mode_voice_quote(transcript, finalized_action)
        done["work_mode_voice_quote"] = _vq
        done["work_mode_voice_quote_source"] = _vq_src
    done_ap = meta_action_payload
    done_at = meta_action_type
    if isinstance(finalized_action, dict):
        if "ui_payload" in finalized_action:
            done_ap = finalized_action.get("ui_payload")
        if "action_type" in finalized_action:
            done_at = finalized_action.get("action_type")
    if done_ap is not None:
        done["action_payload"] = done_ap
    if done_at is not None:
        done["action_type"] = done_at
    yield json.dumps(done, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)


async def iter_text_tts_ndjson_stream_llm_stream(
    *,
    t_start: float,
    t_llm_start: float,
    session_id: str,
    user_text: str,
    client: str,
    history: list[dict],
    messages_override: list[dict] | None = None,
    meta_action_type: str | None = None,
    meta_action_payload: dict | None = None,
    finalize_action_result: Callable[[str], dict] | None = None,
    reasoning_voice_coach: str | None = None,
    reasoning_attachment_context: str | None = None,
    client_context_snapshot: dict | None = None,
) -> AsyncIterator[str]:
    """Text path: stream LLM → sentence TTS chunks; meta has empty reply until done."""
    _cap_action, _cap_feature = _credit_action_for_streaming_meta(meta_action_type)
    if messages_override is None:
        _cap_action = "voice_assistant"
        _cap_feature = None
    try:
        _enforce_usage_credit_cap(
            _cap_action,
            session_id=session_id,
            feature_type=_cap_feature,
        )
    except HTTPException:
        raise
    if messages_override is not None:
        messages = list(messages_override)
        messages, _lane_dbg = _inject_client_context_snapshot(messages, client_context_snapshot, user_text, None)
        messages = _inject_reasoning_voice_coach(
            messages, reasoning_voice_coach, user_text, client_context_snapshot
        )
        messages = _inject_reasoning_attachment_context(messages, reasoning_attachment_context, user_text)
    else:
        # 2026-06-01 identity-leak patch: see run_general_llm above for why
        # we pass session_active_user_info explicitly.
        messages = vera.build_messages(
            history,
            user_text,
            session_active_user_info=_session_active_user_info_for_prompt(session_id),
        )
        messages, _lane_dbg = _inject_client_context_snapshot(messages, client_context_snapshot, user_text, None)
        messages = _inject_reasoning_voice_coach(
            messages, reasoning_voice_coach, user_text, client_context_snapshot
        )
        messages = _inject_reasoning_attachment_context(messages, reasoning_attachment_context, user_text)
        messages = inject_recent_action_context(messages, session_id, user_text)
    messages = _inject_supabase_account_context(messages)

    meta = {
        "type": "meta",
        "user_text": user_text,
        "reply": "",
        "session_id": session_id,
        "client": client,
        "tts_segment_count": 0,
        "action_payload": meta_action_payload,
        "action_type": meta_action_type,
        "llm_streaming": True,
    }
    yield json.dumps(meta, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)

    tts_dir = user_tts_dir(session_id)
    use_bmo_fish = (client or "vera").strip().lower() == "bmo" and bmo_fish_configured()
    date_str = today()
    audio_urls: list[str] = []
    chunk_index = 0
    reply_so_far_parts: list[str] = []
    t_tts_start: float | None = None
    first_chunk_ts: float | None = None
    t_first_chunk_emitted: float | None = None
    t_first_tts_segment_done: float | None = None

    segment_queue: asyncio.Queue = asyncio.Queue()
    llm_stream_state: dict = {}
    prod_task = asyncio.create_task(_pump_llm_segments_to_queue(messages, segment_queue, llm_stream_state))

    while True:
        popped = await segment_queue.get()
        if popped is None:
            break
        if t_tts_start is None:
            t_tts_start = perf_counter()
        async with _tts_lock_diag(session_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                popped,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        if t_first_tts_segment_done is None:
            t_first_tts_segment_done = perf_counter()
        if first_chunk_ts is None and t_tts_start is not None:
            first_chunk_ts = perf_counter() - t_tts_start
        audio_urls.append(rel)
        reply_so_far_parts.append(popped)
        reply_so_far = _cumulative_reply_display(reply_so_far_parts)
        if t_first_chunk_emitted is None:
            t_first_chunk_emitted = perf_counter()
        yield (
            json.dumps(
                {"type": "chunk", "index": chunk_index, "url": rel, "reply_so_far": reply_so_far},
                ensure_ascii=False,
            )
            + "\n"
        )
        chunk_index += 1
        await asyncio.sleep(0)

    await prod_task

    reply_accum = llm_stream_state.get("reply_accum", "")
    t_llm_first_token_ts = llm_stream_state.get("t_llm_first_token_ts")
    t_llm_end = llm_stream_state.get("t_llm_end") or perf_counter()
    t_llm_wall = t_llm_end - t_llm_start

    full_reply = reply_accum.strip() or EMPTY_REPLY_FALLBACK
    if not audio_urls and full_reply:
        if t_tts_start is None:
            t_tts_start = perf_counter()
        async with _tts_lock_diag(session_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                full_reply,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        if t_first_tts_segment_done is None:
            t_first_tts_segment_done = perf_counter()
        if first_chunk_ts is None and t_tts_start is not None:
            first_chunk_ts = perf_counter() - t_tts_start
        audio_urls.append(rel)
        if t_first_chunk_emitted is None:
            t_first_chunk_emitted = perf_counter()
        yield (
            json.dumps(
                {"type": "chunk", "index": 0, "url": rel, "reply_so_far": full_reply},
                ensure_ascii=False,
            )
            + "\n"
        )
        await asyncio.sleep(0)

    t_tts_wall = t_tts_start if t_tts_start is not None else t_llm_end
    t_tts = perf_counter() - t_tts_wall
    t_post_llm = max(0.0, (t_tts_start or t_llm_end) - t_llm_end)
    t_total = perf_counter() - t_start

    llm_first_token_s = (
        (t_llm_first_token_ts - t_llm_start) if t_llm_first_token_ts is not None else None
    )
    llm_first_sentence_ready_s = (
        (t_first_chunk_emitted - t_llm_start) if t_first_chunk_emitted is not None else None
    )

    first_tts_audio_ready_total_s = None
    if t_first_tts_segment_done is not None:
        first_tts_audio_ready_total_s = t_first_tts_segment_done - t_start

    finalized_action: dict | None = None
    if finalize_action_result is not None:
        finalized_action = finalize_action_result(full_reply)

    history.append({"role": "user", "content": user_text})
    history.append({"role": "assistant", "content": full_reply})
    if len(history) > MAX_TURNS * 2:
        history[:] = history[-MAX_TURNS * 2 :]

    print(
        "[LATENCY][TEXT][stream_llm] "
        f"LLM={t_llm_wall:.3f}s TTS={t_tts:.3f}s TOTAL={t_total:.3f}s segments={len(audio_urls)}"
    )
    if llm_first_token_s is not None:
        if llm_first_sentence_ready_s is not None:
            print(
                f"[LATENCY_DETAIL][TEXT] LLM first token (TTFT)={llm_first_token_s:.3f}s | "
                f"first sentence TTS + NDJSON chunk ready={llm_first_sentence_ready_s:.3f}s"
            )
        else:
            print(f"[LATENCY_DETAIL][TEXT] LLM first token (TTFT)={llm_first_token_s:.3f}s")
    if first_tts_audio_ready_total_s is not None:
        print(
            "[LATENCY_DETAIL][TEXT] first TTS segment file ready (server): "
            f"text_start→{first_tts_audio_ready_total_s:.3f}s"
        )

    latency = {
        "total_s": round(t_total, 4),
        "llm_s": round(t_llm_wall, 4),
        "post_llm_s": round(t_post_llm, 4),
        "tts_s": round(t_tts, 4),
        "short_circuit": "text",
    }
    if first_chunk_ts is not None:
        latency["tts_first_chunk_s"] = round(first_chunk_ts, 4)
    if llm_first_token_s is not None:
        latency["llm_first_token_s"] = round(llm_first_token_s, 4)
    if llm_first_sentence_ready_s is not None:
        latency["llm_first_sentence_ready_s"] = round(llm_first_sentence_ready_s, 4)
    if first_tts_audio_ready_total_s is not None:
        latency["first_tts_audio_ready_total_s"] = round(first_tts_audio_ready_total_s, 4)

    done = {
        "type": "done",
        "reply": full_reply,
        "audio_url": audio_urls[0] if audio_urls else "",
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "latency": latency,
    }
    done_ap = meta_action_payload
    done_at = meta_action_type
    if isinstance(finalized_action, dict):
        if "ui_payload" in finalized_action:
            done_ap = finalized_action.get("ui_payload")
        if "action_type" in finalized_action:
            done_at = finalized_action.get("action_type")
    if done_ap is not None:
        done["action_payload"] = done_ap
    if done_at is not None:
        done["action_type"] = done_at
    yield json.dumps(done, ensure_ascii=False) + "\n"
    await asyncio.sleep(0)


async def synthesize_reply_audio(session_id: str, reply: str, client: str = "vera") -> tuple[str, list[str]]:
    """
    Returns (reply_text, list of /audio/... paths). Multiple paths when sentence chunking is on.
    """
    tts_dir = user_tts_dir(session_id)
    use_bmo_fish = (client or "vera").strip().lower() == "bmo" and bmo_fish_configured()

    if not reply or not str(reply).strip():
        reply = EMPTY_REPLY_FALLBACK

    segments = _segments_for_tts(reply)
    urls: list[str] = []
    date_str = today()

    for seg in segments:
        async with _tts_lock_diag(session_id):
            rel = await asyncio.to_thread(
                _sync_synthesize_segment,
                seg,
                session_id,
                date_str,
                tts_dir,
                use_bmo_fish,
                client,
            )
        urls.append(rel)

    if tts_sentence_chunks_enabled():
        preview = (reply[:120] + "…") if len(reply) > 120 else reply
        print(f"[TTS] sentence chunking: segments={len(urls)} preview={preview!r}")
        if len(urls) == 1:
            print(
                "[TTS] hint: only 1 segment — very long single line with no .?! or blank lines; "
                "or chunking disabled (VERA_TTS_SENTENCE_CHUNKS=0)."
            )

    return reply, urls


async def enrich_work_mode_timer_with_tts(session_id: str, wm: dict | None, client: str) -> None:
    """
    Pre-synthesize the timer alarm line with the same VERA/BMO TTS as normal replies so the client
    can play /audio/... at fire time instead of browser speechSynthesis.
    """
    if not isinstance(wm, dict) or wm.get("cancel") is True:
        return
    msg = str(wm.get("message") or "").strip()
    if not msg:
        return
    try:
        _, urls = await synthesize_reply_audio(session_id, msg, client=client)
        wm["audio_url"] = urls[0] if urls else ""
        wm["audio_urls"] = urls
    except Exception as e:
        print(f"[work_mode_timer] TTS enrich failed (client will use speechSynthesis fallback): {e}")


