@app.post("/command")
async def command(
    session_id: str = Form(...),
    action: str = Form(...)
):
    raise HTTPException(400, "Unknown command")

def _infer_latency_json(
    *,
    pre_asr: float,
    asr_lock: float,
    asr_transcribe: float,
    total: float,
    bridge: float | None = None,
    llm: float | None = None,
    post_llm: float | None = None,
    tts: float | None = None,
    llm_internal_reported: float | None = None,
    short_circuit: str | None = None,
    llm_first_token_s: float | None = None,
    llm_first_sentence_ready_s: float | None = None,
    first_tts_audio_ready_total_s: float | None = None,
    first_tts_audio_ready_after_pre_asr_s: float | None = None,
    first_tts_audio_ready_after_asr_end_s: float | None = None,
) -> dict:
    """Structured timings for `/infer` JSON + browser console (seconds)."""
    out: dict = {
        "pre_asr_s": round(pre_asr, 4),
        "asr_lock_s": round(asr_lock, 4),
        "asr_transcribe_s": round(asr_transcribe, 4),
        "total_s": round(total, 4),
    }
    if short_circuit:
        out["short_circuit"] = short_circuit
    if bridge is not None:
        out["bridge_s"] = round(bridge, 4)
    if llm is not None:
        out["llm_s"] = round(llm, 4)
    if post_llm is not None:
        out["post_llm_s"] = round(post_llm, 4)
    if tts is not None:
        out["tts_s"] = round(tts, 4)
    if llm_internal_reported is not None:
        out["llm_internal_reported_s"] = round(llm_internal_reported, 4)
    if llm_first_token_s is not None:
        out["llm_first_token_s"] = round(llm_first_token_s, 4)
    if llm_first_sentence_ready_s is not None:
        out["llm_first_sentence_ready_s"] = round(llm_first_sentence_ready_s, 4)
    if first_tts_audio_ready_total_s is not None:
        out["first_tts_audio_ready_total_s"] = round(first_tts_audio_ready_total_s, 4)
    if first_tts_audio_ready_after_pre_asr_s is not None:
        out["first_tts_audio_ready_after_pre_asr_s"] = round(
            first_tts_audio_ready_after_pre_asr_s, 4
        )
    if first_tts_audio_ready_after_asr_end_s is not None:
        out["first_tts_audio_ready_after_asr_end_s"] = round(
            first_tts_audio_ready_after_asr_end_s, 4
        )
    if (
        bridge is not None
        and llm is not None
        and post_llm is not None
        and tts is not None
    ):
        summed = pre_asr + asr_lock + bridge + llm + post_llm + tts
        out["sum_segments_s"] = round(summed, 4)
        out["drift_s"] = round(total - summed, 4)
    return out


def _infer_latency_early(infer_t0: float, reason: str) -> dict:
    """Before ASR or no ASR split (e.g. tiny audio, audio gate)."""
    return {
        "short_circuit": reason,
        "total_s": round(perf_counter() - infer_t0, 4),
    }


def _print_infer_latency_breakdown(
    *,
    pre_asr: float,
    asr_lock: float,
    asr_transcribe: float,
    bridge: float,
    llm: float,
    post_llm: float,
    tts: float,
    total: float,
) -> None:
    """Sequential phases should sum to ~TOTAL; drift is unaccounted overhead / timer granularity."""
    summed = pre_asr + asr_lock + bridge + llm + post_llm + tts
    drift = total - summed
    print(
        "[LATENCY] "
        f"PreASR={pre_asr:.3f}s | ASR={asr_lock:.3f}s | Bridge={bridge:.3f}s | "
        f"LLM={llm:.3f}s | PostLLM={post_llm:.3f}s | TTS={tts:.3f}s | "
        f"TOTAL={total:.3f}s | Σ={summed:.3f}s Δ={drift:+.4f}s"
    )
    print(
        f"[LATENCY_DETAIL] ASR transcribe_long only={asr_transcribe:.3f}s "
        f"(rest of ASR lock = gate/mute/prints inside lock)"
    )


def _voice_planner_takeover_decision(
    *,
    is_multi_action: bool,
    validate_ok: bool,
    confidence: float,
    clarification_needed: bool,
    min_confidence: float = 0.6,
    actions_preview: list | None = None,
) -> tuple[bool, str, dict]:
    """Decide whether voice ``/infer`` should hand a preview plan to the
    structured multi-action executor.

    2026-06-13 (item 1): generalized so voice mirrors ``/text``. Previously
    the override used a fragile bucket-specific allowlist
    (``voice_compound_…`` for cross-bucket, ``voice_multi_music_…`` and
    ``voice_multi_info_…`` for two same-bucket families). That blocked valid
    same-bucket compounds on voice (checklist+checklist, panel+panel,
    timer+timer) which then fell to the legacy greedy single-action router
    and dropped the second action.

    The rule is now purely validity-based and matches the downstream gate in
    ``try_execute_planned_actions_for_text``: allow takeover for any plan that
    is multi-action, validates clean, clears the confidence floor, and does
    not need clarification. All other safety gates (``should_trigger_planner``
    and the identity/anonymous/snapshot/interrupt fastpath exclusions) are
    enforced by the caller and are unchanged.

    Returns ``(allowed, reason, diag)``.
    """
    diag = {
        "is_multi_action": bool(is_multi_action),
        "validate_ok": bool(validate_ok),
        "confidence": round(float(confidence or 0.0), 3),
        "min_confidence": float(min_confidence),
        "clarification_needed": bool(clarification_needed),
    }
    if clarification_needed:
        return False, "clarification_needed", diag
    preview = [a for a in (actions_preview or []) if isinstance(a, dict) and a.get("type")]
    if len(preview) == 1 and preview[0].get("type") == "reasoning.request":
        payload = preview[0].get("payload") or {}
        if isinstance(payload, dict) and payload.get("explicit_panel_destination"):
            if not validate_ok:
                return False, "validation_failed", diag
            if float(confidence or 0.0) < float(min_confidence):
                return False, "confidence_below_min", diag
            return True, "voice_single_explicit_panel_reasoning", diag
    if not is_multi_action:
        return False, "not_multi_action", diag
    if not validate_ok:
        return False, "validation_failed", diag
    if float(confidence or 0.0) < float(min_confidence):
        return False, "confidence_below_min", diag
    return True, "voice_multi_action_defer_to_backend_planner", diag


@app.post("/infer")
async def infer(
    request: Request,
    audio: Optional[UploadFile] = File(None),
    context_file: Optional[UploadFile] = File(None),
    context_files: Optional[List[UploadFile]] = File(None),
    session_id: str = Form(...),
    mode: str = Form("continuous"),
    client: str = Form("vera"),
    interrupt_debug: Optional[str] = Form(None),
    stream_tts: str = Form("0"),
    context_snapshot: Optional[str] = Form(None),
    transcript: Optional[str] = Form(None),
    use_browser_asr: str = Form("0"),
    transcribe_only: str = Form("0"),
    # ----- ASR-mode hybrid params (PART 8 of the ASR-mode spec) -----
    # Tells the server which client-side ASR mode emitted this turn.
    asr_mode: Optional[str] = Form(None),
    # When the client decides a Whisper verification pass is warranted, it
    # sets request_whisper_verify=1 AND sends BOTH the browser transcript
    # (transcript=...) and the audio blob (audio=...). The server then runs
    # transcribe_long on the audio, calls choose_best_transcript() against
    # the browser transcript, and routes with the selected transcript.
    request_whisper_verify: str = Form("0"),
    hybrid_browser_transcript: Optional[str] = Form(None),
    asr_finalization_mode: Optional[str] = Form(None),
    asr_finalization_reason: Optional[str] = Form(None),
    reasoning_voice_coach: Optional[str] = Form(None),
    thread_follow_up_anchor: Optional[str] = Form(None),
    work_mode_reasoning_context: Optional[str] = Form(None),
    work_mode_strict_lane_context: Optional[str] = Form(None),
    work_mode_voice_brief_completion: Optional[str] = Form(None),
    work_mode_stage2_also_prefix: Optional[str] = Form(None),
    work_mode_stage2_turn_json: Optional[str] = Form(None),
    work_mode_stage2_spoken_override: Optional[str] = Form(None),
    # ----- 2026-05-29 — multi-action planner gating (typed-only execution) -----
    # The Voice UI keyboard input box submits via /infer (not /text), so the
    # planner gate from /text was unreachable for typed compound commands.
    # The frontend now sends ``input_source`` (preferred) and a bool-ish
    # ``typed`` flag. Both default to None so older clients keep working —
    # in that case we fall back to the existing typed_chat heuristic
    # (no audio + use_browser_asr=0 + transcript present).
    input_source: Optional[str] = Form(None),
    typed: Optional[str] = Form(None),
):
    infer_t0 = perf_counter()
    try:
        from auth.request_auth import auth_bind_diagnostics, bind_request_auth_user

        _bound_user = bind_request_auth_user(request)
        print(
            "[auth_bind] "
            + json.dumps(
                {
                    "route": "/infer",
                    **auth_bind_diagnostics(),
                    "resolved": bool(_bound_user),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception as _auth_bind_err:
        print(f"[auth_bind] /infer bind swallowed: {_auth_bind_err}", flush=True)
    want_stream_tts = str(stream_tts or "").strip().lower() in ("1", "true", "yes", "on")

    is_interrupt = (mode or "").strip().lower() == "interrupt"
    infer_mode = (mode or "").strip().lower()

    session_id = safe_id(session_id)
    # Multi-device-concurrency PART 1: per-request id + structured [REQ start]
    # so a two-device tail of the server log shows two distinct request ids
    # interleaved with their lock waits, ASR results, TTS chunks, etc.
    request_id = _new_request_id()
    _current_request_id_var.set(request_id)
    _req_start_ts = log_req_start(
        route="/infer",
        session_id=session_id,
        request_id=request_id,
        source=(
            "interrupt" if is_interrupt
            else ("typed_chat" if str(use_browser_asr or "").strip().lower() not in ("1","true","yes","on") and not (audio and getattr(audio, 'filename', None)) and (transcript or "").strip()
                  else "voice")
        ),
        mode=infer_mode,
        client=client,
        stream_tts=want_stream_tts,
        use_browser_asr=str(use_browser_asr or "0"),
        asr_mode=asr_mode or "",
    )
    cleanup_sessions()

    if session_id not in user_last_seen and len(user_last_seen) >= MAX_ACTIVE_USERS:
        raise HTTPException(429, "Server at capacity")

    user_last_seen[session_id] = time()
    total_sessions_seen.add(session_id)

    audio_bytes = b""
    if audio is not None:
        audio_bytes = await audio.read()

    _snap_for_mode = None
    _wm_on = False
    try:
        _has_file_attachments = bool(
            context_file
            or (context_files and any(f is not None for f in context_files))
        )
        _snap_for_mode = _normalize_client_context_snapshot(context_snapshot)
        _wm_on = _is_work_mode_snapshot(_snap_for_mode)
        _cost_update_request(
            session_id=session_id,
            mode=("work_mode" if _wm_on else "nonwork_mode"),
            request_type=(
                "interrupt" if is_interrupt
                else "file_image" if _has_file_attachments
                else "voice"
            ),
            extra={"client": client, "infer_mode": infer_mode},
        )
    except Exception as _cl_err:
        print(f"[cost_logger] /infer update_request swallowed: {_cl_err}")

    use_browser = str(use_browser_asr or "").strip().lower() in ("1", "true", "yes", "on")
    client_transcript = (transcript or "").strip() if transcript else ""
    browser_transcript = use_browser and bool(client_transcript)

    # ------------------------------------------------------------------
    # PART 8 of the ASR-mode spec — hybrid Whisper verification path.
    #
    # When asr_mode=hybrid AND the client decided this turn warrants a
    # Whisper pass, the request carries BOTH a browser transcript AND an
    # audio blob, plus request_whisper_verify=1. We force the audio path
    # so transcribe_long runs, then choose_best_transcript() picks the
    # final transcript before routing.
    #
    # We also record the asr_mode + finalization_mode flags so they appear
    # in the post-ASR debug log regardless of the path taken.
    # ------------------------------------------------------------------
    _whisper_verify_requested = (
        str(request_whisper_verify or "").strip().lower() in ("1", "true", "yes", "on")
    )
    _hybrid_browser_text = (hybrid_browser_transcript or "").strip()
    if (
        _whisper_verify_requested
        and (_hybrid_browser_text or client_transcript)
        and len(audio_bytes) >= MIN_AUDIO_BYTES
    ):
        # We have both a browser transcript AND audio AND the client asked
        # for verification. Skip the "browser_transcript fast-path" branch
        # so the existing audio-decode + Whisper block runs. The Whisper
        # transcript will be reconciled against the browser transcript via
        # choose_best_transcript() right after transcribe_long returns.
        if not _hybrid_browser_text:
            _hybrid_browser_text = client_transcript
        browser_transcript = False  # force audio pipeline
        client_transcript = ""      # discard fast-path text; real text comes from selector
    elif _whisper_verify_requested:
        # Client asked for verify but didn't give us workable audio. Log
        # and fall back to the browser transcript.
        log_asr_pipeline_decision({
            "stage": "hybrid_verify_requested_but_audio_missing",
            "asr_mode": asr_mode or "",
            "asr_finalization_mode": asr_finalization_mode or "",
            "asr_finalization_reason": asr_finalization_reason or "",
            "browser_transcript": (_hybrid_browser_text or client_transcript or "")[:200],
            "audio_bytes": len(audio_bytes),
        })

    # Safety: cap typed transcript length here too. Voice ASR transcripts on
    # this endpoint also flow through ``transcript``; we tag the request as
    # ``voice`` when there is no typed-text path so its token cap is lower.
    if client_transcript:
        try:
            _safety_request_type = (
                "reasoning" if _wm_on else
                "command"
            )
            # PTT / typed text fields share /infer; the surrounding work-mode
            # branch already routes long composer text into the reasoning
            # cap. Voice (no use_browser_asr) is handled separately below.
            _block_infer = _safety_check_typed_input(
                client_transcript,
                work_mode=_wm_on,
                request_type=_safety_request_type,
            )
            if _block_infer is not None:
                _safety_log_block(
                    reason=_block_infer["reason"],
                    mode=("work_mode" if _wm_on else "non_work"),
                    feature=("voice" if not browser_transcript else "keyboard"),
                    char_count=_block_infer.get("char_count"),
                    estimated_tokens=_block_infer.get("estimated_tokens"),
                    extra={"endpoint": "/infer", "use_browser_asr": browser_transcript},
                )
                raise HTTPException(413, _block_infer["message"])
        except HTTPException:
            raise
        except Exception as _safe_err:
            print(f"[safety_guard] /infer guard swallowed: {_safe_err}")

    if browser_transcript:
        transcript = client_transcript
        t_pre_asr = perf_counter() - infer_t0
        t_asr_transcribe = 0.0
        t_asr_lock_start = infer_t0
        t_asr_lock = 0.0
        t_asr_lock_end = perf_counter()
        print(
            f"[ASR] browser_client mode={infer_mode} session={session_id} text=\"{transcript}\""
        )
        # PART 16 — single-line structured log for the streaming (browser-
        # immediate) finalization path. Server skipped Whisper because the
        # client either selected Streaming mode or Hybrid->browser_immediate.
        log_asr_pipeline_decision({
            "stage": "browser_immediate",
            "asr_mode": asr_mode or "streaming",
            "hybrid_policy": "selective",
            "asr_finalization_mode": asr_finalization_mode or "browser_immediate",
            "asr_finalization_reason": asr_finalization_reason or "client_streaming_or_hybrid_browser_immediate",
            "browser_final_transcript": (transcript or "")[:200],
            "whisper_transcript": "",
            "whisper_confidence": None,
            "selected_transcript": (transcript or "")[:200],
            "selection_source": "browser_streaming",
            "edit_distance": 0,
            "length_ratio": 0.0,
            "token_overlap": 0.0,
            "selection_reason": "browser_immediate_no_whisper",
            "command_normalization_applied": False,
            "normalized_transcript": (transcript or "")[:200],
            "final_transcript_used_for_routing": (transcript or "")[:200],
            "asr_latency_whisper_ms": 0,
        })
        if is_interrupt and interrupt_debug:
            try:
                dbg = json.loads(interrupt_debug)
                print(f"[INTERRUPT][CLIENT] {json.dumps(dbg, ensure_ascii=False)}")
            except Exception:
                print(f"[INTERRUPT][CLIENT] invalid_json len={len(interrupt_debug)}")

        if (
            infer_mode in ("continuous", "interrupt")
            and transcript
            and is_mute_voice_command(transcript)
        ):
            print(
                f"[INTENT] mute_voice_command mode={infer_mode} session={session_id} "
                f"text={transcript!r} conf=n/a_browser"
            )
            t_short = perf_counter() - infer_t0
            return {
                "client_action": "mute_input",
                "transcript": transcript,
                "latency": _infer_latency_json(
                    pre_asr=t_pre_asr,
                    asr_lock=t_asr_lock,
                    asr_transcribe=t_asr_transcribe,
                    total=t_short,
                    short_circuit="mute",
                ),
            }

        if not transcript:
            if is_interrupt:
                print("[INTERRUPT] skip: empty transcript (browser)")
            return {
                "skip": True,
                "latency": _infer_latency_early(infer_t0, "empty_transcript"),
            }

    elif len(audio_bytes) < MIN_AUDIO_BYTES:
        if is_interrupt:
            print(
                f"[INTERRUPT] skip: bytes={len(audio_bytes)} "
                f"(<{MIN_AUDIO_BYTES}) session={session_id}"
            )
        return {"skip": True, "latency": _infer_latency_early(infer_t0, "bytes_too_small")}

    else:
        try:
            seg = AudioSegment.from_file(io.BytesIO(audio_bytes))
        except Exception:
            raise HTTPException(400, "Invalid audio format")

        seg = seg.set_channels(1).set_frame_rate(TARGET_SR)

        samples = np.array(seg.get_array_of_samples(), dtype=np.float32)
        if seg.sample_width == 2:          # int16
            samples /= 32768.0
        elif seg.sample_width == 4:        # int32
            samples /= 2147483648.0
        # robust normalization (always correct)
        raw = samples.copy()

        raw_rms = np.sqrt(np.mean(raw ** 2))
        zcr = zero_crossing_rate(raw)
        voiced_sec = voiced_duration(raw, TARGET_SR, thresh=0.02)
        spec_ratio = spectral_ratio(raw, TARGET_SR)
        peak_raw = float(np.max(np.abs(raw))) if len(raw) else 0.0
        crest = peak_raw / (raw_rms + 1e-8)
        dur_s = len(raw) / float(TARGET_SR)

        if is_interrupt:
            if interrupt_debug:
                try:
                    dbg = json.loads(interrupt_debug)
                    print(f"[INTERRUPT][CLIENT] {json.dumps(dbg, ensure_ascii=False)}")
                except Exception:
                    print(f"[INTERRUPT][CLIENT] invalid_json len={len(interrupt_debug)}")
            print(
                f"[INTERRUPT][AUDIO] session={session_id} bytes={len(audio_bytes)} "
                f"dur_s={dur_s:.3f} rms={raw_rms:.4f} zcr={zcr:.3f} "
                f"voiced={voiced_sec:.3f}s spec={spec_ratio:.2f} crest={crest:.1f} "
                f"gate: min_rms={MIN_AUDIO_RMS} zcr_range=[{ZCR_MIN},{ZCR_MAX}] "
                f"min_voiced={MIN_VOICED_SECONDS}s"
            )
        else:
            print(
                f"[AUDIO] rms={raw_rms:.4f} "
                f"zcr={zcr:.3f} "
                f"voiced={voiced_sec:.3f}s "
                f"spec={spec_ratio:.2f}"
            )

        if (
            raw_rms < MIN_AUDIO_RMS or
            voiced_sec < MIN_VOICED_SECONDS
        ):
            if is_interrupt:
                print(
                    "[INTERRUPT] dropped: audio_gate "
                    f"(rms_ok={raw_rms >= MIN_AUDIO_RMS} "
                    f"zcr_in_band={ZCR_MIN <= zcr <= ZCR_MAX} (not gated) "
                    f"voiced_ok={voiced_sec >= MIN_VOICED_SECONDS})"
                )
            else:
                print("[AUDIO] Dropped non-headset / noise")
            return {"skip": True, "latency": _infer_latency_early(infer_t0, "audio_gate")}

        # remove DC offset
        samples -= np.mean(samples)

        # normalize AFTER gating
        peak = np.max(np.abs(samples))
        if peak > 0:
            samples /= peak

        # =========================
        # ASR
        # =========================

        t_asr_lock_start = perf_counter()
        t_pre_asr = t_asr_lock_start - infer_t0

        # Multi-device-concurrency PART 1 + PART 9: wrap the global asr_lock
        # with _LockDiag so [ASR lock wait] (wait_ms) and [ASR done] (hold_ms)
        # appear in the log. The lock body only runs the Whisper model + the
        # hybrid post-processing — no I/O, no network — so hold_ms reflects
        # real model serialization cost across devices.
        async with _LockDiag(asr_lock, name="ASR", session_id=session_id, request_id=request_id):
            t_tr0 = perf_counter()
            transcript, confidence = transcribe_long(samples)
            t_asr_transcribe = perf_counter() - t_tr0

            # ----- PART 8 + 9 + 10 — hybrid reconciliation ----------------
            # When the client opted into hybrid verification, reconcile the
            # Whisper transcript against the browser transcript and pick the
            # best one. Then apply conservative VERA-domain command
            # normalization if the result still looks like a command. The
            # selected text becomes the canonical transcript used by all
            # downstream routing (mute detection, action router, LLM, …).
            _asr_select_result = None
            _asr_normalize_result = None
            if _whisper_verify_requested and _hybrid_browser_text:
                _asr_select_result = choose_best_transcript(
                    browser_transcript=_hybrid_browser_text,
                    whisper_transcript=transcript or "",
                    whisper_confidence=confidence,
                )
                _selected = _asr_select_result.get("selected") or ""
                _asr_normalize_result = normalize_command_transcript(_selected)
                transcript = _asr_normalize_result.get("normalized") or _selected
                log_asr_pipeline_decision({
                    "stage": "hybrid_post_whisper",
                    "asr_mode": asr_mode or "hybrid",
                    "hybrid_policy": "selective",
                    "asr_finalization_mode": asr_finalization_mode or "whisper_verify",
                    "asr_finalization_reason": asr_finalization_reason or "",
                    "browser_final_transcript": _hybrid_browser_text[:200],
                    "whisper_transcript": (transcript if not _asr_normalize_result.get("applied") else (_selected or ""))[:200],
                    "whisper_confidence": float(confidence) if confidence is not None else None,
                    "selected_transcript": (_asr_select_result.get("selected") or "")[:200],
                    "selection_source": _asr_select_result.get("source"),
                    "edit_distance": _asr_select_result.get("edit_distance"),
                    "length_ratio": _asr_select_result.get("length_ratio"),
                    "token_overlap": _asr_select_result.get("token_overlap"),
                    "selection_reason": _asr_select_result.get("reason"),
                    "command_normalization_applied": bool(_asr_normalize_result.get("applied")),
                    "normalized_transcript": (_asr_normalize_result.get("normalized") or "")[:200],
                    "final_transcript_used_for_routing": (transcript or "")[:200],
                    "asr_latency_whisper_ms": int(round(t_asr_transcribe * 1000)),
                })

            # Mute intent first: bypass ASR confidence gate and all downstream "thinking".
            if (
                infer_mode in ("continuous", "interrupt")
                and transcript
                and is_mute_voice_command(transcript)
            ):
                print(
                    f"[INTENT] mute_voice_command mode={infer_mode} session={session_id} "
                    f"text={transcript!r} conf={confidence:.3f}"
                )
                t_asr_lock_end = perf_counter()
                t_asr_lock = t_asr_lock_end - t_asr_lock_start
                print(
                    "[LATENCY] short_circuit=mute "
                    f"PreASR={t_pre_asr:.3f}s | ASR={t_asr_lock:.3f}s "
                    f"(transcribe={t_asr_transcribe:.3f}s) | "
                    f"TOTAL={perf_counter() - infer_t0:.3f}s"
                )
                t_short = perf_counter() - infer_t0
                return {
                    "client_action": "mute_input",
                    "transcript": transcript,
                    "latency": _infer_latency_json(
                        pre_asr=t_pre_asr,
                        asr_lock=t_asr_lock,
                        asr_transcribe=t_asr_transcribe,
                        total=t_short,
                        short_circuit="mute",
                    ),
                }

            print(f"[ASR] conf={confidence:.3f} text=\"{transcript}\"")
            if is_interrupt:
                print(
                    f"[INTERRUPT][ASR] session={session_id} conf={confidence:.3f} "
                    f"text={transcript!r}"
                )

            if confidence < -0.5: #(TUNER)
                if is_interrupt:
                    print("[INTERRUPT] skip: low ASR confidence")
                else:
                    print("[ASR] Dropped low-confidence transcription")
                t_asr_lock_end = perf_counter()
                t_asr_lock = t_asr_lock_end - t_asr_lock_start
                print(
                    "[LATENCY] short_circuit=asr_confidence "
                    f"PreASR={t_pre_asr:.3f}s | ASR={t_asr_lock:.3f}s "
                    f"(transcribe={t_asr_transcribe:.3f}s) | "
                    f"TOTAL={perf_counter() - infer_t0:.3f}s"
                )
                t_short = perf_counter() - infer_t0
                return {
                    "skip": True,
                    "latency": _infer_latency_json(
                        pre_asr=t_pre_asr,
                        asr_lock=t_asr_lock,
                        asr_transcribe=t_asr_transcribe,
                        total=t_short,
                        short_circuit="asr_confidence",
                    ),
                }

        t_asr_lock_end = perf_counter()
        t_asr_lock = t_asr_lock_end - t_asr_lock_start

        if not transcript:
            if is_interrupt:
                print("[INTERRUPT] skip: empty transcript")
            print(
                "[LATENCY] short_circuit=empty_transcript "
                f"PreASR={t_pre_asr:.3f}s | ASR={t_asr_lock:.3f}s "
                f"(transcribe={t_asr_transcribe:.3f}s) | "
                f"TOTAL={perf_counter() - infer_t0:.3f}s"
            )
            t_short = perf_counter() - infer_t0
            return {
                "skip": True,
                "latency": _infer_latency_json(
                    pre_asr=t_pre_asr,
                    asr_lock=t_asr_lock,
                    asr_transcribe=t_asr_transcribe,
                    total=t_short,
                    short_circuit="empty_transcript",
                ),
            }

        print(f"[ASR] \"{transcript}\"")

    want_transcribe_preflight = str(transcribe_only or "").strip().lower() in ("1", "true", "yes", "on")
    if want_transcribe_preflight and not is_interrupt:
        t_short = perf_counter() - infer_t0
        return {
            "transcript": transcript,
            "preflight_only": True,
            "latency": _infer_latency_json(
                pre_asr=t_pre_asr,
                asr_lock=t_asr_lock,
                asr_transcribe=t_asr_transcribe,
                total=t_short,
                short_circuit="transcribe_only",
            ),
        }

    # =========================
    # COMMAND HANDLING
    # =========================

    history = user_histories[session_id]
    t_llm_start = perf_counter()
    t_bridge = t_llm_start - t_asr_lock_end
    coach_imp = (reasoning_voice_coach or "").strip() or None
    anchor_imp = (thread_follow_up_anchor or "").strip() or None
    client_context = _normalize_client_context_snapshot(context_snapshot)
    if client_context:
        latest_client_context_snapshot[session_id] = client_context
    else:
        client_context = latest_client_context_snapshot.get(session_id)
    coach_reply = _normalize_reasoning_voice_reply(coach_imp, client_context)
    try:
        from auth.request_auth import auth_bind_diagnostics, bind_request_auth_user

        _bound_user = bind_request_auth_user(request)
        print(
            "[auth_bind] "
            + json.dumps(
                {
                    "route": "/infer",
                    "phase": "pre_identity",
                    **auth_bind_diagnostics(),
                    "resolved": bool(_bound_user),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception as _auth_rebind_err:
        print(f"[auth_bind] /infer pre_identity rebind swallowed: {_auth_rebind_err}", flush=True)
    memory_reply = None
    try:
        from auth.memory_commands import try_explicit_memory_fastpath
        from auth.request_auth import get_bound_auth_user

        memory_reply = try_explicit_memory_fastpath(
            transcript, session_id, user_histories.get(session_id)
        )
        if get_bound_auth_user() is None:
            _extract_and_store_session_user_facts(session_id, transcript)
    except Exception as _mem_fp_err:
        memory_reply = None
        print(f"[explicit_memory] fastpath swallowed: {_mem_fp_err}")
        try:
            from auth.request_auth import get_bound_auth_user

            if get_bound_auth_user() is None:
                _extract_and_store_session_user_facts(session_id, transcript)
        except Exception:
            _extract_and_store_session_user_facts(session_id, transcript)
    # 2026-06-01 identity-leak patch: catch identity-challenge questions
    # ("how do you know my name is Nam?", "what's my name?", "am I Nam?")
    # BEFORE the general LLM, so the model never gets a chance to claim
    # "you told me earlier" from creator/admin/demo context.
    identity_reply = _identity_challenge_fastpath_reply(
        transcript, session_id, history=user_histories.get(session_id)
    ) or _creator_question_fastpath_reply(transcript)
    anonymous_reply = _anonymous_user_fastpath_reply(
        transcript, session_id, history=user_histories.get(session_id)
    )
    snapshot_reply = _snapshot_fastpath_reply(transcript, client_context)

    # 2026-05-29 — multi-action planner gate (typed /infer only).
    #
    # The Voice UI keyboard input box submits typed text through /infer
    # (not /text), so /text's planner gate was unreachable for typed
    # compound commands. We now run the same `try_execute_planned_actions_for_text`
    # gate here when the request is clearly a keyboard submit.
    #
    # input_source classification (preferred):
    #   "keyboard"      → planner execution ALLOWED
    #   "voice" | "ptt" | "continuous" | "interruption"
    #                    → SHADOW ONLY (process_user_input will still log
    #                      a [planner] line; greedy router stays in charge)
    #
    # Legacy clients that don't send input_source fall back to the existing
    # typed_chat heuristic (no audio AND use_browser_asr off AND transcript
    # present AND not an interrupt) — same shape the /infer source label
    # already computes above.
    _input_source_lower = (input_source or "").strip().lower()
    _typed_flag = str(typed or "").strip().lower() in ("1", "true", "yes", "on")
    if _input_source_lower in ("keyboard", "typed", "text"):
        is_keyboard_input = True
    elif _input_source_lower in ("voice", "mic", "ptt", "continuous", "interruption", "interrupt"):
        is_keyboard_input = False
    elif _typed_flag:
        is_keyboard_input = True
    else:
        # Legacy heuristic: only treat as typed when ALL signals agree.
        is_keyboard_input = (
            not is_interrupt
            and str(use_browser_asr or "").strip().lower() not in ("1", "true", "yes", "on")
            and not (audio and getattr(audio, "filename", None))
            and bool((transcript or "").strip())
        )
    _planner_gate_transcript = (transcript or "").strip()
    _planner_gate_mp = _load_multi_action_planner()
    _should_trigger_planner_result = False
    _planner_trigger_reason = "planner_unavailable"
    if _planner_gate_mp is not None and _planner_gate_transcript:
        try:
            _should_trigger_planner_result, _planner_trigger_reason = (
                _planner_gate_mp.should_trigger_planner(_planner_gate_transcript)
            )
        except Exception as _stp_exc:
            _should_trigger_planner_result = False
            _planner_trigger_reason = f"should_trigger_error:{type(_stp_exc).__name__}"

    # 2026-05-29 spec PART 4 / 2026-06-13 item 1 — extend the planner gate to
    # fire for voice input on ANY valid multi-action plan. The frontend voice
    # preflight skips the legacy frontend planner for compound transcripts and
    # forwards them unchanged to /infer — so /infer is the only remaining shot
    # at planning them. We keep non-compound voice on the legacy single-action
    # router so existing voice routing stays intact.
    #
    # The override decision is now purely validity-based (is_multi_action +
    # validate_plan.ok + confidence >= floor + no clarification), mirroring
    # ``try_execute_planned_actions_for_text``. This replaces the previous
    # bucket-specific allowlist (cross-bucket-only, plus same-bucket music/info
    # special cases) which silently blocked valid same-bucket compounds like
    # "remove the first item and mark the second complete" (checklist+checklist),
    # "open a new panel and switch to panel 2" (panel+panel), and
    # "start a 10 minute timer and then a 5 minute timer" (timer+timer).
    _voice_compound_override = False
    if (
        not is_keyboard_input
        and _should_trigger_planner_result
        and not is_interrupt
        and _planner_gate_transcript
        and _planner_gate_mp is not None
    ):
        try:
            _voice_plan_preview = _planner_gate_mp.plan_user_actions(
                _planner_gate_transcript, vera=None
            )
            _voice_actions_preview = [
                a for a in (_voice_plan_preview.get("actions") or []) if a.get("type")
            ]
            _voice_is_multi = bool(_voice_plan_preview.get("is_multi_action"))
            _voice_clarify = bool(_voice_plan_preview.get("clarification_needed"))
            try:
                _voice_validate_ok, _voice_validate_errs, _ = _planner_gate_mp.validate_plan(
                    _voice_plan_preview
                )
            except Exception:
                _voice_validate_ok, _voice_validate_errs = False, ["validate_exception"]
            _voice_confidence = 0.0
            if _voice_actions_preview:
                _voice_confidence = sum(
                    float(a.get("confidence") or 0.0) for a in _voice_actions_preview
                ) / max(1, len(_voice_actions_preview))
            _voice_allowed, _override_reason, _override_diag = (
                _voice_planner_takeover_decision(
                    is_multi_action=_voice_is_multi,
                    validate_ok=bool(_voice_validate_ok),
                    confidence=_voice_confidence,
                    clarification_needed=_voice_clarify,
                    actions_preview=_voice_actions_preview,
                )
            )
            _voice_compound_override = bool(_voice_allowed)
            try:
                print(
                    "[route_decision] "
                    + json.dumps(
                        {
                            "route": "multi_action" if _voice_compound_override else "legacy_router",
                            "reason": _override_reason if _voice_compound_override else "voice_planner_takeover_denied",
                            "transcript_preview": _planner_gate_transcript[:200],
                            "action_types": [a.get("type") for a in _voice_actions_preview],
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
                print(
                    "[planner_gate_voice_compound_override] "
                    + json.dumps(
                        {
                            "transcript_preview": _planner_gate_transcript[:200],
                            "voice_takeover_allowed": _voice_compound_override,
                            "planner_action_types": [
                                a.get("type") for a in _voice_actions_preview
                            ],
                            "validation_errors": list(_voice_validate_errs or []),
                            **_override_diag,
                            "reason": _override_reason,
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
        except Exception:
            _voice_compound_override = False

    planner_execution_allowed = bool(is_keyboard_input or _voice_compound_override)
    _planner_gate_called = bool(
        planner_execution_allowed
        and _planner_gate_transcript
        and not identity_reply
        and not memory_reply
        and not anonymous_reply
        and not snapshot_reply
        and not is_interrupt
    )
    _planner_disabled_reasons: list[str] = []
    if not planner_execution_allowed:
        _planner_disabled_reasons.append("planner_execution_not_allowed")
    if not _planner_gate_transcript:
        _planner_disabled_reasons.append("empty_transcript")
    if identity_reply:
        _planner_disabled_reasons.append("identity_fastpath")
    if memory_reply:
        _planner_disabled_reasons.append("memory_fastpath")
    if anonymous_reply:
        _planner_disabled_reasons.append("anonymous_fastpath")
    if snapshot_reply:
        _planner_disabled_reasons.append("snapshot_fastpath")
    if is_interrupt:
        _planner_disabled_reasons.append("interrupt_turn")
    _planner_reason_disabled = ",".join(_planner_disabled_reasons) or ""

    planner_executed_infer: tuple[str, float, dict | None] | None = None
    if (
        _planner_gate_called
    ):
        try:
            planner_executed_infer = try_execute_planned_actions_for_text(
                text=transcript,
                session_id=session_id,
                history=history,
                client_context_snapshot=client_context,
            )
        except Exception as _plan_exc:
            print(f"[planner] /infer execution swallowed: {_plan_exc}")
            planner_executed_infer = None
    # Structured [planner_gate] line — single grep tag for every /infer turn
    # the gate considered. ``planner_gate_called`` reports whether the gate
    # actually ran the planner; ``greedy_router_skipped`` is True iff the
    # gate decided to take over execution (so the legacy single-action
    # routers below are bypassed).
    try:
        _pe = planner_executed_infer
        _pe_action_result = _pe[2] if _pe else None
        _pe_payloads = (
            _pe_action_result.get("ui_payloads")
            if isinstance(_pe_action_result, dict)
            else None
        ) or []
        _pe_actions = (
            _pe_action_result.get("planner_actions")
            if isinstance(_pe_action_result, dict)
            else None
        ) or []
        print(
            "[planner_gate] "
            + json.dumps(
                {
                    "endpoint": "/infer",
                    "input_source": _input_source_lower or "unknown",
                    "typed": _typed_flag,
                    "planner_execution_allowed": planner_execution_allowed,
                    "planner_gate_called": _planner_gate_called,
                    "should_trigger_planner_result": bool(_should_trigger_planner_result),
                    "planner_trigger_reason": _planner_trigger_reason,
                    "plan_is_multi_action": bool(_pe_actions and len(_pe_actions) > 1),
                    "validation_ok": _pe is not None,
                    "planner_executed": planner_executed_infer is not None,
                    "planner_confidence": None,  # confidence is per-action; aggregated avg is in [planner]
                    "clarification_needed": (
                        isinstance(_pe_action_result, dict)
                        and _pe_action_result.get("action_type") == "clarification"
                    ),
                    "greedy_router_skipped": planner_executed_infer is not None,
                    "fallback_router_used": False,
                    "fallback_action_type": "",
                    "reason_disabled": _planner_reason_disabled,
                    "action_payloads_count": len(_pe_payloads),
                    "request_id": request_id,
                    "transcript_len": len((transcript or "").strip()),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    work_mode_intent = _work_mode_toggle_intent(transcript, client, client_context)
    checklist_action_name = None
    if planner_executed_infer is None:
        checklist_action_name = is_checklist_action_request(transcript)
    if not checklist_action_name:
        checklist_action_name = peek_checklist_undo_action_name(
            session_id, transcript, client_context
        )
    try:
        fallback_action_type = ""
        fallback_router_used = False
        if planner_executed_infer is None:
            fallback_action_type = (
                checklist_action_name
                or ((work_mode_intent or {}).get("action") if isinstance(work_mode_intent, dict) else "")
                or ""
            )
            fallback_router_used = bool(fallback_action_type)
        print(
            "[planner_route] "
            + json.dumps(
                {
                    "endpoint": "/infer",
                    "input_source": _input_source_lower or "unknown",
                    "typed": _typed_flag,
                    "planner_gate_called": _planner_gate_called,
                    "should_trigger_planner_result": bool(_should_trigger_planner_result),
                    "planner_trigger_reason": _planner_trigger_reason,
                    "planner_executed": planner_executed_infer is not None,
                    "greedy_router_skipped": planner_executed_infer is not None,
                    "fallback_router_used": fallback_router_used,
                    "fallback_action_type": fallback_action_type,
                    "reason_disabled": _planner_reason_disabled,
                    "request_id": request_id,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
        has_connector = bool(re.search(r"\b(?:and|then|also|plus)\b", _planner_gate_transcript, re.IGNORECASE))
        if has_connector and not planner_execution_allowed:
            print(
                "[planner_bypass_warning] "
                + json.dumps(
                    {
                        "transcript": _planner_gate_transcript[:240],
                        "input_source": _input_source_lower or "unknown",
                        "typed": _typed_flag,
                        "use_browser_asr": str(use_browser_asr or ""),
                        "endpoint": "/infer",
                        "planner_execution_allowed": planner_execution_allowed,
                        "reason_disabled": _planner_reason_disabled,
                        "would_trigger_planner": bool(_should_trigger_planner_result),
                        "planner_trigger_reason": _planner_trigger_reason,
                        "greedy_router_selected": fallback_action_type,
                        "request_id": request_id,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass

    # ------------------------------------------------------------------
    # 2026-05-29 LIVE-TRACE DIAGNOSTIC (no behavior change).
    # Single grep tag ``[planner_live_trace]`` (stage="gate") that
    # combines the gate-time state with the planner gate's own diag
    # contextvar so an operator can answer all 10 investigation
    # questions from one log line.
    # ------------------------------------------------------------------
    try:
        _gate_diag = _planner_last_gate_diag_var.get() or {}
        _client_app_version = ""
        try:
            _client_app_version = str(
                (client_context or {}).get("app_js_version")
                or (client_context or {}).get("client_app_version")
                or ""
            )[:24]
        except Exception:
            _client_app_version = ""
        print(
            "[planner_live_trace] "
            + json.dumps(
                {
                    "stage": "gate",
                    "endpoint": "/infer",
                    "request_id": request_id,
                    "transcript": _planner_gate_transcript[:240],
                    "input_source": _input_source_lower or "unknown",
                    "typed": _typed_flag,
                    "use_browser_asr": str(use_browser_asr or ""),
                    "client_app_version": _client_app_version,
                    "planner_module_path": getattr(_planner_gate_mp, "__file__", "") or "",
                    "planner_execution_allowed": planner_execution_allowed,
                    "should_trigger_planner_result": bool(_should_trigger_planner_result),
                    "planner_trigger_reason": _planner_trigger_reason,
                    "planner_gate_called": _planner_gate_called,
                    "planner_executed": planner_executed_infer is not None,
                    "planner_returned_none_reason": _gate_diag.get(
                        "planner_returned_none_reason", ""
                    ),
                    "planner_validation_ok": _gate_diag.get("validation_ok", None),
                    "planner_validation_errors": _gate_diag.get("validation_errors", []),
                    "planner_confidence": _gate_diag.get("confidence", None),
                    "planner_json": _gate_diag.get("planner_json", {}),
                    "deterministic_action_types": _gate_diag.get(
                        "deterministic_action_types", []
                    ),
                    "deterministic_is_multi_action": _gate_diag.get(
                        "deterministic_is_multi_action", None
                    ),
                    "chosen_action_types": _gate_diag.get("chosen_action_types", []),
                    "chosen_is_multi_action": _gate_diag.get(
                        "chosen_is_multi_action", None
                    ),
                    "plan_source": _gate_diag.get("plan_source", ""),
                    "llm_plan_chosen": _gate_diag.get("llm_plan_chosen", None),
                    "deterministic_only_families": _gate_diag.get(
                        "deterministic_only_families", []
                    ),
                    "chosen_only_families": _gate_diag.get(
                        "chosen_only_families", []
                    ),
                    "reason_disabled": _planner_reason_disabled,
                },
                ensure_ascii=False,
            ),
            flush=True,
        )

        # Hard mismatch — the heuristic gate said this looks compound but
        # we returned a non-multi-action turn. Surfaces both bypass and
        # planner-rejected-its-own-plan cases.
        if _should_trigger_planner_result and planner_executed_infer is None:
            print(
                "[planner_live_mismatch_error] "
                + json.dumps(
                    {
                        "endpoint": "/infer",
                        "request_id": request_id,
                        "transcript": _planner_gate_transcript[:240],
                        "input_source": _input_source_lower or "unknown",
                        "typed": _typed_flag,
                        "planner_execution_allowed": planner_execution_allowed,
                        "planner_gate_called": _planner_gate_called,
                        "planner_returned_none_reason": _gate_diag.get(
                            "planner_returned_none_reason", ""
                        ),
                        "deterministic_action_types": _gate_diag.get(
                            "deterministic_action_types", []
                        ),
                        "chosen_action_types": _gate_diag.get("chosen_action_types", []),
                        "plan_source": _gate_diag.get("plan_source", ""),
                        "llm_plan_chosen": _gate_diag.get("llm_plan_chosen", None),
                        "expected": "multi_action",
                        "actual": "planner_did_not_execute",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )

        # Hard mismatch — deterministic backbone (which the smoke tests
        # exercise) found families the chosen plan dropped. Most common
        # cause: the LLM upgrade hook doesn't know about a family that
        # was added to ACTION_ANCHORS after the prompt was last updated
        # (e.g. timer.set / timer.cancel).
        if (
            _gate_diag.get("deterministic_only_families")
            and _gate_diag.get("llm_plan_chosen")
        ):
            print(
                "[planner_version_or_path_mismatch] "
                + json.dumps(
                    {
                        "endpoint": "/infer",
                        "request_id": request_id,
                        "transcript": _planner_gate_transcript[:240],
                        "planner_module_path": getattr(_planner_gate_mp, "__file__", "") or "",
                        "deterministic_action_types": _gate_diag.get(
                            "deterministic_action_types", []
                        ),
                        "chosen_action_types": _gate_diag.get("chosen_action_types", []),
                        "deterministic_only_families": _gate_diag.get(
                            "deterministic_only_families", []
                        ),
                        "chosen_only_families": _gate_diag.get(
                            "chosen_only_families", []
                        ),
                        "plan_source": _gate_diag.get("plan_source", ""),
                        "llm_plan_chosen": True,
                        "likely_cause": (
                            "llm_prompt_missing_action_family"
                            if "timer.set" in (_gate_diag.get("deterministic_only_families") or [])
                            or "timer.cancel" in (_gate_diag.get("deterministic_only_families") or [])
                            else "llm_rewrote_action_list"
                        ),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass
    if checklist_action_name:
        # Checklist edit commands should execute immediately in work mode, never be replaced by reasoning coach voice.
        coach_reply = None
    # Digest-only TTS skips the LLM entirely; deictic/code follow-ups must see Reasoning workspace + snapshot.
    coach_tts_fastpath = (
        bool(coach_reply)
        and not anchor_imp
        and not _work_mode_transcript_asks_deictic_followup(transcript)
    )
    attachment_ctx_imp: Optional[str] = None
    upload_list: List[UploadFile] = []
    if context_files:
        upload_list.extend([f for f in context_files if f is not None])
    if context_file is not None:
        upload_list.append(context_file)
    if upload_list:
        parts_infer: List[str] = []
        for uf in upload_list:
            try:
                context_bytes = await uf.read()
                if not context_bytes:
                    continue
                if len(context_bytes) > WORK_MODE_UPLOAD_MAX_BYTES:
                    raise HTTPException(413, "File too large (max 25MB)")
                fname = uf.filename or "upload"
                ctype = uf.content_type or ""
                if reasoning_ai is not None:
                    part = await asyncio.to_thread(
                        reasoning_ai.extract_attachment_context,
                        fname,
                        ctype,
                        context_bytes,
                    )
                else:
                    part = _fallback_infer_attachment_context(fname, ctype, context_bytes)
                if (part or "").strip():
                    parts_infer.append((part or "").strip())
            except HTTPException:
                raise
            except Exception as e:
                raise HTTPException(400, f"Attachment processing failed: {e}") from e
        if parts_infer:
            attachment_ctx_imp = "\n\n--- FILE ---\n\n".join(parts_infer)

    wm_ctx_imp = _normalize_work_mode_reasoning_context_payload(work_mode_reasoning_context)
    strict_lane_imp = str(work_mode_strict_lane_context or "").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )
    brief_voice_imp = str(work_mode_voice_brief_completion or "").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )
    also_voice_imp = str(work_mode_stage2_also_prefix or "").strip().lower() in (
        "1",
        "true",
        "yes",
        "on",
    )
    stage2_turn_imp = _normalize_work_mode_stage2_turn(work_mode_stage2_turn_json)
    stage2_spoken_override_imp = (work_mode_stage2_spoken_override or "").strip() or None
    if stage2_spoken_override_imp and len(stage2_spoken_override_imp) > 800:
        stage2_spoken_override_imp = stage2_spoken_override_imp[:800]

    if work_mode_intent and not brief_voice_imp:
        action_name, reply = _work_mode_toggle_reply(work_mode_intent, client_context)
        t_tts_start = perf_counter()
        reply, audio_urls = await synthesize_reply_audio(session_id, reply, client=client)
        t_tts = perf_counter() - t_tts_start
        t_total = perf_counter() - infer_t0
        return {
            "transcript": transcript,
            "reply": reply,
            "audio_url": audio_urls[0] if audio_urls else "",
            "audio_urls": audio_urls,
            "tts_segment_count": len(audio_urls),
            "client_action": action_name,
            "latency": _infer_latency_json(
                pre_asr=t_pre_asr,
                asr_lock=t_asr_lock,
                asr_transcribe=t_asr_transcribe,
                bridge=max(0.0, t_tts_start - t_asr_lock_end),
                llm=0.0,
                post_llm=0.0,
                tts=t_tts,
                total=t_total,
                short_circuit="work_mode_toggle",
            ),
        }

    # 2026-05-29 spec PART 3 — when the multi-action planner already
    # executed a typed compound command (e.g. ``"set a timer for 10s
    # and pause the music"``), the work-mode timer short-circuit must
    # YIELD. Otherwise it would steal the turn from the planner and
    # drop the second action (the music.pause sibling). Skipping the
    # call entirely also avoids enqueueing a duplicate timer when the
    # planner's direct dispatcher already did so via the timer.set
    # branch of ``_dispatch_planned_action_directly``.
    if planner_executed_infer is None:
        timer_short = _try_work_mode_timer_extend_core(
            session_id, transcript, client_context, client
        ) or _try_work_mode_timer_core(session_id, transcript, client_context, client)
    else:
        timer_short = None
        try:
            print(
                "[planner_route] "
                + json.dumps(
                    {
                        "endpoint": "/infer",
                        "request_id": request_id,
                        "timer_short_skipped_due_to_planner": True,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass

    if want_stream_tts:
        if not (
            timer_short is not None
            or identity_reply
            or memory_reply
            or anonymous_reply
            or snapshot_reply
            or planner_executed_infer is not None
            or brief_voice_imp
        ):
            _preflight_general_llm_credit_cap(
                session_id,
                transcript,
                history,
                client_context_snapshot=client_context,
            )
        async def ndjson_infer():
            # First bytes to the client: ASR line (Voice UI user bubble). Omit transcript for reasoning stage‑2
            # brief so the client does not re-insert an older user line above this assistant reply.
            _asr_transcript = "" if brief_voice_imp else transcript
            yield (
                json.dumps({"type": "asr", "transcript": _asr_transcript}, ensure_ascii=False) + "\n"
            ).encode("utf-8")
            # 2026-05-29 LIVE-TRACE DIAGNOSTIC — stream-path final stage.
            # Mirrors the non-stream trace above; runs once per request so
            # `[planner_live_trace] stage="final"` always appears, regardless
            # of which streaming sub-branch (timer / anonymous / snapshot /
            # planner / legacy) is about to fire.
            try:
                if planner_executed_infer is not None:
                    _branch_taken = "planner"
                elif timer_short is not None:
                    _branch_taken = "timer_short"
                elif identity_reply:
                    _branch_taken = "identity_fastpath"
                elif memory_reply:
                    _branch_taken = "memory_fastpath"
                elif anonymous_reply:
                    _branch_taken = "anonymous_fastpath"
                elif snapshot_reply:
                    _branch_taken = "snapshot_fastpath"
                else:
                    _branch_taken = "legacy_resolver_or_llm"
                _gate_diag_stream = _planner_last_gate_diag_var.get() or {}
                _stream_action_result = (
                    planner_executed_infer[2]
                    if (planner_executed_infer and len(planner_executed_infer) >= 3)
                    else None
                )
                _stream_payloads = []
                if isinstance(_stream_action_result, dict):
                    _stream_payloads = _stream_action_result.get("ui_payloads") or []
                _stream_action_type = (
                    (_stream_action_result or {}).get("action_type")
                    if isinstance(_stream_action_result, dict) else None
                ) or (_branch_taken if _branch_taken != "legacy_resolver_or_llm" else "")
                print(
                    "[planner_live_trace] "
                    + json.dumps(
                        {
                            "stage": "final",
                            "endpoint": "/infer",
                            "path": "stream",
                            "branch_taken": _branch_taken,
                            "request_id": request_id,
                            "transcript": _planner_gate_transcript[:240],
                            "input_source": _input_source_lower or "unknown",
                            "typed": _typed_flag,
                            "use_browser_asr": str(use_browser_asr or ""),
                            "planner_execution_allowed": planner_execution_allowed,
                            "should_trigger_planner_result": bool(_should_trigger_planner_result),
                            "planner_executed": planner_executed_infer is not None,
                            "timer_short_called": timer_short is not None,
                            "checklist_shortcut_called": bool(checklist_action_name),
                            "greedy_router_selected": (
                                checklist_action_name
                                or ((work_mode_intent or {}).get("action") if isinstance(work_mode_intent, dict) else "")
                                or ""
                            ),
                            "final_action_type": _stream_action_type,
                            "final_planner_actions": list(
                                (_stream_action_result or {}).get("planner_actions") or []
                            ) if isinstance(_stream_action_result, dict) else [],
                            "final_action_payloads_count": len(_stream_payloads),
                            "final_action_payload_ops": [
                                (p.get("op") or "") for p in _stream_payloads if isinstance(p, dict)
                            ],
                            "planner_returned_none_reason": _gate_diag_stream.get(
                                "planner_returned_none_reason", ""
                            ),
                            "plan_source": _gate_diag_stream.get("plan_source", ""),
                            "llm_plan_chosen": _gate_diag_stream.get("llm_plan_chosen", None),
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
                if (
                    bool(_should_trigger_planner_result)
                    and _stream_action_type != "multi_action"
                ):
                    print(
                        "[planner_live_mismatch_error] "
                        + json.dumps(
                            {
                                "endpoint": "/infer",
                                "stage": "final",
                                "path": "stream",
                                "branch_taken": _branch_taken,
                                "request_id": request_id,
                                "transcript": _planner_gate_transcript[:240],
                                "expected": "multi_action",
                                "actual": _stream_action_type or _branch_taken,
                                "deterministic_action_types": _gate_diag_stream.get(
                                    "deterministic_action_types", []
                                ),
                                "chosen_action_types": _gate_diag_stream.get(
                                    "chosen_action_types", []
                                ),
                                "planner_returned_none_reason": _gate_diag_stream.get(
                                    "planner_returned_none_reason", ""
                                ),
                                "plan_source": _gate_diag_stream.get("plan_source", ""),
                                "llm_plan_chosen": _gate_diag_stream.get("llm_plan_chosen", None),
                                "timer_short_called": timer_short is not None,
                                "checklist_shortcut_called": bool(checklist_action_name),
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )

                # 2026-05-29 spec PART 2 — emit the per-turn
                # ``[compound_route_trace]`` JSON. Stream path captures
                # what we know before the body actually streams; the
                # diagnostic captures every spec field plus the new
                # ``[planner_should_have_run_but_did_not]`` /
                # ``[info_clause_dropped]`` hard warnings.
                _stream_legacy_selected = (
                    checklist_action_name
                    or ((work_mode_intent or {}).get("action")
                        if isinstance(work_mode_intent, dict) else "")
                    or ""
                )
                _emit_compound_route_trace(
                    request_id=request_id,
                    transcript=_planner_gate_transcript,
                    endpoint="/infer",
                    input_source=_input_source_lower or "unknown",
                    typed=bool(_typed_flag),
                    use_browser_asr=bool(use_browser_asr or ""),
                    planner_execution_allowed=bool(planner_execution_allowed),
                    should_trigger_planner_result=bool(_should_trigger_planner_result),
                    planner_trigger_reason=_planner_trigger_reason or "",
                    planner_gate_called=bool(_planner_gate_called),
                    planner_executed=planner_executed_infer is not None,
                    gate_diag=_gate_diag_stream,
                    action_result=_stream_action_result
                    if isinstance(_stream_action_result, dict) else None,
                    legacy_router_called=planner_executed_infer is None,
                    legacy_router_selected=_stream_legacy_selected,
                    final_action_type=_stream_action_type or "",
                    final_reply="",  # stream path doesn't materialize a single reply string here
                    path="stream",
                )
            except Exception:
                pass

            # PART 3 — planner outranks the timer short-circuit when both
            # could fire. The earlier ``planner_executed_infer is None``
            # guard around ``_try_work_mode_timer_core`` already keeps
            # ``timer_short`` empty in that case; this defensive check
            # keeps the branch order obvious if a future edit forgets to
            # gate the helper call.
            if planner_executed_infer is None and timer_short is not None:
                t_llm_end = perf_counter()
                reply_tm = timer_short["reply"]
                wm_tm = timer_short.get("work_mode_timer")
                if wm_tm and isinstance(wm_tm, dict) and not wm_tm.get("cancel"):
                    await enrich_work_mode_timer_with_tts(session_id, wm_tm, client)
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": reply_tm})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=reply_tm,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_timer=wm_tm,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            # 2026-06-01 identity-leak patch: identity-challenge fastpath
            # wins before the anonymous "what do you know about me" path so
            # the LLM never sees these questions.
            if identity_reply:
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": identity_reply})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=identity_reply,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            if memory_reply:
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": memory_reply})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=memory_reply,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            if anonymous_reply:
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": anonymous_reply})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=anonymous_reply,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            if snapshot_reply:
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": snapshot_reply})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=snapshot_reply,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            # Multi-action planner — typed-only execution. When the gate
            # at the top of /infer already ran and produced a triple, use
            # its combined reply + chained ui_payloads and skip both the
            # streaming-action prep AND the legacy resolver.
            if planner_executed_infer is not None:
                reply_pe, _t_llm_pe, action_result_pe = planner_executed_infer
                t_llm_end = perf_counter()
                # PART 3 — surface ``work_mode_timer`` from the planner's
                # aggregated action_result so the NDJSON stream still
                # carries the timer meta the frontend needs to enqueue
                # the alarm. ``execute_planned_actions`` stashes it under
                # ``work_mode_timer`` on the combined_ar.
                wm_tm_pe: dict | None = None
                if isinstance(action_result_pe, dict):
                    _wmt_candidate = action_result_pe.get("work_mode_timer")
                    if isinstance(_wmt_candidate, dict) and _wmt_candidate:
                        wm_tm_pe = _wmt_candidate
                if wm_tm_pe and isinstance(wm_tm_pe, dict) and not wm_tm_pe.get("cancel"):
                    try:
                        await enrich_work_mode_timer_with_tts(session_id, wm_tm_pe, client)
                    except Exception:
                        pass
                history.append({"role": "user", "content": transcript})
                if reply_pe:
                    history.append({"role": "assistant", "content": reply_pe})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2:]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=reply_pe,
                    client=client,
                    action_result=action_result_pe,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_timer=wm_tm_pe,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            prepared_stream = (
                None
                if brief_voice_imp
                or memory_reply
                or identity_reply
                or anonymous_reply
                or snapshot_reply
                else try_prepare_streaming_action_messages(session_id, transcript, history)
            )

            if prepared_stream is not None:
                ps = prepared_stream
                async for line in iter_infer_tts_ndjson_stream_llm_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    client=client,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_bridge=t_bridge,
                    history=history,
                    messages_override=ps.messages,
                    meta_action_type=ps.meta_action_type,
                    meta_action_payload=ps.meta_action_payload,
                    finalize_action_result=ps.finalize,
                    reasoning_voice_coach=coach_imp,
                    reasoning_attachment_context=attachment_ctx_imp,
                    client_context_snapshot=client_context,
                    thread_follow_up_anchor=anchor_imp,
                    work_mode_reasoning_context=wm_ctx_imp,
                    work_mode_strict_lane_context=strict_lane_imp,
                    work_mode_voice_brief_completion=brief_voice_imp,
                    work_mode_stage2_also_prefix=also_voice_imp,
                    work_mode_stage2_turn=stage2_turn_imp,
                    work_mode_stage2_spoken_override=stage2_spoken_override_imp,
                ):
                    yield line.encode("utf-8")
                return

            if (
                brief_voice_imp
                and stage2_spoken_override_imp
                and _stage2_status_scope_matches(stage2_turn_imp, wm_ctx_imp)
            ):
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": stage2_spoken_override_imp})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=stage2_spoken_override_imp,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            resolved = (
                None
                if brief_voice_imp
                or memory_reply
                or identity_reply
                or anonymous_reply
                or snapshot_reply
                else resolve_reply_if_not_general_llm(
                    session_id,
                    transcript,
                    history,
                    client_context_snapshot=client_context,
                )
            )

            if resolved is not None:
                reply, t_llm_reported, action_result = resolved
                t_llm_end = perf_counter()

                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": reply})

                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]

                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=reply,
                    client=client,
                    action_result=action_result,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=t_llm_reported,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            if coach_tts_fastpath:
                t_llm_end = perf_counter()
                history.append({"role": "user", "content": transcript})
                history.append({"role": "assistant", "content": coach_reply})
                if len(history) > MAX_TURNS * 2:
                    history[:] = history[-MAX_TURNS * 2 :]
                async for line in iter_infer_tts_ndjson_stream(
                    infer_t0=infer_t0,
                    session_id=session_id,
                    transcript=transcript,
                    reply=coach_reply,
                    client=client,
                    action_result=None,
                    t_pre_asr=t_pre_asr,
                    t_asr_lock=t_asr_lock,
                    t_asr_transcribe=t_asr_transcribe,
                    t_asr_lock_end=t_asr_lock_end,
                    t_llm_start=t_llm_start,
                    t_llm_end=t_llm_end,
                    t_llm_reported=0.0,
                    work_mode_voice_brief_completion=brief_voice_imp,
                ):
                    yield line.encode("utf-8")
                return

            async for line in iter_infer_tts_ndjson_stream_llm_stream(
                infer_t0=infer_t0,
                session_id=session_id,
                transcript=transcript,
                client=client,
                t_pre_asr=t_pre_asr,
                t_asr_lock=t_asr_lock,
                t_asr_transcribe=t_asr_transcribe,
                t_asr_lock_end=t_asr_lock_end,
                t_llm_start=t_llm_start,
                t_bridge=t_bridge,
                history=history,
                reasoning_voice_coach=coach_imp,
                reasoning_attachment_context=attachment_ctx_imp,
                client_context_snapshot=client_context,
                thread_follow_up_anchor=anchor_imp,
                work_mode_reasoning_context=wm_ctx_imp,
                work_mode_strict_lane_context=strict_lane_imp,
                work_mode_voice_brief_completion=brief_voice_imp,
                work_mode_stage2_also_prefix=also_voice_imp,
                work_mode_stage2_turn=stage2_turn_imp,
                work_mode_stage2_spoken_override=stage2_spoken_override_imp,
            ):
                yield line.encode("utf-8")

        return StreamingResponse(
            _diag_wrap_stream(
                ndjson_infer(),
                route="/infer",
                session_id=session_id,
                request_id=request_id,
                start_ts=_req_start_ts,
                mode=infer_mode,
                client=client,
            ),
            media_type="application/x-ndjson",
            headers=_ndjson_stream_headers(),
        )

    wm_timer_out: dict | None = None
    if timer_short is not None:
        reply = timer_short["reply"]
        wm_timer_out = timer_short.get("work_mode_timer")
        t_llm_reported = 0.0
        action_result = None
    elif identity_reply:
        reply, t_llm_reported, action_result = identity_reply, 0.0, None
    elif memory_reply:
        reply, t_llm_reported, action_result = memory_reply, 0.0, None
    elif anonymous_reply:
        reply, t_llm_reported, action_result = anonymous_reply, 0.0, None
    elif snapshot_reply:
        reply, t_llm_reported, action_result = snapshot_reply, 0.0, None
    elif planner_executed_infer is not None:
        # Multi-action planner — typed-only execution path. Gate at the
        # top of /infer already executed each action's span and built the
        # aggregated action_result. Skip the legacy resolver entirely.
        reply, t_llm_reported, action_result = planner_executed_infer
        # PART 3 — propagate ``work_mode_timer`` produced by the planner's
        # timer.set / timer.cancel dispatch into the same ``wm_timer_out``
        # variable the non-stream response uses below, so the response
        # JSON still carries the alarm meta the frontend enqueues.
        if isinstance(action_result, dict):
            _wmt_candidate_ns = action_result.get("work_mode_timer")
            if isinstance(_wmt_candidate_ns, dict) and _wmt_candidate_ns:
                wm_timer_out = _wmt_candidate_ns
    else:
        if brief_voice_imp:
            reply, t_llm_reported, action_result = process_user_input(
                session_id,
                transcript,
                history,
                reasoning_voice_coach=coach_imp,
                reasoning_attachment_context=attachment_ctx_imp,
                client_context_snapshot=client_context,
                thread_follow_up_anchor=anchor_imp,
                work_mode_reasoning_context=wm_ctx_imp,
                work_mode_strict_lane_context=strict_lane_imp,
                work_mode_voice_brief_completion=brief_voice_imp,
                work_mode_stage2_also_prefix=also_voice_imp,
                work_mode_stage2_turn=stage2_turn_imp,
                work_mode_stage2_spoken_override=stage2_spoken_override_imp,
            )
        else:
            resolved = resolve_reply_if_not_general_llm(
                session_id,
                transcript,
                history,
                client_context_snapshot=client_context,
            )
            if resolved is not None:
                reply, t_llm_reported, action_result = resolved
            elif coach_tts_fastpath:
                reply, t_llm_reported, action_result = coach_reply, 0.0, None
            else:
                reply, t_llm_reported, action_result = process_user_input(
                    session_id,
                    transcript,
                    history,
                    reasoning_voice_coach=coach_imp,
                    reasoning_attachment_context=attachment_ctx_imp,
                    client_context_snapshot=client_context,
                    thread_follow_up_anchor=anchor_imp,
                    work_mode_reasoning_context=wm_ctx_imp,
                    work_mode_strict_lane_context=strict_lane_imp,
                    work_mode_voice_brief_completion=brief_voice_imp,
                    work_mode_stage2_also_prefix=also_voice_imp,
                    work_mode_stage2_turn=stage2_turn_imp,
                    work_mode_stage2_spoken_override=stage2_spoken_override_imp,
                )
            if (
                brief_voice_imp
                and stage2_spoken_override_imp
                and _stage2_status_scope_matches(stage2_turn_imp, wm_ctx_imp)
            ):
                reply = stage2_spoken_override_imp
    t_llm_end = perf_counter()
    t_llm_wall = t_llm_end - t_llm_start

    history.append({"role": "user", "content": transcript})
    history.append({"role": "assistant", "content": reply})

    if len(history) > MAX_TURNS * 2:
        history[:] = history[-MAX_TURNS * 2:]

    t_tts_start = perf_counter()
    t_post_llm = t_tts_start - t_llm_end
    reply, audio_urls = await synthesize_reply_audio(session_id, reply, client=client)
    audio_url = audio_urls[0] if audio_urls else ""
    t_tts = perf_counter() - t_tts_start
    t_total = perf_counter() - infer_t0
    if wm_timer_out is not None and isinstance(wm_timer_out, dict) and not wm_timer_out.get("cancel"):
        await enrich_work_mode_timer_with_tts(session_id, wm_timer_out, client)

    _print_infer_latency_breakdown(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
    )
    print(
        f"[LATENCY_DETAIL] process_user_input internal t_llm={t_llm_reported:.3f}s "
        f"(subset of LLM column when paths return partial timings)"
    )

    latency_payload = _infer_latency_json(
        pre_asr=t_pre_asr,
        asr_lock=t_asr_lock,
        asr_transcribe=t_asr_transcribe,
        bridge=t_bridge,
        llm=t_llm_wall,
        post_llm=t_post_llm,
        tts=t_tts,
        total=t_total,
        llm_internal_reported=t_llm_reported,
    )

    out = {
        "transcript": transcript,
        "reply": reply,
        "audio_url": audio_url,
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "action_payload": action_result.get("ui_payload") if action_result else None,
        "action_type": action_result.get("action_type") if action_result else None,
        "latency": latency_payload,
        "request_id": request_id,
    }
    # PART 4 — surface multi-action aggregates so a client that opts out
    # of TTS streaming still sees every payload + the planner trace.
    if isinstance(action_result, dict):
        _aps_ns = action_result.get("ui_payloads")
        if isinstance(_aps_ns, list) and _aps_ns:
            out["action_payloads"] = _aps_ns
        _pa_ns = action_result.get("planner_actions")
        if isinstance(_pa_ns, list) and _pa_ns:
            out["planner_actions"] = _pa_ns
    if wm_timer_out is not None:
        out["work_mode_timer"] = wm_timer_out
    # 2026-05-29 LIVE-TRACE DIAGNOSTIC — final-stage trace pairs with the
    # gate-stage line via request_id. Captures the action_type the user
    # actually saw plus the chained payload ops so an operator can confirm
    # the gate decision matched the realized turn.
    try:
        _final_payloads = []
        if isinstance(action_result, dict):
            _final_payloads = action_result.get("ui_payloads") or []
            if not _final_payloads and isinstance(action_result.get("ui_payload"), dict):
                _final_payloads = [action_result["ui_payload"]]
        _final_payload_ops = [
            (p.get("op") or "") for p in _final_payloads if isinstance(p, dict)
        ]
        _final_planner_actions: list[str] = []
        if isinstance(action_result, dict):
            _final_planner_actions = list(action_result.get("planner_actions") or [])
        _gate_diag_final = _planner_last_gate_diag_var.get() or {}
        _final_action_type = (
            (action_result or {}).get("action_type") if isinstance(action_result, dict) else None
        ) or ""
        print(
            "[planner_live_trace] "
            + json.dumps(
                {
                    "stage": "final",
                    "endpoint": "/infer",
                    "path": "non_stream",
                    "request_id": request_id,
                    "transcript": _planner_gate_transcript[:240],
                    "input_source": _input_source_lower or "unknown",
                    "typed": _typed_flag,
                    "use_browser_asr": str(use_browser_asr or ""),
                    "planner_execution_allowed": planner_execution_allowed,
                    "should_trigger_planner_result": bool(_should_trigger_planner_result),
                    "planner_executed": planner_executed_infer is not None,
                    "timer_short_called": timer_short is not None,
                    "checklist_shortcut_called": bool(checklist_action_name),
                    "greedy_router_selected": (
                        checklist_action_name
                        or ((work_mode_intent or {}).get("action") if isinstance(work_mode_intent, dict) else "")
                        or ""
                    ),
                    "final_action_type": _final_action_type,
                    "final_planner_actions": _final_planner_actions,
                    "final_action_payloads_count": len(_final_payloads),
                    "final_action_payload_ops": _final_payload_ops,
                    "planner_returned_none_reason": _gate_diag_final.get(
                        "planner_returned_none_reason", ""
                    ),
                    "plan_source": _gate_diag_final.get("plan_source", ""),
                    "llm_plan_chosen": _gate_diag_final.get("llm_plan_chosen", None),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
        if (
            bool(_should_trigger_planner_result)
            and _final_action_type != "multi_action"
        ):
            print(
                "[planner_live_mismatch_error] "
                + json.dumps(
                    {
                        "endpoint": "/infer",
                        "stage": "final",
                        "path": "non_stream",
                        "request_id": request_id,
                        "transcript": _planner_gate_transcript[:240],
                        "expected": "multi_action",
                        "actual": _final_action_type or "no_action",
                        "deterministic_action_types": _gate_diag_final.get(
                            "deterministic_action_types", []
                        ),
                        "chosen_action_types": _gate_diag_final.get("chosen_action_types", []),
                        "planner_returned_none_reason": _gate_diag_final.get(
                            "planner_returned_none_reason", ""
                        ),
                        "plan_source": _gate_diag_final.get("plan_source", ""),
                        "llm_plan_chosen": _gate_diag_final.get("llm_plan_chosen", None),
                        "timer_short_called": timer_short is not None,
                        "checklist_shortcut_called": bool(checklist_action_name),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )

        # 2026-05-29 spec PART 2 — emit ``[compound_route_trace]`` for the
        # non-stream /infer path. Pairs with the gate-stage trace via
        # request_id; the dispatcher's existing ``[compound_action_dropped]``
        # and ``[reasoning_prompt_contaminated_by_app_action]`` warnings
        # already cover the other two hard cases from the spec.
        _final_legacy_selected = (
            checklist_action_name
            or ((work_mode_intent or {}).get("action")
                if isinstance(work_mode_intent, dict) else "")
            or ""
        )
        _emit_compound_route_trace(
            request_id=request_id,
            transcript=_planner_gate_transcript,
            endpoint="/infer",
            input_source=_input_source_lower or "unknown",
            typed=bool(_typed_flag),
            use_browser_asr=bool(use_browser_asr or ""),
            planner_execution_allowed=bool(planner_execution_allowed),
            should_trigger_planner_result=bool(_should_trigger_planner_result),
            planner_trigger_reason=_planner_trigger_reason or "",
            planner_gate_called=bool(_planner_gate_called),
            planner_executed=planner_executed_infer is not None,
            gate_diag=_gate_diag_final,
            action_result=action_result if isinstance(action_result, dict) else None,
            legacy_router_called=planner_executed_infer is None,
            legacy_router_selected=_final_legacy_selected,
            final_action_type=_final_action_type or "",
            final_reply=reply if isinstance(reply, str) else "",
            path="non_stream",
        )
    except Exception:
        pass
    # Multi-device-concurrency PART 1: pair the [REQ start] from the top of
    # /infer with a [REQ end]. Non-stream returns flow through here; stream
    # returns log [REQ end] from _diag_wrap_stream's finally instead.
    log_req_end(
        route="/infer",
        session_id=session_id,
        request_id=request_id,
        start_ts=_req_start_ts,
        ok=True,
        path="non_stream",
        mode=infer_mode,
    )
    return out

