class _QuietPollAccessLogFilter(logging.Filter):
    """Hide high-frequency client poll lines from uvicorn access logs."""

    _SUBSTR = ("GET /status ",)

    def filter(self, record: logging.LogRecord) -> bool:
        try:
            msg = record.getMessage()
        except Exception:
            return True
        return not any(s in msg for s in self._SUBSTR)


async def load_model():
    global vera, SERVER_STATE, reasoning_ai, reasoning_deep_ai
    # await asyncio.sleep(3)
    try:
        print("Loading model...")
        vera = VeraAI(MODEL_PATH)
        reasoning_ai = ReasoningAI()
        reasoning_deep_ai = ReasoningDeepAI()
        # Patch OpenAI clients so chat.completions usage flows into the
        # local cost logger without per-call-site edits.
        try:
            for _ai_obj in (vera, reasoning_ai, reasoning_deep_ai):
                _client = getattr(_ai_obj, "client", None)
                if _client is None:
                    continue
                _model = getattr(_ai_obj, "model_name", None)
                _cost_instrument_openai(_client, default_model=_model)
        except Exception as _instr_err:
            print(f"[cost_logger] instrumentation skipped: {_instr_err}")
        SERVER_STATE = "ready"
        print("Model ready.")

    except Exception as e:
        SERVER_STATE = "offline"
        print("Model failed:", e)

@app.on_event("startup")
async def startup():
    global SERVER_STATE

    logging.getLogger("uvicorn.access").addFilter(_QuietPollAccessLogFilter())

    SERVER_STATE = "starting"
    try:
        from bmo_tts import bmo_fish_configured

        if bmo_fish_configured():
            print("[BMO Fish] Credentials loaded — BMO page will use Fish TTS.")
        else:
            print(
                "[BMO Fish] Not configured in this process — check `.env` next to app.py "
                "or visit GET /health/bmo-tts"
            )
    except Exception as e:
        print("[BMO Fish] Startup check error:", e)

    try:
        _cost_init()
    except Exception as _cl_err:
        print(f"[cost_logger] init failed (continuing without it): {_cl_err}")

    asyncio.create_task(load_model())


# --------------------------------------------------------------------------- #
# Cost-logging middleware: wraps every user-facing request in a context so
# OpenAI / Serper / Fish events get attributed to a request_id, then writes a
# per-request summary on completion. Handlers can refine the default
# mode/request_type by calling _cost_update_request(...) once they know more.
#
# Important: many Vera endpoints return StreamingResponse. Provider events
# (OpenAI tokens, Fish TTS chunks, Serper queries) fire INSIDE that stream's
# body iterator, which Starlette consumes AFTER this middleware function
# returns. If we finalized in a plain `finally` block, the request summary
# would be written before any of those events arrived. So for streaming
# responses we wrap the body iterator and finalize from its `finally` instead.
# --------------------------------------------------------------------------- #
_COST_LOGGING_PATH_PREFIXES = (
    "/infer",
    "/text",
    "/tts_emotion_route",
    "/api/work-mode/reasoning",
    "/api/reasoning",
    "/work_mode/",
)
# Endpoints that are state sync only (no LLM / Fish / Serper call) — skip them
# entirely so they don't pollute pricing analysis with empty rows.
_COST_LOGGING_STATE_SYNC_PREFIXES = (
    "/api/work-mode/checklist",
    "/api/work-mode/timer",
)
_COST_LOGGING_SKIP_PREFIXES = (
    "/audio",
    "/static",
    "/assets",
    "/health",
    "/status",
    "/metrics",
    "/favicon",
    "/cost/",
)


def _cost_default_request_type_for_path(path: str) -> str:
    p = (path or "").lower()
    if p.startswith("/infer"):
        return "voice"
    if p.startswith("/text"):
        return "command"
    if p.startswith("/tts_emotion_route"):
        return "bmo_tts"
    if "reasoning" in p:
        return "reasoning"
    return "other"


async def _cost_wrap_streaming_iter(orig_iter, state, init_success, init_error):
    """Re-emit chunks from ``orig_iter`` and finalize the cost request after
    the iterator is exhausted (success), raises (failure), or is closed early.

    This runs in the same asyncio task Starlette uses for ``StreamingResponse``,
    so the ``_current_request`` contextvar set by the middleware is still
    visible while the body streams. Provider events fired during iteration get
    attributed correctly, and the summary row only gets written after the last
    chunk has been yielded.
    """
    success = bool(init_success)
    error = init_error
    try:
        async for chunk in orig_iter:
            yield chunk
    except Exception as e:
        success = False
        error = error or str(e)[:200]
        raise
    finally:
        try:
            _cost_end_request(state, success=success, error_message=error)
        except Exception as _e:  # pragma: no cover
            print(f"[cost_logger] streaming finalize error: {_e}")


@app.middleware("http")
async def _cost_logging_middleware(request, call_next):
    if not _COST_LOGGING_AVAILABLE:
        return await call_next(request)
    path = request.url.path or ""
    if any(path.startswith(prefix) for prefix in _COST_LOGGING_STATE_SYNC_PREFIXES):
        return await call_next(request)
    if not any(path.startswith(prefix) for prefix in _COST_LOGGING_PATH_PREFIXES):
        return await call_next(request)
    if any(path.startswith(prefix) for prefix in _COST_LOGGING_SKIP_PREFIXES):
        return await call_next(request)
    default_type = _cost_default_request_type_for_path(path)
    state = _cost_begin_request(
        mode="unknown",
        request_type=default_type,
        extra={"http_path": path, "http_method": request.method},
    )
    success = True
    error_message: str | None = None
    finalized_via_stream_wrap = False
    try:
        response = await call_next(request)
        try:
            if getattr(response, "status_code", 200) >= 400:
                success = False
                error_message = f"HTTP {response.status_code}"
        except Exception:
            pass
        body_iter = getattr(response, "body_iterator", None)
        if body_iter is not None and not getattr(response, "_vera_cost_wrapped", False):
            try:
                response.body_iterator = _cost_wrap_streaming_iter(
                    body_iter, state, success, error_message
                )
                response._vera_cost_wrapped = True
                finalized_via_stream_wrap = True
            except Exception as _e:
                print(f"[cost_logger] could not wrap streaming body: {_e}")
        return response
    except Exception as e:
        success = False
        error_message = str(e)[:200]
        raise
    finally:
        if not finalized_via_stream_wrap:
            try:
                _cost_end_request(state, success=success, error_message=error_message)
            except Exception as _e:  # pragma: no cover
                print(f"[cost_logger] middleware end_request error: {_e}")


# --------------------------------------------------------------------------- #
# Cost-logging session endpoints.
#
# Intended flow:
#   1. (Optional) POST /cost/session/start   {session_id, scenario_name}
#      Tags the session with a scenario label up front. Not required —
#      end/live will still work because they can reconstruct from the JSONL.
#   2. Use Vera normally. Each /infer or /text writes a request_cost_summary
#      row immediately after it finishes.
#   3. GET  /cost/session/live?session_id=...  ← inspect totals at any time
#      without finalizing. Reads the JSONL on disk + in-memory rolling state.
#   4. POST /cost/session/end    {session_id, scenario_name?}
#      Appends one row to session_cost_summary.jsonl. This is the canonical
#      finalization. Browser tab close does NOT do this — call it explicitly.
#
# /cost/scenario/{start,end} are kept as aliases for the original names so
# existing scripts keep working.
# --------------------------------------------------------------------------- #
class _CostSessionStartBody(BaseModel):
    session_id: str
    scenario_name: str | None = None


class _CostSessionEndBody(BaseModel):
    session_id: str
    scenario_name: str | None = None


def _cost_do_session_start(body: _CostSessionStartBody) -> dict:
    if not _COST_LOGGING_AVAILABLE:
        raise HTTPException(503, "cost_logging unavailable")
    sid = (body.session_id or "").strip()
    if not sid:
        raise HTTPException(400, "session_id required")
    scenario = (body.scenario_name or "").strip() or None
    _cost_begin_session(sid, scenario_name=scenario)
    if scenario:
        _cost_set_scenario(sid, scenario)
    return {
        "ok": True,
        "session_id": sid,
        "scenario_name": scenario,
        "recommended_scenario_names": list(_COST_RECOMMENDED_SCENARIOS),
    }


def _cost_do_session_end(body: _CostSessionEndBody) -> dict:
    if not _COST_LOGGING_AVAILABLE:
        raise HTTPException(503, "cost_logging unavailable")
    sid = (body.session_id or "").strip()
    if not sid:
        raise HTTPException(400, "session_id required")
    scenario = (body.scenario_name or "").strip() or None
    row = _cost_end_session(sid, scenario_name=scenario)
    if row is None:
        return {
            "ok": True,
            "ended": False,
            "session_id": sid,
            "reason": "no_open_session_and_no_jsonl_rows",
        }
    return {"ok": True, "ended": True, "session_id": sid, "summary": row}


