# --------------------------------------------------------------------------- #
# Backup: on graceful shutdown (uvicorn SIGINT/SIGTERM → FastAPI shutdown
# event), flush a session summary row for every session that still has
# in-memory state. This is best-effort — the canonical path is an explicit
# POST /cost/session/end from the client.
# --------------------------------------------------------------------------- #
@app.on_event("shutdown")
async def _cost_logging_shutdown_flush():
    if not _COST_LOGGING_AVAILABLE:
        return
    try:
        open_sids = _cost_list_open_sessions()
    except Exception as e:
        print(f"[cost_logger] shutdown flush list error: {e}")
        return
    if not open_sids:
        return
    print(
        f"[cost_logger] shutdown flush: writing best-effort session summaries "
        f"for {len(open_sids)} open session(s)"
    )
    for sid in open_sids:
        try:
            row = _cost_end_session(sid)
            if row:
                tc = row.get("total_api_cost_usd")
                tc_str = f"${tc:.6f}" if isinstance(tc, (int, float)) else "n/a"
                print(
                    f"[cost_logger] shutdown flush: session={sid} "
                    f"requests={row.get('total_requests', 0)} cost={tc_str} "
                    f"source={row.get('source')}"
                )
        except Exception as e:
            print(f"[cost_logger] shutdown flush error for session={sid}: {e}")

