_USER_FILE_NAME_RE = re.compile(r"^[a-zA-Z0-9._-]{1,80}$")


def _safe_user_json_stem(username: str) -> str:
    name = (username or "").strip()
    if not _USER_FILE_NAME_RE.fullmatch(name):
        raise HTTPException(status_code=400, detail="Invalid username.")
    return name


class UserSignInBody(BaseModel):
    username: str
    password: str
    # Multi-device-concurrency PART 7: each browser/device passes its own
    # session_id so the backend can map this active user PER SESSION instead
    # of clobbering the process-global `vera.active_user_info_path` for every
    # other device. Optional for backward-compat with old clients (they still
    # set the process-global, single-user behavior).
    session_id: str | None = None


def _active_username_from_runtime() -> str | None:
    if vera is not None and getattr(vera, "active_user_info_path", None):
        try:
            return Path(str(vera.active_user_info_path)).stem
        except Exception:
            return None
    return None


def _ensure_user_profile_json_path(stem: str) -> Path:
    safe_stem = _safe_user_json_stem(stem)
    path = _resolve_user_profile_path(safe_stem)
    if path is not None:
        return path
    USERS_FILES_DIR.mkdir(parents=True, exist_ok=True)
    p = (USERS_FILES_DIR / f"{safe_stem}.json").resolve()
    base = USERS_FILES_DIR.resolve()
    try:
        p.relative_to(base)
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid username.")
    if not p.exists():
        p.write_text("{}", encoding="utf-8")
    return p


def _read_user_profile_json(path: Path) -> dict:
    try:
        raw = path.read_text(encoding="utf-8-sig")
    except FileNotFoundError:
        return {}
    except Exception:
        return {}
    if not raw.strip():
        return {}
    try:
        obj = json.loads(raw)
        return obj if isinstance(obj, dict) else {}
    except Exception:
        return {}


def _write_user_profile_json(path: Path, payload: dict) -> None:
    tmp = path.with_suffix(path.suffix + ".tmp")
    tmp.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    tmp.replace(path)


def _normalize_checklist_items(items: object) -> list[dict]:
    if not isinstance(items, list):
        return []
    out: list[dict] = []
    for row in items[:300]:
        if not isinstance(row, dict):
            continue
        rid = str(row.get("id", "")).strip()[:80]
        text = str(row.get("text", "")).replace("\r", " ").replace("\n", " ").strip()[:200]
        done = bool(row.get("done"))
        if not rid:
            rid = f"{int(time() * 1000)}-{uuid.uuid4().hex[:6]}"
        parent_id = row.get("parent_id")
        parent_id_norm = str(parent_id).strip()[:80] if parent_id is not None else None
        if parent_id_norm == rid:
            parent_id_norm = None
        candidate = {"id": rid, "text": text, "done": done, "parent_id": parent_id_norm}
        if is_checklist_placeholder_item(candidate):
            continue
        out.append(candidate)
    return out


def _load_checklist_state_for_session(session_id: str) -> tuple[list[dict], bool, str | None]:
    # Multi-device-concurrency PART 7: prefer the session-scoped active user
    # so two devices signed in as different users get independent checklists.
    # The process-global active user is only consulted when no session mapping
    # exists (single-user / legacy code path).
    active_stem = get_active_username_for_session(session_id)
    if active_stem:
        path = _ensure_user_profile_json_path(active_stem)
        profile = _read_user_profile_json(path)
        state = profile.get("_vera_state")
        if not isinstance(state, dict):
            state = {}
        wm = state.get("work_mode")
        if not isinstance(wm, dict):
            wm = {}
        items = _normalize_checklist_items(wm.get("checklist_items"))
        collapsed = bool(wm.get("completed_collapsed", False))
        return items, collapsed, active_stem
    anon = anonymous_work_mode_checklists.get(session_id) or {}
    items = _normalize_checklist_items(anon.get("items"))
    collapsed = bool(anon.get("completed_collapsed", False))
    return items, collapsed, None


def _save_checklist_state_for_session(
    session_id: str,
    items: list[dict],
    completed_collapsed: bool | None = None,
) -> tuple[int, str | None]:
    # Multi-device-concurrency PART 7: see _load_checklist_state_for_session.
    active_stem = get_active_username_for_session(session_id)
    norm_items = _normalize_checklist_items(items)
    if active_stem:
        path = _ensure_user_profile_json_path(active_stem)
        profile = _read_user_profile_json(path)
        state = profile.get("_vera_state")
        if not isinstance(state, dict):
            state = {}
        wm = state.get("work_mode")
        if not isinstance(wm, dict):
            wm = {}
        wm["checklist_items"] = norm_items
        if completed_collapsed is not None:
            wm["completed_collapsed"] = bool(completed_collapsed)
        state["work_mode"] = wm
        profile["_vera_state"] = state
        _write_user_profile_json(path, profile)
        return len(norm_items), active_stem

    existing = anonymous_work_mode_checklists.get(session_id) or {}
    entry = {
        "items": norm_items,
        "completed_collapsed": bool(existing.get("completed_collapsed", False)),
    }
    if completed_collapsed is not None:
        entry["completed_collapsed"] = bool(completed_collapsed)
    anonymous_work_mode_checklists[session_id] = entry
    return len(norm_items), None


class WorkChecklistSaveBody(BaseModel):
    items: list[dict]
    completed_collapsed: bool | None = None
    session_id: str | None = None


@app.get("/api/diag/sessions")
def api_diag_sessions():
    """Multi-device-concurrency PART 11 — concurrency debug snapshot.

    Returns a structured view of every session_id the backend currently
    tracks across all the per-session dicts (chat history, panels, news
    context, checklist, locks state, etc.). Designed to be polled from
    DevTools by a tester running two devices in parallel; the response is
    intentionally cheap to compute so polling is safe.
    """
    sids = set(user_last_seen.keys())
    sids.update(_session_active_user.keys())
    sids.update(pending_action.keys())
    sids.update(recent_action_context.keys())
    sids.update(recent_news_context.keys())
    rows = []
    for sid in sorted(sids):
        rows.append(
            {
                "session_id": sid[:32],
                "last_seen": user_last_seen.get(sid),
                "active_user": _session_active_user.get(sid),
                "user_history_len": len(user_histories.get(sid, [])) if sid in user_histories else 0,
                "has_pending_action": sid in pending_action,
                "has_recent_action_context": sid in recent_action_context,
                "has_recent_news_context": sid in recent_news_context,
                "has_session_user_facts": sid in session_user_facts,
                "has_pending_voice_action": sid in pending_voice_actions,
                "has_work_mode_timer_plan": sid in work_mode_timer_plans,
                "has_checklist_undo_snapshot": sid in checklist_undo_snapshots,
                "has_latest_client_snapshot": sid in latest_client_context_snapshot,
                "anon_checklist_items": len((anonymous_work_mode_checklists.get(sid) or {}).get("items") or [])
                    if sid in anonymous_work_mode_checklists else 0,
                "reasoning_lane_keys": [k for k in reasoning_lane_histories.keys() if str(k).startswith(f"{sid}:")],
            }
        )
    return {
        "now": time(),
        "total_sessions": len(rows),
        "asr_lock_locked": asr_lock.locked(),
        "tts_lock_locked": tts_lock.locked(),
        "llm_lock_locked": llm_lock.locked(),
        "sessions": rows,
        "process_active_user_path": (vera.active_user_info_path if vera is not None else None),
    }


@app.get("/api/user/active")
def api_user_active(request: Request, session_id: str | None = None):
    """Current active user profile path (None = default / admin-as-current).

    PART 7: when a session_id is supplied, returns the per-session active
    user (so two devices on the same server can each see their own logged-in
    identity). Without session_id, returns the legacy process-global view.

    Phase 2: when a valid Supabase JWT is present, return supabase auth
    metadata and do NOT surface legacy users_files identity (Supabase wins).
    """
    from auth.jwt_auth import resolve_auth_user

    supabase_user = resolve_auth_user(request)
    if supabase_user is not None:
        return {
            "active_user_info_path": None,
            "server_ready": vera is not None and SERVER_STATE == "ready",
            "username": None,
            "session_scoped": False,
            "supabase_authenticated": True,
            "supabase_user_id": supabase_user.user_id,
            "supabase_email": supabase_user.email,
        }
    if vera is None:
        return {
            "active_user_info_path": None,
            "server_ready": False,
            "username": None,
            "session_scoped": False,
        }
    sess_user = None
    if session_id:
        sess_user = _session_active_user.get(safe_id(session_id))
    if sess_user:
        return {
            "active_user_info_path": str(_resolve_user_profile_path(sess_user) or ""),
            "server_ready": SERVER_STATE == "ready",
            "username": sess_user,
            "session_scoped": True,
        }
    p = vera.active_user_info_path
    username = None
    if p:
        try:
            username = Path(p).stem
        except Exception:
            username = None
    return {
        "active_user_info_path": p,
        "server_ready": SERVER_STATE == "ready",
        "username": username,
        "session_scoped": False,
    }


def _resolve_user_profile_path(stem: str) -> Path | None:
    """Return users_files/<stem>.json if present; else case-insensitive *.json match (Windows-friendly)."""
    base = USERS_FILES_DIR.resolve()
    if not base.is_dir():
        return None
    exact = (base / f"{stem}.json").resolve()
    try:
        exact.relative_to(base)
    except ValueError:
        return None
    if exact.is_file():
        return exact
    stem_lower = stem.lower()
    for p in base.glob("*.json"):
        if p.stem.lower() == stem_lower:
            return p.resolve()
    return None


def _password_matches(expected, submitted: str) -> bool:
    if expected is None:
        return False
    a = str(expected).strip()
    b = (submitted or "").strip()
    return a == b


@app.post("/api/user/sign-in")
def api_user_sign_in(body: UserSignInBody):
    """Authenticate against users_files/<username>.json field \"password\"; set active user profile."""
    global vera
    if vera is None or SERVER_STATE != "ready":
        raise HTTPException(status_code=503, detail="Server not ready.")
    stem = _safe_user_json_stem(body.username)
    path = _resolve_user_profile_path(stem)
    if path is None or not path.is_file():
        raise HTTPException(status_code=401, detail="Wrong password or username.")
    try:
        # utf-8-sig: BOM from some editors must not break the first JSON key
        with open(path, "r", encoding="utf-8-sig") as f:
            data = json.load(f)
    except Exception:
        raise HTTPException(status_code=401, detail="Wrong password or username.")
    expected = data.get("password")
    if not _password_matches(expected, body.password):
        raise HTTPException(status_code=401, detail="Wrong password or username.")
    path_str = str(path)
    # 2026-06-01 identity-leak patch: when a session_id is provided, scope
    # this active user STRICTLY to this session and DO NOT touch the
    # process-global ``vera.active_user_info_path``. The old behavior of
    # also updating the process-global field was the root cause of the
    # "VERA assumes you are Nam" leak: once any device signed in as Nam,
    # ``vera.active_user_info`` (and therefore the default profile
    # injected into every other session's chat prompt) became Nam until
    # server restart. With this change cross-session contamination is
    # impossible for the modern session-scoped sign-in path.
    if body.session_id:
        set_active_user_for_session(body.session_id, stem)
        print(
            f"[SIGN-IN] session={safe_id(body.session_id)} username={stem} "
            f"(per-session active user set; process-global LEFT UNCHANGED to "
            f"prevent cross-session identity leak)",
            flush=True,
        )
        return {
            "ok": True,
            "active_user_info_path": path_str,
            "username": stem,
            "session_scoped": True,
        }
    # Legacy / CLI / no-session-id path: keep the old process-global update
    # so single-user setups still work. Note the WARNING - this path can
    # cross-contaminate any other signed-in device on the same server.
    print(
        f"[SIGN-IN] session=<none> username={stem} "
        f"(no session_id supplied - falling back to process-global active user; "
        f"WARNING: this can cross-contaminate other signed-in devices)",
        flush=True,
    )
    vera.set_active_user_info_path(path_str)
    return {
        "ok": True,
        "active_user_info_path": path_str,
        "username": stem,
        "session_scoped": False,
    }


class UserSignOutBody(BaseModel):
    session_id: str | None = None


@app.post("/api/user/sign-out")
def api_user_sign_out(body: UserSignOutBody | None = None):
    """Reset to default (active_user_info_path None — same as Nam.json admin-as-current behavior).

    PART 7: when a session_id is supplied, only clears the per-session active
    user and leaves the process-global one alone (so other devices keep
    their session). Without a session_id, behaves like the legacy global
    sign-out.
    """
    global vera
    if vera is None:
        raise HTTPException(status_code=503, detail="Server not ready.")
    sid = (body.session_id if body and body.session_id else "") or ""
    if sid:
        set_active_user_for_session(sid, None)
        # Only reset the process-global field if no OTHER session is signed in.
        # Otherwise we'd accidentally sign out the remaining devices.
        if not _session_active_user:
            vera.set_active_user_info_path(None)
        print(
            f"[SIGN-OUT] session={safe_id(sid)} "
            f"(per-session active user cleared; remaining sessions={len(_session_active_user)})",
            flush=True,
        )
        return {"ok": True, "active_user_info_path": None, "username": None, "session_scoped": True}
    vera.set_active_user_info_path(None)
    print("[SIGN-OUT] session=<none> (process-global active user cleared)", flush=True)
    return {"ok": True, "active_user_info_path": None, "username": None, "session_scoped": False}


@app.get("/api/work-mode/checklist")
def api_work_mode_checklist_get(session_id: str):
    sid = safe_id(session_id or "")
    if not sid:
        raise HTTPException(status_code=400, detail="Missing session_id.")
    items, completed_collapsed, username = _load_checklist_state_for_session(sid)
    return {"ok": True, "username": username, "items": items, "completed_collapsed": completed_collapsed}


@app.put("/api/work-mode/checklist")
def api_work_mode_checklist_put(body: WorkChecklistSaveBody):
    sid = safe_id(body.session_id or "")
    if not sid:
        raise HTTPException(status_code=400, detail="Missing session_id.")
    before_items, before_collapsed, _ = _load_checklist_state_for_session(sid)
    before_count = len(_checklist_undo_non_empty_items(before_items))
    count, username = _save_checklist_state_for_session(
        sid,
        body.items,
        completed_collapsed=body.completed_collapsed,
    )
    if before_count > 0 and count == 0:
        _emit_undo_routing_log(
            "checklist_clear_execute_start",
            session_id=sid[:64],
            source="ui_erase",
            server_item_count_before=before_count,
            client_snapshot_item_count=0,
            client_undo_snapshot_present=False,
            pending_server_undo=bool(
                checklist_undo_snapshots.get(sid) or pending_checklist_undo_context.get(sid)
            ),
            selected_base="client_snapshot",
        )
        _emit_undo_routing_log(
            "checklist_clear_execute_done",
            session_id=sid[:64],
            source="ui_erase",
            server_item_count_before=before_count,
            result_item_count=count,
            result_titles=[],
        )
    return {"ok": True, "username": username, "items_count": count}


# =========================
# FREE MUSIC (productivity panel — static files under ./Free_music)
# Subfolders = playlists (all audio files inside, sorted by name).
# Audio files at the root of Free_music = single-track items (e.g. white noise).
# =========================

FREE_MUSIC_DIR_NAME = "Free_music"
FREE_MUSIC_AUDIO_SUFFIXES = {".mp3", ".wav", ".ogg", ".m4a", ".flac", ".opus"}
FREE_MUSIC_SOUND_TITLES = {
    "brown_noise": "Brown Noise",
    "white_noise": "White Noise",
    "rain_sound": "Rain Sounds",
}


def _free_music_normalize_key(value: str) -> str:
    key = str(value or "").strip().lower().replace("-", "_")
    key = "_".join(part for part in key.replace(" ", "_").split("_") if part)
    return key


def _free_music_sound_canonical(stem: str) -> tuple[str, str]:
    """Map on-disk stems (snake_case or human names) to stable ids + UI labels."""
    norm = _free_music_normalize_key(stem)
    aliases = {
        "brown_noise": "brown_noise",
        "brownnoise": "brown_noise",
        "brown": "brown_noise",
        "white_noise": "white_noise",
        "whitenoise": "white_noise",
        "white": "white_noise",
        "rain_sound": "rain_sound",
        "rain_sounds": "rain_sound",
        "rain_and_thunder": "rain_sound",
        "rain_and_thunder_sound": "rain_sound",
        "rainandthunder": "rain_sound",
        "thunderstorm": "rain_sound",
        "thunder": "rain_sound",
        "raining": "rain_sound",
    }
    canonical = aliases.get(norm)
    if not canonical:
        for alias, role in aliases.items():
            if norm == alias or norm.startswith(f"{alias}_"):
                canonical = role
                break
    if canonical:
        return canonical, FREE_MUSIC_SOUND_TITLES.get(canonical, stem.replace("_", " ").strip().title() or stem)
    title = stem.replace("_", " ").strip().title() or stem
    return stem, title


def _free_music_root() -> Path:
    return Path(__file__).resolve().parent / FREE_MUSIC_DIR_NAME


def _free_music_stream_path(rel: str) -> Path:
    root = _free_music_root()
    raw = urllib.parse.unquote(rel or "").strip().replace("\\", "/").lstrip("/")
    if not raw or ".." in raw.split("/"):
        raise HTTPException(status_code=400, detail="Invalid path.")
    candidate = (root / raw).resolve()
    try:
        candidate.relative_to(root.resolve())
    except ValueError as e:
        raise HTTPException(status_code=404, detail="Not found.") from e
    if not candidate.is_file():
        raise HTTPException(status_code=404, detail="Not found.")
    if candidate.suffix.lower() not in FREE_MUSIC_AUDIO_SUFFIXES:
        raise HTTPException(status_code=404, detail="Unsupported audio type.")
    return candidate


@app.get("/api/free-music/catalog")
def api_free_music_catalog():
    """List playlists (subfolders with audio) and single tracks (audio files at root)."""
    root = _free_music_root()
    playlists: list[dict] = []
    tracks: list[dict] = []
    if not root.is_dir():
        return {
            "playlists": [],
            "tracks": [],
            "hint": f"Create folder {FREE_MUSIC_DIR_NAME} next to app.py and add audio files.",
        }
    for entry in sorted(root.iterdir(), key=lambda p: p.name.lower()):
        if entry.name.startswith("."):
            continue
        if entry.is_dir():
            plist: list[dict] = []
            try:
                files = sorted(entry.iterdir(), key=lambda p: p.name.lower())
            except OSError:
                files = []
            for f in files:
                if not f.is_file() or f.suffix.lower() not in FREE_MUSIC_AUDIO_SUFFIXES:
                    continue
                rel = f"{entry.name}/{f.name}"
                plist.append(
                    {
                        "name": f.stem.replace("_", " ").strip() or f.name,
                        "filename": f.name,
                        "url": f"/api/free-music/stream?rel={urllib.parse.quote(rel, safe='')}",
                    }
                )
            if plist:
                playlists.append(
                    {
                        "id": entry.name,
                        "title": entry.name.replace("_", " ").strip().title() or entry.name,
                        "tracks": plist,
                    }
                )
        elif entry.is_file() and entry.suffix.lower() in FREE_MUSIC_AUDIO_SUFFIXES:
            rel = entry.name
            track_id, track_title = _free_music_sound_canonical(entry.stem)
            tracks.append(
                {
                    "id": track_id,
                    "title": track_title,
                    "filename": entry.name,
                    "url": f"/api/free-music/stream?rel={urllib.parse.quote(rel, safe='')}",
                }
            )
    return {"playlists": playlists, "tracks": tracks}


@app.get("/api/free-music/stream")
def api_free_music_stream(rel: str = Query(..., min_length=1, max_length=512)):
    path = _free_music_stream_path(rel)
    suffix = path.suffix.lower()
    media_type = (
        "audio/mpeg"
        if suffix == ".mp3"
        else "audio/wav"
        if suffix == ".wav"
        else "audio/ogg"
        if suffix == ".ogg"
        else "audio/mp4"
        if suffix == ".m4a"
        else "audio/flac"
        if suffix == ".flac"
        else "audio/opus"
        if suffix == ".opus"
        else "application/octet-stream"
    )
    return FileResponse(path, media_type=media_type)


