# --- Spotify user OAuth (Web Playback SDK) + play proxy ---
# user-read-playback-state: GET /me/player/devices (required so we can see the Web Playback device).
# user-modify-playback-state: transfer + start playback from the API.
# Users who connected before these scopes were added must Disconnect and Connect Spotify again.
SPOTIFY_USER_SCOPES = (
    "streaming user-read-email user-read-private "
    "user-read-playback-state user-modify-playback-state "
    "playlist-read-private playlist-read-collaborative"
)
# Popup completes OAuth on API host; opener (GitHub Pages) often cannot send session cookies (third-party blocks).
# Handoff + Bearer lets the opener claim Spotify without relying on cross-site cookies.
SPOTIFY_HANDOFFS: dict[str, dict] = {}
SPOTIFY_BEARER_TOKENS: dict[str, dict] = {}
SPOTIFY_HANDOFF_TTL_SEC = 600.0

_spotify_bearer_disk_lock = threading.Lock()


def _spotify_bearer_store_path() -> Path:
    raw = os.environ.get("VERA_SPOTIFY_BEARER_STORE", "").strip()
    if raw:
        return Path(raw)
    return _ENV_FILE.parent / ".vera_spotify_bearers.json"


def _load_spotify_bearer_disk() -> None:
    """Restore cross-tab Spotify bearer sessions after API restart (refresh tokens on disk)."""
    path = _spotify_bearer_store_path()
    if not path.is_file():
        return
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
        bearers = data.get("bearers")
        if not isinstance(bearers, dict):
            return
        n = 0
        for k, v in bearers.items():
            if not isinstance(k, str) or not isinstance(v, dict):
                continue
            rt = v.get("rt")
            if not rt:
                continue
            SPOTIFY_BEARER_TOKENS[k] = {
                "rt": str(rt),
                "at": v.get("at"),
                "exp": float(v.get("exp") or 0),
            }
            n += 1
        if n:
            print(f"[Spotify] Restored {n} bearer session(s) from {path}")
    except Exception as e:
        print(f"[Spotify] Could not load bearer store {path}: {e}")


def _persist_spotify_bearer_disk() -> None:
    path = _spotify_bearer_store_path()
    tmp = path.with_suffix(path.suffix + ".tmp")
    payload = json.dumps({"bearers": SPOTIFY_BEARER_TOKENS}, ensure_ascii=False, indent=0)
    with _spotify_bearer_disk_lock:
        try:
            tmp.write_text(payload, encoding="utf-8")
            tmp.replace(path)
        except OSError as e:
            print(f"[Spotify] Could not persist bearer store {path}: {e}")


_load_spotify_bearer_disk()


def _spotify_oauth_app_redirect(params: dict[str, str]) -> str:
    """
    After /auth/spotify/callback, redirect here. Default is /?spotify_*=… on the API host.
    Set SPOTIFY_OAUTH_RETURN_URL (e.g. https://you.github.io/Online_demo) so GitHub Pages users
    land on the static site with ?spotify_connected=1 instead of the Worker root.
    """
    base = os.environ.get("SPOTIFY_OAUTH_RETURN_URL", "").strip().rstrip("/")
    qs = urllib.parse.urlencode(params)
    if not base:
        return f"/?{qs}"
    return f"{base}/?{qs}"


def _spotify_request_public_host(request: Request) -> str:
    raw = (request.headers.get("x-vera-public-host") or "").split(",")[0].strip()
    if raw:
        return raw.split(":")[0].lower()
    return (request.headers.get("host") or "").split(":")[0].lower()


def _warn_if_spotify_login_host_differs_from_redirect_uri(request: Request) -> None:
    """Session cookie is set on the host that serves /auth/spotify/login; callback must hit the same site."""
    ru = os.environ.get("SPOTIFY_REDIRECT_URI", "").strip()
    if not ru:
        return
    try:
        pu = urllib.parse.urlparse(ru)
        rh = (pu.hostname or "").lower()
    except Exception:
        return
    h = _spotify_request_public_host(request)
    if not h or not rh:
        return
    if h != rh:
        logging.warning(
            "Spotify OAuth: /auth/spotify/login was opened on host %r but SPOTIFY_REDIRECT_URI is on %r. "
            "Spotify will redirect the browser to %r for /auth/spotify/callback without this session → invalid_state. "
            "Fix: start Connect from the same origin as SPOTIFY_REDIRECT_URI (e.g. GitHub Pages + Worker URL in app.js), "
            "or set SPOTIFY_REDIRECT_URI=http://127.0.0.1:8000/auth/spotify/callback and use only http://127.0.0.1:8000 for Connect.",
            h,
            rh,
            rh,
        )


def _validate_spotify_opener_origin(raw: str) -> str | None:
    """
    Origin of the tab that opened OAuth (for postMessage after callback). Tight allowlist.
    """
    s = (raw or "").strip()
    if not s:
        return None
    try:
        p = urllib.parse.urlparse(s)
    except Exception:
        return None
    if p.scheme not in ("http", "https"):
        return None
    host = (p.hostname or "").lower()
    if not host:
        return None
    netloc = (p.netloc or "").lower()
    allowed = (
        host in ("localhost", "127.0.0.1")
        or host.endswith(".github.io")
        or host == "github.io"
        or host == "workwithvera.com"
        or host.endswith(".workwithvera.com")
    )
    if not allowed:
        return None
    return f"{p.scheme}://{netloc}"


def _spotify_oauth_finish_redirect(request: Request, *, error: str | None = None) -> RedirectResponse:
    """If popup flow stored an opener origin, finish on API host with postMessage; else redirect to app URL."""
    if request.session.get("spotify_oauth_opener_origin"):
        if error:
            q = urllib.parse.urlencode({"error": error})
            return RedirectResponse(f"/auth/spotify/oauth-complete?{q}")
        return RedirectResponse("/auth/spotify/oauth-complete")
    if error:
        return RedirectResponse(_spotify_oauth_app_redirect({"spotify_error": error}))
    return RedirectResponse(_spotify_oauth_app_redirect({"spotify_connected": "1"}))


def _spotify_redirect_uri(request: Request | None = None) -> str:
    """OAuth redirect_uri must match Spotify Dashboard and the URL the browser hits for /auth/spotify/callback."""
    u = os.environ.get("SPOTIFY_REDIRECT_URI", "").strip()
    if u:
        return u
    if request is not None:
        hdr = request.headers
        # Worker sets these; some tunnels strip X-Forwarded-Host before uvicorn.
        raw_host = hdr.get("x-vera-public-host") or hdr.get("x-forwarded-host") or ""
        pub_host = raw_host.split(",")[0].strip()
        if pub_host:
            pub_proto = (
                hdr.get("x-vera-public-proto") or hdr.get("x-forwarded-proto") or ""
            ).split(",")[0].strip().lower()
            scheme = pub_proto or "https"
            return f"{scheme}://{pub_host}/auth/spotify/callback"
    return "http://127.0.0.1:8000/auth/spotify/callback"


def _spotify_post_token(form: dict) -> dict:
    cid = os.environ.get("SPOTIFY_CLIENT_ID", "").strip()
    secret = os.environ.get("SPOTIFY_CLIENT_SECRET", "").strip()
    if not cid or not secret:
        raise HTTPException(503, detail="Spotify app credentials missing (SPOTIFY_CLIENT_ID / SPOTIFY_CLIENT_SECRET).")
    auth = base64.b64encode(f"{cid}:{secret}".encode()).decode()
    data = urllib.parse.urlencode(form).encode()
    req = urllib.request.Request(
        "https://accounts.spotify.com/api/token",
        data=data,
        method="POST",
        headers={
            "Authorization": f"Basic {auth}",
            "Content-Type": "application/x-www-form-urlencoded",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=25) as resp:
            return json.loads(resp.read().decode())
    except urllib.error.HTTPError as e:
        err = e.read().decode() if e.fp else ""
        raise HTTPException(502, detail=f"Spotify token error: {err or e.code}") from e


def _spotify_auth_header_bearer(request: Request) -> str | None:
    auth = (request.headers.get("authorization") or "").strip()
    if not auth.lower().startswith("bearer "):
        return None
    return auth[7:].strip() or None


def _spotify_get_creds(request: Request) -> tuple[str | None, dict] | None:
    bk = _spotify_auth_header_bearer(request)
    if bk and bk in SPOTIFY_BEARER_TOKENS:
        return bk, dict(SPOTIFY_BEARER_TOKENS[bk])
    rt = request.session.get("spotify_refresh_token")
    if rt:
        return None, {
            "rt": rt,
            "at": request.session.get("spotify_access_token"),
            "exp": float(request.session.get("spotify_expires_at") or 0),
        }
    return None


def _spotify_set_creds(request: Request, bearer_key: str | None, rt: str, at: str, exp: float) -> None:
    if bearer_key is not None:
        SPOTIFY_BEARER_TOKENS[bearer_key] = {"rt": rt, "at": at, "exp": exp}
        _persist_spotify_bearer_disk()
    else:
        request.session["spotify_refresh_token"] = rt
        request.session["spotify_access_token"] = at
        request.session["spotify_expires_at"] = exp


def _ensure_spotify_user_access_token(request: Request) -> str:
    now = time()
    got = _spotify_get_creds(request)
    if not got:
        raise HTTPException(401, detail="Not connected to Spotify. Use Connect Spotify first (Premium required).")
    bearer_key, creds = got
    exp = float(creds.get("exp") or 0)
    access = creds.get("at")
    if access and exp > now + 90:
        return str(access)
    rt = creds.get("rt")
    if not rt:
        raise HTTPException(401, detail="Not connected to Spotify. Use Connect Spotify first (Premium required).")
    body = _spotify_post_token(
        {"grant_type": "refresh_token", "refresh_token": str(rt)}
    )
    new_at = body.get("access_token")
    if not new_at:
        if bearer_key:
            SPOTIFY_BEARER_TOKENS.pop(bearer_key, None)
            _persist_spotify_bearer_disk()
        else:
            request.session.pop("spotify_refresh_token", None)
        raise HTTPException(401, detail="Spotify session expired. Connect again.")
    new_exp = now + float(body.get("expires_in", 3600))
    new_rt = body.get("refresh_token") or rt
    _spotify_set_creds(request, bearer_key, new_rt, new_at, new_exp)
    return str(new_at)


@app.get("/auth/spotify/login")
def spotify_oauth_login(request: Request, opener_origin: str | None = None):
    cid = os.environ.get("SPOTIFY_CLIENT_ID", "").strip()
    if not cid:
        raise HTTPException(503, detail="SPOTIFY_CLIENT_ID not configured.")
    oo = _validate_spotify_opener_origin(opener_origin or "")
    if oo:
        request.session["spotify_oauth_opener_origin"] = oo
    else:
        request.session.pop("spotify_oauth_opener_origin", None)
    state = secrets.token_urlsafe(16)
    request.session["spotify_oauth_state"] = state
    redirect_uri = _spotify_redirect_uri(request)
    params = urllib.parse.urlencode(
        {
            "response_type": "code",
            "client_id": cid,
            "scope": SPOTIFY_USER_SCOPES,
            "redirect_uri": redirect_uri,
            "state": state,
        }
    )
    _warn_if_spotify_login_host_differs_from_redirect_uri(request)
    return RedirectResponse(f"https://accounts.spotify.com/authorize?{params}")


@app.get("/auth/spotify/callback")
def spotify_oauth_callback(
    request: Request,
    code: str | None = None,
    state: str | None = None,
    error: str | None = None,
):
    if error:
        return _spotify_oauth_finish_redirect(request, error=error)
    expected = request.session.get("spotify_oauth_state")
    request.session.pop("spotify_oauth_state", None)
    if not state or state != expected:
        logging.warning(
            "Spotify OAuth invalid_state: cookie_state=%s query_state=%s host=%s "
            "(open /auth/spotify/login on the SAME host as SPOTIFY_REDIRECT_URI)",
            "missing" if expected is None else "mismatch",
            state,
            _spotify_request_public_host(request),
        )
        return _spotify_oauth_finish_redirect(request, error="invalid_state")
    if not code:
        return _spotify_oauth_finish_redirect(request, error="missing_code")
    redirect_uri = _spotify_redirect_uri(request)
    try:
        body = _spotify_post_token(
            {
                "grant_type": "authorization_code",
                "code": code,
                "redirect_uri": redirect_uri,
            }
        )
    except HTTPException:
        return _spotify_oauth_finish_redirect(request, error="token_exchange_failed")
    rt = body.get("refresh_token")
    at = body.get("access_token")
    if not rt or not at:
        return _spotify_oauth_finish_redirect(request, error="no_refresh_token")
    exp = time() + float(body.get("expires_in", 3600))
    request.session["spotify_refresh_token"] = rt
    request.session["spotify_access_token"] = at
    request.session["spotify_expires_at"] = exp
    handoff = secrets.token_urlsafe(32)
    SPOTIFY_HANDOFFS[handoff] = {
        "rt": rt,
        "at": at,
        "exp": exp,
        "created_at": time(),
    }
    request.session["spotify_oauth_handoff"] = handoff
    return _spotify_oauth_finish_redirect(request, error=None)


@app.get("/auth/spotify/oauth-complete")
def spotify_oauth_complete_page(request: Request, error: str | None = None):
    """
    Loaded in the OAuth popup tab: postMessage to opener (GitHub Pages / local) then window.close().
    """
    opener = request.session.pop("spotify_oauth_opener_origin", None)
    handoff = request.session.pop("spotify_oauth_handoff", None)
    if not opener:
        if error:
            return RedirectResponse(_spotify_oauth_app_redirect({"spotify_error": error}))
        return RedirectResponse(_spotify_oauth_app_redirect({"spotify_connected": "1"}))
    err_js = json.dumps(error) if error else "null"
    ok_js = "false" if error else "true"
    handoff_js = json.dumps(handoff) if (handoff and not error) else "null"
    html = f"""<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/><title>Spotify</title></head>
<body>
<script>
(function() {{
  var err = {err_js};
  try {{
    if (window.opener && !window.opener.closed) {{
      var msg = {{ type: "vera-spotify-oauth", ok: {ok_js}, error: err, handoff: {handoff_js} }};
      window.opener.postMessage(msg, "*");
    }}
  }} catch (e) {{}}
  try {{ window.close(); }} catch (e) {{}}
}})();
</script>
<p style="font-family:system-ui,sans-serif;padding:1rem;color:#ccc;background:#111;margin:0;min-height:100vh;">You can close this tab and return to VERA.</p>
</body></html>"""
    return HTMLResponse(html)


@app.get("/{locale}/login/google")
def spotify_accounts_shim_google_login(locale: str, request: Request):
    """
    Spotify login sometimes resolves /{locale}/login/google against the redirect_uri host
    instead of accounts.spotify.com. Send the browser to the real accounts page.
    """
    if len(locale) != 2 or not locale.isalpha():
        raise HTTPException(404)
    loc = locale.lower()
    qs = request.url.query
    url = f"https://accounts.spotify.com/{loc}/login/google"
    if qs:
        url = f"{url}?{qs}"
    return RedirectResponse(url, status_code=302)


def _parse_form_fields_from_body(body: bytes, content_type: str) -> list[tuple[str, str]]:
    ct = (content_type or "").lower()
    fields: list[tuple[str, str]] = []
    if "application/json" in ct and body:
        try:
            data = json.loads(body.decode("utf-8"))
            if isinstance(data, dict):
                for k, v in data.items():
                    if isinstance(v, (dict, list)):
                        val = json.dumps(v)
                    else:
                        val = "" if v is None else str(v)
                    fields.append((str(k), val))
        except (json.JSONDecodeError, UnicodeDecodeError):
            pass
    elif "application/x-www-form-urlencoded" in ct and body:
        for k, vals in urllib.parse.parse_qs(body.decode("utf-8", errors="replace")).items():
            for v in vals:
                fields.append((k, v))
    return fields


async def _parse_form_fields_from_request(request: Request) -> list[tuple[str, str]]:
    ct = (request.headers.get("content-type") or "").lower()
    if "multipart/form-data" in ct:
        form = await request.form()
        out: list[tuple[str, str]] = []
        for k, v in form.multi_items():
            if isinstance(v, str):
                out.append((k, v))
            else:
                try:
                    raw = await v.read()
                    out.append((k, raw.decode("utf-8", errors="replace") if raw else ""))
                except Exception:
                    out.append((k, ""))
        return out
    body = await request.body()
    return _parse_form_fields_from_body(body, ct)


def _spotify_proxy_cors_headers(request: Request) -> dict[str, str]:
    """Credentialed fetch from accounts.spotify.com requires a specific Allow-Origin, not *."""
    origin = (request.headers.get("origin") or "").strip()
    h: dict[str, str] = {"Access-Control-Expose-Headers": "*"}
    if origin in ("https://accounts.spotify.com", "https://open.spotify.com"):
        h["Access-Control-Allow-Origin"] = origin
        h["Access-Control-Allow-Credentials"] = "true"
    elif origin:
        h["Access-Control-Allow-Origin"] = origin
    else:
        h["Access-Control-Allow-Origin"] = "*"
    return h


def _html_form_auto_post_to(action_url: str, fields: list[tuple[str, str]], title: str) -> str:
    """POST form in-browser so third-party cookies (Spotify/Google) are sent."""
    inputs = "".join(
        f'<input type="hidden" name="{html_module.escape(name)}" value="{html_module.escape(val)}"/>'
        for name, val in fields
    )
    return f"""<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8"/><title>{html_module.escape(title)}</title></head>
<body>
<form id="ext-post" method="post" action="{html_module.escape(action_url)}" enctype="application/x-www-form-urlencoded">
{inputs}
</form>
<script>document.getElementById("ext-post").submit();</script>
<noscript><button type="submit">Continue</button></noscript>
</body></html>"""


@app.options("/login/otc/start")
async def spotify_accounts_shim_otc_options(request: Request):
    """CORS preflight for credentialed fetch from accounts.spotify.com to the redirect host."""
    ach = request.headers.get("access-control-request-headers", "*")
    h = {
        **_spotify_proxy_cors_headers(request),
        "Access-Control-Allow-Methods": "POST, OPTIONS",
        "Access-Control-Allow-Headers": ach,
        "Access-Control-Max-Age": "86400",
    }
    return Response(status_code=204, headers=h)


@app.post("/login/otc/start")
async def spotify_accounts_shim_otc_start(request: Request):
    """
    Spotify POSTs here (redirect_uri host). A server-side proxy cannot send Spotify
    session cookies, so Spotify returns 400 {"error":"errorUnknown"}. Respond with 307
    Temporary Redirect so the browser re-POSTs to accounts.spotify.com with the same
    body and first-party cookies (RFC 7231). fetch() follows and reads Spotify's JSON.
    """
    otc = "https://accounts.spotify.com/login/otc/start"
    if request.url.query:
        otc = f"{otc}?{request.url.query}"
    return Response(
        status_code=307,
        headers={"Location": otc, **_spotify_proxy_cors_headers(request)},
    )


@app.api_route("/v3/signin/{path:path}", methods=["GET", "POST", "OPTIONS"])
async def google_accounts_v3_signin_shim(path: str, request: Request):
    """
    Spotify/Google sign-in sometimes POSTs /v3/signin/... to the OAuth redirect host.
    Forward to accounts.google.com so the browser sends Google cookies.
    """
    if request.method == "OPTIONS":
        return Response(
            status_code=204,
            headers={
                "Access-Control-Allow-Origin": "*",
                "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
                "Access-Control-Allow-Headers": "*",
            },
        )
    # CSP violation reports (JSON) are mis-posted to the redirect_uri host; do not
    # return HTML form replay (breaks reporting and can confuse the sign-in page).
    if "cspreport" in path.lower():
        return Response(
            status_code=204,
            headers={"Access-Control-Allow-Origin": "*"},
        )
    target = f"https://accounts.google.com/v3/signin/{path}"
    if request.url.query:
        target = f"{target}?{request.url.query}"
    if request.method == "GET":
        return RedirectResponse(target, status_code=302)
    fields = await _parse_form_fields_from_request(request)
    page = _html_form_auto_post_to(target, fields, "Continue to Google")
    return Response(content=page, status_code=200, media_type="text/html; charset=utf-8")


@app.api_route("/google", methods=["GET", "POST", "HEAD", "OPTIONS"])
async def google_accounts_shim_root_google(request: Request):
    """
    Spotify sometimes links https://{redirect_uri host}/google?continue=... (not under /v3/signin/).
    Without this route, StaticFiles at / can serve the wrong document so the page stays on the
    Worker origin and Google scripts fail CSP/CORS.
    """
    if request.method == "OPTIONS":
        return Response(
            status_code=204,
            headers={
                "Access-Control-Allow-Origin": "*",
                "Access-Control-Allow-Methods": "GET, POST, HEAD, OPTIONS",
                "Access-Control-Allow-Headers": "*",
            },
        )
    qs = request.url.query
    base = "https://accounts.google.com/v3/signin/identifier"
    target = f"{base}?{qs}" if qs else base
    if request.method in ("GET", "HEAD"):
        return RedirectResponse(target, status_code=302)
    fields = await _parse_form_fields_from_request(request)
    page = _html_form_auto_post_to(target, fields, "Continue to Google")
    return Response(content=page, status_code=200, media_type="text/html; charset=utf-8")


