class SpotifyClaimHandoffBody(BaseModel):
    handoff: str


@app.post("/api/spotify/claim-handoff")
def api_spotify_claim_handoff(request: Request, body: SpotifyClaimHandoffBody):
    """Opener tab exchanges one-time handoff from oauth-complete for a Bearer token (no third-party cookie needed)."""
    key = (body.handoff or "").strip()
    data = SPOTIFY_HANDOFFS.pop(key, None)
    if not data:
        raise HTTPException(400, detail="invalid or expired handoff")
    if time() - float(data.get("created_at", 0)) > SPOTIFY_HANDOFF_TTL_SEC:
        raise HTTPException(400, detail="handoff expired")
    rt = data["rt"]
    at = data["at"]
    exp = float(data["exp"])
    request.session["spotify_refresh_token"] = rt
    request.session["spotify_access_token"] = at
    request.session["spotify_expires_at"] = exp
    bearer = secrets.token_urlsafe(32)
    SPOTIFY_BEARER_TOKENS[bearer] = {"rt": rt, "at": at, "exp": exp}
    _persist_spotify_bearer_disk()
    return {"ok": True, "bearer": bearer}


