@app.post("/api/spotify/logout")
def api_spotify_logout(request: Request):
    bk = _spotify_auth_header_bearer(request)
    if bk and bk in SPOTIFY_BEARER_TOKENS:
        SPOTIFY_BEARER_TOKENS.pop(bk, None)
        _persist_spotify_bearer_disk()
    request.session.pop("spotify_refresh_token", None)
    request.session.pop("spotify_access_token", None)
    request.session.pop("spotify_expires_at", None)
    return {"ok": True}


# =========================
# WORK MODE — reasoning LLM + classifier (separate from main VERA)
# =========================


class WorkModeTextPayload(BaseModel):
    session_id: str
    text: str
    lane_id: Optional[str] = None
    """When set, classifier may mark the new `text` as continuing the same panel/thread as this prior user line."""
    anchor_for_thread: Optional[str] = None
    """Visible panel + registry excerpt from the browser (same shape as upload merge block)."""
    work_mode_lane_client_context: Optional[str] = None
    """Structured voice → panel handoff packet from the browser (Phase 1)."""
    voice_to_panel_context: Optional[dict] = None


class WorkModePanelTitlePayload(BaseModel):
    session_id: str
    user_prompt: str = ""
    markdown_excerpt: str = ""
    summary_excerpt: str = ""


class WorkModeVoiceFinalBriefPayload(BaseModel):
    session_id: str
    user_text: str
    panel_markdown: str
    turn_id: Optional[str] = None
    lane_id: Optional[str] = None
    lane_title: Optional[str] = None
    stream_lane_id: Optional[str] = None


def _validate_voice_final_brief_scope(
    *,
    turn_id: str | None,
    lane_id: str | None,
    stream_lane_id: str | None,
    panel_markdown: str | None = None,
) -> tuple[bool, str]:
    """Return (scope_ok, skip_reason). Frontend is authoritative; server mirrors checks."""
    tid = str(turn_id or "").strip()
    lid = str(lane_id or "").strip()
    stream = str(stream_lane_id or lane_id or "").strip()
    if lid and stream and lid != stream:
        return False, "frozen_stream_lane_mismatch"
    if not tid:
        return False, "missing_turn_id"
    md = str(panel_markdown or "").strip()
    if len(md) < 24:
        return False, "panel_markdown_too_short"
    return True, ""


