WORK_MODE_UPLOAD_MAX_BYTES = 25 * 1024 * 1024


def _normalize_reasoning_lane_id(raw_lane_id: str | None) -> str:
    lane = str(raw_lane_id or "").strip().lower()
    if re.match(r"^wm_lane_\d{3}$", lane):
        return lane
    if lane in {"atlas", "echo", "nova"}:
        return lane
    if lane in {"0", "thread_1", "thread-1", "thread 1", "panel_1", "panel-1", "panel 1"}:
        return "atlas"
    if lane in {"1", "thread_2", "thread-2", "thread 2", "panel_2", "panel-2", "panel 2"}:
        return "echo"
    if lane in {"2", "thread_3", "thread-3", "thread 3", "panel_3", "panel-3", "panel 3"}:
        return "nova"
    return lane or "atlas"


def _reasoning_lane_history_key(session_id: str, lane_id: str) -> str:
    return f"{session_id}:{lane_id}"


def _reasoning_tokens(text: str) -> set[str]:
    stop = {
        "the", "and", "for", "with", "that", "this", "from", "into", "your", "you",
        "what", "when", "where", "which", "about", "have", "has", "had", "can",
        "could", "would", "should", "then", "than", "just", "more", "most", "some",
        "any", "using", "use", "used", "also", "very", "much", "yes", "yeah", "yep",
        "sure", "help", "okay", "show", "example", "examples", "please", "briefly",
        "quickly", "explain", "answer", "question", "first", "second", "third", "problem",
        "part", "same", "thing", "like",
    }
    toks = {t for t in re.findall(r"[a-z0-9]{3,}", (text or "").lower())}
    return {t for t in toks if t not in stop}


def _is_generic_example_request(user_text: str) -> bool:
    """True when the user asks for an example without naming a new topic.

    Uses phrasing-based detection (not only fixed substrings) so natural forms like
    "can you give me an example" still match — those must route to last-turn context
    instead of unrelated-memory token overlap.
    """
    t = (user_text or "").strip().lower()
    if not t:
        return False
    if re.search(
        r"\b("
        r"show(\s+me)?\s+an?\s+example|"
        r"give(\s+me)?\s+an?\s+example|"
        r"(can|could)\s+you\s+(show|give)(\s+me)?\s+an?\s+example|"
        r"example\s+of\s+that|"
        r"example\s+please|"
        r"(another|one more)\s+example"
        r")\b",
        t,
    ):
        return True
    return bool(re.search(r"\b(need|want|got)\s+an?\s+example\b", t))


def _has_explicit_cross_thread_reference(user_text: str) -> bool:
    t = (user_text or "").strip().lower()
    if not t:
        return False
    return bool(
        re.search(r"\b(thread\s*[123]|panel\s*[123]|atlas|echo|nova)\b", t)
        or re.search(r"\b(previous thread|other thread|earlier thread)\b", t)
    )


def _last_reasoning_memory_message(session_id: str) -> list[dict]:
    entries = reasoning_global_memory.get(session_id) or []
    if not entries:
        return []
    last = entries[-1]
    mem_text = str(last.get("memory", "")).strip()
    if not mem_text:
        return []
    return [{"role": "assistant", "content": f"[Last turn context] {mem_text[:900]}"}]


def _related_reasoning_memory_messages(session_id: str, user_text: str, max_items: int = 2) -> list[dict]:
    if not _has_explicit_cross_thread_reference(user_text):
        return []
    entries = reasoning_global_memory.get(session_id) or []
    if not entries:
        return []
    q = _reasoning_tokens(user_text)
    if len(q) < 2:
        return []
    scored: list[tuple[float, str]] = []
    for e in entries:
        mem_text = str(e.get("memory", "")).strip()
        if not mem_text:
            continue
        t = _reasoning_tokens(mem_text)
        if not t:
            continue
        shared = q & t
        overlap = len(shared) / float(len(q | t))
        # Keep only actually related snippets to prevent cross-topic bleed.
        if overlap >= 0.22 and len(shared) >= 2:
            scored.append((overlap, mem_text[:900]))
    scored.sort(key=lambda x: x[0], reverse=True)
    out = []
    for _, text in scored[:max_items]:
        out.append({"role": "assistant", "content": f"[Related prior context] {text}"})
    return out


def _append_reasoning_turn_memory(
    session_id: str,
    lane_id: str,
    user_text: str,
    summary_text: str,
) -> None:
    lane_key = _reasoning_lane_history_key(session_id, lane_id)
    lane_history = reasoning_lane_histories[lane_key]
    if user_text.strip():
        lane_history.append({"role": "user", "content": user_text.strip()[:2500]})
    if summary_text.strip():
        lane_history.append({"role": "assistant", "content": summary_text.strip()[:2500]})
    if len(lane_history) > MAX_TURNS * 2:
        lane_history[:] = lane_history[-MAX_TURNS * 2 :]

    if user_text.strip() or summary_text.strip():
        reasoning_global_memory[session_id].append(
            {
                "lane_id": lane_id,
                "memory": f"{user_text.strip()[:400]} {summary_text.strip()[:500]}".strip(),
                "ts": time(),
            }
        )
        if len(reasoning_global_memory[session_id]) > 60:
            reasoning_global_memory[session_id] = reasoning_global_memory[session_id][-60:]


def _work_mode_touch_session(session_id: str) -> str:
    sid = safe_id(session_id)
    cleanup_sessions()
    if sid not in user_last_seen and len(user_last_seen) >= MAX_ACTIVE_USERS:
        raise HTTPException(429, "Server at capacity")
    user_last_seen[sid] = time()
    total_sessions_seen.add(sid)
    return sid


@app.post("/work_mode/voice_final_brief")
async def work_mode_voice_final_brief(request: Request, data: WorkModeVoiceFinalBriefPayload):
    """Phase A: grounded Voice UI final brief from completed panel markdown (not main /infer)."""
    try:
        from auth.request_auth import bind_request_auth_user

        bind_request_auth_user(request)
    except Exception:
        pass
    sid = _work_mode_touch_session(data.session_id)
    if reasoning_ai is None:
        raise HTTPException(503, "Reasoning model not loaded")

    user_text = (data.user_text or "").strip()
    panel_md = (data.panel_markdown or "").strip()
    turn_id = (data.turn_id or "").strip() or None
    lane_id = _normalize_reasoning_lane_id(data.lane_id) if data.lane_id else None
    stream_lane_id = (
        _normalize_reasoning_lane_id(data.stream_lane_id) if data.stream_lane_id else lane_id
    )
    lane_title = (data.lane_title or "").strip() or None

    _log_voice_panel_contract_server(
        {
            "turn_id": turn_id,
            "lane_id": lane_id,
            "user_text": user_text[:240],
        }
    )
    _log_lane_handoff_server(
        {
            "turn_id": turn_id,
            "frozen_lane_id": lane_id,
            "stream_lane_id": stream_lane_id,
            "active_dom_lane_id": None,
            "mismatch": bool(lane_id and stream_lane_id and lane_id != stream_lane_id),
        }
    )

    scope_ok, skip_reason = _validate_voice_final_brief_scope(
        turn_id=turn_id,
        lane_id=lane_id,
        stream_lane_id=stream_lane_id,
        panel_markdown=panel_md,
    )
    if not scope_ok:
        _log_voice_final_brief(
            {
                "turn_id": turn_id,
                "lane_id": lane_id,
                "skipped": True,
                "skip_reason": skip_reason,
                "source": "panel_markdown",
                "excerpt_length": len(panel_md),
                "brief_preview": "",
            }
        )
        return {
            "brief": "",
            "skipped": True,
            "skip_reason": skip_reason,
            "source": "panel_markdown",
        }

    if not user_text:
        raise HTTPException(400, "Empty user_text")

    try:
        _enforce_usage_credit_cap(
            "work_mode_voice_summary",
            session_id=sid,
            feature_type="work_mode",
            precharge_credits=2,
        )
    except HTTPException:
        raise

    try:
        brief = await asyncio.to_thread(
            reasoning_ai.summarize_panel_for_voice,
            user_text,
            panel_md,
            lane_title,
        )
    except Exception as e:
        print(f"[WORK_MODE/voice_final_brief] error: {e}")
        raise HTTPException(500, "Voice final brief failed") from e

    _log_voice_final_brief(
        {
            "turn_id": turn_id,
            "lane_id": lane_id,
            "skipped": False,
            "source": "panel_markdown",
            "excerpt_length": len(panel_md),
            "brief_preview": (brief or "")[:240],
        }
    )
    return {
        "brief": brief,
        "skipped": False,
        "source": "panel_markdown",
        "excerpt_length": len(panel_md),
    }


@app.post("/work_mode/classify")
async def work_mode_classify(data: WorkModeTextPayload):
    _work_mode_touch_session(data.session_id)
    if reasoning_ai is None:
        raise HTTPException(503, "Reasoning model not loaded")
    text = data.text.strip()
    if not text:
        raise HTTPException(400, "Empty text")
    try:
        route = await asyncio.to_thread(reasoning_ai.classify_route_reasoning, text)
    except Exception as e:
        print(f"[WORK_MODE/classify] error: {e}")
        raise HTTPException(500, "Classifier failed") from e
    out = {
        # Legacy keys — frontend already consumes these.
        "reasoning": bool(route.get("prompt_reasoning")),
        "prompt_reasoning": bool(route.get("prompt_reasoning")),
        "category": route.get("category", "none"),
        "confidence": float(route.get("confidence", 0.0)),
        "continue_prior_lane": False,
        # New 2026-05-29 reasoning-gate keys.
        "route": route.get("route") or ("reasoning_panel" if route.get("prompt_reasoning") else "voice_ui"),
        "reason": route.get("reason") or "",
        "resolved_topic": route.get("resolved_topic"),
        "target_panel": route.get("target_panel"),
        "source": route.get("source") or "backend_unknown",
    }
    anchor = (data.anchor_for_thread or "").strip()
    if anchor and anchor.lower() != text.lower():
        try:
            cont = await asyncio.to_thread(
                reasoning_ai.classify_thread_continuation, anchor, text
            )
            out["continue_prior_lane"] = bool(cont.get("continue_prior_lane"))
        except Exception as e:
            print(f"[WORK_MODE/classify] thread continuation error: {e}")
            out["continue_prior_lane"] = False
    return out


# ---------------------------------------------------------------------------
# 2026-05-29 spec — POST /debug/reasoning_gate
#
# Dry-run reasoning-gate endpoint used by run_reasoning_gate_tests.py to
# batch-test whether a given utterance enters the reasoning panel.
#
# Mirrors CHAT_REASONING.classify_route_reasoning EXACTLY for the
# deterministic short-circuits (explicit panel reference / brief modifier
# / simple definition / artifact verbs / explain-with-complexity), and
# uses the LLM fallback only when no deterministic branch fires AND a
# reasoning model is loaded. If no model is loaded we still return a
# response; the "reason" field is stamped "no_llm_model_available" so the
# caller can tell the gate ran without the LLM tier.
#
# Additional pronoun-resolution rule (only the debug endpoint enforces it,
# because production /infer/text paths already resolve via
# workModeLastSubstantiveUserText on the frontend):
#
#   * If the explicit-panel match captured a "this|that|it" pronoun
#     instead of a concrete topic, and previous_user_text was supplied,
#     return route="reasoning_panel" with resolved_topic=previous_user_text
#     and prior_topic_used=true.
#   * If the explicit-panel match was pronoun-only and no
#     previous_user_text was supplied, return route="clarification" so the
#     test runner can verify the production frontend would have prompted
#     the user. This is the only place "clarification" ever fires.
#
# The endpoint NEVER opens a reasoning stream, NEVER mutates any panel,
# NEVER plays audio, NEVER touches the session checklist or timer.
# ---------------------------------------------------------------------------

_REASONING_DEBUG_PRONOUN_RE = re.compile(r"\b(this|that|it|them)\b", re.IGNORECASE)


def _resolve_reasoning_debug_payload(
    text: str,
    previous_user_text: str,
    active_work_mode: bool,
    active_panel_index: Optional[int],
) -> dict:
    """Compute the full ``[reasoning_gate_debug]`` payload for ``text``.

    Pure function — no network, no panel mutation, no audio. Reuses the
    reasoning model's deterministic short-circuits when one is loaded;
    falls back to a regex-only mirror otherwise so tests can run without
    the LLM.
    """
    safe_text = (text or "").strip()
    safe_prev = (previous_user_text or "").strip()
    base_diag: dict = {
        "reasoning_gate_called": True,
        "explicit_panel_reference": False,
        "simple_definition_detected": False,
        "brief_explanation_detected": False,
        "broad_complex_topic_detected": False,
        "complex_task_detected": False,
        "active_work_mode": bool(active_work_mode),
        "prior_topic_used": False,
        "resolved_topic": None,
        "route_source": "backend_debug",
    }

    if not safe_text:
        base_diag["reasoning_gate_result"] = "voice_ui"
        base_diag["reasoning_gate_reason"] = "empty_text"
        return {
            "text": safe_text,
            "route": "voice_ui",
            "reason": "empty_text",
            "resolved_topic": None,
            "target_panel": None,
            "prompt_reasoning": False,
            "active_panel_index": active_panel_index,
            "previous_user_text": safe_prev,
            "diagnostics": base_diag,
        }

    explicit_pronoun_topic = None
    explicit_pronoun_target = None
    if reasoning_ai is not None:
        try:
            panel_ref = reasoning_ai._detect_explicit_reasoning_panel_reference(safe_text)  # noqa: SLF001 — diagnostic
        except Exception:
            panel_ref = {"matched": False, "topic": None, "target_panel": None}
    else:
        panel_ref = {"matched": False, "topic": None, "target_panel": None}
        if re.search(
            r"\b(?:in|into|using|on|via|inside)\s+(?:the\s+)?"
            r"(?:reasoning\s+)?(?:panel|tab|space|page|work\s*mode)\b",
            safe_text,
            re.IGNORECASE,
        ):
            panel_ref = {"matched": True, "topic": None, "target_panel": None}
        m_panel_num = re.search(r"\bpanel\s+(\d+)\b", safe_text, re.IGNORECASE)
        if m_panel_num:
            try:
                panel_ref["target_panel"] = int(m_panel_num.group(1))
                panel_ref["matched"] = True
            except Exception:
                pass

    if panel_ref.get("matched"):
        explicit_pronoun_topic = panel_ref.get("topic")
        explicit_pronoun_target = panel_ref.get("target_panel")
        pronoun_present = bool(_REASONING_DEBUG_PRONOUN_RE.search(safe_text))
        if pronoun_present and not explicit_pronoun_topic:
            if safe_prev:
                diagnostics = dict(base_diag)
                diagnostics["explicit_panel_reference"] = True
                diagnostics["prior_topic_used"] = True
                diagnostics["resolved_topic"] = safe_prev[:240]
                diagnostics["reasoning_gate_result"] = "reasoning_panel"
                diagnostics["reasoning_gate_reason"] = "explicit_panel_pronoun_resolved_from_prior"
                return {
                    "text": safe_text,
                    "route": "reasoning_panel",
                    "reason": "explicit_panel_pronoun_resolved_from_prior",
                    "resolved_topic": safe_prev[:240],
                    "target_panel": explicit_pronoun_target,
                    "prompt_reasoning": True,
                    "active_panel_index": active_panel_index,
                    "previous_user_text": safe_prev,
                    "diagnostics": diagnostics,
                }
            diagnostics = dict(base_diag)
            diagnostics["explicit_panel_reference"] = True
            diagnostics["reasoning_gate_result"] = "clarification"
            diagnostics["reasoning_gate_reason"] = "explicit_panel_pronoun_without_prior_topic"
            return {
                "text": safe_text,
                "route": "clarification",
                "reason": "explicit_panel_pronoun_without_prior_topic",
                "resolved_topic": None,
                "target_panel": explicit_pronoun_target,
                "prompt_reasoning": False,
                "active_panel_index": active_panel_index,
                "previous_user_text": safe_prev,
                "diagnostics": diagnostics,
            }

    classifier_result: dict = {}
    if reasoning_ai is not None:
        try:
            classifier_result = reasoning_ai.classify_route_reasoning(safe_text) or {}
        except Exception as exc:
            classifier_result = {
                "route": "voice_ui",
                "reason": "classifier_error",
                "prompt_reasoning": False,
                "category": "none",
                "confidence": 0.0,
                "resolved_topic": None,
                "target_panel": None,
                "source": "backend_debug_classifier_error",
                "diagnostics": {"classifier_exception": str(exc)[:200]},
            }

    if not classifier_result:
        diagnostics = dict(base_diag)
        if explicit_pronoun_target is not None:
            diagnostics["explicit_panel_reference"] = True
        diagnostics["reasoning_gate_result"] = "voice_ui"
        diagnostics["reasoning_gate_reason"] = "no_llm_model_available"
        return {
            "text": safe_text,
            "route": "voice_ui",
            "reason": "no_llm_model_available",
            "resolved_topic": None,
            "target_panel": explicit_pronoun_target,
            "prompt_reasoning": False,
            "active_panel_index": active_panel_index,
            "previous_user_text": safe_prev,
            "diagnostics": diagnostics,
        }

    diagnostics = dict(classifier_result.get("diagnostics") or {})
    diagnostics.setdefault("reasoning_gate_called", True)
    diagnostics["active_work_mode"] = bool(active_work_mode)
    diagnostics["resolved_topic"] = classifier_result.get("resolved_topic")
    diagnostics["prior_topic_used"] = False
    diagnostics["route_source"] = classifier_result.get("source") or "backend_classifier"
    diagnostics.setdefault("explicit_panel_reference", bool(panel_ref.get("matched")))
    diagnostics.setdefault("simple_definition_detected", False)
    diagnostics.setdefault("brief_explanation_detected", False)
    diagnostics.setdefault("broad_complex_topic_detected", False)
    diagnostics.setdefault("complex_task_detected", False)

    route = classifier_result.get("route") or (
        "reasoning_panel" if classifier_result.get("prompt_reasoning") else "voice_ui"
    )
    reason = classifier_result.get("reason") or ""
    resolved_topic = classifier_result.get("resolved_topic")
    target_panel = classifier_result.get("target_panel")
    if target_panel is None and explicit_pronoun_target is not None:
        target_panel = explicit_pronoun_target

    diagnostics["reasoning_gate_result"] = route
    diagnostics["reasoning_gate_reason"] = reason

    return {
        "text": safe_text,
        "route": route,
        "reason": reason,
        "resolved_topic": resolved_topic,
        "target_panel": target_panel,
        "prompt_reasoning": route == "reasoning_panel",
        "active_panel_index": active_panel_index,
        "previous_user_text": safe_prev,
        "diagnostics": diagnostics,
    }


def _emit_reasoning_gate_debug_log(payload: dict) -> None:
    """Emit one structured [reasoning_gate_debug] log line per call."""
    try:
        diagnostics = payload.get("diagnostics") or {}
        log_obj = {
            "text": (payload.get("text") or "")[:240],
            "route": payload.get("route"),
            "reason": payload.get("reason"),
            "resolved_topic": payload.get("resolved_topic"),
            "target_panel": payload.get("target_panel"),
            "explicit_panel_reference": diagnostics.get("explicit_panel_reference"),
            "simple_definition_detected": diagnostics.get("simple_definition_detected"),
            "brief_explanation_detected": diagnostics.get("brief_explanation_detected"),
            "broad_complex_topic_detected": diagnostics.get("broad_complex_topic_detected"),
            "complex_task_detected": diagnostics.get("complex_task_detected"),
            "active_work_mode": diagnostics.get("active_work_mode"),
            "prior_topic_used": diagnostics.get("prior_topic_used"),
            "route_source": diagnostics.get("route_source"),
        }
        print(
            "[reasoning_gate_debug] " + json.dumps(log_obj, ensure_ascii=False, default=str),
            flush=True,
        )
    except Exception:
        pass


def _normalize_reasoning_debug_truthy(value: Any) -> bool:
    if value is None:
        return True
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    s = str(value).strip().lower()
    if not s:
        return True
    return s in ("1", "true", "yes", "y", "on")


def _normalize_reasoning_debug_panel_index(value: Any) -> Optional[int]:
    if value is None or value == "":
        return None
    try:
        return int(value)
    except Exception:
        return None


# =========================
# Semantic normalizer — Stage A read-only observability endpoint.
#
# Returns the proposed ``NormalizedTurn`` shape for any text by adapting the
# existing deterministic outputs (multi_action_planner + classify_info_tool +
# classify_sports_intent). Does NOT execute anything, mutate session state, or
# alter the live routing pipeline — every action surface stays wired exactly
# the way it was before this endpoint existed. See ``actions/normalizer.py``
# for the full module banner and the action-type catalog.
#
# This endpoint is the Stage A observability hook from the 2026-05-31
# normalizer investigation. Stage B+ will add LLM-shadow output; Stage C+
# will start letting the dispatcher consume NormalizedTurn for app actions.
# Until then this is read-only — safe to hit from anywhere.
# =========================
@app.post("/debug/normalize")
async def debug_normalize(request: Request):
    """Stage A read-only normalizer endpoint.

    Body shape (JSON or x-www-form-urlencoded):

        {
          "text": "...",                       # required
          "session_id": "..."                  # optional; if provided we
                                               # pull recent_news_context /
                                               # recent_sports_context from
                                               # session state
          "recent_news_context": {...} | null, # optional override
          "recent_sports_context": {...} | null
        }

    Returns the ``NormalizedTurn`` dict. Never executes an action.
    """
    parsed: dict = {}
    try:
        ctype = (request.headers.get("content-type") or "").lower()
        if "application/json" in ctype:
            parsed = await request.json()
        else:
            form = await request.form()
            parsed = dict(form)
    except Exception:
        parsed = {}
    if not isinstance(parsed, dict):
        parsed = {}

    text = str(parsed.get("text") or parsed.get("transcript") or "").strip()
    if not text:
        raise HTTPException(400, "Empty text")

    raw_session_id = parsed.get("session_id") or ""
    session_id = safe_id(str(raw_session_id)) if raw_session_id else ""

    # Optional explicit overrides take precedence; otherwise pull from
    # the per-session context stores so callers can reproduce live
    # follow-up behavior just by passing session_id.
    news_ctx = parsed.get("recent_news_context")
    if news_ctx is None and session_id:
        try:
            news_ctx = get_recent_news_context(session_id)
        except Exception:
            news_ctx = None
    sports_ctx = parsed.get("recent_sports_context")
    if sports_ctx is None and session_id:
        try:
            sports_ctx = get_recent_sports_context(session_id)
        except Exception:
            sports_ctx = None

    history = user_histories.get(session_id) if session_id else None

    from actions.normalizer import build_normalized_turn as _build_normalized_turn
    from actions.sports import classify_sports_intent as _classify_sports_intent
    from actions.multi_action_planner import (
        plan_user_actions as _plan_user_actions,
    )

    turn = await asyncio.to_thread(
        _build_normalized_turn,
        text,
        session_id=session_id or None,
        history=history,
        context_snapshot=None,
        recent_news_context=news_ctx if isinstance(news_ctx, dict) else None,
        recent_sports_context=sports_ctx if isinstance(sports_ctx, dict) else None,
        classify_info_tool=classify_info_tool,
        classify_sports_intent=_classify_sports_intent,
        plan_user_actions=_plan_user_actions,
        note="debug_normalize_endpoint",
    )
    return turn


@app.post("/debug/reasoning_gate")
async def debug_reasoning_gate(request: Request):
    """Dry-run reasoning gate for batch-testing route decisions.

    Accepts either application/json or x-www-form-urlencoded / multipart so
    the same endpoint works from curl, ``requests``, and HTML forms. The
    JSONL runner lives in ``run_reasoning_gate_tests.py``.

    Returns the spec-required shape verbatim AND emits a structured
    ``[reasoning_gate_debug]`` log line for every call so an operator can
    grep server logs for the full route trace.
    """
    parsed: dict = {}
    try:
        ctype = (request.headers.get("content-type") or "").lower()
        if "application/json" in ctype:
            parsed = await request.json()
        else:
            form = await request.form()
            parsed = dict(form)
    except Exception:
        parsed = {}
    text = ""
    previous_user_text = ""
    active_work_mode: Any = None
    active_panel_index: Any = None
    if isinstance(parsed, dict):
        text = parsed.get("text") or parsed.get("transcript") or ""
        previous_user_text = parsed.get("previous_user_text") or ""
        active_work_mode = parsed.get("active_work_mode")
        active_panel_index = parsed.get("active_panel_index")

    response_payload = await asyncio.to_thread(
        _resolve_reasoning_debug_payload,
        str(text or ""),
        str(previous_user_text or ""),
        _normalize_reasoning_debug_truthy(active_work_mode),
        _normalize_reasoning_debug_panel_index(active_panel_index),
    )
    _emit_reasoning_gate_debug_log(response_payload)
    return response_payload


def _log_math_problem_classify_debug(payload: dict) -> None:
    try:
        print(
            "[MATH_PROBLEM_CLASSIFY_DEBUG] "
            + json.dumps(payload, ensure_ascii=False, default=str),
            flush=True,
        )
    except Exception:
        pass


def _summarize_classifier_for_debug(
    classifier_result: dict, raw_text: str, has_attachment: bool
) -> dict:
    return {
        "raw_text": (raw_text or "")[:240],
        "has_attachment": bool(has_attachment),
        "domain": classifier_result.get("domain"),
        "problem_mode": classifier_result.get("problem_mode"),
        "calculation_required": classifier_result.get("calculation_required"),
        "code_required": classifier_result.get("code_required"),
        "trigger_terms": classifier_result.get("trigger_terms", []),
        "numeric_targets": classifier_result.get("numeric_targets", []),
        "missing_variables": classifier_result.get("missing_variables", []),
        "final_route": classifier_result.get("final_route"),
        "reason": (classifier_result.get("reason") or "")[:240],
    }


def _build_clarification_markdown(classifier_result: dict, user_text: str) -> str:
    missing = classifier_result.get("missing_variables") or []
    targets = classifier_result.get("numeric_targets") or []
    domain = classifier_result.get("domain") or "math"
    bullets = "\n".join(f"- `{m}`" for m in missing[:12]) or "- the numeric inputs the model needs"
    target_line = (
        f"To work out **{', '.join(targets[:6])}** I need a few values first."
        if targets
        else "Before I work this out I need a few values."
    )
    return (
        f"# Clarification needed\n\n"
        f"{target_line}\n\n"
        f"**Please confirm or provide:**\n{bullets}\n\n"
        f"Once you reply with those, I'll lay out the calculation step by step in this panel.\n\n"
        f"*(Classifier: {domain} → {classifier_result.get('problem_mode')}; "
        f"reason: {classifier_result.get('reason', '')[:160]})*\n"
    )


def _build_code_first_intro_markdown(
    classifier_result: dict, executor_result: dict, user_text: str
) -> str:
    """Short header chunk streamed before the deep markdown synth. Mirrors the
    structure the deep model is asked to follow so the panel renders something
    useful even if the synth call is slow or fails."""
    targets = classifier_result.get("numeric_targets") or []
    variables = classifier_result.get("variables_detected") or {}
    title = "Computational solution"
    if targets:
        title = f"Computing {', '.join(targets[:3])}"
    elif classifier_result.get("domain") in {"finance", "math", "statistics", "probability"}:
        title = f"{classifier_result.get('domain', '').title()} computation"

    given_lines = []
    if variables:
        for k, v in list(variables.items())[:14]:
            given_lines.append(f"- **{k}** = {v}")
    given_block = "\n".join(given_lines) if given_lines else "- (inputs extracted from the problem statement)"

    success = bool(executor_result.get("execution_success"))
    computed = executor_result.get("computed_result") or {}
    rounded_block = ""
    if success and isinstance(computed, dict):
        fa = computed.get("final_answer", computed.get("value"))
        label = computed.get("label") or computed.get("name") or "Result"
        units = computed.get("units") or ""
        if fa is not None:
            try:
                if isinstance(fa, (int, float)):
                    fa_str = f"{fa:.6f}".rstrip("0").rstrip(".")
                else:
                    fa_str = str(fa)
            except Exception:
                fa_str = str(fa)
            unit_str = f" {units}" if units else ""
            rounded_block = f"\n**{label}: {fa_str}{unit_str}**\n"

    fail_note = ""
    if not success:
        ek = executor_result.get("error_kind") or "error"
        fail_note = (
            f"\n> _Calculation did not finish (`{ek}`)._ The reasoning below shows the setup; "
            "no fabricated final number.\n"
        )

    return (
        f"# {title}\n\n"
        f"## Given\n{given_block}\n\n"
        f"## Computed result\n"
        + (rounded_block if rounded_block else "_(see Python check section below)_\n")
        + fail_note
        + "\n"
    )


async def _run_math_problem_pipeline_or_none(
    *,
    user_text: str,
    history: list,
    attachment_context: str | None,
    request_label: str,
):
    """Run the math-problem classifier and, when code is required, execute Python.

    Returns:
      - ("code_first", executor_result, classifier_result, classifier_log)
      - ("clarification", clarification_markdown, classifier_result, classifier_log)
      - ("normal", None, classifier_result, classifier_log)
    The classifier log is also emitted to stdout for [MATH_PROBLEM_CLASSIFY_DEBUG].

    When ENABLE_MATH_ROUTER is False the classifier is NOT called — we return
    ("normal", ...) immediately so every request goes through the standard
    deep-reasoning markdown stream. A `[REASONING_PIPELINE_DEBUG]` log row is
    emitted so the disabled-router path is still auditable.
    """
    if not ENABLE_MATH_ROUTER:
        classifier_stub = {
            "domain": None,
            "problem_mode": None,
            "calculation_required": None,
            "code_required": None,
            "trigger_terms": [],
            "numeric_targets": [],
            "missing_variables": [],
            "final_route": "normal_reasoning",
            "reason": "math_router_disabled_feature_flag",
        }
        try:
            print(
                "[REASONING_PIPELINE_DEBUG] "
                + json.dumps(
                    {
                        "endpoint": request_label,
                        "math_router_enabled": False,
                        "selected_route": "normal_reasoning",
                        "reason": "math_router_disabled_feature_flag",
                        "raw_text": (user_text or "")[:240],
                        "has_attachment": bool((attachment_context or "").strip()),
                    },
                    ensure_ascii=False,
                    default=str,
                ),
                flush=True,
            )
        except Exception:
            pass
        return ("normal", None, classifier_stub, classifier_stub)

    classifier_result = await asyncio.to_thread(
        reasoning_ai.classify_math_problem_mode, user_text, attachment_context
    )
    classifier_log = _summarize_classifier_for_debug(
        classifier_result, user_text, bool((attachment_context or "").strip())
    )
    classifier_log["endpoint"] = request_label
    classifier_log["math_router_enabled"] = True
    _log_math_problem_classify_debug(classifier_log)

    route = classifier_result.get("final_route") or "normal_reasoning"

    if route == "clarification":
        return ("clarification", _build_clarification_markdown(classifier_result, user_text), classifier_result, classifier_log)

    if route != "code_first_reasoning":
        return ("normal", None, classifier_result, classifier_log)

    # ----- code-first path -----
    try:
        initial_code = await asyncio.to_thread(
            reasoning_deep_ai.generate_python_code_for_problem,
            user_text,
            attachment_context,
            classifier_result,
            history,
        )
    except Exception as e:
        print(f"[MATH_CODE_EXECUTION_DEBUG][codegen_error] {type(e).__name__}: {e}")
        initial_code = ""

    if not (initial_code or "").strip():
        # Codegen failed entirely — fall back to normal reasoning so the user
        # still gets an on-screen answer (degraded but not silent).
        return ("normal", None, classifier_result, classifier_log)

    retry_cb = reasoning_deep_ai.make_python_retry_callback(
        user_text=user_text,
        attachment_context=attachment_context,
        classifier_result=classifier_result,
        history=history,
    )
    executor_result = await asyncio.to_thread(
        _run_math_python_with_retry,
        initial_code,
        fix_code_cb=retry_cb,
        debug_extra={"endpoint": request_label, "domain": classifier_result.get("domain")},
    )
    return ("code_first", executor_result, classifier_result, classifier_log)


VOICE_TO_PANEL_MAX_BLOCK_CHARS = 4000
VOICE_TO_PANEL_ACTION_SUMMARY_MAX = 500
VOICE_TO_PANEL_MAX_TURN_PAIRS = 3


def _voice_to_panel_task_references_recent_action(
    task_text: str, client_packet: dict | None
) -> bool:
    if isinstance(client_packet, dict):
        if client_packet.get("deictic_detected"):
            return True
        reasons = client_packet.get("inclusion_reasons") or []
        if "recent_action_reference" in reasons:
            return True
    low = (task_text or "").lower()
    return bool(
        re.search(
            r"\bwhy(?:\s+did|\s+does|\s+that|\s+it|\s+this)?\s+(?:that|it|this)\s+work",
            low,
        )
        or re.search(r"\bwhy\s+(?:that|it|this)\s+(?:worked|failed|succeeded|happened)\b", low)
        or re.search(
            r"\b(?:explain|describe)\s+(?:why|how)\s+(?:that|it|this|the)\s+(?:worked|failed|route|routing)\b",
            low,
        )
        or re.search(r"\b(?:recent|last)\s+(?:action|command|request|play|pause|route|routing)\b", low)
    )


def _summarize_recent_action_for_voice_to_panel(session_id: str) -> str:
    ctx = get_recent_action_context(session_id)
    if not ctx:
        return ""
    action_name = str(ctx.get("action_name") or "").strip()
    slots = ctx.get("slots") if isinstance(ctx.get("slots"), dict) else {}
    result = ctx.get("result") if isinstance(ctx.get("result"), dict) else {}
    spoken = str(result.get("spoken_reply") or "").strip()
    query = str(slots.get("query") or slots.get("track_query") or "").strip()
    parts = [f"action={action_name}" if action_name else ""]
    if query:
        parts.append(f"query={query}")
    if spoken:
        parts.append(f"spoken_reply={spoken[:220]}")
    ui = result.get("ui_payload")
    if isinstance(ui, dict):
        ui_type = str(ui.get("panel_type") or ui.get("op") or "").strip()
        if ui_type:
            parts.append(f"ui={ui_type}")
    summary = "; ".join(p for p in parts if p).strip()
    if len(summary) > VOICE_TO_PANEL_ACTION_SUMMARY_MAX:
        summary = f"{summary[:VOICE_TO_PANEL_ACTION_SUMMARY_MAX]}…"
    return summary


def _voice_histories_tail_for_panel(session_id: str, max_pairs: int = VOICE_TO_PANEL_MAX_TURN_PAIRS) -> list[dict]:
    history = user_histories.get(session_id) or []
    if not history:
        return []
    tail = history[-(max_pairs * 2) :]
    out: list[dict] = []
    for msg in tail:
        if not isinstance(msg, dict):
            continue
        role = str(msg.get("role") or "").strip().lower()
        content = str(msg.get("content") or "").strip()
        if role not in {"user", "assistant"} or not content:
            continue
        out.append({"role": role, "content": content[:800]})
    return out[-(max_pairs * 2) :]


def _render_server_voice_session_enrichment(
    *,
    session_id: str,
    task_text: str,
    client_packet: dict | None,
    server_turns: list[dict],
    action_summary: str,
) -> str:
    lines: list[str] = []
    if server_turns:
        client_has_turns = bool(
            isinstance(client_packet, dict) and (client_packet.get("recent_voice_turns") or [])
        )
        if not client_has_turns:
            lines.append("Recent Voice UI turns (server session history):")
            for t in server_turns:
                role = "Assistant" if t.get("role") == "assistant" else "User"
                content = str(t.get("content") or "").strip()
                if content:
                    lines.append(f"{role}: {content}")
    if action_summary:
        lines.append(f"Recent action result: {action_summary}")
    if not lines:
        return ""
    block = "\n".join(lines).strip()
    if len(block) > VOICE_TO_PANEL_MAX_BLOCK_CHARS:
        block = f"{block[:VOICE_TO_PANEL_MAX_BLOCK_CHARS]}\n…"
    return block


def _build_voice_session_context_for_panel(
    session_id: str,
    task_text: str,
    client_packet: dict | None,
) -> str:
    """Server-side enrichment for voice → panel handoff (Phase 1).

    The browser renders the primary RELEVANT_PRIOR_VOICE_UI_CONTEXT block in
    ``work_mode_lane_client_context``. This helper adds authoritative server
    session history (when the client packet is sparse) and recent action
    summaries when the task references a recent command/outcome.
    """
    if not isinstance(client_packet, dict):
        return ""
    if not client_packet:
        return ""
    server_turns = _voice_histories_tail_for_panel(session_id)
    action_summary = ""
    if _voice_to_panel_task_references_recent_action(task_text, client_packet):
        action_summary = _summarize_recent_action_for_voice_to_panel(session_id)
    return _render_server_voice_session_enrichment(
        session_id=session_id,
        task_text=task_text,
        client_packet=client_packet,
        server_turns=server_turns,
        action_summary=action_summary,
    )


def _merge_voice_session_context_into_attachment(
    client_ctx: str | None,
    voice_enrichment: str,
) -> str | None:
    if not voice_enrichment:
        return client_ctx or None
    enrich_block = (
        "SERVER_VOICE_SESSION_ENRICHMENT (authoritative server-side supplement):\n"
        f"{voice_enrichment}"
    )
    base = (client_ctx or "").strip()
    if not base:
        return enrich_block
    if "SERVER_VOICE_SESSION_ENRICHMENT" in base:
        return base
    return f"{base}\n\n---\n\n{enrich_block}"


@app.post("/work_mode/reasoning_stream")
async def work_mode_reasoning_stream(request: Request, data: WorkModeTextPayload):
    try:
        from auth.request_auth import bind_request_auth_user

        bind_request_auth_user(request)
    except Exception:
        pass
    sid = _work_mode_touch_session(data.session_id)
    if reasoning_ai is None or reasoning_deep_ai is None:
        raise HTTPException(503, "Reasoning model not loaded")
    text = data.text.strip()
    if not text:
        raise HTTPException(400, "Empty text")

    # Multi-device-concurrency PART 1: per-request id + [REQ start]. The
    # matching [REQ end] is emitted by _diag_wrap_stream around StreamingResponse.
    _rs_request_id = _new_request_id()
    _current_request_id_var.set(_rs_request_id)
    _rs_start_ts = log_req_start(
        route="/work_mode/reasoning_stream",
        session_id=sid,
        request_id=_rs_request_id,
        source="reasoning",
        mode="reasoning",
        lane_id=_normalize_reasoning_lane_id(data.lane_id),
        chars=len(text),
    )

    # Safety: reasoning-stream char + token caps.
    try:
        _block_rs = _safety_check_typed_input(
            text,
            work_mode=True,
            request_type="reasoning",
        )
        if _block_rs is not None:
            _safety_log_block(
                reason=_block_rs["reason"],
                mode="work_mode",
                feature="reasoning",
                char_count=_block_rs.get("char_count"),
                estimated_tokens=_block_rs.get("estimated_tokens"),
                extra={"endpoint": "/work_mode/reasoning_stream"},
            )
            raise HTTPException(413, _block_rs["message"])
    except HTTPException:
        raise
    except Exception as _safe_err:
        print(f"[safety_guard] reasoning_stream guard swallowed: {_safe_err}")
    try:
        _enforce_usage_credit_cap(
            "work_mode_reasoning_deep",
            session_id=sid,
            feature_type="work_mode",
            precharge_credits=20,
        )
    except HTTPException:
        raise
    lane_id = _normalize_reasoning_lane_id(data.lane_id)
    _cost_touch_work_mode_reasoning_request(
        session_id=sid,
        endpoint="/work_mode/reasoning_stream",
        lane_id=lane_id,
        request=request,
    )
    lane_key = _reasoning_lane_history_key(sid, lane_id)
    lane_history = reasoning_lane_histories[lane_key]
    client_ctx = (data.work_mode_lane_client_context or "").strip()[:22000]
    voice_packet = data.voice_to_panel_context if isinstance(data.voice_to_panel_context, dict) else None
    voice_enrichment = _build_voice_session_context_for_panel(sid, text, voice_packet)
    full_ctx = _merge_voice_session_context_into_attachment(client_ctx, voice_enrichment) or None
    try:
        from auth.memory_context import prepend_explicit_memory_to_attachment_context

        full_ctx = prepend_explicit_memory_to_attachment_context(full_ctx)
    except Exception as _mem_ctx_err:
        print(f"[explicit_memory] reasoning_stream ctx swallowed: {_mem_ctx_err}")
    if _is_generic_example_request(text):
        related_memory = _last_reasoning_memory_message(sid)
    else:
        related_memory = _related_reasoning_memory_messages(sid, text)
    history = [*lane_history, *related_memory]

    async def gen():
        # Multi-device-concurrency PART 3: snapshot the shared model field
        # `reasoning_deep_ai.last_deep_reasoning_effort_active` PER STREAM so
        # a concurrent reasoning request can't overwrite it before we serialize
        # it into our `done` payload.
        effort_snap = _EffortSnapshot()
        stream_ok = True
        stream_err: str | None = None
        # Tag every diag log inside this generator with our request_id.
        _current_request_id_var.set(_rs_request_id)
        try:
            route_kind, route_payload, classifier_result, _classifier_log = (
                await _run_math_problem_pipeline_or_none(
                    user_text=text,
                    history=history,
                    attachment_context=full_ctx,
                    request_label="reasoning_stream",
                )
            )

            markdown_acc = ""

            if route_kind == "code_first":
                executor_result = route_payload
                success = bool(executor_result.get("execution_success"))
                summary = await asyncio.to_thread(
                    reasoning_ai.generate_voice_digest_code_first,
                    text,
                    executor_result.get("computed_result"),
                    success,
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                intro_md = _build_code_first_intro_markdown(
                    classifier_result, executor_result, text
                )
                markdown_acc += intro_md
                yield (
                    json.dumps({"type": "markdown", "text": intro_md}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                async for delta in _stream_markdown_capture_effort(
                    effort_snap,
                    method=reasoning_deep_ai.async_generate_stream_markdown_with_computed_result,
                    user_text=text,
                    attachment_context=full_ctx,
                    classifier_result=classifier_result,
                    executor_result=executor_result,
                    history=history,
                ):
                    if delta:
                        markdown_acc += str(delta)
                        yield (
                            json.dumps({"type": "markdown", "text": delta}, ensure_ascii=False) + "\n"
                        ).encode("utf-8")

            elif route_kind == "clarification":
                summary = (
                    "I need a couple of inputs before I run the calculation — I've listed them in the panel."
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                clar_md = route_payload
                markdown_acc += clar_md
                yield (
                    json.dumps({"type": "markdown", "text": clar_md}, ensure_ascii=False) + "\n"
                ).encode("utf-8")

            else:
                summary = await asyncio.to_thread(
                    reasoning_ai.generate_voice_digest, text, history, full_ctx
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                async for delta in _stream_markdown_capture_effort(
                    effort_snap,
                    method=reasoning_deep_ai.async_generate_stream_markdown,
                    user_text=text,
                    attachment_context=full_ctx,
                    history=history,
                ):
                    if delta:
                        markdown_acc += str(delta)
                        yield (
                            json.dumps({"type": "markdown", "text": delta}, ensure_ascii=False) + "\n"
                        ).encode("utf-8")

            _append_reasoning_turn_memory(sid, lane_id, text, summary or markdown_acc[:1000])
            done_payload: dict = {"type": "done", "request_id": _rs_request_id}
            if effort_snap.value is not None:
                done_payload["deep_reasoning_effort_active"] = bool(effort_snap.value)
            done_payload["math_problem_mode"] = classifier_result.get("problem_mode")
            done_payload["math_final_route"] = classifier_result.get("final_route")
            yield (json.dumps(done_payload, ensure_ascii=False) + "\n").encode("utf-8")
        except Exception as e:
            stream_ok = False
            stream_err = str(e)[:200]
            print(f"[WORK_MODE/reasoning_stream] error: {e}")
            yield (
                json.dumps({"type": "error", "message": str(e), "request_id": _rs_request_id}, ensure_ascii=False) + "\n"
            ).encode("utf-8")
        finally:
            _cost_finalize_work_mode_stream(
                session_id=sid,
                endpoint="/work_mode/reasoning_stream",
                request=request,
                deep_reasoning_effort_active=effort_snap.value,
                success=stream_ok,
                error_message=stream_err,
            )

    return StreamingResponse(
        _diag_wrap_stream(
            gen(),
            route="/work_mode/reasoning_stream",
            session_id=sid,
            request_id=_rs_request_id,
            start_ts=_rs_start_ts,
            mode="reasoning",
        ),
        media_type="application/x-ndjson",
        headers=_ndjson_stream_headers(),
    )


@app.post("/work_mode/reasoning_stream_upload")
async def work_mode_reasoning_stream_upload(
    request: Request,
    session_id: str = Form(...),
    text: str = Form(""),
    lane_id: str = Form("atlas"),
    file: Optional[UploadFile] = File(None),
    files: Optional[List[UploadFile]] = File(None),
    work_mode_lane_client_context: str = Form(""),
    voice_to_panel_context: str = Form(""),
):
    try:
        from auth.request_auth import bind_request_auth_user

        bind_request_auth_user(request)
    except Exception:
        pass
    sid = _work_mode_touch_session(session_id)
    if reasoning_ai is None or reasoning_deep_ai is None:
        raise HTTPException(503, "Reasoning model not loaded")
    lane = _normalize_reasoning_lane_id(lane_id)
    lane_key = _reasoning_lane_history_key(sid, lane)
    lane_history = reasoning_lane_histories[lane_key]

    q = (text or "").strip()
    if not q:
        raise HTTPException(400, "Empty text")

    # Safety: typed prompt accompanying the upload (attachment bodies
    # bypass this — uploads use the separate WORK_MODE_UPLOAD_MAX_BYTES
    # path below).
    try:
        _block_rsu = _safety_check_typed_input(
            q,
            work_mode=True,
            request_type="reasoning",
        )
        if _block_rsu is not None:
            _safety_log_block(
                reason=_block_rsu["reason"],
                mode="work_mode",
                feature="reasoning",
                char_count=_block_rsu.get("char_count"),
                estimated_tokens=_block_rsu.get("estimated_tokens"),
                extra={"endpoint": "/work_mode/reasoning_stream_upload"},
            )
            raise HTTPException(413, _block_rsu["message"])
    except HTTPException:
        raise
    except Exception as _safe_err:
        print(f"[safety_guard] reasoning_stream_upload guard swallowed: {_safe_err}")

    # PART 1 diagnostics for reasoning_stream_upload too.
    _rsu_request_id = _new_request_id()
    _current_request_id_var.set(_rsu_request_id)
    _rsu_start_ts = log_req_start(
        route="/work_mode/reasoning_stream_upload",
        session_id=sid,
        request_id=_rsu_request_id,
        source="reasoning_upload",
        mode="reasoning",
        lane_id=lane,
        chars=len(q),
    )

    upload_items: List[UploadFile] = []
    extracted_parts: List[str] = []
    if files:
        upload_items.extend(files)
    if file is not None:
        upload_items.append(file)
    if not upload_items:
        raise HTTPException(400, "Missing file")

    _cost_touch_work_mode_reasoning_request(
        session_id=sid,
        endpoint="/work_mode/reasoning_stream_upload",
        lane_id=lane,
        request=request,
        has_upload=True,
        upload_count=len(upload_items),
    )

    try:
        _enforce_usage_credit_cap(
            "image_pdf_reasoning",
            session_id=sid,
            feature_type="image_pdf",
        )
    except HTTPException:
        raise

    for uf in upload_items:
        b = await uf.read()
        if len(b) > WORK_MODE_UPLOAD_MAX_BYTES:
            raise HTTPException(413, "File too large (max 25MB)")
        try:
            part = await asyncio.to_thread(
                reasoning_ai.extract_attachment_context,
                uf.filename or "upload",
                uf.content_type or "",
                b,
            )
        except Exception as e:
            raise HTTPException(400, f"Attachment processing failed: {e}") from e
        if (part or "").strip():
            extracted_parts.append((part or "").strip())

    attachment_context = "\n\n--- FILE ---\n\n".join(extracted_parts) if extracted_parts else ""

    prior = (reasoning_lane_upload_plain_chain.get(lane_key) or "").strip()
    current = (attachment_context or "").strip()
    if prior:
        new_stored = f"{prior}\n\n--- UPLOAD ---\n\n{current}"
    else:
        new_stored = current
    max_store = 120000
    if len(new_stored) > max_store:
        new_stored = f"{new_stored[:max_store]}\n…"
    reasoning_lane_upload_plain_chain[lane_key] = new_stored

    client = (work_mode_lane_client_context or "").strip()[:22000]
    voice_packet_upload: dict | None = None
    if (voice_to_panel_context or "").strip():
        try:
            parsed_v = json.loads(voice_to_panel_context)
            if isinstance(parsed_v, dict):
                voice_packet_upload = parsed_v
        except Exception:
            voice_packet_upload = None
    voice_enrichment_upload = _build_voice_session_context_for_panel(sid, q, voice_packet_upload)
    client = _merge_voice_session_context_into_attachment(client, voice_enrichment_upload) or client
    merged_for_pass = new_stored
    if client:
        merged_for_pass = f"{new_stored}\n\n--- CLIENT_LANE_PRIOR_CONTEXT ---\n\n{client}"

    vars_block = ""
    try:
        vars_block = await asyncio.to_thread(
            reasoning_ai.extract_finance_math_known_variables,
            merged_for_pass,
            q,
        )
    except Exception as e:
        print(f"[WORK_MODE/reasoning_stream_upload] known-variables pass: {e}")

    vb = (vars_block or "").strip()
    if vb:
        full_ctx = (
            merged_for_pass
            + "\n\n--- KNOWN_VARIABLES_AFTER_MERGE (authoritative; use for solving; "
            "do not ask the user to repeat these unless clearly wrong or absent) ---\n\n"
            + vb[:8000]
        )
    else:
        full_ctx = merged_for_pass

    try:
        from auth.memory_context import prepend_explicit_memory_to_attachment_context

        full_ctx = prepend_explicit_memory_to_attachment_context(full_ctx)
    except Exception as _mem_ctx_err:
        print(f"[explicit_memory] reasoning_stream_upload ctx swallowed: {_mem_ctx_err}")

    async def gen():
        # PART 3: per-stream snapshot of the shared model field.
        effort_snap = _EffortSnapshot()
        stream_ok = True
        stream_err: str | None = None
        _current_request_id_var.set(_rsu_request_id)
        try:
            if _is_generic_example_request(q):
                related_memory = _last_reasoning_memory_message(sid)
            else:
                related_memory = _related_reasoning_memory_messages(sid, q)
            history = [*lane_history, *related_memory]

            route_kind, route_payload, classifier_result, _classifier_log = (
                await _run_math_problem_pipeline_or_none(
                    user_text=q,
                    history=history,
                    attachment_context=full_ctx,
                    request_label="reasoning_stream_upload",
                )
            )

            markdown_acc = ""

            if route_kind == "code_first":
                executor_result = route_payload
                success = bool(executor_result.get("execution_success"))
                summary = await asyncio.to_thread(
                    reasoning_ai.generate_voice_digest_code_first,
                    q,
                    executor_result.get("computed_result"),
                    success,
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                intro_md = _build_code_first_intro_markdown(
                    classifier_result, executor_result, q
                )
                markdown_acc += intro_md
                yield (
                    json.dumps({"type": "markdown", "text": intro_md}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                async for delta in _stream_markdown_capture_effort(
                    effort_snap,
                    method=reasoning_deep_ai.async_generate_stream_markdown_with_computed_result,
                    user_text=q,
                    attachment_context=full_ctx,
                    classifier_result=classifier_result,
                    executor_result=executor_result,
                    history=history,
                ):
                    if delta:
                        markdown_acc += str(delta)
                        yield (
                            json.dumps({"type": "markdown", "text": delta}, ensure_ascii=False) + "\n"
                        ).encode("utf-8")

            elif route_kind == "clarification":
                summary = (
                    "I need a couple of inputs before I run the calculation — I've listed them in the panel."
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                clar_md = route_payload
                markdown_acc += clar_md
                yield (
                    json.dumps({"type": "markdown", "text": clar_md}, ensure_ascii=False) + "\n"
                ).encode("utf-8")

            else:
                summary = await asyncio.to_thread(
                    reasoning_ai.generate_voice_digest, q, history, full_ctx
                )
                yield (
                    json.dumps({"type": "summary", "text": summary}, ensure_ascii=False) + "\n"
                ).encode("utf-8")
                async for delta in _stream_markdown_capture_effort(
                    effort_snap,
                    method=reasoning_deep_ai.async_generate_stream_markdown,
                    user_text=q,
                    attachment_context=full_ctx,
                    history=history,
                ):
                    if delta:
                        markdown_acc += str(delta)
                        yield (
                            json.dumps({"type": "markdown", "text": delta}, ensure_ascii=False) + "\n"
                        ).encode("utf-8")

            _append_reasoning_turn_memory(sid, lane, q, summary or markdown_acc[:1000])
            done_payload: dict = {"type": "done", "request_id": _rsu_request_id}
            if effort_snap.value is not None:
                done_payload["deep_reasoning_effort_active"] = bool(effort_snap.value)
            done_payload["math_problem_mode"] = classifier_result.get("problem_mode")
            done_payload["math_final_route"] = classifier_result.get("final_route")
            yield (json.dumps(done_payload, ensure_ascii=False) + "\n").encode("utf-8")
        except Exception as e:
            stream_ok = False
            stream_err = str(e)[:200]
            yield (
                json.dumps({"type": "error", "message": str(e), "request_id": _rsu_request_id}, ensure_ascii=False) + "\n"
            ).encode("utf-8")
        finally:
            _cost_finalize_work_mode_stream(
                session_id=sid,
                endpoint="/work_mode/reasoning_stream_upload",
                request=request,
                deep_reasoning_effort_active=effort_snap.value,
                success=stream_ok,
                error_message=stream_err,
            )

    return StreamingResponse(
        _diag_wrap_stream(
            gen(),
            route="/work_mode/reasoning_stream_upload",
            session_id=sid,
            request_id=_rsu_request_id,
            start_ts=_rsu_start_ts,
            mode="reasoning",
        ),
        media_type="application/x-ndjson",
        headers=_ndjson_stream_headers(),
    )


@app.post("/work_mode/reasoning_panel_title")
async def work_mode_reasoning_panel_title(data: WorkModePanelTitlePayload):
    """LLM-generated tab label after the first completed reasoning turn on a panel (browser UI)."""
    sid = _work_mode_touch_session(data.session_id)
    if reasoning_ai is None:
        raise HTTPException(503, "Reasoning model not loaded")
    up = (data.user_prompt or "").strip()
    md = (data.markdown_excerpt or "").strip()
    sm = (data.summary_excerpt or "").strip()
    if not up and not md and not sm:
        raise HTTPException(400, "Empty payload")
    try:
        title = await asyncio.to_thread(
            reasoning_ai.generate_reasoning_panel_title,
            up,
            md,
            sm,
        )
    except Exception as e:
        print(f"[WORK_MODE/reasoning_panel_title] error: {e}")
        raise HTTPException(500, "Title generation failed") from e
    return {"title": (title or "").strip()}


# =========================
# FEEDBACK
# =========================

class Feedback(BaseModel):
    session_id: str
    feedback: str
    userAgent: str | None = None
    timestamp: str | None = None

@app.post("/feedback")
async def receive_feedback(data: Feedback):
    size = len(data.feedback.encode("utf-8"))
    if size > MAX_FEEDBACK_BYTES:
        raise HTTPException(413, "Feedback exceeds 1MB limit")

    path = user_feedback_dir(safe_id(data.session_id)) / "feedback.jsonl"

    entry = data.dict()
    entry["timestamp"] = entry.get("timestamp") or datetime.utcnow().isoformat()

    with open(path, "a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")

    return {"status": "ok"}

class TextInput(BaseModel):
    session_id: str
    text: str
    client: str = "vera"
    stream_tts: bool = False
    context_snapshot: dict | None = None
    """When True, skip LLM and synthesize `text` verbatim (sentence-chunked TTS like normal replies)."""
    tts_only: bool = False


# 2026-05-29 — multi-action planner (shadow-only this turn).
# The planner module is observable + testable on its own before the
# dispatcher is allowed to act on its plans. This input model + endpoint
# give the frontend a way to request a structured plan; the shadow-log
# integration below keeps a server-side audit trail without changing any
# existing execution paths.
class PlanActionsInput(BaseModel):
    session_id: str
    text: str
    # ``use_llm`` is a debug knob: when True (default), the planner asks the
    # VERA LLM for a richer plan and falls back to deterministic if the LLM
    # output fails schema/family validation. Smoke tests pass False to keep
    # the deterministic backbone exclusively in play.
    use_llm: bool = True
    context: dict | None = None


# Lazy import wrapper so the planner module is reloadable in dev without
# restarting the FastAPI process (and so an import failure here never blocks
# the app from starting — the endpoint will just return 503).
def _load_multi_action_planner():
    try:
        from actions import multi_action_planner as _mp
        return _mp
    except Exception as exc:
        print(f"[planner] import failed (will return 503): {exc}", flush=True)
        return None


def _shadow_run_multi_action_planner(
    *,
    text: str,
    session_id: str,
    note: str = "",
) -> None:
    """Fire-and-forget shadow planner call from /text and /infer.

    Logs the resulting plan under the ``[planner]`` grep tag but does NOT
    change routing. This gives us a server-side audit trail while we
    verify the planner's output across real-world utterances before we
    flip the execution path. The dispatcher continues to use the legacy
    single-action routers.

    NEVER raises — any failure here is swallowed so a shadow log can never
    take down a request path.
    """
    if not text:
        return
    # Re-entry guard — see _planner_executing_var comment.
    if _planner_executing_var.get():
        return
    mp = _load_multi_action_planner()
    if mp is None:
        return
    try:
        triggered, trigger_reason = mp.should_trigger_planner(text)
        # Skip the planner entirely when the heuristic gate is closed AND
        # the text is short — keeps log noise down for "what time is it".
        if not triggered and len(text) < 24:
            return
        plan = mp.plan_user_actions(text, vera=None)
        ok, errors, cq = mp.validate_plan(plan)
        mp.log_planner(
            raw_user_text=text,
            plan=plan,
            triggered=triggered,
            trigger_reason=trigger_reason,
            validation_results={"ok": ok, "errors": errors, "clarification": cq},
            greedy_router_skipped=False,
            note=note or ("shadow_from_" + (note or "request")),
        )
    except Exception as exc:
        try:
            print(f"[planner] shadow_swallowed exc={exc}", flush=True)
        except Exception:
            pass


def _dispatch_planned_action_directly(
    action: dict,
    *,
    session_id: str,
    client_context_snapshot: dict | None = None,
) -> tuple[str, float, dict | None] | None:
    """Direct backend dispatch for action families we don't want routed
    through ``process_user_input``.

    Why this exists: relying on the LLM router to interpret a tiny planner
    span like ``"play Feather by Sabrina Carpenter"`` proved unreliable —
    the LLM would frequently return a chatty "Playing Feather…" reply
    WITHOUT invoking `music.play_track`, so the assistant claimed to play
    the song while no ui_payload reached the frontend. Direct dispatch
    uses the planner's structured payload (`query`, `direction`, etc.)
    and calls the same handlers the single-action path uses, so the
    resulting ui_payload shape is identical (and panel renders the same).

    Returns:
        ``(reply, t_llm, action_result)`` triple ready to feed into the
        executor's aggregate. Returns ``None`` to mean "this family
        doesn't have a direct backend dispatcher — fall back to
        ``process_user_input``".
    """
    family = (action or {}).get("type") or ""
    payload = (action or {}).get("payload") or {}
    t0 = perf_counter()
    try:
        print(
            "[action_dispatch] "
            + json.dumps(
                {
                    "action_type": family,
                    "span": ((action or {}).get("span") or "")[:160],
                    "payload": payload if isinstance(payload, dict) else {},
                    "direct_dispatch_candidate": family.startswith("music."),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
        if family.startswith("music."):
            print(
                "[music_action_dispatch] "
                + json.dumps(
                    {
                        "action_type": family,
                        "span": ((action or {}).get("span") or "")[:160],
                        "payload": payload if isinstance(payload, dict) else {},
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass

    def _log_music_action_result(ar: dict | None) -> None:
        if not family.startswith("music."):
            return
        try:
            up = (ar or {}).get("ui_payload") or {}
            print(
                "[music_action_result] "
                + json.dumps(
                    {
                        "action_type": family,
                        "success": isinstance(ar, dict) and bool(up),
                        "response_fragment": str((ar or {}).get("spoken_reply") or "")[:200],
                        "ui_payload_present": bool(up),
                        "ui_payload_op": up.get("op") or "",
                        "ui_payload_delta": up.get("delta"),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass

    if family == "panel.open":
        span_text = str(action.get("span") or "").strip()
        slots: dict = {"count": _work_mode_create_reasoning_panel_count(span_text) or 1}
        if isinstance(payload, dict) and payload.get("content_task"):
            slots["content_task"] = str(payload.get("content_task") or "").strip()
        if isinstance(payload, dict) and payload.get("new_panel_request_id"):
            slots["new_panel_request_id"] = str(payload.get("new_panel_request_id") or "").strip()
        if isinstance(payload, dict) and payload.get("action_plan_id"):
            slots["action_plan_id"] = str(payload.get("action_plan_id") or "").strip()
        ar = handle_work_mode_reasoning_open_panel(client_context_snapshot, slots)
        try:
            up = (ar or {}).get("ui_payload") or {}
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "raw_panel_span": (action.get("span") or "")[:160],
                        "direct_panel_open_dispatch": True,
                        "content_task": slots.get("content_task") or "",
                        "panel_open_request_id": slots.get("new_panel_request_id") or "",
                        "action_plan_id": slots.get("action_plan_id") or "",
                        "action_ui_payload_present": bool(up),
                        "action_ui_payload_type": up.get("panel_type") or "",
                        "action_ui_payload_op": up.get("op") or "",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family.startswith("info."):
        info_span = (action.get("span") or payload.get("text") or payload.get("query") or "").strip()
        info_query = (payload.get("query") or payload.get("text") or info_span).strip()
        info_location = (payload.get("location") or payload.get("query") or "").strip()
        info_action_type = ""
        route: dict | None = None
        classification: dict | None = None

        if family == "info.time":
            info_action_type = "time.current"
            route = {
                "domain": "utility",
                "is_action_request": True,
                "action_name": "time.current",
                "slots": {"location": clean_location_text(info_location)},
                "needs_followup": False,
                "missing_slot": None,
            }
        elif family == "info.weather":
            route = weather_action_route_from_text(
                info_span, location_hint=info_location, session_id=session_id
            )
            info_action_type = str(route.get("action_name") or "weather.current")
            if not route.get("needs_followup"):
                parsed_loc = clean_location_text(
                    (route.get("_parsed_weather") or {}).get("location") or ""
                )
                if parsed_loc:
                    route["slots"]["location"] = parsed_loc
                elif info_location:
                    route["slots"]["location"] = clean_location_text(info_location)
        elif (
            family == "info.search"
            and not looks_like_supported_app_action(info_span)
            and re.search(
                r"\b(?:search(?:\s+the\s+web)?\s+for|look\s+up|google)\b",
                info_span,
                re.IGNORECASE,
            )
        ):
            info_action_type = "web.search"
            route = {
                "domain": "web",
                "is_action_request": True,
                "action_name": "web.search",
                "slots": {"query": info_query, "user_text": info_span},
                "needs_followup": False,
                "missing_slot": None,
            }
        else:
            try:
                classification = classify_info_tool(
                    info_span,
                    recent_news_context=get_recent_news_context(session_id),
                    recent_sports_context=get_recent_sports_context(session_id),
                    session_id=session_id,
                )
                route = build_route_from_info_tool(info_span, classification, session_id)
                info_action_type = str((route or {}).get("action_name") or "")
            except Exception as _info_exc:
                print(f"[planner] info_dispatch_classifier_failed type={family} exc={_info_exc}")
                classification = None
                route = None

            if route is None:
                if family == "info.news":
                    info_action_type = "news.latest"
                    route = {
                        "domain": "news",
                        "is_action_request": True,
                        "action_name": "news.latest",
                        "slots": {"query": info_query, "user_text": info_span},
                        "needs_followup": False,
                        "missing_slot": None,
                    }
                elif family == "info.finance":
                    info_action_type = "finance.quote"
                    route = {
                        "domain": "finance",
                        "is_action_request": True,
                        "action_name": "finance.quote",
                        "slots": {"query": info_query, "user_text": info_span},
                        "needs_followup": False,
                        "missing_slot": None,
                    }
                elif family == "info.search":
                    # 2026-06-01 — Priority-order patch: defense-in-depth.
                    # If the planner attached info.search to a span that is
                    # ACTUALLY a supported VERA app action ("play Feather by
                    # Sabrina Carpenter", "set a 5 minute timer", "open a
                    # reasoning panel"), defer to the legacy single-action
                    # router (route_action_request) instead of forcing a
                    # web.search dispatch. The planner anchor table has
                    # music / timer / panel ordered AFTER info.search, so
                    # a tie can land on info.search even when the user
                    # clearly meant the supported action.
                    if looks_like_supported_app_action(info_span):
                        try:
                            print(
                                "[planner_action_dispatch_defer] " + json.dumps(
                                    {
                                        "family": "info.search",
                                        "info_span": info_span[:200],
                                        "reason": "supported_app_action_intent_detected",
                                    },
                                    ensure_ascii=False,
                                ),
                                flush=True,
                            )
                        except Exception:
                            pass
                        info_action_type = ""
                        route = None
                    else:
                        info_action_type = "web.search"
                        route = {
                            "domain": "web",
                            "is_action_request": True,
                            "action_name": "web.search",
                            "slots": {"query": info_query, "user_text": info_span},
                            "needs_followup": False,
                            "missing_slot": None,
                        }
                elif family == "info.sports":
                    # Planner saw a sports anchor but the classifier didn't
                    # confidently route it. Run the sport-aware classifier
                    # directly so we still dispatch to the right web.sports_*
                    # action (with the sport / entity / query_type slots
                    # populated) rather than collapsing to generic web.search.
                    try:
                        _planner_sports_intent = classify_sports_intent(
                            info_span,
                            recent_sports_context=get_recent_sports_context(session_id),
                        )
                    except Exception:  # noqa: BLE001
                        _planner_sports_intent = None
                    if isinstance(_planner_sports_intent, dict) and _planner_sports_intent.get("is_sports"):
                        _planner_action_name = _sports_action_name_for_intent(_planner_sports_intent)
                        info_action_type = _planner_action_name
                        route = {
                            "domain": "sports",
                            "is_action_request": True,
                            "action_name": _planner_action_name,
                            "slots": {
                                "query": info_query,
                                "user_text": info_span,
                                "sports_intent": _planner_sports_intent,
                            },
                            "needs_followup": False,
                            "missing_slot": None,
                        }
                    else:
                        info_action_type = "web.search"
                        route = {
                            "domain": "web",
                            "is_action_request": True,
                            "action_name": "web.search",
                            "slots": {"query": info_query, "user_text": info_span},
                            "needs_followup": False,
                            "missing_slot": None,
                        }

        try:
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "info_action_detected": True,
                        "info_action_type": info_action_type,
                        "info_query": info_query[:200],
                        "info_location": info_location[:120],
                        "info_route": (classification or {}).get("route") or "",
                        "info_tool": (classification or {}).get("tool") or "",
                        "info_handler_called": bool(route),
                        "legacy_info_router_skipped_for_planner": True,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass

        if route is None:
            return None

        try:
            ar, t_action = execute_structured_action(
                session_id,
                info_span,
                route,
                client_context_snapshot=client_context_snapshot,
            )
        except Exception as _info_exec_exc:
            print(f"[planner] info_dispatch_execute_failed type={family} exc={_info_exec_exc}")
            return None

        try:
            if family == "info.finance":
                print(
                    "[finance_anchor_detected] "
                    + json.dumps(
                        {
                            "raw_clause": info_span[:240],
                            "query": info_query[:240],
                            "finance_anchor_detected": _has_finance_anchor_in_text(info_span),
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
                print(
                    "[finance_route_selected] "
                    + json.dumps(
                        {
                            "raw_clause": info_span[:240],
                            "selected_route": info_action_type
                            or str((route or {}).get("action_name") or "finance.quote"),
                            "query": info_query[:240],
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            print(
                "[planner_info_action] "
                + json.dumps(
                    {
                        "family": family,
                        "info_action_detected": True,
                        "info_action_type": info_action_type or str(route.get("action_name") or ""),
                        "info_query": info_query[:200],
                        "info_location": info_location[:120],
                        "info_handler_called": True,
                        "info_spoken_reply": str((ar or {}).get("spoken_reply") or "")[:300],
                        "action_payloads_count": int(bool((ar or {}).get("ui_payload"))),
                        "legacy_info_router_skipped_for_planner": True,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return (ar or {}).get("spoken_reply") or "", float(t_action or 0.0), ar

    if family == "checklist.plan":
        from actions.checklist_plan import (
            CHECKLIST_PLAN_MAIN_ITEM_LIMIT,
            checklist_plan_context_from_snapshot,
            log_checklist_plan_detected,
        )

        span_text = (action.get("span") or "").strip()
        payload = action.get("payload") if isinstance(action.get("payload"), dict) else {}
        source = str(payload.get("source") or "voice")
        log_checklist_plan_detected(span_text or str(payload.get("raw") or ""), source=source)
        ctx = checklist_plan_context_from_snapshot(client_context_snapshot)
        main_count = int(ctx.get("main_count") or 0)
        subitem_count = int(ctx.get("subitem_count") or 0)
        try:
            print(
                "[checklist_plan_context] "
                + json.dumps(
                    {
                        "main_count": main_count,
                        "subitem_count": subitem_count,
                        "source": source,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            print(
                "[checklist_plan_action_start] "
                + json.dumps(
                    {
                        "span": span_text[:200],
                        "source": source,
                        "main_count": main_count,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        if main_count <= 0:
            spoken = "Add text to at least one ongoing item first."
            ar = {
                "spoken_reply": spoken,
                "action_type": "checklist_plan",
                "data": {"success": False, "reason": "no_main_items", "main_count": 0},
                "ui_payload": None,
            }
            try:
                print(
                    "[checklist_plan_action_done] "
                    + json.dumps({"success": False, "reason": "no_main_items"}, ensure_ascii=False),
                    flush=True,
                )
            except Exception:
                pass
            return spoken, perf_counter() - t0, ar
        if main_count > CHECKLIST_PLAN_MAIN_ITEM_LIMIT:
            try:
                print(
                    "[checklist_plan_limit_exceeded] "
                    + json.dumps(
                        {
                            "main_count": main_count,
                            "limit": CHECKLIST_PLAN_MAIN_ITEM_LIMIT,
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            spoken = (
                f"I can make a plan for up to {CHECKLIST_PLAN_MAIN_ITEM_LIMIT} main checklist items. "
                f"You currently have {main_count}. Please remove or group a few first."
            )
            ar = {
                "spoken_reply": spoken,
                "action_type": "checklist_plan",
                "data": {
                    "success": False,
                    "reason": "too_many_main_items",
                    "main_count": main_count,
                    "limit": CHECKLIST_PLAN_MAIN_ITEM_LIMIT,
                },
                "ui_payload": None,
            }
            try:
                print(
                    "[checklist_plan_action_done] "
                    + json.dumps(
                        {"success": False, "reason": "too_many_main_items", "main_count": main_count},
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            return spoken, perf_counter() - t0, ar
        spoken = "I'll build a plan from your checklist."
        ui_payload = {
            "panel_type": "checklist_plan",
            "op": "run",
            "source": source,
            "max_main_items": CHECKLIST_PLAN_MAIN_ITEM_LIMIT,
            "main_count": main_count,
            "subitem_count": subitem_count,
        }
        ar = {
            "spoken_reply": spoken,
            "action_type": "checklist_plan",
            "data": {"success": True, "main_count": main_count, "subitem_count": subitem_count},
            "ui_payload": ui_payload,
        }
        try:
            print(
                "[checklist_plan_action_done] "
                + json.dumps(
                    {"success": True, "main_count": main_count, "subitem_count": subitem_count},
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return spoken, perf_counter() - t0, ar

    if family == "checklist.add":
        # Multi-action planner spans can be intentionally terse:
        #   "can you add hello and play yea in my playlist"
        # may arrive here as a structured checklist.add action with
        # payload.items=["hello"], even though the span itself lacks the
        # legacy "...to checklist" tail that is_checklist_action_request()
        # expects. Dispatch from the planner payload directly so the
        # checklist mutation returns the same frontend ui_payload as the
        # single-action route, instead of relying on the short span to be
        # re-detected by the greedy router.
        raw_items = payload.get("items") if isinstance(payload, dict) else []
        items = [
            str(item or "").strip()
            for item in (raw_items if isinstance(raw_items, list) else [raw_items])
            if str(item or "").strip()
        ]
        if not items:
            ar = {
                "spoken_reply": "I could not find what to add to the checklist.",
                "action_type": "checklist",
                "data": {"changed": False, "planner_payload_items": []},
                "ui_payload": None,
            }
            try:
                print(
                    "[planner_action_dispatch] "
                    + json.dumps(
                        {
                            "family": family,
                            "raw_checklist_span": (action.get("span") or "")[:160],
                            "checklist_items_from_planner": [],
                            "direct_checklist_dispatch": True,
                            "action_ui_payload_present": False,
                            "payload_dropped_reason": "empty_planner_checklist_items",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            return ar.get("spoken_reply") or "", perf_counter() - t0, ar

        # Reuse the existing work-mode checklist handler, but give it a
        # canonical checklist command so its parser always returns
        # item_texts and therefore a checklist_control payload.
        if len(items) == 1:
            item_phrase = items[0]
        else:
            item_phrase = ", ".join(items[:-1]) + f" and {items[-1]}"
        synthetic_text = f"add {item_phrase} to the checklist"
        ar = _handle_checklist_action(
            session_id,
            synthetic_text,
            "checklist.add_item",
            client_context_snapshot,
        )
        try:
            up = (ar or {}).get("ui_payload") or {}
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "raw_checklist_span": (action.get("span") or "")[:160],
                        "synthetic_checklist_text": synthetic_text[:160],
                        "checklist_items_from_planner": items,
                        "direct_checklist_dispatch": True,
                        "action_ui_payload_present": bool(up),
                        "action_ui_payload_type": up.get("panel_type") or "",
                        "action_ui_payload_op": up.get("op") or "",
                        "checklist_payload_mode": up.get("payload_mode") or "",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.play":
        # 2026-05-29 spec PART 2 — dispatch by ``play_kind`` rather than
        # re-parsing the raw text. The planner has already normalized the
        # utterance via ``parse_music_play_intent`` and attached the
        # structured intent to the payload. We re-parse the raw span here
        # as a SAFETY NET in case an older planner / LLM-built plan
        # omitted the music_intent block, but the parsed result is
        # equivalent to what the planner would have produced.
        planner_music_span = (action.get("span") or "").strip()
        raw_music_span = planner_music_span
        existing_intent = payload.get("music_intent") if isinstance(payload, dict) else None
        if isinstance(existing_intent, dict) and existing_intent.get("play_kind"):
            intent = existing_intent
            intent_source_path = "planner_payload"
        else:
            try:
                from actions.music_intent import parse_music_play_intent as _parse_mi
                intent = _parse_mi(planner_music_span or payload.get("query") or "")
                intent_source_path = "executor_fallback_parse"
            except Exception:
                intent = {
                    "play_kind": "track",
                    "source": "spotify",
                    "query": (payload.get("query") or "").strip(),
                    "raw_span": planner_music_span,
                    "query_before_cleanup": "",
                    "query_after_cleanup": "",
                    "playlist_scope_phrase": "",
                    "confidence": 0.5,
                }
                intent_source_path = "fallback_default"

        play_kind = (intent.get("play_kind") or "track").lower()
        source = (intent.get("source") or "spotify").lower()
        query = (intent.get("query") or payload.get("query") or "").strip()
        playlist_scope_phrase = (intent.get("playlist_scope_phrase") or "").strip()

        log_base = {
            "family": family,
            "raw_music_span": raw_music_span[:160],
            "normalized_music_intent": {
                "play_kind": play_kind,
                "source": source,
                "query": query[:120],
                "playlist_scope_phrase": playlist_scope_phrase,
                "confidence": float(intent.get("confidence") or 0.0),
            },
            "play_kind": play_kind,
            "source": source,
            "query_before_cleanup": (intent.get("query_before_cleanup") or "")[:120],
            "query_after_cleanup": (intent.get("query_after_cleanup") or "")[:120],
            "intent_source_path": intent_source_path,
            "spotify_play_called_with_uri": False,
            "spotify_resume_called": False,
        }

        def _emit_dispatch_log(extra: dict | None = None) -> None:
            try:
                merged = dict(log_base)
                if extra:
                    merged.update(extra)
                print(
                    "[planner_action_dispatch] "
                    + json.dumps(merged, ensure_ascii=False),
                    flush=True,
                )
            except Exception:
                pass

        # ---- playlist_by_name -------------------------------------------------
        if play_kind == "playlist_by_name":
            if not query:
                ar = {
                    "spoken_reply": "Which playlist should I play?",
                    "action_type": "music",
                    "data": None,
                    "ui_payload": None,
                }
                _emit_dispatch_log({
                    "playlist_name_intent_detected": True,
                    "playlist_name_query": "",
                    "routed_to_existing_playlist_handler": False,
                    "generic_track_search_blocked": True,
                    "clarification_asked": True,
                })
                return ar.get("spoken_reply") or "", perf_counter() - t0, ar
            ar = handle_music_play_playlist(
                {"playlist_name": query, "playlist_scope_phrase": playlist_scope_phrase}
            )
            try:
                set_recent_action_from_result(
                    session_id,
                    "music.play_playlist",
                    {"playlist_name": query, "planner_span": planner_music_span},
                    ar,
                )
            except Exception:
                pass
            up = (ar or {}).get("ui_payload") or {}
            _emit_dispatch_log({
                "playlist_name_intent_detected": True,
                "playlist_name_query": query[:120],
                "routed_to_existing_playlist_handler": True,
                "playlist_handler_payload_op": up.get("op") or "",
                "music_play_payload_present": bool(up),
                "music_play_op": up.get("op") or "",
                "generic_track_search_blocked": True,
                "clarification_asked": False,
            })
            return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

        # ---- resume -----------------------------------------------------------
        if play_kind == "resume":
            ar = handle_music_resume()
            _log_music_action_result(ar)
            _emit_dispatch_log({
                "spotify_resume_called": True,
                "music_play_op": ((ar or {}).get("ui_payload") or {}).get("op") or "",
                "music_play_payload_present": bool((ar or {}).get("ui_payload")),
            })
            return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

        # ---- album ------------------------------------------------------------
        if play_kind == "album":
            if not query:
                ar = {
                    "spoken_reply": "Which album should I play?",
                    "action_type": "music",
                    "data": None,
                    "ui_payload": None,
                }
                _emit_dispatch_log({"album_intent_detected": True, "music_play_payload_present": False})
                return ar.get("spoken_reply") or "", perf_counter() - t0, ar
            try:
                from actions.music import handle_music_play_album as _hpa
                ar = _hpa({"album_name": query, "query": query})
            except Exception:
                # Defensive — fall back to generic search if album path is missing.
                ar = handle_music_play_for_user_text(f"album {query}")
            try:
                set_recent_action_from_result(
                    session_id, "music.play_album", {"album_name": query}, ar
                )
            except Exception:
                pass
            up = (ar or {}).get("ui_payload") or {}
            _emit_dispatch_log({
                "album_intent_detected": True,
                "music_play_op": up.get("op") or "",
                "music_play_panel_type": up.get("panel_type") or "",
                "music_play_payload_present": bool(up),
                "music_play_uri_present": bool(up.get("uri")),
            })
            return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

        # ---- builtin / track --------------------------------------------------
        # Built-in is now routed by the normalized play_kind instead of
        # hoping the generic text handler re-detects the same catalog match.
        # This keeps "play lo-fi" from falling through to Spotify when the
        # planner already resolved it as source=builtin.
        if not query:
            ar = {
                "spoken_reply": "What would you like me to play?",
                "action_type": "music",
                "data": None,
                "ui_payload": None,
            }
            _emit_dispatch_log({"music_play_payload_present": False, "music_play_op": ""})
            return ar.get("spoken_reply") or "", perf_counter() - t0, ar
        if play_kind == "builtin":
            bm = payload.get("builtin_match") if isinstance(payload, dict) else None
            if not isinstance(bm, dict):
                bm = intent.get("builtin_match") if isinstance(intent, dict) else None
            try:
                if isinstance(bm, dict) and bm.get("kind") == "playlist":
                    ar = handle_music_play_builtin(playlist_id=str(bm.get("id") or ""), sound_id="")
                elif isinstance(bm, dict) and bm.get("kind") == "sound":
                    ar = handle_music_play_builtin(playlist_id="", sound_id=str(bm.get("id") or ""))
                else:
                    ar = handle_music_play_for_user_text(query)
            except Exception:
                ar = handle_music_play_for_user_text(query)
            try:
                set_recent_action_from_result(session_id, "music.play_builtin", {"query": query}, ar)
            except Exception:
                pass
            up = (ar or {}).get("ui_payload") or {}
            _emit_dispatch_log({
                "music_play_query": query[:120],
                "music_play_payload_present": bool(up),
                "music_play_op": up.get("op") or "",
                "music_play_panel_type": up.get("panel_type") or "",
                "music_play_playlist_id": up.get("playlist_id") or "",
                "music_play_sound_id": up.get("sound_id") or "",
                "planned_music_play_called": True,
                "builtin_play_kind_routed_directly": True,
                "spotify_play_called_with_uri": False,
                "playlist_scope_detected": False,
            })
            return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar
        ar = handle_music_play_for_user_text(query)
        try:
            recent_kind = "music.play_builtin" if play_kind == "builtin" else "music.play_track"
            set_recent_action_from_result(session_id, recent_kind, {"query": query}, ar)
        except Exception:
            pass
        up = (ar or {}).get("ui_payload") or {}
        _emit_dispatch_log({
            "music_play_query": query[:120],
            "music_play_payload_present": bool(up),
            "music_play_op": up.get("op") or "",
            "music_play_panel_type": up.get("panel_type") or "",
            "music_play_uri_present": bool(up.get("uri")),
            "music_play_playlist_id": up.get("playlist_id") or "",
            "music_play_sound_id": up.get("sound_id") or "",
            "planned_music_play_called": True,
            "spotify_play_called_with_uri": bool(up.get("uri") and up.get("op") == "play_track"),
            "playlist_scope_detected": False,
        })
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.pause":
        ar = handle_music_pause()
        _log_music_action_result(ar)
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.resume":
        ar = handle_music_resume()
        _log_music_action_result(ar)
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.next":
        ar = handle_music_skip_next(client_context_snapshot)
        _log_music_action_result(ar)
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.previous":
        ar = handle_music_skip_previous(client_context_snapshot)
        _log_music_action_result(ar)
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "music.volume":
        direction = (payload.get("direction") or "").strip().lower()
        # Per-step delta intentionally matches the single-action handler
        # defaults so multi-action volume changes feel identical to
        # "turn up the volume" said on its own.
        if direction == "down":
            ar = handle_music_volume_down()
        elif direction == "set" and payload.get("level") is not None:
            # No backend "set absolute volume" handler today; degrade to
            # a single up/down nudge so the executor still emits a
            # music_control payload the frontend understands.
            ar = handle_music_volume_up()
        else:
            ar = handle_music_volume_up()
        _log_music_action_result(ar)
        return (ar or {}).get("spoken_reply") or "", perf_counter() - t0, ar

    if family == "timer.extend":
        span_text = (action.get("span") or "").strip()
        payload = action.get("payload") if isinstance(action.get("payload"), dict) else {}
        try:
            print(
                "[timer_extend_action_payload] "
                + json.dumps(
                    {
                        "family": family,
                        "span": span_text[:160],
                        "duration_delta_seconds": payload.get("duration_delta_seconds"),
                        "source": payload.get("source"),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            wm_out = _try_work_mode_timer_extend_core(
                session_id, span_text, client_context_snapshot, "vera"
            )
        except Exception as _texc:
            wm_out = None
            try:
                print(
                    f"[planner_action_dispatch] timer_extend_exception family={family} exc={_texc}"
                )
            except Exception:
                pass
        if not isinstance(wm_out, dict):
            ar = {
                "spoken_reply": (
                    "I understood the timer extension, but couldn't apply it. "
                    "Try saying 'add 3 minutes to the timer.'"
                ),
                "action_type": "work_mode_timer",
                "data": {"changed": False, "family": family},
                "ui_payload": None,
            }
            return ar["spoken_reply"], perf_counter() - t0, ar
        reply_text = str(wm_out.get("reply") or "").strip()
        wm_block = wm_out.get("work_mode_timer")
        ar = {
            "spoken_reply": reply_text or "Okay, I extended your timer.",
            "action_type": "work_mode_timer",
            "data": {"changed": bool(wm_block), "family": family},
            "ui_payload": None,
            "work_mode_timer": wm_block,
        }
        return ar["spoken_reply"], perf_counter() - t0, ar

    if family in ("timer.set", "timer.cancel"):
        # 2026-05-29 spec PART 3 — direct timer dispatch.
        # The planner just hands us the span; we route it through the
        # existing ``_try_work_mode_timer_core`` so the work-mode
        # snapshot/cancel/duration logic stays in one place. We surface
        # ``work_mode_timer`` on the action_result so the executor's
        # aggregator can hand it to the /infer NDJSON stream — without
        # this propagation the timer would be planned but never fire on
        # the device.
        span_text = (action.get("span") or "").strip()
        if not span_text:
            span_text = "set a timer" if family == "timer.set" else "cancel the timer"
        try:
            print(
                "[timer_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "action_type": "timer.set" if family == "timer.set" else "timer.cancel",
                        "span": span_text[:160],
                        "planned_duration_seconds": (action.get("payload") or {}).get(
                            "duration_seconds"
                        ) if isinstance(action.get("payload"), dict) else None,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            wm_out = _try_work_mode_timer_core(session_id, span_text, client_context_snapshot, "vera")
        except Exception as _texc:
            wm_out = None
            try:
                print(f"[planner_action_dispatch] timer_dispatch_exception family={family} exc={_texc}")
            except Exception:
                pass
        if not isinstance(wm_out, dict):
            # The timer core declined (no snapshot, no duration parsed, …).
            # Bubble up a graceful spoken reply rather than nothing so the
            # multi-action aggregate still narrates what happened.
            fallback_reply = (
                "I understood the timer request, but couldn't start it. "
                "Try saying 'set a timer for 10 minutes.'"
                if family == "timer.set"
                else "I couldn't find a timer to cancel."
            )
            ar = {
                "spoken_reply": fallback_reply,
                "action_type": "work_mode_timer",
                "data": {"changed": False, "family": family},
                "ui_payload": None,
            }
            try:
                print(
                    "[planner_action_dispatch] "
                    + json.dumps(
                        {
                            "family": family,
                            "timer_span": span_text[:160],
                            "timer_core_returned": False,
                            "payload_dropped_reason": "timer_core_declined",
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            return ar["spoken_reply"], perf_counter() - t0, ar

        reply_text = str(wm_out.get("reply") or "").strip()
        wm_block = wm_out.get("work_mode_timer")
        try:
            print(
                "[timer_action_payload] "
                + json.dumps(
                    {
                        "action": family,
                        "duration_seconds": (
                            (action.get("payload") or {}).get("duration_seconds")
                            if isinstance(action.get("payload"), dict)
                            else None
                        ),
                        "work_mode_timer_created": bool(
                            isinstance(wm_block, dict) and wm_block.get("fire_at_epoch_ms")
                        ),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        ar = {
            "spoken_reply": reply_text or (
                "Okay, timer set." if family == "timer.set" else "Okay, timer cancelled."
            ),
            "action_type": "work_mode_timer",
            "data": {"changed": True, "family": family},
            "ui_payload": None,
            # Carried separately so ``execute_planned_actions`` can merge
            # it into the combined_ar (work_mode_timer is a top-level
            # meta field on /infer, not a panel ui_payload).
            "work_mode_timer": wm_block,
        }
        try:
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "timer_span": span_text[:160],
                        "timer_core_returned": True,
                        "work_mode_timer_present": wm_block is not None,
                        "work_mode_timer_cancel": bool(isinstance(wm_block, dict) and wm_block.get("cancel")),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return ar["spoken_reply"], perf_counter() - t0, ar

    if family == "reasoning.request":
        # 2026-05-29 spec PART 1 — direct dispatch for reasoning.request.
        #
        # Why: previously reasoning.request fell through to
        # ``process_user_input``, which routed the bare span through the
        # general LLM and produced a chat reply (never a reasoning panel).
        # The frontend then had to fall back to its own reasoning gate,
        # which fired ``/work_mode/reasoning_stream`` with the FULL
        # original transcript — contaminating the prompt with
        # "play lo-fi", "go to panel 2", etc.
        #
        # Now: emit a structured ``work_mode_reasoning open_and_stream``
        # ui_payload carrying ONLY the cleaned reasoning span and the
        # resolved (1-based + 0-based) target panel index. The frontend
        # NDJSON applier activates the target panel and calls
        # ``/work_mode/reasoning_stream`` with the clean prompt.
        clean_prompt_raw = ""
        if isinstance(payload, dict):
            clean_prompt_raw = str(payload.get("text") or "").strip()
        if not clean_prompt_raw:
            clean_prompt_raw = str(action.get("span") or "").strip()

        # Resolve panel target (1-based from planner → keep 1-based +
        # carry a 0-based mirror for the frontend's existing executor,
        # which uses ``panelIndex - 1`` to index DOM tabs).
        target_index_1based: int | None = None
        target_index_0based: int | None = None
        target_title: str | None = None
        target_new_panel = False
        new_panel_request_id = ""
        action_plan_id_for_payload = ""
        explicit_panel_destination = False
        content_task_for_payload = ""
        parent_turn_id_for_payload = ""
        planner_action_index: int | None = None
        if isinstance(payload, dict):
            tgt = payload.get("target") or {}
            if isinstance(tgt, dict):
                target_new_panel = bool(tgt.get("new"))
                idx = tgt.get("index")
                if isinstance(idx, int) and idx >= 1:
                    target_index_1based = idx
                    target_index_0based = idx - 1
                title = tgt.get("title")
                if isinstance(title, str) and title.strip():
                    target_title = title.strip()
            new_panel_request_id = str(payload.get("new_panel_request_id") or "").strip()
            action_plan_id_for_payload = str(payload.get("action_plan_id") or "").strip()
            explicit_panel_destination = bool(payload.get("explicit_panel_destination"))
            content_task_for_payload = str(payload.get("content_task") or "").strip()
            parent_turn_id_for_payload = str(payload.get("parent_turn_id") or "").strip()
            _pai = payload.get("planner_action_index")
            if isinstance(_pai, int):
                planner_action_index = _pai
        if not parent_turn_id_for_payload and isinstance(client_context_snapshot, dict):
            parent_turn_id_for_payload = str(
                client_context_snapshot.get("turn_id")
                or client_context_snapshot.get("parent_turn_id")
                or ""
            ).strip()

        action_id_for_payload = ""
        reasoning_request_id_for_payload = ""
        if action_plan_id_for_payload and planner_action_index is not None:
            action_id_for_payload = f"{action_plan_id_for_payload}:{planner_action_index}"
            reasoning_request_id_for_payload = (
                f"{action_plan_id_for_payload}:reasoning:{planner_action_index}"
            )
        elif action_plan_id_for_payload:
            reasoning_request_id_for_payload = f"{action_plan_id_for_payload}:reasoning"

        # Hard warning: if the cleaned reasoning prompt still contains
        # known app-action phrases, log so live regressions are visible.
        contaminated_markers: list[str] = []
        if clean_prompt_raw:
            low_p = clean_prompt_raw.lower()
            for needle, label in (
                ("play lo-fi", "play_lofi"),
                ("play the lo-fi", "play_lofi"),
                ("pause music", "pause_music"),
                ("pause the music", "pause_music"),
                ("set a timer", "set_timer"),
                ("set timer", "set_timer"),
                ("checklist", "checklist"),
                ("go to panel", "go_to_panel"),
            ):
                if needle in low_p:
                    contaminated_markers.append(label)
            if contaminated_markers:
                try:
                    print(
                        "[reasoning_prompt_contaminated_by_app_action] "
                        + json.dumps(
                            {
                                "reasoning_prompt_final": clean_prompt_raw[:200],
                                "contamination_markers": contaminated_markers,
                                "source": "backend_reasoning_request_dispatcher",
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass

        # Title hint for the reasoning lane — a short, cleaned label that
        # the frontend can show on the tab while the answer streams in.
        title_hint = ""
        try:
            t = re.sub(r"^(?:please\s+)?(?:can\s+you\s+|could\s+you\s+|would\s+you\s+|please\s+)+", "", clean_prompt_raw or "", flags=re.IGNORECASE).strip()
            t = re.sub(r"^(?:explain|describe|tell\s+me\s+about|summari[sz]e|analy[sz]e|walk\s+me\s+through|teach\s+me\s+about)\s+", "", t, flags=re.IGNORECASE).strip()
            if t:
                title_hint = t[:60].rstrip(".,;:!? ")
        except Exception:
            title_hint = ""

        ui_payload: dict = {
            "panel_type": "work_mode_reasoning",
            "op": "open_and_stream",
            "prompt": clean_prompt_raw,
            "title_hint": title_hint,
            "target_panel_index_1based": target_index_1based,
            "target_panel_index_0based": target_index_0based,
            "target_panel_title": target_title,
            "target_panel": "new" if target_new_panel else None,
            "target_new_panel": target_new_panel,
            "new_panel_request_id": new_panel_request_id,
            "action_plan_id": action_plan_id_for_payload,
            "planner_action_index": planner_action_index,
            "action_id": action_id_for_payload,
            "reasoning_request_id": reasoning_request_id_for_payload,
            "request_id": reasoning_request_id_for_payload,
            "parent_turn_id": parent_turn_id_for_payload,
            "explicit_panel_destination": explicit_panel_destination,
            "content_task": content_task_for_payload,
            "source": "planner_reasoning_request_dispatcher",
        }
        _compound_raw = ""
        try:
            _compound_raw = str(_planner_plan_raw_text_var.get() or "").strip()
        except Exception:
            _compound_raw = ""
        if _compound_raw:
            ui_payload["original_user_text"] = _compound_raw
        try:
            print(
                "[reasoning_request_dispatch] "
                + json.dumps(
                    {
                        "action_id": action_id_for_payload,
                        "parent_turn_id": parent_turn_id_for_payload,
                        "explicit_panel_destination": explicit_panel_destination,
                        "panel_target": (
                            "new"
                            if target_new_panel
                            else target_index_1based
                            if target_index_1based is not None
                            else target_title
                            if target_title
                            else "active"
                        ),
                        "target_panel": (
                            target_index_1based
                            if target_index_1based is not None
                            else "new"
                            if target_new_panel
                            else target_title
                            if target_title
                            else "active"
                        ),
                        "task": (content_task_for_payload or clean_prompt_raw)[:160],
                        "content_task": (content_task_for_payload or clean_prompt_raw)[:160],
                        "new_panel_request_id": new_panel_request_id,
                        "reasoning_request_id": reasoning_request_id_for_payload,
                        "op": "open_and_stream",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            print(
                "[panel_task_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "content_task": clean_prompt_raw[:240],
                        "target_panel": (
                            "new"
                            if target_new_panel
                            else target_index_1based
                            if target_index_1based is not None
                            else target_title
                            if target_title
                            else "active"
                        ),
                        "new_panel_request_id": new_panel_request_id,
                        "action_plan_id": action_plan_id_for_payload,
                        "op": "open_and_stream",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass

        # Spoken stub for the multi-action aggregated voice reply.
        speak_reasoning_ack = not bool(target_new_panel and new_panel_request_id)
        if not speak_reasoning_ack:
            spoken = "Opening a reasoning panel."
        elif target_index_1based is not None:
            spoken = f"Explaining in Panel {target_index_1based}."
        elif target_title:
            spoken = f"Explaining in the {target_title} panel."
        else:
            spoken = "Opening a reasoning panel."

        ar: dict = {
            "spoken_reply": spoken,
            "speak": speak_reasoning_ack,
            "ui_status": spoken,
            "action_type": "work_mode_reasoning",
            "data": {
                "family": "reasoning.request",
                "target_panel_index_1based": target_index_1based,
                "target_panel_index_0based": target_index_0based,
                "target_panel_title": target_title,
                "target_panel": "new" if target_new_panel else None,
                "new_panel_request_id": new_panel_request_id,
                "action_plan_id": action_plan_id_for_payload,
                "explicit_panel_destination": explicit_panel_destination,
                "content_task": content_task_for_payload,
                "prompt_preview": clean_prompt_raw[:160],
                "prompt_contamination_markers": contaminated_markers,
                "ack_suppressed_reason": "new_panel_open_action_owns_ack" if not speak_reasoning_ack else "",
            },
            "ui_payload": ui_payload,
        }
        try:
            print(
                "[panel_task_result] "
                + json.dumps(
                    {
                        "content_task": clean_prompt_raw[:240],
                        "ui_payload_present": True,
                        "ui_payload_op": ui_payload.get("op"),
                        "prompt_len": len(clean_prompt_raw or ""),
                        "spoken_reply": spoken,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "reasoning_span": (action.get("span") or "")[:160],
                        "reasoning_prompt_final": clean_prompt_raw[:160],
                        "reasoning_target_panel_1based": target_index_1based,
                        "reasoning_target_panel_0based": target_index_0based,
                        "reasoning_target_panel_title": target_title,
                        "reasoning_target_panel": "new" if target_new_panel else None,
                        "new_panel_request_id": new_panel_request_id,
                        "action_plan_id": action_plan_id_for_payload,
                        "contamination_markers": contaminated_markers,
                        "direct_reasoning_dispatch": True,
                        "action_ui_payload_present": True,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return ar["spoken_reply"], perf_counter() - t0, ar

    # 2026-05-29 spec PART 5 — no direct dispatcher for this family. Log
    # so an unsupported family in a planned multi-action is visible in
    # logs rather than silently dropped. The executor will still attempt
    # ``process_user_input`` for the span, which handles panel.*,
    # reasoning.*, and voice.answer via existing routers. Anything else
    # gets surfaced as ``unsupported_action_family``.
    try:
        if family not in (
            "panel.navigate", "panel.open", "panel.close",
            "checklist.remove", "checklist.complete", "checklist.sync",
            "voice.answer",
        ):
            print(
                "[planner_action_dispatch] "
                + json.dumps(
                    {
                        "family": family,
                        "raw_span": (action.get("span") or "")[:160],
                        "direct_dispatch_supported": False,
                        "payload_dropped_reason": "unsupported_action_family",
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass
    return None


def _human_failure_reply_for_action(action: dict) -> str:
    """Return a short, friendly partial-success reply for a failed
    planned action.

    Used by :func:`execute_planned_actions` when an individual action
    hard-fails (exception, not a normal "I couldn't find that"
    spoken_reply). Without this, a multi-info utterance like
    ``"weather in Irvine and time in Tokyo"`` would silently drop the
    failed half — the user just hears the successful one and has no
    idea VERA tried the other. Returning a sentence here keeps the
    other action's reply intact while making the partial-failure
    explicit, e.g.
        "The time in Tokyo is 4:12 PM. I couldn't get the weather for
         Fountain Valley right now."
    """
    family = (action.get("type") or "").lower()
    payload = action.get("payload") or {}
    location = (payload.get("location") or "").strip()
    query = (payload.get("query") or "").strip()
    target = location or query
    if family == "info.time":
        if target:
            return f"I couldn't get the time for {target} right now."
        return "I couldn't get the time right now."
    if family == "info.weather":
        if target:
            return f"I couldn't get the weather for {target} right now."
        return "I couldn't get the weather right now."
    if family == "info.news":
        if target:
            return f"I couldn't get the news on {target} right now."
        return "I couldn't get the news right now."
    if family == "info.finance":
        if target:
            return f"I couldn't get the price information for {target} right now."
        return "I couldn't get the finance information right now."
    if family == "info.sports":
        if target:
            return f"I couldn't get the score for {target} right now."
        return "I couldn't get the sports update right now."
    if family.startswith("info."):
        return "I couldn't complete one of the info requests right now."
    return ""


_CHECKLIST_PLANNER_TO_HANDLER_ACTION = {
    "checklist.add": "checklist.add_item",
    "checklist.remove": "checklist.remove_item",
    "checklist.complete": "checklist.complete_item",
    "checklist.uncomplete": "checklist.uncomplete_item",
}

_CHECKLIST_ORDINAL_TO_INT = {
    "first": 1,
    "1st": 1,
    "one": 1,
    "second": 2,
    "2nd": 2,
    "two": 2,
    "third": 3,
    "3rd": 3,
    "three": 3,
    "fourth": 4,
    "4th": 4,
    "four": 4,
    "fifth": 5,
    "5th": 5,
    "five": 5,
    "sixth": 6,
    "6th": 6,
    "six": 6,
    "seventh": 7,
    "7th": 7,
    "seven": 7,
    "eighth": 8,
    "8th": 8,
    "eight": 8,
    "ninth": 9,
    "9th": 9,
    "nine": 9,
    "tenth": 10,
    "10th": 10,
    "ten": 10,
}


def _checklist_log(tag: str, payload: dict) -> None:
    """Best-effort temporary checklist debug logs requested for live triage."""
    try:
        print(f"[{tag}] " + json.dumps(payload, ensure_ascii=False, default=str), flush=True)
    except Exception:
        try:
            print(f"[{tag}] <unserializable>", flush=True)
        except Exception:
            pass


def _checklist_ordinal_range_from_planner_payload(payload: dict) -> dict | None:
    targets = payload.get("targets") if isinstance(payload, dict) else None
    if not isinstance(targets, list):
        return None
    for target in targets:
        if isinstance(target, dict) and target.get("kind") == "ordinal_range":
            return target
    return None


def _checklist_target_ordinals_from_planner_payload(payload: dict) -> list[int]:
    out: list[int] = []
    targets = payload.get("targets") if isinstance(payload, dict) else None
    if not isinstance(targets, list):
        return out
    for target in targets:
        n: int | None = None
        if isinstance(target, dict):
            raw = target.get("ordinal") or target.get("index")
        else:
            raw = target
        if isinstance(raw, int):
            n = raw
        else:
            s = str(raw or "").strip().lower()
            if re.fullmatch(r"\d{1,3}", s):
                n = int(s)
            else:
                n = _CHECKLIST_ORDINAL_TO_INT.get(s)
        if isinstance(n, int) and n > 0 and n not in out:
            out.append(n)
    return out


def _checklist_reply_fragment(reply: str) -> str:
    frag = str(reply or "").strip().rstrip(".").strip()
    frag = re.sub(r"\s+(?:to|from)\s+(?:your|the|my)\s+checklist$", "", frag, flags=re.IGNORECASE)
    frag = re.sub(r"\s+from\s+(?:your|the|my)\s+list$", "", frag, flags=re.IGNORECASE)
    return frag


def _join_checklist_success_fragments(fragments: list[str]) -> str:
    clean = [f for f in (_checklist_reply_fragment(x) for x in fragments) if f]
    if not clean:
        return ""
    parts = [clean[0]]
    for frag in clean[1:]:
        parts.append(frag[:1].lower() + frag[1:] if frag else frag)
    if len(parts) == 1:
        return parts[0] + "."
    if len(parts) == 2:
        return f"{parts[0]} and {parts[1]}."
    return f"{', '.join(parts[:-1])}, and {parts[-1]}."


def _combine_checklist_batch_replies(results: list[dict]) -> str:
    successes = [str(r.get("reply") or "") for r in results if r.get("changed")]
    failures = [str(r.get("reply") or "") for r in results if not r.get("changed")]
    success_reply = _join_checklist_success_fragments(successes)
    if not failures:
        return success_reply
    failure_frags = [
        _checklist_reply_fragment(f).lower()
        for f in failures
        if _checklist_reply_fragment(f)
    ]
    if not success_reply:
        return _join_checklist_success_fragments(failures)
    if not failure_frags:
        return success_reply
    failure_text = " ".join(
        f[:1].upper() + f[1:] if f.startswith("i ") or f.startswith("i'") else f
        for f in failure_frags
    )
    return success_reply.rstrip(".") + ", but " + failure_text + "."


def _execute_planned_checklist_batch(
    *,
    actions: list[dict],
    plan: dict,
    session_id: str,
    client_context_snapshot: dict | None,
) -> tuple[str, float, dict | None] | None:
    """Execute a checklist-only multi-action plan against one shared state.

    Indexing policy for compound checklist commands:
      Ordinal references ("first item", "second item") refer to the
      original visible checklist at the start of the utterance. We resolve
      those ordinals to stable row ids once, then apply each action to the
      live in-memory list sequentially. This matches user expectation for
      "remove the first item and mark the second complete": remove original
      #1 and complete original #2, not the item that becomes #2 after
      deletion.
    """
    if not actions:
        return None
    if any((a or {}).get("type") not in _CHECKLIST_PLANNER_TO_HANDLER_ACTION for a in actions):
        return None

    t0 = perf_counter()
    if not _is_work_mode_snapshot(client_context_snapshot):
        ar = {
            "spoken_reply": "Checklist voice and typed editing only works in Work Mode.",
            "action_type": "checklist",
            "data": {"changed": False, "reason": "not_work_mode"},
            "ui_payload": None,
            "ui_payloads": [],
            "planner_actions": [(a or {}).get("type") or "unknown" for a in actions],
        }
        return ar["spoken_reply"], perf_counter() - t0, ar

    items, collapsed, owner_stem = _load_checklist_state_for_session(session_id)
    snapshot_checklist = (
        client_context_snapshot.get("checklist")
        if isinstance(client_context_snapshot, dict)
        and isinstance(client_context_snapshot.get("checklist"), dict)
        else None
    )
    snapshot_items = snapshot_checklist.get("items") if isinstance(snapshot_checklist, dict) else None
    if isinstance(snapshot_items, list):
        items = snapshot_items
    rows = normalize_checklist_action_items(items)
    original_rows = normalize_checklist_action_items(rows)
    original_flat = visible_flattened_summary(original_rows)
    original_id_by_ordinal = {
        int(row.get("index") or 0): str(row.get("id") or "")
        for row in original_flat
        if int(row.get("index") or 0) > 0 and str(row.get("id") or "")
    }

    _checklist_log(
        "checklist_plan",
        {
            "session_id": (session_id or "")[:32],
            "index_policy": "original_visible_list",
            "raw_user_text": (plan or {}).get("raw_user_text") or (plan or {}).get("_raw_user_text") or "",
            "actions": [
                {
                    "type": (a or {}).get("type"),
                    "span": ((a or {}).get("span") or "")[:200],
                    "payload": (a or {}).get("payload") or {},
                }
                for a in actions
            ],
            "initial_state": original_flat,
        },
    )

    undo_snapshot = {
        "items": [
            {
                "id": str((r or {}).get("id") or ""),
                "text": str((r or {}).get("text") or ""),
                "done": bool((r or {}).get("done")),
                "parent_id": (r or {}).get("parent_id"),
            }
            for r in original_rows
            if isinstance(r, dict)
        ],
        "completed_collapsed": bool(collapsed),
        "created_at": time(),
    }

    current_rows = rows
    results: list[dict] = []
    changed_any = False

    for idx, action in enumerate(actions):
        family = (action or {}).get("type") or ""
        payload = (action or {}).get("payload") or {}
        span = str((action or {}).get("span") or payload.get("raw") or "").strip()
        action_name = _CHECKLIST_PLANNER_TO_HANDLER_ACTION.get(family)
        if not action_name:
            continue

        if family == "checklist.add":
            raw_items = payload.get("items") if isinstance(payload, dict) else []
            item_texts = [
                str(item or "").strip()
                for item in (raw_items if isinstance(raw_items, list) else [raw_items])
                if str(item or "").strip()
            ]
            parsed = {"action": action_name, "item_texts": item_texts, "item_text": item_texts[0] if item_texts else ""}
            exec_text = f"add {', '.join(item_texts)} to the checklist" if item_texts else span
        else:
            exec_text = span
            parsed = parse_checklist_command(vera, exec_text, action_name)
            range_target = _checklist_ordinal_range_from_planner_payload(payload)
            if range_target:
                direction = str(range_target.get("direction") or "first").strip().lower()
                count = int(range_target.get("count") or 0)
                if count > 0:
                    parsed["target_count"] = count
                    parsed["target_count_direction"] = direction
                    parsed["target_count_mode"] = f"{direction}_visible_rows"
                    parsed["target_count_reason"] = range_target.get("reason") or f"{direction}_n_items"
                    parsed["target_mode"] = (
                        "count_from_end" if direction == "last" else "count_from_start"
                    )
                    parsed.pop("target_relative_ordinals", None)
                    parsed["target_indices"] = []
                    parsed.pop("target_index", None)
            ordinals = _checklist_target_ordinals_from_planner_payload(payload)
            if ordinals:
                resolved_ids = [
                    original_id_by_ordinal.get(n, "")
                    for n in ordinals
                    if original_id_by_ordinal.get(n)
                ]
                parsed["target_ids"] = resolved_ids
                parsed["_reply_ordinals"] = list(ordinals)
                parsed["target_indices"] = []
                parsed.pop("target_index", None)
                parsed.pop("target_count", None)
                parsed.pop("target_count_mode", None)
                parsed["target_mode"] = "original_visible_ordinal"
                parsed["target_ids_source"] = "planner_original_visible_ordinals"

        before_state = visible_flattened_summary(current_rows)
        _checklist_log(
            "checklist_action_before",
            {
                "action_index": idx,
                "action_type": family,
                "handler_action": action_name,
                "span": span[:200],
                "parsed": parsed,
                "state_before": before_state,
            },
        )
        next_rows, reply, changed = apply_checklist_action(
            current_rows,
            action_name,
            parsed,
            vera=vera,
            user_text=exec_text,
        )
        after_state = visible_flattened_summary(next_rows)
        verified_changed = before_state != after_state
        # Trust actual state diff over a handler reply flag so we never
        # report success from intention alone.
        changed = bool(changed and verified_changed)
        _checklist_log(
            "checklist_action_after",
            {
                "action_index": idx,
                "action_type": family,
                "handler_action": action_name,
                "state_after": after_state,
            },
        )
        _checklist_log(
            "checklist_action_result",
            {
                "action_index": idx,
                "action_type": family,
                "reply": reply,
                "handler_changed": bool(changed),
                "verified_state_changed": bool(verified_changed),
                "succeeded": bool(changed),
            },
        )
        results.append(
            {
                "type": family,
                "handler_action": action_name,
                "span": span,
                "parsed": parsed,
                "reply": reply,
                "changed": bool(changed),
                "state_before": before_state,
                "state_after": after_state,
            }
        )
        current_rows = next_rows
        changed_any = changed_any or bool(changed)

    persisted_count = 0
    readback_items = current_rows
    if changed_any:
        checklist_undo_snapshots[session_id] = undo_snapshot
        persisted_count, owner_stem = _save_checklist_state_for_session(
            session_id,
            current_rows,
            completed_collapsed=collapsed,
        )
        try:
            readback_items, _readback_collapsed, _readback_owner = _load_checklist_state_for_session(session_id)
        except Exception:
            readback_items = current_rows
    else:
        checklist_undo_snapshots.pop(session_id, None)

    final_state = visible_flattened_summary(current_rows)
    readback_state = visible_flattened_summary(readback_items)
    verified_final_state = final_state == readback_state if changed_any else True
    combined_reply = _combine_checklist_batch_replies(results)
    if not combined_reply:
        combined_reply = "I couldn't update the checklist."

    _checklist_log(
        "checklist_final_state",
        {
            "changed_any": bool(changed_any),
            "persisted_count": persisted_count,
            "final_state": final_state,
            "readback_state": readback_state,
            "verified_final_state": bool(verified_final_state),
        },
    )
    _checklist_log(
        "checklist_response_summary",
        {
            "reply": combined_reply,
            "results": [
                {
                    "type": r.get("type"),
                    "changed": bool(r.get("changed")),
                    "reply": r.get("reply"),
                }
                for r in results
            ],
        },
    )

    final_payload = (
        {
            "panel_type": "checklist_control",
            "op": "checklist.batch",
            "items": current_rows,
            "completed_collapsed": bool(collapsed),
            "owner_username": owner_stem,
            "payload_mode": "full_state",
        }
        if changed_any
        else None
    )
    ar = {
        "spoken_reply": combined_reply,
        "action_type": "multi_action",
        "data": {
            "executed": [(a or {}).get("type") or "unknown" for a in actions],
            "count": len(actions),
            "checklist_batch": True,
            "index_policy": "original_visible_list",
            "results": results,
            "changed": bool(changed_any),
            "verified_final_state": bool(verified_final_state),
        },
        "ui_payload": final_payload,
        "ui_payloads": [final_payload] if final_payload else [],
        "planner_actions": [(a or {}).get("type") or "unknown" for a in actions],
    }
    return combined_reply, perf_counter() - t0, ar


def execute_planned_actions(
    *,
    plan: dict,
    session_id: str,
    history: list[dict],
    client_context_snapshot: dict | None = None,
) -> tuple[str, float, dict | None]:
    """Sequentially execute a multi-action plan via the legacy dispatchers.

    Strategy: for each action span, re-route through ``process_user_input``
    with the planner re-entry guard set. The greedy single-action routers
    inside process_user_input will then pick the right backend handler for
    each (now short, single-action) span. We aggregate spoken replies and
    collect each handler's ui_payload into a list.

    Returns ``(combined_reply, total_t_llm, combined_action_result)``.

    The combined_action_result mirrors the existing per-action shape with
    one new field:

        {
          "spoken_reply": <joined replies>,
          "action_type":  "multi_action",
          "data": {"executed": [<types>], "count": N},
          "ui_payload":   <first payload — keeps single-payload clients working>,
          "ui_payloads":  [<payload>, <payload>, ...],
          "planner_actions": [<types in execution order>],
        }
    """
    actions = (plan or {}).get("actions") or []
    if not actions:
        return "", 0.0, None

    checklist_batch = _execute_planned_checklist_batch(
        actions=actions,
        plan=plan or {},
        session_id=session_id,
        client_context_snapshot=client_context_snapshot,
    )
    if checklist_batch is not None:
        return checklist_batch

    action_plan_id = f"plan_{uuid.uuid4().hex}"
    parent_turn_id = str((plan or {}).get("user_turn_id") or (plan or {}).get("turn_id") or "").strip()
    try:
        print(
            "[workmode_route] "
            + json.dumps(
                {
                    "stage": "pre_dispatch_action_plan",
                    "session_id": (session_id or "")[:64],
                    "user_turn_id": (plan or {}).get("user_turn_id") or (plan or {}).get("turn_id") or "",
                    "action_plan_id": action_plan_id,
                    "raw_user_text": (plan or {}).get("raw_user_text") or (plan or {}).get("_raw_user_text") or "",
                    "actions": [
                        {
                            "type": (a or {}).get("type"),
                            "span": ((a or {}).get("span") or "")[:200],
                            "target": ((a or {}).get("payload") or {}).get("target"),
                            "target_panel": ((a or {}).get("payload") or {}).get("target_panel"),
                            "new_panel_request_id": ((a or {}).get("payload") or {}).get("new_panel_request_id"),
                            "prompt": ((a or {}).get("payload") or {}).get("text"),
                        }
                        for a in actions
                    ],
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        action_plan_id = ""

    token = _planner_executing_var.set(True)
    _plan_raw_token = _planner_plan_raw_text_var.set(
        str((plan or {}).get("_raw_user_text") or (plan or {}).get("raw_user_text") or "").strip()
    )
    replies: list[str] = []
    payloads: list[dict] = []
    executed_types: list[str] = []
    per_action_diag: list[dict] = []  # one entry per planned action — preserved order
    total_t_llm = 0.0
    # work_mode_timer is a top-level meta field on /infer (not a panel
    # ui_payload), so we collect it separately. Multi-action plans
    # currently only emit one timer at most; we keep the LAST non-empty
    # one so a cancel-then-set sequence still ends up with the set.
    collected_work_mode_timer: dict | None = None
    try:
        try:
            print(
                "[multi_action_execute_start] "
                + json.dumps(
                    {
                        "action_count": len(actions),
                        "action_types": [(a or {}).get("type") for a in actions],
                        "action_plan_id": action_plan_id,
                        "raw_user_text": str((plan or {}).get("raw_user_text") or "")[:240],
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        _exec_successes = 0
        _exec_failures = 0
        for _action_idx, action in enumerate(actions):
            if isinstance(action, dict):
                payload_for_plan = action.get("payload")
                if isinstance(payload_for_plan, dict):
                    if action_plan_id:
                        payload_for_plan.setdefault("action_plan_id", action_plan_id)
                    payload_for_plan.setdefault("planner_action_index", _action_idx)
                    if parent_turn_id:
                        payload_for_plan.setdefault("parent_turn_id", parent_turn_id)
            span = (action.get("span") or "").strip()
            if not span:
                continue
            action_family_for_log = action.get("type") or "unknown"
            _action_id_for_log = (
                f"{action_plan_id}:{_action_idx}" if action_plan_id else f"action:{_action_idx}"
            )
            try:
                print(
                    "[multi_action_action_start] "
                    + json.dumps(
                        {
                            "index": _action_idx,
                            "action": action_family_for_log,
                            "action_type": action_family_for_log,
                            "action_id": _action_id_for_log,
                            "parent_turn_id": parent_turn_id or "",
                            "span": span[:160],
                            "payload": (action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {},
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            # Try direct backend dispatch first. Music/transport/volume
            # actions go through their dedicated handlers so the planner
            # always emits a real ui_payload (the LLM router would
            # otherwise return chatty "Playing X…" replies without an
            # actual music_control payload). Other families
            # (panel.*, checklist.*, reasoning.*, voice.answer) keep going
            # through process_user_input so they pick up the existing
            # heuristic + LLM routing + pending-action machinery.
            direct = None
            try:
                direct = _dispatch_planned_action_directly(
                    action,
                    session_id=session_id,
                    client_context_snapshot=client_context_snapshot,
                )
            except Exception as _ddx:
                print(f"[planner] direct_dispatch_swallowed type={action.get('type')} exc={_ddx}")
                direct = None

            if direct is not None:
                reply_i, t_llm_i, ar_i = direct
            else:
                try:
                    reply_i, t_llm_i, ar_i = process_user_input(
                        session_id,
                        span,
                        history,
                        client_context_snapshot=client_context_snapshot,
                    )
                except HTTPException:
                    raise
                except Exception as _exc:
                    # An individual action failing must NOT take down the rest.
                    print(f"[planner] action_failed type={action.get('type')} span={span!r} exc={_exc}")
                    # 2026-06-02 partial-success messaging — surface a
                    # friendly fallback so a multi-info utterance like
                    # "weather in Irvine and time in Tokyo" doesn't
                    # silently drop the failed half. We still count the
                    # action in executed_types for diagnostics so the
                    # post-loop accounting matches the planned action
                    # count.
                    _action_family_failed = action.get("type") or "unknown"
                    executed_types.append(_action_family_failed)
                    _exec_failures += 1
                    try:
                        print(
                            "[multi_action_action_done] "
                            + json.dumps(
                                {
                                    "index": _action_idx,
                                    "action_type": _action_family_failed,
                                    "success": False,
                                    "error": str(_exc)[:200],
                                },
                                ensure_ascii=False,
                            ),
                            flush=True,
                        )
                    except Exception:
                        pass
                    _fallback_reply = _human_failure_reply_for_action(action)
                    if _fallback_reply:
                        replies.append(_fallback_reply)
                    continue
            total_t_llm += float(t_llm_i or 0.0)
            action_family = action.get("type") or "unknown"
            executed_types.append(action_family)
            speak_action_reply = not (isinstance(ar_i, dict) and ar_i.get("speak") is False)
            if isinstance(reply_i, str) and reply_i.strip():
                try:
                    print(
                        "[workmode_ack_source] "
                        + json.dumps(
                            {
                                "source": action_family,
                                "text": reply_i.strip()[:240],
                                "speak": bool(speak_action_reply),
                                "suppressed_reason": (
                                    ((ar_i.get("data") or {}).get("ack_suppressed_reason") or "")
                                    if isinstance(ar_i, dict) and isinstance(ar_i.get("data"), dict)
                                    else ""
                                ),
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
            if speak_action_reply and isinstance(reply_i, str) and reply_i.strip():
                replies.append(reply_i.strip())
            _timer_action_ok = True
            _timer_action_err = ""
            if action_family == "timer.set":
                _timer_action_ok = bool(
                    isinstance(ar_i, dict)
                    and isinstance(ar_i.get("work_mode_timer"), dict)
                    and ar_i["work_mode_timer"].get("fire_at_epoch_ms")
                )
                if not _timer_action_ok:
                    _timer_action_err = (
                        (ar_i or {}).get("spoken_reply") or "timer_not_started"
                        if isinstance(ar_i, dict)
                        else "timer_dispatch_failed"
                    )
            try:
                print(
                    "[multi_action_result] "
                    + json.dumps(
                        {
                            "action": action_family,
                            "success": _timer_action_ok
                            if action_family == "timer.set"
                            else bool(isinstance(reply_i, str) and reply_i.strip()),
                            "error": _timer_action_err or None,
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            # 2026-05-29 spec PART 4 — preserve every successful action's
            # ui_payload in execution order. The "first wins" branch above
            # (combined_ar["ui_payload"] = payloads[0]) is for legacy
            # single-payload clients only; the full ordered list lives in
            # ``action_payloads`` and is what the frontend's NDJSON
            # applier iterates.
            payload_preserved = False
            payload_dropped_reason = ""
            action_payload_candidates: list[dict] = []
            if isinstance(ar_i, dict):
                plural_payloads = ar_i.get("ui_payloads")
                if isinstance(plural_payloads, list):
                    action_payload_candidates.extend(
                        p for p in plural_payloads if isinstance(p, dict)
                    )
                single_payload = ar_i.get("ui_payload")
                if isinstance(single_payload, dict):
                    if not action_payload_candidates:
                        action_payload_candidates.append(single_payload)
                    elif not any(p is single_payload for p in action_payload_candidates):
                        # Defensive: a future handler may return both a
                        # plural list and a distinct primary ui_payload.
                        action_payload_candidates.append(single_payload)

            if action_payload_candidates:
                for p in action_payload_candidates:
                    if isinstance(p, dict):
                        if action_plan_id:
                            p.setdefault("action_plan_id", action_plan_id)
                        p["planner_action_index"] = len(payloads)
                    payloads.append(p)
                payload_preserved = True
            else:
                payload_dropped_reason = (
                    "no_action_result" if not isinstance(ar_i, dict)
                    else "no_ui_payload_in_action_result"
                )
            # Capture work_mode_timer hand-off from timer.set / timer.cancel
            # direct dispatch so the /infer aggregator can merge it into
            # the NDJSON meta/done blocks.
            if isinstance(ar_i, dict):
                wmt = ar_i.get("work_mode_timer")
                if isinstance(wmt, dict) and wmt:
                    collected_work_mode_timer = wmt
            first_action_payload = action_payload_candidates[0] if action_payload_candidates else {}
            per_action_diag.append({
                "family": action_family,
                "executing_action_type": action_family,
                "action_spoken_reply": (reply_i or "")[:200] if isinstance(reply_i, str) else "",
                "action_ui_payload_present": bool(action_payload_candidates),
                "action_ui_payload_type": first_action_payload.get("panel_type") or "",
                "action_ui_payload_op": first_action_payload.get("op") or "",
                "payload_preserved_for_action": payload_preserved,
                "payload_dropped_reason": payload_dropped_reason,
                "payload_op": first_action_payload.get("op") or "",
                "payload_type": first_action_payload.get("panel_type") or "",
                "action_payloads_count_after_each_action": len(payloads),
            })
            try:
                print(
                    "[planner_action_payload] "
                    + json.dumps(
                        {
                            "executing_action_type": action_family,
                            "action_spoken_reply": (reply_i or "")[:200]
                            if isinstance(reply_i, str)
                            else "",
                            "action_ui_payload_present": bool(action_payload_candidates),
                            "action_ui_payload_type": first_action_payload.get("panel_type") or "",
                            "action_ui_payload_op": first_action_payload.get("op") or "",
                            "payload_preserved_for_action": payload_preserved,
                            "payload_dropped_reason": payload_dropped_reason,
                            "action_payloads_count_after_each_action": len(payloads),
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            if action_family == "panel.open":
                try:
                    print(
                        "[active_panel_after_action] "
                        + json.dumps(
                            {
                                "action": "panel.open",
                                "payload_op": first_action_payload.get("op") or "",
                                "expected_active_panel": "newly_opened_panel",
                                "note": "frontend activates the new panel when applying open_new before the next payload",
                            },
                            ensure_ascii=False,
                        ),
                        flush=True,
                    )
                except Exception:
                    pass
            _action_ok = (
                _timer_action_ok
                if action_family == "timer.set"
                else bool(
                    payload_preserved
                    or (isinstance(reply_i, str) and reply_i.strip())
                    or (isinstance(ar_i, dict) and ar_i.get("work_mode_timer"))
                )
            )
            if _action_ok:
                _exec_successes += 1
            else:
                _exec_failures += 1
            try:
                print(
                    "[multi_action_action_done] "
                    + json.dumps(
                        {
                            "index": _action_idx,
                            "action": action_family,
                            "action_type": action_family,
                            "action_id": (
                                f"{action_plan_id}:{_action_idx}" if action_plan_id else f"action:{_action_idx}"
                            ),
                            "parent_turn_id": parent_turn_id or "",
                            "success": _action_ok,
                            "error": _timer_action_err or (None if _action_ok else payload_dropped_reason or "empty_reply"),
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
            except Exception:
                pass
            # App-state propagation between actions: handled implicitly.
            # Each backend handler (panel.navigate → active_panel_id,
            # checklist.add → checklist state, music.* → music state) makes
            # its own state mutation before returning, so the NEXT action's
            # process_user_input call sees the updated state without us
            # threading anything explicit through. We deliberately do NOT
            # append to ``history`` here — the /text handler appends the
            # full original user text + combined reply ONCE at the end of
            # the turn, keeping conversation logs symmetric with regular
            # non-multi-action turns.
        try:
            print(
                "[multi_action_execute_done] "
                + json.dumps(
                    {
                        "successes": _exec_successes,
                        "failures": _exec_failures,
                        "executed_types": executed_types,
                        "payload_count": len(payloads),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
    finally:
        _planner_executing_var.reset(token)
        _planner_plan_raw_text_var.reset(_plan_raw_token)

    combined_reply = " ".join(r for r in replies if r).strip()

    try:
        music_ops = [
            p.get("op")
            for p in payloads
            if isinstance(p, dict) and p.get("panel_type") == "music_control"
        ]
        if music_ops:
            dup_ops = sorted({op for op in music_ops if music_ops.count(op) > 1})
            print(
                "[music_plan_payloads] "
                + json.dumps(
                    {
                        "normalized_user_text": str(
                            (plan or {}).get("raw_user_text")
                            or (plan or {}).get("_raw_user_text")
                            or ""
                        )[:240],
                        "planned_action_types": executed_types,
                        "action_count": len(executed_types),
                        "payload_ops_in_order": music_ops,
                        "duplicate_ops_detected": dup_ops,
                        "payload_count": len(payloads),
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
    except Exception:
        pass

    # 2026-05-29 spec PART 6 — build a clean voice quote from the planned
    # action spans so ``meta["work_mode_voice_quote"]`` no longer echoes
    # the raw original transcript. For a compound command like
    # "Can you go to panel 2, explain the Vietnam War and play the lo-fi mix?"
    # the cleaned quote becomes
    # "go to panel 2, explain the Vietnam War, play the lo-fi mix"
    # — which is what the voice stage-2 reply should quote back.
    cleaned_action_spans: list[str] = []
    for action in actions:
        sp = (action.get("span") or "").strip().strip(".,;:!? ")
        if not sp:
            continue
        cleaned_action_spans.append(sp)
    voice_quote_override = ", ".join(cleaned_action_spans) if cleaned_action_spans else ""

    combined_ar: dict = {
        "spoken_reply": combined_reply,
        "action_type": "multi_action",
        "data": {
            "executed": executed_types,
            "count": len(executed_types),
            "cleaned_action_spans": cleaned_action_spans,
        },
        "ui_payload": payloads[0] if payloads else None,
        "ui_payloads": payloads,
        "planner_actions": executed_types,
        # Streaming /infer functions read this when present and use it as
        # the value of ``work_mode_voice_quote`` instead of the raw
        # transcript. None / empty falls back to the legacy behavior.
        "voice_quote_override": voice_quote_override,
    }
    if collected_work_mode_timer is not None:
        # /infer reads ``work_mode_timer`` off the action_result and
        # propagates it to the NDJSON meta/done blocks. Keeping it on
        # the combined_ar lets the caller pick it up without a separate
        # return value (preserves the existing function signature).
        combined_ar["work_mode_timer"] = collected_work_mode_timer

    # 2026-05-29 hard warnings ([planner_reasoning_request_downgraded_to_chat],
    # [compound_action_dropped]) — surface dropped reasoning panels and
    # missing action families so live regressions are loud.
    try:
        planned_families = list(executed_types)
        # planner_reasoning_request_downgraded_to_chat:
        # If a reasoning.request was planned/executed but no payload of
        # panel_type=work_mode_reasoning was produced, the reasoning span
        # downgraded into a chat reply via process_user_input rather than
        # opening a reasoning panel.
        planned_reasoning_count = sum(1 for t in planned_families if t == "reasoning.request")
        reasoning_payload_count = sum(
            1
            for p in payloads
            if isinstance(p, dict) and (p.get("panel_type") == "work_mode_reasoning")
        )
        if planned_reasoning_count > reasoning_payload_count:
            print(
                "[planner_reasoning_request_downgraded_to_chat] "
                + json.dumps(
                    {
                        "planner_actions": planned_families,
                        "planned_reasoning_count": planned_reasoning_count,
                        "reasoning_payload_count": reasoning_payload_count,
                        "final_payload_types": [
                            (p.get("panel_type") or "")
                            for p in payloads
                            if isinstance(p, dict)
                        ],
                        "combined_reply_preview": combined_reply[:160],
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )

        # compound_action_dropped:
        # Plan had multiple distinct families but the FINAL ui_payloads
        # don't cover them. e.g. plan=[panel.navigate, reasoning.request,
        # music.play] but payloads contain only music_control → reasoning
        # AND panel navigation were dropped from the response surface.
        plan_families = list((plan or {}).get("actions") or [])
        plan_family_set = {a.get("type") for a in plan_families if a.get("type")}
        if len(plan_family_set) >= 2:
            covered: set[str] = set()
            for p in payloads:
                if not isinstance(p, dict):
                    continue
                pt = p.get("panel_type") or ""
                op = p.get("op") or ""
                if pt == "music_control":
                    covered.add("music")
                elif pt == "work_mode_reasoning":
                    if op in {"open_new", "activate", "close", "reopen_last"}:
                        covered.add("panel")
                    if op in {"open_and_stream", "append_stream", "replace_stream"}:
                        covered.add("reasoning")
                elif pt == "checklist_control":
                    covered.add("checklist")
                elif pt in ("panel_control", "work_mode_panel"):
                    covered.add("panel")
            # Map planned families to coverage buckets.
            plan_buckets: set[str] = set()
            for f in plan_family_set:
                if f.startswith("music."):
                    plan_buckets.add("music")
                elif f.startswith("reasoning."):
                    plan_buckets.add("reasoning")
                elif f.startswith("checklist."):
                    plan_buckets.add("checklist")
                elif f.startswith("panel."):
                    plan_buckets.add("panel")
                elif f.startswith("timer."):
                    plan_buckets.add("timer")
            if collected_work_mode_timer is not None:
                covered.add("timer")
            missing = plan_buckets - covered
            if missing:
                print(
                    "[compound_action_dropped] "
                    + json.dumps(
                        {
                            "planner_actions": planned_families,
                            "plan_family_set": sorted(plan_family_set),
                            "plan_buckets": sorted(plan_buckets),
                            "covered_buckets": sorted(covered),
                            "missing_buckets": sorted(missing),
                            "final_payload_types": [
                                (p.get("panel_type") or "")
                                for p in payloads
                                if isinstance(p, dict)
                            ],
                            "combined_reply_preview": combined_reply[:160],
                        },
                        ensure_ascii=False,
                    ),
                    flush=True,
                )
    except Exception:
        pass
    # Single aggregate log for the executor's final tally — pairs with the
    # per-action [planner_action_dispatch] lines emitted inside the loop.
    try:
        payload_types = [
            (p.get("panel_type") or p.get("type") or "unknown")
            for p in payloads
            if isinstance(p, dict)
        ]
        payload_ops = [
            (p.get("op") or "")
            for p in payloads
            if isinstance(p, dict)
        ]
        planned_music_play_called = any(t == "music.play" for t in executed_types)
        music_play_payload_present = any(
            (isinstance(p, dict)
             and p.get("panel_type") == "music_control"
             and (p.get("op") or "").startswith("play_"))
            for p in payloads
        )
        print(
            "[planner_actions_executed] "
            + json.dumps(
                {
                    "planner_actions": executed_types,
                    "executed_types": executed_types,
                    "action_payloads_count": len(payloads),
                    "action_payload_types": payload_types,
                    "action_payload_ops": payload_ops,
                    "final_action_payloads_count": len(payloads),
                    "final_action_payload_types": payload_types,
                    "final_action_payload_ops": payload_ops,
                    "per_action_diag": per_action_diag,
                    "planned_music_play_called": planned_music_play_called,
                    "music_play_payload_present": music_play_payload_present,
                    "combined_reply_chars": len(combined_reply),
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
        print(
            "[multi_action_result_summary] "
            + json.dumps(
                {
                    "planner_actions": executed_types,
                    "success": bool(executed_types),
                    "action_count": len(executed_types),
                    "payload_count": len(payloads),
                    "payload_ops": payload_ops,
                    "response_fragments": replies,
                    "combined_reply": combined_reply[:300],
                },
                ensure_ascii=False,
            ),
            flush=True,
        )
    except Exception:
        pass
    return combined_reply, total_t_llm, combined_ar


def try_execute_planned_actions_for_text(
    *,
    text: str,
    session_id: str,
    history: list[dict],
    client_context_snapshot: dict | None = None,
    min_confidence: float = 0.6,
) -> tuple[str, float, dict | None] | None:
    """Plan + (maybe) execute the typed-text utterance.

    Returns the (reply, t_llm, action_result) triple ready for the /text
    handler to use; or ``None`` to mean "fall through to the legacy
    single-action pipeline". The decision matrix follows the spec:

        - clarification_needed=True   → return the question, do not execute.
        - is_multi_action=False       → None (let legacy router handle it).
        - validation.ok=False         → None (legacy router is safer).
        - confidence < min_confidence → None.
        - otherwise                   → execute, return aggregate.

    Voice/infer/streaming intentionally do NOT call this helper this turn.
    Only ``/text`` (typed) wires it in.
    """
    mp = _load_multi_action_planner()
    if mp is None:
        return None
    text = (text or "").strip()
    if not text:
        return None
    # The re-entry guard would already suppress nested logging, but we
    # also avoid recomputing a plan during executor recursion.
    if _planner_executing_var.get():
        return None

    triggered, trigger_reason = mp.should_trigger_planner(text)

    # 2026-05-29 LIVE-TRACE DIAGNOSTIC — also compute the PURE deterministic
    # backbone plan (no LLM upgrade) so the caller can compare it against
    # what we actually used. If the LLM hook rewrites the action list
    # (e.g. drops timer.set because it isn't in the LLM's family menu),
    # the deterministic_plan field is the "ground truth" — used by the
    # ``[planner_version_or_path_mismatch]`` detector at the /infer
    # endpoint.
    deterministic_plan: dict | None = None
    try:
        deterministic_plan = mp._heuristic_plan(text)  # noqa: SLF001 — diagnostic
    except Exception as _det_exc:
        try:
            print(f"[planner_live_trace] deterministic_plan_exception exc={_det_exc}")
        except Exception:
            pass
        deterministic_plan = None
    det_action_types: list[str] = []
    if isinstance(deterministic_plan, dict):
        det_action_types = [
            (a or {}).get("type") or "?"
            for a in (deterministic_plan.get("actions") or [])
        ]

    # 2026-05-29 Option B — live execution uses the deterministic
    # backbone only. We deliberately pass ``vera=None`` here even when
    # the module-level ``ENABLE_LLM_MULTI_ACTION_PLANNER`` flag stays
    # False, so a future flip of that flag still cannot inject the LLM
    # upgrade into the live action loop without an explicit call-site
    # change. See actions/multi_action_planner.py module banner for the
    # full reasoning.
    plan = mp.plan_user_actions(text, vera=None)
    try:
        plan["_raw_user_text"] = text
    except Exception:
        pass
    ok_v, errors_v, cq_v = mp.validate_plan(plan)
    confidence = 0.0
    if plan.get("actions"):
        confidence = sum(float(a.get("confidence") or 0) for a in plan["actions"]) / max(
            1, len(plan["actions"])
        )

    chosen_action_types: list[str] = [
        (a or {}).get("type") or "?"
        for a in (plan.get("actions") or [])
    ]
    # Compare. If the deterministic backbone would have planned families
    # that the chosen (possibly LLM-influenced) plan dropped, surface a
    # ``[planner_version_or_path_mismatch]`` so the operator can see the
    # LLM hook rewrote the plan and lost a family the smoke tests prove
    # the planner module knows about.
    deterministic_only_families = [
        t for t in det_action_types if t not in chosen_action_types
    ]
    chosen_only_families = [
        t for t in chosen_action_types if t not in det_action_types
    ]
    plan_source = plan.get("reason") or ""
    llm_plan_chosen = "llm_plan_accepted" in plan_source

    # Always emit the [planner] line — even when we choose NOT to execute —
    # so the audit trail covers both shadow- and execute-decisions.
    try:
        mp.log_planner(
            raw_user_text=text,
            plan=plan,
            triggered=triggered,
            trigger_reason=trigger_reason,
            validation_results={"ok": ok_v, "errors": errors_v, "clarification": cq_v},
            greedy_router_skipped=bool(
                plan.get("is_multi_action")
                and not plan.get("clarification_needed")
                and ok_v
                and confidence >= min_confidence
            ),
            note="text_endpoint_plan_gate",
        )
    except Exception:
        pass

    # Populate the contextvar BEFORE any early-return branch so the
    # caller can read it whether we executed, clarified, or skipped.
    _gate_diag: dict = {
        "text": text[:240],
        "triggered": bool(triggered),
        "trigger_reason": trigger_reason or "",
        "plan_source": plan_source,
        "llm_plan_chosen": bool(llm_plan_chosen),
        "deterministic_action_types": det_action_types,
        "deterministic_is_multi_action": bool(
            isinstance(deterministic_plan, dict)
            and deterministic_plan.get("is_multi_action")
        ),
        "chosen_action_types": chosen_action_types,
        "chosen_is_multi_action": bool(plan.get("is_multi_action")),
        "validation_ok": bool(ok_v),
        "validation_errors": list(errors_v or []),
        "confidence": round(float(confidence), 3),
        "min_confidence": float(min_confidence),
        "clarification_needed": bool(plan.get("clarification_needed")),
        "clarification_question": plan.get("clarification_question") or "",
        "planner_json": {
            "is_multi_action": bool(plan.get("is_multi_action")),
            "actions": [
                {
                    "type": (a or {}).get("type"),
                    "span": ((a or {}).get("span") or "")[:120],
                    "confidence": (a or {}).get("confidence"),
                }
                for a in (plan.get("actions") or [])
            ],
        },
        "deterministic_only_families": deterministic_only_families,
        "chosen_only_families": chosen_only_families,
        "planner_returned_none_reason": "",
        "planner_executed": False,
        "execution_returned_clarification": False,
    }

    if plan.get("clarification_needed"):
        cq = plan.get("clarification_question") or (
            "Could you clarify what you'd like me to do first?"
        )
        _gate_diag["planner_returned_none_reason"] = "clarification_needed"
        _gate_diag["execution_returned_clarification"] = True
        _planner_last_gate_diag_var.set(_gate_diag)
        return cq, 0.0, {
            "spoken_reply": cq,
            "action_type": "clarification",
            "data": {"reason": plan.get("reason") or "ambiguous_multi_action"},
            "ui_payload": None,
            "ui_payloads": [],
            "planner_actions": [],
        }
    # 2026-06-15 — music-family unsupported-modifier guard (Option A). If ANY
    # planned music action carries a delayed/conditional/recurring modifier
    # ("play Feather and pause in 10 minutes"), block the WHOLE plan before
    # any side effect runs. We do not execute valid siblings and we do not
    # schedule anything — just speak the action-specific "can't schedule yet"
    # reply. Runs before the is_multi_action gate so a single transport action
    # planned with timing ("pause in 10 minutes") is blocked here too.
    _music_block = _scan_plan_for_unsupported_music(plan.get("actions") or [])
    if _music_block is not None:
        (block_family, block_meta), valid_clause = _music_block
        spoken = _music_unsupported_spoken(
            block_family,
            phrase=block_meta.get("phrase") or "",
            valid_clause=valid_clause,
        )
        try:
            print(
                "[music_unsupported_modifier] "
                + json.dumps(
                    {
                        "stage": "pre_execution_plan_gate",
                        "user_text": (text or "")[:200],
                        "blocked_family": block_family,
                        "timing_kind": block_meta.get("timing_kind"),
                        "phrase": block_meta.get("phrase"),
                        "valid_play_clause": valid_clause,
                        "planned_actions": chosen_action_types,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        _gate_diag["planner_returned_none_reason"] = "music_unsupported_modifier_blocked"
        _gate_diag["planner_executed"] = False
        _planner_last_gate_diag_var.set(_gate_diag)
        return spoken, 0.0, {
            "spoken_reply": spoken,
            "action_type": "music",
            "data": {
                "unsupported": True,
                "family": block_family,
                "reason": block_meta.get("reason") or "",
                "timing_kind": block_meta.get("timing_kind") or "",
                "blocked": True,
            },
            "ui_payload": None,
            "ui_payloads": [],
            "planner_actions": [],
        }

    if not plan.get("is_multi_action"):
        _gate_diag["planner_returned_none_reason"] = "plan_not_multi_action"
        _planner_last_gate_diag_var.set(_gate_diag)
        return None
    if not ok_v:
        _gate_diag["planner_returned_none_reason"] = (
            "validation_failed:" + ",".join(errors_v or [])[:160]
        )
        _planner_last_gate_diag_var.set(_gate_diag)
        return None
    if confidence < min_confidence:
        _gate_diag["planner_returned_none_reason"] = (
            f"confidence_below_min:{confidence:.3f}<{min_confidence:.3f}"
        )
        _planner_last_gate_diag_var.set(_gate_diag)
        return None

    _gate_diag["planner_executed"] = True
    _planner_last_gate_diag_var.set(_gate_diag)

    return execute_planned_actions(
        plan=plan,
        session_id=session_id,
        history=history,
        client_context_snapshot=client_context_snapshot,
    )


@app.post("/api/plan_actions")
async def api_plan_actions(data: PlanActionsInput):
    """Return a structured multi-action plan for ``data.text``.

    Spec contract (see actions/multi_action_planner.py for the full schema):
        {
          is_multi_action: bool,
          actions: [ {type, span, payload, order, confidence}, ... ],
          clarification_needed: bool,
          clarification_question: str | None,
          reason: str,
          trigger_reason: str,
          validation: {ok, errors, clarification_question},
          request_id: str,
        }

    This endpoint is the single source of truth the frontend can call when
    it wants to *plan first, execute later*. It does NOT execute anything.
    """
    mp = _load_multi_action_planner()
    if mp is None:
        raise HTTPException(503, "multi_action_planner unavailable")

    text = (data.text or "").strip()
    if not text:
        raise HTTPException(400, "empty text")

    request_id = _new_request_id()
    _current_request_id_var.set(request_id)

    triggered, trigger_reason = mp.should_trigger_planner(text)
    # The endpoint always runs the planner (even when the gate is closed)
    # so the caller can ask "is this single-action?" too. LLM only fires
    # when the gate is open and the caller opted in.
    plan = mp.plan_user_actions(
        text, vera=(vera if (data.use_llm and triggered) else None), context=data.context
    )
    ok_v, errors_v, cq_v = mp.validate_plan(plan)
    mp.log_planner(
        raw_user_text=text,
        plan=plan,
        triggered=triggered,
        trigger_reason=trigger_reason,
        validation_results={"ok": ok_v, "errors": errors_v, "clarification": cq_v},
        greedy_router_skipped=False,
        note="/api/plan_actions",
    )
    return {
        **plan,
        "trigger_reason": trigger_reason,
        "validation": {
            "ok": ok_v,
            "errors": errors_v,
            "clarification_question": cq_v,
        },
        "request_id": request_id,
        "session_id": safe_id(data.session_id),
    }


class TtsEmotionRouteIn(BaseModel):
    """Batch-classify spoken sentences for BMO face routing (light LLM, JSON only)."""

    session_id: str
    """Original user / narrator text (tts_only input) — use to judge user-related sadness."""
    user_text: str = ""
    sentences: list[str]


_EMOTION_ROUTE_DEV = (
    "You label each sentence of a short spoken script for a cartoon robot face.\n"
    "Output MUST be a single JSON object only, no markdown, no prose.\n"
    "Schema: {\"labels\":[\"sad\"|\"neutral\"|\"happy\", ...]} — same length and order as `sentences`.\n\n"
    "Rules:\n"
    "- sad: GENUINE grief, loss, fear, shame, regret, pain, loneliness, failure, danger, condolences, or empathetic "
    "comfort about something actually bad — especially when it clearly relates to the USER's feelings or the "
    "`user_text` context.\n"
    "- Do NOT label sad just because a sentence contains the word 'sorry', 'hurt', 'pain', or 'unfortunately'. "
    "A sentence is only sad when the sentence as a whole expresses real distress, grief, apology, danger, or comfort.\n"
    "- Playful/idiomatic uses of negative words are NEUTRAL or HAPPY, not sad. Examples that must NOT be sad: "
    "'never hurt anyone', 'doesn't hurt', 'can't hurt', 'no harm done', 'just kidding', 'just teasing', "
    "'no big deal', 'nothing to worry about', light teasing or self-deprecating jokes.\n"
    "- If `user_text` clearly signals the user is sad, hurt, anxious, or struggling, label empathy, apologies, "
    "or gentle comfort in `sentences` as **sad** (warm tone is OK — sad is about matching their moment, not being "
    "tearful). If `user_text` is casual/neutral, do NOT promote empathy phrases to sad.\n"
    "- happy: clearly positive, warm, playful, celebratory, or reassuring (not sad).\n"
    "- neutral: facts, filler, mild small-talk, transitions, light jokes/teasing, or genuinely upbeat reassurance "
    "with no sorrow thread.\n"
    "When unsure between neutral and happy, prefer neutral. When unsure between neutral and sad and `user_text` "
    "shows no distress, prefer **neutral**.\n"
)


def _normalize_tts_emotion_labels(labels: object, n: int) -> list[str]:
    out: list[str] = []
    if not isinstance(labels, list):
        labels = []
    for i in range(n):
        raw = labels[i] if i < len(labels) else "neutral"
        lab = str(raw).strip().lower()
        if lab not in ("sad", "neutral", "happy"):
            lab = "neutral"
        out.append(lab)
    return out


_USER_DISTRESS_HINT_RX = re.compile(
    r"\b("
    # Direct emotional descriptors that are unambiguous on their own.
    r"sad|depressed|depressing|anxious|anxiety|worried|worries|"
    r"cry|crying|tearful|grief|grieving|mourning|hopeless|despair|despairing|"
    r"overwhelmed|exhausted|drained|"
    # Phrasal forms: require the word "feel/feeling" or "i'm" to qualify ambiguous tokens
    # ('down', 'blue', 'alone', 'hurt', 'broken', 'in pain') as actual distress.
    r"|feel(?:ing)?\s+(?:down|blue|empty|numb|lonely|alone|sad|hurt|broken|hopeless|low|terrible|awful|miserable|like\s+crap|like\s+shit)"
    r"|i'?m\s+(?:hurting|hurt|in\s+pain|crying|broken|lost|done|struggling|overwhelmed|exhausted|drained|not\s+ok(?:ay)?|miserable|grieving)"
    r"|can'?t\s+cope|cannot\s+cope|cant\s+cope|"
    r"not\s+ok(?:ay)?|"
    r"having\s+a\s+(?:hard|tough|rough)\s+time|"
    r"need\s+(?:to\s+)?(?:cry|vent|talk)"
    r")\b",
    re.I,
)


# Playful/idiomatic uses of negative words that should NOT route to a sad face.
# These match whole-phrase patterns so isolated nouns like "hurt" or "pain" do not
# flip a clearly playful sentence to sad.
_BMO_PLAYFUL_NEGATIVE_RX = re.compile(
    r"\b("
    r"never\s+(?:hurt|hurts|harmed|killed|cried|failed|did\s+anything)\s+(?:anyone|anybody|anything|nobody|no\s+one|a\s+soul)"
    r"|(?:doesn|don|didn|won|wouldn|couldn|shouldn|can|cannot|cant)'?t\s+hurt(?:\s+(?:to|anyone|anybody|me|us|you|it))?"
    r"|no\s+harm(?:\s+done|\s+in\s+(?:that|trying|asking))?"
    r"|just\s+(?:kidding|teasing|joking|playing|messing\s+with\s+you)"
    r"|only\s+(?:kidding|teasing|joking)"
    r"|no\s+big\s+deal"
    r"|nothing\s+to\s+worry\s+about"
    r"|all\s+in\s+good\s+fun"
    r"|grammatical\s+weathering"
    r")\b",
    re.I,
)


def _is_bmo_playful_negative(sentence: str) -> bool:
    return bool(_BMO_PLAYFUL_NEGATIVE_RX.search(sentence or ""))


def _downgrade_playful_sad_labels(
    user_text: str, sentences: list[str], labels: list[str]
) -> list[str]:
    """Demote LLM/heuristic 'sad' to 'neutral' when the sentence is a playful idiom
    and the user is NOT showing distress. Distressed-user contexts are left alone so
    empathy still wins when it matters.
    """
    if not sentences or not labels or len(labels) != len(sentences):
        return labels
    ut = (user_text or "").strip()
    if ut and _USER_DISTRESS_HINT_RX.search(ut):
        return labels
    out = list(labels)
    for i, s in enumerate(sentences):
        if out[i] == "sad" and _is_bmo_playful_negative(s):
            out[i] = "neutral"
    return out

_EMPATHY_OR_APLOGY_IN_ASSISTANT_RX = re.compile(
    r"\b(i\s*'?m\s+sorry|i\s+am\s+sorry|sorry\s+you'?re|sorry\s+to\s+hear|"
    r"hearing\s+(?:that|you)|that\s+sounds\s+(?:really\s+)?(?:hard|rough|awful|difficult|tough)|"
    r"i\s+hear\s+you|wish\s+i\s+could|sending\s+(?:you\s+)?(?:a\s+)?hug|"
    r"take\s+(?:a\s+)?breath|i\s+understand\s+(?:how\s+)?(?:hard|difficult)|"
    r"that\s+must\s+be|that\s+is\s+hard|i\s+can\s+imagine|my\s+condolences|"
    r"i\s*'?m\s+here\s+for\s+you|i\s+am\s+here\s+for\s+you)\b",
    re.I,
)


def _boost_sad_for_user_distress_and_empathy(
    user_text: str, sentences: list[str], labels: list[str]
) -> list[str]:
    """If the user sounded distressed but the model said neutral for empathy lines, use sad face."""
    if not sentences or not labels or len(labels) != len(sentences):
        return labels
    ut = (user_text or "").strip()
    if not ut or not _USER_DISTRESS_HINT_RX.search(ut):
        return labels
    out = list(labels)
    for i, s in enumerate(sentences):
        if out[i] in ("sad", "happy"):
            continue
        if _EMPATHY_OR_APLOGY_IN_ASSISTANT_RX.search(s) or re.search(r"\bsorry\b", s, re.I):
            out[i] = "sad"
    return out


def _heuristic_tts_emotion_labels(sentences: list[str]) -> list[str]:
    sad_rx = re.compile(
        r"\b(sorry|sad|cry|tears|afraid|scared|worried|anxious|depress|lonely|hurt|pain|hate|angry|terrible|"
        r"awful|worst|unfortunately|regret|loss|lose|lost|die|death|grief|mourn|hopeless|despair|upset|failure)\b",
        re.I,
    )
    happy_rx = re.compile(
        r"\b(happy|joy|great|wonderful|awesome|love|celebrat|excit|fun|laugh|smile|yay|glad|victory|beautiful)\b",
        re.I,
    )
    out: list[str] = []
    for s in sentences:
        t = (s or "").strip()
        # Playful idiom guard: 'never hurt anyone', 'doesn't hurt', 'no harm done',
        # 'just kidding/teasing' — keep neutral instead of flipping to sad on the
        # bare 'hurt'/'pain'/'sorry' tokens.
        if _is_bmo_playful_negative(t):
            if happy_rx.search(t) and not sad_rx.search(t):
                out.append("happy")
            else:
                out.append("neutral")
            continue
        if sad_rx.search(t) and not happy_rx.search(t):
            out.append("sad")
        elif happy_rx.search(t) and not sad_rx.search(t):
            out.append("happy")
        elif sad_rx.search(t):
            out.append("sad")
        elif happy_rx.search(t):
            out.append("happy")
        else:
            out.append("neutral")
    return out


@app.post("/tts_emotion_route")
async def tts_emotion_route(data: TtsEmotionRouteIn):
    """Light LLM: one label per sentence (sad / neutral / happy) for BMO TTS face routing."""
    _ = safe_id(data.session_id)
    sentences = [str(s or "").strip() for s in data.sentences if str(s or "").strip()]
    if not sentences:
        raise HTTPException(400, "No sentences")
    if len(sentences) > 48:
        raise HTTPException(413, "Too many sentences")

    user_text = (data.user_text or "").strip()[:6000]
    if vera is None or SERVER_STATE != "ready":
        labs = _heuristic_tts_emotion_labels(sentences)
        labs = _boost_sad_for_user_distress_and_empathy(user_text, sentences, labs)
        labs = _downgrade_playful_sad_labels(user_text, sentences, labs)
        return {
            "labels": labs,
            "source": "heuristic",
            "detail": "model_not_ready",
        }

    payload = json.dumps({"user_text": user_text, "sentences": sentences}, ensure_ascii=False)
    messages = [
        {"role": "developer", "content": _EMOTION_ROUTE_DEV},
        {"role": "user", "content": payload},
    ]

    def _call_llm() -> str:
        response = vera.client.chat.completions.create(
            model=vera.model_name,
            messages=messages,
            temperature=0.12,
            max_completion_tokens=320,
        )
        choice = response.choices[0]
        return (choice.message.content or "").strip()

    try:
        raw = await asyncio.to_thread(_call_llm)
    except Exception as e:
        print(f"[tts_emotion_route] LLM error: {e}")
        try:
            _safety_log_block(reason="bmo_state_failure", mode="bmo",
                              feature="bmo", extra={"error": str(e)[:200]})
        except Exception:
            pass
        labs = _heuristic_tts_emotion_labels(sentences)
        labs = _boost_sad_for_user_distress_and_empathy(user_text, sentences, labs)
        labs = _downgrade_playful_sad_labels(user_text, sentences, labs)
        return {
            "labels": labs,
            "source": "heuristic",
            "detail": str(e)[:200],
            "service_failure": "bmo_state",
        }

    parsed = vera._parse_json_object(raw, {})
    labels = parsed.get("labels")
    normalized = _normalize_tts_emotion_labels(labels, len(sentences))
    normalized = _boost_sad_for_user_distress_and_empathy(user_text, sentences, normalized)
    normalized = _downgrade_playful_sad_labels(user_text, sentences, normalized)
    return {"labels": normalized, "source": "llm"}


@app.post("/text")
async def text_input(request: Request, data: TextInput):
    t_start = perf_counter()

    try:
        from auth.request_auth import bind_request_auth_user

        bind_request_auth_user(request)
    except Exception:
        pass

    session_id = safe_id(data.session_id)
    text = data.text.strip()

    if not text:
        raise HTTPException(400, "Empty text")
    
    print(f"[TEXT] \"{text}\"")

    # Multi-device-concurrency PART 1: request id + [REQ start] / [REQ end].
    _text_request_id = _new_request_id()
    _current_request_id_var.set(_text_request_id)
    _text_start_ts = log_req_start(
        route="/text",
        session_id=session_id,
        request_id=_text_request_id,
        source=("bmo_tts" if data.tts_only and (data.client or "").lower() == "bmo" else "typed_chat"),
        mode=("tts_only" if data.tts_only else "typed_chat"),
        client=data.client,
        stream_tts=bool(data.stream_tts),
        chars=len(text),
    )

    cleanup_sessions()

    if session_id not in user_last_seen and len(user_last_seen) >= MAX_ACTIVE_USERS:
        raise HTTPException(429, "Server at capacity")

    user_last_seen[session_id] = time()
    total_sessions_seen.add(session_id)

    _snap_for_mode = None
    _wm_on = False
    try:
        _snap_for_mode = _normalize_client_context_snapshot(data.context_snapshot)
        _wm_on = _is_work_mode_snapshot(_snap_for_mode)
        _rt = "command"
        if data.tts_only:
            _rt = "bmo_tts" if (data.client or "").lower() == "bmo" else "command"
        _cost_update_request(
            session_id=session_id,
            mode=("work_mode" if _wm_on else "nonwork_mode"),
            request_type=_rt,
            extra={"client": data.client, "tts_only": bool(data.tts_only)},
        )
    except Exception as _cl_err:
        print(f"[cost_logger] /text update_request swallowed: {_cl_err}")

    # Safety: typed-input length + estimated-token caps. Refuses oversized
    # input before any LLM call. ``tts_only`` requests (BMO speak-this) only
    # synthesize the supplied text and do not run reasoning, so they bypass
    # the LLM-token cap — but still respect the keyboard char limit.
    try:
        _block = _safety_check_typed_input(
            text,
            work_mode=bool(_wm_on),
            request_type=("bmo_tts" if data.tts_only else "command"),
        )
        if _block is not None and not data.tts_only:
            _safety_log_block(
                reason=_block["reason"],
                mode=("work_mode" if _wm_on else "non_work"),
                feature="keyboard",
                char_count=_block.get("char_count"),
                estimated_tokens=_block.get("estimated_tokens"),
                extra={"endpoint": "/text", "client": data.client},
            )
            raise HTTPException(413, _block["message"])
    except HTTPException:
        raise
    except Exception as _safe_err:
        # Safety logic must never break a request. Fall through.
        print(f"[safety_guard] /text guard swallowed: {_safe_err}")

    # =========================
    # TTS-ONLY (no LLM): speak `text` verbatim
    # =========================
    if data.tts_only:
        t_llm_start = perf_counter()
        t_llm_end = perf_counter()
        t_llm_wall = 0.0
        reply = text
        empty_action: dict = {}
        if data.stream_tts:

            async def ndjson_tts_only():
                async for line in iter_text_tts_ndjson_stream(
                    t_start=t_start,
                    session_id=session_id,
                    user_text=text,
                    reply=reply,
                    client=data.client,
                    action_result=empty_action,
                    t_llm_end=t_llm_end,
                    t_llm_wall=t_llm_wall,
                ):
                    yield line.encode("utf-8")

            return StreamingResponse(
                _diag_wrap_stream(
                    ndjson_tts_only(),
                    route="/text",
                    session_id=session_id,
                    request_id=_text_request_id,
                    start_ts=_text_start_ts,
                    mode="tts_only",
                ),
                media_type="application/x-ndjson",
                headers=_ndjson_stream_headers(),
            )

        reply, audio_urls = await synthesize_reply_audio(session_id, reply, client=data.client)
        audio_url = audio_urls[0] if audio_urls else ""
        t_total = perf_counter() - t_start
        print(f"[LATENCY][TEXT][tts_only] TTS-only TOTAL={t_total:.3f}s segments={len(audio_urls)}")
        return {
            "reply": reply,
            "user_text": text,
            "audio_url": audio_url,
            "audio_urls": audio_urls,
            "tts_segment_count": len(audio_urls),
            "action_payload": None,
            "action_type": None,
            "latency": {
                "total_s": round(t_total, 4),
                "llm_s": 0.0,
                "short_circuit": "tts_only",
            },
        }

    # =========================
    # COMMAND HANDLING
    # =========================

    history = user_histories[session_id]
    t_llm_start = perf_counter()
    client_context = _normalize_client_context_snapshot(data.context_snapshot)
    if client_context:
        latest_client_context_snapshot[session_id] = client_context
    else:
        client_context = latest_client_context_snapshot.get(session_id)
    memory_reply = None
    try:
        from auth.memory_commands import try_explicit_memory_fastpath
        from auth.request_auth import get_bound_auth_user

        memory_reply = try_explicit_memory_fastpath(
            text, session_id, user_histories.get(session_id)
        )
        if get_bound_auth_user() is None:
            _extract_and_store_session_user_facts(session_id, text)
    except Exception as _mem_fp_err:
        memory_reply = None
        print(f"[explicit_memory] /text fastpath swallowed: {_mem_fp_err}")
        try:
            from auth.request_auth import get_bound_auth_user

            if get_bound_auth_user() is None:
                _extract_and_store_session_user_facts(session_id, text)
        except Exception:
            _extract_and_store_session_user_facts(session_id, text)
    # 2026-06-01 identity-leak patch: catch identity-challenge questions
    # ("how do you know my name is Nam?", "what's my name?", "am I Nam?")
    # BEFORE the general LLM, so the model never claims a fabricated
    # source like "you told me earlier".
    identity_reply = _identity_challenge_fastpath_reply(
        text, session_id, history=user_histories.get(session_id), request_path="/text"
    ) or _creator_question_fastpath_reply(text)
    anonymous_reply = _anonymous_user_fastpath_reply(
        text, session_id, history=user_histories.get(session_id)
    )
    snapshot_reply = _snapshot_fastpath_reply(text, client_context)
    work_mode_intent = _work_mode_toggle_intent(text, data.client, client_context)

    if work_mode_intent:
        action_name, reply = _work_mode_toggle_reply(work_mode_intent, client_context)
        reply, audio_urls = await synthesize_reply_audio(session_id, reply, client=data.client)
        history.append({"role": "user", "content": text})
        history.append({"role": "assistant", "content": reply})
        if len(history) > MAX_TURNS * 2:
            history[:] = history[-MAX_TURNS * 2:]
        t_total = perf_counter() - t_start
        log_req_end(
            route="/text",
            session_id=session_id,
            request_id=_text_request_id,
            start_ts=_text_start_ts,
            ok=True,
            path="work_mode_toggle",
        )
        return {
            "reply": reply,
            "user_text": text,
            "audio_url": audio_urls[0] if audio_urls else "",
            "audio_urls": audio_urls,
            "tts_segment_count": len(audio_urls),
            "client_action": action_name,
            "action_payload": None,
            "action_type": None,
            "request_id": _text_request_id,
            "latency": {
                "total_s": round(t_total, 4),
                "llm_s": 0.0,
                "short_circuit": "work_mode_toggle",
            },
        }

    text_timer_short = _try_work_mode_timer_extend_core(
        session_id, text, client_context, data.client
    ) or _try_work_mode_timer_core(session_id, text, client_context, data.client)
    if text_timer_short is not None:
        reply_tm = text_timer_short["reply"]
        wm_tm = text_timer_short.get("work_mode_timer")
        t_llm_end = perf_counter()
        t_llm_wall = t_llm_end - t_llm_start
        if data.stream_tts:
            empty_action: dict = {}

            async def ndjson_text_timer():
                if wm_tm and isinstance(wm_tm, dict) and not wm_tm.get("cancel"):
                    await enrich_work_mode_timer_with_tts(session_id, wm_tm, data.client)
                async for line in iter_text_tts_ndjson_stream(
                    t_start=t_start,
                    session_id=session_id,
                    user_text=text,
                    reply=reply_tm,
                    client=data.client,
                    action_result=empty_action,
                    t_llm_end=t_llm_end,
                    t_llm_wall=t_llm_wall,
                    work_mode_timer=wm_tm,
                ):
                    yield line.encode("utf-8")

            return StreamingResponse(
                _diag_wrap_stream(
                    ndjson_text_timer(),
                    route="/text",
                    session_id=session_id,
                    request_id=_text_request_id,
                    start_ts=_text_start_ts,
                    mode="typed_chat_timer",
                ),
                media_type="application/x-ndjson",
                headers=_ndjson_stream_headers(),
            )

        reply, audio_urls = await synthesize_reply_audio(session_id, reply_tm, client=data.client)
        audio_url = audio_urls[0] if audio_urls else ""
        if wm_tm is not None and isinstance(wm_tm, dict) and not wm_tm.get("cancel"):
            await enrich_work_mode_timer_with_tts(session_id, wm_tm, data.client)
        history.append({"role": "user", "content": text})
        history.append({"role": "assistant", "content": reply_tm})
        if len(history) > MAX_TURNS * 2:
            history[:] = history[-MAX_TURNS * 2:]
        t_total = perf_counter() - t_start
        out = {
            "reply": reply_tm,
            "user_text": text,
            "audio_url": audio_url,
            "audio_urls": audio_urls,
            "tts_segment_count": len(audio_urls),
            "action_payload": None,
            "action_type": None,
            "latency": {
                "total_s": round(t_total, 4),
                "llm_s": 0.0,
                "short_circuit": "work_mode_timer",
            },
        }
        if wm_tm is not None:
            out["work_mode_timer"] = wm_tm
        return out

    prepared_stream: PreparedStreamingAction | None = None
    if (
        data.stream_tts
        and not memory_reply
        and not identity_reply
        and not anonymous_reply
        and not snapshot_reply
    ):
        prepared_stream = try_prepare_streaming_action_messages(session_id, text, history)

    if data.stream_tts and prepared_stream is not None:
        ps = prepared_stream

        async def ndjson_text():
            async for line in iter_text_tts_ndjson_stream_llm_stream(
                t_start=t_start,
                t_llm_start=t_llm_start,
                session_id=session_id,
                user_text=text,
                client=data.client,
                history=history,
                messages_override=ps.messages,
                meta_action_type=ps.meta_action_type,
                meta_action_payload=ps.meta_action_payload,
                finalize_action_result=ps.finalize,
                client_context_snapshot=client_context,
            ):
                yield line.encode("utf-8")

        return StreamingResponse(
            _diag_wrap_stream(
                ndjson_text(),
                route="/text",
                session_id=session_id,
                request_id=_text_request_id,
                start_ts=_text_start_ts,
                mode="typed_chat_action",
            ),
            media_type="application/x-ndjson",
            headers=_ndjson_stream_headers(),
        )

    # 2026-05-29 — multi-action planner EXECUTION (typed /text only).
    # Before the legacy single-action resolver, ask the planner whether the
    # utterance is a compound command we should execute sequentially.
    # ``try_execute_planned_actions_for_text`` returns:
    #   * (reply, t_llm, action_result) when it executed or wants to ask a
    #     clarification question — short-circuit the rest of /text.
    #   * None when the utterance is single-action / low-confidence /
    #     ambiguous-without-a-clarification — fall through to legacy flow.
    # Voice/infer/streaming intentionally do NOT call this helper this turn;
    # only typed /text wires it in.
    planner_executed = None
    if (
        not snapshot_reply
        and not anonymous_reply
        and not memory_reply
        and not identity_reply
        and not data.tts_only
    ):
        try:
            planner_executed = try_execute_planned_actions_for_text(
                text=text,
                session_id=session_id,
                history=history,
                client_context_snapshot=client_context,
            )
        except Exception as _plan_exc:
            print(f"[planner] /text execution swallowed: {_plan_exc}")
            planner_executed = None

    resolved = (
        None
        if (
            snapshot_reply
            or anonymous_reply
            or memory_reply
            or identity_reply
            or planner_executed is not None
        )
        else resolve_reply_if_not_general_llm(
            session_id,
            text,
            history,
            client_context_snapshot=client_context,
        )
    )

    if (
        data.stream_tts
        and resolved is None
        and planner_executed is None
        and not snapshot_reply
        and not anonymous_reply
        and not memory_reply
        and not identity_reply
    ):
        _preflight_general_llm_credit_cap(
            session_id,
            text,
            history,
            client_context_snapshot=client_context,
        )
        async def ndjson_text():
            async for line in iter_text_tts_ndjson_stream_llm_stream(
                t_start=t_start,
                t_llm_start=t_llm_start,
                session_id=session_id,
                user_text=text,
                client=data.client,
                history=history,
                client_context_snapshot=client_context,
            ):
                yield line.encode("utf-8")

        return StreamingResponse(
            _diag_wrap_stream(
                ndjson_text(),
                route="/text",
                session_id=session_id,
                request_id=_text_request_id,
                start_ts=_text_start_ts,
                mode="typed_chat_llm",
            ),
            media_type="application/x-ndjson",
            headers=_ndjson_stream_headers(),
        )

    if planner_executed is not None:
        # Planner already ran the multi-action sequence (or produced a
        # clarification question). Use its aggregate reply + chained
        # ui_payloads instead of running the legacy single-action pipeline.
        reply, _, action_result = planner_executed
    elif resolved is not None:
        reply, _, action_result = resolved
    elif identity_reply:
        reply, _, action_result = identity_reply, 0.0, None
    elif memory_reply:
        reply, _, action_result = memory_reply, 0.0, None
    elif anonymous_reply:
        reply, _, action_result = anonymous_reply, 0.0, None
    elif snapshot_reply:
        reply, _, action_result = snapshot_reply, 0.0, None
    else:
        reply, _, action_result = process_user_input(
            session_id,
            text,
            history,
            client_context_snapshot=client_context,
        )
    t_llm_end = perf_counter()
    t_llm_wall = t_llm_end - t_llm_start

    history.append({"role": "user", "content": text})
    history.append({"role": "assistant", "content": reply})

    if len(history) > MAX_TURNS * 2:
        history[:] = history[-MAX_TURNS * 2:]

    # =========================
    # TTS
    # =========================

    if data.stream_tts:

        async def ndjson_text():
            async for line in iter_text_tts_ndjson_stream(
                t_start=t_start,
                session_id=session_id,
                user_text=text,
                reply=reply,
                client=data.client,
                action_result=action_result,
                t_llm_end=t_llm_end,
                t_llm_wall=t_llm_wall,
            ):
                yield line.encode("utf-8")

        return StreamingResponse(
            _diag_wrap_stream(
                ndjson_text(),
                route="/text",
                session_id=session_id,
                request_id=_text_request_id,
                start_ts=_text_start_ts,
                mode="typed_chat_resolved",
            ),
            media_type="application/x-ndjson",
            headers=_ndjson_stream_headers(),
        )

    reply, audio_urls = await synthesize_reply_audio(session_id, reply, client=data.client)
    audio_url = audio_urls[0] if audio_urls else ""

    t_total = perf_counter() - t_start

    print(
        "[LATENCY][TEXT] "
        f"LLM={t_llm_wall:.3f}s TOTAL={t_total:.3f}s"
    )

    log_req_end(
        route="/text",
        session_id=session_id,
        request_id=_text_request_id,
        start_ts=_text_start_ts,
        ok=True,
        path="non_stream",
    )
    return {
        "reply": reply,
        "user_text": text,
        "audio_url": audio_url,
        "audio_urls": audio_urls,
        "tts_segment_count": len(audio_urls),
        "action_payload": action_result.get("ui_payload") if action_result else None,
        # Multi-action planner — when the typed-text planner ran a sequence
        # of actions, every action's ui_payload comes back here in execution
        # order. The frontend applies each entry in turn (see
        # applyActionPayload). Single-action responses leave this empty so
        # nothing changes for callers that only know about action_payload.
        "action_payloads": (action_result.get("ui_payloads") if action_result else None) or [],
        "planner_actions": (action_result.get("planner_actions") if action_result else None) or [],
        "action_type": action_result.get("action_type") if action_result else None,
        "request_id": _text_request_id,
        "latency": {
            "total_s": round(t_total, 4),
            "llm_s": round(t_llm_wall, 4),
            "short_circuit": "text",
        },
    }


# Serve index.html, styles.css, and other repo-root assets from the same origin as the API
# so sign-in and other POST /api/* calls hit this FastAPI process (not file:// or another port).
_REPO_SITE_ROOT = Path(__file__).resolve().parent
app.mount("/", StaticFiles(directory=str(_REPO_SITE_ROOT), html=True), name="vera_site")